/* ============================================================
   Procedure: [dbo].[usp_c2c_GetInitalRemarks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_c2c_GetInitalRemarks]  
(@EntityName NVARCHAR(255),   
 @EntityId   BIGINT  
)  
AS  
BEGIN  
    DECLARE @IntialRemarks NVARCHAR(MAX)= '';  
    SET @IntialRemarks = (CASE  
                                WHEN @EntityName = 'enquiry'  
                                THEN  
    (  
        SELECT InitialRemarks  
        FROM UserEnquiry(NOLOCK)  
        WHERE EnquiryID = @EntityId  
    )  
                                WHEN @EntityName = 'lead'  
                                THEN  
    (  
        SELECT InitialRemarks  
        FROM UserLeads(NOLOCK)  
        WHERE Id = @EntityId  
    )  
                                ELSE ''  
                            END);  
    SELECT @IntialRemarks;  
END;  


GO

/* ============================================================
   Procedure: [dbo].[usp_CalculateClickToCallCost]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_CalculateClickToCallCost(
	@FromMobileNo NVARCHAR(25),
	@ToMobileNo NVARCHAR(25),
	@AgentCallStartTime DATETIME,
	@CustomerStartEndTime DATETIME,
	@CallEndTime DATETIME,
	@DidNo NVARCHAR(25),
	@AgentId BIGINT
)
AS
BEGIN
	
	--DECLARE 
	--	@FromMobileNo NVARCHAR(25) = '0027128814411',
	--	@ToMobileNo NVARCHAR(25) = ' 917725128728',
	--	@AgentCallStartTime DATETIME = '2025-09-19 17:28:13.000',
	--	@CustomerStartEndTime DATETIME = null,
	--	@CallEndTime DATETIME = '2025-09-19 17:28:24.000',
	--	@DidNo NVARCHAR(25) = '27120510948',
	--	@AgentId BIGINT = 49691;

	PRINT '--Passed Parameter and their value'
	PRINT CONCAT('@FromMobileNo => ', @FromMobileNo);
	PRINT CONCAT('@ToMobileNo => ', @ToMobileNo);
	PRINT CONCAT('@AgentCallStartTime => ', format(@AgentCallStartTime, 'dd-MMM-yyyy HH:mm:ss'));
	PRINT CONCAT('@CustomerStartEndTime => ', format(@CustomerStartEndTime, 'dd-MMM-yyyy HH:mm:ss'));
	PRINT CONCAT('@CallEndTime => ', format(@CallEndTime, 'dd-MMM-yyyy HH:mm:ss'));
	PRINT CONCAT('@DidNo => ', @DidNo);
	PRINT CONCAT('@AgentId => ', @AgentId);
	PRINT ''

	DECLARE
		@ParentId bigint  = 0,
		@agentCountryCode nvarchar(5) = '+91',
		@fromCallDuration INT = 0, 
		@toCallDuration INT = 0, 
		@originCountryId INT = 101,              -- default India
		@fromDestinationCountryId INT = 101,     -- default India
		@toDestinationCountryId INT = 101;       -- default India

	select @agentCountryCode = CountryCode, @ParentId = ParentID from User_Detail(nolock) where user_Id = @AgentId

	print '-- Call durations'
	SELECT  
		@fromCallDuration = TRY_CONVERT(int, DATEDIFF(SECOND, @AgentCallStartTime, @CallEndTime)),
		@toCallDuration = isnull(TRY_CONVERT(int, DATEDIFF(SECOND, @CustomerStartEndTime, @CallEndTime)), 0);

	PRINT CONCAT('@fromCallDuration => ', @fromCallDuration);
	PRINT CONCAT('@toCallDuration => ', @toCallDuration);
	print ''

	print '-- Match country IDs'

	SELECT @originCountryId = countryid from dbo.fn_separatecountrycodeandmobile(@DidNo)
	SELECT @fromDestinationCountryId = ISNULL(c.Country_ID, 101) 
		FROM m_country1 c WHERE  LTRIM(rtrim(trim(c.CountryCode))) =  LTRIM(rtrim(@agentCountryCode))
	SELECT @toDestinationCountryId = countryid from dbo.fn_separatecountrycodeandmobile(@ToMobileNo)

	if(@originCountryId<> 101)
	begin
		set @originCountryId = 231
	end

	PRINT CONCAT('@originCountryId => ', @originCountryId);
	PRINT CONCAT('@fromDestinationCountryId => ', @fromDestinationCountryId);
	PRINT CONCAT('@toDestinationCountryId => ', @toDestinationCountryId);
	print ''


	print '-- Rate Setup'
	declare @fromDestinationRate decimal(18,4) = 0.30, @toDestinationRate decimal(18,4) = 0.30 

	if(exists(select 1 from Price_Base_Voice_Rate_Exception(nolock) where UserID = @ParentId
		and OriginCountryId = @originCountryId and DestinationCountryId =  @fromDestinationCountryId ))
	begin
		print '-- Rate Setup From Exception'
		select top 1 @fromDestinationRate = LocalRTrns  from Price_Base_Voice_Rate_Exception(nolock) where UserID = @ParentId
		and OriginCountryId = @originCountryId and DestinationCountryId =  @fromDestinationCountryId order by pvr_id desc
	end
	else
	begin
		print '-- Rate Setup To Base'
		select top 1 @fromDestinationRate = LocalRTrns from Price_Base_Voice_Rate(nolock) where OriginCountryId = @originCountryId 
		and DestinationCountryId =  @fromDestinationCountryId order by pbv_id desc
	end

	if(exists(select 1 from Price_Base_Voice_Rate_Exception(nolock) where UserID = @ParentId
		and OriginCountryId = @originCountryId and DestinationCountryId =  @toDestinationCountryId ))
	begin
		print '-- Rate Setup For ToMobileNo from Exception'
		select top 1 @toDestinationRate = LocalRTrns  from Price_Base_Voice_Rate_Exception(nolock) where UserID = @ParentId
		and OriginCountryId = @originCountryId and DestinationCountryId =  @toDestinationCountryId order by pvr_id desc
	end
	else
	begin
		print '-- Rate Setup For ToMobileNo from base'
		select top 1 @toDestinationRate = LocalRTrns from Price_Base_Voice_Rate(nolock) where OriginCountryId = @originCountryId 
		and DestinationCountryId =  @toDestinationCountryId order by pbv_id desc
	end



	PRINT CONCAT('@fromDestinationRate => ', @fromDestinationRate);
	PRINT CONCAT('@toDestinationRate => ', @toDestinationRate);
	print ''

	print '-- Determine billing units'
	DECLARE 
		@fromBillingUnit INT = CASE WHEN @fromDestinationCountryId = 101 THEN 30 ELSE 60 END,
		@toBillingUnit INT   = CASE WHEN @toDestinationCountryId   = 101 THEN 30 ELSE 60 END;
	PRINT CONCAT('@fromBillingUnit => ', @fromBillingUnit);
	PRINT CONCAT('@toBillingUnit => ', @toBillingUnit);
	print ''

	print '-- Calculate billable units'
	DECLARE 
		@fromBillableUnits INT = CEILING(CAST(@fromCallDuration AS FLOAT) / @fromBillingUnit),
		@toBillableUnits   INT = CEILING(CAST(@toCallDuration AS FLOAT) / @toBillingUnit);
	PRINT CONCAT('@fromBillingUnit => ', @fromBillingUnit);
	PRINT CONCAT('@toBillingUnit => ', @toBillingUnit);
	print''

	print '-- Costs'
	DECLARE 
		@fromDestinationCost DECIMAL(18,4) = @fromBillableUnits * @fromDestinationRate,
		@toDestinationCost   DECIMAL(18,4) = @toBillableUnits   * @toDestinationRate;
	PRINT CONCAT('@fromDestinationCost => ', @fromDestinationCost);
	PRINT CONCAT('@toDestinationCost => ', @toDestinationCost);
	print''

	print '-- Total cost'
	DECLARE @totalCost DECIMAL(18,4) = @fromDestinationCost + @toDestinationCost;
	PRINT CONCAT('@totalCost => ', @totalCost);
	print''

	select @totalCost as totalCost
END



GO

/* ============================================================
   Procedure: [dbo].[usp_CalculateVoiceCredit]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-------------------------------------------------------------------------

CREATE   PROCEDURE usp_CalculateVoiceCredit  --34594,'4660121,4660120,4660119'
    @UserID BIGINT,
    @IDS NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    -- Table variable to store split IDs
    DECLARE @IDsTable TABLE (ID BIGINT);

    -- Replace any curly brackets and split IDs using STRING_SPLIT
    INSERT INTO @IDsTable (ID)
    SELECT CAST(value AS BIGINT)
    FROM STRING_SPLIT(REPLACE(REPLACE(@IDS, '{', ''), '}', ''), ',');

    -- Count the number of IDs
    DECLARE @IDCount INT;
    SELECT @IDCount = COUNT(*) FROM @IDsTable;

    -- Declare a variable to store the function result
    DECLARE @VoiceCredit DECIMAL(18,2);

    -- Call the function with required parameters
    SET @VoiceCredit = dbo.fn_GetVoiceCreditCalculationScalar('Promo', @UserID, 60, @IDCount);

    -- Return the calculated credit
    SELECT @VoiceCredit AS VoiceCredit;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_callend]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROCEDURE [dbo].[usp_callend](@kit19callsid nvarchar(20),@recordurl nvarchar(200),@channelid int,@disposition nvarchar(20)=null)          
as          
begin       
set @recordurl=replace(@recordurl,'http://182.18.144.43','https://recording.kit19.com')  
declare @uniqueid nvarchar(50) ,@calldur int  
select @uniqueid=uniqueid,@calldur=datediff(ss,call_start_time,getdate()) from kit19calls(nolock) where id=@kit19callsid  
--Commented because channel was coming incorrectly    
--set @channelid=(select id from Kit19Channels where channel_uniqueid=@uis)      
--UPDATE Kit19Channels SET channel_calltime = null, channel_uniqueid = null, channel_clientid = null, channel_flowid = 0, channel_flowstep = null, chnnel_dni = null, channel_cli = null, channel_inuse = 'N' WHERE id = @channelid          
UPDATE Kit19Calls SET recordurl = @recordurl,call_end_time = getdate() WHERE id = @kit19callsid          
update diallercalls set call_end_time=GETDATE(), disposition=@disposition where kit19callsid=@kit19callsid      
update diallercalls set billedtime=case when @disposition='ANSWER' then DATEDIFF(ss,call_answer_time,call_end_time) end where kit19callsid=@kit19callsid   
 
 exec [usp_updatecalllog_withreftable]  'Kit19Calls',@kit19callsid

if exists(select 1 from tbl_LeadEventHistory(nolock) where refids=cast(@kit19callsid as nvarchar) and reftables='kit19calls')    
begin    
update tbl_LeadEventHistory set EventDescription=replace(replace(eventdescription,'Call duration: 0','Call duration(sec): '+cast(@calldur as nvarchar)), 'call recording ','call recording: '+@recordurl)     
where refids=cast(@kit19callsid as nvarchar) and reftables='kit19calls'    
end    
if exists(select 1 from tbl_enquiryEventHistory(nolock) where refids=cast(@kit19callsid as nvarchar) and reftables='kit19calls')    
begin    
update tbl_EnquiryEventHistory set EventDescription=replace(replace(eventdescription,'Call duration: 0','Call duration(sec): '+cast(@calldur as nvarchar)), 'call recording ','call recording: '+@recordurl)     
where refids=cast(@kit19callsid as nvarchar) and reftables='kit19calls'    
end    
         
          
declare @duration int,@callstarttime datetime,@agentid bigint          
select @duration=isnull(billedtime,0),@callstarttime=call_start_time,@agentid=user_id from diallercalls(nolock) where kit19callsid=@kit19callsid          
--declare @uniqueid nvarchar(50)= (select uniqueid from Kit19Calls where id=@kit19callsid)          
          
if @duration>0          
begin          
declare @parentid bigint=(select parentid from diallercalls(nolock) where kit19callsid=@kit19callsid)          
declare @cost numeric(18,4)=          
(select dbo.fn_GetVoiceCreditCalculationScalar('Trans',@parentid,@duration,1))          
if @cost>0           
begin          
declare @balance decimal(18,4), @M_ID bigint, @creditid bigint          
select @creditid=max(Credit_ID) from IntCredit_Details where User_ID=@parentid             
select @Balance=  Balance,@M_ID=M_ID from IntCredit_Details where User_ID=@parentid and Credit_ID = @creditid            
          
insert into IntCredit_Details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Remarks,typecredit )  
values(@parentid,@M_ID,@parentid,@cost,0,@Balance-@cost,99999,'Call Charges for click to call dialled out by agent '  
+cast((select user_login from user_detail where USER_ID=@agentid) as nvarchar) +' at '+CAST(@callstarttime as nvarchar)+' , uniqueid: '+@uniqueid,1) 

declare @intCreditId bigint = scope_identity()
exec usp_rf_UpdateReserveFundTransaction @CreditId = @intCreditId


end          
end          
          
end 



GO

