/* ============================================================
   Procedure: [dbo].[usp_callreports_agents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select * from calllog(nolock) where callcreatedon>'20220508' and parentid=35610  
/*  
Agent Summary                           
Date Agent Outgoing calls Incoming calls Outgoing Duration Incoming Duration Missed Calls TotalDuration                    
                           
Calls Summary                           
Date Outgoing Incoming OutgoingAnswered OutgoingUnanswered IncomingAttended IncomingMissed                     
                           
BillingSummary                           
Date Outgoing Incoming                         
                           
DetailedAgent                           
Date Agent DNID Gateway Direction CustomerDisposition AgentDisposition Start time End Time CustomerDuration AgentDuration CallDuration Recording AgentMode Outcome Remarks Logid           
                           
DetailedIncoming                           
Date Calledno(Lead/Enquiry/Others) DNID Gateway IVR Flow Agent CustomerDisposition AgentDisposition Start time End Time CustomerDuration AgentDuration CallDuration Recording Outcome Remarks Logid LastDTMF          
                           
ScheduledCalls                           
ScheduledDate Agent Mobile(Lead/Enquiry) Status LogID                       
*/  
CREATE   PROCEDURE usp_callreports_agents  
@fromdate nvarchar(50)=null ,@todate nvarchar(50)=null,@parentid bigint=null  
as  
begin  
--declare @fromdate nvarchar(50)='20220513' ,@todate nvarchar(50)='20220531',@parentid bigint=34115  
select c.parentid,cast(callcreatedon as date) as Date,
isnull(cal.Agentname,'Agent No changed') as Agent,
sum(case when direction='Outgoing' then 1 else 0 end) as Outgoingcalls,
sum(case when direction='Incoming' then 1 else 0 end) as Incomingcalls,
sum(case when direction='Outgoing' then Calldurationseconds else 0 end) as Outgoingduration,
sum(case when direction='Incoming' then Calldurationseconds else 0 end) as Incomingduration,
sum(case when isnull(agentcalldisposition,'') <>'Answered' and direction='Incoming' then 1 else 0 end) MissedCalls,
sum(calldurationseconds) TotalDuration   
from   
calendar(nolock) ca left join  
calllog(nolock) c on cast(c.callcreatedon as date)=cast(ca.start_dts as date) 
left join Calling_Agents cal(nolock) on cal.id=c.calling_agentid
--left join user_detail u (nolock) on cal.kit19userid = u.User_ID  
where  start_dts between @fromdate and @todate  
and c.parentid=@parentid  
group by cast(callcreatedon as date), Agentname,c.parentid,cast(ca.start_dts as date)  
order by c.parentid,cast(callcreatedon as date) desc  
  
--select top 10 * from calendar  
--Date Outgoing Incoming OutgoingAnswered OutgoingUnanswered IncomingAttended IncomingMissed  
select c.parentid,u.user_login as ParentUser  
,cast(callcreatedon as date) as Date,sum(case when direction='Outgoing' then 1 else 0 end) as Outgoingcalls  
,sum(case when direction='Incoming' then 1 else 0 end) as Incomingcalls  
,sum(case when isnull(customercalldisposition,'') ='Answered' and direction='Outgoing' then 1 else 0 end) OutgoingAnswered  
,sum(case when isnull(customercalldisposition,'') <>'Answered' and direction='Outgoing' then 1 else 0 end) OutgoingUnAnswered  
,sum(case when isnull(agentcalldisposition,'') ='Answered' and direction='Incoming' then 1 else 0 end) IncomingAnswered  
,sum(case when isnull(agentcalldisposition,'') <>'Answered' and direction='Incoming' then 1 else 0 end) IncomingMissed  
from calendar ca(nolock) left join  
calllog c(nolock) on cast(c.callcreatedon as date)=cast(ca.start_dts as date)  
 left join user_detail u (nolock) on c.parentid = u.User_ID  
 where  start_dts between @fromdate and @todate  
and c.parentid=@parentid  
group by cast(callcreatedon as date), u.user_login,c.parentid,cast(ca.start_dts as date)  
order by c.parentid,cast(callcreatedon as date) desc  
  
--Date Outgoing Incoming  
  
select c.parentid,cast(callcreatedon as date) as Date  
,sum(case when direction='Outgoing' then t.cost else 0 end) as Outgoing  
,sum(case when direction='Incoming' then t.cost else 0 end) as Incoming  
--,sum(case when direction='Outgoing' then Calldurationseconds else 0 end) as Outgoingduration,sum(case when direction='Incoming' then Calldurationseconds else 0 end) as Incomingduration  
--,sum(case when isnull(agentcalldisposition,'') <>'Answered' and direction='Incoming' then 1 else 0 end) MissedCalls,sum(calldurationseconds) TotalDuration   
from   
calendar(nolock) ca left join  
calllog(nolock) c on cast(c.callcreatedon as date)=cast(ca.start_dts as date)  
left join user_detail u (nolock) on c.parentid = u.User_ID  
left join TelephonyCostDeducted(nolock) t on t.parentid=c.parentid   
and 1=case when t.gatewaytype<>0 and t.kit19callsdialledid=c.refid then 1  
when t.GatewayType=0 and t.uniqueid=c.uniqueid then 1 else 0 end  
where  start_dts between @fromdate and @todate  
and c.parentid=@parentid  
group by cast(callcreatedon as date), user_login,c.parentid,cast(ca.start_dts as date)  
order by c.parentid,cast(callcreatedon as date) desc  
  
--select top 1000 * from TelephonyCostDeducted(nolock) where parentid=35610 order by id desc  
--select top 10 * from calllog(nolock) where parentid=35610  
  
--select --top 1000   
--sum(case when direction='Outgoing' then t.cost else 0 end) as Outgoing  
--,sum(case when direction='Incoming' then t.cost else 0 end) as Incoming  
----*  
--from   
--calendar(nolock) ca left join  
--calllog(nolock) c on cast(c.callcreatedon as date)=cast(ca.start_dts as date)  
----join user_detail u (nolock) on c.agentuserid = u.User_ID  
--join TelephonyCostDeducted(nolock) t on t.parentid=c.parentid   
--and 1=case when t.gatewaytype<>0 and t.kit19callsdialledid=c.refid then 1  
--when t.GatewayType=0 and t.uniqueid=c.uniqueid then 1 else 0 end  
--where t.parentid=35610 --order by t.id desc  
  
  
  
--alter table calllog add uniqueid nvarchar(100)  
  
--Date Agent DNID Gateway Direction CustomerDisposition AgentDisposition Start time End Time CustomerDuration AgentDuration CallDuration Recording   
--AgentMode Outcome Remarks Logid           
select c.parentid,c.uniqueid  
,isnull(agentname,case when c.agentcalldisposition is null then '' else 'AGENT NO. CHANGED' end) Agent  
,cast(callcreatedon as date) as Date  
,isnull(dnid,'') as DNID  
,s.provider_name as Gateway  
,direction  
,isnull(c.customercalldisposition,'Unknown') as CustomerDisposition  
,isnull(c.agentcalldisposition,case when c.agentcalldisposition is null then 'NOT ATTEMPTED' else 'Unknown' end) as AgentDisposition  
,c.Callstarttime  
,isnull(cast(c.callendtime as nvarchar),'Unknown') as CallEndTime  
,coalesce(customerduration,c.Calldurationseconds,0) CustomerDuration  
,coalesce(agentduration,Calldurationseconds,0) agentDuration  
,isnull(Calldurationseconds,0) Callduration  
,c.recordurl as Recording  
,isnull(c.agentmode,'Mobile') as AgentMode  
,isnull(o.outcomename,'') as Outcome  
,c.remarks  
from   
calendar(nolock) ca left join  
calllog(nolock) c on cast(c.callcreatedon as date)=cast(ca.start_dts as date)
left join Calling_Agents cal(nolock) on cal.id=c.calling_agentid
--left join user_detail u (nolock) on c.agentuserid = u.User_ID  
left join TelephonyCostDeducted(nolock) t on t.parentid=c.parentid   
and 1=case when t.gatewaytype<>0 and t.kit19callsdialledid=c.refid then 1  
when t.GatewayType=0 and t.uniqueid=c.uniqueid then 1 else 0 end  
left join tbl_voip_ServiceProvider s on s.id=c.gatewayid  
left join calloutcomes(nolock) o on o.id=c.outcomeid   
where  start_dts between @fromdate and @todate  
and c.parentid=@parentid  
--group by cast(callcreatedon as date), user_login,c.parentid,cast(ca.start_dts as date)  
order by c.parentid,cast(callcreatedon as date) desc  
  
--Date Calledno(Lead/Enquiry/Others) DNID Gateway IVR Flow Agent CustomerDisposition AgentDisposition   
--Start time End Time CustomerDuration AgentDuration CallDuration Recording Outcome Remarks Logid LastDTMF          
select c.parentid  
,cast(callcreatedon as date) as Date  
,Customernumber  
,customerentity  
,customerentityid  
,isnull(dbo.fn_getentityfullname(customerentity,customerentityid),'') CustomerName  
,isnull(dnid,'') as DNID  
,s.provider_name as Gateway  
,isnull(m.AppName,'') IVRFlow  
,isnull(agentname,case when c.agentcalldisposition is null then ' ' else 'Agent No Changed' end) Agent  
,direction  
,isnull(c.customercalldisposition,'Unknown') as CustomerDisposition  
,isnull(c.agentcalldisposition,case when c.agentcalldisposition is null then 'NOT ATTEMPTED' else 'Unknown' end) as AgentDisposition  
,c.Callstarttime  
,isnull(cast(c.callendtime as nvarchar),'Unknown') as CallEndTime  
,coalesce(customerduration,c.Calldurationseconds,0) CustomerDuration  
,coalesce(agentduration,Calldurationseconds,0) agentDuration  
,isnull(Calldurationseconds,0) Callduration  
,c.recordurl as Recording  
,isnull(c.agentmode,'Mobile') as AgentMode  
,isnull(o.outcomename,'') as Outcome  
,c.remarks  
,isnull(c.lastdtmf,'') LastUserInput  
from   
calendar(nolock) ca left join  
calllog(nolock) c on cast(c.callcreatedon as date)=cast(ca.start_dts as date) 
left join Calling_Agents cal(nolock) on cal.id=c.calling_agentid
--left join user_detail u (nolock) on c.agentuserid = u.User_ID  
left join TelephonyCostDeducted(nolock) t on t.parentid=c.parentid   
and 1=case when t.gatewaytype<>0 and t.kit19callsdialledid=c.refid then 1  
when t.GatewayType=0 and t.uniqueid=c.uniqueid then 1 else 0 end  
left join tbl_voip_ServiceProvider s on s.id=c.gatewayid  
left join calloutcomes(nolock) o on o.id=c.outcomeid   
left join Cloud_app_master(nolock) m on m.AppId=c.appid   
where  start_dts between @fromdate and @todate  
and c.parentid=@parentid  
--group by cast(callcreatedon as date), user_login,c.parentid,cast(ca.start_dts as date)  
order by c.parentid,cast(callcreatedon as date) desc  
end  
  
  
  
  
