/* ============================================================
   Procedure: [dbo].[usp_callstart]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_callstart              
(@CallerId nvarchar(20), @Channel nvarchar(50), @Dnid nvarchar(20), @UniqueId nvarchar(20),@accountcode bigint,@dnidnowithcountrycode nvarchar(20))              
as              
begin    
if @accountcode=15165003004   
set @accountcode=34594

if @accountcode =0 and isnumeric(replace(left(@channel,charindex('-',@channel,1)-1),'SIP/',''))=1
set @accountcode=replace(left(@channel,charindex('-',@channel,1)-1),'SIP/','')
    
declare @kit19callsid bigint,@channelid int,@parentid bigint,@diallercallid bigint              
select @parentid=Parentid from user_detail(nolock) where USER_ID=@accountcode              
SELECT TOP 1 @Channelid=id FROM Kit19Channels(nolock) WHERE ISNULL(channel_inuse, 'N') = 'N'   
ORDER BY ISNULL(channel_lastaccesstime, getdate()) DESC              
if @channelid>0              
begin              
INSERT INTO Kit19Calls(call_start_time, UniqueId, AccountCode, CallerId, CallerIdName, CallingAni2, CallingPres, CallingTns, CallingTon, Channel, Context, Dnid, Enhanced, Extension, Language, LocalPort, Priority, Rdnis, RemotePort, RequestURL, Script,    
  
Type, channel_id, kit19uniqueid,clientid,appid)               
VALUES(getdate(), @uniqueid, @accountcode, @callerid, '', '0', '0', '0', '0', @channel, 'DialerCalls', @dnid, 'False', '0091'+cast(@dnid as nvarchar), 'En', '0', '12', '', '0', 'softphone', '', 'SIP', @channelid, '',@parentid,0)               
SELECT @kit19callsid=scope_IDENTITY()   

create table #calllogid(calllogid bigint)

insert into #calllogid
exec [usp_createcalllog] 'Kit19calls','id',@kit19callsid,'outgoing'
              
insert into diallercalls(user_id,parentid,callerid,dnid,dnidnowithcountrycode,call_start_time, call_answer_time,call_end_time,billedtime ,kit19callsid)              
select @accountcode,@parentid,@CallerId,@Dnid,@dnidnowithcountrycode,GETDATE(),getdate(),null,null,@kit19callsid              
select @diallercallid=SCOPE_IDENTITY()              
              
UPDATE Kit19Channels SET channel_calltime = getdate(), channel_uniqueid = @UniqueId, chnnel_dni = @Dnid, channel_cli = @callerid, channel_inuse = 'Y', channel_lastaccesstime = getdate(),channel_clientid=@parentid,channel_flowid=0        
,channel_flowstep ='DialerCalls' WHERE id = @channelid              
          
          
select @kit19callsid as kit19callid,@channelid as Channelid,@diallercallid as diallercallsid              
          
          
/* Call made to lead */          
             
   Begin try          
          
 Declare @UserID_LDACTV bigint = @accountcode          
 Declare @ParentID_LDACTV bigint = @parentid          
 Declare @MobileNo_LDACTV nvarchar(50) = @Dnid          
 Declare @LeadID_LDACTV bigint = 0          
 Declare @CallDuration_LDACTV int = 0          
 Declare @RecordURL_LDACTV nvarchar(500) = ''          
 Declare @Kit19CallsID_LDACTV bigint = @kit19callsid          
 Declare @CallStartDatetime_LDACTV datetime = null          
 Declare @CallEndDatetime_LDACTV datetime = null          
          
          
    Select @RecordURL_LDACTV = isnull(recordurl,''),@CallStartDatetime_LDACTV = call_start_time ,  
 @CallEndDatetime_LDACTV = call_end_time  from Kit19Calls(nolock) where id =  @Kit19CallsID_LDACTV          
          
 if((@CallStartDatetime_LDACTV is not null) and (@CallEndDatetime_LDACTV is not null))          
   Begin          
         set @CallDuration_LDACTV = DATEDIFF(SECOND,@CallStartDatetime_LDACTV,@CallEndDatetime_LDACTV)          
   End          
  else          
   Begin          
      set  @CallDuration_LDACTV = 0          
   End           
          
   select  @LeadID_LDACTV = isnull(ID,0) from UserLeads(nolock)   
   where ((MobileNo=@MobileNo_LDACTV) or (MobileNo1=@MobileNo_LDACTV) or (MobileNo2=@MobileNo_LDACTV))      
   and parentid=@parentid      
    and rtrim(ltrim(@MobileNo_LDACTV)) <> ''              
          
          
  create table #tblEventDescrb          
     (          
        EVNT_Description nvarchar(max)           
     )          
          
  if( isnull(@LeadID_LDACTV,0) > 0)          
    Begin          
   insert into #tblEventDescrb          
      exec  Usp_EventTemplate_DynamicVarReplacement 'Call made to lead',@UserID_LDACTV,'',@MobileNo_LDACTV,@LeadID_LDACTV,'',null          
   ,0,0,'','',0,'',@CallDuration_LDACTV,@RecordURL_LDACTV,null,null,null,null,null,null,null,null          
   ,null,null,null,null,null,null,null,null,          
   0,0,0,null,null,null,0,null,null,null,null,null,null          
        
   declare @evntMessage nvarchar(max) = ''           
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb          
           
   if(@evntMessage <> '')          
   Begin       
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,    'Call made to lead','Kit19Calls',@kit19callsid          
   end          
   End            
             
   end try          
          
   Begin catch          
             
     exec usp_insertErrorInfo          
             
   end catch          
          
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence            
   Begin            
        DROP TABLE #tblEventDescrb            
   End           
          
          
          
end              
end 


GO

