CREATE   PROC dbo.Usp_CampaignDeletion (
	@CampaignID BIGINT
	,@IsActive BIT
	)
AS
BEGIN
	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserCampaignSettings(NOLOCK)
			WHERE CampaignID = @CampaignID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)
	DECLARE @userid BIGINT = (
			SELECT UserID
			FROM UserCampaignSettings(NOLOCK)
			WHERE CampaignID = @CampaignID
			)

	UPDATE UserCampaignSettings
	SET IsActive = @IsActive
	WHERE CampaignID = @CampaignID

	SELECT 'Record Deactivated'

	--if(@IsActive=1)
