/* ============================================================
   Procedure: [dbo].[usp_CampaignSchedule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_CampaignSchedule]    
AS    
BEGIN    
 IF EXISTS(    
        SELECT cm.ID    
        FROM   CampaignMaster AS cm    
        WHERE  cm.IsExecuted = 0    
               AND ISNULL(cm.SenderID, '') <> ''    
               AND DATEDIFF(MINUTE, GETDATE(), ISNULL(cm.ScheduleTime, GETDATE()))     
                   <= 15  and isrunning=0  
    )    
 BEGIN    
     SELECT cm.ID,    
            cm.CampaignName,    
            CAST(cm.ScheduleTime AS DATETIME) AS ScheduleTime INTO     
            #Temptable    
     FROM   CampaignMaster AS cm    
     WHERE  cm.IsExecuted = 0    
             AND ISNULL(cm.SenderID, '') <> ''    
            AND DATEDIFF(MINUTE, GETDATE(), ISNULL(cm.ScheduleTime, GETDATE()))     
                <= 15  and isrunning=0  
     ORDER BY    
            cm.ScheduleTime,    
            cm.ID ASC      
         
         
     DECLARE @Count INT = (    
                 SELECT COUNT(*)    
                 FROM   #Temptable    
             )        
         
     IF (@Count > 0)    
     BEGIN    
         WHILE @Count > 0    
         BEGIN    
             SET @Count = @Count -1       
                 
                 
             DECLARE @CampaignID BIGINT        
                 
             DECLARE @Delay1 DATETIME        
             SELECT @CampaignID = tt.ID,    
                    @Delay1 = CASE     
                                   WHEN DATEDIFF(MINUTE, GETDATE(), ISNULL(tt.ScheduleTime, GETDATE()))     
                                        < 0 THEN CAST(CAST(GETDATE() AS DATE) AS VARCHAR(50))     
                                        +    
                                        ' 00:00:00'    
                                   ELSE CAST(CAST(GETDATE() AS DATE) AS VARCHAR(50))     
                                        +    
                                        ' 00:' +    
                                        RIGHT(    
                                            '0' + CAST(    
                                                DATEDIFF(MINUTE, GETDATE(), ISNULL(tt.ScheduleTime, GETDATE()))     
                                                AS VARCHAR    
                                            ),    
                                            2    
                                        )     
                                        + ':00'    
                              END    
             FROM   #Temptable tt    
             ORDER BY    
                    tt.ScheduleTime DESC      
                 
                 
             DELETE     
             FROM   #Temptable    
             WHERE  ID = @CampaignID     
                 
                 
             WAITFOR DELAY @Delay1      
             BEGIN    
              EXEC usp_ExecuteCampaign     
                   @CampaignID    
             END    
         END    
     END     
         
     DROP TABLE #Temptable    
 END    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_CampaignScheduleMails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

          
CREATE   PROCEDURE [dbo].[usp_CampaignScheduleMails]        
AS        
BEGIN        
 IF EXISTS(        
        SELECT cm.ID        
        FROM   CampaignMaster AS cm        
        WHERE  cm.IsExecuted = 0        
               AND ISNULL(cm.SenderID, '') = ''        
               AND DATEDIFF(MINUTE, GETDATE(), ISNULL(cm.ScheduleTime, GETDATE()))         
                   <= 15  and isrunning=0      
    )        
 BEGIN        
     SELECT cm.ID,        
            cm.CampaignName,        
            CAST(cm.ScheduleTime AS DATETIME) AS ScheduleTime INTO         
            #Temptable        
     FROM   CampaignMaster AS cm        
     WHERE  cm.IsExecuted = 0        
            AND ISNULL(cm.SenderID, '') = ''        
            AND DATEDIFF(MINUTE, GETDATE(), ISNULL(cm.ScheduleTime, GETDATE()))         
                <= 15      and isrunning=0  
     ORDER BY        
            cm.ScheduleTime,        
            cm.ID ASC          
             
             
     DECLARE @Count INT = (        
                 SELECT COUNT(*)        
                 FROM   #Temptable        
             )            
             
     IF (@Count > 0)        
     BEGIN        
         WHILE @Count > 0        
         BEGIN        
             SET @Count = @Count -1           
                     
                     
             DECLARE @CampaignID BIGINT            
                     
             DECLARE @Delay1 DATETIME            
             SELECT @CampaignID = tt.ID,        
                    @Delay1 = CASE         
                                   WHEN DATEDIFF(MINUTE, GETDATE(), ISNULL(tt.ScheduleTime, GETDATE()))         
                                        < 0 THEN CAST(CAST(GETDATE() AS DATE) AS VARCHAR(50))         
                                        +        
                                        ' 00:00:00'        
                                   ELSE CAST(CAST(GETDATE() AS DATE) AS VARCHAR(50))         
                                        +        
                                        ' 00:' +        
                                        RIGHT(        
                                            '0' + CAST(        
                                                DATEDIFF(MINUTE, GETDATE(), ISNULL(tt.ScheduleTime, GETDATE()))         
                                                AS VARCHAR        
                                            ),        
                                            2        
                                        )         
                                        + ':00'        
                              END        
             FROM   #Temptable tt        
             ORDER BY        
                    tt.ScheduleTime DESC          
                     
                     
             DELETE         
             FROM   #Temptable        
             WHERE  ID = @CampaignID         
                     
                     
             WAITFOR DELAY @Delay1          
             BEGIN        
              EXEC usp_ExecuteCampaignMailCorrected         
                   @CampaignID        
             END        
         END        
     END         
             
     DROP TABLE #Temptable        
 END        
END 


