/* ============================================================
   Procedure: [dbo].[usp_cb_checkwebhookurl1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_cb_checkwebhookurl1  
    @UserId bigint,  
    @WebhookURL NVARCHAR(MAX),  
    @ModuleName varchar(100),  
    @ButtonId bigint  
AS  
BEGIN  
    DECLARE @ParentId BIGINT;  
    DECLARE @ModuleCode VARCHAR(50);  
    DECLARE @WebhookId BIGINT;  
  
    BEGIN TRY  
        -- Get ParentId from User_Detail table  
        SELECT @ParentId = ParentID  
        FROM User_Detail (NOLOCK)  
        WHERE User_ID = @UserId;  
  
        IF @ParentId IS NULL  
        BEGIN  
            -- User not found, return error message  
            THROW 51000, 'User not found.', 1;  
        END;  
  
        -- Get ModuleCode from TBL_UA_ModuleMaster  
        SELECT @ModuleCode = ModuleCode  
        FROM TBL_UA_ModuleMaster (NOLOCK)  
        WHERE ModuleName = @ModuleName;  
  
        IF @ModuleCode IS NULL  
        BEGIN  
            -- Module not found, return error message  
            THROW 51001, 'Module not found.', 1;  
        END;  
  
        -- Get WebhookID from tbl_CB_CustomButtons based on ButtonId  
        SELECT @WebhookId = WebhookID  
        FROM tbl_CB_CustomButtons (NOLOCK)  
        WHERE ButtonId = @ButtonId;  
  
        IF @WebhookId IS NULL  
        BEGIN  
            -- WebhookID not found for the ButtonId, return error message  
            THROW 51002, 'WebhookID not found for the specified ButtonId.', 1;  
        END;  
  
        -- Fetch the Webhook details from Tbl_CB_WebhookSummary  
        SELECT UserId, WebhookID, WebhookURL,  
               REPLACE(REPLACE(Params, ',"AskBefore":true', ''), ',"AskBefore":false', '') AS Params  
        FROM Tbl_CB_WebhookSummary  
        WHERE WebhookURL = @WebhookURL AND ModuleCode = @ModuleCode AND WebhookID = @WebhookId;  
  
    END TRY  
    BEGIN CATCH  
        -- Handle the error  
        DECLARE @ErrorMessage NVARCHAR(4000);  
        DECLARE @ErrorSeverity INT;  
        DECLARE @ErrorState INT;  
  
        SELECT   
            @ErrorMessage = ERROR_MESSAGE(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE();  
  
        -- Return error message  
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);  
    END CATCH  
END;  


GO

