/* ============================================================
   Procedure: [dbo].[usp_cb_InsertAndUpdateWebhookData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_cb_InsertAndUpdateWebhookData      
    @WebhookID BIGINT,      
    @Params NVARCHAR(MAX),      
    @LeadIDs NVARCHAR(MAX),      
    @UserId BIGINT,     
    @HeaderKey NVARCHAR(MAX),      
    @HeaderValue NVARCHAR(MAX),
	@SenderId NVARCHAR(30)=''
AS      
BEGIN      
    DECLARE @WebhookURL NVARCHAR(MAX);      
    DECLARE @ContentType NVARCHAR(MAX);      
    DECLARE @Method VARCHAR(50);      
    DECLARE @ModuleCode NVARCHAR(MAX);      
    DECLARE @ModuleName NVARCHAR(MAX);      
    DECLARE @ExistingParams NVARCHAR(MAX);      
      
    BEGIN TRY      
        -- Fetch values from Tbl_CB_WebhookSummary      
        SELECT @WebhookURL = WebhookURL,      
               @ContentType = ContentType,      
               @Method = Method,      
               @ModuleCode = ModuleCode,      
               @ExistingParams = ISNULL(Params, '[]')      
        FROM Tbl_CB_WebhookSummary      
        WHERE WebhookID = @WebhookID;      
      
        -- Fetch ModuleName from TBL_UA_ModuleMaster based on ModuleCode      
        SELECT @ModuleName = ModuleName      
        FROM TBL_UA_ModuleMaster      
        WHERE ModuleCode = @ModuleCode;      
      
        -- Debugging: Print existing params      
        PRINT 'Existing Params: ' + @ExistingParams;      
      
        -- Parse the existing Params JSON      
        DECLARE @JsonObj NVARCHAR(MAX) = ISNULL(@ExistingParams, '[]');      
      
        -- Debugging: Print parsed JSON      
        PRINT 'Parsed JSON: ' + @JsonObj;      
      
        -- Temporary variable to hold the updated JSON      
        DECLARE @UpdatedJson NVARCHAR(MAX) = @JsonObj;      
      
        -- Get the length of the JSON array      
        DECLARE @ArrayLength INT;      
        SELECT @ArrayLength = COUNT(*)      
        FROM OPENJSON(@JsonObj);      
      
        -- Iterate through each item in the existing Params array      
        DECLARE @Index INT = 0;      
      
        WHILE @Index < @ArrayLength      
        BEGIN      
            -- Get all key-value pairs of the current array element      
            DECLARE @Element NVARCHAR(MAX);      
            SET @Element = JSON_QUERY(@JsonObj, CONCAT('$[', @Index, ']'));      
      
            -- Iterate over each key in the current JSON element      
            DECLARE @CurKey NVARCHAR(MAX);      
            DECLARE @CurValue NVARCHAR(MAX);      
      
            DECLARE cur CURSOR FOR      
            SELECT [key], [value]      
            FROM OPENJSON(@Element);      
      
            OPEN cur      
            FETCH NEXT FROM cur INTO @CurKey, @CurValue;      
      
            WHILE @@FETCH_STATUS = 0      
            BEGIN      
                -- Check if the key exists in @Params      
                DECLARE @ParamValue NVARCHAR(MAX);      
                SET @ParamValue = JSON_VALUE(@Params, CONCAT('$.', @CurKey));      
      
                -- Replace value if @ParamValue is not NULL      
                IF @ParamValue IS NOT NULL AND @CurKey != 'AskBefore'      
                BEGIN      
                    SET @UpdatedJson = JSON_MODIFY(@UpdatedJson, CONCAT('$[', @Index, '].', @CurKey), @ParamValue);      
                END      
      
                FETCH NEXT FROM cur INTO @CurKey, @CurValue;      
            END;      
      
            CLOSE cur;      
            DEALLOCATE cur;      
      
            -- Update 'AskBefore' to false      
            SET @UpdatedJson = JSON_MODIFY(@UpdatedJson, CONCAT('$[', @Index, '].AskBefore'), 'false');      
      
            -- Increment the index      
            SET @Index = @Index + 1;      
        END;      
      
        -- Debugging: Print updated params      
        PRINT 'Updated Params: ' + @UpdatedJson;      
      
        -- Insert data into tbl_cb_webhook_restbl      
        INSERT INTO [dbo].[tbl_cb_webhook_restbl] (WebhookID, UserId, WebhookURL, Params, ContentType, Method, ModuleCode, BaseURL, EntityId, CreatedDate, IsProcessed, EntityType, HeaderKey, HeaderValue,SenderId)      
        VALUES (@WebhookID, @UserId, @WebhookURL, @UpdatedJson, @ContentType, @Method, @ModuleCode, @WebhookURL, @LeadIDs, GETDATE(), 0, @ModuleName, @HeaderKey, @HeaderValue,@SenderId);      
      
    END TRY      
    BEGIN CATCH      
        -- Handle the error      
        DECLARE @ErrorMessage NVARCHAR(4000);      
        DECLARE @ErrorSeverity INT;      
        DECLARE @ErrorState INT;      
      
        SELECT       
            @ErrorMessage = ERROR_MESSAGE(),      
            @ErrorSeverity = ERROR_SEVERITY(),      
            @ErrorState = ERROR_STATE();      
      
        -- Return error message      
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);      
    END CATCH;      
END;


GO

/* ============================================================
   Procedure: [dbo].[usp_cb_InsertAndUpdateWebhookDataBatch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

------------------------------------------------

CREATE   PROCEDURE usp_cb_InsertAndUpdateWebhookDataBatch  
    @WebhookID BIGINT,  
    @Params NVARCHAR(MAX),  
    @BatchId BIGINT,  
    @UserId BIGINT  
AS  
BEGIN  
    DECLARE @WebhookURL NVARCHAR(MAX)  
    DECLARE @ContentType NVARCHAR(MAX)  
    DECLARE @Method VARCHAR(50)  
    DECLARE @ModuleCode NVARCHAR(MAX)  
    DECLARE @ModuleName NVARCHAR(MAX)  
    DECLARE @ExistingParams NVARCHAR(MAX)  
    DECLARE @EntityID BIGINT  
  
    BEGIN TRY  
        -- Fetch values from Tbl_CB_WebhookSummary  
        SELECT @WebhookURL = WebhookURL,  
               @ContentType = ContentType,  
               @Method = Method,  
               @ModuleCode = ModuleCode,  
               @ExistingParams = ISNULL(Params, '[]')  
        FROM Tbl_CB_WebhookSummary  
        WHERE WebhookID = @WebhookID;  
  
        -- Fetch ModuleName from TBL_UA_ModuleMaster based on ModuleCode  
        SELECT @ModuleName = ModuleName  
        FROM TBL_UA_ModuleMaster  
        WHERE ModuleCode = @ModuleCode;  
  
        -- Debugging: Print existing params  
        PRINT 'Existing Params: ' + @ExistingParams  
  
        -- Parse the existing Params JSON  
        DECLARE @JsonObj NVARCHAR(MAX) = ISNULL(@ExistingParams, '[]')  
  
        -- Debugging: Print parsed JSON  
        PRINT 'Parsed JSON: ' + @JsonObj  
  
        -- Temporary variable to hold the updated JSON  
        DECLARE @UpdatedJson NVARCHAR(MAX) = @JsonObj  
  
        -- Iterate through each item in the existing Params array  
        DECLARE @Index INT = 0  
        DECLARE @ArrayLength INT  
  
        -- Get the length of the JSON array  
        SELECT @ArrayLength = COUNT(*)  
        FROM OPENJSON(@JsonObj)  
  
        -- Loop through the JSON array  
        WHILE @Index < @ArrayLength  
        BEGIN  
            -- Get the value of 'AskBefore' for the current array element  
            DECLARE @AskBefore BIT  
            SELECT @AskBefore = JSON_VALUE(@JsonObj, CONCAT('$[', @Index, '].AskBefore'))  
  
            -- Check if AskBefore is true  
            IF @AskBefore = 1  
            BEGIN  
                -- Get all key-value pairs of the current array element  
                DECLARE @Element NVARCHAR(MAX)  
                SET @Element = JSON_QUERY(@JsonObj, CONCAT('$[', @Index, ']'))  
  
                -- Iterate over each key in the current JSON element  
                DECLARE @CurKey NVARCHAR(MAX)  
                DECLARE @CurValue NVARCHAR(MAX)  
  
                DECLARE cur CURSOR FOR  
                SELECT [key], [value]  
                FROM OPENJSON(@Element)  
  
                OPEN cur  
                FETCH NEXT FROM cur INTO @CurKey, @CurValue  
  
                WHILE @@FETCH_STATUS = 0  
                BEGIN  
                    -- Check if the key exists in @Params  
                    DECLARE @ParamValue NVARCHAR(MAX)  
                    SET @ParamValue = (SELECT [value] FROM OPENJSON(@Params) WHERE [key] = @CurKey)  
  
                    -- Replace value if @ParamValue is not NULL  
                    IF @ParamValue IS NOT NULL AND @CurKey != 'AskBefore'  
                    BEGIN  
                        SET @UpdatedJson = JSON_MODIFY(@UpdatedJson, CONCAT('$[', @Index, '].', @CurKey), @ParamValue)  
                    END  
  
                    FETCH NEXT FROM cur INTO @CurKey, @CurValue  
                END  
  
                CLOSE cur  
                DEALLOCATE cur  
  
                -- Update 'AskBefore' to false  
                SET @UpdatedJson = JSON_MODIFY(@UpdatedJson, CONCAT('$[', @Index, '].AskBefore'), 'false')  
            END  
  
            -- Increment the index  
            SET @Index = @Index + 1  
        END  
  
        -- Debugging: Print updated params  
        PRINT 'Updated Params: ' + @UpdatedJson  
  
        -- Fetch all relevant EntityID from Tbl_MassOperationDetails based on SummaryId = @BatchId  
        DECLARE entity_cursor CURSOR FOR  
        SELECT EntityID  
        FROM Tbl_MassOperationDetails  
        WHERE SummaryId = @BatchId  
  
        OPEN entity_cursor  
    FETCH NEXT FROM entity_cursor INTO @EntityID  
  
        WHILE @@FETCH_STATUS = 0  
        BEGIN  
            -- Insert data into tbl_cb_webhook_restbl for each EntityID  
            INSERT INTO [dbo].[tbl_cb_webhook_restbl]   
                (WebhookID, UserId, WebhookURL, Params, ContentType, Method, ModuleCode, BaseURL, BatchId, CreatedDate, IsProcessed, EntityType, EntityID)  
            VALUES   
                (@WebhookID, @UserId, @WebhookURL, @UpdatedJson, @ContentType, @Method, @ModuleCode, @WebhookURL, @BatchId, GETDATE(), 0, @ModuleName, @EntityID);  
  
            FETCH NEXT FROM entity_cursor INTO @EntityID  
        END  
  
        CLOSE entity_cursor  
        DEALLOCATE entity_cursor  
  
    END TRY  
    BEGIN CATCH  
        -- Handle the error  
        DECLARE @ErrorMessage NVARCHAR(4000);  
        DECLARE @ErrorSeverity INT;  
        DECLARE @ErrorState INT;  
  
        SELECT   
            @ErrorMessage = ERROR_MESSAGE(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE();  
  
        -- Return error message  
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);  
    END CATCH  
END  





GO

