--------------------------------

CREATE   PROCEDURE Usp_cb_webhookdetails  
(  
    @UserId bigint,  
    @WebhookURL nvarchar(max),  
    @Method varchar(50),  
    @ContentType nvarchar(max),  
 @Params nvarchar(max),  
 @ModuleCode varchar (100),  
   -- @ParamKey nvarchar(max),  
   -- @ParamValue nvarchar(max),  
    @ErrorMessage nvarchar(max) OUTPUT  
)  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Insert data into Tbl_CB_WebhookSummary table  
        INSERT INTO Tbl_CB_WebhookSummary (UserId, WebhookURL, Method, ContentType, Params, ModuleCode, CreatedDate, IsProcessed)  
