CREATE   PROCEDURE [dbo].[usp_cd_delete_Predefine]
	@UserId Bigint,
    @CustomDashboardId INT,
    @Message NVARCHAR(250) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    -- Check if CustomDashboardId is associated with tbl_cd_TilesMaster
    IF EXISTS (
        SELECT 1 
        FROM tbl_cd_TilesMaster tm 
        INNER JOIN tbl_cd_CustomDashboard_Predifine u ON tm.CustomDashboardId = u.Id
        WHERE u.Id = @CustomDashboardId and tm.UserId = @UserId AND SectionID !=0 and IsPredifine = 0
    )
    BEGIN
        -- If associated, return a message and exit
        SET @Message = 'You cannot delete, because many reports associated with this Custom Dashboard.';
        RETURN;
    END

    -- Perform soft delete by setting IsDelete = 1
    UPDATE tbl_cd_CustomDashboard_Predifine
    SET IsDelete = 1
    WHERE Id = @CustomDashboardId and IsPredifine = 0;

    -- Success message
    SET @Message = 'Custom Dashboard Deleted Successfully.';
END;



