	@dashboardId INT,
	@userId INT
AS
BEGIN
  SELECT ReportID, ReportName, SectionID, rt.TypeId , rt.Type, rt.DefaultGridSizeHeight, rt.DefaultGridSizeWidth,
	CASE 
      WHEN (SELECT COUNT(*) FROM tbl_cd_TilesMaster(nolock)  WHERE UserId = @userId AND CustomDashboardid = @dashboardId AND r.ReportName = ReportName and SectionID = @sectionId) > 0 THEN 1
