/* ============================================================
   Procedure: [dbo].[usp_cd_GetSavedDashboardForVisibility]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_cd_GetSavedDashboardForVisibility]  
 @UserID BIGINT  
AS  
BEGIN  
 ----DECLARE @UserID BIGINT = 32222   
 --SELECT tm.CustomDashboardid, count(1) as [RecordCount]  
 -- FROM tbl_cd_TilesMaster(NOLOCK) tm    
 -- JOIN tbl_cd_Report r ON r.SectionID = tm.SectionID    
 --WHERE tm.UserId = @UserID AND r.ReportName = tm.ReportName and r.IsActive=1 and r.IsDelete=0 
 -- GROUP BY  tm.CustomDashboardid 
 
 SELECT 
    r.Id as CustomDashboardId,
    CASE 
        WHEN COUNT(tm.CustomDashboardId) = 0 THEN 1
        ELSE COUNT(CASE WHEN tm.SectionID = 0 THEN 1 END)
    END AS SectionID_Zero_Count,
    COUNT(CASE WHEN tm.SectionID > 0 THEN 1 END) AS RecordCount --SectionID_One_Count
FROM 
    tbl_cd_CustomDashboard_Predifine (NOLOCK) r 
	LEFT JOIN tbl_cd_TilesMaster (NOLOCK) tm ON r.Id = tm.CustomDashboardId AND tm.UserId = @UserID
WHERE 
	r.UserId = @UserID 
	and r.IsActive = 1 
    AND r.IsDelete = 0 
    AND r.IsPredifine = 0 
    AND r.IsVisible = 1
GROUP BY 
    r.Id;
END   


