/* ============================================================
   Procedure: [dbo].[usp_cd_SaveCustomDashboard_Predefine]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

------------------------------------------------------------------------------------------------------------  
  
CREATE   PROCEDURE [dbo].[usp_cd_SaveCustomDashboard_Predefine]  
    @CustomDashboard NVARCHAR(100),  
    @UserId INT,  
    @IsActive BIT = 1,   
    @IsDelete BIT = 0     
AS  
BEGIN  
    SET NOCOUNT ON;  
  
	DECLARE @NewDashboardId INT=-1;  
  
	If not exists(Select * from tbl_cd_CustomDashboard_Predifine(nolock) Where UserId=@UserId and CustomDashboard=@CustomDashboard and IsActive=1)
	Begin
		INSERT INTO tbl_cd_CustomDashboard_Predifine (CustomDashboard, UserId, IsPredifine, IsVisible, CustomDashboardOrder, IsActive, IsDelete,PreCustomDashboard)  
		VALUES (@CustomDashboard, @UserId, 0, 1, SCOPE_IDENTITY(), @IsActive, @IsDelete,@CustomDashboard);  
      
		SET @NewDashboardId = SCOPE_IDENTITY();  
  
		UPDATE tbl_cd_CustomDashboard_Predifine  SET CustomDashboardOrder = @NewDashboardId  WHERE Id = @NewDashboardId;   
	End

	Select @NewDashboardId as DashboardId
END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_cd_SavedTiles]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_cd_SavedTiles] --335    
(    
 @UserId Bigint,
 @customDashboardId bigint,
 @IsFromManage bit
)    
as    
 Begin    
	if(@IsFromManage = 1)
	begin
      SELECT tcr.ReportName, tct.SectionID, tct.PositionX, tct.PositionY, tct.Width, tct.Height, 
	  tct.Value, tct.UserId,tcrt.Type 
	  from tbl_cd_TilesMaster as tct with(nolock)
	  left join tbl_cd_Report as tcr with(nolock) on tct.ReportName = tcr.ReportName 
	  left join tbl_cd_ReportType as tcrt with(nolock) on tcr.TypeId = tcrt.TypeId 
	  WHERE UserId = @UserId AND CustomDashboardId = @customDashboardId;
	end
	else 
	begin
	  SELECT tcs.SectionName, tct.ReportName, tct.SectionID, tct.PositionX, tct.PositionY, tct.Width, 
	  tct.Height, tct.Value, tct.UserId,tcr.TypeId 
	  FROM tbl_cd_TilesMaster as tct with(nolock)
	  left join tbl_cd_Section as tcs with(nolock) on tct.SectionID = tcs.SectionID 
	  left join tbl_cd_Report as tcr with(nolock) on tcr.SectionID = tct.SectionID 
	  and tcr.ReportName = tct.ReportName 
	  WHERE tct.UserId = @UserId AND tct.CustomDashboardId = @customDashboardId;
	end
 End 



GO

