/* ============================================================
   Procedure: [dbo].[usp_ce_GetenerateCustomEventFromWebhook]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ce_GetenerateCustomEventFromWebhook](  
 @CERequestId bigint  
)  
as  
begin  
  
 --declare   
 -- @CERequestId bigint = 329  
  
 declare   
  @identifier nvarchar(255) = '',  
  @mobileNo nvarchar(255) = '',  
  @emailId nvarchar(255) = '',  
  @entityNo nvarchar(255) = '',  
  @EventName nvarchar(255)  
  
 declare   
  @RequestJSON nvarchar(max) = '',  
  @ParentId bigint =0 ;  
  
 select @RequestJSON = RequestJson, @ParentId = ParentId from tbl_ce_EventWebhook(nolock)   
   where Id = @CERequestId  
  
 --drop table if exists #tempPropertyName  
 --select * into #tempPropertyName from openjson(@RequestJSON)  
  
 --select  @identifier = [value] from #tempPropertyName where [key] = 'EventIdentifier'  
 --select  @mobileNo = [value] from #tempPropertyName where [key] = 'EventIdentifier'  
 --select  @entityNo = [value] from #tempPropertyName where [key] = 'EventIdentifier'  
 --select  @EventName = [value] from #tempPropertyName where [key] = 'EventIdentifier'  
 --select  @emailId = [value] from #tempPropertyName where [key] = 'EventIdentifier'  
  
  
 select   
  @identifier = Identifier,  
  @mobileNo = MobileNo,  
  @entityNo = EntityNo,  
  @EventName = EventName,  
  @emailId = EmailId  
 from openjson(lower(@RequestJSON)) with (  
  EventName nvarchar(255) '$.eventidentifier',  
  Identifier nvarchar(255) '$.entityidentifier',  
  MobileNo nvarchar(255) '$.mobileno',  
  EntityNo nvarchar(255) '$.entityno',  
  EmailId nvarchar(255) '$.emailId'  
 )  
  
 select  @EventName, @identifier  
  
 declare @EventId bigint, @EntityId bigint, @EntityName nvarchar(255), @EventTemplate nvarchar(max), @EventSettingJSON nvarchar(max)  
  
 declare @WebhookProperty nvarchar(max), @ColumnMapping nvarchar(max), @ActionName nvarchar(255), @ErrorDescription nvarchar(max)  
   
  
 if(not exists(select * from ActivityMaster(nolock)   
  where  ParentId = @ParentId and EventName = @EventName   
  and IsPredefind = 0 and IsActive = 1 ))  
 begin  
  exec usp_ce_UpdateCustomEvent @CERequestId, 3, 'EventName not found', 0, '', 0 
  return;  
 end  
 else  
 begin  
  select @EventId = ID, @EventName = EventName, @EntityName = context, @EventTemplate = EventTemplate, @EventSettingJSON = UiSettingJSON  
  from ActivityMaster(nolock) where ParentId = @ParentId and   
  EventName = @EventName and IsPredefind = 0 and IsActive = 1   
 end  
  
 print @EntityName  
  
 update tbl_ce_EventWebhook set EventId = @EventId where Id = @CERequestId   
  
 if(@identifier = 'mobileno' and ISNULL(@mobileNo, '') = '')  
 begin  
  print 'MobileNo not supplied'  
  exec usp_ce_UpdateCustomEvent @CERequestId, 3, 'MobileNo not supplied', @EventId, '', 0 
  return;  
 end  
  
 if(@identifier = 'emailid' and ISNULL(@emailId, '') = '')  
 begin  
  print 'EmailId not supplied'  
  exec usp_ce_UpdateCustomEvent @CERequestId, 3, 'EmailId not supplied', @EventId, '', 0
  return;  
 end  
  
 if(@identifier = 'entityNo' and ISNULL(@entityNo, '') = '')  
 begin  
  print 'EntityNo not supplied'  
  exec usp_ce_UpdateCustomEvent @CERequestId, 3, 'EntityNo not supplied', @EventId, '', 0  
  return;  
 end  
  
 if(@EntityName = 'lead')  
 begin  
    
  print concat('lead, => @mobileNo => ', @mobileNo)  
  print concat('lead, => @identifier => ', @identifier)  
  print concat('lead, => @ParentId => ', @ParentId)  
  
  
  select top 1 @EntityId = ulme_id from Userleads_Mobile_Email(nolock) where Parentid = @ParentId   
   and 1 = ( case when @identifier = 'mobileno' and Mobile = @mobileNo then 1  
     when @identifier = 'entityno' and leadno = @entityNo then 1  
     when @identifier = 'emailid' and email = @entityNo then 1  
    else 0 end) order by ulme_id desc  
 end  
  
 if(@EntityName = 'enquiry')  
 begin  
  print 'enquiry'  
  
  select top 1 @EntityId = enquiryid from Userenquiry_Mobile_Email(nolock) where Parentid = @ParentId   
   and 1 = ( case when @identifier = 'mobileno' and Mobile = @mobileNo then 1  
     when @identifier = 'entityno' and enquiryid = @entityNo then 1  
     when @identifier = 'emailid' and email = @entityNo then 1  
    else 0 end) order by enquiryid desc  
 end  
  
 select   
  @WebhookProperty = WebhookProperty,  
  @ColumnMapping = ColumnMapping,  
  @ActionName = ActionName  
  from openjson (@EventSettingJSON) with (  
   WebhookProperty nvarchar(max) '$.WebhookProperty' as json,  
   ActionName nvarchar(max) '$.ColumnMapping.ActionName',  
   ColumnMapping nvarchar(max)  '$.ColumnMapping' as json)  
  
  
 --if( isnull(@EntityId, 0) = 0 and @ActionName = 'failure')  
 if( isnull(@EntityId, 0) = 0)  
 begin  
  set @ErrorDescription = concat(@EntityName, ' not found');  
  exec usp_ce_UpdateCustomEvent @CERequestId, 3, @ErrorDescription, @EventId, '', 0
  return  
 end  
  
 if(isnull(@EntityId, 0) > 0)  
 begin  
    
    
  
  declare @ReplaceEventTemplate nvarchar(max)   
  
  exec usp_replaceentityplaceholders   
   @EntityId, @EntityName, @EventTemplate , @strvalue = @ReplaceEventTemplate OUTPUT       
  
  
  select @ReplaceEventTemplate = REPLACE(@ReplaceEventTemplate COLLATE SQL_Latin1_General_Cp1_CI_AI, concat('#', @EventName, '.', [key], '#'), isnull([value], ''))   
   from openjson( @RequestJSON  
  ) where [key] not in ('EventIdentifier', 'EntityIdentifier', 'MobileNo', 'EmailId', 'EntityNo')  
  
  print @ReplaceEventTemplate   
  
  exec UspSaveEntityActivity_withid   
   @EntityName,    
   @EntityID,    
   @ParentId,    
   @ParentId,    
   @ReplaceEventTemplate,                     
   @EventName,    
   'tbl_ce_EventWebhook',    
   @CERequestId  

    exec usp_ce_UpdateCustomEvent @CERequestId, 1, '', @EventId, @EntityName, @EntityID
  
 end  
  
  
 update tbl_ce_EventWebhook set   
  EntityId = @EntityId,   
  EntityType  = @EntityName,  
  IsProcess = 1,  
  ErrorDescription = ''    
 where Id = @CERequestId   
  
 update ActivityMaster set SuccessCount = isnull(SuccessCount, 0) + 1 where Id = @EventId  
  
 --select @EventId, @EntityName, @EntityId, @ErrorDescription  
 --select @identifier, @mobileNo, @entityNo, @EventName, @emailId  
  
end  



GO

/* ============================================================
   Procedure: [dbo].[usp_ce_GetenerateCustomEventManually]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_ce_GetenerateCustomEventManually](
	@CERequestId bigint,
	@ParentId bigint,
	@RequestJSON nvarchar(max)
)
as
begin

--declare 
--	@CERequestId bigint = 1

	begin transaction
	begin try
		
		declare 
			@identifier nvarchar(255) = '',
			@mobileNo nvarchar(255) = '',
			@emailId nvarchar(255) = '',
			@entityNo nvarchar(255) = '',
			@EventName nvarchar(255)

		--declare 
		--	@RequestJSON nvarchar(max) = '',
		--	@ParentId bigint =0 ;

		--select @RequestJSON = RequestJson, 
		--@ParentId = ParentId from tbl_ce_EventWebhook(nolock) 
		--		where Id = @CERequestId

		select 
			@identifier = Identifier,
			@mobileNo = MobileNo,
			@entityNo = EntityNo,
			@EventName = EventName,
			@emailId = EmailId
		from openjson(@RequestJSON) with (
			EventName nvarchar(255) '$.EventIdentifier',
			Identifier nvarchar(255) '$.EntityIdentifier',
			MobileNo nvarchar(255) '$.MobileNo',
			EntityNo nvarchar(255) '$.EntityNo',
			EmailId nvarchar(255) '$.EmailId'
		)

		declare @EventId bigint, @EntityId bigint, @EntityName nvarchar(255), @EventTemplate nvarchar(max), @EventSettingJSON nvarchar(max)

		declare @WebhookProperty nvarchar(max), @ColumnMapping nvarchar(max), @ActionName nvarchar(255), @ErrorDescription nvarchar(max)
	

		if(not exists(select * from ActivityMaster(nolock) 
			where  ParentId = @ParentId and EventName = @EventName 
			and IsPredefind = 0 and IsActive = 1 ))
		begin
			exec usp_ce_UpdateCustomEvent @CERequestId, 3, 'EventName not found', 0, '', 0
			return;
		end
		else
		begin
			select @EventId = ID, @EventName = EventName, @EntityName = EventType, @EventTemplate = EventTemplate, @EventSettingJSON = UiSettingJSON
			from ActivityMaster(nolock) where ParentId = @ParentId and 
			EventName = @EventName and IsPredefind = 0 and IsActive = 1 
		end


		update tbl_ce_EventWebhook set 
			EventId = @EventId
		where Id = @CERequestId 

		if(@identifier = 'mobileno' and ISNULL(@mobileNo, '') = '')
		begin
			exec usp_ce_UpdateCustomEvent @CERequestId, 3, 'MobileNo not supplied', @EventId, '', 0
			return;
		end

		if(@identifier = 'emailid' and ISNULL(@emailId, '') = '')
		begin
			exec usp_ce_UpdateCustomEvent @CERequestId, 3, 'EmailId not supplied', @EventId, '', 0
			return;
		end

		if(@identifier = 'entityNo' and ISNULL(@entityNo, '') = '')
		begin
			exec usp_ce_UpdateCustomEvent @CERequestId, 3, 'EmailId not supplied', @EventId, '', 0
			return;
		end

		if(@EntityName = 'lead')
		begin
			select top 1 @EntityId = ulme_id from Userleads_Mobile_Email(nolock) where Parentid = @ParentId 
				and 1 = ( case when @identifier = 'mobileno' and Mobile = @mobileNo then 1
						when @identifier = 'entityno' and leadno = @entityNo then 1
						when @identifier = 'emailid' and email = @entityNo then 1
					else 0 end) order by ulme_id desc
		end

		if(@EntityName = 'enquiry')
		begin
			select top 1 @EntityId = enquiryid from Userenquiry_Mobile_Email(nolock) where Parentid = @ParentId 
				and 1 = ( case when @identifier = 'mobileno' and Mobile = @mobileNo then 1
						when @identifier = 'entityno' and enquiryid = @entityNo then 1
						when @identifier = 'emailid' and email = @entityNo then 1
					else 0 end) order by enquiryid desc
		end

		select 
			@WebhookProperty = WebhookProperty,
			@ColumnMapping = ColumnMapping,
			@ActionName = ActionName
		 from openjson (@EventSettingJSON) with (
				WebhookProperty nvarchar(max) '$.WebhookProperty' as json,
				ActionName nvarchar(max) '$.ColumnMapping.ActionName',
				ColumnMapping nvarchar(max)  '$.ColumnMapping' as json)

		if( isnull(@EntityId, 0) = 0 and @ActionName = 'failure')
		begin
			set @ErrorDescription = concat(@EntityName, ' not found');
			exec usp_ce_UpdateCustomEvent @CERequestId, 3, @ErrorDescription, @EventId, '', 0
			return
		end

		if(isnull(@EntityId, 0) > 0)
		begin
		
			declare @ReplaceEventTemplate nvarchar(max) 

			exec usp_replaceentityplaceholders 
				@EntityId, @EntityName, @EventTemplate , @ReplaceEventTemplate OUTPUT     

			select @ReplaceEventTemplate = REPLACE(@ReplaceEventTemplate, concat('#', @EventName, '.', [key], '#'), [value]) 
				from openjson( @RequestJSON
			) where [key] not in ('EventIdentifier', 'EntityIdentifier', 'MobileNo', 'EmailId', 'EntityNo')

			print @ReplaceEventTemplate
			
			exec UspSaveEntityActivity_withid 
				@EntityName,  
				@EntityID,  
				@ParentId,  
				@ParentId,  
				@ReplaceEventTemplate,                   
				@EventName,  
				'tbl_ce_EventWebhook',  
				@CERequestId

			 exec usp_ce_UpdateCustomEvent @CERequestId, 1, '', @EventId, @EntityName, @EntityID

		end


		update tbl_ce_EventWebhook set 
			EntityId = @EntityId, 
			EntityType  = @EntityName,
			IsProcess = 1,
			ErrorDescription = ''		
		where Id = @CERequestId 

		update ActivityMaster set SuccessCount = isnull(SuccessCount, 0) + 1 where Id = @EventId
		commit transaction
		--select @EventId, @EntityName, @EntityId, @ErrorDescription
		--select @identifier, @mobileNo, @entityNo, @EventName, @emailId
		select 1
	end try
	begin catch
		rollback transaction
		select 0
	end catch
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ce_GetenerateCustomEventManually_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ce_GetenerateCustomEventManually_new]
(
    @CERequestId BIGINT,
    @ParentId BIGINT,
    @RequestJSON NVARCHAR(MAX)
)
AS
BEGIN

    SET NOCOUNT ON;

    BEGIN TRY

        BEGIN TRANSACTION;

        DECLARE 
            @identifier NVARCHAR(255) = '',
            @mobileNo NVARCHAR(255) = '',
            @emailId NVARCHAR(255) = '',
            @entityNo NVARCHAR(255) = '',
            @EventName NVARCHAR(255);

        SELECT 
            @identifier = LOWER(ISNULL(Identifier, '')),
            @mobileNo = ISNULL(MobileNo, ''),
            @entityNo = ISNULL(EntityNo, ''),
            @EventName = ISNULL(EventName, ''),
            @emailId = ISNULL(EmailId, '')
        FROM OPENJSON(@RequestJSON)
        WITH (
            EventName NVARCHAR(255) '$.EventIdentifier',
            Identifier NVARCHAR(255) '$.EntityIdentifier',
            MobileNo NVARCHAR(255) '$.MobileNo',
            EntityNo NVARCHAR(255) '$.EntityNo',
            EmailId NVARCHAR(255) '$.EmailId'
        );

        PRINT CONCAT('@identifier=>', @identifier);
        PRINT CONCAT('@mobileNo=>', @mobileNo);
        PRINT CONCAT('@entityNo=>', @entityNo);
        PRINT CONCAT('@EventName=>', @EventName);
        PRINT CONCAT('@emailId=>', @emailId);

        DECLARE 
            @EventId BIGINT,
            @EntityId BIGINT,
            @EntityName NVARCHAR(255),
            @EventTemplate NVARCHAR(MAX),
            @EventSettingJSON NVARCHAR(MAX);

        DECLARE 
            @WebhookProperty NVARCHAR(MAX),
            @ColumnMapping NVARCHAR(MAX),
            @ActionName NVARCHAR(255),
            @ErrorDescription NVARCHAR(MAX);

        ------------------------------------------------------------
        -- Event Validation
        ------------------------------------------------------------

        IF NOT EXISTS
        (
            SELECT 1
            FROM ActivityMaster(NOLOCK)
            WHERE ParentId = @ParentId
                AND EventName = @EventName
                AND IsPredefind = 0
                AND IsActive = 1
        )
        BEGIN

            EXEC usp_ce_UpdateCustomEvent
                @CERequestId,
                3,
                'EventName not found',
                0,
                '',
                0;

            ROLLBACK TRANSACTION;

            SELECT 0;

            RETURN;
        END
        ELSE
        BEGIN

            SELECT 
                @EventId = ID,
                @EventName = EventName,
                @EntityName = EventType,
                @EventTemplate = EventTemplate,
                @EventSettingJSON = UiSettingJSON
            FROM ActivityMaster(NOLOCK)
            WHERE ParentId = @ParentId
                AND EventName = @EventName
                AND IsPredefind = 0
                AND IsActive = 1;

        END

        ------------------------------------------------------------
        -- Update Event Id
        ------------------------------------------------------------

        UPDATE tbl_ce_EventWebhook
        SET EventId = @EventId
        WHERE Id = @CERequestId;

        ------------------------------------------------------------
        -- Identifier Validation
        ------------------------------------------------------------

        IF(@identifier = 'mobileno' AND ISNULL(@mobileNo, '') = '')
        BEGIN

            EXEC usp_ce_UpdateCustomEvent
                @CERequestId,
                3,
                'MobileNo not supplied',
                @EventId,
                '',
                0;

            ROLLBACK TRANSACTION;

            SELECT 0;

            RETURN;
        END

        IF(@identifier = 'emailid' AND ISNULL(@emailId, '') = '')
        BEGIN

            EXEC usp_ce_UpdateCustomEvent
                @CERequestId,
                3,
                'EmailId not supplied',
                @EventId,
                '',
                0;

            ROLLBACK TRANSACTION;

            SELECT 0;

            RETURN;
        END

        IF(@identifier = 'entityno' AND ISNULL(@entityNo, '') = '')
        BEGIN

            EXEC usp_ce_UpdateCustomEvent
                @CERequestId,
                3,
                'EntityNo not supplied',
                @EventId,
                '',
                0;

            ROLLBACK TRANSACTION;

            SELECT 0;

            RETURN;
        END

        ------------------------------------------------------------
        -- Get Lead Entity Id
        ------------------------------------------------------------

        IF(@EntityName = 'lead')
        BEGIN

            SELECT TOP 1
                @EntityId = ulme_id
            FROM Userleads_Mobile_Email(NOLOCK)
            WHERE Parentid = @ParentId
                AND 1 =
                (
                    CASE
                        WHEN @identifier = 'mobileno'
                             AND Mobile = @mobileNo
                        THEN 1

                        WHEN @identifier = 'entityno'
                             AND LeadNo = @entityNo
                        THEN 1

                        WHEN @identifier = 'emailid'
                             AND Email = @emailId
                        THEN 1

                        ELSE 0
                    END
                )
            ORDER BY ulme_id DESC;

        END

        ------------------------------------------------------------
        -- Get Enquiry Entity Id
        ------------------------------------------------------------

        IF(@EntityName = 'enquiry')
        BEGIN

            SELECT TOP 1
                @EntityId = enquiryid
            FROM Userenquiry_Mobile_Email(NOLOCK)
            WHERE Parentid = @ParentId
                AND 1 =
                (
                    CASE
                        WHEN @identifier = 'mobileno'
                             AND Mobile = @mobileNo
                        THEN 1

                        WHEN @identifier = 'entityno'
                             AND enquiryid = @entityNo
                        THEN 1

                        WHEN @identifier = 'emailid'
                             AND Email = @emailId
                        THEN 1

                        ELSE 0
                    END
                )
            ORDER BY enquiryid DESC;

        END

        ------------------------------------------------------------
        -- Read UI Setting JSON
        ------------------------------------------------------------

        SELECT 
            @WebhookProperty = WebhookProperty,
            @ColumnMapping = ColumnMapping,
            @ActionName = ActionName
        FROM OPENJSON(@EventSettingJSON)
        WITH (
            WebhookProperty NVARCHAR(MAX) '$.WebhookProperty' AS JSON,
            ActionName NVARCHAR(MAX) '$.ColumnMapping.ActionName',
            ColumnMapping NVARCHAR(MAX) '$.ColumnMapping' AS JSON
        );

        ------------------------------------------------------------
        -- Entity Not Found
        ------------------------------------------------------------

        IF(ISNULL(@EntityId, 0) = 0 AND @ActionName = 'failure')
        BEGIN

            SET @ErrorDescription = CONCAT(@EntityName, ' not found');

            EXEC usp_ce_UpdateCustomEvent
                @CERequestId,
                3,
                @ErrorDescription,
                @EventId,
                '',
                0;

            ROLLBACK TRANSACTION;

            SELECT 0;

            RETURN;

        END

        ------------------------------------------------------------
        -- Generate Activity
        ------------------------------------------------------------

        IF(ISNULL(@EntityId, 0) > 0)
        BEGIN

            DECLARE @ReplaceEventTemplate NVARCHAR(MAX);

            EXEC usp_replaceentityplaceholders
                @EntityId,
                @EntityName,
                @EventTemplate,
                @ReplaceEventTemplate OUTPUT;

            SELECT 
                @ReplaceEventTemplate =
                    REPLACE(
                        @ReplaceEventTemplate,
                        CONCAT('#', @EventName, '.', [key], '#'),
                        CAST([value] AS NVARCHAR(MAX))
                    )
            FROM OPENJSON(@RequestJSON)
            WHERE [key] NOT IN
            (
                'EventIdentifier',
                'EntityIdentifier',
                'MobileNo',
                'EmailId',
                'EntityNo'
            );

            PRINT @ReplaceEventTemplate;

            EXEC UspSaveEntityActivity_withid
                @EntityName,
                @EntityID,
                @ParentId,
                @ParentId,
                @ReplaceEventTemplate,
                @EventName,
                'tbl_ce_EventWebhook',
                @CERequestId;

            EXEC usp_ce_UpdateCustomEvent
                @CERequestId,
                1,
                '',
                @EventId,
                @EntityName,
                @EntityID;

        END

        ------------------------------------------------------------
        -- Final Update
        ------------------------------------------------------------

        UPDATE tbl_ce_EventWebhook
        SET
            EntityId = @EntityId,
            EntityType = @EntityName,
            IsProcess = 1,
            ErrorDescription = ''
        WHERE Id = @CERequestId;

        UPDATE ActivityMaster
        SET SuccessCount = ISNULL(SuccessCount, 0) + 1
        WHERE Id = @EventId;

        COMMIT TRANSACTION;

        SELECT 1;

    END TRY
    BEGIN CATCH

        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;

        DECLARE @ErrorMessage NVARCHAR(MAX);

        SET @ErrorMessage = ERROR_MESSAGE();

        PRINT @ErrorMessage;

        Select @EventId=ISNULL(@EventId, 0)

        EXEC usp_ce_UpdateCustomEvent
            @CERequestId,
            3,
            @ErrorMessage,
            @EventId,
            '',
            0;

        SELECT 0;

    END CATCH

END



GO

/* ============================================================
   Procedure: [dbo].[usp_ce_GetEventDetailById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ce_GetEventDetailById](
	@UserId bigint,
	@Offset int,
	@PageSize int,
	@FilterText nvarchar(max) = null
)
as
begin
	
	--declare 
	--	@UserId bigint = 34594,
	--	@Offset int = 0,
	--	@PageSize int = 20,
	--	@FilterText nvarchar(max) = 'test'

	declare  @ParentId bigint, @StartPoint int, @EndPoint int
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	set @StartPoint = (@Offset + 1)
	set @EndPoint = (@StartPoint + @PageSize - 1)

	select rNo, TotalRow, a.Id, EventName, EventTemplate, EventType, IsPredefind, IsActive, IsDeleted, DeletedOn, 
			ParentId, CreatedBy, CreatedOn, UiSettingJSON, LeadSettingJSON, SuccessCount, FailCount
		from ( select m.Id, m.EventName, m.EventTemplate, m.EventType, m.IsPredefind, m.IsActive, m.IsDeleted, m.DeletedOn, 
			m.ParentId, (CONCAT(c.User_Login, '(', c.FName, ' ', c.LName, ')')) as [CreatedBy], m.CreatedOn, m.UiSettingJSON, m.LeadSettingJSON,
			m.SuccessCount,
			m.FailCount,
			ROW_NUMBER() over(partition by (select null) order by m.Id desc) as [rNo],
			COUNT(*) over() as TotalRow
		from ActivityMaster(nolock) m
			left join User_Detail(nolock) c on m.CreatedBy = c.User_ID		
		where  ISNULL(m.ParentId, 0) in (0, @ParentId)
			and EventType = 'custom'
			and m.IsDeleted = 0 and IsPredefind = 0 
				and (
					m.EventName like '%'+ isnull(@FilterText, '') +'%'
					or m.EventTemplate like '%'+ isnull(@FilterText, '') +'%'
				)
	) a where a.rNo between @StartPoint and @EndPoint

end



