/* ============================================================
   Procedure: [dbo].[usp_ce_UpdateCustomEvent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ce_UpdateCustomEvent](
	@RequestId bigint,
	@ProcessId int,
	@errorDescription nvarchar(max),
	@EventId bigint,
	@EntityName nvarchar(255) = '',  
	@EntityId bigint = 0
)
as
begin
	
	declare @RequestJSON nvarchar(max), @ParentId bigint = 0
	
	select @RequestJSON = RequestJson, @ParentId = ParentId
		from tbl_ce_EventWebhook(nolock) where  Id = @RequestId
	
	update tbl_ce_EventWebhook set 
		IsProcess = @ProcessId,
		ErrorDescription = @errorDescription
	where  Id = @RequestId


	declare @interactionTable nvarchar(255), @interactionId nvarchar(255)
	if(lower(trim(@EntityName)) = 'lead')
	begin
		set @interactionTable = 'tbl_LeadEventHistory'
		select top 1 @interactionId = Historyid from tbl_LeadEventHistory(nolock) 
			where reftables = 'tbl_ce_EventWebhook' and refids = @RequestId
				order by HistoryId desc
	end

	if(lower(trim(@EntityName)) = 'enquiry')
	begin
		set @interactionTable = 'tbl_EnquiryEventHistory'
		select top 1 @interactionId = Historyid from tbl_EnquiryEventHistory(nolock) 
			where reftables = 'tbl_ce_EventWebhook' and refids = @RequestId
				order by HistoryId desc
	end



	declare @lcIdentityId bigint = 0;
	exec usp_ce_SaveCustomEventExecutionHistory
		@ceRequestJson = @RequestJSON,
		@ceErrorDescription = @errorDescription,
		@ceParentId  = @ParentId,
		@ceRefTable = 'tbl_ce_EventWebhook',
		@ceRefId = @RequestId,
		@ceEntityName = @EntityName,
		@ceEntityId = @EntityId,
		@ceInteractionTable =  @interactionTable,
		@ceInteractionId = @interactionId,
		@ceIsProcess = @ProcessId,
		@ceActivityMasterId = @EventId,
		@ceIdentityId = @lcIdentityId output
	
	if(@EventId > 0)
	begin
		update ActivityMaster set FailCount  = isnull(FailCount, 0) + 1 where Id = @EventId
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ce_UpdateCustomEventExecutionHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ce_UpdateCustomEventExecutionHistory](
	@Id bigint,
	@EntityName nvarchar(max)
)
as
begin
	
	declare @eventHistoryId bigint = 0, @eventInteractionTable nvarchar(255) = ''

	if(@EntityName = 'lead')
	begin
		select top 1 @eventHistoryId = HistoryID, @eventInteractionTable = 'tbl_LeadEventHistory' 
		from tbl_LeadEventHistory(nolock) where
			reftables = 'tbl_ce_CustomEventExecutionHistory' and  refids = @Id
		order by HistoryID desc
	end

	if(@EntityName = 'enquriy')
	begin
		select top 1 @eventHistoryId = HistoryID, @eventInteractionTable = 'tbl_EnquiryEventHistory' 
		from tbl_EnquiryEventHistory(nolock) where
			reftables = 'tbl_ce_CustomEventExecutionHistory' and  refids = @Id
		order by HistoryID desc
	end

	if(isnull(@eventHistoryId, 0) > 0)
	begin
		update tbl_ce_CustomEventExecutionHistory set 
			InteractionId = @eventHistoryId,
			InterationTable = @eventInteractionTable where id = @Id
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ChangeCommissionSlabsStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ChangeCommissionSlabsStatus]
@Commissionid int,
@status int
as    
begin
declare @duplicatecommission int=(select r.id from Referrer_Payout_Rates r join Referrer_Payout_Rates r1 on r1.ID=@commissionid  where r.ServiceReferred=r1.ServiceReferred and (r.userGroup is null or r.UserGroup=r1.usergroup ) and r.status=1 and (r.ValidFrom between r1.ValidFrom and r1.ValidTill or
r.Validtill between r1.ValidFrom and r1.ValidTill or r1.ValidFrom between r.ValidFrom and r.validtill or r1.validtill between r.ValidFrom and r.ValidTill))
if @duplicatecommission is not null
begin
Select 'This slab coincides with another Slab named ' + (select slabname from Referrer_Payout_Rates where ID=@duplicatecommission) + ' . Kindly change the service,usergroup or validity or deactive the last slab first'
end
else
begin
update Referrer_Payout_Rates set status=@status where ID=@Commissionid
Select 'Record status changed to '+ (select case when @status=1 then 'activated' else 'deactivated' end) +' successfully'
end
end





 






 



