/* ============================================================
   Procedure: [dbo].[USP_ChangePassword_App]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_ChangePassword_App]    
@UserLogin nvarchar(50),    
@OldPwd nvarchar(50),    
@NewPwd nvarchar(50)    
as  
DECLARE @user_id bigint=(select User_ID from User_Detail where  User_Login=@UserLogin)
Declare @count int    
select @count=count(*) from User_Detail(nolock) where user_login=@UserLogin and pwd=@OldPwd    
if @count>0    
Begin    
update User_Detail set pwd=@NewPwd, LastModified = GETDATE() where user_login=@UserLogin and pwd=@OldPwd    
select 'Password changed Successfully' as msg   

 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM User_Detail(NOLOCK)  
   WHERE user_login = @UserLogin and pwd=@OldPwd 
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id  
  ,@Activity_type = 'API_Updt_Password'  
  ,@ActionType = 'U'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'User_Detail'  
END    
else    
Begin    
select 'Wrong Password' as msg    
END    


