CREATE   PROCEDURE dbo.Usp_ChangeStatusAdmnNTFCN (
	@Status INT
	,@EventID INT
	,@UserID BIGINT
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0

	SELECT @ParentID = isnull(ParentID, user_id)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID

	UPDATE adminnotificationsettings
	SET isactive = @Status
	WHERE ans_eventid = @EventID
		AND parentid = @ParentID

	SELECT 'Status Changed'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM adminnotificationsettings
			WHERE ans_eventid = @EventID
				AND parentid = @ParentID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'Updt_ntfcn_sts'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'adminnotificationsettings'
END



