    select @ProfilePicturePath = isnull(ProfilePicturePath,'') from User_Detail WHERE merchant_code=@merchant_code         
    end               
      
    select @merchant_User_ID as MerchantUserID, @merchant_name as MerchantName, @merchant_website as MerchantWebsite       
    ,@ProfilePicturePath as ProfilePicturePath, User_ID,Pwd,CAST(CAST(Mobile AS DECIMAL(20))AS VARCHAR(20))       
    as Mobile,Status,'Login Successful' as Msg, UserType, user_login, Userfilter from User_Detail       
    WHERE user_login=@Mobile and User_ID=@User_ID           
             
    update DBO.User_Detail set OnlineStatus=1,DeviceID=@DeviceID,Version=@Version WHERE user_login=@Mobile and  Pwd=@Pwd      
   END                  
 END 



GO

