/* ============================================================
   Procedure: [dbo].[usp_check_loginApi]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_check_loginApi  --'sms19','NewChoiceIndia','www.kit19.com'                         
 (
     @user_id VARCHAR(50),
     @password VARCHAR(50),
     @url VARCHAR(50)
 )                          
AS                          
DECLARE @type VARCHAR(2)                        
SET @type = (
        SELECT User_Detail.type
        FROM   User_Detail
               JOIN Reseller_Detail
                    ON  User_Detail.M_ID = Reseller_Detail.Reseller_ID
        WHERE  User_Detail.User_Login = @user_id
               AND User_Detail.Pwd = @password
               AND Reseller_Detail.Domain = @url
    )                --select  @type        
                        
IF @type = '0'
   OR @type = '2'
BEGIN
    SELECT User_Detail.User_Login,
           User_Detail.User_ID,
           User_Detail.Pwd,
           Reseller_Detail.Reseller_ID ,
           case User_Detail.userfilter when 'MT' then 'MOMT' when 'MTIX_PRO' then 'Promotional' when 'TRANS' then 'Transactional'   
			when 'OPEN' then 'OPEN DND' when 'TR_CURVE' then 'SCRUB' when 'MT_TRANS' then 'Transactional' when 'MTIX_TR' then 'Transactional'   
			when 'MTIX_TRC' then 'SCRUB' WHEN 'CRITICAL' THEN 'CRITICAL' else 'Promotional' end as AcType
    FROM   User_Detail
           JOIN Reseller_Detail
                ON  User_Detail.M_ID = Reseller_Detail.Reseller_ID
    WHERE  User_Detail.User_Login = @user_id
           AND User_Detail.Pwd = @password
           AND Reseller_Detail.Domain = @url
           AND User_Detail.status = 1
END
ELSE
BEGIN
    SELECT User_Detail.User_Login,
           User_Detail.User_ID,
           User_Detail.Pwd,
           Reseller_Detail.Reseller_ID,
           case User_Detail.userfilter when 'MT' then 'MOMT' when 'MTIX_PRO' then 'Promotional' when 'TRANS' then 'Transactional'   
			when 'OPEN' then 'OPEN DND' when 'TR_CURVE' then 'SCRUB' when 'MT_TRANS' then 'Transactional' when 'MTIX_TR' then 'Transactional'   
			when 'MTIX_TRC' then 'SCRUB' WHEN 'CRITICAL' THEN 'CRITICAL' else 'Promotional' end as AcType
    FROM   User_Detail
           JOIN Reseller_Detail
                ON  User_Detail.User_ID = Reseller_Detail.User_ID
    WHERE  User_Detail.User_Login = @user_id
           AND User_Detail.Pwd = @password
           AND Reseller_Detail.Domain = @url
           AND User_Detail.status = 1
END


GO

