/* ============================================================
   Procedure: [dbo].[usp_check_loginNew1_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_check_loginNew1_New](  
 @user_id varchar(255),    
 @password varchar(255),  
 @url varchar(255)  
)  
as  
begin  
  
 --declare  
 --  @user_id varchar(255)='kmukesh343',    
 --  @password varchar(255)='Correct@2024',  
 --  @url varchar(255)='www.kit19.com'  
  
  
 print 'DATA Init'  
  
 declare @type varchar(2),@turl varchar(50)='', @UserId bigint, @ParentId bigint, @View bit = 0, @M_ID bigint = 0, @resellerId bigint = 0  
   
 if(@url like '%localhost%' or @url like '%kit19web.azurewebsites.net%' or @url like '%.kit19.com')  
 begin  
 set @url  = 'www.kit19.com'  
 end  
  
 drop table if exists #allowDomain  
 create table #allowDomain(  
  resellerId bigint,  
  doaminName nvarchar(255)  
 )  
  
 select @url = replace(replace(replace(@url, 'https://', ''), 'www.', ''), 'http.', '')   
  
 if(exists(   
  select 1 from User_Detail(nolock) ud   
   where ud.User_Login = @user_id   
  and ud.Pwd COLLATE SQL_Latin1_General_CP1_CS_AS = @password and [Status] = 1  
 ))  
 begin  
  print 'correct username or password'  
  
  select top 1  @UserId = User_ID, @ParentId = ParentID, @M_ID = M_ID from User_Detail(nolock) ud   
    where ud.User_Login = @user_id and ud.Pwd COLLATE SQL_Latin1_General_CP1_CS_AS = @password and [Status] = 1 order by User_ID desc  
  
  insert into #allowDomain (resellerId, doaminName)  
  select Reseller_ID, replace(replace(replace(Domain, 'https://', ''), 'www.', ''), 'http://', '')   
   from Reseller_Detail(nolock) where  User_ID = @ParentId or Reseller_ID  = @M_ID  
    
  if(dbo.fn_userdomain(@ParentId) in ('', 'https://', 'http://' ))  
  begin  
   insert into #allowDomain (resellerId, doaminName)  
   select dbo.fn_getusermid(dbo.fn_userimmediatepartner(@ParentId)),   
    replace(replace(replace(dbo.fn_userdomain(dbo.fn_userimmediatepartner(@ParentId)),  
    'https://', ''), 'www.', ''), 'http://', '')   
  end  
  
  
  if(exists(select * from #allowDomain where doaminName = @url))  
  begin  
   print 'Domain allowed'  
  
   select @type = isnull(ud.type, ''), @UserId = isnull(ud.User_Id, 0) from User_Detail ud     
   join Reseller_Detail on ud.M_ID=Reseller_Detail.Reseller_ID                                 
    where ud.User_Login = @user_id and ud.Pwd = @password --and Reseller_Detail.Domain=@url  
  
   select top 1 @View = tuam.[View] from TBL_UA_RolePermissionMappingMaster (nolock) turm    
   inner join TBL_UA_EntityActionMappingMaster (nolock) tuam on turm.EntityActionMappingCode = tuam.EntityActionMappingCode    
   where turm.ModuleCode in ('PAG10300','PAG10317','PAG10320','PAG10321','PAG10323','PAG10324','PAG10331')  
    and turm.ParentId = @ParentId    
    
   PRINT CONCAT('@type: ', @type)   
  
  
   if(@type in (0, 2, 3, 4))                          
   begin                                
      
    select User_Detail.User_Login, User_Detail.Pwd AS [Pwd], Reseller_Detail.Reseller_ID, @View IsLocationTracking  
    from User_Detail join Reseller_Detail on User_Detail.M_ID=Reseller_Detail.Reseller_ID                                 
    where User_Detail.User_Login = @user_id   
     and User_Detail.Pwd COLLATE SQL_Latin1_General_CP1_CS_AS = @password and User_Detail.status=1                  
  
    exec USP_TBL_ET_GetDefaultRecord @UserId    
    
   end                                       
   else                            
   begin                            
    select User_Detail.User_Login, User_Detail.Pwd AS [Pwd], Reseller_Detail.Reseller_ID, @View IsLocationTracking   
    from User_Detail join Reseller_Detail on User_Detail.User_ID=Reseller_Detail.User_ID                                
    where User_Detail.User_Login = @user_id   
     and User_Detail.Pwd COLLATE SQL_Latin1_General_CP1_CS_AS = @password and Reseller_Detail.Domain=@url   
    and User_Detail.status=1                      
    exec USP_TBL_ET_GetDefaultRecord @UserId    
    
   end  
  end  
  else  
  begin  
   print 'Domain not allowed'  
   select ud.User_Login,ud.Pwd, 0 as [Reseller_ID], @View IsLocationTracking from User_Detail(nolock) ud where User_ID = 0  
  end  
 end  
 else  
 begin  
  print 'Incorrect username or password'  
  select ud.User_Login,ud.Pwd, 0 as [Reseller_ID], @View IsLocationTracking from User_Detail(nolock) ud where User_ID = 0  
 end  
end  


GO

