CREATE   PROCEDURE [dbo].[Usp_CheckAllParentVariantsColumns]
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT;
    DECLARE @TableName NVARCHAR(MAX);
    DECLARE @VariantsExists BIT;
    DECLARE @VCombinationExists BIT;

    -- Temporary table to store results
    CREATE TABLE #TempResults (
        ParentID BIGINT,
        TableExists BIT,
        VariantsJsonExists BIT,
        VCombinationJsonExists BIT
    );

    -- Cursor to loop through all ParentIDs
    DECLARE ParentCursor CURSOR FOR 
    SELECT DISTINCT ParentID FROM User_Detail WHERE ParentID IS NOT NULL;

    OPEN ParentCursor;
    
    FETCH NEXT FROM ParentCursor INTO @ParentId;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        -- Set table name dynamically
        SET @TableName = 'tbl_productmaster_' + CAST(@ParentId AS NVARCHAR);

        -- Initialize column existence flags
        SET @VariantsExists = 0;
        SET @VCombinationExists = 0;

        -- Check if table exists
        IF EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME = @TableName AND TABLE_CATALOG = DB_NAME())
        BEGIN
            -- Check if VariantsJson column exists
            IF EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TableName AND COLUMN_NAME = 'VariantsJson')
                SET @VariantsExists = 1;

            -- Check if VCombinationJson column exists
            IF EXISTS (SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TableName AND COLUMN_NAME = 'VCombinationJson')
                SET @VCombinationExists = 1;

            -- Insert result for existing table
            INSERT INTO #TempResults (ParentID, TableExists, VariantsJsonExists, VCombinationJsonExists)
            VALUES (@ParentId, 1, @VariantsExists, @VCombinationExists);
        END
        ELSE
        BEGIN
            -- Insert result for non-existing table
            INSERT INTO #TempResults (ParentID, TableExists, VariantsJsonExists, VCombinationJsonExists)
            VALUES (@ParentId, 0, 0, 0);
        END

        -- Fetch next ParentID
        FETCH NEXT FROM ParentCursor INTO @ParentId;
    END

    -- Close and deallocate cursor
    CLOSE ParentCursor;
    DEALLOCATE ParentCursor;

    -- Return results
    SELECT * FROM #TempResults ORDER BY ParentID;

    -- Drop temporary table
    DROP TABLE #TempResults;
END;


GO

