/* ============================================================
   Procedure: [dbo].[usp_CheckCustomButtons]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_CheckCustomButtons]  --46198,'Enquiries'
    @UserId BIGINT,  
    @ModuleName NVARCHAR(100)  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    DECLARE @ParentId BIGINT;  
    DECLARE @ModuleCode VARCHAR(50);  
    DECLARE @UserType NVARCHAR(50);  
  
    BEGIN TRY  
        -- Get ParentId and UserType from User_Detail table  
        SELECT @ParentId = ParentID, @UserType = UserType  
        FROM User_Detail (NOLOCK)  
        WHERE User_ID = @UserId;  
  
        IF @ParentId IS NULL OR @UserType IS NULL  
        BEGIN  
            -- User not found or UserType not found, return error message  
            THROW 51000, 'User not found or UserType is missing.', 1;  
        END;  
  
        -- Get ModuleCode from TBL_UA_ModuleMaster  
        SELECT @ModuleCode = ModuleCode  
        FROM TBL_UA_ModuleMaster (NOLOCK)  
        WHERE ModuleName = @ModuleName;  
  
        IF @ModuleCode IS NULL  
        BEGIN  
            -- Module not found, return error message  
            THROW 51001, 'Module not found.', 1;  
        END;  
  
        -- Temporary table to store roles  
        CREATE TABLE #UserRoles (  
            RoleId BIGINT,  
            RoleName NVARCHAR(255),  
            RoleCode NVARCHAR(255),  
            ParentId BIGINT  
        );  
  
        -- Get roles using the usp_UA_GetRoleByParentId stored procedure  
        INSERT INTO #UserRoles (RoleId, RoleName, RoleCode, ParentId)  
        EXEC usp_UA_GetRoleByParentId @ParentId = @ParentId;  
  
        -- Fetch custom buttons based on ModuleCode and UserRole from #UserRoles  
        SELECT   
            ButtonId,  
            ButtonName,   
            REPLACE(PlaceOnPage, ' ', '') AS PlaceOnPage,   
            ActionBePerform,   
            ActionDetails,  
            ButtonDisposition  
        FROM tbl_CB_CustomButtons (NOLOCK)  
        WHERE   
            ModuleCode = @ModuleCode AND IsActive=1  and ParentId=@ParentId
            AND EXISTS (  
                SELECT 1  
                FROM OPENJSON(UserType)  
                WHERE value IN (SELECT RoleId FROM #UserRoles)  
            );  
  
        -- Drop the temporary table  
        DROP TABLE #UserRoles;  
  
    END TRY  
    BEGIN CATCH  
        exec usp_InsertErrorInfo  
    END CATCH  
END;



GO

