/* ============================================================
   Procedure: [dbo].[usp_CheckEnquiryDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


----------------------------------
CREATE   PROCEDURE [dbo].[usp_CheckEnquiryDetail]
    @userId BIGINT,
    @attribute NVARCHAR(100),
    @operator NVARCHAR(50),
    @value NVARCHAR(100),
    @EnquiryID BIGINT
AS
BEGIN
    BEGIN TRY
        DECLARE @query NVARCHAR(MAX);
        
        -- Construct the dynamic SQL query
        SET @query = N'SELECT COUNT(*) FROM UserEnquiry (nolock) WHERE parentid = @userId AND EnquiryID = @EnquiryID AND ' 
                    + QUOTENAME(@attribute, '[') + ' ' + @operator + ' @value';
      
        -- Execute the dynamic SQL query with parameters
        EXEC sp_executesql @query,
            N'@userId BIGINT, @EnquiryID BIGINT, @value NVARCHAR(100)',
            @userId = @userId,
            @EnquiryID = @EnquiryID,
            @value = @value;
    END TRY
    BEGIN CATCH
        -- Handle the error
        DECLARE @ErrorMessage NVARCHAR(4000);
        DECLARE @ErrorSeverity INT;
        DECLARE @ErrorState INT;
        DECLARE @ErrorLine INT;
        DECLARE @ErrorProcedure NVARCHAR(200);
        
        -- Capture error details
        SELECT 
            @ErrorMessage = ERROR_MESSAGE(),
            @ErrorSeverity = ERROR_SEVERITY(),
            @ErrorState = ERROR_STATE(),
            @ErrorLine = ERROR_LINE(),
            @ErrorProcedure = ERROR_PROCEDURE();

        PRINT 'Error occurred: ' + @ErrorMessage;
        PRINT 'Error severity: ' + CAST(@ErrorSeverity AS NVARCHAR(10));
        PRINT 'Error state: ' + CAST(@ErrorState AS NVARCHAR(10));
        PRINT 'Error line: ' + CAST(@ErrorLine AS NVARCHAR(10));
        PRINT 'Error procedure: ' + @ErrorProcedure;

        -- Rethrow the error
        THROW;
    END CATCH
END



GO

