SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_CheckIfMicrositeExists_Cloud]   
(  
@pagename nvarchar(200)   
)            
AS   
begin   
  
             
if not exists(select top 1* from ClientPageDetail where PageName='www.kit19.com/' + @pagename  )              
 select 0--'No microsite found'  
else  
begin  

 Declare @UserID bigint = 0
 select @UserID = isnull(USER_ID,0) from ClientPageDetail where PageName='www.kit19.com/' + @pagename      
   
 if(exists(select 1 from Price_UserSubscriptionDetails where PlanEndDate >= Convert(date,getdate()) and UserID = @UserID)) 
