---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
/****************************************************************************
SP_Name        : USP_CHECKIFNUMBERISAIRTELORNOT                   
Author         : vinay
Created ON     : 24/12/2009 04:30 PM      
Version        : 1
Alter BY       :        
Alter Date	   :	
Location       : PELSOFT
SP Description : This SP is Used to CHECK IF NUMBER IS AIRTEL OR NOT
       
****************************************************************************/     
CREATE   PROC [dbo].[USP_CHECKIFNUMBERISAIRTELORNOT]    
@MobileSubSET CHAR(10)    
AS    
BEGIN    
IF EXISTS(SELECT 'X' FROM AirTELSEries WHERE MobileSubSET=@MobileSubSET)    
   BEGIN    
       SELECT '1'    
   END    
       ELSE    
    BEGIN    
        SELECT '0'    
    END    
END 





GO

/* ============================================================
   Procedure: [dbo].[usp_CheckifSales10xisavialbel]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_CheckifSales10xisavialbel]
	@UserID BIGINT
AS
BEGIN
	IF EXISTS (
	       SELECT 'x'
	       FROM   User_Detail AS ud
	       WHERE  (
	                  ud.M_ID = 10043
	                  OR (
	                         ud.IsInternalUser = 1
	                         AND (
	                                 SELECT TOP 1 ud2.M_ID
	                                 FROM   User_Detail AS ud2
	                                 WHERE  ud2.[User_ID] = ud.ParentID
	                             ) = 10043
	                     )
	              )
	              AND ud.[User_ID] = @UserID
	       
	       UNION
	       
	       SELECT 'x'
	       FROM   User_Detail AS ud
	       WHERE  (
	                  ud.M_ID = 10001
	                  OR (
	                         ud.IsInternalUser = 1
	                         AND (
	                                 SELECT TOP 1 ud2.M_ID
	                                 FROM   User_Detail AS ud2
	                                 WHERE  ud2.[User_ID] = ud.ParentID
	                             ) = 10001
	                     )
	              )
	              AND ud.[User_ID] = @UserID
	   )
	BEGIN
	    SELECT 1
	END
END



GO

