/* ============================================================
   Procedure: [dbo].[usp_CheckReportStatusByParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_CheckReportStatusByParentId]
    @ParentId BIGINT
AS
BEGIN
    BEGIN TRY
        -- Declare a variable to store the result
        DECLARE @IsProcessed BIT;

        -- Check if there is a record for the given ParentId with yesterday's ReportDate
        SELECT top 1 @IsProcessed = IsProcessed
        FROM ReportSummaryStatus
        WHERE ParentID = @ParentId
          AND ReportDate = CAST(DATEADD(DAY, -1, GETDATE()) AS DATE) order by id desc;

        -- If a record is found, return 1 for true or 0 for false
        IF @IsProcessed IS NOT NULL
        BEGIN
            SELECT CASE 
                       WHEN @IsProcessed = 1 THEN CAST(1 AS BIT)  -- Return true (1)
                       ELSE CAST(0 AS BIT)                         -- Return false (0)
                   END AS IsProcessed;
        END
        ELSE
        BEGIN
            -- Return false (0) if no records are found
            SELECT CAST(0 AS BIT) AS IsProcessed;  -- No record means not processed
        END
    END TRY
    BEGIN CATCH
        -- Error handling
        DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
        DECLARE @ErrorState INT = ERROR_STATE();

        -- Log the error or return the error details
        SELECT 
            @ErrorMessage AS ErrorMessage, 
            @ErrorSeverity AS ErrorSeverity, 
            @ErrorState AS ErrorState;

        -- Optionally, you can log the error into a table
        EXEC usp_InsertErrorInfo;
    END CATCH
END;


GO

/* ============================================================
   Procedure: [dbo].[usp_CheckScoreDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


------------------------------

CREATE   PROCEDURE [dbo].[usp_CheckScoreDetail]
    @userId BIGINT,
    @scoreValue NVARCHAR(100),
    @enquiryId BIGINT
AS
BEGIN
    SET NOCOUNT ON; -- Prevents extra result sets from interfering

    DECLARE @relativeScore INT; -- Variable to store the relative score
    DECLARE @ErrorMessage NVARCHAR(4000); -- Variable to store error message
    DECLARE @ErrorSeverity INT; -- Variable to store error severity
    DECLARE @ErrorState INT; -- Variable to store error state

    BEGIN TRY
        -- Get the relative score by calling the function
        SET @relativeScore = dbo.fn_getenquiryrelativescore(@enquiryId);

        -- Check if @scoreValue matches the relative score
        IF CAST(@scoreValue AS INT) = @relativeScore
        BEGIN
            RETURN 1; -- Score matches
        END

        RETURN 0; -- Score does not match
    END TRY
    BEGIN CATCH
        -- Capture error details
        SET @ErrorMessage = ERROR_MESSAGE();
        SET @ErrorSeverity = ERROR_SEVERITY();
        SET @ErrorState = ERROR_STATE();
        
        -- Log the error or handle it as needed
        RAISERROR(@ErrorMessage, @ErrorSeverity, @ErrorState);
        
        -- Return -1 for error
        RETURN -1; 
    END CATCH
END



GO

