CREATE   PROCEDURE [dbo].[usp_CheckSearchnameExist]
	@ParentID BIGINT,
	@SearchName VARCHAR(500)
AS
BEGIN
	IF EXISTS (
	       SELECT 'x'
	       FROM   UserSearchList AS usl
	       WHERE  usl.ParentID = @ParentID
	              AND usl.SearchName = @SearchName
	   )
	BEGIN
	    SELECT CAST(0 AS BIT)
	END
	ELSE
	BEGIN
	    SELECT CAST(1 AS BIT)
	END
END



