(
  @ID bigint,
  @Url nvarchar(max),
  @AdorPage nvarchar(50)
) 
as
Begin

   if(rtrim(ltrim(@Url)) <> '')
     Begin
	      if(LTRIM(RTRIM(@AdorPage)) = 'Ad')
		    Begin
	
	    	 declare @PageRequestID bigint = 0
		     select top 1 @PageRequestID = isnull(PageID,0)  from AdRequests where id =@ID 

			 if(exists(select 1 from DigitalMarketingEntities where url = @Url
			  and PageRequestID <> @PageRequestID))
			    Begin
				   select 'Not Available' 
				End
             else 
			    Begin
				    select 'Available'  
				end   


			end
          else
		    Begin
			   if(exists(select 1 from DigitalMarketingEntities where url = @Url
			  and PageRequestID <> @ID))
			    Begin
				   select 'Not Available' 
				End
             else 
			    Begin
				    select 'Available'  
				end   
 
			End  

	 End  
    else
	  Begin
	    select 'Available'
	  end  

End





