/* ============================================================
   Procedure: [dbo].[usp_ChoiceUpdateDelete]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_ChoiceUpdateDelete @parentid=32222,@fieldname= 'ABC',@fieldID= 52771,@OldFiledvalue= '',@Mode= 'Delete'  
-- Exec usp_ChoiceUpdateDelete @parentid=32222,@fieldname= 'PQR',@fieldID= 52771,@OldFiledvalue= '',@Mode= 'Delete'  
-- Exec usp_ChoiceUpdateDelete @parentid=32222,@fieldname= '',@fieldID= 52771,@OldFiledvalue= '',@Mode= 'Delete'  
CREATE   PROC [dbo].[usp_ChoiceUpdateDelete]  
@parentid bigint = 0,  
@fieldname VARCHAR(100) = '',  
@fieldID BIGINT = 0,  
@OldFiledvalue VARCHAR(100) = '',  
@Mode VARCHAR(100) = ''  
as   
begin  
        DECLARE @ParentFieldId BIGINT, @field_ID BIGINT, @DependencyJson NVARCHAR(MAX);  
          DECLARE @remove NVARCHAR(MAX) = @fieldname  
    if(@mode = 'Delete')  
    begin  
        DECLARE @string NVARCHAR(MAX)  
       -- DECLARE @remove NVARCHAR(MAX) = @fieldname -- Assuming @remove should be @fieldname  
        set @string = (SELECT choices FROM customfields(nolock) WHERE field_ID = @fieldID);  
          
		  Select @string=STRING_AGG(item,',') from dbo.splitstring(@string,',') where item !='' and item != @remove

		  /*
        -- Remove value from choices  
        SET @string = REPLACE(@string, @remove , ''); -- text1 followed by a comma  
		if(@remove!='')
		begin
			SET @string = REPLACE(@string, ',' + @remove, ''); -- text1 preceded by a comma  
		end
        SET @string = REPLACE(@string, @remove, '');  
		*/

        update customfields set choices = @string where field_ID = @fieldID  
  
        DROP TABLE if exists #temp;  
        DROP TABLE if exists #Temps;  
        DROP TABLE if exists #tempr;  
        DROP TABLE if exists #tempf;  
        DROP TABLE if exists #Temps1;  
  
        -- Create and populate the temporary table  
        SELECT ParentFieldId, field_ID, DependencyJson   
        INTO #temp   
        FROM customfields   
        WHERE ParentFieldId = @fieldID OR field_ID = @fieldID;  
  
       -- DECLARE @ParentFieldId BIGINT, @field_ID BIGINT, @DependencyJson NVARCHAR(MAX);  
  
        DECLARE dataCursor CURSOR FOR  
        SELECT ParentFieldId, field_ID, DependencyJson   
        FROM #temp;  
  
        OPEN dataCursor;  
  
        FETCH NEXT FROM dataCursor INTO @ParentFieldId, @field_ID, @DependencyJson;  
  
        WHILE @@FETCH_STATUS = 0  
        BEGIN  
            IF (@fieldID = @field_ID)  
            BEGIN  
   if(isnull(@DependencyJson,'') !='')  
      begin  
                -- Parse JSON data into #tempr table  
           select * into #tempChildOfData_ from customfields where field_ID=@fieldID  
           SELECT ParentFieldId,field_ID,ParentValue, ChildValue INTO #tempC_ FROM #tempChildOfData_  
           CROSS APPLY OPENJSON(@DependencyJson)   
              WITH (  
                  ParentValue NVARCHAR(100),  
                  ChildValue NVARCHAR(MAX) AS JSON  
              );  
            
                -- Process data in #tempr  
              WITH JsonDataParsed AS (  
              SELECT  ParentFieldId, field_ID,ParentValue,  
              CASE   
              WHEN ChildValue = '[[]]]' THEN '[]'  
              ELSE ChildValue  
              END AS ChildValue  
         FROM  #tempC_  
       ),  
        ExpandedChildValues AS (  
        SELECT   
            ParentFieldId,  
            field_ID,  
            ParentValue,  
            Value AS ChildValue  
        FROM   
            JsonDataParsed  
            OUTER APPLY OPENJSON(ChildValue)  
         )  
  
                SELECT *   
                INTO #Temps   
                FROM ExpandedChildValues;  
  
                -- Update #Temps where necessary  
                UPDATE #Temps   
                SET ChildValue = ''   
                WHERE field_ID = @fieldID AND ChildValue = @fieldname;  
  
                -- Aggregate and format JSON data  
                 WITH FilteredChildValues AS (  
                SELECT   
                    ParentFieldId,  
                    field_ID,  
                    PareGO

e,  
                    STRING_AGG(ChildValue, ',') AS ChildValues  
                FROM   
                    #Temps  
                GROUP BY   
               ParentFieldId, field_ID, ParentValue  
              )  
         SELECT  ParentValue,CASE WHEN ChildValues IS NULL THEN '[]' ELSE '[' + STRING_AGG('"' + ChildValues + '"', ',') + ']' END AS ChildValue  
         INTO #FormattedData_  
         FROM FilteredChildValues  
         group by ParentValue,ChildValues  
  
  
         update customfields set DependencyJson = (  
         SELECT ParentValue,  
                JSON_QUERY(ChildValue) AS ChildValue  
       FROM #FormattedData_  
         FOR JSON PATH  
                )  
                where field_ID = @fieldID  
   
                 
    end  
            END  
            ELSE  
            BEGIN  
   if(isnull(@DependencyJson,'') !='')  
    begin  
                -- Parse JSON data into #tempf table  
    select * into #tempParentOfData_ from customfields where ParentFieldId=@fieldID  
                SELECT  ParentFieldId,field_ID,ParentValue,ChildValue INTO #tempP_ FROM #tempParentOfData_  
                CROSS APPLY OPENJSON(@DependencyJson)   
                WITH (  
                    ParentValue NVARCHAR(100),  
                    ChildValue NVARCHAR(MAX) AS JSON  
                );  
               
                            -- Process data in #tempf  
                             WITH JsonDataParsed AS (  
                SELECT ParentFieldId,field_ID,ParentValue,  
        CASE   
            WHEN ChildValue = '[[]]]' THEN '[]'  
            ELSE ChildValue  
        END AS ChildValue  
        FROM   
        #tempP_  
               ),  
        ExpandedChildValues AS (  
                SELECT   
                    ParentFieldId,  
                    field_ID,  
                    ParentValue,  
                    Value AS ChildValue  
                FROM   
                    JsonDataParsed  
                    OUTER APPLY OPENJSON(ChildValue)  
            )  
             SELECT *   
             INTO #Temps1   
             FROM ExpandedChildValues;  
              
                         -- Update #Temps1 where necessary  
                         UPDATE #Temps1   
                         SET ParentValue = ''   
                         WHERE ParentFieldId = @fieldID AND ParentValue = @fieldname;  
              
               
                         -- Aggregate and format JSON data  
                          WITH FilteredChildValues AS (  
                       SELECT   
                 ParentFieldId,field_ID,ParentValue,STRING_AGG(ChildValue, ',') AS ChildValues FROM  
                   
                   
                   
                
                 #Temps1  
             GROUP BY   
                 ParentFieldId, field_ID, ParentValue  
           )  
  
           SELECT ParentValue,CASE  WHEN ChildValues IS NULL THEN '[]' ELSE '[' + STRING_AGG('"' + ChildValues + '"', ',') + ']' END AS ChildValue  INTO #FormattedData1_ FROM FilteredChildValues group by ParentValue,ChildValues  
           update customfields set DependencyJson = (  
           SELECT ParentValue,  
                  JSON_QUERY(ChildValue) AS ChildValue  
           FROM #FormattedData1_  
           FOR JSON PATH  
                )  
                where ParentFieldId = @fieldID  
    end  
            END  
  
            FETCH NEXT FROM dataCursor INTO @ParentFieldId, @field_ID, @DependencyJson;  
        END  
  
        -- Close and deallocate the cursor  
        CLOSE dataCursor;  
        DEALLOCATE dataCursor;  
    end  
     if(@mode = 'Edit')  
    begin  
        DECLARE @string1 NVARCHAR(MAX)  
 -- Assuming @remove should be @fieldname  
        set @string1 = (SELECT choices FROM customfields WHERE field_ID = @fieldID);  
         
        -- Remove value from choices  
        SET @string1 = REPLACE(@string1, @OldFiledvalue , @fieldname); -- text1 followed by a comma  
    
       -- SET @string1 = REPLACE(@string1, ',' + @OldFiledvalue, @fieldname); -- text1 preceded by a comma  
    
       -- SET @string1 = REPLACE(@string1, @OldFiledvalue, @fieldname+ ',');  
  
    
    
        update customfields set choices = @string1 where field_ID = @fieldID  
  
        DROP TABLE if exists #temp_;  
        DROP TABLE if exists #Temps_;  
        DROP TABLE if exists #tempr_;  
        DROP TABLE if exists #tempf_;  
        DROP TABLE if exists #Temps1_;  
  
        -- Create and populate the temporary table  
        SELECT ParentFieldId, field_ID, DependencyJson   
        INTO #temp_   
        FROM customfields   
        WHERE ParentFieldId = @fieldID OR field_ID = @fieldID;  
    
  
        DECLARE dataCursor CURSOR FOR  
        SELECT ParentFieldId, field_ID, DependencyJson   
        FROM #temp_;  
  
        OPEN dataCursor;  
  
        FETCH NEXT FROM dataCursor INTO @ParentFieldId, @field_ID, @DependencyJson;  
  
        WHILE @@FETCH_STATUS = 0  
        BEGIN  
            IF (@fieldID = @field_ID)  
            BEGIN  
IF ISNULL(@DependencyJson, '') != ''  
BEGIN  
    -- Step 1: Parse JSON data into #tempr table  
  select * into #tempChildOf_ from customfields where field_ID=@fieldID  
 SELECT   
    ParentFieldId,  
    field_ID,  
    ParentValue,  
    ChildValue  
INTO #tempr_  
FROM   
    #tempChildOf_  
    CROSS APPLY OPENJSON(@DependencyJson)   
    WITH (  
        ParentValue NVARCHAR(100),  
        ChildValue NVARCHAR(MAX) AS JSON  
    );  
  
    -- Step 2: Expand ChildValue JSON arrays into rows  
   WITH JsonDataParsed AS (  
    SELECT   
        ParentFieldId,  
        field_ID,  
