    WHERE field_ID = @fieldID AND ChildValue = @OldFiledvalue;  
  
   
  
    -- Step 4: Aggregate and format JSON data  
   WITH FilteredChildValues AS (  
    SELECT   
        ParentFieldId,  
        field_ID,  
        ParentValue,  
        STRING_AGG(ChildValue, ',') AS ChildValues  
    FROM   
        #Temps_  
    GROUP BY   
        ParentFieldId, field_ID, ParentValue  
)  
  
    SELECT   
    ParentValue,  
    CASE   
        WHEN ChildValues IS NULL THEN '[]'  
        ELSE '[' + STRING_AGG('"' + ChildValues + '"', ',') + ']'  
    END AS ChildValue  
INTO #FormattedData1  
FROM FilteredChildValues  
group by ParentValue,ChildValues  
  
 update customfields set DependencyJson = (  
SELECT ParentValue,  
       JSON_QUERY(ChildValue) AS ChildValue  
FROM #FormattedData1  
FOR JSON PATH  
                )  
                where field_ID = @fieldID  
  
   --  select * from FilteredChildValues  
 --update customfields set DependencyJson = (  
    --                SELECT ParentValue,  
    --       CASE   
    --           WHEN ChildValues IS NULL THEN '[]'  
    --           ELSE JSON_QUERY('[' + ChildValues + ']')  
    --       END AS ChildValue  
    --FROM FilteredChildValues  
    --FOR JSON PATH, ROOT('DependencyJson')  
    --            )  
 --               where ParentFieldId = @fieldID  
END  
  
  
            END  
            ELSE  
            BEGIN  
   if(isnull(@DependencyJson,'') !='')  
    begin  
    -- Step 1: Parse JSON data into #tempr table  
 select * into #tempParentOf_ from customfields where ParentFieldId=@fieldID  
 SELECT   
          ParentFieldId,  
          field_ID,  
          ParentValue,  
          ChildValue  
      INTO #tempr1_  
      FROM   
          #tempParentOf_  
          CROSS APPLY OPENJSON(@DependencyJson)   
          WITH (  
          ParentValue NVARCHAR(100),  
          ChildValue NVARCHAR(MAX) AS JSON  
      );  
  
-- Step 3: Expand ChildValue JSON arrays into rows  
    WITH JsonDataParsed AS (  
    SELECT   
        ParentFieldId,  
        field_ID,  
        ParentValue,  
        CASE   
            WHEN ChildValue = '[[]]]' THEN '[]'  
            ELSE ChildValue  
        END AS ChildValue  
     FROM   
        #tempr1_  
     ),  
    ExpandedChildValues AS (  
    SELECT   
        ParentFieldId,  
        field_ID,  
        ParentValue,  
        Value AS ChildValue  
     FROM   
        JsonDataParsed  
        OUTER APPLY OPENJSON(ChildValue)  
     )  
     SELECT *   
     INTO #Temps1_   
     FROM ExpandedChildValues;  
       
     -- Step 4: Update ChildValue where necessary  
     UPDATE #Temps1_   
     SET ParentValue = @fieldname   
     WHERE ParentFieldId = @fieldID AND ParentValue = @OldFiledvalue;  
  
 -- Step 5: Aggregate and format JSON data  
    WITH FilteredChildValues AS (  
    SELECT   
        ParentFieldId,  
        field_ID,  
        ParentValue,  
        STRING_AGG(ChildValue, ',') AS ChildValues  
     FROM   
        #Temps1_  
     GROUP BY   
        ParentFieldId, field_ID, ParentValue  
     )  
--select * from FilteredChildValues  
    SELECT   
    ParentValue,  
    CASE   
        WHEN ChildValues IS NULL THEN '[]'  
        ELSE '[' + STRING_AGG('"' + ChildValues + '"', ',') + ']'  
    END AS ChildValue  
    INTO #FormattedData  
    FROM FilteredChildValues  
    group by ParentValue,ChildValues  
  
     
 update customfields set DependencyJson = (  
                  SELECT ParentValue,  
       JSON_QUERY(ChildValue) AS ChildValue  
       FROM #FormattedData  
       FOR JSON PATH  
               )  
                 where ParentFieldId = @fieldID  
  
  
  
    end  
            END  
  
            FETCH NEXT FROM dataCursor INTO @ParentFieldId, @field_ID, @DependencyJson;  
        END  
  
        -- Close and deallocate the cursor  
        CLOSE dataCursor;  
        DEALLOCATE dataCursor;  
    end  
end  


