/* ============================================================
   Procedure: [dbo].[usp_cl_GetCallDetailByCallLogId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_cl_GetCallDetailByCallLogId(
	@UserId bigint, 
	@CallLogId bigint
)
as
begin

	--declare 
	--	@UserId bigint = 34594, 
	--	@CallLogId bigint = 2037514 

	declare @parentid  bigint, @isadmin int, @ft nvarchar(max), @TeamCode varchar(10) = '', @ScopeCode varchar(10) = '', 
		@UserIdTeamLst varchar(500) = ''
	
	select @parentid = ParentID, @isadmin = IsAdmin  from MySMS.dbo.User_Detail(nolock) 
		where User_ID = @UserId;
	
	select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst 
		from MySMS.dbo.ufn_GetUserRoleScope(@UserId)

	declare @FinalQuery nvarchar(max), @SqlQuery1 nvarchar(max), @SqlQuery2 nvarchar(max), @SqlQuery3 nvarchar(max)

	set @SqlQuery1 = concat(N'select * from ( select  ROW_NUMBER() OVER( order by cl.parentid, ',
		N'cast(cl.callcreatedon as datetime) desc ) AS [RowNumber1], ',
		N'COUNT(*) OVER() AS [rc1], * from ( select ',
          N'c.id, ',
          N'c.parentid, ',
          N'c.callcreatedon as Date, ',
          N'Customernumber, ',
          N'customerentity, ',
          N'customerentityid, ',
		  N'a.uniqueid, a.callerid, a.channel, ', 
		  N'(case when c.direction = ''incoming'' then ''inbound'' ', 
		  N'when c.direction  in (''out'', ''Outgoing'')  then ''outbound-user'' ', 
		  N'else a.context end  ) as [context], ', 
		  N'a.clientid, m.AppName as appid, ',
          N'isnull ( dbo.fn_getentityfullname(customerentity, customerentityid ), '''' ) as CustomerName, ',
          N'isnull(c.dnid, '''') as [dnid], ',
          N'( case when c.gatewayid = 0 then ''Sim'' else s.provider_name end ) as Gateway, ',
          N'isnull(m.AppName, '''') IVFlow,  ',
		  N'iif(a.id is null, '''', (case when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') ',
			N'or (a.context = ''inbound'')) and (dbo.callstatus1(a.uniqueid) = ''ANSWER'') ',
			N'and (Cast(a.clientid as varchar(10)) = ', Cast(@UserId as varchar(10)), '))  then ''Calls answered by me'' ',
		  N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') ',
			N'or (a.context = ''inbound'')) and (dbo.callstatus1(a.uniqueid) = ''NO ANSWER'') ',
			N'and (Cast(a.clientid as varchar(10)) = ', Cast(@UserId as varchar(10)), '))  then ''Calls missed by me'' ',
		  N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') ',
			N'or (a.context = ''inbound'')) and (dbo.callstatus1 (a.uniqueid) = ''ANSWER'') ',
			N'and (Cast(a.clientid as varchar(10)) != ', Cast(@UserId as varchar(10)), '))  then ''Calls answered by me'' ',
		  N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') ',
			N'or (a.context = ''inbound'')) and (dbo.callstatus1 (a.uniqueid) = ''NO ANSWER'') ',
			N'and (Cast(a.clientid as varchar(10)) != ', Cast(@UserId as varchar(10)), '))  then ''Calls missed today'' ',
		  N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') ',
			N'or (a.context = ''inbound'')) and (dbo.callstatus1 (a.uniqueid) = ''ANSWER''))  then ''Calls answered'' ',
		  N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') ',
			N'or (a.context = ''inbound'')) and (dbo.callstatus1 (a.uniqueid) = ''NO ANSWER''))  then ''Calls missed'' ',
			N'else ''Calls overdue'' End)) as [CallsMsgStatus], ',
		  N'isnull(ul.PersonName,'''') name, ',
 		  N'ul.LeadNo, ul.Id LeadId, ul.ProfileImgFileName as Image, ', 
		  N'concat(ul.MobileNo, iif(ul.MobileNo1 <> '''', concat('''', '''', ul.MobileNo1), ''''),  ',
		  N'iif(ul.MobileNo2 <> '''', concat('''', '''', ul.MobileNo2), '''')) as CsvMobileNo,',
		  N'concat(ul.EmailId, iif(ul.EmailId1 <> '''', concat('''', '''', ul.EmailId1), ''''), ',
		  N'iif(ul.EmailId2 <> '''', concat('''', '''', ul.EmailId2), '''')) as CsvEmailId, ',
		  N'dbo.billduration1 (a.uniqueid) as billduration, ',
		  N'dbo.callstatus1 (a.uniqueid) as callstatus, ',
		  N'isnull(dbo.lastagentattended(a.uniqueid),'+''''+''''+') as AgentUser, ',
		  N'isnull(dbo.lastagentattended(a.uniqueid),'+''''+''''+') as agentname, 0 agentid, ',
		  N'isnull(c.Direction, '''') direction, isnull(c.outcomeid, 0) Outcome, ',
		  N'isnull(o.OutcomeName, '''') OutcomeName, isnull(c.recordurl, '''') RecodingUrl, ',
		  N'isnull(c.Remarks, '''') Remarks, Customernumber MobileNo, '''' CallGetway, ' )

set @SqlQuery2 = concat(N'isnull( u.user_login, case when c.agentcalldisposition is null ',
			N'then '' '' else ''Agent No Changed'' end ) user_login, ',
          N'isnull( c.customercalldisposition, ''Unknown'' ) as CustomerDisposition, ',
          N'isnull( c.agentcalldisposition, case when c.agentcalldisposition is null ',
			N'then ''NOT ATTEMPTED'' else ''Unknown'' end ) as AgentDisposition, ',
          N'isnull(c.Callstarttime, '''') as [call_start_time], ',
		  N'isnull( cast(c.callendtime as nvarchar),  ''Unknown'' ) as call_end_time, ',
          N'coalesce( customerduration, c.Calldurationseconds, 0 ) AS CustomerDuration, ',
          N'( case when c.agentcalldisposition is null then 0 when c.agentcalldisposition = ''NOANSWER'' ',
			N'then 0 else coalesce( agentduration, Calldurationseconds, 0 ) end ) as agentDuration, ',
          N'( case when c.agentcalldisposition IS NULL ',
			N'then 0 else isnull (Calldurationseconds, 0) end ) as Callduration, ',
          N'c.recordurl as [recordurl], ',
          N'isnull(c.agentmode, ''Mobile'') as AgentMode, ',
          N'isnull(c.lastdtmf, '''') [call_last_dtmf], ',
          N'c.callcreatedon from calendar(nolock) ca ', 
          N'left join calllog(nolock) c on cast(c.callstarttime as date)= cast(ca.start_dts as date) ',
          N'left join kit19calls(nolock) a on c.reftable = ''kit19calls'' and c.refid = a.id ',
		  N'left join user_detail(nolock) u on c.agentuserid = u.User_ID ',	             
		  N'left join UserLeads(nolock) ul on c.customerentity = ''lead'' and c.customerentityid = ul.id ', 
          N'left join TelephonyCostDeducted(nolock) t on t.parentid = c.parentid ',
          N'and 1 = case when t.gatewaytype <> 0 ',
          N'and t.kit19callsdialledid = c.refid then 1 when t.GatewayType = 0 ',
          N'and t.uniqueid = c.uniqueid then 1 else 0 end ',
          N'left join tbl_voip_ServiceProvider s on s.id = c.gatewayid ',
          N'left join tbl_CallLogOutcomeMaster(nolock) o on o.id = c.outcomeid ',
          N'left join Cloud_app_master(nolock) m on m.AppId = c.appid ',
          N'where c.parentid = ', @parentid, ' and c.id = ', @CallLogId, ' ) as cl ) t ')


	print @SqlQuery1
	print @SqlQuery2

	set @FinalQuery = @SqlQuery1 + @SqlQuery2

	execute sp_executesql @FinalQuery

end



GO

/* ============================================================
   Procedure: [dbo].[usp_cl_GetCallLogMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_cl_GetCallLogMaster](
	@UserId bigint
)
as
begin

	--declare @UserId bigint  = 34594

	declare @ParentId bigint = 0
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	if(exists(select 1 from tbl_CallLogOutcomeMaster(nolock) where ParentId = @ParentId  ))
	begin
		select  Id, OutcomeName, Indent, Sequence  from tbl_CallLogOutcomeMaster(nolock) 
			where ParentId = @ParentId and IsDeleted = 0 order by Sequence asc
	end
	else
	begin
		select  Id, OutcomeName, Indent, Sequence  from tbl_CallLogOutcomeMaster(nolock) 
			where ParentId = 0 and IsDeleted = 0 order by Sequence asc
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_cl_InsertUpdateCalllogOutcome]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_cl_InsertUpdateCalllogOutcome(
	@clOutcomes clOutcomes readonly,
	@UserId bigint
)
as
begin
	--declare @clOutcomes as clOutcomes, @UserId bigint = 34594
	--insert into @clOutcomes values(1,1,N'Outcome A',N'Positive',1)
	--insert into @clOutcomes values(2,2,N'Outcome B',N'Neutral',2)
	--insert into @clOutcomes values(3,3,N'Outcome C',N'Neutral',3)
	--insert into @clOutcomes values(4,4,N'Outcome D',N'Negative',4)
	--insert into @clOutcomes values(5,0,N'Outcome E',N'Positive',5)
	--insert into @clOutcomes values(5,0,N'Outcome F',N'Positive',5)


	declare @ParentId bigint = 0
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	drop table if exists #tempOutcomes
	select *, isproccess = 0 into #tempOutcomes from @clOutcomes

	while(exists(select * from #tempOutcomes where isproccess = 0))
	begin
	declare 
		@Id bigint,
		@OutcomeId bigint,
		@OutcomeName nvarchar(255),
		@OutcomeIndent nvarchar(20),
		@Sequence int,
		@UniqueId bigint = 0;
		select top 1 @Id = Id, @OutcomeId = OutcomeId, @OutcomeName = OutcomeName, @OutcomeIndent = OutcomeIndent, @Sequence = Sequence
			from #tempOutcomes where isproccess = 0

		if(exists(select 1 from tbl_CallLogOutcomeMaster(nolock) where ParentId = @ParentId and OutcomeName = @OutcomeName))
		begin
			select @UniqueId = Id from tbl_CallLogOutcomeMaster(nolock) where ParentId = @ParentId and OutcomeName = @OutcomeName

			update tbl_CallLogOutcomeMaster set 
				OutcomeName = @OutcomeName, 
				Indent = @OutcomeIndent,
				IsDeleted = 0,
				[Sequence] = @Sequence
			where Id = @UniqueId

		end
		else
		begin
			insert into tbl_CallLogOutcomeMaster( OutcomeName, ParentId, IsDeleted, CreatedOn, CreatedBy, Indent, Sequence)
				values ( @OutcomeName, @ParentId, 0, getdate(), @UserId, @OutcomeIndent, @Sequence )

			select @UniqueId = SCOPE_IDENTITY()
		end

		update #tempOutcomes set isproccess = 1, Id = @UniqueId where Id = @Id

	end
	
	-- Removing tbl_CallLogOutcomeMaster
	update tbl_CallLogOutcomeMaster set
		IsDeleted = 1
	where ParentId = @ParentId and  id not in ( select Id from #tempOutcomes )

	declare @MaxSequence int = 0;
	select @MaxSequence = max(Sequence) from tbl_CallLogOutcomeMaster where ParentId = @ParentId and IsDeleted = 0
	select @MaxSequence 

	update cl set cl.Sequence = @MaxSequence + clr.rn
	from tbl_CallLogOutcomeMaster(nolock) cl inner join (
		select id, ROW_NUMBER() over( order by id asc) as rn from tbl_CallLogOutcomeMaster 
		where ParentId = @ParentId and IsDeleted = 1
	) clr on cl.Id = clr.Id

end



GO

