/* ============================================================
   Procedure: [dbo].[usp_ClaimMailOutboxBatch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_ClaimMailOutboxBatch
    @BatchSize INT
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRAN;
    
    WITH cte AS (
        SELECT TOP (@BatchSize) OutboxId
        FROM MailOutbox WITH (UPDLOCK, READPAST, ROWLOCK)
        WHERE Processed = 0
          AND Processing = 0
          AND (NextRetryAt IS NULL OR NextRetryAt <= getdate())
        ORDER BY OutboxId
    )
    UPDATE a
    SET Processing = 1,
        ProcessingStartedAt = getdate(),
        AttemptCount = ISNULL(AttemptCount, 0) + 1
    OUTPUT inserted.OutboxId, inserted.QueueName, inserted.MessageId, inserted.Payload
    FROM MailOutbox a
    JOIN cte ON a.OutboxId = cte.OutboxId;
    
    COMMIT;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ClaimMessagesByBatch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ClaimMessagesByBatch]
    @BatchSize INT = 10
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @SelectedMassOpBatchId BIGINT;
    
    -- Get the oldest MassOpBatchId that has unprocessed messages
    SELECT TOP 1 @SelectedMassOpBatchId = MassOpBatchId
    FROM [dbo].[Int_MessageDeliveryStatus]
    WHERE Processed = 0 
        AND IsQueued = 0
        AND MassOpBatchId IS NOT NULL
    ORDER BY MessageInsertDate ASC;
    
    -- Return all messages from the selected MassOpBatchId (up to @BatchSize limit)
    SELECT TOP (@BatchSize)
        MessageDeliveryStatusID,
        CountryCode,
        MessageRefID,
        BatchID,
        Mobile,
        Message,
        SenderID,
        MessageStatus,
        Priority,
        MessageInsertDate,
        MessageSubmitDate,
        MessageDeliveredDate,
        SmppID,
        U_ID,
        StatusCode,
        ProviderReference,
        LastError,
        IsUniCode,
        Status,
        IsCompleted,
        StatusCompletedTime,
        StatusCompletedTimeSecs,
        StatusDescription,
        Processed,
        EntityId,
        EntityName,
        SmsMode,
        MassOpBatchId,
        UrlTrack,
        Price,
        IsPersonalised,
        IsQueued
    FROM [dbo].[Int_MessageDeliveryStatus] with (nolock)
    WHERE MassOpBatchId = @SelectedMassOpBatchId
        AND Processed = 0 
        AND IsQueued = 0
    ORDER BY MessageInsertDate ASC;
END




GO

