/* ============================================================
   Procedure: [dbo].[usp_clb_Action_GroupMember]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC usp_clb_Action_GroupMember
(
	@Mode			nvarchar(50), -- Leave,Block,Delete,SetAdmin,UnSetAdmin
	@GroupId		bigint,
	@ActionOnUserId	bigint,
	@ActionByUserId	bigint
)
As
Begin

	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null, @ActivityBy varchar(150)=''

	select @ActivityBy=concat(FName,' ',LName,' (',User_Login,')') from User_Detail(nolock) Where User_ID=@ActionByUserId

	If(@Mode = 'Leave')
	Begin
		Update tbl_clb_GroupMembers set IsLeftGroup=1, LeavingDate=GETDATE(), ModifiedBy=@ActionByUserId, ModifiedOn=GETDATE()
		Where UserId=@ActionOnUserId and GroupId=@GroupId

		Select @@ROWCOUNT as Code, 'Group Member left group successfully' as Msg

		Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
		select GM.GroupId,UD.ParentID, concat(UD.FName,' ',UD.LName,'(',UD.User_Login,') left the Group'),14/*Activity*/,@ActionByUserId,G.GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@ActionByUserId,GETDATE()
		from	tbl_clb_GroupMembers(nolock) GM inner join User_Detail(nolock) UD
		ON		GM.UserId=UD.User_ID inner join tbl_clb_Group(nolock) G
		ON		GM.GroupId=G.GroupId
		WHERE	GM.UserId=@ActionOnUserId and GM.GroupId=@GroupId

		SET @rowJson = (SELECT * FROM tbl_clb_GroupMembers(nolock) WHERE UserId=@ActionOnUserId and GroupId=@GroupId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Lev_Clb_GrpMemb'
		SET @action = 'U'  
	End

	If(@Mode = 'Block')
	Begin
		Update tbl_clb_GroupMembers set IsBlocked=1, BlockedOn=GETDATE(), BlockedBy=@ActionByUserId, ModifiedBy=@ActionByUserId, ModifiedOn=GETDATE()
		Where UserId=@ActionOnUserId and GroupId=@GroupId

		Select @@ROWCOUNT as Code, 'Group Member blocked successfully' as Msg

		Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
		select GM.GroupId,UD.ParentID, concat(UD.FName,' ',UD.LName,' (',UD.User_Login,') blocked from the Group by ',@ActivityBy),14/*Activity*/,@ActionByUserId,G.GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@ActionByUserId,GETDATE()
		from	tbl_clb_GroupMembers(nolock) GM inner join User_Detail(nolock) UD
		ON		GM.UserId=UD.User_ID inner join tbl_clb_Group(nolock) G
		ON		GM.GroupId=G.GroupId
		WHERE	GM.UserId=@ActionOnUserId and GM.GroupId=@GroupId

		SET @rowJson = (SELECT * FROM tbl_clb_GroupMembers(nolock) WHERE UserId=@ActionOnUserId and GroupId=@GroupId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Blk_Clb_GrpMemb'
		SET @action = 'U'  
	End

	If(@Mode = 'UnBlock')
	Begin
		Update tbl_clb_GroupMembers set IsBlocked=0, UnBlockedOn=GETDATE(), UnBlockedBy=@ActionByUserId, ModifiedBy=@ActionByUserId, ModifiedOn=GETDATE()
		Where UserId=@ActionOnUserId and GroupId=@GroupId

		Select @@ROWCOUNT as Code, 'Group Member UnBlocked successfully' as Msg

		Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
		select GM.GroupId,UD.ParentID, concat(UD.FName,' ',UD.LName,' (',UD.User_Login,') unblocked from the Group by ',@ActivityBy),14/*Activity*/,@ActionByUserId,G.GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@ActionByUserId,GETDATE()
		from	tbl_clb_GroupMembers(nolock) GM inner join User_Detail(nolock) UD
		ON		GM.UserId=UD.User_ID inner join tbl_clb_Group(nolock) G
		ON		GM.GroupId=G.GroupId
		WHERE	GM.UserId=@ActionOnUserId and GM.GroupId=@GroupId

		SET @rowJson = (SELECT * FROM tbl_clb_GroupMembers(nolock) WHERE UserId=@ActionOnUserId and GroupId=@GroupId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'UnBlk_Clb_GrpMemb'
		SET @action = 'U'  
	End

	If(@Mode = 'Delete')
	Begin
		Update tbl_clb_GroupMembers set IsActive=0, ModifiedBy=@ActionByUserId, ModifiedOn=GETDATE()
		Where UserId=@ActionOnUserId and GroupId=@GroupId

		Select @@ROWCOUNT as Code, 'Group Member deleted successfully' as Msg

		Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
		select GM.GroupId,UD.ParentID, concat(UD.FName,' ',UD.LName,' (',UD.User_Login,') removed from the Group by ',@ActivityBy),14/*Activity*/,@ActionByUserId,G.GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@ActionByUserId,GETDATE()
		from	tbl_clb_GroupMembers(nolock) GM inner join User_Detail(nolock) UD
		ON		GM.UserId=UD.User_ID inner join tbl_clb_Group(nolock) G
		ON		GM.GroupId=G.GroupId
		WHERE	GM.UserId=@ActionOnUserId and GM.GroupId=@GroupId

		SET @rowJson = (SELECT * FROM tbl_clb_GroupMembers(nolock) WHERE UserId=@ActionOnUserId and GroupId=@GroupId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Del_Clb_GrpMemb'
		SET @action = 'U'  
	End

	If(@Mode = 'SetAdmin')
	Begin
		Update tbl_clb_GroupMembers set IsGroupAdmin=1, ModifiedBy=@ActionByUserId, ModifiedOn=GETDATE()
		Where UserId=@ActionOnUserId and GroupId=@GroupId

		Select @@ROWCOUNT as Code, 'Group Member Set Admin successfully' as Msg

		Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
		select GM.GroupId,UD.ParentID, concat(UD.FName,' ',UD.LName,' (',UD.User_Login,') set as Group Admin by ',@ActivityBy),14/*Activity*/,@ActionByUserId,G.GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@ActionByUserId,GETDATE()
		from	tbl_clb_GroupMembers(nolock) GM inner join User_Detail(nolock) UD
		ON		GM.UserId=UD.User_ID inner join tbl_clb_Group(nolock) G
		ON		GM.GroupId=G.GroupId
		WHERE	GM.UserId=@ActionOnUserId and GM.GroupId=@GroupId

		SET @rowJson = (SELECT * FROM tbl_clb_GroupMembers(nolock) WHERE UserId=@ActionOnUserId and GroupId=@GroupId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Upd_Clb_GrpMembSetAdmin'
		SET @action = 'U'  
	End

	If(@Mode = 'UnSetAdmin')
	Begin
		Update tbl_clb_GroupMembers set IsGroupAdmin=0, ModifiedBy=@ActionByUserId, ModifiedOn=GETDATE()
		Where UserId=@ActionOnUserId and GroupId=@GroupId

		Select @@ROWCOUNT as Code, 'Group Member Unset Admin successfully' as Msg

		Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
		select GM.GroupId,UD.ParentID, concat(UD.FName,' ',UD.LName,' (',UD.User_Login,') unset as Group Admin by ',@ActivityBy),14/*Activity*/,@ActionByUserId,G.GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@ActionByUserId,GETDATE()
		from	tbl_clb_GroupMembers(nolock) GM inner join User_Detail(nolock) UD
		ON		GM.UserId=UD.User_ID inner join tbl_clb_Group(nolock) G
		ON		GM.GroupId=G.GroupId
		WHERE	GM.UserId=@ActionOnUserId and GM.GroupId=@GroupId

		SET @rowJson = (SELECT * FROM tbl_clb_GroupMembers(nolock) WHERE UserId=@ActionOnUserId and GroupId=@GroupId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Upd_Clb_GrpMembUnSetAdmin'
		SET @action = 'U'  
	End

	IF @rowJson IS NOT NULL  
	BEGIN  
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ActionByUserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = 'tbl_clb_GroupMembers'  
	END  

End



