/* ============================================================
   Procedure: [dbo].[usp_clb_ActOnConversation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC usp_clb_ActOnConversation
(
	@ActionMode			nvarchar(50),
	@UserId				bigint,
	@ConversationId		bigint=0,
	@StatusId			int=0
)
As
Begin

	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null

	If(@ActionMode = 'Status')
	Begin
		Update	tbl_clb_Conversation Set StatusId=@StatusId, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		Where	ConversationId=@ConversationId 
	
		SET @activity = 'Upd_Clb_ChatStatus'
	End

	If(@ActionMode = 'Delete')
	Begin
		Update	tbl_clb_Conversation Set IsDeleted=1, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		Where	ConversationId=@ConversationId 

		SET @activity = 'Del_Clb_Chat'
	End

	If(@ActionMode = 'Star')
	Begin
		Update	tbl_clb_Conversation Set IsStarred=1, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		Where	ConversationId=@ConversationId 

		SET @activity = 'Star_Clb_Chat'
	End

	Select @ConversationId as Code, 'Conversation action ' + @ActionMode + ' done successfully' as Msg

	SET @rowJson = (SELECT * FROM tbl_clb_Conversation(nolock) WHERE ConversationId=@ConversationId FOR JSON AUTO,INCLUDE_NULL_VALUES)
	SET @action = 'U'  

	IF @rowJson IS NOT NULL  
	BEGIN  
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = 'tbl_clb_Conversation'  
	END  

End



GO

/* ============================================================
   Procedure: [dbo].[usp_clb_Add_GroupMember]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_clb_Add_GroupMember
(
	@jsonAddMember	nvarchar(max),
	@UserId			bigint
)
As
Begin
	-- declare @jsonAddMember nvarchar(max)=N'[{"GroupId":1,"MemberId":32222,"IsGroupAdmin":true,"ISDCode":91,"MobileNo":9316892313},{"GroupId":1,"MemberId":32392,"IsGroupAdmin":false,"ISDCode":91,"MobileNo":9316832392},{"GroupId":1,"MemberId":32483,"IsGroupAdmin":false,"ISDCode":91,"MobileNo":9316832332}]', @UserId bigint=32222

	drop table if exists #OutputId
	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null,@ActivityBy varchar(150)=''
	create table #OutputId(Id bigint)  

	select @ActivityBy=concat(FName,' ',LName,' (',User_Login,')') from User_Detail(nolock) Where User_ID=@UserId

	If(@jsonAddMember is not null)
	Begin
		insert into tbl_clb_GroupMembers(GroupId,UserId,IsGroupAdmin,ISDCode,MobileNo,AddedBy,AddedOn,
IsActive,CreatedBy,CreatedOn) 
		output inserted.GroupMemberId as Id into #OutputId
		Select GroupId, MemberId, IsGroupAdmin, ISDCode, MobileNo, @UserId, getdate(), 1, @UserId, getdate()
		from openjson(@jsonAddMember)
		with
		(
			GroupId			bigint			'$.GroupId',
			MemberId		bigint			'$.MemberId',
			IsGroupAdmin	bit				'$.IsGroupAdmin',
			ISDCode			nvarchar(16)	'$.ISDCode',
			MobileNo		nvarchar(30)	'$.MobileNo'	
		) T
		Where T.MemberId not in (select GM.UserId from tbl_clb_GroupMembers(nolock) GM where GM.GroupId=T.GroupId and GM.IsActive=1 and GM.IsBlocked=0 and GM.IsLeftGroup=0)

		Select SCOPE_IDENTITY() as Code, 'Group Member added successfully' as Msg

		Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
		select GM.GroupId,UD.ParentID, concat(UD.FName,' ',UD.LName,' (',UD.User_Login,') added to Group by '+@ActivityBy),14/*Activity*/,@UserId,G.GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@UserId,GETDATE()
		from	tbl_clb_GroupMembers(nolock) GM inner join User_Detail(nolock) UD
		ON		GM.UserId=UD.User_ID inner join tbl_clb_Group(nolock) G
		ON		GM.GroupId=G.GroupId
		WHERE	GM.GroupMemberId in (select id from #OutputId)

		SET @rowJson = (SELECT * FROM tbl_clb_GroupMembers(nolock) WHERE GroupMemberId in (select id from #OutputId) FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Ins_Clb_GrpMemb'
		SET @action = 'I'  
	End

	IF @rowJson IS NOT NULL  
	BEGIN  
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = 'tbl_clb_GroupMembers'  
	END  

End



GO

/* ============================================================
   Procedure: [dbo].[usp_clb_AddConversation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_clb_AddConversation
(
	@GroupId			bigint,
	@Content			nvarchar(max),
	@ContentTypeId		int,
	@SenderId			bigint,
	@ReceiverType		nvarchar(20),
	@ContentAction		nvarchar(50), -- Reply, Forward
	@ContentActionRef	bigint,
	@SentOn				datetime,
	@StatusId			int,
	@UserId				bigint
)
As
Begin

	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null, @ParentId bigint, @ConversationId bigint

	Select @ParentId=ParentId from User_detail(nolock) where User_ID=@UserId

	Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
	values(@GroupId,@ParentId,@Content,@ContentTypeId,@SenderId,@ReceiverType,@ContentAction,@ContentActionRef,GETDATE(),@StatusId,1,@UserId,GETDATE())

	select @ConversationId=SCOPE_IDENTITY()

	Select @ConversationId as Code, 'Conversation sent successfully' as Msg

	SET @rowJson = (SELECT * FROM tbl_clb_Conversation(nolock) WHERE ConversationId=@ConversationId FOR JSON AUTO,INCLUDE_NULL_VALUES)
	SET @activity = 'Ins_Clb_Chat'
	SET @action = 'I'  

	IF @rowJson IS NOT NULL  
	BEGIN  
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = 'tbl_clb_Conversation'  
	END  

End



