/* ============================================================
   Procedure: [dbo].[usp_clb_Get_Group]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_clb_Get_Group @UserId=32222,@GroupId=0
-- exec usp_clb_Get_Group @UserId=32226,@GroupId=0
-- exec usp_clb_Get_Group @UserId=34594,@GroupId=0
-- exec usp_clb_Get_Group @UserId=34594,@GroupId=111
CREATE   PROC usp_clb_Get_Group
(
	@UserId		bigint,
	@GroupId	bigint=0 -- 0 - All, <> 0 - particular row
)
As
Begin
	-- declare @UserId bigint=32222,@GroupId bigint=0
	-- declare @UserId bigint=32226,@GroupId bigint=0
	-- declare @UserId bigint=36893,@GroupId bigint=0
	-- declare @UserId bigint=34594,@GroupId bigint=0
	-- declare @UserId bigint=34594,@GroupId bigint=328
	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null, @ParentId bigint, @IsAdmin bit

	If(@GroupId=0) -- All
	Begin
		Select @ParentId=ParentId,@IsAdmin=IsAdmin from User_detail(nolock) where User_ID=@UserId
		/*If(@ParentId=@UserId or @IsAdmin=1)
		Begin
			Select *
			From (
				select ROW_NUMBER()over(partition by GR.GroupId order by CONV.ConversationId desc) Sno, GR.GroupId,
				GroupName=case when GR.GroupType='Individual' then isnull((select top 1 concat(UD.FName,' ',UD.LName,'(',UD.User_Login,')') from User_Detail(nolock) UD where UD.User_ID in (Select GM.UserID from tbl_clb_GroupMembers(nolock)GM Where GM.GroupId=GR.GroupId and GM.IsActive=1 and GM.UserId != @UserId) ),''/*GR.GroupName*/) else GR.GroupName end,
				GR.GroupDesc, GR.Visibility, GR.GroupType, GR.ParentId, GR.IsActive, GR.CreatedBy, GR.CreatedOn, GR.ModifiedBy, GR.ModifiedOn, GR.ProfileUrl, UnreadMsgCnt=sum(iif(CONVDET.ReadOn is null and CONVDET.ReceiverId=@UserId,1,0)) over(partition by GR.GroupId),LastMsg=CONV.Content,LastMsgTimeStamp=isnull(CONVDET.DeliveredOn, CONV.SentOn), IsGrpAdmin=IIF(GR.CreatedBy=@UserId,1,isnull(GRM.IsGroupAdmin,0)), ContentTypeId=isnull(CONV.ContentTypeId,0), ContentType=isnull(CT.ContentType,''), CONV.ConversationId
				from tbl_clb_Group(nolock)GR left join tbl_clb_Conversation(nolock)CONV
				on	 GR.groupId=CONV.GroupId and CONV.IsActive=1 and CONV.IsDeleted=0 left join tbl_clb_ConversationDetail(nolock)CONVDET
				on	 CONV.ConversationId = CONVDET.ConversationId and CONVDET.IsActive=1 and CONVDET.IsDeleted=0 and CONVDET.ReceiverId=@UserId /*and CONVDET.ReadOn is null*/ left join tbl_clb_GroupMembers(nolock) GRM
				on	GR.GroupId=GRM.GroupId and GRM.IsleftGroup=0 and GRM.IsBlocked=0 and GRM.IsActive=1 and GRM.UserId=@UserId left join tbl_clb_ContentType(nolock) CT
				on	CONV.ContentTypeId=CT.ContentTypeId
				where GR.ParentId=@ParentId and GR.IsActive=1 
			) T
			Where T.Sno=1
			order by T.ConversationId desc
		End
		Else*/
		Begin
			Select *
			From (
				select ROW_NUMBER()over(partition by GR.GroupId order by CONV.ConversationId desc) Sno, GR.GroupId,
				GroupName=case when GR.GroupType='Individual' then isnull((select top 1 concat(UD.FName,' ',UD.LName,' (',UD.User_Login,')') from User_Detail(nolock) UD where UD.User_ID in (Select GM.UserID from tbl_clb_GroupMembers(nolock)GM Where GM.GroupId=GR.GroupId and GM.IsActive=1 and GM.UserId != @UserId) ),GR.GroupName) else GR.GroupName end,GR.GroupDesc,GR.Visibility,GR.GroupType,GR.ParentId,GR.IsActive,GR.CreatedBy,GR.CreatedOn,GR.ModifiedBy,GR.ModifiedOn,ProfileUrl=case when GR.GroupType='Individual' then isnull((select top 1 case when UD.Image != '' then ('https://docs.kit19.com/' + REPLACE(REPLACE(UD.Image, '~', ''), '/User', 'User')) else 'https://docs.kit19.com/default/person.png' end from User_Detail(nolock) UD where UD.User_ID in (Select GM.UserID from tbl_clb_GroupMembers(nolock)GM Where GM.GroupId=GR.GroupId and GM.IsActive=1 and GM.UserId != @UserId)),GR.ProfileUrl) else GR.ProfileUrl end,UnreadMsgCnt=sum(iif(CONVDET.ReadOn is null and CONVDET.ReceiverId=@UserId,1,0)) over(partition by GR.GroupId), LastMsg=CONV.Content,LastMsgTimeStamp=isnull(CONVDET.DeliveredOn, CONV.SentOn), IsGrpAdmin=IIF(GR.CreatedBy=@UserId,1,isnull(GRM.IsGroupAdmin,0)), ContentTypeId=isnull(CONV.ContentTypeId,0), ContentType=isnull(CT.ContentType,''), CONV.ConversationId, lastMsgSenderId=CONV.SenderId,
				LastMsgSenderName=concat(UD1.FName,' ',UD1.LName,' (',UD1.User_Login,')')
				from tbl_clb_Group(nolock)GR left join tbl_clb_Conversation(nolock)CONV
				on	 GR.groupId=CONV.GroupId and CONV.IsActive=1 and CONV.IsDeleted=0 left join tbl_clb_ConversationDetail(nolock)CONVDET
				on	CONV.ConversationId = CONVDET.ConversationId and CONVDET.IsActive=1 and CONVDET.IsDeleted=0 and CONVDET.ReceiverId=@UserId /*and CONVDET.ReadOn is null*/ left join tbl_clb_GroupMembers(nolock) GRM
				on	GR.GroupId=GRM.GroupId and GRM.IsleftGroup=0 and GRM.IsBlocked=0 and GRM.IsActive=1 and GRM.UserId=@UserId left join tbl_clb_ContentType(nolock) CT
				on	CONV.ContentTypeId=CT.ContentTypeId left join User_Detail(nolock) UD1
				on	CONV.SenderId=UD1.User_ID
				where GR.ParentId=@ParentId and GR.IsActive=1 and (GR.CreatedBy=@UserId or GR.GroupId in (Select GRM.GroupId from tbl_clb_GroupMembers(nolock)GRM where GRM.IsActive=1 and GRM.IsBlocked=0 and GRM.IsLeftGroup=0 and GRM.UserId=@UserId))
			) T
			Where T.Sno=1
			order by T.ConversationId desc
		End
	End
	Else -- particular row
	Begin
		Select *
		From (
			select ROW_NUMBER()over(partition by GR.GroupId order by CONV.ConversationId desc) Sno, GR.GroupId,
			GroupName=case when GR.GroupType='Individual' then isnull((select top 1 concat(UD.FName,' ',UD.LName,' (',UD.User_Login,')') from User_Detail(nolock) UD where UD.User_ID in (Select GM.UserID from tbl_clb_GroupMembers(nolock)GM Where GM.GroupId=GR.GroupId and GM.IsActive=1 and GM.UserId != @UserId) ),GR.GroupName) else GR.GroupName end, GR.GroupDesc, GR.Visibility, GR.GroupType,GR.ParentId,GR.IsActive,GR.CreatedBy,GR.CreatedOn,GR.ModifiedBy,GR.ModifiedOn, ProfileUrl=case when GR.GroupType='Individual' then isnull((select top 1 case when UD.Image != '' then ('https://docs.kit19.com/' + REPLACE(REPLACE(UD.Image, '~', ''), '/User', 'User')) else 'https://docs.kit19.com/default/person.png' end from User_Detail(nolock) UD where UD.User_ID in (Select GM.UserID from tbl_clb_GroupMembers(nolock)GM Where GM.GroupId=GR.GroupId and GM.IsActive=1 and GM.UserId != @UserId)),GR.ProfileUrl) else GR.ProfileUrl end,UnreadMsgCnt=sum(iif(CONVDET.ReadOn is null and CONVDET.ReceiverId=@UserId,1,0)) over(partition by GR.GroupId), LastMsg=CONV.Content,LastMsgTimeStamp=isnull(CONVDET.DeliveredOn, CONV.SentOn), IsGrpAdmin=IIF(GR.CreatedBy=@UserId,1,isnull(GRM.IsGroupAdmin,0)), ContentTypeId=isnull(CONV.ContentTypeId,0), ContentType=isnull(CT.ContentType,''), CONV.ConversationId, lastMsgSenderId=CONV.SenderId,
			LastMsgSenderName=concat(UD1.FName,' ',UD1.LName,' (',UD1.User_Login,')')
			from tbl_clb_Group(nolock)GR left join tbl_clb_Conversation(nolock)CONV
			on	 GR.groupId=CONV.GroupId and CONV.IsActive=1 and CONV.IsDeleted=0 left join tbl_clb_ConversationDetail(nolock)CONVDET
			on	CONV.ConversationId = CONVDET.ConversationId and CONVDET.IsActive=1 and CONVDET.IsDeleted=0 and CONVDET.ReceiverId=@UserId /*and CONVDET.ReadOn is null*/ left join tbl_clb_GroupMembers(nolock) GRM
			on	GR.GroupId=GRM.GroupId and GRM.IsleftGroup=0 and GRM.IsBlocked=0 and GRM.IsActive=1 and GRM.UserId=@UserId left join tbl_clb_ContentType(nolock) CT
			on	CONV.ContentTypeId=CT.ContentTypeId left join User_Detail(nolock) UD1
			on	CONV.SenderId=UD1.User_ID
			where GR.GroupId=@GroupId /*GR.ParentId=@ParentId*/ --and GR.IsActive=1 and (GR.CreatedBy=@UserId or GR.GroupId in (Select GRM.GroupId from tbl_clb_GroupMembers(nolock)GRM where GRM.IsActive=1 and GRM.IsBlocked=0 and GRM.IsLeftGroup=0 and GRM.UserId=@UserId))
		) T
		Where T.Sno=1
		order by T.ConversationId desc
	End

	SET @rowJson = ''  
	SET @activity = 'View_Clb_Grp'
	SET @action = 'S'  

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
	,@Activity_type = @activity  
	,@ActionType = @action  
	,@RowJson = @rowJson  
	,@Table_name = 'tbl_clb_Group'  

End



GO

/* ============================================================
   Procedure: [dbo].[usp_clb_GetCalls]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_clb_GetCalls
(
	@SenderId			bigint,
	@SenderType			nvarchar(20), -- Individual/Group/All
	@CallType			nvarchar(10), -- Audio/Video/All
	@UserId				bigint,
	@FromRecNo			int=1,
	@ToRecNo			int=50
)
As
Begin
	-- declare @SenderId bigint=32226,@SenderType nvarchar(20)='Individual',@CallType nvarchar(10)='Audio',@UserId bigint=32226,@FromRecNo int=1,@ToRecNo int=50

	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null, @ParentId bigint, @ConversationId bigint

	Select @ParentId=ParentId from User_detail(nolock) where User_ID=@UserId

	Select * 
	From (
	SELECT	ROW_NUMBER()over(order by CD.CallLogId desc) SNo,CD.*,GRP.GroupName
	FROM	tbl_clb_CallDetail AS CD WITH (nolock) INNER JOIN tbl_clb_Group AS GRP WITH (nolock) 
	ON		CD.GroupId = GRP.GroupId INNER JOIN tbl_clb_CallReceiverDetail(NOLOCK) CRD
	ON		CD.CallLogId = CRD.CallLogId and CRD.ReceiverId=@userId
	Where CD.GroupId=Case when @SenderType = 'Group' then @SenderId else CD.GroupId end and
		  CD.SenderId=Case when @SenderType = 'Individual' then @SenderId else CD.SenderId end and
		  CD.CallType=case when @CallType = 'All' then CD.CallType else @CallType end and CD.IsActive=1 and CRD.IsActive=1
	) T
	Where T.SNo between @FromRecNo and @ToRecNo

	SET @rowJson = ''
	SET @activity = 'View_Clb_Call'
	SET @action = 'S'  

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
	,@Activity_type = @activity  
	,@ActionType = @action  
	,@RowJson = @rowJson  
	,@Table_name = 'tbl_clb_CallDetail'  

End



GO

/* ============================================================
   Procedure: [dbo].[usp_clb_GetCollaborationData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_clb_GetCollaborationData @jsonData='{"Mode":"GetGroupMember","UserId":32222,"GroupId":1}'
-- exec usp_clb_GetCollaborationData @jsonData='{"Mode":"GetCallLog","UserId":32222,"FromRecNo":1,"ToRecNo":50}'
-- exec usp_clb_GetCollaborationData @jsonData='{"Mode":"GetAgentByParentId","UserId":32222}'
-- exec usp_clb_GetCollaborationData @jsonData='{"Mode":"GetPermission","UserId":32222}'
-- exec usp_clb_GetCollaborationData @jsonData='{"Mode":"GetPermission","UserId":34594}'
-- exec usp_clb_GetCollaborationData @jsonData='{"Mode":"GetUserList","UserId":34594}'
CREATE   PROC [dbo].[usp_clb_GetCollaborationData]
(
	@jsonData	nvarchar(max)
)
As
Begin
	-- declare @jsonData nvarchar(max)='{"Mode":"GetGroupMember","UserId":32222,"GroupId":1}'
	-- declare @jsonData nvarchar(max)='{"Mode":"GetCallLog","UserId":32222,"FromRecNo":1,"ToRecNo":50}'
	-- declare @jsonData nvarchar(max)='{"Mode":"GetAgentByParentId","UserId":32222}'
	-- declare @jsonData nvarchar(max)='{"Mode":"BulkStarChatReceiver","UserId":32222,"ConversationId":[49,53,56],"StatusId":0}'
	-- declare @jsonData nvarchar(max)='{"Mode":"SetPermission","UserId":32222,"PermissionIds":"49,53,56"}'
	-- declare @jsonData nvarchar(max)='{"Mode":"SearchChat","UserId":32222,"GroupId":"44","SearchText":"msg"}'
	-- declare @jsonData nvarchar(max)=N'{"Mode": "BulkChatReceiver","DefResponseId":"1","ActionTimeStamp":"19-Dec-2023 16:45:25.000","UserId": 32222,"ReceiverIds": [36893,37442,42546],"ConversationId": 1078}'
	-- declare @jsonData nvarchar(max)=N'{"Mode": "GetUserList","UserId":"32483"}'
	-- declare @jsonData nvarchar(max)=N'{"Mode": "AddGroupWithMember","UserId":32222,"GroupName":"TetsGrp3","GroupDesc":"test Grp Desc3","Visibility":"Public","GroupType":"Group","ProfileUrl":"https://docs.kit19.com:443/32222/Enquiry/1697198831.jpg","IsActive":true,"jsonMemberList":[{"MemberId":32392,"IsGroupAdmin":false,"ISDCode":91,"MobileNo":9316832392},{"MemberId":32483,"IsGroupAdmin":false,"ISDCode":91,"MobileNo":9316832332}]}'
	-- declare @jsonData nvarchar(max)=N'{"Mode": "GlobalSearch","UserId":"32222","SearchText":"User"}'
	-- declare @jsonData nvarchar(max)=N'{"Mode": "GetUserList","UserId":"34594"}'
	-- declare @jsonData nvarchar(max)=N'{"Mode": "DeleteForEveryone","UserId":"32222","ConversationId": [1731,1732]}'
	-- declare @jsonData nvarchar(max)=N'{"Mode":"AddGroupWithMember","UserId":38991,"GroupName":"ankit asdads (34594-Ankit)","GroupDesc":"","Visibility":"Private","GroupType":"Individual","ProfileUrl":"https://docs.kit19.com/default/person.png","IsActive":true,"jsonMemberList":[{"MemberId":38993,"IsGroupAdmin":false,"ISDCode":"+91","MobileNo":7303590412}]}'
	-- declare @jsonData nvarchar(max)=N'{"Mode":"AddGetConversation","UserId":32222,"GroupId":452,"Content":"Test 456","ContentTypeId":1,"SenderId":32222,"ReceiverType":"Broadcast","ContentAction":"","ContentActionRef":0,"SentOn":"16-Mar-2024 17:02:17","StatusId":5}'

	DECLARE @activity VARCHAR(MAX) = '', @action VARCHAR(1) = '', @rowJson NVARCHAR(MAX) = null, 
			@TableName varchar(100)='', @ParentId bigint, @UserId bigint, @IsAdmin bit, @Mode nvarchar(100)=''

	Declare @GroupId bigint, @CloneUserId bigint, @SearchText nvarchar(200)
	Declare @FromRecNo int=1,@ToRecNo int=50
	declare @Content nvarchar(max), @ContentTypeId int, @SenderId bigint, 
			@ReceiverType nvarchar(20), @ContentAction nvarchar(50), @ContentActionRef bigint,
			@SentOn datetime, @StatusId int, @ConversationId bigint
	Declare @ConvDetailId bigint, @ActionTimeStamp datetime, @ActionUserId bigint
	Declare @GroupName nvarchar(250), @GroupDesc nvarchar(600), @Visibility	nvarchar(20), 
			@GroupType nvarchar(20), @ProfileUrl nvarchar(4000), @IsActive bit, 
			@ActivityBy varchar(150)=''
	
	drop table if exists #tmpConvId
	create table #tmpConvId(ConvDetailId bigint)

	Select @Mode=Mode,@UserId=UserId
	From openjson(@jsonData)
	With 
	(
		Mode		nvarchar(100)	'$.Mode',
		UserId		bigint			'$.UserId'
	)

	print '@jsonData: ' + isnull(@jsonData,'')
	print '@Mode: ' + isnull(@Mode,'')

	SELECT @ParentId = ParentID, @IsAdmin = IsAdmin, @ActivityBy=concat(FName,' ',LName,' (',User_Login,')')
	FROM User_Detail(nolock) 
	WHERE User_ID = @UserId;    

	print concat('@ParentId: ',@ParentId)
	print concat('@IsAdmin: ',@IsAdmin)
	print concat('@ActivityBy: ',@ActivityBy)

	If(@Mode='GetGroupMember')
	Begin
		Select @GroupId=GroupId
		From openjson(@jsonData)
		With 
		(
			GroupId		bigint      '$.GroupId'
		)

		Select	GM.*, ud.user_id as Id, ud.fname as FirstName, ud.lname as LastName, ud.user_login as UserName,
				'https://docs.kit19.com/' + isnull(nullif(ud.image,''),'default/agent.png') as image, concat(ud.fname,' ', ud.lname,' (',ud.user_login,')') as DisplayName, ud.CountryCode, cast(ud.Mobile as bigint) as Mobile, ud.DeviceID,IsSuperAdmin=IIf(GM.UserId=GM.AddedBy,1,0)
		From	tbl_clb_GroupMembers(nolock) GM inner join User_Detail(nolock) ud
		On		GM.UserId=ud.User_ID
		Where	GM.GroupId=@GroupId and GM.IsActive=1 and GM.IsLeftGroup=0 

		SET @rowJson = ''
		SET @activity = 'View_Clb_GrpMember'
		SET @action = 'S'  
		SET @TableName = 'tbl_clb_GroupMembers'
	End

	If(@Mode = 'GetCallLog')
	Begin
		-- declare @jsonData nvarchar(max)='{"Mode":"GetCallLog","UserId":32222,"FromRecNo":1,"ToRecNo":50}',@UserId bigint=32222,@FromRecNo int=1,@ToRecNo int=50, @ParentId bigint=32222

		Select @FromRecNo=FromRecNo,@ToRecNo=ToRecNo
		From openjson(@jsonData)
		With 
		(
			FromRecNo	int			'$.FromRecNo',
			ToRecNo		int			'$.ToRecNo'
		)

		select *
		From 
		(
			Select ROW_NUMBER()over(order by S.CallLogId desc) SNo, * 
			From
			(
				/*
				select	CD.CallLogId, CD.CallUrl, CD.CallType, CD.ReceiverType, CD.StartTime, CD.EndTime,
						CD.GeneratedOn, CallDirection='Outgoing', ud.user_id as Id, ud.fname as FirstName,
						ud.lname as LastName, ud.user_login as UserName, 'https://docs.kit19.com/' + isnull(nullif(ud.image,''),'default/agent.png') as image, concat(ud.fname,' ', ud.lname,' (',ud.user_login,')') as DisplayName, ud.CountryCode, cast(ud.Mobile as bigint) as Mobile, ud.DeviceID
				from	tbl_clb_CallDetail(nolock) CD inner join User_Detail(nolock) AS ud
				On		CD.SenderId=ud.User_ID
				Where	CD.IsActive=1 and CD.SenderId=@UserId
		
				union

				select	CRD.CallLogId, CD.CallUrl, CD.CallType, CD.ReceiverType, CRD.ReceivedOn as StartTime, 
						CRD.EndedOn as EndTime, CD.GeneratedOn, CallDirection='Incoming', ud.user_id as Id, 
						ud.fname as FirstName, ud.lname as LastName, ud.user_login as UserName, 'https://docs.kit19.com/' + isnull(ud.image,'default/agent.png') as image,
						concat(ud.fname,' ', ud.lname,' (',ud.user_login,')') as DisplayName, ud.CountryCode, cast(ud.Mobile as bigint) as Mobile, ud.DeviceID
				from	tbl_clb_CallReceiverDetail(nolock) CRD inner join tbl_clb_CallDetail(nolock) CD
				On		CRD.CallLogId=CD.CallLogId inner join User_Detail(nolock) AS ud
				On		CRD.ReceiverId=ud.User_ID
				Where	CD.IsActive=1 and CRD.IsActive=1 and CRD.ReceiverId=@UserId
				*/
				select	CRD.CallLogId, CD.CallUrl, CD.CallType, CD.ReceiverType, CRD.ReceivedOn as StartTime, 
				CRD.EndedOn as EndTime, CD.GeneratedOn, CallDirection=iif(CRD.ReceiverId=@UserId,'Incoming','Outgoing'), Id=iif(CRD.ReceiverId=@UserId,ud1.user_id,ud.user_id), 
				FirstName=iif(CRD.ReceiverId=@UserId,ud1.fname,ud.fname), LastName=iif(CRD.ReceiverId=@UserId,ud1.lname,ud.lname), UserName=iif(CRD.ReceiverId=@UserId,ud1.user_login,ud.user_login), image='https://docs.kit19.com/' + iif(CRD.ReceiverId=@UserId,isnull(ud1.image,'default/agent.png'),isnull(ud.image,'default/agent.png')),
				DisplayName=iif(CRD.ReceiverId=@UserId,concat(ud1.fname,' ', ud1.lname,' (',ud1.user_login,')'),concat(ud.fname,' ', ud.lname,' (',ud.user_login,')')), CountryCode=iif(CRD.ReceiverId=@UserId,ud1.CountryCode,ud.CountryCode), Mobile=iif(CRD.ReceiverId=@UserId,cast(ud1.Mobile as bigint),cast(ud.Mobile as bigint)), DeviceID=iif(CRD.ReceiverId=@UserId,ud1.DeviceID,ud.DeviceID)
				from	tbl_clb_CallReceiverDetail(nolock) CRD inner join tbl_clb_CallDetail(nolock) CD
				On		CRD.CallLogId=CD.CallLogId left join User_Detail(nolock) AS ud
				On		CRD.ReceiverId=ud.User_ID left join User_Detail(nolock) AS ud1
				On		CD.SenderId=ud1.User_ID
				Where	CD.IsActive=1 and CRD.IsActive=1 and (CRD.ReceiverId=@UserId or CD.SenderId=@UserId)

			) S
		) T
		Where T.SNo between @FromRecNo and @ToRecNo

		SET @rowJson = ''
		SET @activity = 'View_Clb_CallLog'
		SET @action = 'S'  
		SET @TableName = 'tbl_clb_CallDetail'
	End

	If(@Mode = 'GetAgentByParentId')
	Begin
		SELECT	ud.user_id as Id, ud.fname as FirstName, ud.lname as LastName, ud.user_login as UserName, 
				'https://docs.kit19.com/' + isnull(nullif(ud.image,''),'default/agent.png') as image, concat(ud.fname,' ', ud.lname,' (',ud.user_login,')') as DisplayName, ud.CountryCode, cast(ud.Mobile as bigint) as Mobile, ud.DeviceID 
		FROM	User_Detail(nolock) AS ud       
		WHERE	ud.[ParentId] = @ParentId and ud.status = 1         
		order by User_Login asc  
	End

	If(@Mode = 'AddGetConversation')
	Begin
		Select @GroupId=GroupId,@Content=Content,@ContentTypeId=ContentTypeId,@SenderId=SenderId,@ReceiverType=ReceiverType,@ContentAction=ContentAction,@ContentActionRef=ContentActionRef,@SentOn=SentOn,@StatusId=StatusId
		From openjson(@jsonData)
		With 
		(
			GroupId				bigint				'$.GroupId',
			Content				nvarchar(max)		'$.Content',
			ContentTypeId		int					'$.ContentTypeId',
			SenderId			bigint				'$.SenderId',
			ReceiverType		nvarchar(20)		'$.ReceiverType',
			ContentAction		nvarchar(50)		'$.ContentAction', 
			ContentActionRef	bigint				'$.ContentActionRef',
			SentOn				datetime			'$.SentOn',
			StatusId			int					'$.StatusId'
		)

		select @GroupType=GroupType from tbl_clb_Group(nolock) Where GroupId=@GroupId
		
		Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
		values(@GroupId,@ParentId,@Content,@ContentTypeId,@SenderId,@ReceiverType,@ContentAction,@ContentActionRef,GETDATE(),@StatusId,1,@UserId,GETDATE())

		select @ConversationId=SCOPE_IDENTITY()

		If(@GroupType='Broadcast')
		Begin
			Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn,RefConversationId)
			output inserted.ConversationId into #tmpConvId
			select GroupId, ParentId, @Content, @ContentTypeId, @SenderId, 'Individual', @ContentAction, @ContentActionRef, GETDATE(), @StatusId, 1, @UserId, GETDATE(), @ConversationId
			From (
			Select Row_number()over(partition by GM1.UserId,GM2.UserId order by GR.GroupId desc) as SNo,GR.GroupId,GR.GroupName,GR.GroupDesc,GR.Visibility,GR.GroupType,GR.ParentId,GR.IsActive,GR.CreatedBy,GR.CreatedOn,GR.ModifiedBy,GR.ModifiedOn,GR.ProfileUrl,GM1.UserId as User1,GM2.UserId as User2
			From tbl_clb_Group(nolock) GR inner join tbl_clb_GroupMembers(nolock) GM1
			ON	GR.GroupId=GM1.GroupId and GR.IsActive=1 inner join tbl_clb_GroupMembers(nolock) GM2
			On	GM1.GroupId=GM2.GroupId and GM1.UserId!=GM2.UserId and GM1.IsActive=1 and GM1.IsLeftGroup=0 and GM1.IsBlocked=0 and GM2.IsActive=1 and GM2.IsLeftGroup=0 and GM2.IsBlocked=0
			Where GR.GroupType='Individual' and GM1.UserId = @SenderId and GM2.UserId in (Select GM3.UserId From tbl_clb_GroupMembers(nolock) GM3 Where GM3.GroupId=@GroupId) 
			) as T
			Where T.Sno=1
		End
		Else
		Begin
			insert into #tmpConvId
			values(@ConversationId)
		End

		SELECT	CON.ConversationId, CON.GroupId, CON.ParentId, CON.[Content], CON.ContentTypeId, CON.SenderId,
				CON.ReceiverType, CON.ContentAction, CON.ContentActionRef, CON.SentOn, CON.StatusId,
				CON.IsStarred, CON.IsDeleted, CON.IsActive, CON.CreatedBy, CON.CreatedOn, CON.ModifiedBy,
				CON.ModifiedOn,	GRP.GroupName, GRP.Visibility, GRP.GroupType, CT.ContentType, STAT.StatusName,
				CDT.ReceiverId,	CDT.DeliveredOn, CDT.ReadOn, CDT.ReceivedOn, CON.RefConversationId
		FROM	tbl_clb_Conversation AS CON WITH (nolock) INNER JOIN tbl_clb_Group AS GRP WITH (nolock) 
		ON		CON.GroupId = GRP.GroupId INNER JOIN tbl_clb_ContentType AS CT WITH (nolock) 
		ON		CON.ContentTypeId = CT.ContentTypeId INNER JOIN tbl_clb_ConversationStatus(nolock) AS STAT
		ON		CON.StatusId = STAT.StatusId LEFT JOIN tbl_clb_ConversationDetail(NOLOCK) CDT
		ON		CON.ConversationId = CDT.ConversationId and CDT.IsActive=1 and CDT.IsDeleted=0
				and CDT.ReceiverId=@userId
		Where	CON.ConversationId in (Select ConvDetailId From #tmpConvId)

		SET @rowJson = (SELECT * FROM tbl_clb_Conversation(nolock) WHERE ConversationId in (Select ConvDetailId From #tmpConvId) FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Ins_Clb_Chat'
		SET @action = 'I'  
		SET @TableName = 'tbl_clb_Conversation'
	End

	If(@Mode = 'SetReadChatReceiver')
	Begin
		Select @ConversationId=ConversationId,@ActionTimeStamp=ActionTimeStamp
		From openjson(@jsonData)
		With 
		(
			ConversationId		bigint				'$.ConversationId',
			ActionTimeStamp		datetime			'$.ActionTimeStamp'
		)

		Select @GroupId=GroupId From tbl_clb_Conversation(nolock) Where ConversationId=@ConversationId

		Update	COND Set COND.ReadOn=@ActionTimeStamp, COND.ModifiedBy=@UserId, COND.ModifiedOn=GETDATE(), @ConvDetailId=COND.ConvDetailId
		output inserted.ConvDetailId into #tmpConvId
		From tbl_clb_ConversationDetail COND inner join tbl_clb_Conversation CON
		ON	COND.ConversationId=CON.ConversationId
		Where	COND.ConversationId<=@ConversationId and CON.GroupId=@GroupId and COND.ReceiverId=@UserId and COND.ReadOn is null

		Select @ConvDetailId as Code, 'Receiver Chat action ' + @Mode + ' done successfully' as Msg

		SET @rowJson = (SELECT * FROM tbl_clb_ConversationDetail(nolock) WHERE ConvDetailId in (select ConvDetailId From #tmpConvId) FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Upd_Clb_RecvrChatRead'
		SET @action = 'U'  
		SET @TableName = 'tbl_clb_ConversationDetail'
	End

	If(@Mode = 'SetReceivedChatReceiver')
	Begin
		Select @ConversationId=ConversationId,@ActionTimeStamp=ActionTimeStamp
		From openjson(@jsonData)
		With 
		(
			ConversationId		bigint				'$.ConversationId',
			ActionTimeStamp		datetime			'$.ActionTimeStamp'
		)

		Select @GroupId=GroupId From tbl_clb_Conversation(nolock) Where ConversationId=@ConversationId

		Update	COND Set COND.ReceivedOn=@ActionTimeStamp, COND.ModifiedBy=@UserId, COND.ModifiedOn=GETDATE(), @ConvDetailId=COND.ConvDetailId
		output inserted.ConvDetailId into #tmpConvId
		From tbl_clb_ConversationDetail COND inner join tbl_clb_Conversation CON
		ON	COND.ConversationId=CON.ConversationId
		Where	COND.ConversationId<=@ConversationId and CON.GroupId=@GroupId and COND.ReceiverId=@UserId and COND.ReceivedOn is null

		Select @ConvDetailId as Code, 'Receiver Chat action ' + @Mode + ' done successfully' as Msg

		SET @rowJson = (SELECT * FROM tbl_clb_ConversationDetail(nolock) WHERE ConvDetailId in (select ConvDetailId From #tmpConvId) FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Upd_Clb_RecvrChatRecv'
		SET @action = 'U'  
		SET @TableName = 'tbl_clb_ConversationDetail'
	End

	If(@Mode = 'DeleteForEveryone') --DeleteChatReceiver
	Begin
		insert into #tmpConvId
		Select B.value as ConvDetailId
		From openjson(@jsonData)
		With 
		(
			ConversationId		nvarchar(max) as Json
		)A cross apply openjson(A.ConversationId) B

		Update	tbl_clb_Conversation Set IsDeleted=1, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		From	tbl_clb_Conversation inner join #tmpConvId
		On		tbl_clb_Conversation.ConversationId=#tmpConvId.ConvDetailId

		Update	tbl_clb_ConversationDetail Set IsDeleted=1, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		From	tbl_clb_ConversationDetail inner join #tmpConvId
		On		tbl_clb_ConversationDetail.ConversationId=#tmpConvId.ConvDetailId
		Where	tbl_clb_ConversationDetail.IsActive=1

		Select @@ROWCOUNT as Code, 'Chat action ' + @Mode + ' done successfully' as Msg

		SET @rowJson = (SELECT * FROM tbl_clb_Conversation(nolock) WHERE ConversationId in (select ConvDetailId From #tmpConvId) FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'DelAll_Clb_Chat'
		SET @action = 'U'  
		SET @TableName = 'tbl_clb_Conversation'
	End

	If(@Mode = 'StarChatReceiver')
	Begin
		Select @ConversationId=ConversationId
		From openjson(@jsonData)
		With 
		(
			ConversationId		bigint				'$.ConversationId'
		)

		Update	tbl_clb_ConversationDetail Set IsStarred=1, ModifiedBy=@UserId, ModifiedOn=GETDATE(), @ConvDetailId=ConvDetailId
		Where	ConversationId=@ConversationId and ReceiverId=@UserId

		Select @ConvDetailId as Code, 'Receiver Chat action ' + @Mode + ' done successfully' as Msg

		SET @rowJson = (SELECT * FROM tbl_clb_ConversationDetail(nolock) WHERE ConvDetailId=@ConvDetailId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Star_Clb_RecvrChat'
		SET @action = 'U'  
		SET @TableName = 'tbl_clb_ConversationDetail'
	End

	If(@Mode = 'BulkChatReceiver')
	Begin

		Insert into tbl_clb_ConversationDetail(ConversationId,ReceiverId,DeliveredOn,DefResponseId,IsActive,CreatedBy,
CreatedOn)
		output inserted.ConvDetailId into #tmpConvId
		Select A.ConversationId, B.value as ReceiverId, A.ActionTimeStamp, A.DefResponseId, 1, @UserId, GETDATE()
		From openjson(@jsonData)
		With 
		(
			ConversationId		bigint			'$.ConversationId',
			DefResponseId		bigint			'$.DefResponseId',
			ActionTimeStamp		datetime		'$.ActionTimeStamp',
			ReceiverIds			nvarchar(max) as Json
		) A
		cross apply openjson(A.ReceiverIds) B

		Select @@ROWCOUNT as Code, 'Receiver Chat action ' + @Mode + ' done successfully' as Msg

		SET @rowJson = (SELECT * FROM tbl_clb_ConversationDetail(nolock) WHERE ConvDetailId in (select ConvDetailId From #tmpConvId) FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Bulk_Clb_RecvrChat'
		SET @action = 'I'  
		SET @TableName = 'tbl_clb_ConversationDetail'
	End

	If(@Mode = 'BulkStarChatReceiver')
	Begin

		Update CD Set IsStarred=1, ModifiedBy=@UserId, ModifiedOn=GETDATE(), @ConvDetailId=ConvDetailId
		output inserted.ConvDetailId into #tmpConvId
		From	tbl_clb_ConversationDetail CD inner join (Select A.UserId, B.value as ConversationId
		From openjson(@jsonData)
		With 
		(
			UserId			bigint			'$.UserId',
			ConversationId	nvarchar(max) as Json
		) A
		cross apply openjson(A.ConversationId) B) JD
		on CD.ConversationId=JD.ConversationId and CD.ReceiverId=JD.UserId

		Select @@ROWCOUNT as Code, 'Received Chat action ' + @Mode + ' done successfully' as Msg

		SET @rowJson = (SELECT * FROM tbl_clb_ConversationDetail(nolock) WHERE ConvDetailId in (select ConvDetailId From #tmpConvId) FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'BulkStar_Clb_RecvrChat'
		SET @action = 'U'  
		SET @TableName = 'tbl_clb_ConversationDetail'
	End

	If(@Mode = 'BulkUnStarChatReceiver')
	Begin

		Update CD Set IsStarred=0, ModifiedBy=@UserId, ModifiedOn=GETDATE(), @ConvDetailId=ConvDetailId
		output inserted.ConvDetailId into #tmpConvId
		From	tbl_clb_ConversationDetail CD inner join (Select A.UserId, B.value as ConversationId
		From openjson(@jsonData)
		With 
		(
			UserId			bigint			'$.UserId',
			ConversationId	nvarchar(max) as Json
		) A
		cross apply openjson(A.ConversationId) B) JD
		on CD.ConversationId=JD.ConversationId and CD.ReceiverId=JD.UserId

		Select @@ROWCOUNT as Code, 'Receiver Chat action ' + @Mode + ' done successfully' as Msg

		SET @rowJson = (SELECT * FROM tbl_clb_ConversationDetail(nolock) WHERE ConvDetailId in (select ConvDetailId From #tmpConvId) FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'BulkUnStar_Clb_RecvrChat'
		SET @action = 'U'  
		SET @TableName = 'tbl_clb_ConversationDetail'
	End

	If(@Mode = 'BulkDeleteChatReceiver') -- DeleteForMe
	Begin

		Update CD Set IsDeleted=1, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		output inserted.ConversationId into #tmpConvId
		From	tbl_clb_Conversation CD inner join (Select A.UserId, B.value as ConversationId
		From openjson(@jsonData)
		With 
		(
			UserId			bigint			'$.UserId',
			ConversationId	nvarchar(max) as Json
		) A
		cross apply openjson(A.ConversationId) B) JD
		on CD.ConversationId=JD.ConversationId and CD.SenderId=JD.UserId

		truncate table #tmpConvId

		Update CD Set IsDeleted=1, ModifiedBy=@UserId, ModifiedOn=GETDATE(), @ConvDetailId=ConvDetailId
		output inserted.ConvDetailId into #tmpConvId
		From	tbl_clb_ConversationDetail CD inner join (Select A.UserId, B.value as ConversationId
		From openjson(@jsonData)
		With 
		(
			UserId			bigint			'$.UserId',
			ConversationId	nvarchar(max) as Json
		) A
		cross apply openjson(A.ConversationId) B) JD
		on CD.ConversationId=JD.ConversationId and CD.ReceiverId=JD.UserId

		Select @@ROWCOUNT as Code, 'Receiver Chat action ' + @Mode + ' done successfully' as Msg

		SET @rowJson = (SELECT * FROM tbl_clb_ConversationDetail(nolock) WHERE ConvDetailId in (select ConvDetailId From #tmpConvId) FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'BulkDel_Clb_RecvrChat'
		SET @action = 'U'  
		SET @TableName = 'tbl_clb_ConversationDetail'
	End

	If(@Mode = 'GetPermission')
	Begin
		SELECT	P.PermissionId, P.PermissionName, cast(P.PermissionCode as varchar) as PermissionCode, P.SectionName, P.SubSectionLevel1,
				P.SubSectionLevel2, PermissionHierarchy=CONCAT(isnull(P.SectionName,''),'\',isnull(P.SubSectionLevel1,''),'\',isnull(P.SubSectionLevel2,''),'\',isnull(P.PermissionName,'')), PUM.PermissionMapId, UserId=isnull(PUM.UserId,@UserId), 
				ParentId=isnull(PUM.ParentId,@ParentId), IsAllowed=IIf(@UserId=@ParentId,1,IIf(isnull(PUM.PermissionId,0)>0,1,0))
		FROM	tbl_clb_Permissions(nolock) P LEFT JOIN	tbl_clb_PermissionUserMapping(nolock) PUM 
		ON		P.PermissionId = PUM.PermissionId and P.IsActive=1 and PUM.IsActive=1 AND PUM.UserId = @UserId
		Order by P.PermissionCode
	End

	If(@Mode = 'SetPermission')
	Begin
		If exists(Select * From tbl_clb_PermissionUserMapping(nolock) Where UserId=@UserId and IsActive=1)
		Begin
			Update tbl_clb_PermissionUserMapping 
			Set IsActive=0, @ActionUserId=CreatedBy, @ActionTimeStamp=CreatedOn
			Where UserId=@UserId and IsActive=1
		End
		Else
		Begin
			Select @ActionTimeStamp=null, @ActionUserId = null
		End

		Insert into tbl_clb_PermissionUserMapping(PermissionId, UserId, ParentId, IsActive, CreatedBy, CreatedOn, ModifiedBy, ModifiedOn)
		Select distinct item as PermissionId, @UserId as UserId, @ParentId as ParentId, 1 as IsActive, isnull(@ActionUserId, @UserId) as CreatedBy, isnull(@ActionTimeStamp, GETDATE()) as CreatedOn, iif(@ActionUserId is null,null,@UserId) as ModifiedBy, iif(@ActionTimeStamp is null,null,GETDATE()) as ModifiedOn
		from dbo.fu_SplitString((select PermissionIds
		From openjson(@jsonData)
		With 
		(
			PermissionIds	nvarchar(max)	'$.PermissionIds'
		)),',')

		select 'Permissions Saved Successfully' as Msg, 1 as Code
	End

	If(@Mode = 'ClonePermission')
	Begin
		Select @CloneUserId=CloneUserId
		From openjson(@jsonData)
		With 
		(
			CloneUserId		bigint			'$.CloneUserId'
		)


		Delete From tbl_clb_PermissionUserMapping Where UserId=@CloneUserId

		Insert into tbl_clb_PermissionUserMapping(PermissionId, UserId, ParentId, IsActive, CreatedBy, CreatedOn)
		Select distinct PermissionId, @CloneUserId as UserId, @ParentId as ParentId, 1 as IsActive, @CloneUserId as CreatedBy, GETDATE() as CreatedOn
		from tbl_clb_PermissionUserMapping(nolock)
		Where UserId=@UserId and IsActive=1

		select 'Permissions Cloned Successfully' as Msg, 1 as Code
	End

	If(@Mode = 'SearchChat')
	Begin
		Select @GroupId=GroupId,@SearchText=SearchText
		From openjson(@jsonData)
		With 
		(
			GroupId			bigint				'$.GroupId',
			SearchText		nvarchar(200)		'$.SearchText'
		)

		select *
		From (
		Select ROW_NUMBER()over(order by T.ConversationId desc) SNo,T.* 
		From (
		SELECT	ROW_NUMBER()over(partition by CON.ConversationId/*,CDT.ReceiverId*/ order by CON.ConversationId desc) RNo,
				CON.ConversationId, CON.GroupId, CON.ParentId, CON.[Content], CON.ContentTypeId, CON.SenderId,
				CON.ReceiverType, CON.ContentAction, CON.ContentActionRef, CON.SentOn, CON.StatusId, 
				IsStarred=IIF(CON.SenderId=@userId,CON.IsStarred,CDT.IsStarred), UD.User_Login as SenderName,
				IsDeleted=IIF(CON.SenderId=@userId,CON.IsDeleted,CDT.IsDeleted), 
				ProfilePicturePath=case when UD.Image != '' then ('https://docs.kit19.com/' + REPLACE(REPLACE(UD.Image, '~', ''), '/User', 'User')) else 'https://docs.kit19.com/default/person.png' end,
				CON.IsActive, CON.CreatedBy, CON.CreatedOn, CON.ModifiedBy, CON.ModifiedOn,
				GRP.GroupName, GRP.Visibility, GRP.GroupType, CT.ContentType, STAT.StatusName, CDT.ReceiverId,
				CDT.DeliveredOn, CDT.ReadOn, CDT.ReceivedOn
		FROM	tbl_clb_Conversation(nolock) CON INNER JOIN tbl_clb_Group(nolock) GRP
		ON		CON.GroupId = GRP.GroupId INNER JOIN tbl_clb_ContentType(nolock) CT
		ON		CON.ContentTypeId = CT.ContentTypeId INNER JOIN tbl_clb_ConversationStatus(nolock) STAT 
		ON		CON.StatusId = STAT.StatusId INNER JOIN User_Detail(Nolock) UD
		ON		CON.SenderId = UD.User_ID LEFT JOIN tbl_clb_ConversationDetail(NOLOCK) CDT
		ON		CON.ConversationId = CDT.ConversationId and CON.IsActive=1 and CDT.IsActive=1 
				--and CDT.IsDeleted=0 and CDT.ReceiverId=@userId
		Where CON.GroupId=@GroupId and
			  --(CON.SenderId=@userId or CDT.ReceiverId=@userId) and 
			  --CON.IsDeleted=0 and CON.IsActive=1 and 
			  CON.StatusId not in (6)
		) T
		Where T.RNo=1
		) U
		Where	U.[Content] like '%'+@SearchText+'%'

		SET @rowJson = ''
		SET @activity = 'View_Srch_Chat'
		SET @action = 'S'  
		SET @TableName = 'tbl_clb_Conversation'
	End

	If(@Mode = 'GetUserList')
	Begin
		select  UD.User_ID, UD.User_Login, concat(FName,' ',LName,' (',User_Login,')') as FullName, LH.ActivityType,
				ActivityDate=LH.Datecreated,ProfilePicturePath=case when UD.Image != '' then ('https://docs.kit19.com/' + REPLACE(REPLACE(UD.Image, '~', ''), '/User', 'User')) else 'https://docs.kit19.com/default/person.png' end,
				CountryCode, cast(Mobile as bigint) as Mobile, GroupId=(select top  1 GroupId
					From
					(
					select  G.GroupId From tbl_clb_Group(nolock) G inner join tbl_clb_GroupMembers(nolock) GM On G.GroupId=GM.GroupId Where G.GroupType='Individual' and G.IsActive=1 and GM.IsActive=1 and GM.userId=@UserId
					intersect 
					select  G.GroupId From tbl_clb_Group(nolock) G inner join tbl_clb_GroupMembers(nolock) GM On G.GroupId=GM.GroupId Where G.GroupType='Individual' and G.IsActive=1 and GM.IsActive=1 and GM.userId=UD.User_ID
					) T
				)
		FROM	User_Detail(Nolock) UD outer apply (SELECT top 1 * FROM [loginhistory](NOLOCK) WHERE user_id = UD.User_id order by 1 desc) LH
		Where	UD.ParentID=@ParentId and UD.Status=1 

		SET @rowJson = ''
		SET @activity = 'View_User_List'
		SET @action = 'S'  
		SET @TableName = 'User_Detail'
	End

	If(@Mode = 'AddGroupWithMember')
	Begin
		
		Select @GroupName=GroupName, @GroupDesc=GroupDesc, @Visibility=Visibility, @GroupType=GroupType, @ProfileUrl=ProfileUrl, @IsActive=IsActive, @Content=jsonMemberList
		From openjson(@jsonData)
		With 
		(
			GroupName			nvarchar(250),
			GroupDesc			nvarchar(600),
			Visibility			nvarchar(20), --	Public/Private
			GroupType			nvarchar(20), --	Group/Broadcast
			ProfileUrl			nvarchar(4000), 
			IsActive			bit,
			jsonMemberList		nvarchar(max) as Json
		)

		If(@GroupType='Individual')
		Begin
			If(@Content is not null)
			Begin
				declare @MemberId bigint=0

				Select @MemberId=MemberId
				from openjson(@Content)
				with
				(
					MemberId		bigint			'$.MemberId'	
				) T

				If not exists(select GR.GroupId,count(*) from tbl_clb_Group(nolock) GR inner Join tbl_clb_GroupMembers(nolock) GM On	GR.GroupId=GM.GroupId Where GR.ParentId=@ParentId and GR.IsActive=1 and GR.GroupType='Individual' and GM.IsActive=1 and GM.IsLeftGroup=0 and GM.IsBlocked=0 and GM.UserId in (@UserId,@MemberId) group by GR.GroupId having count(*)>1)
				Begin
					Insert into tbl_clb_Group(GroupName, GroupDesc, Visibility, GroupType, ProfileUrl, ParentId, IsActive, CreatedBy, CreatedOn)
					values(@GroupName, @GroupDesc, @Visibility, @GroupType, @ProfileUrl, @ParentId, @IsActive, @UserId, GETDATE())

					Set @GroupId=Scope_Identity()

					insert into tbl_clb_GroupMembers(GroupId, UserId, IsGroupAdmin, ISDCode, MobileNo, AddedBy, AddedOn, IsActive, CreatedBy, CreatedOn) 
					Select @GroupId, @UserId, 1, CountryCode, cast(Mobile as bigint), @UserId, getdate(), 1, @UserId, getdate()
					From User_Detail(nolock)
					Where User_ID=@UserId

					insert into tbl_clb_GroupMembers(GroupId, UserId, IsGroupAdmin, ISDCode, MobileNo, AddedBy, AddedOn, IsActive, CreatedBy, CreatedOn) 
					Select @GroupId, MemberId, IsGroupAdmin, ISDCode, MobileNo, @UserId, getdate(), 1, @UserId, getdate()
					from openjson(@Content)
					with
					(
						MemberId		bigint			'$.MemberId',
						IsGroupAdmin	bit				'$.IsGroupAdmin',
						ISDCode			nvarchar(16)	'$.ISDCode',
						MobileNo		nvarchar(30)	'$.MobileNo'	
					) T
					Where T.MemberId not in (select GM.UserId from tbl_clb_GroupMembers(nolock) GM where GM.GroupId=@GroupId and GM.IsActive=1 and GM.IsBlocked=0 and GM.IsLeftGroup=0)

					Select @GroupId as Code, 'Group with Member added successfully' as Msg

					Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
					select @GroupId,@ParentId,'Group Created by '+@ActivityBy,14/*Activity*/, @UserId,@GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@UserId,GETDATE()
				End
				Else
				Begin
					Select -1 as Code, 'Individual Group already exists' as Msg
				End
			End
			Else
			Begin
				Select -2 as Code, 'Group Member details missing' as Msg
			End
		End
		Else If(@GroupType='Group' or @GroupType='Broadcast')
		Begin
			If not exists(select * from tbl_clb_Group(nolock) GR Where GR.ParentId=@ParentId and GR.IsActive=1 and GR.GroupName=@GroupName)
			Begin
				Insert into tbl_clb_Group(GroupName,GroupDesc,Visibility,GroupType,ProfileUrl,ParentId,IsActive,CreatedBy,CreatedOn)
				values(@GroupName,@GroupDesc,@Visibility,@GroupType,@ProfileUrl,@ParentId,@IsActive,@UserId,GETDATE())

				Set @GroupId=Scope_Identity()

				insert into tbl_clb_GroupMembers(GroupId, UserId, IsGroupAdmin, ISDCode, MobileNo, AddedBy, AddedOn, IsActive, CreatedBy, CreatedOn) 
				Select @GroupId, @UserId, 1, CountryCode, cast(Mobile as bigint), @UserId, getdate(), 1, @UserId, getdate()
				From User_Detail(nolock)
				Where User_ID=@UserId

				If(@Content is not null)
				Begin
					insert into tbl_clb_GroupMembers(GroupId, UserId, IsGroupAdmin, ISDCode, MobileNo, AddedBy, AddedOn, IsActive, CreatedBy, CreatedOn) 
					Select @GroupId, MemberId, IsGroupAdmin, ISDCode, MobileNo, @UserId, getdate(), 1, @UserId, getdate()
					from openjson(@Content)
					with
					(
						MemberId		bigint			'$.MemberId',
						IsGroupAdmin	bit				'$.IsGroupAdmin',
						ISDCode			nvarchar(16)	'$.ISDCode',
						MobileNo		nvarchar(30)	'$.MobileNo'	
					) T
					Where T.MemberId not in (select GM.UserId from tbl_clb_GroupMembers(nolock) GM where GM.GroupId=@GroupId and GM.IsActive=1 and GM.IsBlocked=0 and GM.IsLeftGroup=0)
				End

				Select @GroupId as Code, 'Group with Member added successfully' as Msg

				Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
				select @GroupId,@ParentId,'Group Created by '+@ActivityBy,14/*Activity*/, @UserId,@GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@UserId,GETDATE()
			End
			Else
			Begin
				Select -1 as Code, 'Group already exists' as Msg
			End			
		End

		SET @rowJson = (SELECT * FROM tbl_clb_Group(nolock) G inner join tbl_clb_GroupMembers(nolock) GM On G.GroupId=GM.GroupId WHERE G.GroupId = @GroupId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'AddGrpMem_Clb_Group'
		SET @action = 'I'  
		SET @TableName = 'tbl_clb_Group'
	End

	If(@Mode = 'GlobalSearch')
	Begin
		Select @SearchText=SearchText
		From openjson(@jsonData)
		With 
		(
			SearchText		nvarchar(200)		'$.SearchText'
		)

		select *
		From (
		Select ROW_NUMBER()over(order by T.ConversationId desc) SNo,T.* 
		From (
		SELECT	ROW_NUMBER()over(partition by CON.ConversationId/*,CDT.ReceiverId*/ order by CON.ConversationId desc) RNo,
				CON.ConversationId, CON.GroupId, CON.ParentId, CON.[Content], CON.ContentTypeId, CON.SenderId,
				CON.ReceiverType, CON.ContentAction, CON.ContentActionRef, CON.SentOn, CON.StatusId, 
				IsStarred=IIF(CON.SenderId=@userId,CON.IsStarred,CDT.IsStarred), UD.User_Login as SenderName,
				IsDeleted=IIF(CON.SenderId=@userId,CON.IsDeleted,CDT.IsDeleted), 
				ProfilePicturePath=case when UD.Image != '' then ('https://docs.kit19.com/' + REPLACE(REPLACE(UD.Image, '~', ''), '/User', 'User')) else 'https://docs.kit19.com/default/person.png' end,
				CON.IsActive, CON.CreatedBy, CON.CreatedOn, CON.ModifiedBy, CON.ModifiedOn,
				GRP.GroupName, GRP.Visibility, GRP.GroupType, CT.ContentType, STAT.StatusName, CDT.ReceiverId,
				CDT.DeliveredOn, CDT.ReadOn, CDT.ReceivedOn
		FROM	tbl_clb_Conversation(nolock) CON INNER JOIN tbl_clb_Group(nolock) GRP
		ON		CON.GroupId = GRP.GroupId INNER JOIN tbl_clb_ContentType(nolock) CT
		ON		CON.ContentTypeId = CT.ContentTypeId INNER JOIN tbl_clb_ConversationStatus(nolock) STAT 
		ON		CON.StatusId = STAT.StatusId INNER JOIN User_Detail(Nolock) UD
		ON		CON.SenderId = UD.User_ID LEFT JOIN tbl_clb_ConversationDetail(NOLOCK) CDT
		ON		CON.ConversationId = CDT.ConversationId and CON.IsActive=1 and CDT.IsActive=1 
				--and CDT.IsDeleted=0 and CDT.ReceiverId=@userId
		Where CON.ParentId=@ParentId and
			  (CON.GroupId in (Select GroupId from tbl_clb_GroupMembers(nolock) where UserId=@UserId and IsBlocked=0 and IsActive=1 and IsLeftGroup=0)) and 
			  --CON.IsDeleted=0 and CON.IsActive=1 and 
			  CON.StatusId not in (6)
		) T
		Where T.RNo=1
		) U
		Where	U.[Content] like '%'+@SearchText+'%'

		select  UD.User_ID, UD.User_Login, concat(FName,' ',LName,' (',User_Login,')') as FullName, LH.ActivityType,
		ActivityDate=LH.Datecreated,ProfilePicturePath=case when UD.Image != '' then ('https://docs.kit19.com/' + REPLACE(REPLACE(UD.Image, '~', ''), '/User', 'User')) else 'https://docs.kit19.com/default/person.png' end,
		CountryCode, cast(Mobile as bigint) as Mobile, GroupId=(select top 1 G.GroupId From tbl_clb_Group(nolock) G inner join tbl_clb_GroupMembers(nolock) GM On G.GroupId=GM.GroupId Where G.GroupType='Individual' and G.IsActive=1 and GM.IsActive=1 and GM.userId=UD.User_ID)
		FROM	User_Detail(Nolock) UD outer apply (SELECT top 1 * FROM [loginhistory](NOLOCK) WHERE user_id = UD.User_id order by 1 desc) LH 
		Where	UD.ParentID=@ParentId and UD.Status=1 and concat(FName,' ',LName,' (',User_Login,')') like '%' + @SearchText+ '%'

		Select *
		From (
			select ROW_NUMBER()over(partition by GR.GroupId order by CONV.ConversationId desc) Sno, GR.GroupId,
			GroupName=case when GR.GroupType='Individual' then isnull((select top 1 concat(UD.FName,' ',UD.LName,' (',UD.User_Login,')') from User_Detail(nolock) UD where UD.User_ID in (Select GM.UserID from tbl_clb_GroupMembers(nolock)GM Where GM.GroupId=GR.GroupId and GM.IsActive=1 and GM.UserId != @UserId) ),GR.GroupName) else GR.GroupName end,GR.GroupDesc,GR.Visibility,GR.GroupType,GR.ParentId,GR.IsActive,GR.CreatedBy,GR.CreatedOn,GR.ModifiedBy,GR.ModifiedOn,GR.ProfileUrl,UnreadMsgCnt=sum(iif(CONVDET.ReadOn is null and CONVDET.ReceiverId=@UserId,1,0)) over(partition by GR.GroupId), LastMsg=CONV.Content,LastMsgTimeStamp=isnull(CONVDET.DeliveredOn, CONV.SentOn), IsGrpAdmin=IIF(GR.CreatedBy=@UserId,1,isnull(GRM.IsGroupAdmin,0)), ContentTypeId=isnull(CONV.ContentTypeId,0), ContentType=isnull(CT.ContentType,''), CONV.ConversationId
			from tbl_clb_Group(nolock)GR left join tbl_clb_Conversation(nolock)CONV
			on	 GR.groupId=CONV.GroupId and CONV.IsActive=1 and CONV.IsDeleted=0 left join tbl_clb_ConversationDetail(nolock)CONVDET
			on	CONV.ConversationId = CONVDET.ConversationId and CONVDET.IsActive=1 and CONVDET.IsDeleted=0 and CONVDET.ReceiverId=@UserId /*and CONVDET.ReadOn is null*/ left join tbl_clb_GroupMembers(nolock) GRM
			on	GR.GroupId=GRM.GroupId and GRM.IsleftGroup=0 and GRM.IsBlocked=0 and GRM.IsActive=1 and GRM.UserId=@UserId left join tbl_clb_ContentType(nolock) CT
			on	CONV.ContentTypeId=CT.ContentTypeId
			where GR.ParentId=@ParentId and GR.IsActive=1 and (GR.CreatedBy=@UserId or GR.GroupId in (Select GRM.GroupId from tbl_clb_GroupMembers(nolock)GRM where GRM.IsActive=1 and GRM.IsBlocked=0 and GRM.IsLeftGroup=0 and GRM.UserId=@UserId))
		) T
		Where T.Sno=1 and T.GroupName like '%' + @SearchText+ '%'
		order by T.ConversationId desc

		SET @rowJson = ''
		SET @activity = 'View_Srch_Global'
		SET @action = 'S'  
		SET @TableName = 'tbl_clb_Conversation'
	End

	IF (@Mode = 'GetTokenByUserId')
BEGIN
    IF EXISTS (
        SELECT 1 
        FROM User_Detail (NOLOCK)
        WHERE User_ID = @UserId 
          AND ISNULL(otp, '') <> ''
    )
    BEGIN
        SELECT otp AS Token
        FROM User_Detail (NOLOCK)
        WHERE User_ID = @UserId;
    END
    ELSE
    BEGIN
        SELECT 'Token Not Exist' AS Token;
    END
END


	If(@rowJson is not null)
	Begin
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = @TableName
	End

End



GO

/* ============================================================
   Procedure: [dbo].[usp_clb_GetCommonList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_clb_GetCommonList
(
	@ListType	nvarchar(50),
	@ParentId	bigint
)
As
Begin

	If(@ListType='ConversationStatus')
	Begin
		Select StatusId,StatusName From tbl_clb_ConversationStatus(nolock) Where IsActive=1
	End

	If(@ListType='ContentType')
	Begin
		Select ContentTypeId,ContentType From tbl_clb_ContentType(nolock) Where IsActive=1
	End

	If(@ListType='DefResponseByAudioCall')
	Begin
		Select DefResponseId,ResponseText From tbl_clb_DefaultResponse(nolock) 
		Where IsActive=1 and ResponseType='Audio' and ParentId=@ParentId or ParentId is null
	End

	If(@ListType='DefResponseByVideoCall')
	Begin
		Select DefResponseId,ResponseText From tbl_clb_DefaultResponse(nolock) 
		Where IsActive=1 and ResponseType='Video' and ParentId=@ParentId or ParentId is null
	End

	If(@ListType='DefResponseByChat')
	Begin
		Select DefResponseId,ResponseText From tbl_clb_DefaultResponse(nolock) 
		Where IsActive=1 and ResponseType='Chat' and ParentId=@ParentId or ParentId is null
	End

End



GO

/* ============================================================
   Procedure: [dbo].[usp_clb_GetConversation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_clb_GetConversation
(
	@SenderId			bigint,
	@SenderType			nvarchar(20), -- Individual/Group
	@UserId				bigint,
	@FromRecNo			int=1,
	@ToRecNo			int=50
)
As
Begin
	-- declare @SenderId bigint=32226,@SenderType nvarchar(20)='Individual',@UserId bigint=32226,@FromRecNo int=1,@ToRecNo int=50
	-- declare @SenderId bigint=8,@SenderType nvarchar(20)='Group',@UserId bigint=32226,@FromRecNo int=1,@ToRecNo int=50
	-- declare @SenderId bigint=0,@SenderType nvarchar(20)='',@UserId bigint=32483,@FromRecNo int=1,@ToRecNo int=50
	-- declare @SenderId bigint=0,@SenderType nvarchar(20)='',@UserId bigint=32222,@FromRecNo int=1,@ToRecNo int=50
	-- declare @SenderId bigint=44,@SenderType nvarchar(20)='Group',@UserId bigint=32483,@FromRecNo int=0,@ToRecNo int=1000
	-- declare @SenderId bigint=48,@SenderType nvarchar(20)='Group',@UserId bigint=0,@FromRecNo int=0,@ToRecNo int=1000
	-- declare @SenderId bigint=72,@SenderType nvarchar(20)='Individual',@UserId bigint=39882,@FromRecNo int=0,@ToRecNo int=1000
	-- declare @SenderId bigint=48,@SenderType nvarchar(20)='Group',@UserId bigint=39882,@FromRecNo int=0,@ToRecNo int=1000
	-- declare @SenderId bigint=51,@SenderType nvarchar(20)='Group',@UserId bigint=39882,@FromRecNo int=0,@ToRecNo int=1000
	-- declare @SenderId bigint=44,@SenderType nvarchar(20)='Group',@UserId bigint=36893,@FromRecNo int=0,@ToRecNo int=1000
	-- declare @SenderId bigint=110,@SenderType nvarchar(20)='Group',@UserId bigint=32397,@FromRecNo int=0,@ToRecNo int=1000
	-- declare @SenderId bigint=368,@SenderType nvarchar(20)='Group',@UserId bigint=32222,@FromRecNo int=0,@ToRecNo int=1000
	-- declare @SenderId bigint=390,@SenderType nvarchar(20)='Group',@UserId bigint=32222,@FromRecNo int=0,@ToRecNo int=1000

	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null, @ParentId bigint, @ConversationId bigint

	Select @ParentId=ParentId from User_detail(nolock) where User_ID=@UserId

	select *
	From (
	Select ROW_NUMBER()over(order by T.ConversationId desc) SNo,T.* 
	From (
	SELECT	ROW_NUMBER()over(partition by CON.ConversationId/*,CDT.ReceiverId*/ order by CON.ConversationId  desc, isnull(CDT.ReadOn,getdate()) desc, isnull(CDT.ReceivedOn,getdate()) desc) RNo,
			CON.ConversationId, CON.GroupId, CON.ParentId, CON.[Content], CON.ContentTypeId, CON.SenderId,
			CON.ReceiverType, CON.ContentAction, CON.ContentActionRef, CON.SentOn, CON.StatusId, 
			IsStarred=IIF(CON.SenderId=@userId,CON.IsStarred,CDT.IsStarred), UD.User_Login as SenderName,
			IsDeleted=IIF(CON.SenderId=@userId,CON.IsDeleted,CDT.IsDeleted), 
			ProfilePicturePath=case when UD.Image != '' then ('https://docs.kit19.com/' + REPLACE(REPLACE(UD.Image, '~', ''), '/User', 'User')) else 'https://docs.kit19.com/default/person.png' end,
			CON.IsActive, CON.CreatedBy, CON.CreatedOn, CON.ModifiedBy, CON.ModifiedOn,
			GRP.GroupName, GRP.Visibility, GRP.GroupType, CT.ContentType, STAT.StatusName, CDT.ReceiverId,
			CDT.DeliveredOn, CDT.ReadOn, CDT.ReceivedOn
	FROM	tbl_clb_Conversation(nolock) CON INNER JOIN tbl_clb_Group(nolock) GRP
	ON		CON.GroupId = GRP.GroupId INNER JOIN tbl_clb_ContentType(nolock) CT
	ON		CON.ContentTypeId = CT.ContentTypeId INNER JOIN tbl_clb_ConversationStatus(nolock) STAT 
	ON		CON.StatusId = STAT.StatusId INNER JOIN User_Detail(Nolock) UD
	ON		CON.SenderId = UD.User_ID LEFT JOIN tbl_clb_ConversationDetail(NOLOCK) CDT
	ON		CON.ConversationId = CDT.ConversationId and CON.IsActive=1 and CDT.IsActive=1 --and CDT.ReceiverId=iif(CON.ReceiverType='Individual',CDT.ReceiverId,@userId) 
			--and CDT.IsDeleted=0
	Where CON.GroupId=Case when @SenderType = 'Group' then @SenderId else CON.GroupId end and
		  CON.SenderId=Case when @SenderType = 'Individual' then @SenderId else CON.SenderId end and
		  --(CON.SenderId=@userId or CDT.ReceiverId=@userId) and 
		  --CON.IsDeleted=0 and CON.IsActive=1 and 
		  CON.StatusId not in (6)
	) T
	Where T.RNo=1
	) U
	Where U.SNo between @FromRecNo and @ToRecNo

	SET @rowJson = ''
	SET @activity = 'View_Clb_Chat'
	SET @action = 'S'  

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
	,@Activity_type = @activity  
	,@ActionType = @action  
	,@RowJson = @rowJson  
	,@Table_name = 'tbl_clb_Conversation'  

End



GO

/* ============================================================
   Procedure: [dbo].[usp_clb_ReceiveChat]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_clb_ReceiveChat
(
	@ConversationId		bigint,
	@ReceiverId			bigint,
	@DeliveredOn		datetime,
	@DefResponseId		bigint,
	@UserId				bigint
)
As
Begin

	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null, @ParentId bigint, @ConvDetailId bigint, @GroupId bigint, @GroupType nvarchar(40)

	Select @ParentId=ParentId from User_detail(nolock) where User_ID=@UserId
	Select @GroupId=GroupId from tbl_clb_Conversation(nolock) where ConversationId=@ConversationId
	Select @GroupType=GroupType from tbl_clb_Group(nolock) where GroupId=@GroupId

	-- receiver detail not be inserted for broadcast group, will be inserted for individual Group Instead
	If(@GroupType!='Broadcast')
	Begin
		Insert into tbl_clb_ConversationDetail(ConversationId,ReceiverId,DeliveredOn,DefResponseId,IsActive,CreatedBy,CreatedOn)
		values(@ConversationId,@ReceiverId,@DeliveredOn,@DefResponseId,1,@UserId,GETDATE())
	End

	select @ConvDetailId=SCOPE_IDENTITY()
	  
	Select @ConvDetailId as Code, 'Received chat' as Msg

	SET @rowJson = (SELECT * FROM tbl_clb_ConversationDetail(nolock) WHERE ConvDetailId=@ConvDetailId FOR JSON AUTO,INCLUDE_NULL_VALUES)
	SET @activity = 'Ins_Clb_ChatRecv'
	SET @action = 'I'  

	IF @rowJson IS NOT NULL  
	BEGIN  
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = 'tbl_clb_ConversationDetail'  
	END  

End



GO

/* ============================================================
   Procedure: [dbo].[usp_clb_Save_Group]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_clb_Save_Group
(
	@GroupId	bigint, -- 0 - insert, <> 0 - edit
	@GroupName	nvarchar(250),
	@GroupDesc	nvarchar(600),
	@Visibility	nvarchar(20), --	Public/Private
	@GroupType	nvarchar(20), --	Group/Broadcast
	@ProfileUrl	nvarchar(4000), 
	@ParentId	bigint,
	@IsActive	bit,
	@UserId		bigint
)
As
Begin

	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null,@activitydesc nvarchar(max)='', @ActivityBy varchar(150)=''

	select @ActivityBy=concat(FName,' ',LName,' (',User_Login,')') from User_Detail(nolock) Where User_ID=@UserId

	If(@GroupId=0) -- Insert
	Begin
		If not exists(select * from tbl_clb_Group(nolock) where ParentId=@ParentId and IsActive=1 and GroupName=@GroupName)
		Begin
			Insert into tbl_clb_Group(GroupName,GroupDesc,Visibility,GroupType,ProfileUrl,ParentId,IsActive,CreatedBy,CreatedOn)
			values(@GroupName,@GroupDesc,@Visibility,@GroupType,@ProfileUrl,@ParentId,@IsActive,@UserId,GETDATE())

			Set @GroupId=Scope_Identity()

			insert into tbl_clb_GroupMembers(GroupId,UserId,IsGroupAdmin,ISDCode,MobileNo,AddedBy,AddedOn,IsActive,CreatedBy,CreatedOn) 
			Select @GroupId, @UserId, 1, CountryCode, Mobile, @UserId, getdate(), 1, @UserId, getdate()
			From User_Detail(nolock)
			Where User_ID=@UserId

			Select @GroupId as Code, 'Group saved successfully' as Msg

			Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
			select @GroupId,@ParentId,'Group Created by '+@ActivityBy,14/*Activity*/,@UserId,@GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@UserId,GETDATE()

			SET @rowJson = (SELECT * FROM tbl_clb_Group(nolock) WHERE GroupId = @GroupId FOR JSON AUTO,INCLUDE_NULL_VALUES)  
			SET @activity = 'Ins_Clb_Grp'
			SET @action = 'I'  
		End
		Else
		Begin
			Select -1 as Code, 'Group already exists' as Msg
		End
	End
	Else -- Update
	Begin
		If not exists(select * from tbl_clb_Group(nolock) where ParentId=@ParentId and IsActive=1 and GroupName=@GroupName and GroupId!=@GroupId)
		Begin

			Select @activitydesc=concat(case when GroupName!=@GroupName then 'Group Name changed,' end, case when GroupDesc!=@GroupDesc then 'Group Description changed,' end, case when Visibility!=@Visibility then 'Group Visibility changed,' else '' end, case when GroupType!=@GroupType then 'Group Type changed,' else '' end, case when ProfileUrl!=@ProfileUrl then 'Profile Picture changed' else '' end)
			From tbl_clb_Group(nolock)
			Where GroupId=@GroupId

			Update tbl_clb_Group set GroupName=@GroupName,GroupDesc=@GroupDesc,Visibility=@Visibility,GroupType=@GroupType,ProfileUrl=@ProfileUrl,ParentId=@ParentId,IsActive=@IsActive,CreatedBy=@UserId,CreatedOn=GETDATE()
			Where GroupId=@GroupId

			Select @GroupId as Code, 'Group saved successfully' as Msg

			Insert into tbl_clb_Conversation(GroupId,ParentId,Content,ContentTypeId,SenderId,ReceiverType,ContentAction,ContentActionRef,SentOn,StatusId,IsActive,CreatedBy,CreatedOn)
			select @GroupId,@ParentId,item+' by '+@ActivityBy,14/*Activity*/,@UserId,@GroupType,'Activity',0,GETDATE(),5/*OK*/,1,@UserId,GETDATE()
			from dbo.splitstring(@activitydesc,',') 
			where item != ''

			SET @rowJson = (SELECT * FROM tbl_clb_Group(nolock) WHERE GroupId = @GroupId FOR JSON AUTO,INCLUDE_NULL_VALUES)  
			SET @activity = 'Upd_Clb_Grp'
			SET @action = 'U'  
		End
		Else
		Begin
			Select -1 as Code, 'Group already exists' as Msg
		End
	End

	IF @rowJson IS NOT NULL  
	BEGIN  
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = 'tbl_clb_Group'  
	END  

End



GO

