/* ============================================================
   Procedure: [dbo].[usp_clb_UpdateReceiverChatStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_clb_UpdateReceiverChatStatus
(
	@ActionMode			nvarchar(50),
	@UserId				bigint,
	@ConvDetailId		bigint=0,
	@ActionTimeStamp	Datetime=null
)
As
Begin

	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null

	If(@ActionMode = 'SetRead')
	Begin
		Update	tbl_clb_ConversationDetail Set ReadOn=@ActionTimeStamp, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		Where	ConvDetailId=@ConvDetailId 
	
		SET @activity = 'Upd_Clb_RecvrChatRead'
	End

	If(@ActionMode = 'SetReceived')
	Begin
		Update	tbl_clb_ConversationDetail Set ReceivedOn=@ActionTimeStamp, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		Where	ConvDetailId=@ConvDetailId 
	
		SET @activity = 'Upd_Clb_RecvrChatRecv'
	End

	If(@ActionMode = 'Delete')
	Begin
		Update	tbl_clb_ConversationDetail Set IsDeleted=1, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		Where	ConvDetailId=@ConvDetailId

		SET @activity = 'Del_Clb_RecvrChat'
	End

	If(@ActionMode = 'Star')
	Begin
		Update	tbl_clb_ConversationDetail Set IsStarred=1, ModifiedBy=@UserId, ModifiedOn=GETDATE()
		Where	ConvDetailId=@ConvDetailId 

		SET @activity = 'Star_Clb_RecvrChat'
	End

	Select @ConvDetailId as Code, 'Receiver Chat action ' + @ActionMode + ' done successfully' as Msg

	SET @rowJson = (SELECT * FROM tbl_clb_ConversationDetail(nolock) WHERE ConvDetailId=@ConvDetailId FOR JSON AUTO,INCLUDE_NULL_VALUES)
	SET @action = 'U'  

	IF @rowJson IS NOT NULL  
	BEGIN  
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = 'tbl_clb_ConversationDetail'  
	END  

End



