/* ============================================================
   Procedure: [dbo].[usp_clientemails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_clientemails    
as    
BEGIN    
declare @RecordCnt int;    
--declare @Batchid int;    
select @RecordCnt=COUNT(1) FROM MySMS.dbo.emailsfilter e (nolock) join BatchEmail_Infos b (nolock) on b.BatchID=e.Mail_BatchID and b.IsProcess=1    
--SELECT @logcnt    
while(@RecordCnt > 0)    
BEGIN    
SET NOCOUNT ON;    
DELETE TOP (1000) e from    
emailsfilter e join BatchEmail_Infos b on b.BatchID=e.Mail_BatchID and b.IsProcess=1    
SET @RecordCnt=@RecordCnt-1000;    
SET NOCOUNT ON;    
--SELECT @logaltcnt    
END    
    
    
select * into #clientemails from clientemails c (nolock) where     
SentDateTime<DATEADD(dd, 0, DATEDIFF(dd, 0, GETDATE())) and     
not exists(select 1 from emailsfilter (nolock) where mail_batchid=c.batchid)    
    
    
select @RecordCnt = count(1) from #clientemails    
while @RecordCnt>0    
begin    
insert into MySMS.dbo.ThirtyDaysClientEmails([ClientEmailsId]    
      ,[GUID]    
      ,[Email_Id]    
      ,[SentDateTime]    
      ,[UserId]    
      ,[ReplyTo]    
      ,[Status]     
      ,[BatchID]    
      ,[Campaignid]    
      ,[ParentId],
	  SentFinalDatetime,
CreatedBy,
Status_Desc)    
  select top 1000 [Id]    
      ,[GUID]    
      ,[Email_Id]    
      ,[SentDateTime]    
      ,[UserId]    
      ,[ReplyTo]    
      ,[Status]    
      ,[BatchID]    
      ,[Campaignid]    
      ,[ParentId],
	  SentFinalDatetime,
CreatedBy,
Status_Desc FROM #clientemails c     
  set @RecordCnt=@RecordCnt-1000    
  end        
          
      insert into [MySMS].[dbo].[ThirtyDaysMessages]([SentDateTime]    
      ,[UserId]    
      ,[ReplyTo]    
      ,[BatchID]    
      ,[Campaignid]    
      ,[ParentId]    
      ,[Message]    
      ,[Count])    
      select distinct  [SentDateTime]    
      ,[UserId]    
      ,[ReplyTo]    
      ,B.BatchID    
      ,C.Campaignid    
      ,C.ParentId    
      , case when c1.messages is not null then cast(c1.messages as nvarchar) when isnull(c1.templateid,0)<>0 then umt.mailcontent else (select top 1 Message FROM #clientemails where batchid=B.batchid) end    
      ,B.Count FROM #clientemails C (nolock) join     
   (select distinct batchid,Totalrecords as Count FROM batchemail_infos (nolock)) B on C.BatchID=B.batchid  left join   
   campaignmessages c1 on c1.BatchID=c.batchid left join usermailtemplate umt  
   on c1.templateid=umt.id  
      
          
select @RecordCnt = count(1) from #clientemails    
while @RecordCnt>0    
begin    
      delete top (1000) c from ClientEmails c join #clientemails cm on c.id=cm.id    
set @RecordCnt=@RecordCnt-1000    
end    
    
drop table #clientemails    
end


