      ,[SentDateTime]              
      ,[UserId]              
      ,[ReplyTo]              
      ,[Status]              
      ,[BatchID]              
      ,[Campaignid]              
      ,[ParentId],SentFinalDatetime , CreatedBy,Status_Desc FROM #clientemails c order by id           
          
declare @deletedIds table ( id bigint );          
          
   delete top (1000) cm           
   output deleted.id into @deletedIds          
   from (select top 1000 * from #clientemails order by id) cm;          
          
   delete c          
   from ClientEmails c          
    join @deletedIds d          
      on d.id = c.id;          
         
