/* ============================================================
   Procedure: [dbo].[Usp_CloneMessage_ByTbl]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_CloneMessage_ByTbl
(
  @CloneMSG_Tbl  CloneMessage_TBLType Readonly
 ,@TotalCount int
)
as
Begin

    if(@TotalCount > 0 and  @TotalCount < 6)
       Begin
	     
		 insert into CloneMessageDeliveryStatusLess
		 ( BatchID ,
           U_ID ,
           Mobile ,
           Message ,
           ScheduledDate ,
           ScheduledTime ,
           SenderID ,
           IsPrority ,
           IsAllowDND ,
           IsUniCode ,
           SmppID ,
           MobileSubSet ,
           MessageStatus
	    )
		select
		   BatchID ,
           U_ID ,
           Mobile ,
           Message ,
           ScheduledDate ,
           ScheduledTime ,
           SenderID ,
           IsPrority ,
           IsAllowDND ,
           IsUniCode ,
           SmppID ,
           MobileSubSet ,
           MessageStatus from  @CloneMSG_Tbl


	   end
    else if(@TotalCount > 5 and  @TotalCount < 201)
	   Begin
	      insert into CloneMessageDeliveryStatus
		 ( BatchID ,
           U_ID ,
           Mobile ,
           Message ,
           ScheduledDate ,
           ScheduledTime ,
           SenderID ,
           IsPrority ,
           IsAllowDND ,
           IsUniCode ,
           SmppID ,
           MobileSubSet ,
           MessageStatus
	    )
		select
		   BatchID ,
           U_ID ,
           Mobile ,
           Message ,
           ScheduledDate ,
           ScheduledTime ,
           SenderID ,
           IsPrority ,
           IsAllowDND ,
           IsUniCode ,
           SmppID ,
           MobileSubSet ,
           MessageStatus from  @CloneMSG_Tbl
   
	   end


	  select 'Record saved' 

End


