/* ============================================================
   Procedure: [dbo].[usp_Cloud_UserSearch_id]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Cloud_UserSearch_id]   
  @did varchar(20) ,        
  @mpas varchar(max)          
 AS          
 BEGIN 
 declare @searchid varchar(max) =''
 select position id,value into #tempsearches from dbo.fn_split(@mpas,',')  
 select * from #tempsearches
 declare @pid bigint=(select user_id from dbo.Cloud_app_master where PhoneNo=@did)           


 
 select @searchid= @searchid+','+ cast(id as varchar)  from usersearchlist where ParentID = @pid and		IsSearch =1      
   and SearchName in (select value From #tempsearches)     
select @searchid searchid,@pid pid
END



GO

