/* ============================================================
   Procedure: [dbo].[usp_coll_AddCollaboratorTeam]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_coll_AddCollaboratorTeam]
    @CollTypeName NVARCHAR(100),
    @AddedUserIds NVARCHAR(MAX),
    @UserId BIGINT,
    @CollTeamId BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        DECLARE @ExistingTeamId INT = NULL;

        -- Step 1: If team ID is passed, fetch team by ID
        IF @CollTeamId IS NOT NULL AND @CollTeamId > 0
        BEGIN
            SELECT @ExistingTeamId = id 
            FROM tbl_coll_CollaboratorTeams WITH(NOLOCK)
            WHERE id = @CollTeamId;

            IF @ExistingTeamId IS NOT NULL
            BEGIN
                -- Step 2: Update team
                UPDATE tbl_coll_CollaboratorTeams
                SET 
                    team_name = @CollTypeName,
                    lastmodifiedon = GETDATE(),
                    lastmodifiedby = @UserId
                WHERE id = @ExistingTeamId;

                -- Step 3: Delete old mappings
                DELETE FROM tbl_coll_Collaboratorteams_user_mapping
                WHERE team_id = @ExistingTeamId;

                -- Step 4: Insert new mappings
                ;WITH CTE_UserIds AS (
                    SELECT value AS user_id
                    FROM STRING_SPLIT(@AddedUserIds, ',')
                    WHERE TRY_CAST(value AS INT) IS NOT NULL
                )
                INSERT INTO tbl_coll_Collaboratorteams_user_mapping (
                    team_id, user_id, createdby, createdon, isactive
                )
                SELECT 
                    @ExistingTeamId,
                    CAST(user_id AS INT),
                    @UserId,
                    GETDATE(),
                    1
                FROM CTE_UserIds;

                SELECT 1 AS Status, 'Updated successfully' AS Message;
                RETURN;
            END
        END

        -- Step 5: If no CollTeamId, check for team name duplication
        IF EXISTS (
            SELECT 1 
            FROM tbl_coll_CollaboratorTeams WITH(NOLOCK)
            WHERE LTRIM(RTRIM(team_name)) = LTRIM(RTRIM(@CollTypeName))
        )
        BEGIN
            SELECT 0 AS Status, 'Team already exists' AS Message;
            RETURN;
        END

        -- Step 6: Insert new team
        INSERT INTO tbl_coll_CollaboratorTeams (team_name, createdby, createdon, isactive)
        VALUES (@CollTypeName, @UserId, GETDATE(), 1); 

        DECLARE @NewTeamId INT = SCOPE_IDENTITY();

        -- Step 7: Insert new mappings
        ;WITH CTE_UserIds AS (
            SELECT value AS user_id
            FROM STRING_SPLIT(@AddedUserIds, ',')
            WHERE TRY_CAST(value AS INT) IS NOT NULL
        )
        INSERT INTO tbl_coll_Collaboratorteams_user_mapping (
            team_id, user_id, createdby, createdon, isactive
        )
        SELECT 
            @NewTeamId, 
            CAST(user_id AS INT), 
            @UserId, 
            GETDATE(), 
            1
        FROM CTE_UserIds;

        SELECT 1 AS Status, 'Saved successfully' AS Message;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
        SELECT 0 AS Status, ERROR_MESSAGE() AS Message;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_coll_AddOrUpdateCollaboratorType]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_coll_AddOrUpdateCollaboratorType]
(
    @UserId BIGINT,
    @CollTypeName NVARCHAR(100),
    @ActionIds NVARCHAR(MAX),  -- comma-separated action IDs
    @CollTypeId BIGINT
)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        DECLARE @ExistingId INT;
        DECLARE @NewCollabTypeId INT;

        -- Check if updating existing record
        SELECT @ExistingId = id
        FROM Tbl_coll_CollaboratorTypeMaster WITH (NOLOCK)
        WHERE id = @CollTypeId AND isactive = 1;

        IF @ExistingId IS NOT NULL
        BEGIN
            -- Update existing record
            UPDATE Tbl_coll_CollaboratorTypeMaster
            SET 
                type_name = @CollTypeName,
                lastmodifiedon = GETDATE(),
                lastmodifiedby = @UserId
            WHERE id = @ExistingId;

            -- Delete old mappings
            DELETE FROM tbl_coll_CollaboratorType_Action_mapping
            WHERE collaborator_type_id = @ExistingId;

            -- Insert new mappings
            INSERT INTO tbl_coll_CollaboratorType_Action_mapping (
                collaborator_type_id,
                action_id,
                createdon,
                createdby
            )
            SELECT 
                @ExistingId,
                TRY_CAST([value] AS INT),
                GETDATE(),
                @UserId
            FROM STRING_SPLIT(@ActionIds, ',')
            WHERE TRY_CAST([value] AS INT) IS NOT NULL;

            SELECT 1 AS StatusCode, 'Updated successfully' AS Message;
        END
        ELSE
        BEGIN
            -- Check if a type with the same name already exists (case-insensitive)
            IF EXISTS (
                SELECT 1
                FROM Tbl_coll_CollaboratorTypeMaster WITH (NOLOCK)
                WHERE LTRIM(RTRIM(type_name)) = LTRIM(RTRIM(@CollTypeName)) AND isactive = 1
            )
            BEGIN
                SELECT 0 AS StatusCode, 'Collaborator type already exists' AS Message;
                RETURN;
            END

            -- Insert new record
            INSERT INTO Tbl_coll_CollaboratorTypeMaster (type_name, createdon, createdby, isactive)
            VALUES (@CollTypeName, GETDATE(), @UserId, 1);

            SET @NewCollabTypeId = SCOPE_IDENTITY();

            -- Insert mappings
            INSERT INTO tbl_coll_CollaboratorType_Action_mapping (
                collaborator_type_id,
                action_id,
                createdon,
                createdby
            )
            SELECT 
                @NewCollabTypeId,
                TRY_CAST([value] AS INT),
                GETDATE(),
                @UserId
            FROM STRING_SPLIT(@ActionIds, ',')
            WHERE TRY_CAST([value] AS INT) IS NOT NULL;

            SELECT 1 AS StatusCode, 'Saved successfully' AS Message;
        END
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK;

        SELECT 0 AS StatusCode, ERROR_MESSAGE() AS Message;

        EXEC usp_InsertErrorInfo;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_coll_ChangeCollTeamStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_coll_ChangeCollTeamStatus]  
(  
    @blStatus INT,  
    @CollTeamId BIGINT  
)  
AS  
BEGIN  
    BEGIN TRY  
        -- Check if the team ID exists in any mapping (as comma-separated value or exact match)
        IF EXISTS (
            SELECT 1 
            FROM tbl_coll_Lead_collaborator_mapping nolock
            WHERE ',' + ISNULL(teamid, '') + ',' LIKE '%,' + CAST(@CollTeamId AS NVARCHAR) + ',%'
        )
        BEGIN  
            SELECT 'Cannot change status. Team is already mapped in collaborator lead mapping.' AS Message  
            RETURN  
        END  

        -- Perform update if not found in mapping
        UPDATE tbl_coll_CollaboratorTeams 
        SET isactive = @blStatus 
        WHERE id = @CollTeamId  

        SELECT 'Status Changed' AS Message  
    END TRY  

    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;
    END CATCH  
END 



