    BEGIN TRY
        -- Insert data into Tbl_CB_WebhookSummary table
        INSERT INTO tbl_coll_CollaboratorTeams (team_name, createdon, createdby, isactive)
        VALUES (@CollTeamName, GETDATE(), @UserId,1);

