/* ============================================================
   Procedure: [dbo].[usp_Coll_DeleteTypeOrTeamById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Coll_DeleteTypeOrTeamById]
    @UserId BIGINT,
    @TeamId INT = NULL,
    @TypeId INT = NULL
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        IF @TeamId IS NOT NULL
        BEGIN
            UPDATE tbl_coll_CollaboratorTeams
            SET isactive = 0,
                lastmodifiedon = GETDATE(),
                lastmodifiedby = CAST(@UserId AS NVARCHAR(50))
            WHERE id = @TeamId AND isactive = 1;

            SELECT 'Deleted' AS Message;
            RETURN;
        END

        IF @TypeId IS NOT NULL
        BEGIN
            UPDATE Tbl_coll_CollaboratorTypeMaster
            SET isactive = 0,
                lastmodifiedon = GETDATE(),
                lastmodifiedby = CAST(@UserId AS NVARCHAR(50))
            WHERE id = @TypeId AND isactive = 1;

            SELECT 'Deleted' AS Message;
            RETURN;
        END

        -- If neither provided
        SELECT 'No action taken' AS Message;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
    END CATCH
END



