/* ============================================================
   Procedure: [dbo].[usp_coll_Get_Lead_Collaborator_Mapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

------------------------------------------------


CREATE   PROCEDURE [dbo].[usp_coll_Get_Lead_Collaborator_Mapping]
    @entityId INT
AS
BEGIN
    SET NOCOUNT ON;
	--declare @entityId INT=1772868
    --------------------------------------------------------------------
    -- Temporary table to store actual result
    --------------------------------------------------------------------
    DECLARE @Result TABLE
    (
        id BIGINT,
        entityId BIGINT,
        entityname NVARCHAR(255),
        type_names NVARCHAR(MAX),
        team_names NVARCHAR(MAX),
        UserName NVARCHAR(255),
        typeid NVARCHAR(MAX),
        teamid NVARCHAR(MAX),
        createdon DATETIME,
        createdby BIGINT,
        isactive BIT,
        updatedon DATETIME,
        updatedby BIGINT,
        userid BIGINT
    );

    --------------------------------------------------------------------
    -- Insert main query result
    --------------------------------------------------------------------
    INSERT INTO @Result
    SELECT 
        m.id,
        m.entityId,
        m.entityname,

        -- Type Names
        STUFF((SELECT ',' + t.type_name
               FROM STRING_SPLIT(m.typeid, ',') s
               INNER JOIN Tbl_coll_CollaboratorTypeMaster t ON t.id = s.value
               WHERE t.isactive = 1
               FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        -- Team Names
        STUFF((SELECT ',' + tm.team_name
               FROM STRING_SPLIT(m.teamid, ',') s
               INNER JOIN tbl_coll_CollaboratorTeams tm ON tm.id = s.value
               WHERE tm.isactive = 1
               FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        u.User_Login AS UserName,

        m.typeid,
        m.teamid,
        m.createdon,
        m.createdby,
        m.isactive,
        m.updatedon,
        m.updatedby,
        m.userid
    FROM dbo.tbl_coll_Lead_collaborator_mapping m WITH (NOLOCK)
    LEFT JOIN User_Detail u WITH (NOLOCK)
        ON u.User_ID = TRY_CAST(m.userid AS BIGINT)
    WHERE m.entityId = @entityId
      AND m.isactive = 1;

    --------------------------------------------------------------------
    -- If no records found, return default row
    --------------------------------------------------------------------
    IF NOT EXISTS (SELECT 1 FROM @Result)
    BEGIN
        INSERT INTO @Result
        VALUES
        (
            0,              -- id
            @entityId,      -- entityId
            NULL,           -- entityname
            '',             -- type_names
            '',             -- team_names
            '',             -- UserName
            'Empty',        -- typeid
            'Empty',        -- teamid
            NULL,           -- createdon
            0,              -- createdby
            1,              -- isactive
            NULL,           -- updatedon
            0,              -- updatedby
            0               -- userid
        );
    END

    --------------------------------------------------------------------
    -- Final output (Convert NULL → Empty String)
    --------------------------------------------------------------------
    SELECT  
        id,
        entityId,
        entityname,
        type_names,
		 ISNULL(CONVERT(VARCHAR(20), team_names), '') AS team_names,
		 ISNULL(CONVERT(VARCHAR(20), UserName), '') AS UserName,
        typeid,
		ISNULL(CONVERT(VARCHAR(20), teamid), '') AS teamid,
        ISNULL(CONVERT(VARCHAR(25), createdon, 120), '1900-01-01 00:00:00.000') AS createdon,
        createdby,
        isactive,
        ISNULL(CONVERT(VARCHAR(25), updatedon, 120), '1900-01-01 00:00:00.000') AS updatedon,
        ISNULL(CONVERT(VARCHAR(20), updatedby), '') AS updatedby,
        ISNULL(CONVERT(VARCHAR(20), userid), '') AS userid
    FROM @Result;
END


------------------------------------------------------






