SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_coll_GetAllCollaboratorTypes]
    @UserID BIGINT = NULL,
    @TypeName NVARCHAR(100) = NULL
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        -- Result Set 1: Collaborator Types
        SELECT 
            id,
            type_name AS TypeName,
            createdon,
            createdby,
            isactive
        FROM Tbl_coll_CollaboratorTypeMaster WITH (NOLOCK)
        WHERE 
            (@UserID IS NULL OR TRY_CAST(createdby AS BIGINT) = @UserID)
            AND (@TypeName IS NULL OR @TypeName = '' OR type_name LIKE '%' + @TypeName + '%')
            AND isactive = 1
        ORDER BY id DESC;

        -- Result Set 2: Action Mapping with Action Type
        SELECT 
            m.collaborator_type_id AS CollaboratorTypeId,
            a.id AS ActionId,
            a.entity AS ActionType,           -- <-- Added: Type of action (e.g., Lead, Enquiry)
            a.action_name AS ActionName
        FROM tbl_coll_CollaboratorType_Action_mapping  m WITH (NOLOCK)
        INNER JOIN Tbl_coll_ActionMaster a WITH (NOLOCK) ON m.action_id = a.id;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
    END CATCH
END



