/* ============================================================
   Procedure: [dbo].[usp_Coll_GetTeamAndTypeByLeadId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Coll_GetTeamAndTypeByLeadId]
    @UserId BIGINT,
    @LeadId BIGINT
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRY

        -- ✅ Table 1: Collaborator Count (by distinct TypeId)
        SELECT 
            COUNT(DISTINCT TRY_CAST(lm.typeid AS INT)) AS CollaboratorCount
        FROM tbl_coll_Lead_collaborator_mapping lm with(nolock)
        WHERE lm.entityId = @LeadId
          AND lm.entityname = 'lead'
          AND lm.isactive = 1;

        -- ✅ Table 2: Team + Type pairs
        SELECT DISTINCT 
            TRY_CAST(lm.typeid AS INT) AS TypeId,
            ctm.type_name AS TypeName,
            TRY_CAST(lm.teamid AS INT) AS TeamId,
            tm.team_name AS TeamName
        FROM tbl_coll_Lead_collaborator_mapping lm with(nolock)
        INNER JOIN Tbl_coll_CollaboratorTypeMaster ctm with(nolock)
            ON TRY_CAST(lm.typeid AS INT) = ctm.id
        INNER JOIN tbl_coll_CollaboratorTeams tm with(nolock)
            ON TRY_CAST(lm.teamid AS INT) = tm.id
        WHERE lm.entityId = @LeadId
          AND lm.entityname = 'lead'
          AND lm.isactive = 1
          AND tm.isactive = 1
          AND ctm.isactive = 1
          AND TRY_CAST(lm.teamid AS INT) IS NOT NULL;

        -- ✅ Table 3: User + Type pairs
        SELECT DISTINCT 
            TRY_CAST(lm.typeid AS INT) AS TypeId,
            ctm.type_name AS TypeName,
            TRY_CAST(lm.userid AS INT) AS UserId,
            u.User_Login AS UserName
        FROM tbl_coll_Lead_collaborator_mapping lm with(nolock)
        INNER JOIN Tbl_coll_CollaboratorTypeMaster ctm with(nolock)
            ON TRY_CAST(lm.typeid AS INT) = ctm.id
        INNER JOIN User_Detail u with(nolock)
            ON TRY_CAST(lm.userid AS INT) = u.User_ID
        WHERE lm.entityId = @LeadId
          AND lm.entityname = 'lead'
          AND lm.isactive = 1
          AND ctm.isactive = 1
          AND TRY_CAST(lm.userid AS INT) IS NOT NULL;

        -- ✅ Table 4: Action Details (same as before)
        SELECT DISTINCT 
            am.id AS ActionId,
            am.entity,
            am.action_name,
            am.isactive,
            am.createdon
        FROM tbl_coll_Lead_collaborator_mapping lm with(nolock)
        INNER JOIN Tbl_coll_CollaboratorType_Action_mapping cta with(nolock)
            ON TRY_CAST(lm.typeid AS INT) = cta.collaborator_type_id
        INNER JOIN Tbl_coll_ActionMaster am with(nolock)
            ON cta.action_id = am.id
        WHERE lm.entityId = @LeadId
          AND lm.entityname = 'lead'
          AND lm.isactive = 1
          AND cta.isactive = 1
          AND am.isactive = 1;

    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
    END CATCH
END



