/* ============================================================
   Procedure: [dbo].[usp_coll_Insert_Lead_Collaborator_Mapping_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




 
 
 
 
 
 
 
CREATE   PROCEDURE [dbo].[usp_coll_Insert_Lead_Collaborator_Mapping_new]

(

    @entityId BIGINT,

    @entityname NVARCHAR(100),

    @typeids NVARCHAR(MAX) = NULL,

    @teamids NVARCHAR(MAX) = NULL,

    @userids NVARCHAR(MAX) = NULL,

    @createdby BIGINT,

    @deletedTypeIds NVARCHAR(MAX) = NULL,

    @deletedTeamIds NVARCHAR(MAX) = NULL,

    @deletedUserIds NVARCHAR(MAX) = NULL

)

AS

BEGIN

    SET NOCOUNT ON;

--	declare
 
--	 @entityId bigint=17727341,

--    @entityname NVARCHAR(100)='lead',

--   @typeids NVARCHAR(MAX) = '6,3,10,10,10',

--@teamids NVARCHAR(MAX) = '0,4,0,7,9',

--@userids NVARCHAR(MAX) = '32222,0,32221,0,0',       

--    @createdby BIGINT=32222,

--    @deletedTypeIds NVARCHAR(MAX) = NULL,  

--    @deletedTeamIds NVARCHAR(MAX) = NULL,  

--    @deletedUserIds NVARCHAR(MAX) = NULL  
 
 
    BEGIN TRY
 
    --------------------------------------------------------------------------

    -- STEP 0 — Build the row-wise dataset into #FinalPairs

    --------------------------------------------------------------------------
 
    IF OBJECT_ID('tempdb..#FinalPairs') IS NOT NULL DROP TABLE #FinalPairs;
 
    CREATE TABLE #FinalPairs

    (

        typeid INT,

        teamid INT NULL,

        userid BIGINT NULL

    );
 
    ;WITH TypeCTE AS (

        SELECT TRY_CAST(value AS INT) AS typeid,

               ROW_NUMBER() OVER (ORDER BY (SELECT 1)) AS rn

        FROM STRING_SPLIT(ISNULL(@typeids,''), ',')

    ),

    TeamCTE AS (

        SELECT NULLIF(TRY_CAST(value AS INT),0) AS teamid,

               ROW_NUMBER() OVER (ORDER BY (SELECT 1)) AS rn

        FROM STRING_SPLIT(ISNULL(@teamids,''), ',')

    ),

    UserCTE AS (

        SELECT NULLIF(TRY_CAST(value AS INT),0) AS userid,

               ROW_NUMBER() OVER (ORDER BY (SELECT 1)) AS rn

        FROM STRING_SPLIT(ISNULL(@userids,''), ',')

    )

    INSERT INTO #FinalPairs(typeid, teamid, userid)

    SELECT 

        T.typeid,

        TM.teamid,

        U.userid

    FROM TypeCTE T

    LEFT JOIN TeamCTE TM ON TM.rn = T.rn

    LEFT JOIN UserCTE U ON U.rn = T.rn

    WHERE T.typeid IS NOT NULL

      AND (TM.teamid IS NOT NULL OR U.userid IS NOT NULL);
 
    --------------------------------------------------------------------------

    -- STEP 1 — Handle Deletions

    --------------------------------------------------------------------------
 
    IF ISNULL(@deletedTypeIds,'') <> ''

       OR ISNULL(@deletedTeamIds,'') <> ''

       OR ISNULL(@deletedUserIds,'') <> ''

    BEGIN

        ;WITH DelType AS (

            SELECT TRY_CAST(value AS INT) AS typeid

            FROM STRING_SPLIT(@deletedTypeIds, ',')

            WHERE TRY_CAST(value AS INT) IS NOT NULL

        ),

        DelTeam AS (

            SELECT NULLIF(TRY_CAST(value AS INT),0) AS teamid

            FROM STRING_SPLIT(@deletedTeamIds, ',')

        ),

        DelUser AS (

            SELECT NULLIF(TRY_CAST(value AS INT),0) AS userid

            FROM STRING_SPLIT(@deletedUserIds, ',')

        ),

        DelPairs AS (

            SELECT t.typeid, tm.teamid, u.userid

            FROM DelType t

            FULL JOIN DelTeam tm ON 1=1

            FULL JOIN DelUser u ON 1=1

            WHERE t.typeid IS NOT NULL

              AND (tm.teamid IS NOT NULL OR u.userid IS NOT NULL)

        )

        UPDATE lm

        SET lm.isactive = 0,

            lm.updatedon = GETDATE(),

            lm.updatedby = @createdby

        FROM tbl_coll_Lead_collaborator_mapping lm

        JOIN DelPairs dp

            ON lm.typeid = dp.typeid

           AND ISNULL(lm.teamid,0) = ISNULL(dp.teamid,0)

           AND ISNULL(lm.userid,0) = ISNULL(dp.userid,0)

        WHERE lm.entityId = @entityId

          AND lm.entityname = @entityname

          AND lm.isactive = 1;

    END
 
    --------------------------------------------------------------------------

    -- STEP 2 — INSERT new row-wise pairs

    --------------------------------------------------------------------------
 
    INSERT INTO tbl_coll_Lead_collaborator_mapping

    (

        entityId, entityname, typeid, teamid, userid,

        createdon, createdby, isactive

    )

    SELECT 

        @entityId,

        @entityname,

        fp.typeid,

        fp.teamid,

        fp.userid,

        GETDATE(),

        @createdby,

        1

    FROM #FinalPairs fp

    WHERE NOT EXISTS (

        SELECT 1

        FROM tbl_coll_Lead_collaborator_mapping lm

        WHERE lm.entityId = @entityId

          AND lm.entityname = @entityname

          AND lm.typeid = fp.typeid

          AND ISNULL(lm.teamid,0) = ISNULL(fp.teamid,0)

          AND ISNULL(lm.userid,0) = ISNULL(fp.userid,0)

          AND lm.isactive = 1

    );
 
    --------------------------------------------------------------------------

    -- SUCCESS RESPONSE

    --------------------------------------------------------------------------

    SELECT 1 AS Status, 'Collaborator(s) processed successfully.' AS Message;
 
    END TRY

    BEGIN CATCH

        EXEC usp_InsertErrorInfo;

        SELECT 0 AS Status, ERROR_MESSAGE() AS Message;

    END CATCH

END
 


GO

/* ============================================================
   Procedure: [dbo].[usp_coll_Insert_Lead_Collaborator_Mapping_new1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_coll_Insert_Lead_Collaborator_Mapping_new1]

(

    @entityId        VARCHAR(MAX),     -- NOW COMMA SEPARATED

    @entityname      NVARCHAR(100),

    @typeids         NVARCHAR(MAX) = NULL,

    @teamids         NVARCHAR(MAX) = NULL,

    @createdby       BIGINT

)

AS

BEGIN  

    SET NOCOUNT ON;
 
    BEGIN TRY
 
    --------------------------------------------------------------------------

    -- STEP 0: Prepare split entityIds, typeIds, teamIds

    --------------------------------------------------------------------------
 
    IF OBJECT_ID('tempdb..#FinalPairs') IS NOT NULL DROP TABLE #FinalPairs;
 
    CREATE TABLE #FinalPairs

    (

        entityId BIGINT,

        typeid INT,

        teamid INT NULL

    );
 
    -- Split Entity Ids

    ;WITH EntityCTE AS (

        SELECT TRY_CAST(value AS BIGINT) AS entityId

        FROM STRING_SPLIT(ISNULL(@entityId,''), ',')

        WHERE TRY_CAST(value AS BIGINT) IS NOT NULL

    ),

    TypeCTE AS (

        SELECT TRY_CAST(value AS INT) AS typeid,

               ROW_NUMBER() OVER (ORDER BY (SELECT 1)) AS rn

        FROM STRING_SPLIT(ISNULL(@typeids,''), ',')

    ),

    TeamCTE AS (

        SELECT NULLIF(TRY_CAST(value AS INT),0) AS teamid,

               ROW_NUMBER() OVER (ORDER BY (SELECT 1)) AS rn

        FROM STRING_SPLIT(ISNULL(@teamids,''), ',')

    )

    INSERT INTO #FinalPairs(entityId, typeid, teamid)

    SELECT 

        E.entityId,

        T.typeid,

        TM.teamid

    FROM EntityCTE as E with(nolock)

    CROSS JOIN TypeCTE T

    LEFT JOIN TeamCTE TM ON TM.rn = T.rn

    WHERE T.typeid IS NOT NULL;
 
    --------------------------------------------------------------------------

    -- STEP 1 — INSERT new row-wise pairs (no userid anymore)

    --------------------------------------------------------------------------
 
    INSERT INTO tbl_coll_Lead_collaborator_mapping

    (

        entityId, entityname, typeid, teamid,

        createdon, createdby, isactive

    )

    SELECT 

        fp.entityId,

        @entityname,

        fp.typeid,

        fp.teamid,

        GETDATE(),

        @createdby,

        1

    FROM #FinalPairs fp

    WHERE NOT EXISTS (

        SELECT 1

        FROM tbl_coll_Lead_collaborator_mapping as lm with(nolock)

        WHERE lm.entityId  = fp.entityId

          AND lm.entityname = @entityname

          AND lm.typeid = fp.typeid

          AND ISNULL(lm.teamid,0) = ISNULL(fp.teamid,0)

          AND lm.isactive = 1

    );
 
    --------------------------------------------------------------------------

    -- SUCCESS RESPONSE

    --------------------------------------------------------------------------

    SELECT 1 AS Status, 'Collaborator(s) processed successfully.' AS Message;
 
    END TRY

    BEGIN CATCH

        EXEC usp_InsertErrorInfo;

        SELECT 0 AS Status, ERROR_MESSAGE() AS Message;

    END CATCH

END
 


