/* ============================================================
   Procedure: [dbo].[usp_coll_Insert_Lead_Collaborator_MappingFolloup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_coll_Insert_Lead_Collaborator_MappingFolloup]
    @entityId NVARCHAR(MAX),               -- Modified to accept comma-separated list
    @entityname NVARCHAR(100),
    @typeids NVARCHAR(MAX) = NULL,         -- comma-separated
    @teamids NVARCHAR(MAX) = NULL,         -- comma-separated
    @createdby BIGINT,
    @deletedTypeIds NVARCHAR(MAX) = NULL,  -- comma-separated
    @deletedTeamIds NVARCHAR(MAX) = NULL   -- comma-separated
AS
BEGIN
    SET NOCOUNT ON;
	--declare 
	--@entityId NVARCHAR(MAX)='1772665',               
 --   @entityname NVARCHAR(100)='lead',
 --   @typeids NVARCHAR(MAX) = '2',         
 --   @teamids NVARCHAR(MAX) = '4,3',        
 --   @createdby BIGINT=32222,
 --   @deletedTypeIds NVARCHAR(MAX) = NULL,  
 --   @deletedTeamIds NVARCHAR(MAX) = NULL 
    BEGIN TRY
        -- === DELETE MAPPINGS ===
        IF ISNULL(@deletedTypeIds, '') <> '' OR ISNULL(@deletedTeamIds, '') <> ''
        BEGIN
            ;WITH DelTypeCTE AS (
                SELECT TRY_CAST(TRIM(value) AS INT) AS typeid
                FROM STRING_SPLIT(@deletedTypeIds, ',')
                WHERE TRY_CAST(value AS INT) IS NOT NULL
            ),
            DelTeamCTE AS (
                SELECT TRY_CAST(TRIM(value) AS INT) AS teamid
                FROM STRING_SPLIT(@deletedTeamIds, ',')
                WHERE TRY_CAST(value AS INT) IS NOT NULL
            ),
            DelEntityCTE AS (
                SELECT TRY_CAST(TRIM(value) AS BIGINT) AS entityid
                FROM STRING_SPLIT(@entityId, ',')
                WHERE TRY_CAST(value AS BIGINT) IS NOT NULL
            ),
            DelPairs AS (
                SELECT e.entityid, dt.typeid, tm.teamid
                FROM DelEntityCTE e
                CROSS JOIN DelTypeCTE dt
                CROSS JOIN DelTeamCTE tm
            )
            UPDATE lm
            SET lm.isactive = 0,
                lm.updatedon = GETDATE(),
                lm.updatedby = @createdby
            FROM tbl_coll_Lead_collaborator_mapping lm with(nolock)
            JOIN DelPairs dp ON 
                lm.entityId = dp.entityid AND 
                lm.typeid = dp.typeid AND 
                lm.teamid = dp.teamid
            WHERE lm.entityname = @entityname
              AND lm.isactive = 1;
        END

        -- === INSERT MAPPINGS ===
        IF ISNULL(@typeids, '') <> '' AND ISNULL(@teamids, '') <> '' AND ISNULL(@entityId, '') <> ''
        BEGIN
            ;WITH EntityCTE AS (
                SELECT TRY_CAST(TRIM(value) AS BIGINT) AS entityid
                FROM STRING_SPLIT(@entityId, ',')
                WHERE TRY_CAST(value AS BIGINT) IS NOT NULL
            ),
            TypeCTE AS (
                SELECT TRY_CAST(TRIM(value) AS INT) AS typeid 
                FROM STRING_SPLIT(@typeids, ',') 
                WHERE TRY_CAST(value AS INT) IS NOT NULL
            ),
            TeamCTE AS (
                SELECT TRY_CAST(TRIM(value) AS INT) AS teamid 
                FROM STRING_SPLIT(@teamids, ',') 
                WHERE TRY_CAST(value AS INT) IS NOT NULL
            ),
            Combined AS (
                SELECT 
                    e.entityid,
                    t.typeid,
                    tm.teamid
                FROM EntityCTE e
                CROSS JOIN TypeCTE t
                CROSS JOIN TeamCTE tm
            )
            INSERT INTO tbl_coll_Lead_collaborator_mapping (
                entityId, entityname, typeid, teamid, createdon, createdby
            )
            SELECT 
                c.entityid,
                @entityname,
                c.typeid,
                c.teamid,
                GETDATE(),
                @createdby
            FROM Combined c
            WHERE NOT EXISTS (
                SELECT 1 
                FROM tbl_coll_Lead_collaborator_mapping lm with(nolock)
                WHERE 
                    lm.entityId = c.entityid
                    AND lm.entityname = @entityname
                    AND lm.typeid = c.typeid
                    AND lm.teamid = c.teamid
                    AND lm.isactive = 1
            );
        END

        SELECT 1 AS Status, 'Collaborator(s) processed successfully.' AS Message;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
        SELECT 0 AS Status, ERROR_MESSAGE() AS Message;
    END CATCH
END



