/* ============================================================
   Procedure: [dbo].[usp_CollegeDuniaWebhooks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_CollegeDuniaWebhooks](              
 @RequestJson nvarchar(max),              
 @ParentId bigint              
)              
as              
begin             
          
  begin try        
        
   declare @Mobile nvarchar(50) = '' , @CountryCode nvarchar(50) = ''      
  
      
  Select @Mobile = MobileNo, @CountryCode = CountryCode  
    from OpenJson(@RequestJson)         
  With      
   (        
 MobileNo nvarchar(max) '$.MobileNo',        
    CountryCode nvarchar(max) '$.CountryCode'     
   )        
        
   if(exists( select top 1 ID from tbl_CollegeDuniaWebhooks with(nolock) where ( ( RequestJson like '%"MobileNo":"'+ @Mobile +'"%'       
                                                     and RequestJson like '%"CountryCode":"'+ @CountryCode +'"%'        
                                                     ) and ParentID = @ParentId)
													 
													 order by ID desc ))      
      
        Begin      
            declare @RequestJsonDataMatched nvarchar(max) = ''      
   select top 1 @RequestJsonDataMatched = RequestJson from tbl_CollegeDuniaWebhooks with(nolock) where  
                                                     ( ( RequestJson like '%"MobileNo":"'+ @Mobile +'"%'       
                                                        and RequestJson like '%"CountryCode":"'+ @CountryCode +'"%'        
                 )  
              )  
              and ParentID = @ParentId        
              order by ID desc       
         
        select top 1 cast(ID as nvarchar(50)) as CollegeDuniaPrimaryID , cast(0 as nvarchar(50)) as Status, isnull(EnquiryID,0)  as  CollegeDuniaEnqID      
      , 'Duplicate Request Found' as RequestStatus      
     from tbl_CollegeDuniaWebhooks with(nolock)       
     where  
         (  ( RequestJson like '%"MobileNo":"'+ @Mobile +'"%'       
                 and RequestJson like '%"CountryCode":"'+ @CountryCode +'"%'        
      )  
    )  
    
  and ParentID = @ParentId        
     order by ID desc                
  End           
    else      
   Begin       
           insert into tbl_CollegeDuniaWebhooks(RequestJson, ParentId)              
     values(@RequestJson, @ParentId)              
          DECLARE @ID BIGINT = SCOPE_IDENTITY()       
                
    begin try       
       exec Usp_TransferLeadDatatoCustomFieldMapping @apiname='CollegeDunia',@rawleadid=@ID    
    end try      
    begin catch       
      exec usp_inserterrorInfo       
    end catch      
      
    Select  cast(ID as nvarchar(50)) as CollegeDuniaPrimaryID , cast(1 as nvarchar(50)) as Status, isnull(EnquiryID,0) as  CollegeDuniaEnqID      
     ,'Valid Request Found' as RequestStatus       
    from tbl_CollegeDuniaWebhooks with(nolock) where ID = @ID and ParentID = @ParentId             
       end       
      
  end try        
  begin catch        
    exec usp_inserterrorInfo        
  end catch          
        
end 


