/* ============================================================
   Procedure: [dbo].[usp_Common_ActionModebased]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE  PROCEDURE [dbo].[usp_Common_ActionModebased]
    @jsonData NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE 
        @Mode NVARCHAR(50),
        @UserId BIGINT,
        @CurrentPage NVARCHAR(255),
        @CompletedServices NVARCHAR(MAX),
        @CompletedSubServices NVARCHAR(MAX),
        @EventType NVARCHAR(50),
        @ItemId NVARCHAR(100),
        @VisitedAt DATETIME,
        @jsonResult NVARCHAR(MAX)--,  -- Unified variable for JSON results
        --@jsonData NVARCHAR(MAX)=N'{"Mode":"SkipWizard","UserId":51021}'
 
    -- Parse input JSON
    SELECT 
        @Mode = JSON_VALUE(@jsonData, '$.Mode'),
        @UserId = JSON_VALUE(@jsonData, '$.UserId'),
        @CurrentPage = JSON_VALUE(@jsonData, '$.CurrentPage');

    IF @UserId IS NULL RETURN;

    -- Mode: VerifyUser - Fetch user details
    IF @Mode = 'VerifyUser'
    BEGIN
        SELECT @jsonResult = (
            SELECT 
                User_ID, 
                DateCreated,
                (SELECT TOP 1 PageUrl FROM Wizard_Page_Visits (nolock)
                 WHERE UserId = User_ID ORDER BY VisitedAt DESC) AS LastVisitedPage
            FROM User_Detail WITH (NOLOCK)
            WHERE User_ID = @UserId
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        );
        SELECT @jsonResult AS JsonResult;
    END

    -- Mode: IsNewUser - Check if user is new (created within last 10 days)
    ELSE IF @Mode = 'IsNewUser'
    BEGIN
        DECLARE @IsNew BIT = 0;
        
        SELECT @IsNew = CASE 
            WHEN DateCreated >= DATEADD(DAY, -10, GETDATE()) THEN 1 ELSE 0 
        END
        FROM User_Detail WITH (NOLOCK)
        WHERE User_ID = @UserId;
        
        SELECT @jsonResult = (
            SELECT @IsNew AS IsNewUser
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        );
        SELECT @jsonResult AS JsonResult;
    END

    -- Mode: GetWizardStatus - Determine wizard visibility/status
    ELSE IF @Mode = 'GetWizardStatus'
    BEGIN
        DECLARE 
            @shouldShow BIT = 0,
            @isSkipped BIT = 0,
            @isPageClosed BIT = 0,
            @hideProgress BIT = 0,
            @completionDate DATETIME;

        -- User created in last 10 days?
        SELECT @shouldShow = CASE 
            WHEN DATEDIFF(DAY, DateCreated, GETDATE()) <= 10 THEN 1 ELSE 0 
        END
        FROM User_Detail(nolock) 
        WHERE User_ID = @UserId;

        -- Wizard skipped?
        SELECT @isSkipped = 1 
        FROM Wizard_User_Status(nolock) 
        WHERE UserId = @UserId AND Status = 'Skipped';

        -- Page closed by user?
        SELECT @isPageClosed = 1 
        FROM Wizard_User_Events(nolock)
        WHERE UserId = @UserId 
          AND EventType = 'page_closed' 
          AND PageUrl = @CurrentPage;

        -- Wizard completed >7 days ago?
        SELECT TOP 1 @completionDate = EventDate 
        FROM Wizard_User_Events(nolock) 
        WHERE UserId = @UserId AND EventType = 'wizard_completed';

        IF @completionDate IS NOT NULL AND DATEDIFF(DAY, @completionDate, GETDATE()) > 7
            SET @hideProgress = 1;

        -- Return status as JSON
        SELECT @jsonResult = (
            SELECT 
                @shouldShow AS shouldShow,
                @isSkipped AS isSkipped,
                @isPageClosed AS isPageClosed,
                @hideProgress AS hideProgressBar
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        );
        SELECT @jsonResult AS JsonResult;
    END

    -- Mode: GetWizardProgress - Fetch completion state
    ELSE IF @Mode = 'GetWizardProgress'
    BEGIN
        SELECT @jsonResult = (
            SELECT 
                JSON_QUERY(ISNULL(
                    (SELECT CompletedServices FROM Wizard_User_Progress(nolock) WHERE UserId = @UserId), 
                    '[]'
                )) AS completedServices,
                JSON_QUERY(ISNULL(
                    (SELECT CompletedSubServices FROM Wizard_User_Progress(nolock) WHERE UserId = @UserId), 
                    '[]'
                )) AS completedSubServices,
                (SELECT COUNT(*) 
                 FROM Wizard_Page_Visits(nolock) 
                 WHERE UserId = @UserId AND PageUrl = @CurrentPage) AS visitsToCurrentPage
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        );
        SELECT @jsonResult AS JsonResult;
    END

    -- Mode: SaveWizardProgress - Update completion state and log visit
    ELSE IF @Mode = 'SaveWizardProgress'
    BEGIN
        SELECT 
            @CompletedServices = JSON_VALUE(@jsonData, '$.CompletedServices'),
            @CompletedSubServices = JSON_VALUE(@jsonData, '$.CompletedSubServices');

        MERGE INTO Wizard_User_Progress AS target
        USING (SELECT @UserId AS UserId) AS source
        ON target.UserId = source.UserId
        WHEN MATCHED THEN UPDATE SET 
            CompletedServices = @CompletedServices,
            CompletedSubServices = @CompletedSubServices,
            LastUpdated = GETDATE()
        WHEN NOT MATCHED THEN INSERT (UserId, CompletedServices, CompletedSubServices, LastUpdated)
            VALUES (@UserId, @CompletedServices, @CompletedSubServices, GETDATE());

        INSERT INTO Wizard_Page_Visits (UserId, PageUrl, VisitedAt)
        VALUES (@UserId, @CurrentPage, GETDATE());
    
          SELECT scope_identity() AS JsonResult;
    
    END

    -- Mode: TrackEvent - Record user interaction
    ELSE IF @Mode = 'TrackEvent'
    BEGIN
        SELECT 
            @EventType = JSON_VALUE(@jsonData, '$.EventType'),
            @ItemId = JSON_VALUE(@jsonData, '$.ItemId'),
            @VisitedAt = ISNULL(JSON_VALUE(@jsonData, '$.EventDate'), GETDATE());

        INSERT INTO Wizard_User_Events (UserId, EventType, ItemId, PageUrl, EventDate)
        VALUES (@UserId, @EventType, @ItemId, @CurrentPage, @VisitedAt);

        -- Log additional visit for specific events
        IF @EventType IN ('wizard_opened', 'service_completed', 'subservice_completed')
        BEGIN
            INSERT INTO Wizard_Page_Visits (UserId, PageUrl, VisitedAt, AssociatedEvent)
            VALUES (@UserId, @CurrentPage, @VisitedAt, @EventType);
        END

         SELECT scope_identity()  AS JsonResult;
    END

    -- Mode: SkipWizard - Mark wizard as skipped
    ELSE IF @Mode = 'SkipWizard'
    BEGIN
        MERGE INTO Wizard_User_Status AS target
        USING (SELECT @UserId AS UserId) AS source
        ON target.UserId = source.UserId
        WHEN MATCHED THEN UPDATE SET 
            Status = 'Skipped', 
            SkipDate = GETDATE()
        WHEN NOT MATCHED THEN INSERT (UserId, Status, SkipDate)
            VALUES (@UserId, 'Skipped', GETDATE());
    
        SELECT 'Skipped'  AS JsonResult;
    END

ELSE IF @Mode = 'GetTourStatus'
BEGIN
    DECLARE @tourStatus NVARCHAR(20) = 'not_started';
    

    SELECT TOP 1 @tourStatus = EventType 
    FROM Wizard_User_Events (nolock)
    WHERE UserId = @UserId 
        AND PageUrl = @CurrentPage 
        AND EventType IN ('tour_completed', 'tour_closed')
    ORDER BY EventDate DESC;
    
    SELECT @tourStatus AS TourStatus;
END

ELSE IF @Mode = 'SaveTourStatus'
BEGIN
 
    SELECT 
            @EventType = JSON_VALUE(@jsonData, '$.EventType'),
            @ItemId = JSON_VALUE(@jsonData, '$.ItemId'),
            @VisitedAt = ISNULL(JSON_VALUE(@jsonData, '$.EventDate'), GETDATE());
    INSERT INTO Wizard_User_Events (UserId, EventType, ItemId, PageUrl, EventDate)
    VALUES (@UserId, @EventType, 'TourGuide', @CurrentPage, GETDATE());

      SELECT scope_identity()  AS JsonResult;
END
ELSE IF @Mode = 'DeleteTask'

BEGIN
 
    SET @ItemId = TRY_CAST(JSON_VALUE(@jsonData, '$.TaskId') AS BIGINT);
 
    IF @ItemId IS NOT NULL

    BEGIN

        EXEC usp_mk_tsk_DeleteTaskDetailById 

            @Id = @ItemId,

            @UserId = @UserId;
 
        -- Success message

        SELECT 

            1 AS Status,

            'Task deleted successfully' AS Message;

    END

    ELSE

    BEGIN

        SELECT 

            0 AS Status,

            'Invalid TaskId' AS Message;

    END

END
 



END








GO

/* ============================================================
   Procedure: [dbo].[usp_commonInteralOperations]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_commonInteralOperations(    
 @UserId bigint,    
 @Mode nvarchar(255),    
 @Payload nvarchar(max)    
)    
as    
begin    
    
 --declare     
 -- @UserId bigint,    
 -- @Mode nvarchar(255),    
 -- @Payload nvarchar(max)    
    
 --select @UserId=335,@Mode=N'execute_procedure',@Payload=N'{"procedureName":"usp_ims_GetConversationPaylaodForAPI","parameters":[{"Name":"@MobileNo","Value":"9315028217"},{"Name":"@UserLogin","Value":"KANDD941485"},{"Name":"@TemplateName","Value":"conex"}]}'


    
 print 'Executing your request'    
    
 declare @procedureName nvarchar(255)    
    
 if(@Mode = 'get_procedures')    
 begin    
      
  select ProcedureName, DisplayName from tbl_internalOperationProcedures(nolock)    
    
 end    
    
 if(@Mode = 'get_params')    
 begin    
  set @procedureName = JSON_VALUE(@Payload, '$.procedureName')    
    
  SELECT *    
  FROM OPENJSON((select top 1 ParameterJson from tbl_internalOperationProcedures(nolock) where ProcedureName = @procedureName ))    
  WITH (    
   ParameterName NVARCHAR(100) '$.ParameterName',    
   DataType NVARCHAR(50) '$.DataType',    
   MaxLength INT '$.MaxLength',    
   Precision INT '$.Precision',    
   Scale INT '$.Scale',    
   IsOutput BIT '$.IsOutput'    
  );    
    
 end    
    
 if(@Mode = 'execute_procedure')    
 begin    
  insert into tbl_internalOperationLogs(Mode, Payload, ExecutedBy)    
   values (@Mode, @Payload, @Userid)    
    
  set @procedureName = JSON_VALUE(@Payload, '$.procedureName')    
    
    
  DECLARE @ProcName NVARCHAR(256) = JSON_VALUE(@Payload, '$.procedureName');    
  DECLARE @sqlProcedure NVARCHAR(MAX), @sqlParams nvarchar(max)    
    
    
  SELECT @sqlParams = isnull(@sqlParams, '') + [Name] + ' = ' + QUOTENAME([Value], '''') + ', '    
   FROM OPENJSON(@Payload, '$.parameters')    
     WITH (    
      [Name] NVARCHAR(128) '$.Name',    
