/* ============================================================
   Procedure: [dbo].[usp_contact_bulk_eachContact_Import]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_contact_bulk_eachContact_Import]           
@m_id bigint,          
@user_id int, -- from bigint,          
@group_id bigint,      
@name varchar(100),      
@number varchar(100),      
@email varchar(100),      
@bloodGroup varchar(40),      
@dob varchar(40),      
@anniversary varchar(50)      
 as   
declare @result int  
if not exists (select Contact_Mobile  from contact_detail where Contact_Mobile= @number and user_id=@user_id and m_id=@m_id and group_id=@group_id )      
begin      
insert  into contact_detail(m_id,user_id,group_id,Contact_Name,Contact_Mobile,Contact_Email,Contact_BG,Contact_DOB,Contact_Anniversary)       
values      
(@m_id,@user_id,@group_id,@name,@number,@email,@bloodGroup,@dob,@anniversary)      
declare @contactid bigint
set @contactid=scope_identity()
insert into Contact_Group_Detail(m_id,user_id,group_id,contact_id) values (@m_id,@user_id,@group_id,@contactid)
set @result=1  
if @@error=0  
begin   
set @result=1  
end   
else   
begin  
set @result=0  
end  
end   
  
else  
begin  
set @result=0  
end  
  
select @result



GO

