/* ============================================================
   Procedure: [dbo].[Usp_ContactForApp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- =============================================      
-- Author:  <Chandra prakash singh and vinay kumar upadhyay>      
-- Create date: <21 March 2015>      
-- Description: <Description,,>      
-- =============================================      
CREATE   PROC [dbo].[Usp_ContactForApp]        
@User_ID int,      
@Contact_ID bigint,      
@Contact_Name varchar(50),      
@Contact_Mobile varchar(15),      
@Contact_DOB varchar(15),      
@Contact_Anniversary varchar(20),        
@Action varchar(20)          
          
as         
begin       
if (@Action='delete')      
begin       
  DELETE FROM Contact_Detail WHERE Contact_ID=@Contact_ID and User_ID=@User_ID      
  select 'Record  Deleted Successfully' as Msg      
  end      
    
else if (@Action='Update')      
begin  
IF NOT EXISTS(SELECT 'X' FROM  [dbo].[Contact_Detail] WHERE Contact_Mobile= @Contact_Mobile)  
begin      
  UPDATE Contact_Detail SET User_ID=@User_ID ,Contact_Name=@Contact_Name,Contact_Mobile=@Contact_Mobile,Contact_DOB=@Contact_DOB,Contact_Anniversary=@Contact_Anniversary WHERE Contact_ID=@Contact_ID and User_ID=@User_ID     
 select 'Record  Updated Successfully' as Msg     
 end     
  ELSE  
 BEGIN  
 SELECT 'MobileNo Already Exists' as Error  
 END  
 end   
  else if (@Action='Select')      
   begin      
  SELECT * FROM Contact_Detail WHERE User_ID=@User_ID and Contact_ID=@Contact_ID      
  end      
end 


GO

