            ISNULL(tteq.emailid2, '')  AS EmailID2,                              
            ISNULL(tteq.countrycode, '')  AS countrycode,                              
            ISNULL(tteq.countrycode1, '') AS countrycode1,                              
   ISNULL(tteq.countrycode2, '') AS countrycode2,                              
            tteq.country,                              
            tteq.[state],                              
