            A.MobileNo1,                              
            A.MobileNo2,                              
            A.EMAILID,                              
            A.EmailID1,                              
            A.EmailID2,            
   A.countrycode,      
   A.countrycode1,      
   A.countrycode2,      
            A.country,                              
            A.[state],                              
            A.city,                              
            A.pincode,                              
            A.residentialaddress,                              
            A.officeaddress,                              
            A.SourceName,                         
            A.MediumName,                              
            A.CampaignName,                              
            A.initialremarks,                              
            A.WhatsAppNoColName,                              
            A.ParentID--,                              
            --A.CampaignID                              
     FROM   (                              
                SELECT tteq.ID , @SearchType as SearchType, tteq.personname,                              
       tteq.companyname,                              
                       ISNULL(tteq.mobileno, '') AS MobileNo,                              
                       ISNULL(tteq.mobileno1, '') AS MobileNo1,                              
                       ISNULL(tteq.mobileno2, '') AS MobileNo2,                              
                       ISNULL(tteq.emailid, '') AS EMAILID,                              
