      ISNULL(tteq.countrycode1, '') AS countrycode1,                              
      ISNULL(tteq.countrycode2, '') AS countrycode2,                              
                       tteq.country,           
                       tteq.[state],                              
                       tteq.city,                              
                       tteq.pincode,                              
                       tteq.residentialaddress,                              
                       tteq.officeaddress,                              
                       tteq.SourceName,                              
                       tteq.MediumName,                              
                       tteq.CampaignName,                              
                       tteq.initialremarks,                              
                       @CriteriaID    AS SearchID,                              
                       tteq.WhatsAppNoColName,      
                       @ParentID    AS ParentID--,                              
                       --@CampaignID  AS CampaignID                              
                FROM   @tblEnquiryData AS tteq                              
                                                    
                                              
                  
                                
                UNION                              
                                              
                                              
                                              
                SELECT tteq.ID , @SearchType as SearchType,tteq.personname,                              
                       tteq.companyname,                 
                       ISNULL(tteq.mobileno, '') AS MobileNo,                              
                       ISNULL(tteq.mobileno1, '') AS MobileNo1,                              
                       ISNULL(tteq.mobileno2, '') AS MobileNo2,                              
                       ISNULL(tteq.emailid, '') AS EMAILID,                              
                       ISNULL(tteq.emailid1, '') AS EmailID1,                              
                       ISNULL(tteq.emailid2, '') AS EmailID2,                              
      ISNULL(tteq.countrycode, '')  AS countrycode,                              
      ISNULL(tteq.countrycode1, '') AS countrycode1,                              
      ISNULL(tteq.countrycode2, '') AS countrycode2,                              
      tteq.country,                              
                       tteq.[state],                              
                       tteq.city,                              
                       tteq.pincode,                              
                       tteq.residentialaddress,                              
                       tteq.officeaddress,                              
                       tteq.SourceName,                              
                       tteq.MediumName,                              
                       tteq.CampaignName,                              
                       tteq.initialremarks,                              
                       @CriteriaID    AS SearchID,                              
                       tteq.WhatsAppNoColName,      
                       @ParentID    AS ParentID--,                              
                 --@CampaignID  AS CampaignID                              
                FROM   @tblLeadData AS tteq                              
                                                   
            ) A        
    
    
    
    
    
  End -- end of all    
        
   drop table if exists #tblEnquiryData    
