-- Exec [usp_conv_ExecuteUserSearch] 34594,230572      
CREATE   PROCEDURE [dbo].[usp_conv_ExecuteCustomUserSearch_agent_batchsize_start_entityid]  --34594,231643  
	@ParentID BIGINT,                              
	@CriteriaID BIGINT,  
	@batchsize int=0,
	@Start_entityid bigint
	
AS                              
BEGIN         

	--declare 
	--	@ParentID BIGINT = 27471,                      
	--	@CriteriaID BIGINT = 238178,                              
	--	@CampaignID BIGINT = NULL      
	declare @CampaignID BIGINT = NULL                              	   
	set nocount on	        
                          
	drop table if exists #tblEnquiryData    
	drop table if exists #tblLeadData    
	drop table if exists #tblLeadConversionData   
	drop table if exists  #tempConditions                
	drop table if exists  #tempConditionsCustom                   
  
  
     declare @isevent int = isnull((select iseventbased from UserCampaignMaster(nolock) where ID=@campaignid),0)                                
     declare @cmedium nvarchar(20)= (select medium from UserCampaignMaster(nolock) where ID=@campaignid)                                
     declare @LastExecutedTime datetime      
                                  
 -- if @isevent=1 and @cmedium is not  null                                
 -- begin                                
 -- select @LastExecutedTime = case when @cmedium='SMS'                   
 -- then isnull((select CampaignExecutedDatetime from UserCampaignExecution where issms=1 and isevent=1),getdate())                   
 -- else isnull((select CampaignExecutedDatetime from UserCampaignExecution where issms=0 and isevent=1),getdate()) end                                
 -- end          
             
 --if(@LastExecutedTime is null)      
 --  Begin      
 --     set @LastExecutedTime = getdate();      
 --  End      
       
               
   --Declare @CriteriaID bigint = 4                   
  -- declare @ParentID bigint = 0                  
   Declare @IsAdmin bit = 0                  
   Declare @ApplyTo nvarchar(50) = 'applyall'                   
   Declare @AndorOR nvarchar(10) = 'and'                  
   Declare @SearchType nvarchar(200) = 'Enquiry'                  
                  
   --select top 1 @ParentID = isnull(ParentID,USER_ID),@IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID                  
   select @ApplyTo = isnull(ApplyTo,'') , @SearchType = CriteriaType from tbl_SearchCriteria(nolock) where ID = @CriteriaID                   
                     
   if(@ApplyTo = 'applyall')                  
     Begin                  
      set @AndorOR = 'and';                         
  End                  
   else                   
     Begin                  
      set @AndorOR = 'or'                  
  End                         
                  
  declare @tempConditions table(RowNum int,FieldName nvarchar(200),[FieldType] nvarchar(200),[Operator] nvarchar(200),Value nvarchar(max))  
  
  --SELECT ROW_NUMBER() over(order by id asc) as RowNum,                  
  --    [FieldName]                  
  --    ,[FieldType]                  
  --    ,[Operator]                  
  --    ,[Value] into #tempConditions                        
  --FROM [tbl_SearchCriteriaConditions] where CriteriaID = @CriteriaID  and [FieldType] <> 'Custom'                   
  insert into @tempConditions(RowNum,                  
      [FieldName]                  
      ,[FieldType]                  
      ,[Operator]                  
      ,[Value] )
  SELECT ROW_NUMBER() over(order by id asc) as RowNum,                  
      REPLACE([FieldName], 'LeadID', 'ID')                
      ,[FieldType]                  
      ,[Operator]                  
      ,[Value]                        
  FROM [tbl_SearchCriteriaConditions] where CriteriaID = @CriteriaID  and [FieldType] <> 'Custom'                   
 
    
                    
                    
  Declare @InvertedComma nvarchar(10) = '''';                  
  --select @InvertedComma+'a'                  
  declare @Count int = 0                  
  declare @RowIndex int = 0                  
  Declare @FieldName nvarchar(200) = ''                  
  Declare @FieldOperator nvarchar(200) = ''                  
  Declare @Value nvarchar(max) = ''                  
  Declare @FieldType nvarchar(200) = ''                  
  Declare @DataType nvarchar(200)= ''                        
  --select @Count = count(1) from #tempConditions 
  select @Count = count(1) from @tempConditions  
                    
  Declare @FilterQuery nvarchar(max) = ' ('                  
                      
   if(@Count = 0)                  
     Begin                  
    set @FilterQuery = @FilterQuery + '1=1'                    
  end                  
                  
   while(@Count > 0)                  
     Begin                  
   set @RowIndex = @RowIndex + 1                   
   select @FieldName = FieldName,@FieldOperator = Operator,@Value = Value ,@FieldType = FieldType from  @tempConditions where RowNum = @RowIndex                  
                  
      select @DataType = dbo.ufn_FetchDataType(@FieldName,@FieldType,@ParentID);                    
  -- select @DataType                  
      
	  
	  if(@FieldName = 'IsOpen' and @FieldType = 'Enquiry')              
       Begin              
        set @FieldName = 'IsOpen'  
		if(@Value = 'True')
		  Begin
		     set @Value = '''open'''
		  End 
		 else
		   Begin
		     set @Value = '''lead''' 
		   end            
      End    
	  
	  if(@FieldName = 'LeadNo' and @FieldType = 'Enquiry')              
     Begin              
        set @FieldName = ' cast( isnull(nullif(Leads,''''),''0'') as bigint ) '   
     End    
	  
	         
  if(@FieldName = 'LastFollowupCreatedBy')      
     Begin      
     set @FieldName =  'LastFollowupCreatedByName'      
  end      
               
     if(@FieldName = 'CreatedOn' and @FieldType = 'Lead')                  
     Begin                  
        set @FieldName = 'CreatedOn1'                  
     End                   
                  
     if(@FieldName = 'CreatedBy')       
     Begin                  
        set @FieldName = 'User_Login'                  
     End           
            
   if(@FieldName = 'AssignedTo' and @FieldType = 'Lead')                  
     Begin                  
        set @FieldName = 'assigneduser'                  
     End              
          
  if(@FieldName = 'GoogleLocation')                  
     Begin                  
        set @FieldName = 'whereAddress'                  
     End          
          
          
if(@FieldOperator = '%[A]%')                  
     Begin                  
        set @FieldOperator = ' like '                  
     set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
     set @Value = @InvertedComma + REPLACE('%[A]%','[A]',@Value) + @InvertedComma;                    
    End                         
    else if(@FieldOperator = '[A]%')                  
     Begin                  
        set @FieldOperator = ' like '                  
     set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
     set @Value = @InvertedComma + REPLACE('[A]%','[A]',@Value) + @InvertedComma;                    
     End                       
        else if(@FieldOperator = '%[A]')                  
     Begin                  
        set @FieldOperator = ' like '                  
     set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
     set @Value = @InvertedComma + REPLACE('%[A]','[A]',@Value) + @InvertedComma;                    
     End                      
        else if(@FieldOperator = '[A]')                  
     Begin                  
       -- set @FieldOperator = ' like '    
		set @FieldOperator = ' = '	
		              
     set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
     set @Value = @InvertedComma + REPLACE('[A]','[A]',@Value) + @InvertedComma;                    
     End                     
        else if(@FieldOperator = 'not %[A]%')                  
     Begin                  
        set @FieldOperator = ' not like '                  
     set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
     set @Value = @InvertedComma + REPLACE('%[A]%','[A]',@Value) + @InvertedComma;                    
     End                  
     else if(@FieldOperator = 'not [A]%')                  
     Begin                  
        set @FieldOperator = ' not like '                  
     set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
     set @Value = @InvertedComma + REPLACE('[A]%','[A]',@Value) + @InvertedComma ;                    
     End                  
  else if(@FieldOperator = 'not %[A]')                  
     Begin                  
        set @FieldOperator = ' not like '                  
     set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
     set @Value = @InvertedComma + REPLACE('%[A]','[A]',@Value) + @InvertedComma;                    
     End                     
  else if(@FieldOperator = 'not [A]')                  
     Begin                  
        set @FieldOperator = ' not like '                  
     set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
     set @Value = @InvertedComma + REPLACE('[A]','[A]',@Value) + @InvertedComma ;                    
     End          
  else if(@FieldOperator = 'in [A]' and @FieldName <> 'pipeline')                  
     Begin                  
        set @FieldOperator = ' in '                  
     --set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);                  
     set @Value = REPLACE('in [A]','in [A]',@Value) ;                    
     End            
    else if(@FieldOperator = 'in [A]' and @FieldName = 'pipeline')              
     Begin              
         set @FieldOperator = ''
		 set @FieldName = ''              
         --set @Value = SUBSTRING(@Value,2,LEN(@Value)-2);              
         -- set @Value = REPLACE('in [A]','in [A]',@Value) ;
		 select @Value = dbo.fn_getPipelineExpForSQL(@Value,@ParentID)  
		 set @Value = '( ID in ( select LeadID from LeadPipelineMapping_Latest(nolock) where ( '+ @Value +' ) )) '
		 set @Value = REPLACE(@Value,'PipelineStageID','PipelineStage');
		                 
     End                   
                  
   if(@DataType = 'datetime' and @FieldOperator = 'between')                  
        Begin                  
                        
             --set @FieldName = ' DATEDIFF(DAY,'+@FieldName+',getdate()) '                
    set @FieldName = ' DATEDIFF(DAY,getdate(),'+@FieldName+') '                    
                  
     end                  
                      
    if(@RowIndex = 1)                  
  Begin              
      if(@FieldName = 'MobileNo')              
     Begin              
     set @FilterQuery = @FilterQuery + ' ( ' + '('+'MobileNo' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or '+ '('+'MobileNo1' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or ' + '('+'MobileNo2' +' '+ @FieldOperator+' '+ @Value + ')' +' ) ';              
     End            
 else if(@FieldName = 'EmailID')              
     Begin              
     set @FilterQuery = @FilterQuery + ' ( ' + '('+'EmailID' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or '+ '('+'EmailID1' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or ' + '('+'EmailID2' +' '+ @FieldOperator+' '+ @Value + ')' +' ) ';              
     End              
    else              
     Begin                          
          set @FilterQuery = @FilterQuery + ' ( ' + @FieldName +' '+ @FieldOperator+' '+ @Value + ' ) ';                  
      end                
  end                  
  else                   
   Begin               
        if(@FieldName = 'MobileNo')              
     Begin              
     set @FilterQuery = @FilterQuery + @AndorOR + ' ( ' + '('+'MobileNo' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or '+ '('+'MobileNo1' +' '+ @FieldOperator+' '+ @Value + ')'+ ' or ' + '('+'MobileNo2' +' '+ @FieldOperator+' '+ @Value + ')' +' ) ';       
 
    
      
        
     End            
 else if(@FieldName = 'EmailID')              
