OR (MobileNo1 IS NOT NULL AND LTRIM(RTRIM(MobileNo1)) <> '''' AND MobileNo1 <> ''0'')  
OR (MobileNo2 IS NOT NULL AND LTRIM(RTRIM(MobileNo2)) <> '''' AND MobileNo2 <> ''0'')) and '  
when @channel='email' then '((emailid IS NOT NULL AND LTRIM(RTRIM(emailid)) <> '''')  
OR (emailid1 IS NOT NULL AND LTRIM(RTRIM(emailid1)) <> '''')  
OR (emailid2 IS NOT NULL AND LTRIM(RTRIM(emailid2)) <> '''')) and '   
else '(1=1) and ' end +@filterquery  
  
   end  
  
      declare @tblEnquiryData table(ID bigint, PersonName varchar(200),CompanyName varchar(200),MobileNo VARCHAR(100), MobileNo1 VARCHAR(100), MobileNo2 VARCHAR(100),Countrycode VARCHAR(50),Countrycode1 VARCHAR(50),Countrycode2 VARCHAR(50), EmailID VARCHAR(100), EmailID1 VARCHAR(100), EmailID2 VARCHAR(100), City VARCHAR(100), [State] VARCHAR(100), Country VARCHAR(100), Pincode VARCHAR(50), Residentialaddress VARCHAR(500), Officeaddress VARCHAR(500), SourceName VARCHAR(200), MediumName VARCHAR(200), CampaignName VARCHAR(200), Initialremarks VARCHAR(1000),CreatedDate VARCHAR(50),WhatsAppNoColName   varchar(10))            
    print concat('Enquiry search: @FilterQueryCustom: ', @FilterQueryCustom,', Parentid: ',@Parentid,', @FilterQuery: ',@FilterQuery, ', @batchsize: ', @batchsize, ', start_entityid: ',@start_entityid )  
