        exec Usp_ViewUserEnquriyDetails_DynamicSearchForConv_Search_startentityid @FilterQueryCustom,@Parentid,@Parentid,@FilterQuery,' enquiryid ',1,@batchsize,'',@start_entityid   
  
  
         
           
    if(@SearchType = 'Enquiry')      
