  end          
           
   if(@SearchType = 'Lead' or  @SearchType = 'All' )                    
    Begin      
      print concat('entered: ','@SearchType = Lead or @SearchType = All')         
  
    declare @LeadCount int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)      
     select @batchsize=case when @batchsize=0 then @LeadCount else @batchsize end    
--       create table #tblLeadData(ID bigint,LeadNo bigint ,PersonName VARCHAR(200), CompanyName VARCHAR(200),MobileNo VARCHAR(100) , MobileNo1 VARCHAR(100), MobileNo2 VARCHAR(100),Countrycode VARCHAR(50),Countrycode1 VARCHAR(50),Countrycode2 VARCHAR(50),EmailID VARCHAR(100), EmailID1 VARCHAR(100), EmailID2 VARCHAR(100), City VARCHAR(100), [State] VARCHAR(100), Country VARCHAR(100), Pincode VARCHAR(50), Residentialaddress VARCHAR(500), Officeaddress VARCHAR(500), SourceName VARCHAR(200), MediumName VARCHAR(  
    
--200), CampaignName VARCHAR(200), Initialremarks VARCHAR(1000), datecreated VARCHAR(50) ,AssignedTo VARCHAR(200),followupstatus VARCHAR(200),nextfollowupdate VARCHAR(200),WhatsAppNoColName varchar(10))            
          
--      insert into #tblLeadData        
