   declare @tblLeadData table (ID bigint,LeadNo bigint ,PersonName VARCHAR(200), CompanyName VARCHAR(200),MobileNo VARCHAR(100) , MobileNo1 VARCHAR(100), MobileNo2 VARCHAR(100),Countrycode VARCHAR(50),Countrycode1 VARCHAR(50),Countrycode2 VARCHAR(50),EmailID VARCHAR(100), EmailID1 VARCHAR(100), EmailID2 VARCHAR(100), City VARCHAR(100), [State] VARCHAR(100), Country VARCHAR(100), Pincode VARCHAR(50), Residentialaddress VARCHAR(500), Officeaddress VARCHAR(500), SourceName VARCHAR(200), MediumName VARCHAR(200), CampaignName VARCHAR(200), Initialremarks VARCHAR(1000), datecreated VARCHAR(50) ,AssignedTo VARCHAR(200),followupstatus VARCHAR(200),nextfollowupdate VARCHAR(200),WhatsAppNoColName varchar(10),followupdate varchar(200),rownumber1 int,currentscore int)            
        
   if @conditioncount>0  
   begin  
   select @FilterQuery = case when @channel='whatsapp' then '((MobileNo IS NOT NULL AND LTRIM(RTRIM(MobileNo)) <> '''' AND MobileNo <> ''0'')  
OR (MobileNo1 IS NOT NULL AND LTRIM(RTRIM(MobileNo1)) <> '''' AND MobileNo1 <> ''0'')  
OR (MobileNo2 IS NOT NULL AND LTRIM(RTRIM(MobileNo2)) <> '''' AND MobileNo2 <> ''0'')) and '  
