OR (emailid1 IS NOT NULL AND LTRIM(RTRIM(emailid1)) <> '''')  
OR (emailid2 IS NOT NULL AND LTRIM(RTRIM(emailid2)) <> '''')) and '   
else '(1=1) and ' end +@filterquery  
  
   end  
  
  
    print concat('Lead search: @FilterQueryCustom: ', @FilterQueryCustom,', Parentid: ',@Parentid,', @FilterQuery: ',@FilterQuery, ', @batchsize: ', @batchsize, ', start_entityid: ',@start_entityid )  
