      exec Usp_ViewUserLeadDetails2_DynamicSearchForConv_Search_startentityid @FilterQueryCustom,@ParentID,@Parentid,@FilterQuery,1,@batchsize,' id ',0,@start_entityid         
  
  
  
    if(@SearchType = 'Lead')      
