         end      
                      
    End        
        
   if(@SearchType = 'Conversion'  or @SearchType = 'All' )                    
    Begin      
      print concat('entered: ','@SearchType = Conversion or @SearchType = All')         
  
      declare @LeadCount_conv int =  (select count(1) from Userleads(nolock) where ParentID = @ParentID)      
            select @batchsize=case when @batchsize=0 then @LeadCount_conv else @batchsize end    
  
       --create table #tblLeadConversionData(ID bigint,LeadNo bigint ,PersonName VARCHAR(200), CompanyName VARCHAR(200),MobileNo VARCHAR(100) , MobileNo1 VARCHAR(100), MobileNo2 VARCHAR(100),Countrycode VARCHAR(50),Countrycode1 VARCHAR(50),Countrycode2 VARCHAR(50),EmailID VARCHAR(100), EmailID1 VARCHAR(100), EmailID2 VARCHAR(100), City VARCHAR(100), [State] VARCHAR(100), Country VARCHAR(100), Pincode VARCHAR(50), Residentialaddress VARCHAR(500), Officeaddress VARCHAR(500), SourceName VARCHAR(200), MediumName VARCHAR(200), CampaignName VARCHAR(200), Initialremarks VARCHAR(1000), datecreated VARCHAR(50) ,AssignedTo VARCHAR(200),followupstatus VARCHAR(200),nextfollowupdate VARCHAR(200),WhatsAppNoColName varchar(10))            
          
      declare  @tblLeadConversionData table (ID bigint,LeadNo bigint ,PersonName VARCHAR(200), CompanyName VARCHAR(200),MobileNo VARCHAR(100) , MobileNo1 VARCHAR(100), MobileNo2 VARCHAR(100),Countrycode VARCHAR(50),Countrycode1 VARCHAR(50),Countrycode2 VARCHAR(50),EmailID VARCHAR(100), EmailID1 VARCHAR(100), EmailID2 VARCHAR(100), City VARCHAR(100), [State] VARCHAR(100), Country VARCHAR(100), Pincode VARCHAR(50), Residentialaddress VARCHAR(500), Officeaddress VARCHAR(500), SourceName VARCHAR(200), MediumName VARCHAR(200), CampaignName VARCHAR(200), Initialremarks VARCHAR(1000), datecreated VARCHAR(50) ,AssignedTo VARCHAR(200),followupstatus VARCHAR(200),nextfollowupdate VARCHAR(200),WhatsAppNoColName varchar(10),followupdate varchar(200),rownumber1 int,currentscore int)            
  
  
  
      
     set   @FilterQuery = '( ( FollowupStatus = ''Converted'' ) and  ' + '('+@FilterQuery +')'+ ')'        
      
 if @conditioncount>0  
   begin  
   select @FilterQuery = case when @channel='whatsapp' then '((MobileNo IS NOT NULL AND LTRIM(RTRIM(MobileNo)) <> '''' AND MobileNo <> ''0'')  
OR (MobileNo1 IS NOT NULL AND LTRIM(RTRIM(MobileNo1)) <> '''' AND MobileNo1 <> ''0'')  
OR (MobileNo2 IS NOT NULL AND LTRIM(RTRIM(MobileNo2)) <> '''' AND MobileNo2 <> ''0'')) and '  
when @channel='email' then '((emailid IS NOT NULL AND LTRIM(RTRIM(emailid)) <> '''')  
OR (emailid1 IS NOT NULL AND LTRIM(RTRIM(emailid1)) <> '''')  
OR (emailid2 IS NOT NULL AND LTRIM(RTRIM(emailid2)) <> '''')) and '   
else '(1=1) and ' end +@filterquery  
  
   end  
  
   print concat('Conversion search: @FilterQueryCustom: ', @FilterQueryCustom,', Parentid: ',@Parentid,', @FilterQuery: ',@FilterQuery, ', @batchsize: ', @batchsize, ', start_entityid: ',@start_entityid )  
     insert into @tblLeadConversionData(ID ,LeadNo  ,PersonName , CompanyName ,MobileNo  , MobileNo1 , MobileNo2 ,Countrycode ,Countrycode1 ,Countrycode2 ,EmailID , EmailID1 , EmailID2 , City , [State] , Country , Pincode , Residentialaddress , Officeaddress , SourceName , MediumName , CampaignName , Initialremarks , datecreated  ,AssignedTo ,followupstatus ,nextfollowupdate ,WhatsAppNoColName,followupdate,rownumber1,currentscore)           
      exec Usp_ViewUserLeadDetails2_DynamicSearchForConv_Search_startentityid @FilterQueryCustom,@ParentID,@Parentid,@FilterQuery,1,@batchsize,' id ',0         
      
    if(@SearchType = 'Conversion')      
   Begin       
    print concat('entered: ','@SearchType = Conversion')         
  
   insert into tbl_SearchResult(SPID,EntityName,EntityID,SearchId,parentid)  
      SELECT @spid,'Lead', tteq.ID ,@CriteriaID,@ParentID                                
     FROM   @tblLeadConversionData         AS tteq                                
                                  
   --   where   
   --1=case when @channel='whatsapp' and  ISNULL(tteq.mobileno, '') != '' and tteq.mobileno != '0'  then 1  
   --when @channel='mail' and  ISNULL(tteq.EmailID, '') != '' and tteq.EmailID != '0'  then 1  
   --else 0 end  
  print concat('conversions inserted: ',@@rowcount)      
  
    end      
    End                   
             
          
    if(@SearchType = 'All')      
  Begin   
   print concat('entered: ','@SearchType = All')         
  
 declare @SearchTypeAsLead nvarchar(200) = 'lead', @SearchTypeAsEnquiry nvarchar(200) = 'enquiry'  
 select @batchsize=case when @batchsize=0 then 5000 else @batchsize end  
 insert into tbl_SearchResult(spid,EntityName,EntityID,SearchId,ParentID)  
     SELECT top (@batchsize) @spid,A.SearchType,A.ID,@CriteriaID,@ParentID  
     FROM   (                                
                SELECT tteq.ID , 'lead' as SearchType                   
                FROM   @tblLeadConversionData AS tteq                                                    
                                                
      UNION                                     
                SELECT tteq.ID , 'enquiry' as SearchType                           
                FROM   @tblEnquiryData AS tteq                                
                                                      
                UNION                                
                SELECT tteq.ID , 'lead' as SearchType                        
                FROM   @tblLeadData AS tteq                                
                                                     
            ) A          
      
    print concat('All inserted: ',@@rowcount)      
  
      
      
      
  End -- end of all      
          
   drop table if exists #tblEnquiryData      
   drop table if exists #tblLeadData      
   drop table if exists #tblLeadConversionData                     
    
    set nocount off        
        
END   



