      ISNULL(tteq.countrycode, '')  AS countrycode,                              
      ISNULL(tteq.countrycode1, '') AS countrycode1,                              
      ISNULL(tteq.countrycode2, '') AS countrycode2,                              
                      tteq.country,                              
                       tteq.[state],                              
                       tteq.city,                              
                       tteq.pincode,                              
                       tteq.residentialaddress,                              
                       tteq.officeaddress,                              
                       tteq.SourceName,                              
                       tteq.MediumName,                              
        tteq.CampaignName,                              
        tteq.initialremarks,                              
        @CriteriaID    AS SearchID,                              
        tteq.WhatsAppNoColName,      
        @ParentID   AS ParentID                              
            --@CampaignID  AS CampaignID                              
                FROM   @tblLeadConversionData AS tteq                                                  
                               
                                              
                                              
      UNION                              
                       
                                              
                                              
                SELECT @SearchType as SearchType,tteq.personname,                              
                       tteq.companyname,                              
                       ISNULL(tteq.mobileno, '') AS MobileNo,                              
                       ISNULL(tteq.mobileno1, '') AS MobileNo1,                              
                       ISNULL(tteq.mobileno2, '') AS MobileNo2,                              
                       ISNULL(tteq.emailid, '') AS EMAILID,                              
                       ISNULL(tteq.emailid1, '') AS EmailID1,                              
                       ISNULL(tteq.emailid2, '') AS EmailID2,                              
      ISNULL(tteq.countrycode, '')  AS countrycode,                              
      ISNULL(tteq.countrycode1, '') AS countrycode1,                              
      ISNULL(tteq.countrycode2, '') AS countrycode2,                              
                       tteq.country,           
                       tteq.[state],                              
                       tteq.city,                              
                       tteq.pincode,                              
                       tteq.residentialaddress,                              
                       tteq.officeaddress,                              
                       tteq.SourceName,                              
                       tteq.MediumName,                              
                       tteq.CampaignName,                              
                       tteq.initialremarks,                              
                       @CriteriaID    AS SearchID,                              
                       tteq.WhatsAppNoColName,      
                       @ParentID    AS ParentID--,                              
                       --@CampaignID  AS CampaignID                              
                FROM   @tblEnquiryData AS tteq                              
                                                    
                                              
                  
                                
                UNION                              
                                              
                                              
                                              
                SELECT @SearchType as SearchType,tteq.personname,                              
                       tteq.companyname,                 
                       ISNULL(tteq.mobileno, '') AS MobileNo,                              
                       ISNULL(tteq.mobileno1, '') AS MobileNo1,                              
                       ISNULL(tteq.mobileno2, '') AS MobileNo2,                              
                       ISNULL(tteq.emailid, '') AS EMAILID,                              
                       ISNULL(tteq.emailid1, '') AS EmailID1,                              
                       ISNULL(tteq.emailid2, '') AS EmailID2,                              
      ISNULL(tteq.countrycode, '')  AS countrycode,                              
      ISNULL(tteq.countrycode1, '') AS countrycode1,                              
      ISNULL(tteq.countrycode2, '') AS countrycode2,                              
      tteq.country,                              
                       tteq.[state],                              
                       tteq.city,                              
                       tteq.pincode,                              
                       tteq.residentialaddress,                              
                       tteq.officeaddress,                              
                       tteq.SourceName,                              
                       tteq.MediumName,                              
                       tteq.CampaignName,                              
                       tteq.initialremarks,                              
                       @CriteriaID    AS SearchID,                              
                       tteq.WhatsAppNoColName,      
                       @ParentID    AS ParentID--,                              
                 --@CampaignID  AS CampaignID                              
                FROM   @tblLeadData AS tteq                              
                                                   
            ) A        
    
    
    
    
    
  End -- end of all    
        
   drop table if exists #tblEnquiryData    
   drop table if exists #tblLeadData    
   drop table if exists #tblLeadConversionData                   
  
    set nocount off	     
      
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_conv_GetTriggeredCampaignFieldValue_forentity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_conv_GetTriggeredCampaignFieldValue_forentity] --75406709 --74846642               
(                    
	@batchId bigint                    
)                    
as  
begin       
  
--declare @batchId bigint = 164087628

DECLARE @sql NVARCHAR(MAX)
DECLARE @sql1 NVARCHAR(MAX)
declare @entityId bigint=0,@entity nvarchar(20)='',@activityid bigint=0,@campaignid bigint=0,@contacttype nvarchar(10)='',@parentid bigint=0,@eventid int=0, @event_type varchar(50) ,@bot_id bigint,@call_logid bigint                
select @activityid=trigerringactivityid,@campaignid=campaignid from mysms.dbo.WBatchInfo where batchid=@BatchId 

-- SET @sql = 'SELECT trigerringactivityid FROM WBatchInfo (NOLOCK) WHERE batchid = ' + CAST(@BatchId AS NVARCHAR);
--SET @sql1 = 'SELECT campaignid FROM WBatchInfo (NOLOCK) WHERE batchid = ' + CAST(@BatchId AS NVARCHAR);

---- Fetch values using CLR
--EXEC usp_clr_GetRemoteLongValue @sql, @retval = @activityid OUTPUT;
--EXEC usp_clr_GetRemoteLongValue @sql1, @retval = @campaignid OUTPUT;

 select @entity=a.context,@contacttype=u.ContactType,@parentid=u.ParentID,@eventid=u.eventid from mysms.dbo.activitymaster(nolock) a     
 join mysms.dbo.UserCampaignMaster(nolock) u                
 on u.eventid=a.ID  where u.ID =  @campaignid    

 print concat('@activityid:',@activityid)
 print concat('@campaignid:',@campaignid)
 print concat('@entity:',@entity)
 print concat('@contacttype:',@contacttype)
 print concat('@parentid:',@parentid)
 print concat('@eventid:',@eventid)


 select @event_type =eventtype from activitymaster(nolock) where id=@eventid
 if @entity='lead'
 begin
 select @call_logid=refids from tbl_LeadEventHistory(nolock) where Historyid=@activityid and reftables='calllog'
 end
 else if @entity='enquiry'
 begin
 select @call_logid=refids from tbl_enquiryEventHistory(nolock) where Historyid=@activityid and reftables='calllog'
 end
 
 if @call_logid is not null
 begin
 select @bot_id=bot_id from CallLog(nolock) where id=@call_logid
 end

            
drop table if exists #epht_w ;                   
drop table if exists #entitydata_replace_w  ;                  
create table #epht_w(fieldnameexposed nvarchar(200),fieldnameactual nvarchar(200),fieldtype nvarchar(10));                   
insert into #epht_w(fieldnameexposed,fieldnameactual,fieldtype)                   
exec mysms.dbo.usp_getentityplaceholders @parentid,@entity  
/*select @sql = '
EXEC usp_getentityplaceholders ' + 
    CAST(@parentid AS NVARCHAR) + ', ' + 
    CAST(@entity AS NVARCHAR) + ';'
EXEC usp_clr_GetRemoteData @sql;*/

            
alter table #epht_w add fieldvalue nvarchar(max)     
    
    
declare @ad nvarchar(max)    
drop table if exists #activitydata_r      
create table #activitydata_r(entitydata nvarchar(max),activitydata nvarchar(max),userdata nvarchar(max))      
    
insert into #activitydata_r(entitydata,activitydata,userdata)      
exec usp_getmetadata_foractivity @activityid,@entity   

--select @sql = concat('
--EXEC usp_getmetadata_foractivity ' , 
--    @activityid , ', ''' , 
--    CAST(@entity AS NVARCHAR),'''')
--	print @sql
--insert into #activitydata_r(entitydata,activitydata,userdata)      
--EXEC usp_clr_GetRemoteData @sql;

    
select top 1 @ad=activitydata from #activitydata_r      
select @ad=replace(replace(@ad,'[',''),']','')      
      
drop table if exists #activitydata_withevent_r      
create table #activitydata_withevent_r(eventid int,keyv nvarchar(max),valuev nvarchar(max),typev nvarchar(max),displaykey nvarchar(100))      
      
insert into #activitydata_withevent_r(keyv,valuev,typev)      
select [key],[value],[type] from      
(      
select [key],isnull([value],'') value,[type] from openjson(@ad)      
) A      
      
update #activitydata_withevent_r set displaykey=exposedname,valuev=case when e.datatype='datetime' and valuev<>''  
then try_convert(nvarchar,try_cast(replace(a.valuev,'T',' ') as smalldatetime),100) else valuev end  
from #activitydata_withevent_r a     
join mysms.dbo.eventplaceholders e on a.keyv=e.alias and e.eventid=@eventid and e.isexposed=1      
  
if @event_type='AI Bot'
begin
    update #activitydata_withevent_r set displaykey=label,valuev=case when isnull(json_value(detailsjson,'$.datatype'),'string')='date' and valuev<>''        
    then try_convert(nvarchar,try_cast(replace(a.valuev,'T',' ') as smalldatetime),100) else valuev end        
    from #activitydata_withevent_r a join tbl_ai_goalslots e on a.keyv=e.name          
    and e.GoalId=@bot_id 
end

drop table if exists #apht  
  
create table #apht(fieldn nvarchar(200),fieldv nvarchar(max))    
                   
          
                    
declare @entitydata nvarchar(max)                    
if @entity='lead'                    
begin          
select @entityid=leadid from mysms.dbo.tbl_leadeventhistory(nolock) where historyid=@activityid 
--SET @sql = 
--    'SELECT leadid FROM tbl_leadeventhistory (NOLOCK) WHERE historyid = ' + 
--    CAST(@activityid AS NVARCHAR);
--EXEC usp_clr_GetRemoteLongValue @sql, @retval = @entityid OUT;

set @entitydata=(select * from (select u.*,isnull(str(d.mobile),'') as AssignedToPhone,isnull(d.email,'') as AssignedToEmail  
,mysms.dbo.fn_getentityfullname('user',d.user_id) as AssignedToName  
from MySMS.dbo.Userleads u(nolock) left join MySMS.dbo.user_detail d(nolock) on d.user_id=u.assignedto where u.id=@entityid) a for json auto,INCLUDE_NULL_VALUES)                    
update e set fieldvalue=isnull(cast(c.fieldvalue as nvarchar(max)),'') from #epht_w e                     
join                     
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from mysms.dbo.customfields(nolock) f                   
left join mysms.dbo.customfieldleadvalue c on c.fieldID=f.field_ID and c.LeadID=@entityid where f.parentid=@parentid)                    
c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'                    
end          
else                    
begin          
select @entityid=EnquiryID from mysms.dbo.tbl_enquiryeventhistory(nolock) where historyid=@activityid 
--set @sql  =  'SELECT EnquiryID FROM tbl_enquiryeventhistory (NOLOCK) WHERE historyid = ' +  CAST(@activityid AS NVARCHAR);

--EXEC usp_clr_GetRemoteLongValue @sql, @retval = @entityid OUT;

-- Optional: SELECT @entityid;

set @entitydata=(select * from (select u.*,isnull(str(d.mobile),'') as CreatedByPhone,isnull(d.email,'') as CreatedByEmail  
,mysms.dbo.fn_getentityfullname('user',d.user_id) as CreatedByName  
from MySMS.dbo.UserEnquiry u(nolock)  left join MySMS.dbo.user_detail d(nolock) on d.user_id=u.CreatedBy  where enquiryid=@entityid) a for json auto,INCLUDE_NULL_VALUES)                    
update e set fieldvalue=isnull(cast(c.fieldvalue as nvarchar(max)),'') from #epht_w e                     
join                     
(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from mysms.dbo.customfields(nolock) f                   
left join mysms.dbo.customfieldEnquiryvalue c on c.fieldID=f.field_ID and c.EnquiryID=@entityid where f.parentid=@parentid)                    
c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'         
end          
                    
                    
create table #entitydata_replace_w(k nvarchar(200),v nvarchar(max),t nvarchar(20))                    
insert into #entitydata_replace_w                    
select * from openjson(replace(replace(@entitydata,'[',''),']',''))                   
                  
update  #entitydata_replace_w set v='' where v is null                  
                    
update ed set v=case                     
when k in ('createdby','assignedto') then mysms.dbo.fn_getuserlogins(v)                     
when k='sourcename' then s.name                    
when k='mediumname' then m.name                    
when k='campaignname' then c.name                    
else v end                    
from #entitydata_replace_w ed                     
left join mysms.dbo.UserSourceSettings s on ed.v=cast(s.SourceID as nvarchar)                    
left join mysms.dbo.UsermediumSettings m on ed.v=cast(m.MediumID as nvarchar)                    
left join mysms.dbo.UserCampaignSettings c on ed.v=cast(c.CampaignID as nvarchar)                    
    
update e set fieldvalue=cast(isnull(c.v,'') as nvarchar(max)) from #epht_w e                     
left join #entitydata_replace_w c on @entity+'.'+c.k=e.fieldnameactual       
          
drop table if exists #tbr         
select   
  
 --TF.RowId,TF.fieldname,  
bfv.FieldValue FieldValue, bfv.FileName, bfv.DefaultValue, TF.*  into #tbr           
  from [10.0.0.135].MysmsConversations.dbo.tbl_wsap_BroadcastFieldsValue as BFV with (nolock)
  inner join [10.0.0.135].MysmsConversations.dbo.tbl_wsap_TemplateFields as TF with (nolock)            
  ON   BFV.TemplateFieldId=TF.RowId                
  --left join #epht_w e on '#'+e.fieldnameexposed+'#'=BFV.FieldValue             
  where Cmpgn_ID = @CampaignId         
        
declare @tbl as recursivereplace      
    
insert into @tbl(displaykey,[value])          
select fieldnameexposed,fieldvalue from    
(select fieldnameexposed,fieldvalue from #epht_w      
union all    
select displaykey,valuev from #activitydata_withevent_r) a    
      
  declare @ct int= (select count(1) from #tbr where fieldvalue like '%#%#%'),@rid int=0,@st nvarchar(500)      
    
    
  while @ct>0      
  begin      
  select @rid=min(rowid) from #tbr where rowid>@rid and fieldvalue like '%#%#%'    
    
  select @st= replace(fieldvalue, '#bot_slot.', '#')  from #tbr where rowid=@rid      
  --select @st      
  --if exists(select 1 from #epht_w where @st like '#'+fieldnameexposed+'#')      
  --begin      
  update @tbl set displaykey=replace(displaykey, @entity + '.', '')  
  select @st=dbo.fn_recursivereplace(@tbl,@st)      
  --select @rid,@st      
  --end      
  
  print concat('@st => ', @st)  
  
  update #tbr set fieldvalue=@st where rowid=@rid      
  set @ct=@ct-1      
  end      
        
  select  (case when FieldType = 'predefined'  and ( FieldValue like 'lead.%' or FieldValue like 'enquiry.%')
		then concat('#', trim(FieldValue), '#')
		else FieldValue end
	)
	
	FieldValue, FileName, DefaultValue, RowId, TemplateId, 
	
  FieldName, FieldType, 
	SectionType, SequenceNo, IsActive, CreatedBy, CreatedOn
  from #tbr order by SequenceNo asc     
        
  drop table if exists #tbr      
                   
end   



GO

/* ============================================================
   Procedure: [dbo].[usp_conv_GettriggeredcampaignRecepients]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_conv_GettriggeredcampaignRecepients]          
(          
 @BatchId bigint          
)          
as
begin   
  
 --declare @BatchId bigint = 154259570  
  
 DROP TABLE IF EXISTS #tblRecepientList          
 CREATE TABLE #tblRecepientList          
 (                                  
  id                     BIGINT,                       
  SearchType             varchar(10),                                 
  personname             VARCHAR(200),                                  
  companyname             VARCHAR(200),                                  
  mobileno               VARCHAR(100),                                  
  mobileno1               VARCHAR(100),                                  
  mobileno2               VARCHAR(100),                                  
  emailid     VARCHAR(100),                                  
  emailid1               VARCHAR(100),                                  
  emailid2               VARCHAR(100),                                  
  countrycode            VARCHAR(50),                                  
  countrycode1            VARCHAR(50),                                  
  countrycode2            VARCHAR(50),                                  
  country                VARCHAR(100),                                
  STATE                  VARCHAR(100),                                  
  city                   VARCHAR(100),                                  
  pincode                VARCHAR(50),                                  
  residentialaddress     VARCHAR(500),                                  
  officeaddress          VARCHAR(500),                                  
  sourcename             VARCHAR(200) COLLATE sql_latin1_general_cp1_ci_as,                                  
  mediumname             VARCHAR(200) COLLATE sql_latin1_general_cp1_ci_as,                                  
  campaignname           VARCHAR(200) COLLATE sql_latin1_general_cp1_ci_as,                                  
  initialremarks         VARCHAR(1000) collate SQL_Latin1_General_CP1_CI_AS,                                  
  WhatsAppNoColName   varchar(10),          
  ParentID     bigint          
 )                               
        
 declare @entityId bigint=0,@entityname nvarchar(20),@activityid int,@campaignid bigint,@contacttype nvarchar(10),@parentid bigint  
   
 select @activityid=trigerringactivityid,@campaignid=campaignid from mysms.dbo.WBatchInfo where batchid=@BatchId        
 select @entityname=a.context,@contacttype=u.ContactType,@parentid=u.ParentID   
  from mysms.dbo.activitymaster(nolock) a join mysms.dbo.UserCampaignMaster(nolock) u        
   on u.eventid=a.ID  where u.ID =  @campaignid      

   declare @channelProfileId nvarchar(max) = null
	

  if @entityname='lead'        
  begin        
     
   select @entityId=leadid from mysms.dbo.tbl_LeadEventHistory(nolock) where HistoryID = @activityid     
   
   set  @channelProfileId = dbo.udf_GetConvChannelProfileId(@entityname, @entityId, @parentid)

   insert into #tblRecepientList(id, SearchType, personname, companyname, mobileno, mobileno1, mobileno2, emailid, emailid1, emailid2, countrycode, countrycode1, countrycode2, country, STATE, city, pincode, residentialaddress, officeaddress, sourcename, mediumname, campaignname, initialremarks, WhatsAppNoColName,ParentID)          
   select id,'lead',personname,companyname,
		(case 
			when isnull(@channelProfileId, '') = '' then mobileno
			when @channelProfileId like '%' + mobileno then right(@channelProfileId, len(mobileno))
			else mobileno 
		end) as [mobileno],
		(case 
			when isnull(@channelProfileId, '') = '' then mobileno1
			when @channelProfileId like '%' + mobileno1 then right(@channelProfileId, len(mobileno1))
			else mobileno1 
		end) as [mobileno1],
		(case 
			when isnull(@channelProfileId, '') = '' then mobileno2
			when @channelProfileId like '%' + mobileno2 then right(@channelProfileId, len(mobileno2))
			else mobileno2 
		end) as [mobileno2],	
	emailid,emailid1,emailid2,ltrim(rtrim(countrycode)),          
   ltrim(rtrim(countrycode1)),ltrim(rtrim(countrycode2)),country,STATE,city,pincode,residentialaddress,officeaddress,sourcename,mediumname,campaignname,initialremarks,          
   WhatsAppNoColName,ParentID from mysms.dbo.UserLeads(nolock)
   WHERE id=@entityId        
 end  
   
 if @entityname='enquiry'        
 begin        
  select @entityid=enquiryid from mysms.dbo.tbl_enquiryEventHistory(nolock) where HistoryID=@activityid  
  
  set  @channelProfileId = dbo.udf_GetConvChannelProfileId(@entityname, @entityId, @parentid)
    
  insert into #tblRecepientList(id, SearchType, personname, companyname, mobileno, mobileno1, mobileno2, emailid, emailid1, emailid2, countrycode, countrycode1, countrycode2, country, STATE, city, pincode, residentialaddress, officeaddress, sourcename, mediumname, campaignname, initialremarks, WhatsAppNoColName,ParentID)          
  select enquiryid,'enquiry',personname,companyname,
		(case 
			when isnull(@channelProfileId, '') = '' then mobileno
			when @channelProfileId like '%' + mobileno then right(@channelProfileId, len(mobileno))
			else mobileno 
		end) as [mobileno],
		(case 
			when isnull(@channelProfileId, '') = '' then mobileno1
			when @channelProfileId like '%' + mobileno1 then right(@channelProfileId, len(mobileno1))
			else mobileno1 
		end) as [mobileno1],
		(case 
			when isnull(@channelProfileId, '') = '' then mobileno2
			when @channelProfileId like '%' + mobileno2 then right(@channelProfileId, len(mobileno2))
			else mobileno2 
		end) as [mobileno2],	
	emailid,emailid1,emailid2,ltrim(rtrim(countrycode)),          
  ltrim(rtrim(countrycode1)),ltrim(rtrim(countrycode2)),country,STATE,city,pincode,residentialaddress,officeaddress,sourcename,mediumname,campaignname,initialremarks,          
  WhatsAppNoColName,ParentID from mysms.dbo.UserEnquiry           
  WHERE enquiryid=@entityId        
 end
 
 -- Updaing Source,Medium,Campaign
update ed set 
	ed.sourcename = isnull(s.Name, ''),
	ed.campaignname = isnull(c.Name, ''),
	ed.mediumname = isnull(m.Name, '')
from #tblRecepientList ed                     
	left join mysms.dbo.UserSourceSettings s on ed.sourcename = cast(s.SourceID as nvarchar)                    
	left join mysms.dbo.UsermediumSettings m on ed.mediumname = cast(m.MediumID as nvarchar)                    
	left join mysms.dbo.UserCampaignSettings c on ed.campaignname = cast(c.CampaignID as nvarchar)                    
    
 
          
 If(@ContactType = 'A')          
 begin          
  --select distinct id, SearchType, personname, companyname, mobileno, mobileno1, mobileno2, emailid, emailid1, emailid2, countrycode,   
  -- countrycode1, countrycode2, country, STATE, city, pincode, residentialaddress, officeaddress, sourcename, mediumname, campaignname, initialremarks, WhatsAppNoColName, ParentID          
  --From #tblRecepientList    

	select distinct id, SearchType, personname, companyname, mobileno, mobileno1, mobileno2, emailid, emailid1, emailid2, countrycode,   
	   countrycode1, countrycode2, country, STATE, city, pincode, residentialaddress, officeaddress, sourcename, mediumname, campaignname, initialremarks, WhatsAppNoColName, ParentID          
	  From #tblRecepientList    
  
 end          
 else          
 begin          
  select RL.*           
  -- select *          
  from [10.0.0.135].MySMSConversations.dbo.convusers CU with (nolock) inner join #tblRecepientList RL          
   on (CU.Entity=RL.SearchType and CU.EntityId=RL.Id) or (CU.Channelprofileid=replace(RL.CountryCode,'+','')+RL.MobileNo)          
  where CU.Channelid=2 and CU.convuserparentid=@ParentId and CU.isactive=1          
 end          
end     


GO

/* ============================================================
   Procedure: [dbo].[usp_converter_GetCallRecordingForConversion]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_converter_GetCallRecordingForConversion]
AS
BEGIN
    SET NOCOUNT ON;
 
    BEGIN TRY
 
        SELECT Id, RecordUrl
        FROM CallLog WITH (NOLOCK)
        WHERE RecordUrl LIKE 'https://docs.kit19.com%'
        AND RecordUrl NOT LIKE '%.mp3' and  parentid IN (34594, 32222) order by 1 desc;
 
    END TRY
    BEGIN CATCH
 
        DECLARE @ErrMsg NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrLine INT = ERROR_LINE();
        DECLARE @ErrProc NVARCHAR(200) = ERROR_PROCEDURE();
 
        RAISERROR(
            'usp_converter_GetCallRecordingForConversion failed at line %d in %s: %s',
            16,
            1,
            @ErrLine,
            @ErrProc,
            @ErrMsg
        );
 
        RETURN;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_converter_UpdateCallRecording]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_converter_UpdateCallRecording
    @Id BIGINT,
    @NewUrl VARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;
 
    BEGIN TRY
 
        UPDATE CallLog
        SET RecordUrl = @NewUrl
        WHERE Id = @Id;
 
        IF @@ROWCOUNT = 0
        BEGIN
            RAISERROR('No record found for given Id', 16, 1);
            RETURN;
        END
 
    END TRY
    BEGIN CATCH
 
        DECLARE @ErrMsg NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrLine INT = ERROR_LINE();
        DECLARE @ErrProc NVARCHAR(200) = ERROR_PROCEDURE();
 
        RAISERROR(
            'usp_converter_UpdateCallRecording failed at line %d in %s: %s',
            16,
            1,
            @ErrLine,
            @ErrProc,
            @ErrMsg
        );
 
        RETURN;
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ConvertGoogleLeadgenToEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_ConvertGoogleLeadgenToEnquiry](
	@gwAutoId  bigint
)
AS
BEGIN

    --declare @gwAutoId bigint = 20

    drop table if exists #tgEnquiry
    drop table  if exists #tempCustomEnquiryField
    drop table  if exists #tempLead
   
   
	declare @isleadcreated int = 0, @formGuild NVARCHAR(255) = '', @RequestJSON NVARCHAR(MAX) = '', @ParentId bigint = 0, @googleFromId bigint = 0,
		@EnquiryId BIGINT = 0, @QUERY NVARCHAR(MAX) = '', @ParamDef NVARCHAR(500) = '', @AutoLeadDistribution BIT, @tempEnquiryId BIGINT = -1, 
		@LeadValueRow NVARCHAR(MAX), @fbFeildName NVARCHAR(200), @enquiryFeildName NVARCHAR(200), @enquiryFeildDataType NVARCHAR(200), 
		@SourceCode NVARCHAR(200), @MediumCode BIGINT, @CampaignCode BIGINT, @Trace varchar(max)='', @json varchar(max)=''

    BEGIN TRY  

        select @formGuild = FormGUID, @RequestJSON = RequestJSON, @ParentId = ParentId from tbl_GoogleForm_Webhook(nolock) where id = @gwAutoId
        select  @googleFromId = Id from tbl_GoogleFormIntegration(nolock) where FormGUID = @formGuild

        print CONCAT('@googleFromId => ', @googleFromId)
        print CONCAT('@RequestJSON => ', @RequestJSON)
        print CONCAT('@ParentId => ', @ParentId)
        print CONCAT('@formGuild => ', @formGuild)

        
        declare @googleLeadsJson NVARCHAR(MAX) = ''
        select @googleLeadsJson = json_query(@RequestJSON, '$.user_column_data') 
        print CONCAT('@googleLeadsJson => ', @googleLeadsJson)
		


        if(isnull(@googleLeadsJson, '') != '')
        BEGIN
            declare @SourceId bigint = 0, @MediumId bigint = 0, @CampaignId bigint = 0, @columnMappingJSON nvarchar(max) = ''

            select @SourceId = SourceId, @MediumId = MediumId, @CampaignId = CampaignId, @columnMappingJSON = ColMappings
				from tbl_GoogleFormLeadMapping(nolock) where FormIntegrationId = @googleFromId

			

			PRINT CONCAT('@columnMappingJSON => ', @columnMappingJSON)
            
			drop table if exists #tgColMapping

			select
                ROW_NUMBER() over(partition by (select null) order by (select null) ) as sno,
                *, cast(0 as bit) isProcess into #tgColMapping from openjson(@columnMappingJSON) with (
                country_code nvarchar(255) '$.country_code',
                Google_field_name nvarchar(255) '$.Google_field_name',
                Google_field_path nvarchar(255) '$.Google_field_path',
                enquir_col_name nvarchar(255) '$.enquir_col_name',
                default_value nvarchar(255) '$.default_value'
            )

            alter table #tgColMapping add google_field_value nvarchar(255)


            drop table if exists #tgwLeadValue

            select * into #tgwLeadValue from openjson(@googleLeadsJson) with (
                column_name nvarchar(255) '$.column_name',
                string_value nvarchar(255) '$.string_value',
                column_id nvarchar(255) '$.column_id'
            )

	
            update c set
				c.google_field_value = case when isnull(w.string_value, '')  = '' then c.default_value else w.string_value end  
            from #tgwLeadValue w inner join #tgColMapping c on c.Google_field_path = w.column_id

            SELECT * INTO #tgEnquiry FROM UserEnquiry(NOLOCK) WHERE EnquiryID = 0
            CREATE TABLE #tempCustomEnquiryField ( fieldID BIGINT, fieldvalue SQL_VARIANT )

            SET IDENTITY_INSERT #tgEnquiry ON
            insert into #tgEnquiry (EnquiryID, SourceName, MediumName, CampaignName, ParentID, IsOpen, CreatedDate, CreatedBy, IsduplicateEmail, IsduplicateMobile)
            values ( @tempEnquiryId, @SourceId, @MediumId, @CampaignId, @ParentId, 1, GETDATE(), @ParentId, 0, 0 )
            SET IDENTITY_INSERT #tgEnquiry OFF

            while(exists(select 1 from #tgColMapping(nolock)  where isProcess = 0))
            begin
                declare @Sno bigint  = 0, @enquiryColName nvarchar(255) = '', @enquiryColValue nvarchar(255) = ''

                select top 1 @Sno = sno, @enquiryColName = enquir_col_name, @enquiryColValue = google_field_value
					from #tgColMapping(nolock) where isProcess = 0 order by sno asc

                print concat('@enquiryColName => ', @enquiryColName)
                print concat('@enquiryColValue => ', @enquiryColValue)
                
				SELECT @enquiryFeildDataType = DATA_TYPE
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE  TABLE_NAME = 'UserEnquiry' AND COLUMN_NAME  = @enquiryColName
                IF(COL_LENGTH('dbo.UserEnquiry', @enquiryColName) IS NOT NULL)
                begin
                    if( @enquiryColName in ('MobileNo', 'MobileNo1', 'MobileNo2'))                    
                    begin

                        DECLARE @Start INT = 1, @CountryCode NVARCHAR(10) = '', @MobileNo_Checked BIGINT = 0, @PatterCountryCode NVARCHAR(10), @CountryCodeLen INT = 0;
                        select @PatterCountryCode = LTRIM(RTRIM(CountryCode)), @CountryCodeLen = LEN(LTRIM(RTRIM(CountryCode)))
                        from m_country1
                        where @enquiryColValue like (rtrim(CountryCode) + '%')

                        set @MobileNo_Checked = SUBSTRING(@enquiryColValue, @CountryCodeLen + 1, LEN(@enquiryColValue))
                        set @CountryCode = isnull(@PatterCountryCode, trim(dbo.udf_GetParentCountryCode(@ParentId)))
                        print concat('@CountryCode => ', @CountryCode)
                        print concat('@MobileNo_Checked => ', @MobileNo_Checked)

                        UPDATE #tgEnquiry SET
                            CountryCode = case when @enquiryColName = 'MobileNo' then @CountryCode else CountryCode end,
                            CountryCode1 = case when @enquiryColName = 'MobileNo1' then @CountryCode else CountryCode1 end,
                            CountryCode2 = case when @enquiryColName = 'MobileNo2' then @CountryCode else CountryCode2 end,
                            MobileNo = case when @enquiryColName = 'MobileNo' then @MobileNo_Checked else MobileNo end,
                            MobileNo1 = case when @enquiryColName = 'MobileNo1' then @MobileNo_Checked else MobileNo1 end,
                            MobileNo2 = case when @enquiryColName = 'MobileNo2' then @MobileNo_Checked else MobileNo2 end
                        WHERE EnquiryID = @tempEnquiryId

                        PRINT concat('@tempEnquiryId => ', @tempEnquiryId)
                    END
                ELSE
                BEGIN
                    PRINT 'custom datatype' 
                        SET @QUERY = concat(' UPDATE #tgEnquiry SET ', @enquiryColName, ' =  ',  
                        CASE  WHEN @enquiryFeildDataType IN ('int', 'bigint', 'float', 'numeric', 'decimal', 'money')
                            THEN JSON_VALUE(@LeadValueRow, N'$.values[0]')
                        ELSE '''' + @enquiryColValue + ''''
                    END, 
                ' WHERE EnquiryID = ', CAST(@tempEnquiryId AS NVARCHAR))

                        print @QUERY
                        execute sp_executesql @QUERY
                    end
                end
            ELSE              
            BEGIN

                    DECLARE @CustomFieldId BIGINT = 0
                    SELECT @CustomFieldId = field_ID FROM customfields WHERE ParentID = @ParentId and fieldname = @enquiryFeildName
                    print concat('@CustomFieldId =>',@CustomFieldId)

                    INSERT INTO #tempCustomEnquiryField (fieldID, fieldvalue)
                    VALUES (@CustomFieldId, JSON_VALUE(@LeadValueRow, N'$.values[0]'))

                    set @json=(SELECT JSON_QUERY((select * from #tgEnquiry for json path)) as col1)

                END
                update #tgColMapping set isProcess = 1 where sno = @Sno

            end
       
	 
		BEGIN TRY 
			BEGIN TRANSACTION

			DECLARE @leadn1 BIGINT = 0              
            SELECT * INTO  #tempLead
                FROM (
                    SELECT leadno, isnull(mobileno,'0') AS [mobile], '1' AS [email] FROM UserLeads(NOLOCK) WHERE ParentID=@ParentID and MobileNo<>''
                    union
                        select leadno, isnull(mobileno1, '0') as [mobile], '1' as [email] from UserLeads(nolock) where ParentID=@ParentID and MobileNo1<>'' 
                    union
                        select leadno, isnull(mobileno2,'0'), '1' from UserLeads(nolock) where ParentID=@ParentID and MobileNo2<>''
                    union
                        select leadno, '0' as [mobile], isnull(nullif(emailid,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID and emailid<>''
                    union select leadno, '0' as [mobile], isnull(nullif(emailid1,''),'1') as [email] from UserLeads(nolock)
                        where ParentID=@ParentID and emailid1<>''
                    union
                        select leadno, '0' as [mobile], isnull(nullif(emailid2,''),'1') from UserLeads(nolock) where ParentID=@ParentID and emailid2<>''                                         
            ) lc              
            WHERE leadno not in (select leadno from #tgEnquiry)    
            
            SET @json=(SELECT JSON_QUERY((select * from #tempLead for json path)) as col1)
                
        
            declare @RC bigint=0              
            
            INSERT INTO UserEnquiry (PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName,enquirysource )
            SELECT PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName, 2
            FROM #tgEnquiry Where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '') and ISNULL(SourceName, '') != ''   
                    
            Select @RC = @@ROWCOUNT              
            SELECT @EnquiryId = isnull(SCOPE_IDENTITY(), 0)              
            
			
			
            print concat('@EnquiryId =>',@EnquiryId) 
    
			set @leadn1 = isnull((select top 1 t.leadno from #tempLead t inner join UserEnquiry e 
			on t.mobile in (e.MobileNo, e.MobileNo1, e.MobileNo2) or t.email in (e.EmailID, e.EmailID1, e.EmailID2) where e.EnquiryID = @EnquiryId), 0) 
        
			set @json=(SELECT JSON_QUERY((select * from #tgEnquiry where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '')
				 and ISNULL(SourceName, '') != '' for json path)) as col1)
                                
			IF(@EnquiryId > 0 and @RC > 0)              
			BEGIN

				INSERT INTO customfieldEnquiryvalue ( EnquiryID, fieldID, fieldvalue ) 
				SELECT @EnquiryId, fieldID, fieldvalue FROM #tempCustomEnquiryField

				SET @json=(SELECT (JSON_QUERY((select * from #tgEnquiry for json path))) as col1)
				SET @Trace += '; insert into customfieldEnquiryvalue table: ' + isnull(@json,'')

				INSERT INTO parsedenquiries (rawenquiryid, enquiryid, parentid, EnquirySource)
					VALUES( @gwAutoId, @EnquiryId, @ParentId, 'Google leadgen')
                

				SET @AutoLeadDistribution = isnull((SELECT isnull(AutoLeadDistribution,0) FROM CRMCampaignSettings(nolock) WHERE UserID = @ParentId),0)

				IF (@AutoLeadDistribution = 1 and @leadn1=0)                                            
				BEGIN
					SET @Leadn1 = isnull((SELECT MAX(LeadNo) FROM UserLeads WHERE ParentID = @ParentID), 0) + 1;
					declare @returnAgentId bigint
                    
					print concat('@returnAgentId=>',@returnAgentId)
					exec udf_GetAgentToAssigned @ParentId = @ParentId, @AgentId = @returnAgentId output
					print concat('@returnAgentId=>',@returnAgentId)
                    
					INSERT INTO UserLeads( LeadNo, PersonName, MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode, CountryCode1, ResidentialAddress, OfficeAddress, CompanyName,
						AssignedTo, SourceName, Mediumname, Campaignname, ParentID, InitialRemarks, CreatedOn, CreatedBy, enquirysource)
					SELECT @leadn1, substring(PersonName,1,100), MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode, CountryCode1, ResidentialAddress, OfficeAddress, CompanyName, 
						@returnAgentId, SourceName, Mediumname, Campaignname, @ParentId, InitialRemarks, GETDATE(), @ParentId, enquirysource FROM UserEnquiry(nolock) where EnquiryID = @EnquiryId

					DECLARE @LeadId BIGINT;
					SET @LeadId = SCOPE_IDENTITY() 

					set @isleadcreated=1
					print concat('@LeadId=>',@LeadId)

					INSERT INTO customfieldLeadvalue ( EnquiryID, fieldID, fieldvalue, LeadID )
					SELECT @EnquiryId, fieldID, fieldvalue, @LeadId FROM #tempCustomEnquiryField

					UPDATE UserEnquiry  SET LeadNo = 
						CASE WHEN @LeadN1<>0 THEN @leadn1 ELSE null END, 
						IsOpen= case when @isleadcreated=1 then 0 else 1 end 
					WHERE EnquiryID=@EnquiryId;

					--select * from customfieldLeadvalue
                   
					if not exists(select 1 from tbl_MergeLeadsEnquiry(nolock) 
						where EnquiryNo=@EnquiryId and LeadNo=@leadn1)    
					begin
						insert into  tbl_MergeLeadsEnquiry (EnquiryNo ,LeadNo,IsOpen)
						values(@EnquiryId, @Leadn1, case when @isleadcreated=1 then 0 else 1 end)

						exec usp_ims_UpgradeEnquiryToLead @EnquiryId

					end
				end
			END 
			UPDATE tbl_GoogleForm_Webhook SET isprocessed = 1, Processed = GETDATE() WHERE Id = @gwAutoId    


			COMMIT TRANSACTION              
		END TRY              
		BEGIN CATCH              
			ROLLBACK TRANSACTION  THROW              
		END CATCH
		
    END
    END TRY              
    BEGIN CATCH              
        
        EXEC usp_InsertErrorInfo
        DECLARE @FailedReason NVARCHAR(MAX)  = ERROR_MESSAGE()
        UPDATE tbl_GoogleForm_Webhook SET isprocessed = 1, Processederror = @FailedReason, Processed = GETDATE()  WHERE Id = @gwAutoId              
                    
        SELECT @FailedReason, @gwAutoId              
                
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ConvertLeadgenToEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ConvertLeadgenToEnquiry](
	@LeadgenAutoId NVARCHAR(200)  
)
AS                    
BEGIN  

 --declare @LeadgenAutoId NVARCHAR(200) = 2548510

 drop table if exists #tempEnquiry
 drop table if exists #customEnquiryField
 drop table if exists #fbLeadData
 drop table if exists #tempLead
 drop table if exists #errorMSG
 drop table if exists #tempEnquiryMainField
 drop table if exists #tempCustomEnquiryField

 declare @isleadcreated int = 0                   
 DECLARE @RowJson NVARCHAR(MAX), @ParentId BIGINT, @FbLeadgenId NVARCHAR(200), @FbFormId NVARCHAR(200), @Cnt INT  = 0, @RowCount INT, @EnquiryId BIGINT = 0, @QUERY NVARCHAR(MAX) = '', @ParamDef NVARCHAR(500) = '', @AutoLeadDistribution BIT, @tempEnquiryId BIGINT = -1, @LeadValueRow NVARCHAR(MAX), @fbFeildName NVARCHAR(200), @enquiryFeildName NVARCHAR(200), @enquiryFeildDataType NVARCHAR(200), @SourceCode NVARCHAR(200), @MediumCode BIGINT, @CampaignCode BIGINT, @Trace varchar(max)='', @json varchar(max)=''
  
    
      
                    
 --SELECTING ROW                    
 --SELECT @LeadgenAutoId = Id, @FbLeadgenId = LeadgenId, @RowJson = JsonData FROM inserted                    
	
 SELECT @FbLeadgenId = LeadgenId, @RowJson = JsonData,  @ParentId = ParentId, @FbFormId = FbFormId  FROM tbl_fb_FacebookLeadJson where Id = @LeadgenAutoId                    
                     
 BEGIN TRY  
 
  -- GETTING PARENT ID AND FROM ID                    
	--SELECT TOP 1 @ParentId = FP.ParentId, @FbFormId = FWJ.FbForm_Id from ( select * from tbl_fb_WebhookJsonData(nolock)              
	--	where FbLeadgen_Id in (            
	--	SELECT LeadgenId FROM tbl_fb_FacebookLeadJson where Id = @LeadgenAutoId            
	--	)  )FWJ            
	--	INNER JOIN tbl_fb_FacebookPages(nolock) FP on FWJ.FbPageId = FP.FbPageId              
	--	INNER JOIN tbl_fb_FacebookPageForms(nolock) FPF on FP.FbPageId = FPF.FbPageId            
	--order by fwj.CreatedOn desc      
	
	
             
	PRINT @ParentId            
            
            
   -- PARSING JSON field_data DATA                    
    SELECT * INTO  #fbLeadData FROM OPENJSON(@RowJson, N'$.field_data')                    
   -- Count to tolal field in _field_data                    
    SELECT @RowCount = COUNT(*) FROM #fbLeadData                    
                    
   SELECT @SourceCode = EnquiryFieldValue FROM tbl_MarketingApiSource(nolock) WHERE FbFormId = @FbFormId AND EnquiryField = 'SourceName'                    
   SELECT @MediumCode = EnquiryFieldValue FROM tbl_MarketingApiSource(nolock) WHERE FbFormId = @FbFormId AND EnquiryField = 'MediumName'                    
   SELECT @CampaignCode = EnquiryFieldValue FROM tbl_MarketingApiSource(nolock) WHERE FbFormId = @FbFormId AND EnquiryField = 'CampaignName'                    
                    
  set @Trace += '; @ParentId=' + cast(isnull(@ParentId,0) as varchar(max)) + ', @FbFormId=' + cast(isnull(@FbFormId,0) as varchar(max)) + ', @RowCount=' + cast(isnull(@RowCount,0) as varchar(max)) + ', @SourceCode=' + cast(isnull(@SourceCode,'')          
  
    
     
  as varchar(max)) + ', @FbLeadgenId=' + cast(isnull(@FbLeadgenId,0) as varchar(max)) + ', @RowJson=' + cast(isnull(@RowJson, '') as varchar(max)) + ', @LeadgenAutoId=' + cast(isnull(@LeadgenAutoId,0) as varchar(max))                    
                    
   SELECT * INTO #tempEnquiryMainField FROM UserEnquiry(nolock) WHERE EnquiryID < 0                    
                       
   SET IDENTITY_INSERT #tempEnquiryMainField ON                    
   INSERT INTO #tempEnquiryMainField (EnquiryID, SourceName, MediumName, CampaignName, ParentID, IsOpen, CreatedDate, CreatedBy,IsduplicateEmail, IsduplicateMobile) VALUES ( @tempEnquiryId, @SourceCode, @MediumCode, @CampaignCode, @ParentId, 1, GETDATE(), @ParentId ,0,0)                    
   SET IDENTITY_INSERT #tempEnquiryMainField OFF                    
           
 set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)                     
 set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')                    
                    
   CREATE TABLE #tempCustomEnquiryField                    
   (                    
    fieldID BIGINT,                    
    fieldvalue SQL_VARIANT                    
   )                    
                     
   IF NOT EXISTS(SELECT * FROM tbl_fb_FormFeildMapping(nolock) where  FbFormId = @FbFormId)                  
   BEGIN                  
  DECLARE @msg nvarchar(500) = 'There is no entry available in tbl_fb_FormFeildMapping aginst FbFormId : ' + @FbFormId                   
  set @Trace += ';   returning from procedure usp_ConvertLeadgenToEnquiry '+@msg+ ''                  
  UPDATE tbl_fb_FacebookLeadJson SET IsProccesed = 1, FailedReason = @msg, LastProccessedOn = GETDATE()  WHERE Id = @LeadgenAutoId                  
  insert into dbg_MySms values('procedure usp_ConvertLeadgenToEnquiry', isnull(@Trace,''),GETDATE())                    
                  
  RETURN                  
   END                  
                  
   WHILE( @Cnt < @RowCount)                    
   BEGIN                    
    SELECT @LeadValueRow  = [value] From #fbLeadData(nolock) WHERE [key] = @Cnt
	
	if(exists(select 1 from tbl_fb_FormFeildMapping(nolock) 
			where FbFieldName  = JSON_VALUE(@LeadValueRow, N'$.name') and FbFormId = @FbFormId  ))
		begin
			print concat('@LeadValueRow => ', @LeadValueRow)

		SELECT @enquiryFeildName = LTRIM(RTRIM(EnquiryFieldName)) FROM tbl_fb_FormFeildMapping(nolock) where FbFieldName  = JSON_VALUE(@LeadValueRow, N'$.name') and FbFormId = @FbFormId                       
                   
		SELECT @enquiryFeildDataType = DATA_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE  TABLE_NAME = 'UserEnquiry' AND COLUMN_NAME  = @enquiryFeildName                     
                        
		--SELECT @FbFormId,  JSON_VALUE(@LeadValueRow, N'$.name'), @enquiryFeildName                    
		 --SET @QUERY = 'INSERT INTO #tempEnquiryMainField ( ' + @enquiryFeildName+', ParentId, SourceName, MediumName, CampaignName ) VALUES '                    
		 -- SET @QUERY += CASE WHEN @enquiryFeildDataType = 'int'                    
		 --   THEN  ' ( ' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+' )'                    
		 --   WHEN @enquiryFeildDataType = 'bigint'                     
		 --   THEN  ' ( ' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+' )'                    
		 --   WHEN @enquiryFeildDataType = 'float'                    
		 --   THEN  ' ( ' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+' )'                    
		 --   WHEN @enquiryFeildDataType = 'numeric'                    
		 --   THEN  ' ( ' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+' )'                    
		 --   ELSE                    
		 --   ' ( ''' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+''', '+CAST(@ParentId AS nvarchar)+', '+ CAST(@SourceCode AS NVARCHAR) +', '+ CAST(@MediumCode AS NVARCHAR) +', '+CAST(@CampaignCode AS NVARCHAR)+' )'                    
		 -- END;                      
                         
		 -- Set @QUERY += ' SET @EnquiryIdOut=Scope_Identity() print @EnquiryIdOut '                    
		 -- SET @ParamDef += ' @EnquiryIdOut bigint output'                    
		 -- --print @QUERY                            
		 -- execute sp_executesql @QUERY, @ParamDef, @EnquiryIdOut = @EnquiryId output                     
		  --select @EnquiryId                    
		  --print 'EnquiryId :' + CAST(@EnquiryId AS VARCHAR(15))                    
                    
		set @Trace += '; @enquiryFeildName=' + cast(isnull(@enquiryFeildName, '') as varchar(max))                     
                    
		IF(COL_LENGTH('dbo.UserEnquiry', @enquiryFeildName) IS NOT NULL)                    
		 BEGIN                    
		  set @Trace += '; entering A1 '                    
                    
		  IF( @enquiryFeildName = 'MobileNo' OR @enquiryFeildName = 'MobileNo1' OR @enquiryFeildName = 'MobileNo2')                    
		   BEGIN                    
		   set @Trace += '; entering A1.1 '                    
                    
			DECLARE @Mobile NVARCHAR(50) =   REPLACE(JSON_VALUE(@LeadValueRow, N'$.values[0]'), ' ', ''), @Start INT = 1, @CountryCode NVARCHAR(10) = '', @MobileNo_Checked BIGINT = 0, @PatterCountryCode NVARCHAR(10), @CountryCodeLen INT = 0;                  
  
                    
			select @PatterCountryCode = LTRIM(RTRIM(CountryCode)), @CountryCodeLen = LEN(LTRIM(RTRIM(CountryCode))) from m_country1 where @Mobile like (rtrim(CountryCode) + '%')                 
                
	  print '@Mobile: ' + isnull(@Mobile,'') + ' , @CountryCodeLen: ' + cast(@CountryCodeLen as varchar) 
  
                    
			SET @MobileNo_Checked = SUBSTRING(@Mobile, @CountryCodeLen + 1, LEN(@Mobile))                    
                            
			set @Trace += '; @Mobile=' + cast(isnull(@Mobile, '') as varchar(max)) + ' @PatterCountryCode=' + cast(isnull(@PatterCountryCode, '') as varchar(max)) + ' @MobileNo_Checked=' + cast(isnull(@MobileNo_Checked, '') as varchar(max)) + ' @CountryCodeLen=' + cast(isnull(@CountryCodeLen, '') as varchar(max))                    
                
	  SET @CountryCode = isnull(@PatterCountryCode, trim(dbo.udf_GetParentCountryCode(@ParentId)))
                
            
             
			UPDATE #tempEnquiryMainField                     
			SET CountryCode = case when @enquiryFeildName = 'MobileNo' then @CountryCode else CountryCode end,                     
			 CountryCode1 = case when @enquiryFeildName = 'MobileNo1' then @CountryCode else CountryCode1 end,                     
			 CountryCode2 = case when @enquiryFeildName = 'MobileNo2' then @CountryCode else CountryCode2 end,                     
	   MobileNo = case when @enquiryFeildName = 'MobileNo' then @MobileNo_Checked else MobileNo end,                    
			 MobileNo1 = case when @enquiryFeildName = 'MobileNo1' then @MobileNo_Checked else MobileNo1 end,                    
			 MobileNo2 = case when @enquiryFeildName = 'MobileNo2' then @MobileNo_Checked else MobileNo2 end                
			WHERE EnquiryID = @tempEnquiryId                    
                    
                            
			set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)                     
			set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')                    
                            
		   END                    
		  ELSE                    
		   BEGIN                    
			set @Trace += '; entering B1 '                    
                    
			SET @QUERY = 'UPDATE #tempEnquiryMainField SET ' + @enquiryFeildName+' =  '                    
			SET @QUERY += CASE WHEN @enquiryFeildDataType = 'int'                    
			 OR @enquiryFeildDataType = 'bigint'                     
			 OR @enquiryFeildDataType = 'float'                    
			 OR @enquiryFeildDataType = 'numeric'                    
			 OR @enquiryFeildDataType = 'decimal'                    
			 OR @enquiryFeildDataType = 'money'                    
			  THEN JSON_VALUE(@LeadValueRow, N'$.values[0]')+'  WHERE EnquiryID = '+CAST(@tempEnquiryId AS NVARCHAR)                    
			 ELSE                    
			 '''' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+'''  WHERE EnquiryID = ' + CAST(@tempEnquiryId AS NVARCHAR)                    
			 END                    
			 --print @QUERY                    
         
			 set @Trace += '; Query: for updating #tempEnquiryMainField table: ' + isnull(@QUERY,'')  
		 
			 execute sp_executesql @QUERY                    
         
		 
			set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)                     
			set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')                    
                            
		   END                    
		 END                    
		ELSE                    
		 BEGIN                    
		   set @Trace += '; entering C1 '                    
                    
		  DECLARE @CustomFieldId BIGINT = 0                    
		  SELECT @CustomFieldId = field_ID FROM customfields WHERE ParentID = @ParentId and fieldname = @enquiryFeildName                    
                    
		  INSERT INTO #tempCustomEnquiryField (fieldID, fieldvalue) VALUES (@CustomFieldId, JSON_VALUE(@LeadValueRow, N'$.values[0]'))                    
                    
		  set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)                     
		  set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')                            
                    
		 END                    
           
		--PRINT @LeadValueRow  
		end
		select @LeadValueRow = '', @enquiryFeildName = ''
		SET @Cnt = @Cnt + 1 
   END                    
                    
                  
  BEGIN TRY                    
           
   BEGIN TRANSACTION                       
          
    set @Trace += '; entering D1 '                    
                    
   DECLARE @leadn1 BIGINT = 0                    
   SELECT * INTO  #tempLead FROM (                            
    SELECT leadno, isnull(mobileno,'0') AS [mobile], '1' AS [email] FROM UserLeads(NOLOCK) WHERE ParentID=@ParentID and isnull(MobileNo,'') <>''                                            
    union                                    
    select leadno, isnull(mobileno1,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and isnull(MobileNo1,'') <>''                                            
    union                                            
    select leadno, isnull(mobileno2,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and isnull(MobileNo2,'') <>''                                            
    union                                            
    select leadno, '0' as [mobile],isnull(nullif(emailid,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID   and isnull(emailid,'') <>''                                          
    union                                            
    select leadno, '0' as [mobile],isnull(nullif(emailid1,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and isnull(emailid1,'') <>''                                                           
    union                                            
    select leadno, '0' as [mobile],isnull(nullif(emailid2,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and isnull(emailid2,'') <>''                                               
   ) lc                    
                    
   set @json=(SELECT (JSON_QUERY((select * from #tempLead for json path))) as col1)                     
   set @Trace += '; #tempLead table: ' + isnull(@json,'')                     
             
   set @Trace += '; entering E1 '                    
          
 declare @RC bigint=0                    
    INSERT INTO UserEnquiry (PersonName,  CompanyName,  MobileNo,  MobileNo1,  MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName,      
  
 CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName,enquirysource,IsduplicateEmail, IsduplicateMobile )                     
      SELECT PersonName,  CompanyName,  MobileNo,  MobileNo1,  MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName,
   InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName,2,0,0                     
      FROM #tempEnquiryMainField                     
      Where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '') and ISNULL(SourceName, '') != ''                    
      Select @RC = @@ROWCOUNT                    
    SELECT @EnquiryId = isnull(SCOPE_IDENTITY(), 0)                    
                    
                
 set @leadn1 = isnull( ( select top 1 t.leadno from #tempLead t INNER JOIN UserEnquiry e(nolock) on                          
  (                    
   (t.mobile = e.MobileNo and isnull(t.mobile,'') <> '') or (t.mobile = e.MobileNo1 and isnull(t.mobile,'') <> '' ) 
   or (t.mobile = e.MobileNo2 and isnull(t.mobile,'') <> '' ) or (t.email = e.EmailID and isnull(t.email,'') <> '') 
   or (t.email = e.EmailID1 and isnull(t.email,'') <> '') or (t.email = e.EmailID2 and isnull(t.email,'') <> '')                   
  ) WHERE e.EnquiryID = @EnquiryId                     
    ), 0 )                    
                    
   set @Trace += '; @leadn1=' + cast(isnull(@leadn1, 0) as varchar(max))                   
                
                
                
                
    set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '') and ISNULL(SourceName, '') != '' for json path))) as col1)                     
    set @Trace += '; insert into UserEnquiry table: ' + isnull(@json,'')                     
                     
    set @Trace += '; @EnquiryId=' + cast(isnull(@EnquiryId, 0) as varchar(max)) + '   @RC=' + cast(isnull(@RC, 0) as varchar(max))                    
                    
    IF(@EnquiryId > 0 and @RC > 0)                    
    BEGIN                  
     set @Trace += '; entering E1.1 '                    
     INSERT INTO customfieldEnquiryvalue  ( EnquiryID, fieldID, fieldvalue )                    
      SELECT @EnquiryId, fieldID, fieldvalue FROM #tempCustomEnquiryField                    
                    
     set @json=(SELECT (JSON_QUERY((select * from #tempCustomEnquiryField for json path))) as col1)                     
     set @Trace += '; insert into customfieldEnquiryvalue table: ' + isnull(@json,'')                     
                    
     INSERT INTO parsedenquiries(rawenquiryid, enquiryid, parentid, EnquirySource) VALUES (@LeadgenAutoId, @EnquiryId, @ParentId, 'Facebook leadgen')                    
                  
 /************Added following code block to capture our facebook leads into CRM ****************/               
              
if exists(select 1 from LeadSettings(nolock) where UserID=@ParentId and source='facebook')              
 begin              
 create table #fbfrml(id int identity(1,1),settingid int,fbpage nvarchar(100),fbfrm nvarchar(100))              
 insert into #fbfrml(settingid,fbpage,fbfrm)              
 select id,FBPagename,FBFormTitle from LeadSettings(nolock) where UserID=@ParentId and source='facebook'              
 --select * from #fbfrml              
 declare @c int=(select min(id) from #fbfrml),@settingid int              
 declare @frm varchar(50),@Name nvarchar(100),@MobileN nvarchar(50),@EmailID nvarchar(100),@Company nvarchar(200),@Fremarks nvarchar(100),@fbpagename nvarchar(200)='',@fbfrmn nvarchar(200)=''              
 while @c is not null              
 begin              
               
 select @frm=f.fbformid,@fbpagename=p.FbPageName,@fbfrmn=f.FbFormTitle,@settingid=settingid from tbl_fb_FacebookPageForms f(nolock) join tbl_fb_FacebookPages p(nolock) on f.FbPageId=p.FbPageId              
 join #fbfrml l on l.fbfrm=f.FbFormTitle and l.fbpage=p.FbPageName              
 where l.id=@c --and p.ParentId=@ParentId              
 --select @C,@frm,@fbpagename,@fbfrmn,@FbFormId              
 if @frm=@FbFormId              
 begin              
     declare @CountryCodeTemp nvarchar(10) = ''
 select @Name=PersonName,@CountryCodeTemp = CountryCode,@MobileN=MobileNo,@EmailID=EmailID,@Company=CompanyName,@Fremarks='Lead through facebook page '+@fbpagename+ ' and formname '+@fbfrmn +' Leadgenid: '              
 +cast(@FbLeadgenId as nvarchar(25) ) from UserEnquiry(nolock) where EnquiryID=@EnquiryId              
 --select @Name,@MobileN,@EmailID,@Company,@Fremarks,@fbpagename,@fbfrmn              
 --exec Usp_insertIntoLeadList_Process 'FacebookLead','Name|Mobile|EmailID|Company',@Name,@MobileN,@EmailID,@Company,'',@Fremarks,@ParentID,@settingid              
 exec Usp_insertIntoLeadList_ProcessWithCountryCode 'FacebookLead','Name|CountryCode|Mobile|EmailID|Company',@Name,@MobileN,@EmailID,@Company,'',@Fremarks,@ParentID,@CountryCodeTemp,@settingid   
 end              
 delete from #fbfrml where id=@c              
 select @c=min(id) from #fbfrml              
    end              
 drop table #fbfrml              
 end              
              
 /************Added above code block to capture our facebook leads into CRM ****************/              
                
     --Auto Lead Distribution section start                    
      SET @AutoLeadDistribution = isnull((SELECT isnull(AutoLeadDistribution,0) FROM CRMCampaignSettings(nolock) WHERE UserID = @ParentId),0)                    
      IF (@AutoLeadDistribution = 1 and @leadn1=0)                                                  
      BEGIN                                       
                                                                 
    declare @returnAgentId bigint      
    exec udf_GetAgentToAssigned @ParentId = @ParentId, @AgentId = @returnAgentId output      
      
		set Context_Info 0x55555
	
	     declare @CreatedOn1 datetime = getdate()
		 begin transaction
		SET @Leadn1 = isnull((select MAX(LeadNo) FROM UserLeads(nolock) WHERE  ParentID = @ParentID),0)+1  			
        INSERT INTO userleads (LeadNo, PersonName, MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode, CountryCode1, ResidentialAddress, OfficeAddress, CompanyName, AssignedTo, SourceName, Mediumname,Campaignname,ParentID, InitialRemarks, CreatedOn, CreatedBy,enquirysource
		  ,LastFollowupCreatedBy,LastFollowupCreatedOn )               
        SELECT @leadn1, substring(PersonName,1,100), MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode, CountryCode1, ResidentialAddress, OfficeAddress, CompanyName, @returnAgentId, SourceName,Mediumname,Campaignname, @ParentId,InitialRemarks,@CreatedOn1, @ParentId,enquirysource
		,@ParentId,@CreatedOn1 FROM UserEnquiry(nolock) where EnquiryID = @EnquiryId              
                          
        DECLARE @LeadId BIGINT;                    
        SET @LeadId = SCOPE_IDENTITY()     
		commit transaction
		--exec usp_insertdefaultfollowup @parentid,@leadid    
     
					
		declare @csvLeadId nvarchar(max) = '', @CsvID nvarchar(max) = ''
				
		Exec MySMS.dbo.usp_ExecLeadTriggerTasks @LeadId

		if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end
		create table #outputLeadInteraction(id bigint)  
		insert into MySMS.dbo.leadinteractionhistory( LeadNo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks, AssignedTo, ParentID, CreatedOn, CreatedBy, followupdate,id_lead ) 
			output inserted.ID into #outputLeadInteraction
		select LeadNo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks, AssignedTo, ParentID, @CreatedOn1, CreatedBy, followupdate,id from MySMS.dbo.userleads(nolock) ul 
		inner join dbo.fn_Split(@LeadId,  ',') cui on ul.ID = cui.[value]
	
		select @CsvID = STRING_AGG(CONVERT(NVARCHAR(max), ID),',') From #outputLeadInteraction

		Exec MySMS.dbo.usp_ExecLeadInteractionTriggerTasks @CsvID

		SET Context_Info 0x
	 
		set @isleadcreated=1   
	 
      
	  INSERT INTO customfieldLeadvalue ( EnquiryID, fieldID, fieldvalue, LeadID )                    
	  SELECT @EnquiryId, fieldID, fieldvalue, @LeadId FROM #tempCustomEnquiryField                    
                    
	  UPDATE UserEnquiry  SET LeadNo = CASE WHEN @LeadN1<>0 THEN @leadn1 ELSE null END,       
	  IsOpen= case when @isleadcreated=1 then 0 else 1 end WHERE EnquiryID=@EnquiryId           
    
	  --insert into debug_isopenfromfacebook(leadgen,enquiryid,leadid,leadno,parentid,isopen)  
	  --select @LeadgenAutoId,@enquiryid,@LeadId,CASE WHEN @LeadN1<>0 THEN @leadn1 ELSE null END,  
	  --@parentid,case when @isleadcreated=1 then 0 else 1 end  
            
		  if not exists(select 1 from tbl_MergeLeadsEnquiry(nolock) where EnquiryNo=@EnquiryId and LeadNo=@leadn1)          
		  begin                      
			  insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen)         
			   values (@EnquiryId,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)      
        
	    
		  end          
      end                    
    --Auto Lead Distribution section end                    
    END                    
    --UPDATING tbl_fb_FacebookLeadJson table after successfully completed all work                    
    UPDATE tbl_fb_FacebookLeadJson SET IsProccesed = 1, LastProccessedOn = GETDATE(), EnquiryId = @EnquiryId WHERE Id = @LeadgenAutoId                    
                    
   --SAVING ALL WORK                    
   COMMIT TRANSACTION  
   
	begin try
		if(isnull(@EnquiryId, 0) > 0)
		begin
		exec usp_ims_UpgradeEnquiryToLead @EnquiryId  
		end
	end try
	begin catch
		exec usp_InsertErrorInfo
	end catch


  END TRY                    
  BEGIN CATCH                    
   ROLLBACK TRANSACTION                    
   THROW                    
  END CATCH                    
 END TRY                    
 BEGIN CATCH                    
  SELECT * INTO #errorMSG FROM(                    
   SELECT ERROR_NUMBER() AS ErrorNumber, ERROR_SEVERITY() AS ErrorSeverity, ERROR_STATE() AS ErrorState, ERROR_PROCEDURE() AS ErrorProcedure, ERROR_LINE() AS ErrorLine, ERROR_MESSAGE() AS ErrorMessage) ER                    
                      
  DECLARE @FailedReason NVARCHAR(MAX)                    
  SELECT @FailedReason = ErrorMessage FROM #errorMSG                    
                    
  SELECT LEN(@FailedReason)                    
                    
  UPDATE tbl_fb_FacebookLeadJson SET IsProccesed = 1, FailedReason = @FailedReason, LastProccessedOn = GETDATE()  WHERE Id = @LeadgenAutoId                    
                    
  SELECT @FailedReason, @LeadgenAutoId                    
                    
 END CATCH   
 
 drop table if exists #tempEnquiry
 drop table if exists #customEnquiryField
 drop table if exists #fbLeadData
 drop table if exists #tempLead
 drop table if exists #errorMSG
 drop table if exists #tempEnquiryMainField
 drop table if exists #tempCustomEnquiryField   
                   
   PRINT  @Trace     
   
  --insert into dbg_MySms values('procedure usp_ConvertLeadgenToEnquiry', isnull(@Trace,''),GETDATE())                    


END 



GO

/* ============================================================
   Procedure: [dbo].[usp_ConvertLeadgenToEnquiry1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--SELECT * FROM tbl_fb_FacebookLeadJson          
-- exec usp_ConvertLeadgenToEnquiry '11294'          
CREATE   PROCEDURE [dbo].[usp_ConvertLeadgenToEnquiry1]          
@LeadgenAutoId NVARCHAR(200)          
--ON tbl_fb_FacebookLeadJson          
--AFTER INSERT          
AS          
BEGIN          
 IF OBJECT_ID('tempdb..#tempEnquiry') = NULL BEGIN DROP TABLE #tempEnquiry END          
 IF OBJECT_ID('tempdb..#customEnquiryField') = NULL BEGIN DROP TABLE #customEnquiryField END          
 IF OBJECT_ID('tempdb..#fbLeadData') = NULL BEGIN DROP TABLE #fbLeadData END          
 IF OBJECT_ID('tempdb..#tempLead') = NULL BEGIN DROP TABLE #tempLead END          
 IF OBJECT_ID('tempdb..#errorMSG') = NULL BEGIN DROP TABLE #errorMSG END          
   
 declare @isleadcreated int=0         
 DECLARE @RowJson NVARCHAR(MAX), @ParentId BIGINT, @FbLeadgenId NVARCHAR(200), @FbFormId NVARCHAR(200), @Cnt INT  = 0, @RowCount INT, @EnquiryId BIGINT = 0, @QUERY NVARCHAR(MAX) = '', @ParamDef NVARCHAR(500) = '', @AutoLeadDistribution BIT, @tempEnquiryId
  
    
      
        
 BIGINT = -1, @LeadValueRow NVARCHAR(MAX), @fbFeildName NVARCHAR(200), @enquiryFeildName NVARCHAR(200), @enquiryFeildDataType NVARCHAR(200), @SourceCode NVARCHAR(200), @MediumCode BIGINT, @CampaignCode BIGINT, @Trace varchar(max)='', @json varchar(max)=''
  
    
      
        
          
          
 --SELECTING ROW          
 --SELECT @LeadgenAutoId = Id, @FbLeadgenId = LeadgenId, @RowJson = JsonData FROM inserted          
 SELECT @FbLeadgenId = LeadgenId, @RowJson = JsonData FROM tbl_fb_FacebookLeadJson where Id = @LeadgenAutoId          
           
 BEGIN TRY          
  -- GETTING PARENT ID AND FROM ID          
   SELECT @ParentId = FP.ParentId, @FbFormId = FWJ.FbForm_Id FROM tbl_fb_FacebookLeadJson(nolock) FLJ           
    INNER JOIN tbl_fb_WebhookJsonData(nolock) FWJ ON FLJ.LeadgenId = FWJ.FbLeadgen_Id          
    INNER JOIN tbl_fb_FacebookPages(nolock) FP on FWJ.FbPageId = FP.FbPageId WHERE FLJ.LeadgenId = @FbLeadgenId;          
   -- PARSING JSON field_data DATA          
    SELECT * INTO  #fbLeadData FROM OPENJSON(@RowJson, N'$.field_data')          
   -- Count to tolal field in _field_data          
    SELECT @RowCount = COUNT(*) FROM #fbLeadData          
          
   SELECT @SourceCode = EnquiryFieldValue FROM tbl_MarketingApiSource(nolock) WHERE FbFormId = @FbFormId AND EnquiryField = 'SourceName'          
   SELECT @MediumCode = EnquiryFieldValue FROM tbl_MarketingApiSource(nolock) WHERE FbFormId = @FbFormId AND EnquiryField = 'MediumName'          
   SELECT @CampaignCode = EnquiryFieldValue FROM tbl_MarketingApiSource(nolock) WHERE FbFormId = @FbFormId AND EnquiryField = 'CampaignName'          
          
  set @Trace += '; @ParentId=' + cast(isnull(@ParentId,0) as varchar(max)) + ', @FbFormId=' + cast(isnull(@FbFormId,0) as varchar(max)) + ', @RowCount=' + cast(isnull(@RowCount,0) as varchar(max)) + ', @SourceCode=' + cast(isnull(@SourceCode,'')     
  as varchar(max)) + ', @FbLeadgenId=' + cast(isnull(@FbLeadgenId,0) as varchar(max)) + ', @RowJson=' + cast(isnull(@RowJson, '') as varchar(max)) + ', @LeadgenAutoId=' + cast(isnull(@LeadgenAutoId,0) as varchar(max))          
          
   SELECT * INTO #tempEnquiryMainField FROM UserEnquiry WHERE EnquiryID < 0          
             
   SET IDENTITY_INSERT #tempEnquiryMainField ON          
   INSERT INTO #tempEnquiryMainField (EnquiryID, SourceName, MediumName, CampaignName, ParentID, IsOpen, CreatedDate, CreatedBy) VALUES ( @tempEnquiryId, @SourceCode, @MediumCode, @CampaignCode, @ParentId, 1, GETDATE(), @ParentId )          
   SET IDENTITY_INSERT #tempEnquiryMainField OFF          
          
   set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)           
   set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')          
          
   CREATE TABLE #tempCustomEnquiryField          
   (          
    fieldID BIGINT,          
    fieldvalue SQL_VARIANT          
   )          
           
   IF NOT EXISTS(SELECT * FROM tbl_fb_FormFeildMapping(nolock) where  FbFormId = @FbFormId)        
   BEGIN        
  DECLARE @msg nvarchar(500) = 'There is no entry available in tbl_fb_FormFeildMapping aginst FbFormId : ' + @FbFormId         
  set @Trace += ';   returning from procedure usp_ConvertLeadgenToEnquiry '+@msg+ ''        
  UPDATE tbl_fb_FacebookLeadJson SET IsProccesed = 1, FailedReason = @msg, LastProccessedOn = GETDATE()  WHERE Id = @LeadgenAutoId        
  insert into dbg_MySms values('procedure usp_ConvertLeadgenToEnquiry', isnull(@Trace,''),GETDATE())          
        
  RETURN        
   END        
        
   WHILE( @Cnt < @RowCount)          
   BEGIN          
    SELECT @LeadValueRow  = [value] From #fbLeadData(nolock) WHERE [key] = @Cnt          
    SELECT @enquiryFeildName = LTRIM(RTRIM(EnquiryFieldName)) FROM tbl_fb_FormFeildMapping(nolock) where FbFieldName  = JSON_VALUE(@LeadValueRow, N'$.name') and FbFormId = @FbFormId             
         
    SELECT @enquiryFeildDataType = DATA_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE  TABLE_NAME = 'UserEnquiry' AND COLUMN_NAME  = @enquiryFeildName           
              
    --SELECT @FbFormId,  JSON_VALUE(@LeadValueRow, N'$.name'), @enquiryFeildName          
     --SET @QUERY = 'INSERT INTO #tempEnquiryMainField ( ' + @enquiryFeildName+', ParentId, SourceName, MediumName, CampaignName ) VALUES '          
     -- SET @QUERY += CASE WHEN @enquiryFeildDataType = 'int'          
     --   THEN  ' ( ' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+' )'          
     --   WHEN @enquiryFeildDataType = 'bigint'           
     --   THEN  ' ( ' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+' )'          
     --   WHEN @enquiryFeildDataType = 'float'          
     --   THEN  ' ( ' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+' )'          
     --   WHEN @enquiryFeildDataType = 'numeric'          
     --   THEN  ' ( ' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+' )'          
     --   ELSE          
     --   ' ( ''' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+''', '+CAST(@ParentId AS nvarchar)+', '+ CAST(@SourceCode AS NVARCHAR) +', '+ CAST(@MediumCode AS NVARCHAR) +', '+CAST(@CampaignCode AS NVARCHAR)+' )'          
     -- END;            
               
     -- Set @QUERY += ' SET @EnquiryIdOut=Scope_Identity() print @EnquiryIdOut '          
     -- SET @ParamDef += ' @EnquiryIdOut bigint output'          
     -- --print @QUERY                  
     -- execute sp_executesql @QUERY, @ParamDef, @EnquiryIdOut = @EnquiryId output           
      --select @EnquiryId          
      --print 'EnquiryId :' + CAST(@EnquiryId AS VARCHAR(15))          
          
    set @Trace += '; @enquiryFeildName=' + cast(isnull(@enquiryFeildName, '') as varchar(max))           
          
    IF(COL_LENGTH('dbo.UserEnquiry', @enquiryFeildName) IS NOT NULL)          
     BEGIN          
      set @Trace += '; entering A1 '          
          
      IF( @enquiryFeildName = 'MobileNo' OR @enquiryFeildName = 'MobileNo1' OR @enquiryFeildName = 'MobileNo2')          
       BEGIN          
       set @Trace += '; entering A1.1 '          
          
        DECLARE @Mobile NVARCHAR(50) = JSON_VALUE(@LeadValueRow, N'$.values[0]'), @Start INT = 1, @CountryCode NVARCHAR(10) = '', @MobileNo_Checked BIGINT = 0, @PatterCountryCode NVARCHAR(10), @CountryCodeLen INT = 0;          
          
        select @PatterCountryCode = LTRIM(RTRIM(CountryCode)), @CountryCodeLen = LEN(LTRIM(RTRIM(CountryCode))) from m_country1 where @Mobile like (rtrim(CountryCode) + '%')       
      
  print '@Mobile: ' + isnull(@Mobile,'') + ' , @CountryCodeLen: ' + cast(@CountryCodeLen as varchar)      
          
        SET @MobileNo_Checked = SUBSTRING(@Mobile, @CountryCodeLen + 1, LEN(@Mobile))          
                  
        set @Trace += '; @Mobile=' + cast(isnull(@Mobile, '') as varchar(max)) + ' @PatterCountryCode=' + cast(isnull(@PatterCountryCode, '') as varchar(max)) + ' @MobileNo_Checked=' + cast(isnull(@MobileNo_Checked, '') as varchar(max)) + ' @CountryCodeLen=' + cast(isnull(@CountryCodeLen, '') as varchar(max))          
      
  SET @CountryCode = @PatterCountryCode      
          
        UPDATE #tempEnquiryMainField           
        SET CountryCode = case when @enquiryFeildName = 'MobileNo' then @CountryCode else CountryCode end,           
         CountryCode1 = case when @enquiryFeildName = 'MobileNo1' then @CountryCode else CountryCode1 end,           
         CountryCode2 = case when @enquiryFeildName = 'MobileNo2' then @CountryCode else CountryCode2 end,           
   MobileNo = case when @enquiryFeildName = 'MobileNo' then @MobileNo_Checked else MobileNo end,          
         MobileNo1 = case when @enquiryFeildName = 'MobileNo1' then @MobileNo_Checked else MobileNo1 end,          
         MobileNo2 = case when @enquiryFeildName = 'MobileNo2' then @MobileNo_Checked else MobileNo2 end      
        WHERE EnquiryID = @tempEnquiryId          
          
                  
        set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)           
        set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')          
                  
       END          
      ELSE          
       BEGIN          
        set @Trace += '; entering B1 '          
          
        SET @QUERY = 'UPDATE #tempEnquiryMainField SET ' + @enquiryFeildName+' =  '          
        SET @QUERY += CASE WHEN @enquiryFeildDataType = 'int'          
         OR @enquiryFeildDataType = 'bigint'           
         OR @enquiryFeildDataType = 'float'          
         OR @enquiryFeildDataType = 'numeric'          
         OR @enquiryFeildDataType = 'decimal'          
         OR @enquiryFeildDataType = 'money'          
          THEN JSON_VALUE(@LeadValueRow, N'$.values[0]')+'  WHERE EnquiryID = '+CAST(@tempEnquiryId AS NVARCHAR)          
         ELSE          
         '''' + JSON_VALUE(@LeadValueRow, N'$.values[0]')+'''  WHERE EnquiryID = ' + CAST(@tempEnquiryId AS NVARCHAR)          
         END          
         --print @QUERY          
         execute sp_executesql @QUERY          
          
        set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)           
        set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')          
                  
       END          
     END          
    ELSE          
     BEGIN          
       set @Trace += '; entering C1 '          
          
      DECLARE @CustomFieldId BIGINT = 0          
      SELECT @CustomFieldId = field_ID FROM customfields WHERE ParentID = @ParentId and fieldname = @enquiryFeildName          
          
      INSERT INTO #tempCustomEnquiryField (fieldID, fieldvalue) VALUES (@CustomFieldId, JSON_VALUE(@LeadValueRow, N'$.values[0]'))          
          
      set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)           
      set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')                  
          
     END          
          
    --PRINT @LeadValueRow          
    SET @Cnt = @Cnt + 1          
   END          
          
    set @Trace += '; entering D1 '          
          
   DECLARE @leadn1 BIGINT = 0          
   SELECT * INTO  #tempLead FROM (                  
    SELECT leadno, isnull(mobileno,'0') AS [mobile], '1' AS [email] FROM UserLeads(NOLOCK) WHERE ParentID=@ParentID and MobileNo<>''                                  
    union                                  
    select leadno, isnull(mobileno1,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and MobileNo1<>''                                  
    union                                  
    select leadno, isnull(mobileno2,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and MobileNo2<>''                                  
    union                                  
    select leadno, '0' as [mobile],isnull(nullif(emailid,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID   and emailid<>''                                
    union                                  
    select leadno, '0' as [mobile],isnull(nullif(emailid1,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and emailid1<>''                                                 
    union                                  
    select leadno, '0' as [mobile],isnull(nullif(emailid2,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and emailid2<>''                                     
   ) lc          
          
   set @json=(SELECT (JSON_QUERY((select * from #tempLead for json path))) as col1)           
   set @Trace += '; #tempLead table: ' + isnull(@json,'')           
          
          
          
          
  BEGIN TRY          
   set @Trace += '; entering E1 '          
   BEGIN TRANSACTION             
 declare @RC bigint=0          
    INSERT INTO UserEnquiry (PersonName,  CompanyName,  MobileNo,  MobileNo1,  MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName,     
 CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName )           
      SELECT PersonName,  CompanyName,  MobileNo,  MobileNo1,  MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName,     
   InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName           
      FROM #tempEnquiryMainField           
      Where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '') and ISNULL(SourceName, '') != ''          
      Select @RC = @@ROWCOUNT          
    SELECT @EnquiryId = isnull(SCOPE_IDENTITY(), 0)          
          
      
 set @leadn1 = isnull( ( select top 1 t.leadno from #tempLead t INNER JOIN UserEnquiry e on                
  (          
   t.mobile = e.MobileNo or t.mobile = e.MobileNo1 or t.mobile = e.MobileNo2 or t.email = e.EmailID or t.email = e.EmailID1 or t.email = e.EmailID2          
  ) WHERE e.EnquiryID = @EnquiryId           
    ), 0 )          
          
   set @Trace += '; @leadn1=' + cast(isnull(@leadn1, 0) as varchar(max))         
      
      
      
      
    set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '') and ISNULL(SourceName, '') != '' for json path))) as col1)           
    set @Trace += '; insert into UserEnquiry table: ' + isnull(@json,'')           
              
    set @Trace += '; @EnquiryId=' + cast(isnull(@EnquiryId, 0) as varchar(max)) + '   @RC=' + cast(isnull(@RC, 0) as varchar(max))          
          
    IF(@EnquiryId > 0 and @RC > 0)          
    BEGIN          
     set @Trace += '; entering E1.1 '          
     INSERT INTO customfieldEnquiryvalue  ( EnquiryID, fieldID, fieldvalue )          
      SELECT @EnquiryId, fieldID, fieldvalue FROM #tempCustomEnquiryField          
          
     set @json=(SELECT (JSON_QUERY((select * from #tempCustomEnquiryField for json path))) as col1)           
     set @Trace += '; insert into customfieldEnquiryvalue table: ' + isnull(@json,'')           
          
     INSERT INTO parsedenquiries(rawenquiryid, enquiryid, parentid, EnquirySource) VALUES (@LeadgenAutoId, @EnquiryId, @ParentId, 'Facebook leadgen')          
    
if exists(select 1 from LeadSettings(nolock) where UserID=@ParentId and source='facebook')    
 begin    
 create table #fbfrml(id int identity(1,1),fbpage nvarchar(100),fbfrm nvarchar(100))    
 insert into #fbfrml(fbpage,fbfrm)    
 select FBPagename,FBFormTitle from LeadSettings(nolock) where UserID=@ParentId and source='facebook'    
 --select * from #fbfrml    
 declare @c int=(select min(id) from #fbfrml)    
 declare @frm varchar(50),@Name nvarchar(100),@MobileN nvarchar(50),@EmailID nvarchar(100),@Company nvarchar(200),@Fremarks nvarchar(100),@fbpagename nvarchar(200)='',@fbfrmn nvarchar(200)=''    
 while @c is not null    
 begin    
     
 select @frm=f.fbformid,@fbpagename=p.FbPageName,@fbfrmn=f.FbFormTitle from tbl_fb_FacebookPageForms f(nolock) join tbl_fb_FacebookPages p(nolock) on f.FbPageId=p.FbPageId    
 join #fbfrml l on l.fbfrm=f.FbFormTitle and l.fbpage=p.FbPageName    
 where l.id=@c --and p.ParentId=@ParentId    
 --select @C,@frm,@fbpagename,@fbfrmn,@FbFormId    
 if @frm=@FbFormId    
 begin
   declare @CountryCodeTemp nvarchar(10) = ''
     
 select @Name=PersonName,@CountryCodeTemp = CountryCode, @MobileN=MobileNo,@EmailID=EmailID,@Company=CompanyName,@Fremarks='Lead through facebook page '+@fbpagename+ ' and formname '+@fbfrmn +' Leadgenid: '    
 +cast(@FbLeadgenId as nvarchar(25) ) from UserEnquiry(nolock) where EnquiryID=@EnquiryId    
 --select @Name,@MobileN,@EmailID,@Company,@Fremarks,@fbpagename,@fbfrmn    
 
 --exec Usp_insertIntoLeadList_Process 'FacebookLead','Name|Mobile|EmailID|Company',@Name,@MobileN,@EmailID,@Company,'',@Fremarks,@ParentID    
   exec Usp_insertIntoLeadList_ProcessWithCountryCode 'FacebookLead','Name|CountryCode|Mobile|EmailID|Company',@Name,@MobileN,@EmailID,@Company,'',@Fremarks,@ParentID,@CountryCodeTemp    
   
 end    
 delete from #fbfrml where id=@c    
 select @c=min(id) from #fbfrml    
    end    
 drop table #fbfrml    
 end    
    
    
    
          
          
     --Auto Lead Distribution section start          
      SET @AutoLeadDistribution = isnull((SELECT isnull(AutoLeadDistribution,0) FROM CRMCampaignSettings(nolock) WHERE UserID = @ParentId),0)          
      IF (@AutoLeadDistribution = 1 and @leadn1=0)                                        
      BEGIN                             
       SET @Leadn1 = isnull((select MAX(LeadNo) FROM UserLeads WHERE  ParentID = @ParentID),0)+1                                                  
        INSERT INTO userleads (LeadNo, PersonName, MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode, CountryCode1, ResidentialAddress, OfficeAddress, CompanyName, AssignedTo, SourceName, ParentID, Remarks, CreatedOn, CreatedBy)   
  
        SELECT @leadn1, substring(PersonName,1,100), MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country,   
  CountryCode, CountryCode1, ResidentialAddress, OfficeAddress, CompanyName, (SELECT TOP 1 VALUE FROM fn_Split((SELECT agents FROM   
  CRMCampaignSettings WHERE userid=@ParentId),'#') ORDER BY NEWID()), SourceName, @ParentId,'',GETDATE(), @ParentId FROM UserEnquiry where EnquiryID = @EnquiryId          
                
        DECLARE @LeadId BIGINT;          
        SET @LeadId = SCOPE_IDENTITY()          
  set @isleadcreated=1  
          
          INSERT INTO customfieldLeadvalue ( EnquiryID, fieldID, fieldvalue, LeadID )          
      SELECT @EnquiryId, fieldID, fieldvalue, @LeadId FROM #tempCustomEnquiryField          
          
        UPDATE UserEnquiry  SET LeadNo = CASE WHEN @LeadN1<>0 THEN @leadn1 ELSE null END, 
		IsOpen= case when @isleadcreated=1 then 0 else 1 end WHERE EnquiryID=@EnquiryId          
              
       insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen)   
    values (@EnquiryId,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)          
      end          
    --Auto Lead Distribution section end          
    END          
    --UPDATING tbl_fb_FacebookLeadJson table after successfully completed all work          
    UPDATE tbl_fb_FacebookLeadJson SET IsProccesed = 1, LastProccessedOn = GETDATE(), EnquiryId = @EnquiryId WHERE Id = @LeadgenAutoId          
          
   --SAVING ALL WORK          
   COMMIT TRANSACTION          
  END TRY          
  BEGIN CATCH          
   ROLLBACK TRANSACTION          
   THROW          
  END CATCH          
 END TRY          
 BEGIN CATCH          
  SELECT * INTO #errorMSG FROM(          
   SELECT ERROR_NUMBER() AS ErrorNumber, ERROR_SEVERITY() AS ErrorSeverity, ERROR_STATE() AS ErrorState, ERROR_PROCEDURE() AS ErrorProcedure, ERROR_LINE() AS ErrorLine, ERROR_MESSAGE() AS ErrorMessage) ER          
            
  DECLARE @FailedReason NVARCHAR(MAX)          
  SELECT @FailedReason = ErrorMessage FROM #errorMSG          
          
  SELECT LEN(@FailedReason)          
          
  UPDATE tbl_fb_FacebookLeadJson SET IsProccesed = 1, FailedReason = @FailedReason, LastProccessedOn = GETDATE()  WHERE Id = @LeadgenAutoId          
          
  SELECT @FailedReason, @LeadgenAutoId          
          
 END CATCH          
 IF OBJECT_ID('tempdb..#tempEnquiry') = NULL BEGIN DROP TABLE #tempEnquiry END          
 IF OBJECT_ID('tempdb..#customEnquiryField') = NULL BEGIN DROP TABLE #customEnquiryField END          
 IF OBJECT_ID('tempdb..#fbLeadData') = NULL BEGIN DROP TABLE #fbLeadData END          
 IF OBJECT_ID('tempdb..#tempLead') = NULL BEGIN DROP TABLE #tempLead END          
 IF OBJECT_ID('tempdb..#errorMSG') = NULL BEGIN DROP TABLE #errorMSG END          
         
         
   PRINT  @Trace      
  --insert into dbg_MySms values('procedure usp_ConvertLeadgenToEnquiry', isnull(@Trace,''),GETDATE())          
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_ConvertPrechatDataToEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 -- exec usp_ConvertPrechatDataToEnquiry 1       
      
CREATE   PROCEDURE [dbo].[usp_ConvertPrechatDataToEnquiry]          
 @PrechatAutoId NVARCHAR(200)              
AS          
BEGIN       
      
 IF OBJECT_ID('tempdb..#tempEnquiry') = NULL BEGIN DROP TABLE #tempEnquiry END          
 IF OBJECT_ID('tempdb..#customEnquiryField') = NULL BEGIN DROP TABLE #customEnquiryField END          
 IF OBJECT_ID('tempdb..#fbLeadData') = NULL BEGIN DROP TABLE #fbLeadData END          
 IF OBJECT_ID('tempdb..#tempLead') = NULL BEGIN DROP TABLE #tempLead END          
 IF OBJECT_ID('tempdb..#errorMSG') = NULL BEGIN DROP TABLE #errorMSG END          
 declare @isleadcreated int=0        
  
 DECLARE @RowJson NVARCHAR(MAX), @ParentId BIGINT, @TtcClientId NVARCHAR(200), @FbFormId NVARCHAR(200), @Cnt INT  = 0, @RowCount INT, @EnquiryId BIGINT = 0, @QUERY NVARCHAR(MAX) = '', @ParamDef NVARCHAR(500) = '', @AutoLeadDistribution BIT, @tempEnquiryId
  
    
 BIGINT = -1, @LeadValueRow NVARCHAR(MAX), @fbFeildName NVARCHAR(200), @enquiryFeildName NVARCHAR(200), @enquiryFeildDataType NVARCHAR(200), @SourceCode NVARCHAR(200), @MediumCode BIGINT, @CampaignCode BIGINT, @Trace varchar(max)='', @json varchar(max)=''
  
    
      
        
       
 SELECT @TtcClientId = TtcClientId, @RowJson = PrechatFormJson FROM tbl_ttc_PrechatFormData where Id = @PrechatAutoId      
      
      
           
 BEGIN TRY          
  -- GETTING PARENT ID AND FROM ID          
   SELECT @ParentId = ParentId From tbl_ttc_ClientDetails where Id = @TtcClientId      
   -- PARSING JSON field_data DATA         
         
      
    SELECT * INTO  #fbLeadData FROM OPENJSON(@RowJson)          
         
         
   -- Count to tolal field in _field_data          
    SELECT @RowCount = COUNT(*) FROM #fbLeadData          
          
   SELECT @SourceCode = DefaultValue FROM tbl_ttc_FormFieldMapping(nolock) WHERE TtcClientId = @TtcClientId AND EnFieldName = 'SourceName'          
   SELECT @MediumCode = DefaultValue FROM tbl_ttc_FormFieldMapping(nolock) WHERE TtcClientId = @TtcClientId AND EnFieldName = 'MediumName'          
   SELECT @CampaignCode = DefaultValue FROM tbl_ttc_FormFieldMapping(nolock) WHERE TtcClientId = @TtcClientId AND EnFieldName = 'CampaignName'          
           
          
   SELECT * INTO #tempEnquiryMainField FROM UserEnquiry WHERE EnquiryID < 0          
             
   SET IDENTITY_INSERT #tempEnquiryMainField ON          
   INSERT INTO #tempEnquiryMainField (EnquiryID, SourceName, MediumName, CampaignName, ParentID, IsOpen, CreatedDate, CreatedBy) VALUES ( @tempEnquiryId, @SourceCode, ISNULL(@MediumCode, 0), ISNULL(@CampaignCode, 0), @ParentId, 1, GETDATE(), @ParentId )  
  
        
   SET IDENTITY_INSERT #tempEnquiryMainField OFF          
          
          
   CREATE TABLE #tempCustomEnquiryField          
   (          
    fieldID BIGINT,          
    fieldvalue SQL_VARIANT          
   )          
           
   IF NOT EXISTS(SELECT * FROM tbl_ttc_FormFieldMapping(nolock) where  TtcClientId = @TtcClientId)        
   BEGIN        
  DECLARE @msg nvarchar(500) = 'There is no entry available in tbl_fb_FormFeildMapping aginst FbFormId : ' + @TtcClientId         
      
  set @Trace += ';   returning from procedure usp_ConvertLeadgenToEnquiry '+@msg+ ''        
  UPDATE tbl_ttc_PrechatFormData SET IsProcessed = 1, Reason = @msg, ProcessedOn = GETDATE()  WHERE Id = @PrechatAutoId        
      
  insert into dbg_MySms values('procedure usp_ConvertLeadgenToEnquiry', isnull(@Trace,''),GETDATE())          
        
  RETURN        
   END        
        
   WHILE( @Cnt < @RowCount)          
   BEGIN          
          
 SELECT @LeadValueRow  = [value] From #fbLeadData(nolock) WHERE [key] = @Cnt         
       
    SELECT @enquiryFeildName = LTRIM(RTRIM(EnFieldName)) FROM tbl_ttc_FormFieldMapping (nolock) where  TtcFieldName  = JSON_VALUE(@LeadValueRow, N'$.label') and TtcClientId = @TtcClientId             
         
      
   print @enquiryFeildName      
      
    SELECT @enquiryFeildDataType = DATA_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE  TABLE_NAME = 'UserEnquiry' AND COLUMN_NAME  = @enquiryFeildName           
              
          
    set @Trace += '; @enquiryFeildName=' + cast(isnull(@enquiryFeildName, '') as varchar(max))           
          
    IF(COL_LENGTH('dbo.UserEnquiry', @enquiryFeildName) IS NOT NULL)          
     BEGIN          
      set @Trace += '; entering A1 '          
          
IF( @enquiryFeildName = 'MobileNo' OR @enquiryFeildName = 'MobileNo1' OR @enquiryFeildName = 'MobileNo2')          
       BEGIN          
       set @Trace += '; entering A1.1 '          
          
        DECLARE @Mobile NVARCHAR(50) = JSON_VALUE(@LeadValueRow, N'$.answer'), @Start INT = 1, @CountryCode NVARCHAR(10) = '', @MobileNo_Checked BIGINT = 0, @PatterCountryCode NVARCHAR(10), @CountryCodeLen INT = 0;          
          
        select @PatterCountryCode = LTRIM(RTRIM(CountryCode)), @CountryCodeLen = LEN(LTRIM(RTRIM(CountryCode))) from m_country1 where @Mobile like (rtrim(CountryCode) + '%')       
      
  print '@Mobile: ' + isnull(@Mobile,'') + ' , @CountryCodeLen: ' + cast(@CountryCodeLen as varchar)      
          
        SET @MobileNo_Checked = SUBSTRING(@Mobile, @CountryCodeLen + 1, LEN(@Mobile))          
                  
        set @Trace += '; @Mobile=' + cast(isnull(@Mobile, '') as varchar(max)) + ' @PatterCountryCode=' + cast(isnull(@PatterCountryCode, '') as varchar(max)) + ' @MobileNo_Checked=' + cast(isnull(@MobileNo_Checked, '') as varchar(max)) + ' @CountryCodeLe
  
n=' + cast(isnull(@CountryCodeLen, '') as varchar(max))          
          
 IF(@CountryCode = 0) BEGIN SET @CountryCode = '+91' END      
      
        UPDATE #tempEnquiryMainField           
        SET CountryCode = case when @enquiryFeildName = 'MobileNo' then @CountryCode else CountryCode end,           
         CountryCode1 = case when @enquiryFeildName = 'MobileNo1' then @CountryCode else CountryCode1 end,           
         CountryCode2 = case when @enquiryFeildName = 'MobileNo2' then @CountryCode else CountryCode2 end,           
         MobileNo = case when @enquiryFeildName = 'MobileNo' then @MobileNo_Checked else MobileNo end,          
         MobileNo1 = case when @enquiryFeildName = 'MobileNo1' then @MobileNo_Checked else MobileNo1 end,          
         MobileNo2 = case when @enquiryFeildName = 'MobileNo2' then @MobileNo_Checked else MobileNo2 end      
        WHERE EnquiryID = @tempEnquiryId          
          
                  
        set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)           
        set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')          
                  
       END          
      ELSE          
       BEGIN          
        set @Trace += '; entering B1 '          
          
        SET @QUERY = 'UPDATE #tempEnquiryMainField SET ' + @enquiryFeildName+' =  '          
        SET @QUERY += CASE WHEN @enquiryFeildDataType = 'int'          
         OR @enquiryFeildDataType = 'bigint'           
         OR @enquiryFeildDataType = 'float'          
         OR @enquiryFeildDataType = 'numeric'          
         OR @enquiryFeildDataType = 'decimal'          
         OR @enquiryFeildDataType = 'money'          
          THEN JSON_VALUE(@LeadValueRow, N'$.answer')+'  WHERE EnquiryID = '+CAST(@tempEnquiryId AS NVARCHAR)          
         ELSE          
         '''' + JSON_VALUE(@LeadValueRow, N'$.answer')+'''  WHERE EnquiryID = ' + CAST(@tempEnquiryId AS NVARCHAR)          
         END          
         --print @QUERY          
         execute sp_executesql @QUERY          
          
        set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)           
        set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')          
                  
       END          
     END          
    ELSE          
     BEGIN          
       set @Trace += '; entering C1 '          
          
      DECLARE @CustomFieldId BIGINT = 0          
      SELECT @CustomFieldId = field_ID FROM customfields WHERE ParentID = @ParentId and fieldname = @enquiryFeildName          
          
      INSERT INTO #tempCustomEnquiryField (fieldID, fieldvalue) VALUES (@CustomFieldId, JSON_VALUE(@LeadValueRow, N'$.answer'))          
          
      set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField for json path))) as col1)           
      set @Trace += '; #tempEnquiryMainField table: ' + isnull(@json,'')                  
          
     END          
          
    --PRINT @LeadValueRow          
    SET @Cnt = @Cnt + 1          
   END          
          
    set @Trace += '; entering D1 '          
          
   DECLARE @leadn1 BIGINT = 0          
   SELECT * INTO  #tempLead FROM (                  
    SELECT leadno, isnull(mobileno,'0') AS [mobile], '1' AS [email] FROM UserLeads(NOLOCK) WHERE ParentID=@ParentID and MobileNo<>''                                  
    union                                  
    select leadno, isnull(mobileno1,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and MobileNo1<>''                                  
    union                                  
    select leadno, isnull(mobileno2,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and MobileNo2<>''                                  
    union                                  
    select leadno, '0' as [mobile],isnull(nullif(emailid,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID   and emailid<>''                                
    union                                  
    select leadno, '0' as [mobile],isnull(nullif(emailid1,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and emailid1<>''                                                 
    union                                  
    select leadno, '0' as [mobile],isnull(nullif(emailid2,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and emailid2<>''                                     
   ) lc          
          
   set @json=(SELECT (JSON_QUERY((select * from #tempLead for json path))) as col1)           
   set @Trace += '; #tempLead table: ' + isnull(@json,'')           
          
          
   set @leadn1 = isnull( ( select top 1 t.leadno from #tempLead t INNER JOIN UserEnquiry e on                
    (          
     t.mobile = e.MobileNo or t.mobile = e.MobileNo1 or t.mobile = e.MobileNo2 or t.email = e.EmailID or t.email = e.EmailID1 or t.email = e.EmailID2          
    ) WHERE e.EnquiryID = @tempEnquiryId           
    ), 0 )          
          
   set @Trace += '; @leadn1=' + cast(isnull(@leadn1, 0) as varchar(max))           
          
  BEGIN TRY          
   set @Trace += '; entering E1 '          
   BEGIN TRANSACTION             
   declare @RC bigint=0          
    INSERT INTO UserEnquiry (PersonName,  CompanyName,  MobileNo,  MobileNo1,  MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName,   
 CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName )           
      SELECT PersonName,  CompanyName,  MobileNo,  MobileNo1,  MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName,   
   InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName           
      FROM #tempEnquiryMainField           
      Where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '') and ISNULL(SourceName, '') != ''          
      Select @RC = @@ROWCOUNT          
    SELECT @EnquiryId = isnull(SCOPE_IDENTITY(), 0)          
          
    set @json=(SELECT (JSON_QUERY((select * from #tempEnquiryMainField where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '') and ISNULL(SourceName, '') != '' for json path))) as col1)           
    set @Trace += '; insert into UserEnquiry table: ' + isnull(@json,'')           
              
    set @Trace += '; @EnquiryId=' + cast(isnull(@EnquiryId, 0) as varchar(max)) + '   @RC=' + cast(isnull(@RC, 0) as varchar(max))          
          
    IF(@EnquiryId > 0 and @RC > 0)          
    BEGIN          
     set @Trace += '; entering E1.1 '          
     INSERT INTO customfieldEnquiryvalue  ( EnquiryID, fieldID, fieldvalue )          
      SELECT @EnquiryId, fieldID, fieldvalue FROM #tempCustomEnquiryField          
          
     set @json=(SELECT (JSON_QUERY((select * from #tempCustomEnquiryField for json path))) as col1)           
     set @Trace += '; insert into customfieldEnquiryvalue table: ' + isnull(@json,'')           
          
     INSERT INTO parsedenquiries(rawenquiryid, enquiryid, parentid, EnquirySource) VALUES (@PrechatAutoId, @EnquiryId, @ParentId, 'TawkTo Prechat')          
          
          
     --Auto Lead Distribution section start          
      SET @AutoLeadDistribution = isnull((SELECT isnull(AutoLeadDistribution,0) FROM CRMCampaignSettings(nolock) WHERE UserID = @ParentId),0)          
      IF (@AutoLeadDistribution = 1 and @leadn1=0)                                        
      BEGIN                             
       SET @Leadn1 = isnull((select MAX(LeadNo) FROM UserLeads WHERE  ParentID = @ParentID),0)+1                                                  
 INSERT INTO userleads (LeadNo, PersonName, MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode, CountryCode1, 
 ResidentialAddress, OfficeAddress, CompanyName, AssignedTo, SourceName, ParentID, Remarks, CreatedOn, CreatedBy,MediumName  
,CampaignName,InitialRemarks)       
 SELECT @leadn1, substring(PersonName,1,100), MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode, CountryCode1, 
 ResidentialAddress, OfficeAddress, CompanyName, (SELECT TOP 1 VALUE FROM fn_Split(  
 (SELECT agents FROM CRMCampaignSettings WHERE userid=@ParentId),'#') ORDER BY NEWID()), SourceName, @ParentId,'',GETDATE(), @ParentId,MediumName,CampaignName,InitialRemarks FROM UserEnquiry where EnquiryID = @EnquiryId          
                
        DECLARE @LeadId BIGINT;          
        SET @LeadId = SCOPE_IDENTITY()          
  set @isleadcreated=1  
          
          INSERT INTO customfieldLeadvalue ( EnquiryID, fieldID, fieldvalue, LeadID )          
      SELECT @EnquiryId, fieldID, fieldvalue, @LeadId FROM #tempCustomEnquiryField          
          
        UPDATE UserEnquiry  SET LeadNo = CASE WHEN @LeadN1<>0 THEN @leadn1 ELSE null END, 
		IsOpen= case when @isleadcreated=1 then 0 else 1 end WHERE EnquiryID=@EnquiryId          
              
       insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen)   
    values (@EnquiryId,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)          
      end          
    --Auto Lead Distribution section end          
    END          
    --UPDATING tbl_fb_FacebookLeadJson table after successfully completed all work          
    UPDATE tbl_ttc_PrechatFormData SET IsProcessed = 1, ProcessedOn = GETDATE(), EnquiryId = @EnquiryId WHERE Id = @PrechatAutoId          
          
   --SAVING ALL WORK          
   COMMIT TRANSACTION          
  END TRY          
  BEGIN CATCH          
   ROLLBACK TRANSACTION          
   THROW          
  END CATCH          
 END TRY          
 BEGIN CATCH          
 SELECT * INTO #errorMSG FROM(          
 SELECT ERROR_NUMBER() AS ErrorNumber, ERROR_SEVERITY() AS ErrorSeverity, ERROR_STATE() AS ErrorState, ERROR_PROCEDURE() AS ErrorProcedure, ERROR_LINE() AS ErrorLine, ERROR_MESSAGE() AS ErrorMessage) ER          
            
  DECLARE @FailedReason NVARCHAR(MAX)          
  SELECT @FailedReason = ErrorMessage FROM #errorMSG          
          
  SELECT LEN(@FailedReason)          
          
  UPDATE tbl_ttc_PrechatFormData SET IsProcessed = 1, Reason = @FailedReason, ProcessedOn = GETDATE()  WHERE Id = @PrechatAutoId          
          
      
           END CATCH          
 IF OBJECT_ID('tempdb..#tempEnquiry') = NULL BEGIN DROP TABLE #tempEnquiry END          
 IF OBJECT_ID('tempdb..#customEnquiryField') = NULL BEGIN DROP TABLE #customEnquiryField END          
 IF OBJECT_ID('tempdb..#fbLeadData') = NULL BEGIN DROP TABLE #fbLeadData END          
 IF OBJECT_ID('tempdb..#tempLead') = NULL BEGIN DROP TABLE #tempLead END          
 IF OBJECT_ID('tempdb..#errorMSG') = NULL BEGIN DROP TABLE #errorMSG END          
         
         
   PRINT  @Trace      
  --insert into dbg_MySms values('procedure usp_ConvertLeadgenToEnquiry', isnull(@Trace,''),GETDATE())          
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_correct_inaccurate_bal]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_correct_inaccurate_bal
as
begin
declare @c int,@parentid bigint,@sql nvarchar(2000),@credits numeric(18,4)
drop table if exists #bal_diff
select balance_should_be-actualbalance as bal_diff,* into #bal_diff  from 
(
select i.user_id,tdebits,tcredits,balance as balance_before_may,isnull(Balance,0)+tcredits-tdebits as balance_should_be,dbo.fn_getmoneybalance(i.user_id) as actualbalance 
 from
 (
 (select user_id,sum(debits) tdebits,sum(credits) tcredits from intcredit_details(nolock)i where i.DateCreated>dateadd(d,-1,getdate()) group by user_id) i
left join
(select user_id,balance,credit_id from intcredit_details i(nolock) where credit_id=
(select max(credit_id) from intcredit_details(nolock) where DateCreated<dateadd(d,-1,getdate()) and user_id=i.user_id)) b on b.User_ID=i.User_ID
)  
 ) a where balance_should_be<>actualbalance order by balance_should_be-actualbalance asc

 select @c=count(1) from #bal_diff where bal_diff<0
 


select @sql=concat('select i.* into intcredit_wrong_debit_',format(getdate(),'yyyyMMdd_HH_mm') , ' FROM IntCredit_Details i WITH (NOLOCK) join #bal_diff b on i.User_ID=b.User_ID WHERE DateCreated > dateadd(d,-1,getdate())')
print @sql
exec sp_executesql @sql

 while @c>0
 begin
 select top 1 @parentid=user_id from #bal_diff order by bal_diff
 
SELECT i.*
INTO #t
FROM IntCredit_Details i WITH (NOLOCK) 
WHERE user_id=@parentid and DateCreated>dateadd(d,-1,getdate())  
ORDER BY credit_id;

select top 1 @credits=credits from #t order by credit_id
while @credits>0
begin
delete t from (select top 1 * from #t order by credit_id) t
select top 1 @credits=credits from #t order by credit_id
end



;WITH OrderedTxns AS (
    SELECT *,
           ROW_NUMBER() OVER (ORDER BY credit_id) AS rn
    FROM #t
),
BaseBalance AS (
    SELECT TOP 1 balance FROM OrderedTxns WHERE rn = 1
),
RunningBalance AS (
    SELECT 
        o.credit_id,
        o.user_id,
        o.DateCreated,
        o.debits,
        o.credits,
        o.remarks,
        o.rn,
        -- Calculate balance using windowed SUM
        CAST((
            (SELECT * FROM BaseBalance) + 
            SUM(credits - debits) OVER (ORDER BY rn ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW)
        ) AS numeric(18,4)) AS balance
    FROM OrderedTxns o
)

-- Step 2: Update #t with corrected balances
UPDATE t
SET t.balance = rb.balance
FROM #t t
JOIN RunningBalance rb ON t.credit_id = rb.credit_id;

/*
-- Step 5: Show discrepancies from original data
IF EXISTS (
    SELECT 1
    FROM IntCredit_Details c
    JOIN #t t ON t.credit_id = c.Credit_ID
    WHERE c.balance <> t.balance
)
BEGIN
    SELECT 
        t.balance - c.balance AS balance_diff,
        t.balance AS corrected_balance,
        c.*
    FROM IntCredit_Details c
    JOIN #t t ON t.credit_id = c.Credit_ID
    WHERE c.balance <> t.balance
    ORDER BY c.credit_id;
END
*/

update c set c.balance=t.balance FROM IntCredit_Details c
    JOIN #t t ON t.credit_id = c.Credit_ID

 DROP TABLE IF EXISTS #t;
	delete from #bal_diff where user_id=@parentid

set @c=@c-1
 end


end




GO

/* ============================================================
   Procedure: [dbo].[usp_count_contact]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC  [dbo].[usp_count_contact]    
@gruup_id BIGINT -- from nvarchar(50)          
AS        
BEGIN
	SELECT COUNT(cdg.contact_id)      AS contact
	FROM   Contact_Group_Detail cdg
	       INNER JOIN Contact_Detail  AS cd
	            ON  cd.Contact_ID = cdg.Contact_ID
	            AND cd.[User_ID] = cdg.[User_ID]
	WHERE  cdg.group_id = @gruup_id
END   
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_Count_Message]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_Count_Message]
AS
	DECLARE @C11 NVARCHAR(500)
	DECLARE @C12 NVARCHAR(500)
	DECLARE @C13 NVARCHAR(500)
	DECLARE @C14 NVARCHAR(500)
	DECLARE @C15 NVARCHAR(500)
	DECLARE @C21 NVARCHAR(500)
	DECLARE @C22 NVARCHAR(500)
	DECLARE @C23 NVARCHAR(500)
	DECLARE @C24 NVARCHAR(500)
	DECLARE @C25 NVARCHAR(500)

	SELECT @C11=COUNT(*) FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE  LEN(MESSAGE)<=160 AND (ACCOUNT	='VF_TRANS' OR ACCOUNT='PELS3') 
	SELECT @C12=COUNT(*)*2 FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE  LEN(MESSAGE)>160 AND  LEN		(MESSAGE)<=320 AND (ACCOUNT='VF_TRANS' OR ACCOUNT='PELS3') 
	SELECT @C13=COUNT(*)*3 FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE  LEN(MESSAGE)>320 AND  LEN		(MESSAGE)<=480 AND (ACCOUNT='VF_TRANS' OR ACCOUNT='PELS3') 
	SELECT @C14=COUNT(*)*4 FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE  LEN(MESSAGE)>480 AND  LEN		(MESSAGE)<=640 AND (ACCOUNT='VF_TRANS' OR ACCOUNT='PELS3') 
	SELECT @C15=COUNT(*)*5 FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE LEN(MESSAGE)>640 AND  LEN		(MESSAGE)<=800 AND (ACCOUNT='VF_TRANS' OR ACCOUNT='PELS3')

	SELECT @C21=COUNT(*) FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE  LEN(MESSAGE)<=160 AND (ACCOUNT	='PELS4' OR ACCOUNT='PELS5') 
	SELECT @C22=COUNT(*)*2 FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE  LEN(MESSAGE)>160 AND  LEN		(MESSAGE)<=320 AND (ACCOUNT='PELS4' OR ACCOUNT='PELS5') 
	SELECT @C23=COUNT(*)*3 FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE  LEN(MESSAGE)>320 AND  LEN		(MESSAGE)<=480 AND (ACCOUNT='PELS4' OR ACCOUNT='PELS5') 
	SELECT @C24=COUNT(*)*4 FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE  LEN(MESSAGE)>480 AND  LEN		(MESSAGE)<=640 AND (ACCOUNT='PELS4' OR ACCOUNT='PELS5') 
	SELECT @C25=COUNT(*)*5 FROM [MYSMS].[DBO].[MESSAGEDELIVERYSTATUSTEMP](NOLOCK) WHERE LEN(MESSAGE)>640 AND  LEN		(MESSAGE)<=800 AND (ACCOUNT='PELS4' OR ACCOUNT='PELS5')

	SELECT '1.2' ROUTE,CAST(@C11 AS INT)+CAST(@C12 AS INT)+CAST(@C13 AS INT)+CAST(@C14 AS INT)+CAST(@C15 AS INT) AS		TOTALCREDIT,CAST(@C11 AS INT) CREDIT1 ,CAST(@C12 AS INT) CREDIT2,CAST(@C13 AS INT) CREDIT3,CAST(@C14 AS INT)		CREDIT4,CAST(@C15 AS INT) AS CREDIT5 UNION
	SELECT '3.6' ROUTE,CAST(@C21 AS INT)+CAST(@C22 AS INT)+CAST(@C23 AS INT)+CAST(@C24 AS INT)+CAST(@C25 AS INT) AS		TOTALCREDIT,CAST(@C21 AS INT) CREDIT1,CAST(@C22 AS INT) CREDIT2,CAST(@C23 AS INT) CREDIT3,CAST(@C24 AS INT)			CREDIT4,CAST(@C25 AS INT) AS CREDIT5

	SELECT '1.2' ROUTE,CAST(@C11 AS INT)+CAST(@C12 AS INT)/2+CAST(@C13 AS INT)/3+CAST(@C14 AS INT)/4+CAST(@C15 AS		INT)/5 AS TOTALMESSAGE,CAST(@C11 AS INT) COUNT1 ,CAST(@C12 AS INT)/2 COUNT2,CAST(@C13 AS INT)/3 COUNT3,CAST(@C14	AS INT)/4 COUNT4,CAST(@C15 AS INT)/5 AS COUNT5 UNION
	SELECT '3.6' ROUTE,CAST(@C21 AS INT)+CAST(@C22 AS INT)/2+CAST(@C23 AS INT)/3+CAST(@C24 AS INT)/4+CAST(@C25 AS		INT)/5 AS TOTALMESSAGE,CAST(@C21 AS INT) COUNT1,CAST(@C22 AS INT)/2 COUNT2,CAST(@C23 AS INT)/3 COUNT3,CAST(@C24		AS INT)/4 COUNT4,CAST(@C25 AS INT)/5 AS [COUNT]


GO

