/* ============================================================
   Procedure: [dbo].[usp_create_entity_for_whatsapp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_create_entity_for_whatsapp]    
@ChannelId bigint,@PersonName nvarchar(255)= '',      
 @ChannelProfileId nvarchar(500),      
 @IntialRemarks nvarchar(max),      
 @MoblieNo nvarchar(50),      
 @CountryCode nvarchar(10),      
 @EmailId nvarchar(255),      
 @ParentId bigint      
as    
begin    
DECLARE      
 @entity nvarchar(50), @entityid bigint;      
 declare @Query nvarchar(max)=''      
    
 drop table if exists #convuser_entities    
    
 select entity,entityid,isactive,channelid into #convuser_entities from  [10.0.0.135].MYsmsconversations.dbo.convusers with (NOLOCK) where convuserparentid = @parentid    
     
 if @entityid is null      
 begin      
  print 'user section'      
  SELECT TOP 1 @entity = 'team', @entityid = User_ID from MySMS.dbo.User_Detail(nolock) WHERE 1 = ( case       
   when RIGHT(@channelprofileid, LEN(trim(cast(mobile as nvarchar)))) = dbo.fnGetNumericValue(trim(cast(mobile as nvarchar)))      
     AND trim(ISNULL(cast(mobile as nvarchar), '')) <> ''       
     AND LEN(trim(ISNULL(cast(mobile as nvarchar), 0))) > 5       
    then 1      
   when  RIGHT(@channelprofileid, LEN(trim(wa_mobile_no))) =trim(wa_mobile_no)      
     AND trim(ISNULL(wa_mobile_no, '')) <> ''       
     AND LEN(trim(ISNULL(wa_mobile_no, 0))) > 5       
    then 1      
   else 0 end )      
  AND ParentID = @ParentId       
  AND User_ID NOT IN ( SELECT entityid FROM #convuser_entities WHERE channelid = @channelid AND  entity = 'team' )      
  ORDER BY id DESC;      
 end      
      
 if @entityid is null      
 begin      
  print 'userleads';      
  SELECT  @entity='lead',@entityid= ulme_id FROM MySMS.dbo.userleads_mobile_email(NOLOCK) WHERE  1 = ( case      
    when RIGHT(@channelprofileid, LEN(trim(mobile))) =
    trim( mobile)   
      AND trim(ISNULL(mobile, '')) <> ''       
      AND  LEN(trim(ISNULL(mobile, 0))) > 5       
     then 1      
    else 0 end )      
   and ParentID = @ParentId       
   and ulme_id  NOT IN (SELECT entityid FROM #convuser_entities WHERE channelid = @channelid AND entity = 'lead')      
  order by ulme_id desc;      
 end      
      
 if @entityid is null      
 begin      
  print 'userenquiry';      
  select top 1 @entity = 'enquiry', @entityid = enquiryid FROM      
   MySMS.dbo.Userenquiry_Mobile_Email where 1 = ( case      
   when RIGHT(@channelprofileid, LEN(trim(Mobile))) =trim( Mobile)     
     AND trim(ISNULL(Mobile, '')) <> ''       
     AND  LEN(trim(ISNULL(Mobile, 0))) > 5       
    then 1      
   else 0 end )      
  AND ParentID = @ParentId       
  AND enquiryid NOT IN ( SELECT entityid FROM #convuser_entities WHERE channelid = @channelid AND entity = 'enquiry' )      
  ORDER BY enquiryid DESC;      
 end      
       
 if @entityid is null      
 begin      
  if ISNULL(@ChannelProfileId, '') <> ''      
  begin      
   declare @SourceId bigint; select @SourceId = SourceID from MySMS.dbo.UserSourceSettings(nolock)       
    where UserID = @ParentId AND Name = 'Chat';      
   declare @cc nvarchar(10), @waid nvarchar(20)= @ChannelProfileId, @c nvarchar(50), @no nvarchar(20);      
   select @cc = countrycode, @c = Country_Name from MySMS.dbo.m_country1 where SUBSTRING(@waid, 1, LEN(replace(countrycode, '+', ''))) = replace(countrycode, '+', '');      
          
   select @no = RIGHT(@waid, LEN(@waid) - LEN(replace(@cc, '+', '')));      
          
      
   declare @AgentId bigint = cast(isnull((      
    select top 1 value      
    from fn_Split((select agents from MySMS.dbo.CRMCampaignSettings with (nolock) where userid = @parentid ), '#' )      
    order by newid()      
   ), @parentid) as bigint)      
      
   declare @LeadId bigint ;      
          
   if(not exists (select 1 from mysms.dbo.userleads_mobile_email as ume with(nolock)      
    where Parentid = @ParentId and  Mobile <> '1' and Mobile <> '0' and isnull(Mobile,'') <> ''      
        and  isnull(Mobile,'') =  @no and isnull(CountryCode,'') = @cc ))      
   begin       
      
    print 'lead insert section'      
          
    set Context_Info 0x55555      
	--SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;
    begin transaction;       
  
    declare @LeadNo bigint= ( select IIF(COUNT(1) > 0, MAX(LeadNo) + 1, 1)       
    from MySMS.dbo.UserLeads with (UPDLOCK,HOLDLOCK) where ParentID = @ParentId );         
      
 if not exists(select * from UserLeads(nolock) where ParentID = @ParentId and (MobileNo = trim(@no) or MobileNo1 = trim(@no) or MobileNo2 = trim(@no)) )  
 Begin  
    insert into MySMS.dbo.UserLeads( PersonName, CountryCode, MobileNo, Country, CreatedBy, CreatedOn, AssignedTo, ParentID, SourceName, LeadNo, enquirysource, InitialRemarks ,lastfollowupcreatedby,lastfollowupcreatedon)      
    values( @PersonName, @cc, trim(@no), @c, @ParentId, GETDATE(), @AgentId, @ParentId, @SourceId, @LeadNo, 26, left(@IntialRemarks, 1000),      
     @ParentId,GETDATE() );      
                                
    set @LeadId = SCOPE_IDENTITY();      
 End  
  
    commit transaction;      
  
 If isnull(@LeadId,0) > 0  
 Begin  
  Exec MySMS.dbo.usp_ExecLeadTriggerTasks @LeadId      
       
  declare @CsvID bigint      
                    
      
  insert into MySMS.dbo.leadinteractionhistory( LeadNo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks, AssignedTo, ParentID, CreatedOn, CreatedBy, followupdate,id_lead )       
  select LeadNo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks, AssignedTo, ParentID, CreatedOn, CreatedBy, followupdate,id from MySMS.dbo.userleads(nolock) ul       
  inner join dbo.fn_Split(@LeadId,  ',') cui on ul.ID = cui.[value]      
  select @CsvID=scope_identity()    
  Exec MySMS.dbo.usp_ExecLeadInteractionTriggerTasks @CsvID      
          
  select @entityid = @LeadId, @entity = 'lead'      
      
  --EXEC MySMS.dbo.usp_inserleadinteractionhistory @LeadId;      
  --exec MySMS.dbo.usp_insertdefaultfollowup @AgentId, @LeadId      
  
 End  
           
   end      
         
  end        
 end      
      
   SET Context_Info 0x      
      
   select isnull(@entityid,0) AS EntityId, isnull(@entity,'') AS EntityName;     
    
end  



GO

