   Procedure: [dbo].[usp_create_new_user]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_create_new_user]                               
@M_UserID bigint,                                    
@S_UserID int ,
@login_user nvarchar(50),             
@Pwd varchar(50),          
@FName varchar(50),           
@LName varchar(50),           
@EMail varchar(50),           
@Mobile varchar(50),           
@City varchar(50),           
@state varchar(50),           
@Country varchar(50),           
@Type int,                                    
@Status nchar(10),                                    
@Banner_ID int ,      
@AC_Type varchar(50),--by ak          
@urltype int      --by ak                                                                
as                                    
