@CountryCode nchar(10)                     
                         
as                                                                  
declare @mid bigint,@FromDate datetime,@ToDate datetime,@Validity bigint,@rid bigint,@filtermode int, @current_uid bigint,@pagename varchar(200),@userlogin varchar(25)    
    
set @userlogin= LTRIM(RTRIM(@CountryCode)) + LTRIM(RTRIM(@Mobile ))  
set @Validity=99999                                                    
set @FromDate=getdate()                                                      
set @ToDate=getdate()+@Validity                                                    
                                                            
if exists(select * from User_Detail where email=@EMail)                                                                
begin                                                                
select '','E-Mail ID Already Exists'                                                                
end                                                                
else                                                                
if exists(select * from User_Detail where mobile=LTRIM(RTRIM(@Mobile)) and CountryCode=LTRIM(RTRIM(@CountryCode)))                                                                
begin                                                                
select '','Mobile No. Already Exists'                                                                
end                                                                
else                                                                  
begin                                                                  
--and user_id in(select user_id from user_Detail where user_id=@M_UserID))                                                              
set @mid=(select reseller_id from reseller_Detail where user_id=@S_UserID)                                       
set @filtermode=ISNULL((select filtermode from User_Detail with(nolock) where user_id=@S_UserID),3)                                                               
                                      
                                
if(@S_UserID='335')                                   
begin                                  
set @filtermode='3'                                  
end                                                          
                                               
if (@urltype=0)                                          
begin                                          
   set @AC_Type=(select top(1) userfilter from User_Detail where user_id=@S_UserID)                                          
end                                          
--end                                    
                                                            
insert into User_Detail                                                                  
(M_ID,User_Login,Pwd,FName,LName,EMail,Mobile,City,State,Country,Type,Status,Banner_ID,userfilter,FilterMode,CompnayName,Office_Name,Usercategory,CountryCode)                                                                   
values                                
(@mid,@userlogin,@Pwd,@FName,@LName,@EMail,@Mobile,'','',@Country,@Type,@Status,@Banner_ID,@AC_Type,@filtermode,@CompnayName,'',@Usercategory,LTRIM(RTRIM(@CountryCode)))                                                          
                          
 set @current_uid= (select @@IDENTITY)           
         
     --------------------------------------------Insert MasterDB Add by Anuj------------------------------------------------------------------------------------                
  insert into masterdb (Name,MobileNo,Email,City,State,Country,Pin,Company,UserID,UserCategory,SourceID)                
                       values(@FName,@Mobile,@EMail,'','',@Country,'',@CompnayName,@current_uid,@Usercategory,1)                               
--------------------------------------------Insert MasterDB Complet------------------------------------------------------------------------------------                 
                     
 declare @rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@dfc bigint                                                  
set @rmid=(select m_id from reseller_detail where reseller_id=@mid and user_id=@S_UserID)                                                  
set @ruid=(select user_id from reseller_detail where reseller_id=@mid and user_id=@S_UserID)                                                  
set @rbal=(select top 1 balance from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)                                                  
set @rcid=(select top 1 credit_id from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)                                                 
set @dfc=(select top 1 default_credit from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)                                                  
set @rbal=(select top 1 balance from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)                                                  
declare @uid bigint,@mid1 bigint,@credit bigint,@mid2 bigint,@balance bigint,@credit_id bigint,@bal bigint                                                         
set @mid1=(select top 1 m_id from user_detail where m_id=@mid order by user_id desc)                                                          
set @uid=(select top 1 user_id from user_detail where m_id=@mid order by user_id desc)                                                    
--set @mid2=(select m_id from reseller_detail where reseller_id=@mid1 and user_id=@S_UserID)                                                       
--set @balance=(select top 1 balance from credit_details where m_id=@M_UserID and user_id=@S_UserID)                                                    
----set @credit=(select top 1 credits from credit_details where m_id=@mid1 and user_id=@S_UserID order by credit_id desc )                                                        
--set @credit=(select  top 1 default_credit from credit_details where m_id=@mid2 and user_id=@S_UserID order by credit_id desc )                                                        
--set @credit_id =(select  top 1 credit_id from credit_details where m_id=@mid2 and user_id=@S_UserID order by credit_id desc )                  
insert into SenderID_Detail(M_ID,User_ID,Sender_Name,Status,Type,airtel)              
values(@mid,@uid,'TXTSMS',1,'GSM',1)                
                
                                                      
set @bal= @rbal-@dfc                                          
 if @bal>0                                          
 begin                                               
 update credit_details set balance=@bal where m_id=@rmid and user_id=@ruid and credit_id=@rcid                                                   
 insert into credit_details (m_id,user_id,credits,balance,default_credit,validity,FromDate,ToDate) values(@mid1,@uid,@dfc,@dfc,0,@Validity,@FromDate,@ToDate)                                                  
 end                                          
 else                                          
 begin                      
 insert into credit_details (m_id,user_id,credits,balance,default_credit,validity,FromDate,ToDate) values(@mid1,@uid,0,0,0,@Validity,@FromDate,@ToDate)                                                          
 end                                          
select @current_uid,'User Has Been Created Successfully'                                              
end        
        
        


