CREATE   PROC [dbo].[usp_create_sms_user_crm]      
@M_UserID bigint,                                          
         
@login_user nvarchar(50),                   
                              
@Pwd varchar(50),                
@FName varchar(50),                 
@LName varchar(50),                 
@EMail varchar(50),                 
@Mobile varchar(50),                 
@City varchar(50),                 
@state varchar(50),                 
@Country varchar(50),                 
@Type int,                                          
@Status nchar(10),                                          
@Banner_ID int ,            
@AC_Type varchar(50),              
@urltype int       
as      
begin      
declare @u_id bigint,@FromDate datetime,@ToDate datetime,@Validity bigint,@rid bigint,@filtermode int                           
set @Validity=99999                            
set @FromDate=getdate()                              
set @ToDate=getdate()+@Validity        
if exists(select * from User_Detail where User_Login=@login_user and M_ID=@M_UserID)                                          
begin                                          
select 'User ID Already Exists'                                          
end                                         
else                                        
if exists(select * from User_Detail where email=@EMail)                                        
begin                                        
select 'E-Mail ID Already Exists'                                        
end                                        
else  
if exists(select * from User_Detail where Mobile=@Mobile)                                        
begin  
select 'Mobile Number Already Exists'   
end  
   else                                     
     
begin      
insert into User_Detail                                          
(id,M_ID,User_Login,Pwd,FName,LName,EMail,Mobile,City,State,Country,Type,Status,userfilter)                                           
values                                          
( newid(),@M_UserID,@login_user,@Pwd,@FName,@LName,@EMail,@Mobile,@City,@state,@Country,@Type,@Status,@AC_Type)                                      
      
set @u_id=(select top 1 user_id from User_Detail where m_id=@M_UserID order by user_id desc )      
declare @rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@dfc bigint                              
set @rmid=(select m_id from reseller_detail where reseller_id=@M_UserID and user_id=@u_id)                              
set @ruid=(select user_id from reseller_detail where reseller_id=@M_UserID and user_id=@u_id)                              
set @rbal=(select top 1 balance from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)                              
set @rcid=(select top 1 credit_id from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)                              
set @dfc=(select top 1 default_credit from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)                              
set @rbal=(select top 1 balance from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)                              
declare @uid bigint,@mid1 bigint,@credit bigint,@mid2 bigint,@balance bigint,@credit_id bigint,@bal bigint                                     
set @mid1=(select top 1 m_id from user_detail where m_id=@M_UserID order by user_id desc)                                      
set @uid=(select top 1 user_id from user_detail where m_id=@M_UserID order by user_id desc)                                
set @bal= @rbal-@dfc                      
if @bal>0                      
begin                           
update credit_details set balance=@bal where m_id=@rmid and user_id=@ruid and credit_id=@rcid                               
insert into credit_details (m_id,user_id,credits,balance,default_credit,validity,FromDate,ToDate) values(@mid1,@uid,@dfc,@dfc,0,@Validity,@FromDate,@ToDate)                                      
end                      
else                    
begin                      
insert into credit_details (m_id,user_id,credits,balance,default_credit,validity,FromDate,ToDate) values(@mid1,@uid,0,0,0,@Validity,@FromDate,@ToDate)                                      
end                      
select 'User Has Been Created Successfully'                             
      
      
end      
      
      
      
      
end   



