/* ============================================================
   Procedure: [dbo].[usp_create_sms_user_microsite]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROCEDURE [dbo].[usp_create_sms_user_microsite]          
          
 @M_UserID BIGINT,          
          
 @S_UserID INT , -- frm varchar 19-08-2010          
          
 @login_user NVARCHAR(50),    
  -- All below frm nvarchar          
          
 @Pwd VARCHAR(50),          
          
 @FName VARCHAR(50),          
          
 @LName VARCHAR(50),          
          
 @EMail VARCHAR(50),          
          
 @Mobile VARCHAR(50),          
          
 @City VARCHAR(50),          
          
 @state VARCHAR(50),          
          
 @Country VARCHAR(50),          
          
 @Type INT,          
          
 @Status NCHAR(10),          
          
 @Banner_ID INT ,          
          
 @AC_Type VARCHAR(50), --by ak          
          
 @urltype INT, --by ak          
          
 @CompnayName VARCHAR(200), --by Balram          
          
 @DefaultHTML NTEXT,          
          
 @Newmicrosite VARCHAR(200),          
          
 @NewoficeName VARCHAR(50),          
          
 @AccountType VARCHAR(50),          
          
 @Userfilter VARCHAR(50),        
                 
 @CountryCode nvarchar(10)=null          
          
AS          
          
BEGIN          
          
 DECLARE @mid             BIGINT,          
          
         @FromDate        DATETIME,          
          
         @ToDate          DATETIME,          
          
         @Validity        BIGINT,          
          
         @rid             BIGINT,          
          
         @filtermode      INT,          
          
         @current_uid     BIGINT,          
          
         @pagename        VARCHAR(200),    
          @usercreated bigint=0          
          
           
          
           
          
           
          
           
          
           
          
           
          
           
          
 SET @Validity = 99999                                                            
          
           
          
           
          
           
          
 SET @FromDate = GETDATE()                                                              
          
           
          
           
          
           
          
 SET @ToDate = GETDATE() + @Validity                                                            
          
           
          
           
          
           
          
           
          
           
          
           
          
  IF EXISTS(          
          
        SELECT 1          
          
        FROM   User_Detail          
          
        WHERE  Mobile     = @Mobile          
          
               AND M_ID       = @M_UserID          
          
    )          
          
 BEGIN          
          
     SELECT '',          
          
            'Mobile No. Already Exists, pl sign up with a different mobile no.'          
          
 END          
          
 ELSE IF EXISTS(          
          
        SELECT 1          
          
        FROM   User_Detail          
          
        WHERE  User_Login     = @login_user          
          
               AND M_ID       = @M_UserID          
          
    )          
          
 BEGIN          
          
     SELECT '',          
          
            'Username already taken, pl try a different username'          
          
 END          
          
 ELSE                                                                        
          
           
          
           
          
           
          
 IF EXISTS(          
          
        SELECT *          
          
        FROM   User_Detail          
          
        WHERE  email = @EMail          
          
    )          
          
 BEGIN          
          
     SELECT '',          
          
            'E-Mail ID Already Exists, pl sign up with a different email'          
          
 END          
          
 ELSE                 
          
           
          
           
          
           
          
 IF EXISTS(          
          
        SELECT *          
          
        FROM   User_Detail          
          
        WHERE  email = @EMail          
          
    )          
          
 BEGIN          
          
     SELECT '',          
          
            'E-Mail ID Already Exists, pl sign up with a different email'          
          
 END--if exists(select * from User_Detail where mobile=@Mobile)          
          
              
          
              
          
              
          
    --begin          
          
              
          
              
          
              
          
    --select '','Mobile No. Already Exists'          
          
              
          
              
          
              
          
    --end          
          
 ELSE          
          
 BEGIN          
          
     --and user_id in(select user_id from user_Detail where user_id=@M_UserID))                                                                      
          
               
          
               
          
               
          
     SET @mid = (          
          
             SELECT reseller_id          
          
             FROM   reseller_Detail          
          
             WHERE  USER_ID = @S_UserID          
          
         )          
          
               
          
               
          
               
          
               
          
               
          
               
          
               
          
     SET @filtermode = ISNULL(          
          
             (          
          
                 SELECT filtermode          
          
                 FROM   User_Detail WITH (NOLOCK)          
          
                 WHERE  USER_ID = @S_UserID          
          
             ),          
          
             3          
       
         )           
          
               
          
               
          
               
          
               
          
               
          
               
          
               
          
     --by ak                                         
          
               
          
               
          
               
          
     IF (@S_UserID = '335')          
          
     BEGIN          
          
         SET @filtermode = '10'          
          
     END                                                                  
          
               
          
               
          
               
          
               
          
               
          
               
          
               
          
     IF (@urltype = 0)          
          
     BEGIN          
          
         SET @AC_Type = (          
          
                 SELECT TOP(1) userfilter          
          
                 FROM   User_Detail          
          
                 WHERE  USER_ID = @S_UserID          
          
             )          
          
     END           
          
               
          
               
          
               
          
     --end                                     
          
               
          
               
          
               
          
               
          
               
          
               
          
               
          
     INSERT INTO User_Detail          
          
       (          
          
         M_ID,          
          
         User_Login,          
          
         Pwd,          
          
         FName,          
          
         LName,          
          
         EMail,          
          
         Mobile,          
          
         City,          
          
         STATE,          
          
         Country,          
          
         TYPE,          
          
         STATUS,          
          
         Banner_ID,          
          
         FilterMode,          
          
         CompnayName,          
          
         Office_Name,          
          
         AccountType,          
          
         Userfilter,     
             
         CountryCode          
          
       )          
          
     VALUES          
          
       (          
          
         @mid,          
          
         @login_user,          
          
         @Pwd,          
          
         @FName,          
         
         @LName,          
          
         @EMail,          
          
         @Mobile,          
          
         @City,          
          
         @state,          
          
         @Country,          
          
         @Type,          
          
         @Status,          
          
         @Banner_ID,          
          
         10,          
          
         @CompnayName,          
          
         @NewoficeName,          
          
         @AccountType,          
          
         @Userfilter,    
             
         ISNULL(@CountryCode,'+91')          
          
       )                                                                      
          
       set @usercreated=SCOPE_IDENTITY()     
          
               
          
               
          
               
          
               
          
               
          
               
          
     SET @current_uid = (          
          
    SELECT TOP 1 ud.[User_ID]          
          
             FROM   User_Detail AS ud          
          
             WHERE  ud.User_Login = @login_user          
          
         )                                  
          
               
          
               
          
                
          
               
          
     UPDATE User_Detail          
          
     SET    ParentID = @current_uid ,isadmin=1         
          
     WHERE  [User_ID] = @current_uid              
          
               
          
               
          
               
          
               
          
