/* ============================================================
   Procedure: [dbo].[usp_create_sms_user_microsite080318]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
CREATE   PROCEDURE [dbo].[usp_create_sms_user_microsite080318]            
            
 @M_UserID BIGINT,            
            
 @S_UserID INT , -- frm varchar 19-08-2010            
            
 @login_user NVARCHAR(50),      
  -- All below frm nvarchar            
            
 @Pwd VARCHAR(50),            
            
 @FName VARCHAR(50),            
            
 @LName VARCHAR(50),            
            
 @EMail VARCHAR(50),            
            
 @Mobile VARCHAR(50),            
            
 @City VARCHAR(50),            
            
 @state VARCHAR(50),            
            
 @Country VARCHAR(50),            
            
 @Type INT,            
            
 @Status NCHAR(10),            
            
 @Banner_ID INT ,            
            
 @AC_Type VARCHAR(50), --by ak            
            
 @urltype INT, --by ak            
            
 @CompnayName VARCHAR(200), --by Balram            
            
 @DefaultHTML NTEXT,            
            
 @Newmicrosite VARCHAR(200),            
            
 @NewoficeName VARCHAR(50),            
            
 @AccountType VARCHAR(50),            
            
 @Userfilter VARCHAR(50),          
                   
 @CountryCode nvarchar(10)=null  ,      
 @referrerid bigint=null ,    
 @Source nvarchar(100),    
 @Medium nvarchar(100),    
 @Campaign  nvarchar(100)        
            
AS            
            
BEGIN            
 DECLARE @mid             BIGINT,            
         @FromDate        DATETIME,            
         @ToDate          DATETIME,            
         @Validity        BIGINT,            
         @rid             BIGINT,            
         @filtermode      INT,            
         @current_uid     BIGINT,            
         @pagename        VARCHAR(200),      
          @usercreated bigint=0            
       set @referrerid=isnull((select coalesce(id,0) from Referrer_Details where ReferrerLinkid=@referrerid),0)      
 SET @Validity = 99999                                                              
 SET @FromDate = GETDATE()                                                                
  IF EXISTS(            
        SELECT 1            
        FROM   User_Detail            
        WHERE  Mobile     = @Mobile            
               AND M_ID       = @M_UserID            
    )            
 BEGIN            
     SELECT '',            
            'Mobile No. Already Exists, pl sign up with a different mobile no.'            
 END            
 ELSE IF EXISTS(            
        SELECT 1            
        FROM   User_Detail            
        WHERE  User_Login     = @login_user            
               AND M_ID       = @M_UserID  
    )            
 BEGIN            
     SELECT '',            
            'Username already taken, pl try a different username'            
 END            
 ELSE                                                                          
 IF EXISTS(            
        SELECT *  FROM   User_Detail WHERE  email = @EMail            
    )            
 BEGIN            
     SELECT '',            
            'E-Mail ID Already Exists, pl sign up with a different email'            
 END            
 ELSE                   
 IF EXISTS(            
        SELECT *            
        FROM   User_Detail            
        WHERE  email = @EMail            
    )            
 BEGIN            
     SELECT '',            
            'E-Mail ID Already Exists, pl sign up with a different email'            
 END--if exists(select * from User_Detail where mobile=@Mobile)            
    --begin            
    --select '','Mobile No. Already Exists'            
    --end            
 ELSE            
 BEGIN            
     --and user_id in(select user_id from user_Detail where user_id=@M_UserID))                                                                        
     SET @mid = (            
             SELECT reseller_id            
             FROM   reseller_Detail            
             WHERE  USER_ID = @S_UserID            
         )            
     SET @filtermode = ISNULL(            
             (            
                 SELECT filtermode            
                 FROM   User_Detail WITH (NOLOCK)            
                 WHERE  USER_ID = @S_UserID            
             ),            
             3            
         )             
     --by ak                                           
     IF (@S_UserID = '335')            
     BEGIN            
         SET @filtermode = '10'            
     END                                                                    
     IF (@urltype = 0)            
     BEGIN            
         SET @AC_Type = (            
                 SELECT TOP(1) userfilter            
                 FROM   User_Detail            
                 WHERE  USER_ID = @S_UserID            
             )            
     END             
     --end                                       
      declare @referredcontactid bigint =0          
            
      if isnull(@referrerid,0)<>0      
      begin      
      INSERT INTO ReferredContacts (ReferrerID,Name,EMail,CountryCode,Mobile,Company,Country,Source,SignUpStatus,ConversionStatus,DateCreated,SignUpdate)      
     VALUES (@referrerid,isnull(@FName,'') + isnull(@LName,''),@EMail,ISNULL(@CountryCode,'+91') ,@Mobile,@CompnayName,@Country,'Link',1,0,GETDATE(),GETDATE())                          
select @referredcontactid=SCOPE_IDENTITY()       
       exec usp_UpdateUserActivity @referrerid,'ReferredContact',0      
       exec usp_UpdateUserActivity @referrerid,'ReferredContactSignedUp',0      
       end      
            
     INSERT INTO User_Detail            
       (            
         M_ID, User_Login,Pwd,  FName, LName,EMail, Mobile,  City, STATE, Country,TYPE,   STATUS,Banner_ID,  FilterMode, CompnayName, Office_Name,            
         AccountType, Userfilter, CountryCode , referrerid ,  referredcontactid, Source,  Medium, Campaign    
       )            
            
     VALUES            
            
       (            
         @mid,  @login_user,  @Pwd,@FName,@LName, @EMail,  @Mobile, @City,@state,  @Country, @Type,@Status, @Banner_ID, 10,  @CompnayName, @NewoficeName,            
            
         @AccountType, @Userfilter,ISNULL(@CountryCode,'+91') , @referrerid , @referredcontactid,@Source, @Medium,@Campaign      
       )                                                                        
       set @usercreated=SCOPE_IDENTITY()       
        SET @current_uid = @usercreated    
     --SET @current_uid = (            
     --        SELECT TOP 1 ud.[User_ID]            
     --        FROM   User_Detail AS ud            
     --        WHERE  ud.User_Login = @login_user            
     --    )                                    
            
     UPDATE User_Detail            
     SET    ParentID = @current_uid ,isadmin=1           
     WHERE  [User_ID] = @current_uid                
             
     DECLARE @companyCount        INT,            
             @ClientPageID        BIGINT,            
             @ClientPageNewID     BIGINT,            
             @CompanyNamrUrl      VARCHAR(200),            
             @CopmanyNewName      VARCHAR(100)                                    
            
     IF (@Newmicrosite <> '')            
     BEGIN            
         --set @companyCount =( select COUNT(*) from ClientPageDetail where pagename like '%'+@CompnayName +'%')            
         --set @ClientPageID =( select MAX(id) from ClientPageDetail)                                    
           
         -- if(@ClientPageID is NULL)            
         -- begin            
         -- set @ClientPageNewID = 1            
         -- end     
         -- else            
         -- begin            
         -- set @ClientPageNewID = @ClientPageID +1            
         -- end                                    
         -- if(@companyCount>0)            
         -- begin            
         --  set  @CopmanyNewName = @CompnayName+ CAST(@ClientPageNewID as varchar)            
         -- end            
         -- else            
         -- begin            
         --  set @CopmanyNewName= @CompnayName            
         -- end                                     
         SET @CompanyNamrUrl = 'www.kit19.com/' + @Newmicrosite                                    
         INSERT INTO [ClientPageDetail]            
           (            
             [User_ID],            
             [M_ID],            
             [PageName],            
             HtmlContent   
           )            
            
         VALUES            
           (            
             @current_uid,            
             @mid,            
             @CompanyNamrUrl,            
             @DefaultHTML            
           )            
     END                                    
     DECLARE @rmid         BIGINT,            
            
             @ruid         BIGINT,            
            
             @rbal         BIGINT,            
            
             @rcid         BIGINT,            
            
             @dfc          BIGINT,            
            
             @rbalMail     BIGINT,            
            
             @rcidMail     BIGINT,            
            
     @dfcMail      BIGINT            
         
     SET @rmid = (            
            
             SELECT m_id FROM reseller_detail WHERE  reseller_id     = @mid  AND USER_ID     = @S_UserID            
         )            
     SET @ruid = (            
            
             SELECT USER_ID   FROM   reseller_detail WHERE  reseller_id     = @mid AND USER_ID     = @S_UserID            
            
         )            
          
     SET @rbal = (            
            
             SELECT TOP 1 balance  FROM   credit_details WHERE  m_id  = @rmid  AND USER_ID     = @ruid  ORDER BY  credit_id DESC 
         )            
           
     SET @rbalMail = (            
            
             SELECT TOP 1 balance FROM   MailCreditDetails WHERE  m_id = @rmid AND USER_ID     = @ruid  ORDER BY credit_id DESC 
         )            
         
     SET @rcid = (       
            
             SELECT TOP 1 credit_id  FROM   credit_details  WHERE  m_id  = @rmid AND USER_ID     = @ruid ORDER BY credit_id DESC  
         )            
         
     SET @rcidMail = (            
            
             SELECT TOP 1 credit_id FROM   MailCreditDetails  WHERE  m_id            = @rmid AND USER_ID     = @ruid  ORDER BY  credit_id DESC  
         )            
       
     SET @dfc = (            
            
             SELECT TOP 1 default_credit FROM   credit_details WHERE  m_id    = @rmid  AND USER_ID     = @ruid ORDER BY credit_id DESC 
         )            
        
     SET @dfcMail = (            
            
             SELECT TOP 1 default_credit FROM   MailCreditDetails  WHERE  m_id            = @rmid   AND USER_ID     = @ruid ORDER BY  credit_id DESC 
         )             
        
     SET @rbal = (            
            
             SELECT TOP 1 balance  FROM   credit_details   WHERE  m_id            = @rmid AND USER_ID     = @ruid ORDER BY credit_id DESC 
         )            
          
     SET @rbalMail = (            
            
             SELECT TOP 1 balance FROM   MailCreditDetails   WHERE  m_id            = @rmid AND USER_ID     = @ruid ORDER BY credit_id DESC 
         )            
        
     DECLARE @uid           BIGINT,            
            
             @mid1          BIGINT,            
            
             @credit        BIGINT,            
            
             @mid2          BIGINT,            
            
             @balance       BIGINT,            
            
             @credit_id     BIGINT,            
            
             @bal     BIGINT,            
            
             @balMail       BIGINT            
          
     SET @mid1 = (            
            
             SELECT TOP 1       m_id            
            
             FROM   user_detail            
            
             WHERE  m_id = @mid            
            
             ORDER BY            
                    USER_ID     DESC            
         )            
        
     SET @uid = (            
            
             SELECT TOP 1     USER_ID            
            
             FROM   user_detail            
            
             WHERE  m_id = @mid            
            
             ORDER BY            
            
                    USER_ID     DESC            
            
         )             
          
     --set @mid2=(select m_id from reseller_detail where reseller_id=@mid1 and user_id=@S_UserID)            
         
     --set @balance=(select top 1 balance from credit_details where m_id=@M_UserID and user_id=@S_UserID)            
          
     ----set @credit=(select top 1 credits from credit_details where m_id=@mid1 and user_id=@S_UserID order by credit_id desc )            
     --set @credit=(select  top 1 default_credit from credit_details where m_id=@mid2 and user_id=@S_UserID order by credit_id desc )            
     --set @credit_id =(select  top 1 credit_id from credit_details where m_id=@mid2 and user_id=@S_UserID order by credit_id desc )                                
     INSERT INTO SenderID_Detail            
       (            
         M_ID,USER_ID,  Sender_Name,STATUS,TYPE, airtel 
       )            
            
     VALUES            
       (            
         @mid,  @uid,  'TXTSMS',1,'GSM', 1            
       )                              
     SET @bal = @rbal -@dfc                                                        
     IF @bal > 0            
     BEGIN            
         UPDATE credit_details            
         SET    balance = @bal            
         WHERE  m_id = @rmid            
                AND USER_ID = @ruid            
                AND credit_id = @rcid            
            
         INSERT INTO credit_details            
           (            
             m_id,  USER_ID, credits, balance,default_credit, validity, FromDate, ToDate 
           )            
            
         VALUES 
           (            
             @mid1,  @uid,   @dfc,@dfc,0,@Validity, @FromDate,@ToDate 
           )            
            
     END            
            
     ELSE            
            
     BEGIN            
            
         INSERT INTO credit_details            
           (            
             m_id,    USER_ID,  credits, balance, default_credit, validity, FromDate, ToDate  
           )            
            
         VALUES  
           (   
             @mid1, @uid,  0, 0,    0,@Validity,  @FromDate, @ToDate 
           )            
            
     END             
           
     -- mailCreditDetails            
           
     SET @balMail = @rbalMail -@dfcMail                                                     
           
     IF @balMail > 0            
            
     BEGIN            
            
         UPDATE MailCreditDetails            
            
         SET    balance = @balMail  WHERE  m_id = @rmid   AND USER_ID = @ruid  AND credit_id = @rcidMail            
            
         INSERT INTO MailCreditDetails            
            
           (            
            
             m_id,  USER_ID, credits,balance, default_credit,  validity,  FromDate,  ToDate 
           )            
            
         VALUES    
           (     
             @mid1, @uid,@dfcMail, @dfcMail,  0,  @Validity, @FromDate, @ToDate
           )            
            
     END            
            
     ELSE            
            
     BEGIN            
            
         INSERT INTO MailCreditDetails            
            
          (            
            
             m_id, USER_ID, credits, balance,  default_credit, validity, FromDate, ToDate 
           )            
            
         VALUES 
           (    
             @mid1,  @uid,   0, 0, 0, @Validity, @FromDate, @ToDate
           )            
            
     END                  
            
 exec usp_updateparentsuperresellerid @usercreated           
 SELECT @current_uid,            
            
            'You have registered Successfully, Please Login to continue'            
            
 END      
 if @usercreated<>0 and @M_UserID=10043      
 begin      
 exec usp_sendnewsignupmail @usercreated      
 end            
            
END


GO

