         1                  
                  
       )                                    
                  
                       
                  
                       
                  
                       
                  
                       
                  
                       
                  
                       
                  
                       
                  
                       
                  
                       
                  
                       
                  
                       
                  
     SET @bal = @rbal -@dfc                                                              
                  
                       
                  
                       
                  
                    
                  
     IF @bal > 0                  
                  
     BEGIN                  
                  
         UPDATE credit_details                  
                  
         SET    balance = @bal                  
                  
         WHERE  m_id = @rmid                  
                  
                AND USER_ID = @ruid                  
                  
                AND credit_id = @rcid                  
                  
                        
                  
                           
                  
                           
                  
                           
                  
                           
              
                           
                  
                           
                  
         INSERT INTO credit_details                  
                  
           (                  
                  
             m_id,                  
                  
             USER_ID,                  
                  
             credits,                  
                  
             balance,                  
                  
             default_credit,                  
                  
             validity,                  
                  
             FromDate,                  
                  
             ToDate                  
                  
           )                  
                  
         VALUES                  
                  
           (                  
                  
             @mid1,                  
                  
             @uid,                  
                  
             @dfc,                  
                  
             @dfc,                  
                  
             0,                  
                  
             @Validity,                  
                  
             @FromDate,                  
                  
             @ToDate                  
                  
           )                  
                  
     END                  
                  
     ELSE                  
                  
     BEGIN                                
         INSERT INTO credit_details                  
                  
           (                  
                  
             m_id,                  
                  
             USER_ID,                  
                  
             credits,                  
                  
             balance,                  
                  
             default_credit,                  
                  
             validity,                  
                  
           FromDate,                  
                  
        ToDate                  
                  
           )                  
                  
         VALUES                  
                  
           (                  
                  
             @mid1,                  
                  
             @uid,                  
                  
             0,                  
                  
             0,                  
                  
             0,                  
                  
             @Validity,                  
                  
             @FromDate,                  
                  
             @ToDate                  
                  
           )                  
                  
     END                   
                  
                       
                  
                       
                  
           
                  
     -- mailCreditDetails                  
                  
                       
                  
                       
                  
                       
                  
     SET @balMail = @rbalMail -@dfcMail                                                           
                  
                       
                  
                       
                  
                       
                  
     IF @balMail > 0                  
                  
     BEGIN                  
                  
         UPDATE MailCreditDetails                  
                  
         SET    balance = @balMail                  
           
         WHERE  m_id = @rmid                  
                  
                AND USER_ID = @ruid                  
                  
                AND credit_id = @rcidMail                  
                  
                           
                  
                           
                  
                           
                  
                           
                  
                           
                  
                           
                  
                           
                  
   INSERT INTO MailCreditDetails                  
                  
           (                  
                  
