 DECLARE @M_Userid bigint,@Pwd VARCHAR(50), @Mid BIGINT,@Midval BIGINT, @Fromdate DATETIME, @Todate DATETIME, @Validity BIGINT, @Rid BIGINT, @Filtermode INT, @Current_Uid BIGINT, @Pagename VARCHAR(200),        
 @Usercreated BIGINT= 0, @U_Mail nvarchar(200),@P_Mail nvarchar(200),@Partner_Mail nvarchar(200), @NewUserName nvarchar(200), @strMessage nvarchar(max), @batchid BIGINT, @batchid_email BIGINT; 
 DECLARE @NewUserID BIGINT, @Templatedatas nvarchar(max),@DomainName nvarchar(max), @Theme NVARCHAR(MAX),@LogoUrl NVARCHAR(MAX),@Sign NVARCHAR(MAX),@CompanyName NVARCHAR(MAX); 
 declare  @Parentid bigint = 0       
 SET @Referrerid = ISNULL( ( SELECT COALESCE(id, 0) FROM Referrer_Details (nolock) WHERE ReferrerLinkid = @Referrerid ), 0);   
 

 set @Parentid = dbo.ufn_getUserParentID(@S_Userid)

 print concat('@ParentID: ',@ParentID,'')

 SET @DomainName = (select domain from reseller_detail (nolock) where user_id=@S_Userid); 
 set @CompanyName=(select CompnayName from User_Detail (nolock) where user_id=@S_Userid);
  SET @Midval = ( SELECT reseller_id FROM reseller_Detail (nolock) WHERE USER_ID = @S_Userid ); 
 IF EXISTS (
    SELECT 1
    FROM tbl_pt_CustomizationMetadata WITH (NOLOCK)
    WHERE JSON_VALUE(JsonData, '$.USERID') = CAST(@S_Userid AS NVARCHAR)
)
BEGIN
    -- Fetch and assign data to variables
    SELECT 
       
        @LogoUrl = COALESCE(JSON_VALUE(JsonData, '$.LogoUrl'), ''),
        @Theme = COALESCE(JSON_VALUE(JsonData, '$.Theme'), '')
       
    FROM tbl_pt_CustomizationMetadata (nolock)
    WHERE JSON_VALUE(JsonData, '$.USERID') = CAST(@S_Userid AS NVARCHAR);
END
       SELECT 
       @Partner_Mail = COALESCE(
        NULLIF(JSON_VALUE(jsonEmailData, '$.Email'), ''), 
        'noreply@email19.in'
    ),
		@Sign=COALESCE(JSON_VALUE(jsonEmailData, '$.Signature'),'')
       FROM tbl_pt_CustomizationMetadata with(nolock)
    WHERE JSON_VALUE(jsonEmailData, '$.USERID') = CAST(@S_Userid AS NVARCHAR);
	DECLARE @Partnerurl NVARCHAR(MAX);
SET @Partnerurl = @DomainName;
	
	IF @LogoUrl IS NOT NULL AND @LogoUrl <> ''
BEGIN
    SET @LogoUrl = CONCAT('https://kit19.com/assets/custom/Partner/resource/',@Midval, '/', @LogoUrl);
END
ELSE
BEGIN
    -- Optionally, set a default path or leave it as NULL if @LogoUrl is not provided
    SET @LogoUrl = NULL;
END
DECLARE @ThemePage NVARCHAR(MAX);

SET @ThemePage = CASE 
    WHEN @Theme = 'Theme 1' THEN 'AppLogin1.aspx'
    WHEN @Theme = 'Theme 2' THEN 'AppLogin2.aspx'
    WHEN @Theme = 'Theme 3' THEN 'AppLogin3.aspx'
    ELSE 'AppLogin.aspx'
END;

-- Concatenate the domain name and theme page
SET @DomainName = CONCAT(@DomainName, '/', @ThemePage);
	print concat('@@DomainName --',@DomainName,'@@@CompanyName --',@CompanyName,'@LogoUrl --',@LogoUrl,'@Partnerurl',@Partnerurl,'@Theme  --',@Theme,'@Sign  --',@Sign,'@Midval--',@Midval)
	
 SET @Validity = 99999;        
        
 SET @Fromdate = GETDATE();        
        
 SET @Todate = GETDATE() + @Validity; 
 
 SET @M_Userid = ( SELECT reseller_id        
     FROM reseller_Detail (nolock)       
     WHERE USER_ID = dbo.ufn_getUserParentId(@S_Userid));


print concat('@M_Userid=>',@M_Userid)


 SET @Pwd = RIGHT('0000' + CAST(CAST(ABS(CHECKSUM(NEWID())) % 10000 AS INT) AS VARCHAR(4)), 4);
        
 IF EXISTS ( SELECT 1 FROM User_Detail (nolock) WHERE Mobile = @Mobile AND M_ID = @M_Userid AND CountryCode = @Countrycode )        
 BEGIN        
  SELECT '', 'Mobile No. Already Exists, pl sign up with a different mobile no.' as Msg, -1 as Id; 
  RETURN;
 END;        
 ELSE        
 BEGIN        
  IF EXISTS ( SELECT 1 FROM User_Detail (nolock) WHERE User_Login = @Login_User )        
  BEGIN        
   SELECT '', 'Username already taken, plz try a different username' as Msg, -2 as Id;  
   RETURN;
  END;        
  ELSE        
  BEGIN        
   IF EXISTS ( SELECT * FROM User_Detail (nolock) WHERE email = @Email )        
   BEGIN        
    SELECT '', 'E-Mail ID Already Exists, plz sign up with a different email' as Msg, -3 as Id; 
	RETURN;
   END;        
   ELSE        
   BEGIN        
    IF EXISTS ( SELECT * FROM User_Detail (nolock) WHERE email = @Email )        
    BEGIN        
     SELECT '', 'E-Mail ID Already Exists, pl sign up with a different email' as Msg, -3 as Id; 
	 RETURN;
    END        
    --if exists(select * from User_Detail where mobile=@Mobile)        
    --begin        
    --select '','Mobile No. Already Exists'        
    --end ;        
    ELSE        
    BEGIN        
     --and user_id in(select user_id from user_Detail where user_id=@M_UserID))        
     SET @Mid = ( SELECT reseller_id        
