 @state VARCHAR(50),      
      
 @Country VARCHAR(50),      
      
 @Type INT,      
      
 @Status NCHAR(10),      
      
 @Banner_ID INT ,      
      
 @AC_Type VARCHAR(50), --by ak      
      
