 @CompnayName VARCHAR(200), --by Balram      
      
 @DefaultHTML NTEXT,      
      
 @Newmicrosite VARCHAR(200),      
      
 @NewoficeName VARCHAR(50),      
      
 @AccountType VARCHAR(50),      
      
 @Userfilter VARCHAR(50)      
      
AS      
      
BEGIN      
      
 DECLARE @mid             BIGINT,      
      
         @FromDate        DATETIME,      
      
         @ToDate          DATETIME,      
      
         @Validity        BIGINT,      
      
         @rid             BIGINT,      
      
         @filtermode      INT,      
      
         @current_uid     BIGINT,      
      
         @pagename        VARCHAR(200),
          @usercreated bigint=0      
      
       
      
       
      
       
      
       
      
       
      
       
      
       
      
 SET @Validity = 99999                                                        
      
       
      
       
      
       
      
