     SELECT '',      
      
            'Mobile No. Already Exists'      
      
 END      
      
 ELSE IF EXISTS(      
      
        SELECT 1      
      
        FROM   User_Detail      
      
        WHERE  User_Login     = @login_user      
      
               AND M_ID       = @M_UserID      
      
    )      
      
