         SET @filtermode = '10'      
      
     END                                                              
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     IF (@urltype = 0)      
      
     BEGIN      
      
         SET @AC_Type = (      
      
                 SELECT TOP(1) userfilter      
      
                 FROM   User_Detail      
      
                 WHERE  USER_ID = @S_UserID      
      
             )      
      
     END       
      
           
      
           
      
           
      
     --end                                 
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     INSERT INTO User_Detail      
      
