         @Pwd,      
      
         @FName,      
      
         @LName,      
      
         @EMail,      
      
         @Mobile,      
      
         @City,      
      
         @state,      
      
         @Country,      
      
         @Type,      
      
         @Status,      
      
         @Banner_ID,      
      
         10,      
      
         @CompnayName,      
      
         @NewoficeName,      
      
         @AccountType,      
      
         @Userfilter      
      
       )                                                                  
      
       set @usercreated=SCOPE_IDENTITY() 
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @current_uid = (      
      
             SELECT TOP 1 ud.[User_ID]      
      
             FROM   User_Detail AS ud      
      
             WHERE  ud.User_Login = @login_user      
      
         )                              
      
           
      
           
      
            
      
           
      
     UPDATE User_Detail      
      
     SET    ParentID = @current_uid ,isadmin=1     
      
     WHERE  [User_ID] = @current_uid          
      
           
      
           
      
           
      
           
      
     DECLARE @companyCount        INT,      
      
             @ClientPageID        BIGINT,      
      
             @ClientPageNewID     BIGINT,      
      
             @CompanyNamrUrl      VARCHAR(200),      
      
             @CopmanyNewName      VARCHAR(100)                              
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     IF (@Newmicrosite <> '')      
      
     BEGIN      
      
         --set @companyCount =( select COUNT(*) from ClientPageDetail where pagename like '%'+@CompnayName +'%')      
      
               
      
               
      
               
      
         --set @ClientPageID =( select MAX(id) from ClientPageDetail)                              
      
               
      
               
      
               
      
               
      
               
      
               
      
               
      
         -- if(@ClientPageID is NULL)      
      
               
      
               
      
               
      
         -- begin      
      
               
      
               
      
               
      
         -- set @ClientPageNewID = 1      
      
               
      
               
      
               
      
