         -- else      
      
               
      
               
      
               
      
         -- begin      
      
               
      
               
      
               
      
         -- set @ClientPageNewID = @ClientPageID +1      
      
               
      
               
      
               
      
         -- end                              
      
               
      
               
      
               
      
               
      
               
      
               
      
               
      
         -- if(@companyCount>0)      
      
               
      
               
      
               
      
         -- begin      
      
               
      
               
      
               
      
         --  set  @CopmanyNewName = @CompnayName+ CAST(@ClientPageNewID as varchar)      
      
               
      
               
      
               
      
         -- end      
      
               
      
               
      
               
      
         -- else      
      
               
      
         
      
               
      
         -- begin      
      
               
      
               
      
               
      
         --  set @CopmanyNewName= @CompnayName      
      
               
      
               
      
               
      
         -- end                               
      
               
      
               
      
               
      
               
      
               
      
               
      
               
      
         SET @CompanyNamrUrl = 'www.kit19.com/' + @Newmicrosite                              
      
               
      
               
      
               
      
               
      
               
      
               
      
               
      
         INSERT INTO [ClientPageDetail]      
      
           (      
      
             [User_ID],      
      
             [M_ID],      
      
             [PageName],      
      
             HtmlContent      
      
           )      
      
         VALUES      
      
           (      
      
             @current_uid,      
      
             @mid,      
      
             @CompanyNamrUrl,      
      
             @DefaultHTML      
      
           )      
      
     END                              
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     DECLARE @rmid         BIGINT,      
      
             @ruid         BIGINT,      
      
             @rbal         BIGINT,      
      
             @rcid         BIGINT,      
      
             @dfc          BIGINT,      
      
             @rbalMail     BIGINT,      
      
             @rcidMail     BIGINT,      
      
     @dfcMail      BIGINT      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @rmid = (      
      
             SELECT m_id      
      
             FROM   reseller_detail      
      
             WHERE  reseller_id     = @mid      
      
                    AND USER_ID     = @S_UserID      
      
