                    AND USER_ID     = @S_UserID      
      
         )      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @rbal = (      
      
             SELECT TOP 1 balance      
      
             FROM   credit_details      
      
             WHERE  m_id            = @rmid      
      
                    AND USER_ID     = @ruid      
      
             ORDER BY      
      
           credit_id DESC      
      
         )      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @rbalMail = (      
      
             SELECT TOP 1 balance      
      
             FROM   MailCreditDetails      
      
             WHERE  m_id            = @rmid      
      
                    AND USER_ID     = @ruid      
      
             ORDER BY      
      
                    credit_id DESC      
      
         )      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @rcid = (      
      
             SELECT TOP 1 credit_id      
      
             FROM   credit_details      
      
             WHERE  m_id            = @rmid      
      
                    AND USER_ID     = @ruid      
      
             ORDER BY      
      
                    credit_id DESC      
      
         )      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @rcidMail = (      
      
             SELECT TOP 1 credit_id      
      
             FROM   MailCreditDetails      
      
             WHERE  m_id            = @rmid      
      
                    AND USER_ID     = @ruid      
      
             ORDER BY      
      
                    credit_id DESC      
      
         )      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @dfc = (      
      
             SELECT TOP 1 default_credit      
      
             FROM   credit_details      
      
             WHERE  m_id    = @rmid      
      
                    AND USER_ID     = @ruid      
      
             ORDER BY      
      
                    credit_id DESC      
      
         )      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @dfcMail = (      
      
             SELECT TOP 1 default_credit      
      
             FROM   MailCreditDetails      
      
             WHERE  m_id            = @rmid      
      
                    AND USER_ID     = @ruid      
      
             ORDER BY      
      
                    credit_id DESC      
      
         )       
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @rbal = (      
      
