             WHERE  m_id            = @rmid      
      
                    AND USER_ID     = @ruid      
      
             ORDER BY      
      
                    credit_id DESC      
      
         )      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @rbalMail = (      
      
             SELECT TOP 1 balance      
      
             FROM   MailCreditDetails      
      
             WHERE  m_id            = @rmid      
      
                    AND USER_ID     = @ruid      
      
             ORDER BY      
      
                    credit_id DESC      
      
         )      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     DECLARE @uid           BIGINT,      
      
             @mid1          BIGINT,      
      
             @credit        BIGINT,      
      
             @mid2          BIGINT,      
      
             @balance       BIGINT,      
      
             @credit_id     BIGINT,      
      
             @bal           BIGINT,      
      
             @balMail       BIGINT      
      
           
      
           
      
       
      
           
      
           
      
           
      
           
      
     SET @mid1 = (      
      
             SELECT TOP 1       m_id      
      
             FROM   user_detail      
      
             WHERE  m_id = @mid      
      
             ORDER BY      
      
                    USER_ID     DESC      
      
         )      
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @uid = (      
      
             SELECT TOP 1     USER_ID      
      
             FROM   user_detail      
      
             WHERE  m_id = @mid      
      
             ORDER BY      
      
                    USER_ID     DESC      
      
         )       
      
           
      
           
      
           
      
     --set @mid2=(select m_id from reseller_detail where reseller_id=@mid1 and user_id=@S_UserID)      
      
           
      
           
      
           
      
     --set @balance=(select top 1 balance from credit_details where m_id=@M_UserID and user_id=@S_UserID)      
      
           
      
           
      
           
      
     ----set @credit=(select top 1 credits from credit_details where m_id=@mid1 and user_id=@S_UserID order by credit_id desc )      
      
           
      
           
      
           
      
     --set @credit=(select  top 1 default_credit from credit_details where m_id=@mid2 and user_id=@S_UserID order by credit_id desc )      
      
           
      
           
      
           
      
     --set @credit_id =(select  top 1 credit_id from credit_details where m_id=@mid2 and user_id=@S_UserID order by credit_id desc )                          
      
           
      
           
      
           
      
     INSERT INTO SenderID_Detail      
      
       (      
      
         M_ID,      
      
         USER_ID,      
      
         Sender_Name,      
      
         STATUS,      
      
         TYPE,      
      
         airtel      
      
       )      
      
     VALUES      
      
       (      
      
         @mid,      
      
         @uid,      
      
       'TXTSMS',      
      
         1,      
      
         'GSM',      
      
         1      
      
       )                        
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SET @bal = @rbal -@dfc                                                  
      
           
      
           
      
        
      
     IF @bal > 0      
      
     BEGIN      
      
         UPDATE credit_details      
      
         SET    balance = @bal      
      
         WHERE  m_id = @rmid      
      
                AND USER_ID = @ruid      
      
                AND credit_id = @rcid      
      
               
      
               
      
               
      
               
      
               
      
               
      
               
      
         INSERT INTO credit_details      
      
           (      
      
             m_id,      
      
             USER_ID,      
      
             credits,      
      
             balance,      
      
             default_credit,      
      
             validity,      
      
             FromDate,      
      
             ToDate      
      
           )      
      
         VALUES      
      
           (      
      
             @mid1,      
      
             @uid,      
      
             @dfc,      
      
             @dfc,      
      
             0,      
      
             @Validity,      
      
             @FromDate,      
      
             @ToDate      
      
           )      
      
     END      
      
     ELSE      
      
     BEGIN      
      
         INSERT INTO credit_details      
      
           (      
      
             m_id,      
      
             USER_ID,      
      
             credits,      
      
             balance,      
      
             default_credit,      
      
             validity,      
      
             FromDate,      
      
        ToDate      
      
           )      
      
         VALUES      
      
           (      
      
             @mid1,      
      
             @uid,      
      
             0,      
      
             0,      
      
             0,      
      
             @Validity,      
      
             @FromDate,      
      
             @ToDate      
      
           )      
      
     END       
      
           
      
           
      
           
      
     -- mailCreditDetails      
      
           
      
           
      
           
      
     SET @balMail = @rbalMail -@dfcMail                                               
      
           
      
           
      
           
      
     IF @balMail > 0      
      
     BEGIN      
      
         UPDATE MailCreditDetails      
      
         SET    balance = @balMail      
      
         WHERE  m_id = @rmid      
      
                AND USER_ID = @ruid      
      
                AND credit_id = @rcidMail      
      
               
      
               
      
               
      
               
      
               
      
               
      
               
      
         INSERT INTO MailCreditDetails      
      
           (      
      
             m_id,      
      
             USER_ID,      
      
             credits,      
      
             balance,      
      
             default_credit,      
      
             validity,      
      
             FromDate,      
      
             ToDate      
      
           )      
      
         VALUES      
      
           (      
      
             @mid1,      
      
             @uid,      
      
             @dfcMail,      
      
             @dfcMail,      
      
             0,      
      
             @Validity,      
      
             @FromDate,      
      
             @ToDate      
      
           )      
      
     END      
      
     ELSE      
      
     BEGIN      
      
         INSERT INTO MailCreditDetails      
      
          (      
      
             m_id,      
      
             USER_ID,      
      
             credits,      
      
             balance,      
      
             default_credit,      
      
             validity,      
      
             FromDate,      
      
             ToDate      
      
           )      
      
         VALUES      
      
           (      
      
             @mid1,      
      
             @uid,      
      
             0,      
      
             0,      
      
             0,      
      
             @Validity,      
      
             @FromDate,      
      
             @ToDate      
      
           )      
      
     END            
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
           
      
     SELECT @current_uid,      
      
            'User Has Been Created Successfully'      
      
 END
 if @usercreated<>0 and @M_UserID=10043
 begin
 exec usp_sendnewsignupmail @usercreated
 end      
      
END


