CREATE   PROCEDURE [dbo].[usp_create_sms_user12NEW2]                  
 @M_UserID BIGINT,                  
 @S_UserID INT , -- frm varchar 19-08-2010                  
 @login_user NVARCHAR(50),                   
                    
  -- All below frm nvarchar                  
 @Pwd VARCHAR(50),                  
 @FName VARCHAR(50),                  
 @LName VARCHAR(50),                  
 @EMail VARCHAR(50),                  
 @Mobile VARCHAR(50),                  
 @City VARCHAR(50),                  
 @state VARCHAR(50),                  
 @Country VARCHAR(50),                  
 @Type INT,                  
 @Status NCHAR(10),                  
 @Banner_ID INT ,                  
 @AC_Type VARCHAR(50),                  
 @urltype INT,                  
 @CompnayName VARCHAR(200), --by Balram                  
 @DefaultHTML NTEXT,                  
 @Newmicrosite VARCHAR(200),                  
 @NewoficeName VARCHAR(50),                  
 @IsInternalUser BIT,                  
 @IsAdmin BIT,          
 @CountryCode nvarchar(20),          
 @Timezone nvarchar(200)          
           
                   
AS                  
BEGIN                  
 DECLARE @mid             BIGINT,                  
         @FromDate        DATETIME,                  
         @ToDate          DATETIME,                  
         @Validity        BIGINT,                  
         @rid             BIGINT,                  
         @filtermode      INT,                  
         @current_uid     BIGINT,                  
         @pagename        VARCHAR(200)                                                                  
                   
                   
                   
 SET @Validity = 99999                                              
                   
 SET @FromDate = GETDATE()                                                
                   
 SET @ToDate = GETDATE() + @Validity                                              
                   
                   
                   
 IF EXISTS(                  
        SELECT 'x'                  
        FROM   User_Detail                  
        WHERE  User_Login     = @login_user                  
               AND M_ID       = @M_UserID                  
    )                  
 BEGIN                  
     SELECT '',                  
            'User ID Already Exists'                  
 END                  
 ELSE                                                          
                   
 IF EXISTS(                  
        SELECT 'x'                  
        FROM   User_Detail                  
        WHERE  email = @EMail                  
    )                  
 BEGIN                  
     SELECT '',                  
            'E-Mail ID Already Exists'                  
 END                  
 ELSE                                                          
                   
 IF EXISTS(                  
