       --added by vivek                
         exec  [Price_DeductfromIntCredit] 1,@ParentID,'users'              
              
                         
          exec usp_updateparentsuperresellerid @current_uid          
            
    --exec  Usp_CreateMySQLUser @current_uid                  
                       
     IF @IsInternalUser = 0                  
