  WHERE USER_LOGIN = @login_user AND M_ID = @M_UserID            
     --WHERE  [User_ID] = @current_uid          COMMENTED BY TEJINDER SINGH 01082019            
                       
     DECLARE @companyCount        INT,                  
             @ClientPageID        BIGINT,                  
             @ClientPageNewID     BIGINT,                  
             @CompanyNamrUrl      VARCHAR(200),                  
