     DECLARE @rmid         BIGINT,                  
             @ruid         BIGINT,                  
             @rbal         BIGINT,                  
             @rcid         BIGINT,                  
             @dfc          BIGINT,                  
             @rbalMail     BIGINT,                  
             @rcidMail     BIGINT,                  
             @dfcMail      BIGINT                                                
                       
 SET @rmid = (                  
             SELECT TOP 1 m_id                  
