             WHERE  m_id            = @rmid                  
                    AND USER_ID     = @ruid                  
             ORDER BY                  
                    credit_id DESC                  
         )                                                
                       
     SET @rbalMail = (                  
             SELECT TOP 1 balance                  
             FROM   MailCreditDetails            
             WHERE  m_id            = @rmid                  
                    AND USER_ID     = @ruid                  
             ORDER BY                  
                    credit_id DESC                  
         )                                                
                       
                       
     DECLARE @uid           BIGINT,                  
             @mid1          BIGINT,                  
             @credit        BIGINT,                  
             @mid2          BIGINT,                  
             @balance       BIGINT,                  
             @credit_id     BIGINT,                  
             @bal           BIGINT,                  
             @balMail       BIGINT                                                      
                       
     SET @mid1 = (                  
