             validity,                  
             FromDate,                  
             ToDate --,    
      --  CreatedBy                 
     )                  
  VALUES                  
           (                  
             @mid1,                  
             @uid,                  
             @dfc,                  
             @dfc,                  
             0,                  
             @Validity,                  
             @FromDate,                  
             @ToDate --,    
        --@uid                 
           )                               
                           
         INSERT INTO credit_details                  
           (                  
             m_id,                  
             fromuser_id,                  
             USER_ID,                  
             debits,                  
             credits,                  
             balance,                  
             default_credit,                  
 validity,                  
             FromDate,                  
             ToDate  --,    
      --CreatedBy                  
           )                  
         VALUES                  
           (                  
             @rmid,                  
             @uid,                  
             @ruid,                  
             @dfc,                  
             0,                  
             @bal,                  
             @dfc,                  
             @Validity,                  
             @FromDate,                  
             @ToDate--,    
    --@uid                  
           )                  
     END                  
     ELSE                  
