    @FromDate,                  
             @ToDate--,    
    
   -- @uid                   
           )                               
                           
         INSERT INTO MailCreditDetails                  
           (                  
             m_id,                  
             fromuser_id,                  
             USER_ID,                  
             debits,                  
             credits,                  
        balance,                  
