             0,                  
             0,                  
             0,                  
             @Validity,                  
             @FromDate,                  
             @ToDate--,    
    --@uid                  
           )                  
     END                     
                       
    exec  Usp_CreateMySQLUser @current_uid       
                    
     SELECT @current_uid,                  
            'User Has Been Created Successfully'                  


declare @ed nvarchar(200)=cast(@Login_User as nvarchar(50))+' signed up'
Exec UspSaveuserActivity_withid @current_uid,@current_uid,@ParentID,@ed,'User signs up','User_detail',@current_uid 
 END                  
