--------Modified By Abhishek Makkar ----------- Time: 8/17/2017 10:45:37 PM            
CREATE   PROCEDURE [dbo].[usp_create_sms_user12NEW21]        
 @M_UserID BIGINT,        
 @S_UserID BIGINT , -- frm varchar 19-08-2010        
 @login_user NVARCHAR(50),         
          
  -- All below frm nvarchar        
 @Pwd VARCHAR(50),        
 @FName VARCHAR(50),        
 @LName VARCHAR(50),        
 @EMail VARCHAR(50),        
 @Mobile VARCHAR(50),        
 @City VARCHAR(50),        
 @state VARCHAR(50),        
 @Country VARCHAR(50),        
 @Type INT,        
 @Status NCHAR(10),        
 @Banner_ID INT ,        
 @AC_Type VARCHAR(50),        
 @urltype INT,        
 @CompnayName VARCHAR(200), --by Balram        
 @DefaultHTML NTEXT,        
 @Newmicrosite VARCHAR(200),        
 @NewoficeName VARCHAR(50),        
 @IsInternalUser BIT,        
 @IsAdmin BIT        
AS        
BEGIN        
 DECLARE @mid             BIGINT,        
         @FromDate        DATETIME,        
         @ToDate          DATETIME,        
         @Validity        BIGINT,        
         @rid             BIGINT,        
         @filtermode      INT,        
         @current_uid     BIGINT,        
         @pagename        VARCHAR(200),      
         @hasVirtualcredits bit,      
         @parentsuperresellerid bigint                                                        
         
         
         
 SET @Validity = 99999                                    
         
 SET @FromDate = GETDATE()                                      
         
 SET @ToDate = GETDATE() + @Validity                                    
         
         
         
 IF EXISTS(        
        SELECT 'x'        
        FROM   User_Detail        
        WHERE  User_Login     = @login_user        
               AND M_ID       = @M_UserID        
    )        
 BEGIN        
     SELECT '',        
            'User ID Already Exists'        
 END        
 ELSE                                                
         
 IF EXISTS(        
        SELECT 'x'        
        FROM   User_Detail        
        WHERE  email = @EMail        
    )        
 BEGIN        
     SELECT '',        
            'E-Mail ID Already Exists'        
 END        
 ELSE                                                
         
 IF EXISTS(        
        SELECT 'x'        
        FROM   User_Detail        
        WHERE  mobile = @Mobile        
    )        
 BEGIN        
     SELECT '',        
            'Mobile No. Already Exists'        
 END        
 ELSE        
 BEGIN        
     --and user_id in(select user_id from user_Detail where user_id=@M_UserID))                                              
             
     SET @mid = (        
             SELECT m_id        
             FROM   user_Detail        
             WHERE  USER_ID =@S_UserID        
         )                       
             
     SElect @filtermode = ISNULL(filtermode,3),@hasVirtualcredits =hasvirtualcredits,      
         @parentsuperresellerid =@parentsuperresellerid FROM   User_Detail WITH (NOLOCK)        
          WHERE  USER_ID = @S_UserID           
             
             
             
     --by ak                          
             
     IF (@urltype = 0)        
     BEGIN        
         SET @AC_Type = (        
                 SELECT TOP(1) userfilter        
                 FROM   User_Detail        
                 WHERE  USER_ID = @S_UserID        
             )        
     END         
             
     --end                
             
     DECLARE @ParentID BIGINT = @s_userid  
             
     INSERT INTO User_Detail        
       (        
         M_ID,        
         User_Login,        
         Pwd,        
         FName,        
         LName,        
         EMail,        
         Mobile,        
         City,        
         STATE,        
         Country,        
         TYPE,        
         STATUS,        
         Banner_ID,        
         userfilter,        
         FilterMode,        
         IsInternalUser,        
         IsAdmin,        
         CompnayName ,      
         HasVirtualCredits,      
         ParentSuperResellerId            )        
     VALUES        
       (        
         @mid,        
         @login_user,        
         @Pwd,        
         @FName,        
         @LName,        
         @EMail,        
         @Mobile,        
         @City,        
         @state,        
         @Country,        
         @Type,        
         @Status,        
         @Banner_ID,        
         @AC_Type,        
         @filtermode,        
         @IsInternalUser,        
         @IsAdmin,        
         @CompnayName,      
         @HasVirtualCredits,      
         @ParentSuperResellerId        
       )                                            
             
             
             
     SET @current_uid = (        
             SELECT @@IDENTITY        
         )        
             
     IF @IsInternalUser = 0        
     BEGIN        
         SET @ParentID = @current_uid        
     END        
             
     UPDATE User_Detail        
     SET    ParentID = @ParentID        
     WHERE  [User_ID] = @current_uid            
             
     DECLARE @companyCount        INT,        
             @ClientPageID        BIGINT,        
             @ClientPageNewID     BIGINT,        
             @CompanyNamrUrl      VARCHAR(200),        
             @CopmanyNewName      VARCHAR(100)                                
             
             
             
     IF (@Newmicrosite <> '')        
     BEGIN        
         --set @companyCount =( select COUNT(*) from ClientPageDetail where pagename like '%'+@CompnayName +'%')                                
                 
         --set @ClientPageID =( select MAX(id) from ClientPageDetail)                                
                 
                 
                 
         -- if(@ClientPageID is NULL)                                
                 
         -- begin                                
                 
         -- set @ClientPageNewID = 1                                
                 
         -- end                        
                 
         -- else                                
                 
         -- begin                                
                 
         -- set @ClientPageNewID = @ClientPageID +1                                
                 
         -- end                                
                 
                 
                 
         -- if(@companyCount>0)                                
                 
         -- begin                                
                 
         --  set  @CopmanyNewName = @CompnayName+ CAST(@ClientPageNewID as varchar)                                
                 
         -- end                                
                 
         -- else                                
                 
         -- begin                                
                 
         --  set @CopmanyNewName= @CompnayName                                
                 
         -- end                                 
                 
                 
                 
         SET @CompanyNamrUrl = 'www.sms19.com/' + @Newmicrosite                                
                 
                 
                 
         INSERT INTO [ClientPageDetail]        
           (        
             [User_ID],        
             [M_ID],        
             [PageName],        
             HtmlContent        
           )        
         VALUES        
           (        
             @current_uid,        
             @mid,        
             @CompanyNamrUrl,        
             @DefaultHTML        
           )        
     END                                               
             
             
             
     DECLARE @rmid         BIGINT,        
             @ruid         BIGINT,        
             @rbal         BIGINT,        
             @rcid         BIGINT,        
             @dfc          BIGINT,        
             @rbalMail     BIGINT,        
             @rcidMail     BIGINT,        
             @dfcMail      BIGINT                                      
             
     SET @rmid = @mid                              
             
     SET @ruid = @S_UserID        
                                        
             
     SET @rbal = (        
             SELECT TOP 1 balance        
             FROM   credit_details        
             WHERE  m_id            = @rmid        
                    AND USER_ID     = @ruid        
             ORDER BY        
                    credit_id DESC        
         )                                      
             
     SET @rbalMail = (        
             SELECT TOP 1 balance        
             FROM   MailCreditDetails        
             WHERE  m_id            = @rmid        
                    AND USER_ID     = @ruid        
             ORDER BY        
                    credit_id DESC        
         )                                      
             
             
             
     SET @rcid = (        
             SELECT TOP 1 credit_id        
             FROM   credit_details        
             WHERE  m_id            = @rmid        
                    AND USER_ID     = @ruid        
             ORDER BY        
                    credit_id DESC        
         )                                      
             
     SET @rcidMail = (        
             SELECT TOP 1 credit_id        
             FROM   MailCreditDetails        
             WHERE  m_id            = @rmid        
                    AND USER_ID     = @ruid        
             ORDER BY        
                    credit_id DESC        
         )                                      
             
             
     SET @dfc = (        
             SELECT TOP 1 default_credit        
             FROM   credit_details        
             WHERE  m_id            = @rmid        
                    AND USER_ID     = @ruid        
             ORDER BY        
                    credit_id DESC        
         )                                      
             
     SET @dfcMail = (        
             SELECT TOP 1 default_credit        
             FROM   MailCreditDetails        
             WHERE  m_id            = @rmid        
                    AND USER_ID     = @ruid        
             ORDER BY        
                    credit_id DESC        
         )               
             
     SET @rbal = (        
             SELECT TOP 1 balance        
             FROM   credit_details        
             WHERE  m_id            = @rmid        
                    AND USER_ID     = @ruid        
             ORDER BY        
                    credit_id DESC        
         )                                      
             
     SET @rbalMail = (        
             SELECT TOP 1 balance        
             FROM   MailCreditDetails        
             WHERE  m_id            = @rmid        
                    AND USER_ID     = @ruid        
             ORDER BY        
                    credit_id DESC        
         )                                      
             
             
     DECLARE @uid           BIGINT,        
             @mid1          BIGINT,        
             @credit        BIGINT,        
             @mid2          BIGINT,        
             @balance       BIGINT,        
             @credit_id     BIGINT,        
             @bal           BIGINT,        
             @balMail       BIGINT                                            
             
     SET @mid1 = (        
             SELECT TOP 1       m_id        
             FROM   user_detail        
             WHERE  m_id = @mid        
             ORDER BY        
                    USER_ID     DESC        
         )                                              
             
     SET @uid = (        
             SELECT TOP 1       USER_ID        
             FROM   user_detail        
             WHERE  m_id = @mid        
             ORDER BY        
                    USER_ID     DESC        
         )                      
     --set @mid2=(select m_id from reseller_detail where reseller_id=@mid1 and user_id=@S_UserID)                                           
          
     --set @balance=(select top 1 balance from credit_details where m_id=@M_UserID and user_id=@S_UserID)                                        
             
     ----set @credit=(select top 1 credits from credit_details where m_id=@mid1 and user_id=@S_UserID order by credit_id desc )                                            
             
     --set @credit=(select  top 1 default_credit from credit_details where m_id=@mid2 and user_id=@S_UserID order by credit_id desc )                                            
             
     --set @credit_id =(select  top 1 credit_id from credit_details where m_id=@mid2 and user_id=@S_UserID order by credit_id desc )                   
             
     INSERT INTO SenderID_Detail        
       (        
         M_ID,        
         USER_ID,        
         Sender_Name,        
         STATUS,        
         TYPE,        
         airtel        
       )        
     VALUES        
       (        
         @mid,        
         @uid,        
         'TXTSMS',        
         1,        
         'GSM',        
         1        
       )                
             
             
             
     SET @bal = @rbal -@dfc                              
             
     IF @bal >= 0        
     BEGIN        
         --update credit_details set balance=@bal where m_id=@rmid and user_id=@ruid and credit_id=@rcid                                       
                 
         INSERT INTO credit_details        
           (        
             m_id,        
             USER_ID,        
             credits,        
             balance,        
             default_credit,        
             validity,        
             FromDate,        
             ToDate        
           )        
         VALUES        
           (        
             @mid1,        
             @uid,        
             @dfc,        
             @dfc,        
             0,        
             @Validity,        
             @FromDate,        
             @ToDate        
           )                     
                 
         INSERT INTO credit_details        
           (        
             m_id,        
             fromuser_id,        
             USER_ID,        
             debits,        
             credits,        
             balance,        
             default_credit,        
             validity,        
             FromDate,        
             ToDate        
           )        
         VALUES        
           (        
             @rmid,        
             @uid,        
             @ruid,        
             @dfc,        
             0,        
             @bal,        
             @dfc,        
             @Validity,        
             @FromDate,        
             @ToDate        
