             USER_ID,        
             credits,        
             balance,        
             default_credit,        
             validity,        
             FromDate,        
             ToDate        
           )        
         VALUES        
           (        
             @mid1,        
             @uid,        
             0,        
             0,        
             0,        
             @Validity,        
             @FromDate,        
             @ToDate        
           )        
     END         
             
     -- Mailcredit details        
             
     SET @balMail = @rbalMail -@dfcMail                              
             
     IF @balMail >= 0        
     BEGIN        
