         VALUES        
           (        
             @rmid,        
             @uid,        
             @ruid,        
             @dfcMail,        
             0,        
             @balMail,        
             @dfcMail,        
             @Validity,        
             @FromDate,        
             @ToDate        
           )        
     END        
     ELSE        
     BEGIN        
         INSERT INTO MailCreditDetails        
           (        
             m_id,        
             USER_ID,        
             credits,        
             balance,        
             default_credit,        
             validity,        
             FromDate,        
     ToDate        
           )        
         VALUES        
           (        
             @mid1,        
             @uid,        
             0,        
             0,        
             0,        
             @Validity,        
             @FromDate,        
             @ToDate        
           )        
     END           
             
             
     SELECT @current_uid,        
            'User Has Been Created Successfully'        
 END        
END   
  
  


GO

