		(@P_SNO, @@SPID , 0 , '-1' , 'Mobile No Already Exists' )

 END      
 ELSE      
 BEGIN      
  --and user_id in(select user_id from user_Detail where user_id=@M_UserID))                      

  SET @mid = (      
    SELECT CASE       
      WHEN isnull(type, 0) <> 0      
       THEN (      
