CREATE   PROC [DBO].[USP_CREATE_USER_FROM_API]        
@LOGIN_USER VARCHAR(50),      
@FNAME VARCHAR(150),                                  
@PWD VARCHAR(50),                
@EMAIL VARCHAR(50),                 
@MOBILE VARCHAR(50)                 
AS                                          
DECLARE @FROMDATE DATETIME,@TODATE DATETIME,@VALIDITY BIGINT,@UID BIGINT      
SET @VALIDITY=99999                            
SET @FROMDATE=GETDATE()                              
SET @TODATE=GETDATE()+@VALIDITY                            
--IF EXISTS(SELECT * FROM USER_DETAIL WHERE USER_LOGIN=@LOGIN_USER AND M_ID=10043)                                          
--BEGIN                                          
--SELECT 'USER ID ALREADY EXISTS'                                          
--END                                         
--ELSE                                        
IF EXISTS(SELECT * FROM USER_DETAIL with(nolock) WHERE EMAIL=@EMAIL)                                        
BEGIN                                        
SELECT 'E-MAIL ID ALREADY EXISTS'                                        
END                                        
ELSE                                        
IF EXISTS(SELECT * FROM USER_DETAIL with(nolock) WHERE MOBILE=@MOBILE)                                        
BEGIN                                        
SELECT 'MOBILE NO. ALREADY EXISTS'                                        
END                                        
ELSE                                          
BEGIN                                          
INSERT INTO USER_DETAIL                                          
(M_ID,USER_LOGIN,PWD,FNAME,EMAIL,MOBILE,COUNTRY,TYPE,STATUS,USERFILTER,FILTERMODE)                                           
VALUES                                          
(10043,@LOGIN_USER,@PWD,@FNAME,@EMAIL,@MOBILE,'India',0,1,'MTIX_PRO',10)                                      
BEGIN     
select @UID = User_ID from User_Detail with(nolock) where User_Login=@LOGIN_USER       print(@UID)                     
 --Declare @PID bigint = ( select top 1 ParentID from User_Detail with(nolock) where User_ID = @UID ) 
INSERT INTO CREDIT_DETAILS (M_ID,USER_ID,CREDITS,BALANCE,DEFAULT_CREDIT,VALIDITY,FROMDATE,TODATE,CD_CreatedBy) VALUES(10043,@UID,200,200,0,@VALIDITY,@FROMDATE,@TODATE,@UID)                                      
END                      
SELECT 'USER HAS BEEN CREATED SUCCESSFULLY'                             
END 


