CREATE   PROC [dbo].[usp_create_user_leads]       
@cname varchar(200),      
@FirstName  varchar(200),      
@LastName varchar(200),      
@Email varchar(200),      
@Mobile varchar(20),      
@Address varchar(200),      
@City varchar(200),      
@Zip  varchar(20),    
@Remarks varchar(500),  
@Source tinyint      
as      
INSERT INTO [ClientLeadDetails]      
           ([cname]      
           ,[FirstName]      
           ,[LastName]      
           ,[Email]      
           ,[Mobile]      
           ,[Address]      
           ,[City]      
           ,[Zip]    
           ,[Remarks]   
           ,[Source]   
           )      
     VALUES      
           (@cname,@FirstName,@LastName,@Email,@Mobile,@Address,@City,@Zip,@Remarks,@Source)      
declare @PageName varchar(200), @SelectMaxLeads bigint,@SelectMaxLeadsNew bigint           
set @PageName='www.kit19.com/'+@cname         
set @SelectMaxLeads = (select MAX(SiteLeads) from ClientPageDetail where PageName=@PageName)        
 if(@SelectMaxLeads is NULL)              
  begin              
  set @SelectMaxLeadsNew = 1              
  end               
  else              
  begin              
  set @SelectMaxLeadsNew = @SelectMaxLeads +1              
  end                
update ClientPageDetail set SiteLeads = @SelectMaxLeadsNew where PageName= @PageName          
select @SelectMaxLeadsNew   


