  create table #temp(leadno bigint,mobile varchar(100),email varchar(100))                                
  insert into #temp(leadno,mobile,email)                  
  select leadno,Mobile,Email from          
  (select leadno,(cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)) as mobile,isnull(NULLIF(EmailID,''),0) as email from UserLeads (nolock)                 
  where ParentID=@parentid          
  union          
  select leadno,(cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)) as mobile,isnull(NULLIF(EmailID1,''),0) as email from UserLeads  (nolock)               
  where ParentID=@parentid                                
  union          
  select leadno,(cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)) as mobile,isnull(NULLIF(EmailID2,''),0) as email from UserLeads (nolock)                 
  where ParentID=@parentid                                
) A          
                                
          
                                
                
                             
  BEGIN                              
  declare @leadn bigint = 0                
                        
  if exists(select 1 from #temp where Mobile=cast(isnull(@Mobile,1) as nvarchar))                               
  BEGIN                               
  select top 1 @leadn = leadno from #temp where Mobile=cast(isnull(@Mobile,1) as nvarchar)                                
  END                 
  end                
                
  if (@leadn=0)                 
  begin                               
  if exists(select 1 from #temp where email=cast(isnull(NULLIF(@Email,''),1) as nvarchar) )                                
  BEGIN                     
  select top 1 @leadn = leadno from #temp where email=cast(isnull(NULLIF(@Email,''),1) as nvarchar)                     END                  
  end                
                
