/* ============================================================
   Procedure: [dbo].[usp_create_user_leads3]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
                    
CREATE   PROC [dbo].[usp_create_user_leads3]                     
                    
@cname varchar(200),                    
@FirstName  varchar(200),                    
@LastName varchar(200),                    
@Email varchar(200),                    
@Mobile varchar(20),                    
@Address varchar(200),                    
@City varchar(200),                    
@Zip  varchar(20),                  
@Remarks varchar(500),                
@Source varchar(20)  
as                    
                   
                    
declare @PageName varchar(200), @SelectMaxLeads bigint,@SelectMaxLeadsNew bigint                         
set @PageName='www.kit19.com/'+@cname                       
              
declare @ClientPageID bigint, @userid int, @officename varchar(50), @officeid smallint,@sourcetype varchar(20),        
@clientname varchar(100)                 
set @ClientPageID = (select Id from ClientPageDetail where PageName=@PageName)        
set @userid= ( select User_ID from ClientPageDetail where PageName=@PageName)        
set @officename= ( select Office_Name from User_Detail  where User_ID = @userid)         
set @officeid= ( select Office_ID from [CRM19].[dbo].[M_Office] where Office_Name = @officename)        
set @clientname = @FirstName + ' ' +@LastName        
        
if(@Source<>'')              
begin            
 set @sourcetype=(select Marketing_Source from MarketingSource where Id =  @Source)        
end        
else        
begin        
set @sourcetype=(select 'Others')      
end        
              
if(@Source<>'')              
begin              
      INSERT INTO [ClientLeadDetails1]                    
           ([cname]                    
           ,[FirstName]                    
           ,[LastName]                    
           ,[Email]                    
           ,[Mobile]                    
           ,[Address]                    
           ,[City]                    
           ,[Zip]                  
           ,[Remarks]                 
           ,[Source] 
           ,[Date]              
           )                    
     VALUES                    
           (@cname,@FirstName,@LastName,@Email,@Mobile,@Address,@City,@Zip,@Remarks,@Source,getdate())               
  set @SelectMaxLeads = (select MAX(SiteLeads) from ClientSiteUrl where ClientPageiD=@ClientPageID and Ptype= @Source)                      
   if(@SelectMaxLeads is NULL)                            
    begin                            
   set @SelectMaxLeadsNew = 1                            
    end                             
    else                            
    begin                            
   set @SelectMaxLeadsNew = @SelectMaxLeads +1                            
    end                              
  update ClientSiteUrl set SiteLeads = @SelectMaxLeadsNew where ClientPageiD=@ClientPageID and Ptype= @Source                      
end              
 else              
 begin              
       INSERT INTO [ClientLeadDetails1]                    
           ([cname]                    
           ,[FirstName]                    
           ,[LastName]                    
           ,[Email]                    
           ,[Mobile]                    
           ,[Address]                    
           ,[City]                    
           ,[Zip]                  
           ,[Remarks]                 
           ,[Source]   
           ,[Date]              
           )                    
     VALUES                    
           (@cname,@FirstName,@LastName,@Email,@Mobile,@Address,@City,@Zip,@Remarks,'0',GETDATE())           
  if exists(select * from [ClientSiteUrl] where ClientPageiD=@ClientPageID and Ptype = '0')                                                                  
  begin                                                                  
    set @SelectMaxLeads = (select MAX(SiteLeads) from ClientSiteUrl where ClientPageiD=@ClientPageID and Ptype= '0')                      
    if(@SelectMaxLeads is NULL)                            
  begin                       
   set @SelectMaxLeadsNew = 1                            
  end                             
  else                            
  begin     
   set @SelectMaxLeadsNew = @SelectMaxLeads +1                            
  end                              
  update ClientSiteUrl set SiteLeads = @SelectMaxLeadsNew where ClientPageiD=@ClientPageID and Ptype= '0'                      
  end                     
  else                
  begin     
     
   if(@ClientPageID <> NULL)   
   begin                                                                         
   INSERT INTO [ClientSiteUrl]                  
     ([ClientPageiD],[Ptype],SiteLeads)                  
     VALUES                  
     (@ClientPageID ,'0',1)                 
  end  
    
    
  end               
               
 end                 
         
 --EXECUTE  [CRM19].[dbo].[usp_create_user_leads] @officeid,@clientname,@sourcetype,@Mobile,@Email,@Address,@City,@Zip,@Remarks        
select @SelectMaxLeadsNew   


GO

