 @cname VARCHAR(200),                          
 @FirstName VARCHAR(200),                          
 @LastName VARCHAR(200),                          
 @Email VARCHAR(200),                          
 @Mobile VARCHAR(20),                          
 @Address VARCHAR(200),                          
 @City VARCHAR(200),                          
 @Zip VARCHAR(20),                          
 @Remarks VARCHAR(500),                          
 @Source VARCHAR(20) ,                          
 @CampaignName VARCHAR(200) = NULL,                  
 @countryCode VARCHAR(50),  
 @ContactType nvarchar(200)                          
AS                          
BEGIN             
 declare @isleadcreated int=0,@cid bigint                         
    set @Source=coalesce(nullif(@source,''),'0')                           
    set @CampaignName=coalesce(@campaignname,0)                          
    select * into #clientpagedetail from ClientPageDetail where PageName= 'www.kit19.com/' + @cname                           
      
 DECLARE @PageName              VARCHAR(200),                          
         @SelectMaxLeads        BIGINT,                          
         @SelectMaxLeadsNew     BIGINT                            
                           
 SET @PageName = 'www.kit19.com/' + @cname                           
                           
 DECLARE @ClientPageID     BIGINT,                          
         @userid           INT,                          
         @officename       VARCHAR(50),                          
         @officeid         SMALLINT,                          
         @sourcetype       VARCHAR(20),                          
         @clientname       VARCHAR(100)                           
 SET @ClientPageID = (                          
         SELECT Id                          
         FROM   #ClientPageDetail                          
     )                             
 SET @userid = (                          
         SELECT USER_ID                          
         FROM   #ClientPageDetail                          
     )                              
 SET @officename = (                          
         SELECT Office_Name                          
         FROM   User_Detail                          
         WHERE  USER_ID = @userid                          
     )                                
                            
 SET @officeid = (                          
         1                           
                                   
         --SELECT Office_ID                            
                                   
         --FROM   [CRM19].[dbo].[M_Office]                            
                                   
         --WHERE  Office_Name = @officename                          
     )                                
                           
 SET @clientname = @FirstName + ' ' + @LastName                                          
                           
 IF (@Source <> '0')                          
 BEGIN                          
     SET @sourcetype = (                          
             SELECT Marketing_Source                          
             FROM   MarketingSource                          
             WHERE  Id = @Source                          
         )                          
 END                          
 ELSE                          
 BEGIN                          
     SET @sourcetype = (                          
             SELECT 'Others'                          
         )                          
 END                                          
                           
                           
 --declare @leadid bigint             
 declare @cldid bigint                          
 INSERT INTO [ClientLeadDetails]                          
       (                          
         [cname],                          
         [FirstName],                          
         [LastName],                 
         [Email],                          
         [Mobile],                          
         [Address],                          
         [City],                          
         [Zip],              
         [Remarks],                          
         [Source],                          
         IsCallMicrosite,                          
         DateCreated,               
         CampaignName,                  
         CountryCode,  
   ContactType                          
       )                          
     VALUES                          
    (                          
         @cname,                          
         @FirstName,                          
         @LastName,                          
         @Email,                          
         @Mobile,                
         @Address,                          
         @City,                          
         @Zip,                          
         @Remarks,                          
         @Source,                          
         1,                          
         GETDATE(),                          
      @CampaignName,                  
      @CountryCode,  
      @ContactType                       
       )                                      
     set @cldid=SCOPE_IDENTITY()                          
                               
     DECLARE @parentid BIGINT = (                          
                 SELECT TOP 1 ud.ParentID                          
                 FROM   User_Detail ud                          
                 WHERE  ud.[User_ID] = @userid                          
             )                            
                               
if @Email is not null or (@Mobile is not null and @countryCode is not null)                         
begin                          
--if (dbo.fnAppMobileCheck(ISNULL(nullif(@mobile,''),'9999999999'))=1 and dbo.fnAppEmailCheck(ISNULL(nullif(@email,''),'abc@abc.com'))=1) or (@countryCode <> '+91')                            
--begin                          
DECLARE @sourceid bigint,@MediumID BIGINT                           
select @sourceid=sourceid,@MediumID=MediumID                           
from #ClientPageDetail c                           
--select u.Applicabilty,us.Source,c.* from ClientPageDetail c join usercampaignmaster u on u.ID=c.SmsCampaignId join usersearchlist us on u.Applicabilty=us.ID join usersourcesettings s on us.source=s.SourceID                           
--where c.Id=2150                          
                       
declare @leadn bigint = 0                                     
-------------------------                      
if exists(select 1 from Userleads_Mobile_Email(nolock) where parentid=@parentid and (email=@Email or (countrycode=@countrycode       
and mobile=@Mobile)))      
begin      
select top 1 @leadn=leadno from Userleads_Mobile_Email(nolock) where parentid=@parentid and (email=@Email or (countrycode=@countrycode       
and mobile=@Mobile)) order by leadno desc      
end      
/* Commented below code and used above a better way to get leadno      
create table #temp(leadno bigint,countrycode nvarchar(10),mobile varchar(100),email varchar(100))                                      
  insert into #temp(leadno,countrycode,mobile,email)                                    
  select leadno,countrycode,Mobile,Email from                
  (select leadno,cast(isnull(nullif(countrycode,''),0) as nvarchar) countrycode,(cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)) as mobile,isnull(NULLIF(EmailID,''),0) as email from UserLeads (nolock)                       
  where ParentID=@parentid                
  union                
  select leadno,cast(isnull(nullif(countrycode1,''),0) as nvarchar) countrycode,(cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)) as mobile,isnull(NULLIF(EmailID1,''),0) as email from UserLeads  (nolock)                     
  where ParentID=@parentid                                      
  union                
  select leadno,cast(isnull(nullif(countrycode2,''),0) as nvarchar) countrycode,(cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)) as mobile,isnull(NULLIF(EmailID2,''),0) as email from UserLeads (nolock)                       
  where ParentID=@parentid                                      
) A                
                                  
  set @leadn =isnull((select top 1 leadno from #temp where (Mobile=cast(isnull(@Mobile,1) as nvarchar) and CountryCode=cast(isnull(@countrycode,1) as nvarchar))                
  or email=cast(isnull(NULLIF(@Email,''),1) as nvarchar)),0)                                     
*/      
      
                      
declare @enqid bigint                          
INSERT INTO UserEnquiry       
       ( PersonName,                          
         CountryCode,                          
         MobileNo,                          
         EmailID,                          
         City,                          
         [State],                      
         PinCode,                          
         ResidentialAddress,                          
         SourceName,                          
         MediumName,                          
         CampaignName,                          
         InitialRemarks,                          
         ParentID,                          
         CreatedDate,                          
    CreatedBy ,LeadNo,enquirysource                          
       )                          
     VALUES                          
       (                          
         @FirstName + ' ' + @LastName,                          
         @countryCode,                          
         @Mobile,                          
         @Email,                          
         @City,                          
         @City,                          
         @Zip,                          
         @Address,                     
         @Sourceid,                          
         @MediumID,                          
         @CampaignName,                          
         @Remarks,                          
         @parentid,                          
         GETDATE(),                          
         @userid, @leadn,(select id from enquirysources(nolock) where sourcename='Landing page')                          
       )                   
  set @enqid = SCOPE_IDENTITY();                         
  update ClientLeadDetails set AddedToEnquiry=1 where id=@cldid                          
                    
  insert into ParsedEnquiries(RawEnquiryId,enquiryid,EnquirySource,Createddate,Parentid)      
  select @cldid,@enqid,'Landing Page',getdate(),@parentid      
                             
                           
 declare @AutoLeadDistribution bit                            
                             
SELECT @AutoLeadDistribution = AutoLeadDistribution FROM   CRMCampaignSettings                              
 WHERE  UserID = @ParentID                              
                              
 if (@AutoLeadDistribution = 1  and isnull(@leadn,0)=0)                            
 begin                         
 declare @pricingresult int =1                    
 exec @pricingresult= SP_Price_CheckUserPricingPlan @ParentID,26                    
                 
if(@pricingresult >0)                    
  Begin                
                
  Declare @LeadID_Act bigint = 0                
                     
  DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo)                                               
  FROM   UserLeads(nolock) WHERE  ParentID = @ParentID),0)+1                            
                          
  Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,                            
  OfficeAddress,AssignedTo,SourceName,MediumName,CampaignName,ParentID,                            
  Remarks,CreatedOn,CreatedBy)--,FollowUpStatus,NextStatusDate,FollowupDate)                                  
  select @leadno,@FirstName + ' ' + @LastName,@Mobile,@Email,@City,@Zip,@countryCode,@Address,                            
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')                             
  ORDER BY NEWID()),@Sourceid,@MediumID,@CampaignName,@ParentID,@Remarks,GETDATE(),@ParentID--,1,GETDATE(),GETDATE()                              
                          
             
   set @isleadcreated=1                 
                       
  --set @leadid=SCOPE_IDENTITY()                            
                          
  update UserEnquiry  set LeadNo=@LeadNo, IsOpen= case when @isleadcreated=1 then 0 else 1 end where EnquiryID=@enqid                          
                          
  insert into  tbl_MergeLeadsEnquiry( EnquiryNo ,LeadNo,IsOpen)           
  values (@enqid,@Leadno,case when @isleadcreated=1 then 0 else 1 end)                 
                
 exec usp_ims_UpgradeEnquiryToLead @enqid    
   /*Start  Lead filled landing page */              
                
                 
              
              
   /* End Leadfilled landing page*/              
              
              
              
                               
end    --end of pricing condition                  
end    
if isnull(@leadn,0)>0    
begin    
 Begin try              
  set @LeadID_Act=(select id from userleads(nolock) where leadno=@leadn and parentid=@parentid )    
  Declare @UserID_LDACTV bigint = @ParentID              
  Declare @ParentID_LDACTV bigint = @ParentID              
               
  Declare @LeadID_LDACTV bigint = @LeadID_Act              
  Declare @Cname_LDACTV nvarchar(500) = @cname               
              
              
  create table #tblEventDescrb              
   (              
     EVNT_Description nvarchar(max)               
   )              
              
  if( isnull(@LeadID_LDACTV,0) > 0)              
   Begin              
                  
   insert into #tblEventDescrb              
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead filled landing page',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null              
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null              
   ,null,null,null,null,null,null,null,null,              
   0,0,0,null,null,null,0,null,@Cname_LDACTV,null,0,null,null              
                   
   declare @evntMessage nvarchar(max) = ''               
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb              
               
   if(@evntMessage <> '')              
   Begin              
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage, 'Lead filled landing page' ,'ClientLeadDetails',@cldid             
   end              
              
              
   End                
              
   end try              
                 
   Begin catch              
                 
    exec usp_InsertErrorInfo                   
              
   End catch              
              
    IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence                
   Begin                
        DROP TABLE #tblEventDescrb                
   End                
     
end    
else                    
begin       
declare @enqevntMessage nvarchar(1000)=(select 'Enquiry no.: '+cast(@enqid as nvarchar) +' ,Name: '+isnull(@clientname,'no name')+' filled landing page '+@cname)      
exec UspSaveenquiryActivity_withid @enqid,@parentid,@parentid,@enqevntMessage, 'Enquiry filled landing page' ,'ClientLeadDetails',@cldid                         
--select 1                   
-- exec SendMail @ParentID,'LeadExceeded'                    
end                                    
end                         
                           
IF not EXISTS(                          
            SELECT 1                          
            FROM   [ClientSiteUrl]             
            WHERE  ClientPageiD     = @ClientPageID                          
                   AND Ptype        = @source                          
        )                          
BEGIN                          
IF (@ClientPageID <> NULL)                         
         BEGIN                          
             INSERT INTO [ClientSiteUrl]                          
               (                          
                 [ClientPageiD],                          
                 [Ptype],                          
                 SiteLeads                          
               )                          
             VALUES                          
               (                          
                 @ClientPageID,                          
                 @source,                          
                 1                       
               )                          
         END                          
end             
                          
SET @SelectMaxLeads = isnull((                          
             SELECT MAX(SiteLeads)                          
             FROM   ClientSiteUrl                          
             WHERE  ClientPageiD     = @ClientPageID                          
                    AND Ptype        = @Source                          
         ),1)                                
                               
         SET @SelectMaxLeadsNew = @SelectMaxLeads + 1                          
                     
                          
        UPDATE ClientSiteUrl                          
     SET    SiteLeads        = @SelectMaxLeadsNew                          
     WHERE  ClientPageiD     = @ClientPageID                          
            AND Ptype        = @Source                          
END          
      
--select top 10 * from [ClientLeadDetails] order by id desc


GO

/* ============================================================
   Procedure: [dbo].[usp_create_user_leadsNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--------Modified By Abhishek Makkar ----------- Time: 8/26/2017 4:58:55 PM------/
CREATE   PROCEDURE [dbo].[usp_create_user_leadsNew]
	@cname VARCHAR(200),
	@FirstName VARCHAR(200),
	@LastName VARCHAR(200),
	@Email VARCHAR(200),
	@Mobile VARCHAR(20),
	@Address VARCHAR(200),
	@City VARCHAR(200),
	@Zip VARCHAR(20),
	@Remarks VARCHAR(500),
	@Source VARCHAR(20) ,
	@CampaignName VARCHAR(200) = NULL
AS
BEGIN
    set @Source=coalesce(nullif(@source,''),'0') 
    select * into #clientpagedetail from ClientPageDetail where PageName= 'www.kit19.com/' + @cname 
	
	DECLARE @PageName              VARCHAR(200),
	        @SelectMaxLeads        BIGINT,
	        @SelectMaxLeadsNew     BIGINT  
	
	SET @PageName = 'www.kit19.com/' + @cname 
	
	DECLARE @ClientPageID     BIGINT,
	        @userid           INT,
	        @officename       VARCHAR(50),
	        @officeid         SMALLINT,
	        @sourcetype       VARCHAR(20),
	        @clientname       VARCHAR(100) 
	SET @ClientPageID = (
	        SELECT Id
	        FROM   #ClientPageDetail
	    )   
	SET @userid = (
	        SELECT USER_ID
	        FROM   #ClientPageDetail
	    )    
	SET @officename = (
	        SELECT Office_Name
	        FROM   User_Detail
	        WHERE  USER_ID = @userid
	    )      
		
	SET @officeid = (
	        1 
	        
	        --SELECT Office_ID  
	        
	        --FROM   [CRM19].[dbo].[M_Office]  
	        
	        --WHERE  Office_Name = @officename
	    )      
	
	SET @clientname = @FirstName + ' ' + @LastName                
	
	IF (@Source <> '0')
	BEGIN
	    SET @sourcetype = (
	            SELECT Marketing_Source
	            FROM   MarketingSource
	            WHERE  Id = @Source
	        )
	END
	ELSE
	BEGIN
	    SET @sourcetype = (
	            SELECT 'Others'
	        )
	END                
	
	INSERT INTO [ClientLeadDetails]
	      (
	        [cname],
	        [FirstName],
	        [LastName],
	        [Email],
	        [Mobile],
	        [Address],
	        [City],
	        [Zip],
	        [Remarks],
	        [Source],
	        IsCallMicrosite,
	        DateCreated,
	        CampaignName
	      )
	    VALUES
	      (
	        @cname,
	        @FirstName,
	        @LastName,
	        @Email,
	        @Mobile,
	        @Address,
	        @City,
	        @Zip,
	        @Remarks,
	        @Source,
	        1,
	        GETDATE(),
	        @CampaignName
	      )            
	    
	    DECLARE @parentid BIGINT = (
	                SELECT TOP 1 ud.ParentID
	                FROM   User_Detail ud
	                WHERE  ud.[User_ID] = @userid
	            )  
	    
if @Email is not null and @Mobile is not null
begin
if dbo.fnAppEmailCheck(ISNULL(nullif(@mobile,''),'9999999999'))=1 and dbo.fnAppMobileCheck(ISNULL(nullif(@email,''),'abc@abc.com'))=1 
begin
DECLARE @sourceid bigint,@MediumID BIGINT 
select @sourceid=s.sourceid,@MediumID=m.MediumID from usersourcesettings s join usersearchlist us on us.source=s.SourceID and us.ParentID=s.UserID join usercampaignmaster u on u.parentid=us.parentID and u.Applicabilty=us.ID join ClientPageDetail c on u.ID=c.SmsCampaignId 
join usermediumsettings m on m.MediumID=us.Medium
--select u.Applicabilty,us.Source,c.* from ClientPageDetail c join usercampaignmaster u on u.ID=c.SmsCampaignId join usersearchlist us on u.Applicabilty=us.ID join usersourcesettings s on us.source=s.SourceID 
--where c.Id=2150

INSERT INTO UserEnquiry
	      ( PersonName,
	        MobileNo,
	        EmailID,
	        City,
	        [State],
	        PinCode,
	        ResidentialAddress,
	        SourceName,
	        MediumName,
	        CampaignName,
	        InitialRemarks,
	        ParentID,
	        CreatedDate,
	        CreatedBy
	      )
	    VALUES
	      (
	        @FirstName + ' ' + @LastName,
	        @Mobile,
	        @Email,
	        @City,
	        @City,
	        @Zip,
	        @Address,
	        @Sourceid,
	        @MediumID,
	        @CampaignName,
	        @Remarks,
	        @parentid,
	        GETDATE(),
	        @userid
	      ) 
	      
end
end 
IF not EXISTS(
	           SELECT *
	           FROM   [ClientSiteUrl]
	           WHERE  ClientPageiD     = @ClientPageID
	                  AND Ptype        = @source
	       )
BEGIN
	        IF (@ClientPageID <> NULL)
	        BEGIN
	            INSERT INTO [ClientSiteUrl]
	              (
	                [ClientPageiD],
	                [Ptype],
	                SiteLeads
	              )
	            VALUES
	              (
	                @ClientPageID,
	                @source,
	                1
	              )
	        END
end

SET @SelectMaxLeads = (
	            SELECT MAX(SiteLeads)
	            FROM   ClientSiteUrl
	            WHERE  ClientPageiD     = @ClientPageID
	                   AND Ptype        = @Source
	        )      
	    
	    IF (@SelectMaxLeads IS NULL)
	    BEGIN
	        SET @SelectMaxLeadsNew = 1
	    END
	    ELSE
	    BEGIN
	        SET @SelectMaxLeadsNew = @SelectMaxLeads + 1
	    END                                      

        UPDATE ClientSiteUrl
	    SET    SiteLeads        = @SelectMaxLeadsNew
	    WHERE  ClientPageiD     = @ClientPageID
	           AND Ptype        = @Source
	END



GO

