/* ============================================================
   Procedure: [dbo].[Usp_CreateBraodCastGroup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

   
  
  
CREATE   PROC Usp_CreateBraodCastGroup  
@User_ID bigint ,  
@Group_Name nvarchar(500),  
@Group_JID nvarchar(200)  
AS  
BEGIN  
 If not exists(select group_id from group_detail where user_id=@User_ID and group_name=@Group_Name and  Group_JID=@Group_JID )  
  BEGIN  
     declare @mid nvarchar(50)=''  
     select  @mid=m_id from user_detail  where user_id=@User_ID  
     insert into group_detail(M_ID, User_ID, Group_Name, DateCreated,Group_JID)  
     values(@mid,@User_ID,@Group_Name,getutcdate(),@Group_JID)  
  END  
  
select   * from group_detail where user_id=@User_ID and group_name=@Group_Name and  Group_JID=@Group_JID  
  
END


GO

/* ============================================================
   Procedure: [dbo].[usp_createcalllog]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_createcalllog 'tbl_voip_endpointInteraction','id',38506,'Outgoing'                   
CREATE   PROCEDURE [dbo].[usp_createcalllog]( 
	@reftable nvarchar(100),
	@refcolumn nvarchar(100),
	@refid bigint,
	@direction nvarchar(20)
)                    
as                    
begin      

	--declare 
	--	@reftable nvarchar(100) = 'tbl_voip_endpointInteraction',
	--	@refcolumn nvarchar(100) = 'id', 
	--	@refid bigint = 296335,
	--	@direction nvarchar(20) = 'Outgoing'
              
	declare @CallType int,@gatewayid int, @callname nvarchar(50), @recordurl nvarchar(400), @Customernumber nvarchar(20), @customercountrycode nvarchar(10), @Agentnumber nvarchar(20), @agentcountrycode nvarchar(10), @Callstarttime datetime, @Callendtime datetime, @Agentpickuptime datetime, @Customerpickuptime datetime, @Calldurationseconds int, @Billdurationseconds int, @customerduration int, @agentduration int, @lastdtmf nvarchar(50), @agentmode nvarchar(20), @agentcalldisposition nvarchar(50), @customercalldisposition nvarchar(50), @agentuserid bigint, @outcomeid bigint,@remarks nvarchar(max), @customerentity nvarchar(20),@customerentityid bigint,@callcreatedby bigint,@callscheduledfor datetime,@dnid nvarchar(50), @callcreatedon datetime, @parentid bigint, @appid bigint, @calllogid bigint, @uniqueidentity nvarchar(50), @leadno bigint ,@callsid nvarchar(100),@streamsid nvarchar(100),@streamstatus nvarchar(100)                  
                    
	if @reftable='Kit19calls'                    
	begin   
	
		drop table if exists #kit19calls                    
		select * into #kit19calls from kit19calls with (nolock) where id=@refid            
		select @uniqueidentity=uniqueid from #kit19calls                    
		select @CallType=(select id from Calltypes where Typename=case when context='inbound' then 'Incoming' when context='DialerCalls' then 'Click2Call' else 'OBD' end )                   
		,@gatewayid=2                    
		,@Customernumber=case when context= 'Inbound' then callerid else dnid end            
		,@dnid=case when context<> 'Inbound' then callerid else dnid end                
		 ,@recordurl =case when dbo.fn_getcallstatus(@uniqueidentity)='Answered' then recordurl else null end     
		,@customercountrycode=null                  
		,@Agentnumber=case when context='Dialercalls' then accountcode end                 
		,@agentcountrycode=null                  
		,@Callstarttime=call_start_time                  
		,@Callendtime=call_end_time                  
		,@Agentpickuptime=case when context='Dialercalls' then call_start_time end                  
		,@Customerpickuptime=case when context='inbound' then call_start_time end                  
		,@Calldurationseconds=datediff(SS,call_start_time,call_end_time)                  
		,@Billdurationseconds=null                  
		,@customerduration=datediff(SS,call_start_time,call_end_time)                  
		,@agentduration=null                  
		,@lastdtmf=call_last_dtmf                  
		,@agentmode=case when context='Dialercalls' then 'Extension' end                  
		,@agentcalldisposition=case when context='DialerCalls' then 'ANSWERED' when             
		 dbo.fn_getcallstatus(@uniqueidentity)='Answered' then 'ANSWERED' end                 
		,@customercalldisposition=case when context<>'DialerCalls' then 'ANSWERED'             
		else upper(dbo.fn_getcallstatus(uniqueid)) end                  
		,@agentuserid=case when context='DialerCalls' then accountcode end            
		,@outcomeid=null                  
		,@remarks=null                  
		,@callcreatedby=case when context='DialerCalls' then accountcode end            
		,@callscheduledfor=null                  
		,@callcreatedon=call_start_time                  
		,@parentid=clientid                  
		,@appid  =appid            
		,@uniqueidentity=uniqueid               
		,@direction=case when  context= 'Inbound' then 'Incoming' else 'Outgoing' end                
		from #kit19calls                    
		--select @direction=case when  @calltype='Incoming' then 'Inbound' else 'Outgoing' end    
  
		select @parentid=coalesce(@parentid,(select top 1 parentid from cloud_user_phone(nolock)  
		where phoneno=@dnid and active=1 order by userphid desc))  
  
		select @customerentity=                  
		case when exists(select 1 from userleads_mobile_email(nolock) where parentid=@parentid and  dbo.fn_trim0prefix(@Customernumber) =mobile)                  
		then 'lead'                  
		when exists(select 1 from userenquiry_mobile_email(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber) =mobile)                  
		then 'enquiry'                  
		end                  
		select @customerentityid=                  
		case when @customerentity='lead'                  
		then (select top 1 id from userleads(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                  
		in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by id desc)                   
		when @customerentity='enquiry'                  
		then (select top 1 EnquiryID from userenquiry(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                  
		in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by EnquiryID desc)                   
		end                  
		if @customerentity='lead'             
		begin            
		select @leadno=leadno from userleads(nolock) where id=@customerentityid            
		end            
            
            
		declare @sql nvarchar(1000)            
		select @sql= 'select @customercountrycode=countrycode from '+case when @customerentity='lead' then             
		' userleads_mobile_email(nolock) ' else ' userenquiry_mobile_email(nolock) ' end +             
		' where parentid = '+cast(@parentid as nvarchar)+' and ' +'mobile='+cast(dbo.fn_trim0prefix(@Customernumber) as nvarchar)                  
		+' and ' +case when @customerentity='lead' then 'leadno= '+cast(@leadno as nvarchar)            
		else 'enquiryid='+cast(@customerentityid as nvarchar) end            
		exec sp_executesql @sql,N'@parentid bigint,@Customernumber nvarchar(50),@customerentity nvarchar(20),@leadno bigint,            
		@customerentityid bigint,@customercountrycode nvarchar(10) output',@parentid=@parentid,@Customernumber=@Customernumber            
		,@customerentity=@customerentity,@leadno=@leadno,@customerentityid=@customerentityid,@customercountrycode=@customercountrycode output            
            
		select @callname='NewCall_'+cast(@callcreatedon as nvarchar)+'_'+cast(@uniqueidentity as nvarchar(50))            
                  
		end                    
	else if @reftable='twiliocalls'                    
	begin   
	
		drop table if exists #twiliocalls                    
		select * into #twiliocalls from twiliocalls with (nolock) where id=@refid            
		select @callsid=callsid from #twiliocalls                    
		select @CallType=(select id from Calltypes where Typename=case when direction='inbound' then 'Incoming' else 'Click2Call' end )        
		,@gatewayid=8                    
		,@Customernumber=callerid            
		,@dnid=dnid               
		,@customercountrycode=countrycode                 
		,@Agentnumber=null
		,@agentcountrycode=null
		,@Callstarttime=call_start_time                  
		,@Callendtime=call_end_time                  
		,@Agentpickuptime=null                  
		,@Customerpickuptime=case when direction='inbound' then call_start_time end                  
		,@Calldurationseconds=datediff(SS,call_start_time,call_end_time)                  
		,@Billdurationseconds=null                  
		,@customerduration=case when direction='inbound' then datediff(SS,call_start_time,call_end_time) end                  
		,@agentduration=null
		,@lastdtmf=call_last_dtmf                  
		,@agentmode=null
		,@agentcalldisposition=null
		,@customercalldisposition=case when direction='inbound' then 'ANSWERED' end                  
		,@agentuserid=null
		,@outcomeid=null                  
		,@remarks=null                  
		,@callcreatedby=null
		,@callscheduledfor=null                  
		,@callcreatedon=call_start_time                  
		,@parentid=parentid                  
		,@appid  =null            
		,@callsid=callsid,@streamsid=streamsid               
		,@direction=case when  direction= 'Inbound' then 'Incoming' else 'Outgoing' end                
		from #twiliocalls t                    
		--select @direction=case when  @calltype='Incoming' then 'Inbound' else 'Outgoing' end    
  
		select @parentid=coalesce(@parentid,(select top 1 parentid from cloud_user_phone(nolock)  
		where phoneno=@dnid and active=1 order by userphid desc))  
  
		select @customerentity=                  
		case when exists(select 1 from userleads_mobile_email(nolock) where parentid=@parentid and  dbo.fn_trim0prefix(@Customernumber) =mobile)                  
		then 'lead'                  
		when exists(select 1 from userenquiry_mobile_email(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber) =mobile)                  
		then 'enquiry'                  
		end                  
		select @customerentityid=                  
		case when @customerentity='lead'                  
		then (select top 1 id from userleads(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                  
		in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by id desc)                   
		when @customerentity='enquiry'                  
		then (select top 1 EnquiryID from userenquiry(nolock) where parentid=@parentid and dbo.fn_trim0prefix(@Customernumber)                  
		in (isnull(MobileNo,'0'),isnull(MobileNo1,'0'),isnull(MobileNo2,'0')) order by EnquiryID desc)                   
		end                  
		if @customerentity='lead'             
		begin            
		select @leadno=leadno from userleads(nolock) where id=@customerentityid            
		end            
            
            
		--declare @twsql nvarchar(1000)            
		--select @twsql= 'select @customercountrycode=countrycode from '+case when @customerentity='lead' then             
		--' userleads_mobile_email(nolock) ' else ' userenquiry_mobile_email(nolock) ' end +             
		--' where parentid = '+cast(@parentid as nvarchar)+' and ' +'mobile='+cast(dbo.fn_trim0prefix(@Customernumber) as nvarchar)                  
		--+' and ' +case when @customerentity='lead' then 'leadno= '+cast(@leadno as nvarchar)            
		--else 'enquiryid='+cast(@customerentityid as nvarchar) end            
		--exec sp_executesql @twsql,N'@parentid bigint,@Customernumber nvarchar(50),@customerentity nvarchar(20),@leadno bigint,            
		--@customerentityid bigint,@customercountrycode nvarchar(10) output',@parentid=@parentid,@Customernumber=@Customernumber            
		--,@customerentity=@customerentity,@leadno=@leadno,@customerentityid=@customerentityid,@customercountrycode=@customercountrycode output            
            
		select @callname='NewCall_'+cast(@callcreatedon as nvarchar)+'_'+cast(@callsid as nvarchar(50))            
                  
		end                    
	
	else if @reftable='tbl_voip_endpointInteraction'                  
	begin    

		print 'tbl_voip_endpointInteraction'

		declare @response nvarchar(max) ,@providername nvarchar(100)               
		drop table if exists #tbl_voip_endpointInteraction                  
		select * into #tbl_voip_endpointInteraction from tbl_voip_endpointInteraction with (nolock) where id=@refid                
		select @direction= case when tei_direction='incoming' then 'incoming' else  'Outgoing'  end, @CallType=      
		(select id from Calltypes where Typename= case when tei_direction='incoming' then 'incoming' else  'Click2Call' end)      
		from #tbl_voip_endpointInteraction      


			select
				@gatewayid = (select top 1 id from tbl_voip_ServiceProvider(nolock) where provider_name=t.providername),
				@Customernumber = ltrim(rtrim(replace(substring(tomobileno,case when charindex(' ',tomobileno,1)<>0 then charindex(' ',tomobileno,1)                  
				else 1 end,len(tomobileno)-charindex(' ',tomobileno,1)+1),' ','') ))                  
				,@customercountrycode=case when charindex(' ',tomobileno,1)<>0 then ltrim(rtrim(REPLACE(substring(tomobileno,1,charindex(' ',tomobileno,1)),' ','') ))                  
				end                  
				,@Agentnumber= ( case when isnull(a.mobile_no, '')  = '' and t.ProviderName = 'Mobile Like Number' 
									then (select JSON_VALUE([j].[value], '$.value') as 'agentNumber' from openjson(t.request_body) j  
										where JSON_VALUE([j].[value], '$.key') = 'agentNumber')
									when t.ProviderName = 'Kit19 80' then t.kei_AgentMobile else a.mobile_no end)
				,@agentcountrycode = null--to be added in agent setting             
				,@providername = ProviderName               
				,@Callstarttime = t.created_on 
				,@Callendtime = case when ProviderName = 'Kit19 80' then t.kei_CallEndTime else null end
				,@dnid = case when ProviderName = 'Kit19 80' then t.kei_Dnid else null end
				,@Agentpickuptime = case when ProviderName = 'Kit19 80' then t.kei_AgentcallTime else null end                  
				,@Customerpickuptime = case when ProviderName = 'Kit19 80' then t.kei_CustomerCallTime else null end                   
				,@Calldurationseconds = case when ProviderName = 'Kit19 80' 
					then datediff(second, t.kei_AgentcallTime, t.kei_CallEndTime ) else null end                    
				,@Billdurationseconds=null                  
				,@customerduration=case when ProviderName = 'Kit19 80' 
					then datediff(second, t.kei_CustomerCallTime, t.kei_CallEndTime ) else null end                  
				,@agentduration=case when ProviderName = 'Kit19 80' 
					then datediff(second, t.kei_AgentcallTime, t.kei_CallEndTime ) else null end                   
				,@lastdtmf=null                  
				,@agentmode=case when @direction='incoming' and isnull(tei_extension,0)<>0 then 'Extension' else 'Mobile' end          
				,@agentcalldisposition=(case when ProviderName = 'Kit19 80' then kei_AgentDialStatus else (case
						when tie_Agent_Disconnection_Reason = 'BUSY' and tie_Disconnected_by = 'Agent' then 'BUSY'
						when tie_Agent_Disconnection_Reason = 'CONGESTION' and tie_Disconnected_by = 'Agent' then 'CONGESTION'
						when tie_Agent_Disconnection_Reason = 'ANSWERED' and tie_Disconnected_by = 'Agent' then 'ANSWERED'
						when tie_Agent_Disconnection_Reason = 'CANCEL' and tie_Disconnected_by = 'Agent' then 'CANCEL'
						when tie_Agent_Disconnection_Reason = 'NOANSWER' and tie_Disconnected_by = 'Agent' then 'NOANSWER'
						when tie_Agent_Disconnection_Reason = 'HangupByAgent' and tie_Disconnected_by = 'Agent' then 'CONGESTION'		
					else null end) end)
				,@customercalldisposition=(case when ProviderName = 'Kit19 80' then kei_AgentDialStatus else (case
						when tie_Disconnected_by = 'Agent' then 'NOT ATTEMPTED'
						when tie_Cust_Disconnection_Reason = 'BUSY' and tie_Disconnected_by = 'Customer' then 'BUSY'
						when tie_Cust_Disconnection_Reason = 'CONGESTION' and tie_Disconnected_by = 'Customer' then 'CONGESTION'
						when tie_Cust_Disconnection_Reason = 'ANSWERED' and tie_Disconnected_by = 'Customer' then 'ANSWERED'
						when tie_Cust_Disconnection_Reason = 'CANCEL' and tie_Disconnected_by = 'Customer' then 'CANCEL'
						when tie_Cust_Disconnection_Reason = 'NOANSWER' and tie_Disconnected_by = 'Customer' then 'NOANSWER'
					else null end) end)           
				,@agentuserid=agentid                  
				,@outcomeid=null                  
				,@remarks=null                  
				,@callcreatedby=agentid                  
				,@callscheduledfor=null                  
				,@callcreatedon=t.created_on                  
				,@parentid=(select Parentid from User_Detail(nolock) where user_id=agentid)                  
				,@appid  =null                  
				,@customerentity=isnull(t.EntityName,'')                 
				,@customerentityid=isnull(t.EntityId,0)          
				,@response=request_body                  
			from #tbl_voip_endpointInteraction  t(nolock)
			left join tbl_voip_userAgentSetting(nolock) a on t.AgentId=a.user_id                   

			drop table if exists #jsonwebhook_c          
			create table #jsonwebhook_c([key] nvarchar(500),[value] nvarchar(max)) --while @i<3 --begin --select @s=MIN(srv_pro_id) from #t where srv_pro_id>@s --select @r=request_body from #t where srv_pro_id=@s                      
			if @direction='outgoing'    
			begin    
				insert into #jsonwebhook_c([key],[value])                
				select [key],[value] from openjson(@response)          
			end   

			if(isnull(@Agentnumber, '') = '')
			begin
				select @Agentnumber = case when @gatewayid=1 and @direction='outgoing' 
					then ( select isnull(nullif(nullif(json_value([value],'$.value'),''),'null'),'')
							from #jsonwebhook_c where [Key]='2')    
				when @gatewayid=3 
					then ( select json_value((select [value]  from openjson(@response)  where [key]='2'),'$.value'))            
				when @gatewayid=4 and @direction='outgoing' then @Agentnumber          
				when @providername like '%_Asterisk' 
					then (select json_value((select [value]  from openjson(@response)  where [key]='0'),'$.value'))          
				end   
			end
          
			select @agentmode=case when @gatewayid=1 then 'Extension'          
					when @gatewayid in (3,4) then 'Mobile'           
					when @providername like '%_Asterisk' then           
					case when (select json_value((select [value]  from openjson(@response)  where [key]='0'),'$.value'))          
				like '%/%' then 'Extension' else 'Mobile' end end          
          
			select @agentcountrycode = case when @agentmode='Mobile' 
				then case when @gatewayid in (3,4) then '+91' 
					when @providername like '%_Asterisk' 
					then (select countrycode from dbo.fn_separatecountrycodeandmobile(@Agentnumber)) end 
			end
	
	end  

	select @callname='NewCall_'+cast(@callcreatedon as nvarchar)+'_'+cast(@refid as nvarchar)              

	insert into calllog(CallType, gatewayid, Direction, Customernumber, customercountrycode, Agentnumber, agentcountrycode, Callstarttime, Callendtime, Agentpickuptime, Customerpickuptime, Calldurationseconds, Billdurationseconds, customerduration, agentduration, lastdtmf, agentmode, agentcalldisposition, customercalldisposition, agentuserid, outcomeid, remarks, customerentity, customerentityid, callcreatedby, callscheduledfor, callcreatedon, reftable, refcolumn, refid, parentid, appid, callname, dnid, recordurl, uniqueid,callsid)                    
	select @CallType, @gatewayid, @Direction, @Customernumber, @customercountrycode, @Agentnumber, @agentcountrycode, @Callstarttime, @Callendtime,  @Agentpickuptime, @Customerpickuptime, @Calldurationseconds, @Billdurationseconds, @customerduration, @agentduration, @lastdtmf, @agentmode, @agentcalldisposition, @customercalldisposition, @agentuserid, @outcomeid,@remarks, @customerentity, @customerentityid, @callcreatedby, @callscheduledfor, @callcreatedon, @reftable, @refcolumn, @refid, @parentid, @appid, @callname, @dnid, @recordurl, @uniqueidentity ,@callsid
	

	select @calllogid = scope_identity()   
	select @calllogid
        
end



GO

