-- exec [usp_CreateCloneEmailTable]  335          
                                   
CREATE   PROC [dbo].[usp_CreateCloneEmailTable] --335                                
@UserID int        
as         
begin                                     
Declare @query nvarchar(max)                                      
Declare @tableName varchar(100)                                      
DECLARE @TRIG_QUERY VARCHAR(max)      
declare @trig_query1 varchar(max)                                    
                                      
select  @tableName='M'+cast(@UserID as varchar)+convert(nvarchar,getdate(),112)+''+replace(convert(nvarchar,getdate(),114),':','')                                      
set @query='CREATE TABLE [dbo].['+@tableName+'](                                      
               
       [Mail_GUID] [nvarchar](50) DEFAULT NEWID()        
      ,[Mail_ID] [Bigint] IDENTITY(1,1) NOT NULL PRIMARY KEY        
      ,[Mail_FromEmail] [Varchar](100) NOT NULL        
      ,[Mail_ToEmail] [Varchar](100) NOT NULL        
      ,[Mail_Subject] [Varchar](200)        
      ,[Mail_TempleteName] [Varchar] (100)         
      ,[Messages] [nvarchar] (max)        
      ,[Mail_InsertedDate] [datetime] NOT NULL        
      ,[Mail_UserID] [int] NOT NULL        
      ,[Mail_ParentID] [int]        
      ,[ReplyTo] [varchar] (100)        
      ,[Mail_BatchID] [Bigint]         
      ,[Mail_Priority] [INT]        
      ,[Mail_ScheduleDate] [Varchar](50)        
      ,[Mail_ScheduledTime] [Varchar](50)        
      ,[Mail_Attechement] [Varchar](500)        
      ,[Mail_TempleteBody] [nvarchar] (max)        
      ,[IsMonitor] [Bit] NOT NULL        
      ,[TemplateID] [Bigint]         
      ,[Count] [Int] NOT Null        
      ,[Source] [Nvarchar](20) NOT NULL        
             
       )'                                      
                                      
exec (@query)         
 -- select  @tableName        
      
--Declare @tableName varchar(100)                                      
      
--DECLARE @TRIG_QUERY VARCHAR(max)        
--set @tableName = 'M33520180228175035603'        
                                
select  @tableName                                      
    SET @TRIG_QUERY='CREATE TRIGGER TRG_'+@tableName+'                                    
     ON '+@tableName+'                                    
     FOR INSERT                                     
   AS                     
                   
       begin           
begin try        
      
DECLARE @ROW_COUNT BIGINT          
          
SET @ROW_COUNT=@@ROWCOUNT          
declare         
@Mail_BatchID bigint,        
@Mail_ParentID bigint,        
@Mail_userID  bigint,        
@TemplateID bigint,        
@count int,        
@actualcount int,        
@parentsuperresellerid bigint,        
@hassufficientvirtualcredits int,        
@source nvarchar(20),        
@scheduleddate nvarchar(50)        
        
select @TemplateID = TemplateID , @Mail_BatchID = mail_batchid,@Mail_ParentID=Mail_ParentID,@Mail_userID=Mail_userID,@count=count,@source=source,@scheduleddate=mail_scheduledate from inserted        
 select @actualcount = (select COUNT(1) from '+@tableName+' where @Mail_BatchID=Mail_BatchID)        
if @count<>@actualcount        
begin        
waitfor delay ''00:00:00.010''        
End        
select * into #CloneEmailsFilter from '+@tableName+' where @Mail_BatchID=Mail_BatchID        
select @actualcount = (select COUNT(1) from #CloneEmailsFilter where @Mail_BatchID=Mail_BatchID)        
if @count=@actualcount        
begin        
declare @deductcredits int=1        
select @parentsuperresellerid =parentsuperresellerid from user_detail where USER_ID=@Mail_USERID and HasVirtualCredits=1        
if @parentsuperresellerid is not null and @parentsuperresellerid <>335        
begin        
declare @balancecredits bigint = (select top 1 balance from SuperResellermailCreditDetails where USER_ID=@parentsuperresellerid order by Credit_ID desc)        
if(@balancecredits<@count)        
begin        
set @deductcredits =0        
Select ''Something went wrong, please contact your admin & Retry''      drop table #CloneEmailsFilter        
end        
end        
        
IF @deductcredits=1          
BEGIN         
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo,
Tablename)          
SELECT top 1 Mail_BatchID,Mail_UserID,coalesce(Mail_FromEmail,U.Email) as SenderName,case when isnull(@templateid,0)=0 then (select top 1 Cast(Messages AS VARCHAR(MAX)) from #CloneEmailsFilter where mail_batchid=@mail_batchid) else 
(select mailcontent from UserMailTemplate where ID=@TemplateID) end as Message,Count,0,0,0,Mail_Priority,Getdate(),NULL,MAIL_scheduledate,MAIL_scheduleDtime,@TemplateID,0,0,0,Mail_Subject,ReplyTo, '''+@tableName+''' FROM       
#cloneEmailsFilter a (nolock) join user_detail u (nolock) on u.user_id=a.mail_UserID '       
       
        
set @trig_query1='      
Insert INTO Mailcreditdetails                                              
                  (ID,                                              
                   M_ID,                                              
                   FromUser_ID,                                              
                   [User_ID],                                              
                   Debits,                                              
                 Credits,                                              
                 Balance,                                              
                   Validity,                                              
                   Default_Credit,                                              
                   FromDate,                                              
                   ToDate,                                              
                   DateCreated,                                              
                   DateUpdated,                                              
               EmpUpdated,                                              
                   MachineName,                                              
                   LastModified,                                  
                   typecredit,            
                   campaignid)                                              
      SELECT top 1 Newid(),                                              
             Ud.M_ID,                                              
             Mail_UserID,                                              
             Mail_UserID,                                              
             count,                                              
             0,                                              
             (SELECT TOP 1 Mcd.Balance                                              
              FROM   Mailcreditdetails AS Mcd                                              
              WHERE  Mcd.[User_ID] = Mail_UserID                                              
              ORDER  BY Mcd.Credit_ID DESC) - count,                                              
             99999,                                              
             0,                                              
             Getdate(),                                              
             Getdate(),                                              
             Getdate(),                                              
             Getdate(),                                              
             '''',                                              
             '''',                                              
             Getdate(),                                     
             '''',            
             0                                              
      FROM   #cloneemailsfilter  c join user_detail  ud on ud.User_ID=c.mail_userid        
              
 if @parentsuperresellerid is not null        
  begin        
      INSERT INTO SuperresellerMailcreditdetails                                              
                  (ID,                                              
        M_ID,                                              
                   FromUser_ID,                                              
                   [User_ID],                                              
                   Debits,                                              
                 Credits,                               
                 Balance,                                              
                   Validity,                                              
                   Default_Credit,                                              
                   FromDate,                                              
                   ToDate,                                              
                   DateCreated,                                              
                   DateUpdated,                                              
               EmpUpdated,                                              
                   MachineName,                                              
                   LastModified,                                              
                   typecredit,            
                   campaignid)                                              
      SELECT top 1 Newid(),                                              
             Ud.M_ID,                                              
             @ParentSuperResellerId,                                              
             @ParentSuperResellerId,                      
             count,                                              
             0,                                              
             (SELECT TOP 1 Mcd.Balance                                              
              FROM   SuperResellerMailCreditDetails AS Mcd                                              
              WHERE  Mcd.[User_ID] = @ParentSuperResellerId                                              
              ORDER  BY Mcd.Credit_ID DESC) - count,                                              
             99999,                                              
       0,                                              
             Getdate(),                                              
             Getdate(),                                              
             Getdate(),                                              
             Getdate(),                                              
             '''',                                              
             '''',                                              
             Getdate(),                                     
             '''',            
             0                                              
      FROM   #cloneemailsfilter c join user_detail ud on ud.User_ID=@parentsuperresellerid        
end        
end            
end           
END TRY                                               
BEGIN CATCH       
EXEC Usp_inserterrorinfo       
END CATCH       
END'                                                
                                      
EXEC (@trig_query+@trig_query1)          
        
end    
    


GO

