             [dbo].[ufn_GetUserParentId](Mail_UserID),                                                  
             [dbo].[ufn_GetUserParentId](Mail_UserID),                                                  
             count,                                                  
             0,                                                  
             (SELECT TOP 1 Mcd.Balance                                                  
              FROM   Mailcreditdetails AS Mcd                                                  
              WHERE  Mcd.[User_ID] = [dbo].[ufn_GetUserParentId](Mail_UserID)                                                  
              ORDER  BY Mcd.Credit_ID DESC) - count,                            
             99999,                                                  
             0,                                                  
             Getdate(),                                                  
             Getdate(),                                                  
             Getdate(),                                                  
             Getdate(),                                                  
             '''',                                                  
             '''',                                                  
             Getdate(),                                         
             '''',                
             0,@Mail_BatchID                                                  
      FROM   #cloneemailsfilter  c join user_detail  ud(nolock) on ud.User_ID=c.mail_userid            
                  
 if @parentsuperresellerid is not null            
