CREATE   PROC [dbo].[usp_CreateCloneEmailTable111_New_automatedmail] --44296 --335                                      
@UserID int              
as               
begin                                           
Declare @query nvarchar(max)                                            
Declare @tableName varchar(100)                                            
DECLARE @TRIG_QUERY VARCHAR(max)            
declare @trig_query1 varchar(max)                                          
                                            
select  @tableName='M'+cast(@UserID as varchar)+convert(nvarchar,getdate(),112)+''+replace(convert(nvarchar,getdate(),114),':','')                                            
select @query='CREATE TABLE [dbo].['+@tableName+'](                                            
                     
       [Mail_GUID] [nvarchar](50) DEFAULT NEWID()              
      ,[Mail_ID] [Bigint] IDENTITY(1,1) NOT NULL PRIMARY KEY              
      ,[Mail_FromEmail] [Varchar](100) NOT NULL              
      ,[Mail_ToEmail] [Varchar](100) NOT NULL              
      ,[Mail_Subject] [nVarchar](200)              
      ,[Mail_TempleteName] [Varchar] (100)               
      ,[Messages] [nvarchar] (max)              
      ,[Mail_InsertedDate] [datetime] NOT NULL              
      ,[Mail_UserID] [int] NOT NULL              
      ,[Mail_ParentID] [int]              
      ,[ReplyTo] [varchar] (100)              
      ,[Mail_BatchID] [Bigint]               
      ,[Mail_Priority] [INT]              
      ,[Mail_ScheduleDate] [Varchar](50)              
      ,[Mail_ScheduledTime] [Varchar](50)              
      ,[Mail_Attechement] [Varchar](500)              
      ,[Mail_TempleteBody] [nvarchar] (max)              
      ,[IsMonitor] [Bit] NOT NULL              
      ,[TemplateID] [Bigint]               
      ,[Count] [Int] NOT Null              
      ,[Source] [Nvarchar](20) NOT NULL              
      ,[mailroute] [nvarchar](20) null             
       )'                                            
                                            
