 when status=1 and @actualcount >=plimit and isnull(mailroute,''T'')=''T'' then 0   
 else 1 end from processmaillimit),source FROM  #cloneEmailsFilter a (nolock)       
 join user_detail u (nolock) on u.user_id=a.mail_UserID where not exists (select 1 from Batchemail_infos(nolock) where batchid=@batchid)'             
             
              
select @trig_query1=' 
if @source =''API''
begin
Insert INTO Mailcreditdetails                                                    
                  (ID,                                                    
                   M_ID,                                                    
                   FromUser_ID,                                                    
                   [User_ID],                                                    
                   Debits,                                                    
