      SELECT top 1 Newid(),                                                    
             Ud.M_ID,                           
             [dbo].[ufn_GetUserParentId](Mail_UserID),                                                    
             [dbo].[ufn_GetUserParentId](Mail_UserID),                                                    
             count,                                                    
             0,                                                    
             (SELECT TOP 1 Mcd.Balance                                                    
              FROM   Mailcreditdetails AS Mcd                                                    
              WHERE  Mcd.[User_ID] = [dbo].[ufn_GetUserParentId](Mail_UserID)                                                    
              ORDER  BY Mcd.Credit_ID DESC) - count,                              
             99999,                                                    
             0,                                                    
             Getdate(),                                                    
             Getdate(),                                                    
             Getdate(),                                                    
             Getdate(),                                                    
             '''',                                                    
             '''',                                                    
             Getdate(),                                           
             '''',                  
             0,@Mail_BatchID                                                    
      FROM   #cloneemailsfilter  c join user_detail  ud(nolock) on ud.User_ID=c.mail_userid              
end
else if @source <> ''API'' and not exists (select 1 from IntCredit_Details(nolock) where batchid=@batchid)
begin
INSERT INTO IntCredit_Details
        (
            FromUser_ID, M_ID, User_ID, Debits, Credits, Balance,Validity, BatchID, ICD_CreatedBy,typecredit,Remarks
        )
select top 1
            [dbo].[ufn_GetUserParentId](Mail_UserID), ud.m_id, [dbo].[ufn_GetUserParentId](Mail_UserID), @totalcost, 0, dbo.fn_getmoneybalance([dbo].[ufn_GetUserParentId](Mail_UserID))-@totalcost, 99999, null, [dbo].[ufn_GetUserParentId](Mail_UserID),2,''Credits utilized for sending automated mail campaign'' 
			FROM   #cloneemailsfilter  c join user_detail  ud(nolock) on ud.User_ID=c.mail_userid 

		SElecT @InsertedCreditID = SCOPE_IDENTITY();

		exec usp_rf_UpdateReserveFundTransaction @InsertedCreditID
		
end

 if @parentsuperresellerid is not null              
  begin              
      INSERT INTO SuperresellerMailcreditdetails                                                    
                  (ID,                                                    
        M_ID,                                                    
                   FromUser_ID,                                                    
                   [User_ID],                                                    
                   Debits,                                                    
                 Credits,                                     
                 Balance,                                                    
                   Validity,                                                    
                   Default_Credit,                                                    
                   FromDate,                                                    
                   ToDate,                                                    
                   DateCreated,                                                    
                   DateUpdated,                                                    
               EmpUpdated,                                                    
                   MachineName,                                                    
                   LastModified,                                                    
                   typecredit,                  
                   campaignid)                                                    
      SELECT top 1 Newid(),                                                    
             Ud.M_ID,                                                    
             @ParentSuperResellerId,                                                    
             @ParentSuperResellerId,                            
             count,                                                    
             0,                                                    
             (SELECT TOP 1 Mcd.Balance                                                    
              FROM   SuperResellerMailCreditDetails AS Mcd                                                    
              WHERE  Mcd.[User_ID] = @ParentSuperResellerId                                                    
              ORDER  BY Mcd.Credit_ID DESC) - count,                                                    
             99999,                                                    
       0,                                                    
             Getdate(),                                                    
             Getdate(),                                                    
             Getdate(),                                                    
             Getdate(),                                                    
             '''',                                                    
             '''',                                                    
             Getdate(),                                           
             '''',                  
             0                                                    
      FROM   #cloneemailsfilter c join user_detail ud on ud.User_ID=@parentsuperresellerid              
end              
end                  
end                 
END TRY                                                     
BEGIN CATCH             
EXEC Usp_inserterrorinfo             
END CATCH             
END'                                                      
 
 
