                   LastModified,                                        
                   typecredit,                  
                   campaignid,  
       batchid)                                                    
      SELECT top 1 Newid(),                                                    
             Ud.M_ID,                           
             [dbo].[ufn_GetUserParentId](Mail_UserID),                                                    
             [dbo].[ufn_GetUserParentId](Mail_UserID),                                                    
             count,                                                    
             0,                                                    
