            [dbo].[ufn_GetUserParentId](Mail_UserID), ud.m_id, [dbo].[ufn_GetUserParentId](Mail_UserID), @totalcost, 0, dbo.fn_getmoneybalance([dbo].[ufn_GetUserParentId](Mail_UserID))-@totalcost, 99999, null, [dbo].[ufn_GetUserParentId](Mail_UserID),2,''Credits utilized for sending automated mail campaign'' 
			FROM   #cloneemailsfilter  c join user_detail  ud(nolock) on ud.User_ID=c.mail_userid 

		SElecT @InsertedCreditID = SCOPE_IDENTITY();

		exec usp_rf_UpdateReserveFundTransaction @InsertedCreditID
		
end

 if @parentsuperresellerid is not null              
  begin              
      INSERT INTO SuperresellerMailcreditdetails                                                    
                  (ID,                                                    
        M_ID,                                                    
                   FromUser_ID,                                                    
                   [User_ID],                                                    
