/* ============================================================
   Procedure: [dbo].[usp_CreateCloneTable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*                          
CREATE BY :- RAGHWENDRA                           
DATE:-30082010                          
*/                          
CREATE   PROC [dbo].[usp_CreateCloneTable]                          
as                            
Declare @query nvarchar(max)                            
Declare @tableName varchar(100)                            
DECLARE @TRIG_QUERY VARCHAR(max)                          
                            
select  @tableName='R'+convert(nvarchar,getdate(),112)+''+replace(convert(nvarchar,getdate(),114),':','')                            
set @query='CREATE TABLE [dbo].['+@tableName+'](                            
 [MessageID] [bigint] IDENTITY(1,1) NOT NULL,                            
 [BatchID] [bigint] NOT NULL,                            
 [Mobile] [varchar](20) ,                            
 [Message] [nvarchar](2500) ,                            
 [MessageStatus] [varchar](20) ,                            
 [SenderID] [nchar](20) ,                            
 [MessageInsertDate] [datetime] NOT NULL   DEFAULT (getdate()),                            
 [ScheduledDate] [varchar](50) ,                            
 [ScheduledTime] [varchar](50) ,                            
 [SmppID] [tinyint] NOT NULL   DEFAULT ((1)),                            
 [U_ID] [int] NOT NULL,                            
 [IsUniCode] [bit] NOT NULL   DEFAULT ((0)),                            
 [IsDnd] [bit] NOT NULL  DEFAULT ((0)),                            
 [IsAirtel] [bit] NOT NULL   DEFAULT ((0)),                            
 [MobileSubSet] [bigint] NULL,                            
 [ValidNo] [tinyint] NULL ,                          
 [IsPrority] [tinyint] NULL,                          
 [IsAllowDND] [tinyint] NULL,                      
 [DBType] [nchar](10) NULL   DEFAULT ((0))                      
)'                            
                            
exec (@query)                            
select  @tableName                            
                          
                           
SET @TRIG_QUERY='CREATE TRIGGER TRG_'+@tableName+'                          
ON '+@tableName+'                          
FOR INSERT                           
AS                          
DECLARE @ROW_COUNT BIGINT                          
SET @ROW_COUNT=@@ROWCOUNT                          
                  
DECLARE @M_ID BIGINT                          
                          
DECLARE @USERID INT,                                    
@BATCHID BIGINT,                                          
@PRIORITY TINYINT,                                          
@ALLOWDND TINYINT,                                      
@ScheduleDate VARCHAR(50),                                      
@ScheduleTime VARCHAR(50),                                  
@IsUnicode bit,                                
@PageName nvarchar(50),                                
@UserFilter varchar(20),                            
@TableName varchar(100),                          
@MESSAGE_LEN INT ,                          
@MESSAGE_LEN_TEMP INT  ,                      
@MESSAGE_LEN_MAXLEN BIGINT  ,                      
@MESSAGELEN_CLONE BIGINT,                      
@DBType nchar(10)                       
                      
                      
SELECT                           
@MESSAGE_LEN=1,                          
@BATCHID=BatchID,                          
@ALLOWDND=IsAllowDND,                          
@ScheduleDate=ScheduledDate,                          
@ScheduleTime=ScheduledTime,                          
@USERID=U_ID,                          
@IsUnicode=IsUniCode,                          
@PRIORITY=IsPrority,                          
@PageName=''CSV'',                          
@TableName='''+@tableName+''' ,                      
@DBType=DBType                          
FROM '+@tableName+'                        
                      
     
   if(exists (select 1 from  '+@tableName+' where batchid=@batchid  and dbo.fn_IsUnicode(message) = 1 ))
     begin
	   set @IsUnicode = 1      
	 end
   else
     begin
	   set @IsUnicode = 0
	 end



IF(@DBType >= 1)                      
BEGIN                      
SELECT TOP(1) @UserFilter=UserFilter FROM MyGroupAppComb.DBO.USER_DETAILS WHERE USERID=@USERID                      
END                      
                      
ELSE IF(@DBType = 0)                      
BEGIN        
SELECT TOP(1) @UserFilter=UserFilter FROM MySMS.DBO.USER_DETAIL WHERE USER_ID=@USERID                      
END                       
                      
         
EXEC USP_INSERTINTOBATCHINFONewTestNew @USERID,                                      
@BATCHID,                          
@ROW_COUNT,                                        
@PRIORITY,                                 
@ALLOWDND,                                      
@ScheduleDate,                                     
@ScheduleTime,                               
@IsUnicode,                             
@PageName,                             
@UserFilter,                          
@TableName,                
@DBType                           
                      
IF @IsUnicode=0                      
BEGIN                      
SELECT @MESSAGE_LEN_MAXLEN=isnull(sum(dbo.fn_GetMessageCount(len(message),isnull(@IsUnicode,0))),0),@MESSAGELEN_CLONE=count(message) FROM inserted with(nolock) where LEN(MESSAGE)>160 and batchid=@BATCHID                      
END                       
ELSE                      
BEGIN                      
SELECT @MESSAGE_LEN_MAXLEN=isnull(sum(dbo.fn_GetMessageCount(len(message),isnull(@IsUnicode,0))),0),@MESSAGELEN_CLONE=count(message) FROM inserted with(nolock) where LEN(MESSAGE)>70 and batchid=@BATCHID                    
END                      
                      
SET @ROW_COUNT=((@ROW_COUNT+isnull(@MESSAGE_LEN_MAXLEN,0))-isnull(@MESSAGELEN_CLONE,0))                      
                          
IF @PRIORITY=1                          
BEGIN                          
SET @ROW_COUNT=@ROW_COUNT*2                          
END                          
                          
SET @MESSAGE_LEN_TEMP=(SELECT [dbo].[fn_GetMessageCount](@MESSAGE_LEN,@IsUnicode))                          
                          
SET @ROW_COUNT=(@ROW_COUNT*@MESSAGE_LEN_TEMP)                          
                          
IF(@DBType >= 1)                      
BEGIN                      
SELECT @M_ID=MID FROM MyGroupAppComb.DBO.USER_DETAILS WHERE USERID=@USERID                      
                      
EXEC MyGroupAppComb.DBO.proc_UpdateCreditDetail @M_ID,@USERID,@ROW_COUNT,1                      
END                      
                      
ELSE IF(@DBType = 0)                      
BEGIN                      
SELECT @M_ID=M_ID FROM MySMS.DBO.USER_DETAIL WHERE USER_ID=@USERID                      
  set @PRIORITY=(select top (1)IsPrority from '+@tableName+' )                   
EXEC MySMS.DBO.proc_UpdateCreditDetail @M_ID,@USERID,@ROW_COUNT,1                   
END '                            
                            
EXEC (@TRIG_QUERY) 


GO

