select  @tableName='R'+convert(nvarchar,getdate(),112)+''+replace(convert(nvarchar,getdate(),114),':','')                                  
set @query='CREATE TABLE [dbo].['+@tableName+'](                                  
 [MessageID] [bigint] IDENTITY(1,1) NOT NULL,                                  
 [BatchID] [bigint] NOT NULL,                                  
 [Mobile] [varchar](20) ,                                  
 [Message] [nvarchar](2500) ,                                  
 [MessageStatus] [varchar](20) ,                                  
 [SenderID] [nchar](20) ,                                  
 [MessageInsertDate] [datetime] NOT NULL   DEFAULT (getdate()),                                  
 [ScheduledDate] [varchar](50) ,                                  
 [ScheduledTime] [varchar](50) ,                                  
 [SmppID] [tinyint] NOT NULL   DEFAULT ((1)),                                  
 [U_ID] [int] NOT NULL,                                  
 [IsUniCode] [bit] NOT NULL   DEFAULT ((0)),                                  
 [IsDnd] [bit] NOT NULL  DEFAULT ((0)),                                  
 [IsAirtel] [bit] NOT NULL   DEFAULT ((0)),                                  
 [MobileSubSet] [bigint] NULL,                                  
 [ValidNo] [tinyint] NULL ,                                
 [IsPrority] [tinyint] NULL,                                
 [IsAllowDND] [tinyint] NULL,                            
 [DBType] [nchar](10) NULL   DEFAULT ((0))                            
)'                                  
                                  
exec (@query)                                  
select  @tableName                                  
                                
                                 
SET @TRIG_QUERY='CREATE TRIGGER TRG_'+@tableName+'                                
ON '+@tableName+'                                
FOR INSERT                                 
AS                                
DECLARE @ROW_COUNT BIGINT                                
SET @ROW_COUNT=@@ROWCOUNT                                
                        
DECLARE @M_ID BIGINT                                
                                
DECLARE @USERID INT,                                          
@BATCHID BIGINT,                                                
@PRIORITY TINYINT,                                                
@ALLOWDND TINYINT,                                            
@ScheduleDate VARCHAR(50),                                            
@ScheduleTime VARCHAR(50),                                        
@IsUnicode bit,                                      
@PageName nvarchar(50),                                      
@UserFilter varchar(20),                                  
@TableName varchar(100),                                
@MESSAGE_LEN INT ,                                
@MESSAGE_LEN_TEMP INT  ,                            
@MESSAGE_LEN_MAXLEN BIGINT  ,                            
@MESSAGELEN_CLONE BIGINT,                            
@DBType nchar(10)   ,  @count int                            
                            
                            
SELECT                                 
@MESSAGE_LEN=1,                                
@BATCHID=BatchID,                                
@ALLOWDND=IsAllowDND,                                
@ScheduleDate=ScheduledDate,                                
@ScheduleTime=ScheduledTime,                                
@USERID=U_ID,                              
@IsUnicode=IsUniCode,                                
@PRIORITY=IsPrority,                                
@PageName=''CSV'',                                
@TableName='''+@tableName+''' ,                            
@DBType=DBType                                
FROM '+@tableName+'                              
     
select @count=COUNT(1)      
FROM inserted      
    
	 if( exists (select 1 from  '+@tableName+' where batchid=@batchid  and dbo.fn_IsUnicode(message) = 1 ))
     begin
	   set @IsUnicode = 1      
	 end
   else
     begin
	   set @IsUnicode = 0
	 end


if exists(select 1 from Link_smsUrl_dtl where BatchID =@BATCHID)  
begin  
  
select @count=COUNT(1) ,@id=MIN(messageid)       
FROM inserted    
  
DECLARE @result NCHAR(4),@shorturl nvarchar(100)  
select top 1 @shorturl=short_url from Link_smsUrl_dtl where BatchId=@BATCHID  
 --select @Parentid = Parent_id from Link_urlMaster where shorturl=@shorturl  
  
  
RETRY:                                             
BEGIN TRY                                          
BEGIN TRAN  
  
declare @dlcount int  
 select @dlcount= COUNT(*) from dbo.Link_smsMobile where status = 0 and  shorturl=@shorturl  
 --and Parentid = @Parentid  
if @dlcount > 0  
 begin  
 if @dlcount >= @count  
 begin  
  set @dlcount = @count  
  set @count=0  
 end  
 else  
 begin  
  set @count = @count-@dlcount  
 end  
 end   
   
 select row_number() over (order by randomexp) as id, randomexp into #temp from   
 (select top(@dlcount) Final_url randomexp from dbo.Link_smsMobile where status = 0 and shorturl=@shorturl  
 union all  
 select top (@count) randomexp    
 from randomexp where id>(select isnull(lastid,0) from Link_urlMaster where shorturl=@shorturl)   
 order by id) as aa  
 update Link_urlMaster set lastid=isnull(lastid,0)+@count where shorturl=@shorturl   
   
 --select top (@count) row_number() over (order by id) as id, randomexp    
 --into #temp from randomexp where id>(select isnull(lastid,0) from Link_urlMaster where shorturl=@shorturl)   
 --order by id  
 --update Link_urlMaster set lastid=isnull(lastid,0)+@count where shorturl=@shorturl   
  
COMMIT                                          
END TRY                                          
 --trans    
    
 --4444    
 --XXXX    
 --RRRR    
 --WWWW    
 select row_number() over (order by ProcessUrl_Id) as id,Mobile,ins.batchid, short_url,     
 longurl, ProcessUrl_Id,Parentid ,MessageID,Page_nm    
  into #temp2    
  from inserted ins inner join  Link_smsUrl_dtl lk    
  on lk.BatchId = ins.BatchID    
    
    
 insert into dbo.Link_smsMobile     
 (Mobile, batchid,shorturl, longurl,  ProcessUrl_id,Final_url,Parentid,MessageID,Page_nm)    
 select Mobile,batchid, short_url, longurl, ProcessUrl_Id,     
 randomexp,Parentid ,MessageID,Page_nm    
  from #temp ins inner join  #temp2 lk    
  on lk.id = ins.ID    
      
  update cl    
set Message = REPLACE(message,longurl, shorturl+''/''+Final_url)     
from dbo.CloneMessageDeliveryStatusLess cl inner join     
Link_smsMobile lm    
on lm.Mobile= cl.Mobile and lm.batchid = cl.BatchID    
where lm.batchid = @BATCHID    
end      
       
declare @deductcredits int=1,@hassufficientvirtualcredits bit=0,@parentsuperresellerid bigint       
select @parentsuperresellerid =parentsuperresellerid from user_detail where USER_ID=@USERID and HasVirtualCredits=1      
if @parentsuperresellerid is not null and @parentsuperresellerid <>335      
begin      
if (@hassufficientvirtualcredits is null or @hassufficientvirtualcredits=0)      
     begin      
  select *,len(A.message) as len,case when A.isunicode=0 and len(A.message)<=160  then 1 when A.isunicode=0 and LEN(A.message)>160 then ceiling(LEN(A.message)/cast(153 as FLOat)) when A.IsUniCode=1 and len(A.message)<=70 then 1 else ceiling(LEN(A.message
)  
    
/cast(67 as float)) end as Credits into #batchtobeprocessed from ' + @tablename + ' A where BatchID=@BATCHID      
  declare @creditsreqd bigint= (select sum(Credits) from #batchtobeprocessed where batchid=@batchid)      
  declare @balancecredits bigint = (select top 1 balance from SuperResellerCredit_Details where USER_ID=@parentsuperresellerid order by Credit_ID desc)      
 drop table #batchtobeprocessed       
  if (@balancecredits<@creditsreqd)      
  begin      
  set @deductcredits =0      
  Select ''Something went wrong & your SMS were not sent.Pl contact your admin for details. ''      
  end      
        end      
end      
      
if @deductcredits=1      
begin      
      
SELECT TOP(1) @UserFilter=UserFilter FROM MySMS.DBO.USER_DETAIL WHERE USER_ID=@USERID                            
      
                            
               
EXEC USP_INSERTINTOBATCHINFONewTestNew @USERID,                                            
@BATCHID,                                
@ROW_COUNT,                                              
@PRIORITY,                                       
@ALLOWDND,                                            
@ScheduleDate,                                           
@ScheduleTime,                                     
@IsUnicode,                                   
@PageName,                                   
@UserFilter,                                
@TableName,                      
@DBType                                 
                           
IF @IsUnicode=0                            
BEGIN                            
SELECT @MESSAGE_LEN_MAXLEN=isnull(sum(dbo.fn_GetMessageCount(len(message),isnull(@IsUnicode,0))),0),@MESSAGELEN_CLONE=count(message) FROM inserted with(nolock) where LEN(MESSAGE)>160 and batchid=@BATCHID                            
END                             
ELSE                       
BEGIN                            
SELECT @MESSAGE_LEN_MAXLEN=isnull(sum(dbo.fn_GetMessageCount(len(message),isnull(@IsUnicode,0))),0),@MESSAGELEN_CLONE=count(message) FROM inserted with(nolock) where LEN(MESSAGE)>70 and batchid=@BATCHID                          
END                            
                            
SET @ROW_COUNT=((@ROW_COUNT+isnull(@MESSAGE_LEN_MAXLEN,0))-isnull(@MESSAGELEN_CLONE,0))                            
                                
IF @PRIORITY=1                                
BEGIN                                
SET @ROW_COUNT=@ROW_COUNT*2                                
END                                
                                
SET @MESSAGE_LEN_TEMP=(SELECT [dbo].[fn_GetMessageCount](@MESSAGE_LEN,@IsUnicode))                                
                                
SET @ROW_COUNT=(@ROW_COUNT*@MESSAGE_LEN_TEMP)                                
                                
IF(@DBType >= 1)                            
BEGIN                            
SELECT @M_ID=MID FROM MyGroupAppComb.DBO.USER_DETAILS WHERE USERID=@USERID                            
                            
EXEC MyGroupAppComb.DBO.proc_UpdateCreditDetail @M_ID,@USERID,@ROW_COUNT,1                            
END                            
                            
ELSE IF(@DBType = 0)                            
BEGIN                            
SELECT @M_ID=M_ID FROM MySMS.DBO.USER_DETAIL WHERE USER_ID=@USERID                            
  set @PRIORITY=(select top (1)IsPrority from '+@tableName+' )                         
--EXEC MySMS.DBO.proc_UpdateCreditDetail @M_ID,@USERID,@ROW_COUNT,1       
EXEC MySMS.DBO.proc_UpdateCreditDetailvirtual @M_ID,@USERID,@ROW_COUNT,1,@BATCHID,@deductcredits      
end                         
END '                                  
print @TRIG_QUERY                               
EXEC (@TRIG_QUERY) 


GO

