CREATE   PROC [dbo].[usp_CreateCloneTable2]                                      
as                                        
Declare @query nvarchar(max)                                        
Declare @tableName varchar(100)                                        
DECLARE @TRIG_QUERY VARCHAR(max)                                      
                                        
select  @tableName='R'+convert(nvarchar,getdate(),112)+''+replace(convert(nvarchar,getdate(),114),':','')                                        
set @query='CREATE TABLE [dbo].['+@tableName+'](                                        
 [MessageID] [bigint] IDENTITY(1,1) NOT NULL,                                        
 [BatchID] [bigint] NOT NULL,                                        
 [Mobile] [varchar](20) ,                                        
 [Message] [nvarchar](2500) ,                                        
 [MessageStatus] [varchar](20) ,                                        
 [SenderID] [nchar](20) ,                                        
 [MessageInsertDate] [datetime] NOT NULL   DEFAULT (getdate()),                                        
 [ScheduledDate] [varchar](50) ,                                        
 [ScheduledTime] [varchar](50) ,                                        
 [SmppID] [tinyint] NOT NULL   DEFAULT ((1)),                                        
 [U_ID] [int] NOT NULL,                                        
 [IsUniCode] [bit] NOT NULL   DEFAULT ((0)),                                        
 [IsDnd] [bit] NOT NULL  DEFAULT ((0)),                                        
 [IsAirtel] [bit] NOT NULL   DEFAULT ((0)),                                        
 [MobileSubSet] [bigint] NULL,                                        
 [ValidNo] [tinyint] NULL ,                                      
 [IsPrority] [tinyint] NULL,                                      
 [IsAllowDND] [tinyint] NULL,                                  
 [DBType] [nchar](10) NULL   DEFAULT ((0)),
 [isflash] [bit] NULL  DEFAULT ((0))                                  
)'                                        
                                        
exec (@query)                                        
select  @tableName                                        
                                      
                                      
SET @TRIG_QUERY='CREATE TRIGGER TRG_'+@tableName+'                                      
ON '+@tableName+'                                      
FOR INSERT                                       
AS                                      
DECLARE @ROW_COUNT BIGINT                                      
SET @ROW_COUNT=@@ROWCOUNT                                      
                              
DECLARE @M_ID BIGINT                                      
                                      
DECLARE @USERID INT,                                                
@BATCHID BIGINT,                                                      
@PRIORITY TINYINT,                                                      
@ALLOWDND TINYINT,                                                  
@ScheduleDate VARCHAR(50),                                                  
@ScheduleTime VARCHAR(50),                                              
@IsUnicode bit,                                            
@PageName nvarchar(50),                                            
@UserFilter varchar(20),                                        
@TableName varchar(100),                                      
@MESSAGE_LEN INT ,                                      
@MESSAGE_LEN_TEMP INT  ,                                  
@MESSAGE_LEN_MAXLEN BIGINT  ,                                  
@MESSAGELEN_CLONE BIGINT,                                  
@DBType nchar(10)   ,  @count int,@id bigint ,@bmessage nvarchar(2000),@isflash bit                                 
 declare @extrachars int=0                                 
                                  
SELECT                  
@MESSAGE_LEN=1,                                      
@BATCHID=BatchID,                                      
@ALLOWDND=IsAllowDND,                                      
@ScheduleDate=ScheduledDate,                                      
@ScheduleTime=ScheduledTime,                       
@USERID=U_ID,                                      
@IsUnicode=IsUniCode,                                      
@PRIORITY=IsPrority,                                      
@PageName=''CSV'',                                      
@TableName='''+@tableName+''' ,                                  
@DBType=DBType                                      
FROM '+@tableName+'                                    
  
select top 1 @bmessage=message,
@isflash=isnull(isflash,0) from '+@tableName+' where batchid=@batchid  
           
   if( exists (select 1 from  '+@tableName+' where batchid=@batchid  and dbo.fn_IsUnicode(message) = 1 ))
     begin
	   set @IsUnicode = 1      
	 end
   else
     begin
	   set @IsUnicode = 0
	 end
    

select @count=COUNT(1) , @id=MIN(messageid)             
FROM inserted            
          
DECLARE @result NCHAR(4),@shorturl nvarchar(100)          
select top 1 @shorturl=short_url from Link_smsUrl_dtl where BatchId=@BATCHID          
          
--trans        
if exists(select 1 from Link_smsUrl_dtl where BatchID =@BATCHID)        
begin 
select @extrachars=(len(short_url)+7)-LEN(longurl) from Link_smsUrl_dtl where BatchId=@BATCHID   

if @extrachars<0
begin
set @extrachars=0
end

    
RETRY:                                                   
BEGIN TRY                                                
BEGIN TRAN         
 select top (@count) row_number() over (order by id) as id, randomexp          
 into #temp from randomexp where id>(select isnull(lastid,0) from Link_urlMaster where shorturl=@shorturl)         
 order by id        
 update Link_urlMaster set lastid=isnull(lastid,0)+@count where shorturl=@shorturl         
 
 create index ix_#temp_id on #temp(ID);
        
COMMIT                                                
END TRY                                                
                      
BEGIN CATCH                                                                                                    
IF @@TRANCOUNT>0                                                
ROLLBACK                                                
EXECUTE USP_INSERTERRORINFO;           
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number          
BEGIN          
WAITFOR DELAY ''00:00:00.05'' -- Wait for 5 ms          
GOTO RETRY           
END                                                     
END CATCH        
      
 select row_number() over (order by ProcessUrl_Id) as id,Mobile,ins.batchid, short_url,         
 longurl, ProcessUrl_Id,Parentid ,MessageID,Page_nm,p_url        
  into #temp2        
  from inserted ins inner join  Link_smsUrl_dtl lk        
  on lk.BatchId = ins.BatchID 
  
  create index ix_#temp2_id on #temp2(ID);       
        
 insert into dbo.Link_smsMobile         
 (Mobile, batchid,shorturl, longurl,  ProcessUrl_id,Final_url,Parentid,MessageID,Page_nm,p_url)        
 select Mobile,batchid, short_url, longurl, ProcessUrl_Id,         
 randomexp,Parentid ,MessageID,Page_nm ,p_url       
  from #temp ins inner join  #temp2 lk        
  on lk.id = ins.ID        
/*RETRY1:                                                   
BEGIN TRY                                                
BEGIN TRAN         
while @count>0        
begin          
 update cl        
 set Message = REPLACE(message,longurl, shorturl+''/''+Final_url)         
 from '+@tableName+' cl inner join         
 Link_smsMobile lm        
 on lm.Mobile= cl.Mobile and lm.batchid = cl.BatchID        
 where lm.batchid = @BATCHID and cl.messageid between @id and (@id+1000)    
          
 set @count=@count-1000        
 set @id=@id+1000        
end        
COMMIT                                                
END TRY                                                
                      
BEGIN CATCH                                                                                                    
IF @@TRANCOUNT>0                                                
ROLLBACK                                                
EXECUTE USP_INSERTERRORINFO;           
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number          
BEGIN          
WAITFOR DELAY ''00:00:00.05'' -- Wait for 5 ms          
GOTO RETRY1 -- Go to Label RETRY          
END                                                     
END CATCH
 
;WITH cte AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num
FROM '+@tableName+' where batchid=@batchid)
DELETE FROM cte WHERE row_num > 1;
;WITH cte1 AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num
FROM link_smsmobile where batchid=@batchid)
DELETE FROM cte1 WHERE row_num > 1;      
*/
end          
        
             
declare @deductcredits int=1,@hassufficientvirtualcredits bit=0,@parentsuperresellerid bigint             
            
if @deductcredits=1            
begin            
           
SELECT TOP(1) @UserFilter=UserFilter FROM MySMS.DBO.USER_DETAIL WHERE USER_ID=@USERID                                  
                                 
                     
EXEC USP_INSERTINTOBATCHINFONewTestNew1_flash @USERID,                                                  
@BATCHID,                                      
@ROW_COUNT,                                                    
@PRIORITY,                                             
@ALLOWDND,                                                  
@ScheduleDate,                                                 
@ScheduleTime,                                           
@IsUnicode,                                         
@PageName,                                         
@UserFilter,                                      
@TableName,                            
@DBType,@bmessage,@isflash                                       
'                                  
declare @qry1 varchar(max)        
set @qry1 = '     
IF @IsUnicode=0                                  
BEGIN                                  
SELECT @MESSAGE_LEN_MAXLEN=isnull(sum(dbo.fn_GetMessageCount((len(message)+@extrachars),isnull(@IsUnicode,0))),0),@MESSAGELEN_CLONE=count(message) FROM inserted with(nolock) where (len(message)+@extrachars)>160 and batchid=@BATCHID                                  
END                                   
ELSE                             
BEGIN                                  
SELECT @MESSAGE_LEN_MAXLEN=isnull(sum(dbo.fn_GetMessageCount((len(message)+@extrachars),isnull(@IsUnicode,0))),0),@MESSAGELEN_CLONE=count(message) FROM inserted with(nolock) where (len(message)+@extrachars)>70 and batchid=@BATCHID                                
END    
    
SET @ROW_COUNT=((@ROW_COUNT+isnull(@MESSAGE_LEN_MAXLEN,0))-isnull(@MESSAGELEN_CLONE,0))                                  
                                      
IF @PRIORITY=1                                      
BEGIN                                      
SET @ROW_COUNT=@ROW_COUNT*2                                      
END                                      
                                      
SET @MESSAGE_LEN_TEMP=(SELECT [dbo].[fn_GetMessageCount](@MESSAGE_LEN,@IsUnicode))                                      
                                      
SET @ROW_COUNT=(@ROW_COUNT*@MESSAGE_LEN_TEMP)                                      
                                      
                                 
SELECT @M_ID=M_ID FROM MySMS.DBO.USER_DETAIL WHERE USER_ID=@USERID                                  
  set @PRIORITY=(select top (1)IsPrority from '+@tableName+' )                               
--EXEC MySMS.DBO.proc_UpdateCreditDetail @M_ID,@USERID,@ROW_COUNT,1             
EXEC MySMS.DBO.proc_UpdateCreditDetailvirtual @M_ID,@USERID,@ROW_COUNT,1,@BATCHID,@deductcredits            
END '                                        
print @TRIG_QUERY+@qry1    
print @qry1                                     
EXEC (@TRIG_QUERY+@qry1)         
--declare @qry2 varchar(50)='TRG_'+@tableName        
--declare @q3 varchar(500)='ALTER TABLE '+@tableName+' DISABLE TRIGGER '+@qry2 





