if @deductcredits=1                          
begin                          
  set  @sms_source = isnull(@sms_source,'''')             
SELECT TOP(1) @UserFilter=UserFilter FROM MYSMS.dbo.USER_DETAIL WHERE USER_ID=@USERID'                                                
declare @qry1 varchar(max)                      
set @qry1 = '                      
EXEC USP_INSERTINTOBATCHINFONewTestNew1_Flash_FnlSendSMS @USERID,                                                                
@BATCHID,                                                    
@count,                                                                  
@PRIORITY,                                                           
@ALLOWDND,                                                                
@ScheduleDate,                                                               
@ScheduleTime,                                                         
@IsUnicode,                                                       
@PageName,                                                       
@UserFilter,                                                    
@TableName,                                          
@DBType,@bmessage,@isflash,@sms_source,@senderid                                                     
                   
IF @IsUnicode=0                                                
BEGIN                                                
SELECT @MESSAGE_LEN_MAXLEN=isnull(sum(dbo.fn_GetMessageCount((len(message)+@extrachars),isnull(@IsUnicode,0))),0),@MESSAGELEN_CLONE=count(message) FROM inserted with(nolock) where (len(message)+@extrachars)>160 and batchid=@BATCHID                       
  
     
     
        
           
           
                         
END                                                 
ELSE                                           
BEGIN                                                
SELECT @MESSAGE_LEN_MAXLEN=isnull(sum(dbo.fn_GetMessageCount((len(message)+@extrachars),isnull(@IsUnicode,0))),0),@MESSAGELEN_CLONE=count(message) FROM inserted with(nolock) where (len(message)+@extrachars)>70 and batchid=@BATCHID                         
  
    
      
        
          
            
                     
END                  
                  
SET @ROW_COUNT=((@ROW_COUNT+isnull(@MESSAGE_LEN_MAXLEN,0))-isnull(@MESSAGELEN_CLONE,0))                                                
                            
IF @PRIORITY=1                                                    
BEGIN                                                    
SET @ROW_COUNT=@ROW_COUNT*2                                                    
END                                                    
                                                    
SET @MESSAGE_LEN_TEMP=(SELECT [dbo].[fn_GetMessageCount](@MESSAGE_LEN,@IsUnicode))                                                    
                 
SET @ROW_COUNT=(@ROW_COUNT*@MESSAGE_LEN_TEMP)                                                    
                                                    
                                               
SELECT @M_ID=M_ID FROM MYSMS.dbo.USER_DETAIL WHERE USER_ID=@USERID                        
  set @PRIORITY=(select top (1)IsPrority from '+@tableName+' )                                             
--EXEC MYSMS_Dev.dbo.proc_UpdateCreditDetail @M_ID,@USERID,@ROW_COUNT,1                           
EXEC MYSMS.dbo.proc_UpdateCreditDetailvirtual @M_ID,@USERID,@ROW_COUNT,1,@BATCHID,@deductcredits                          
END '              
