declare @deductcredits int=1,@hassufficientvirtualcredits bit=0,@parentsuperresellerid bigint     
select @parentsuperresellerid =parentsuperresellerid from user_detail where USER_ID=@USERID and HasVirtualCredits=1    
if @parentsuperresellerid is not null and @parentsuperresellerid <>335    
begin    
if (@hassufficientvirtualcredits is null or @hassufficientvirtualcredits=0)    
     begin    
  select *,len(A.message) as len,case when A.isunicode=0 and len(A.message)<=160  then 1 when A.isunicode=0 and LEN(A.message)>160 then ceiling(LEN(A.message)/cast(153 as FLOat)) when A.IsUniCode=1 and len(A.message)<=70 then 1 else ceiling(LEN(A.message)
  
/cast(67 as float)) end as Credits into #batchtobeprocessed from ' + @tablename + ' A where BatchID=@BATCHID    
  declare @creditsreqd bigint= (select sum(Credits) from #batchtobeprocessed where batchid=@batchid)    
  declare @balancecredits bigint = (select top 1 balance from SuperResellerCredit_Details where USER_ID=@parentsuperresellerid order by Credit_ID desc)    
 drop table #batchtobeprocessed     
  if (@balancecredits<@creditsreqd)    
  begin    
  set @deductcredits =0    
  Select ''Something went wrong & your SMS were not sent.Pl contact your admin for details. ''    
  end    
        end    
end '                          
