/* ============================================================
   Procedure: [dbo].[usp_CreateCloneTableAndPopulateForSegmentation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE [dbo].[usp_CreateCloneTableAndPopulateForSegmentation]---- in mysms
    @entities dbo.entities READONLY, -- user-defined table type expected
    @actiondetails NVARCHAR(MAX),
    @entityplaceholders NVARCHAR(MAX),
    @batchid BIGINT,
    @type VARCHAR(100),
    @sequenceactionid BIGINT,
    @senderid NVARCHAR(50) = NULL,
    @scheduleddate VARCHAR(50) = NULL,
    @scheduledtime VARCHAR(50) = NULL
AS
BEGIN
    SET NOCOUNT ON;
 
    DECLARE @tableName NVARCHAR(200);
 
    -- Create dynamic clone table and capture returned name
    CREATE TABLE #tblName(name NVARCHAR(200));
    INSERT INTO #tblName
    EXEC dbo.usp_CreateCloneTable2_FnlSendSMS_new1;
 
    SELECT TOP (1) @tableName = name FROM #tblName;
    DROP TABLE #tblName;
 
    IF @tableName IS NULL OR LEN(@tableName)=0
    BEGIN
        RAISERROR('Failed to create clone table.',16,1);
        RETURN;
    END
 
    -- Add ubc_id column to the dynamic clone table
    DECLARE @alterSql NVARCHAR(MAX) = N'ALTER TABLE dbo.[' + @tableName + N'] ADD ubc_id BIGINT NULL';
    EXEC sp_executesql @alterSql;
 
    -- If entityplaceholders not supplied, extract from actiondetails using first entity
    DECLARE @firstEntity NVARCHAR(50);
    SELECT TOP (1) @firstEntity = entity FROM @entities;
    IF ISNULL(@entityplaceholders,'') = '' AND ISNULL(@firstEntity,'') <> ''
    BEGIN
        SET @entityplaceholders = dbo.ExtractPlaceholders(@firstEntity, @actiondetails);
    END
 
    -- If batchid not provided (0 or NULL), create a temporary batch id via GetBatchRecord
    IF ISNULL(@batchid,0) = 0
    BEGIN
        DECLARE @newBatch BIGINT;
        BEGIN TRAN;
        INSERT INTO GetBatchRecord ([User_id], RandNum)
        VALUES (ISNULL(@sequenceactionid,0), ISNULL(@sequenceactionid,0));
        SELECT @newBatch = SCOPE_IDENTITY();
        DELETE FROM GetBatchRecord WHERE BatchId = @newBatch;
        COMMIT;
        SET @batchid = @newBatch;
    END
 
    -- Call replace SP to populate mass_replaced_content
    EXEC dbo.usp_replaceentityplaceholders_bulk_singlecontent_tableinsert_new1
        @entities = @entities,
        @actiondetails = @actiondetails,
        @entityplaceholders = @entityplaceholders,
        @batchid = @batchid,
        @type = @type,
        @sequenceactionid = @sequenceactionid;
 
    -- Insert into dynamic clone table from mass_replaced_content joining to appropriate view for Mobile
    DECLARE @sql NVARCHAR(MAX);
 
    -- Insert lead entities (if any)
    SET @sql = N'
    INSERT INTO dbo.[' + @tableName + N'] (
        BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate,
        ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel,
        MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, isflash, sms_source,
        DT_CreatedBy, ubc_id)
    SELECT
        m.batchid,
        v.Mobile,
        m.replacedcontent,
        N'' AS MessageStatus,
        ISNULL(@snd, NULL) AS SenderID,
        GETDATE() AS MessageInsertDate,
        ISNULL(@sdate, NULL) AS ScheduledDate,
        ISNULL(@stime, NULL) AS ScheduledTime,
        1 AS SmppID,
        v.CreatedBy AS U_ID,
        0 AS IsUniCode,
        0 AS IsDnd,
        0 AS IsAirtel,
        0 AS MobileSubSet,
        1 AS ValidNo,
        0 AS IsPrority,
        0 AS IsAllowDND,
        N''0'' AS DBType,
        0 AS isflash,
        N''ubc'' AS sms_source,
        v.CreatedBy AS DT_CreatedBy,
        @b AS ubc_id
    FROM mass_replaced_content m
    JOIN v_ul v ON v.ID = m.entityid
    WHERE m.batchid = @b AND m.type = @t AND m.sequenceactionid = @s AND m.entity = ''lead''';
 
    EXEC sp_executesql @sql,
        N'@b bigint,@t varchar(100),@s bigint,@snd nvarchar(50),@sdate varchar(50),@stime varchar(50)',
        @b = @batchid, @t = @type, @s = @sequenceactionid, @snd = @senderid, @sdate = @scheduleddate, @stime = @scheduledtime;
 
    -- Insert enquiry entities (if any)
    SET @sql = N'
    INSERT INTO dbo.[' + @tableName + N'] (
        BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate,
        ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel,
        MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, isflash, sms_source,
        DT_CreatedBy, ubc_id)
    SELECT
        m.batchid,
        v.Mobile,
        m.replacedcontent,
        N'' AS MessageStatus,
        ISNULL(@snd, NULL) AS SenderID,
        GETDATE() AS MessageInsertDate,
        ISNULL(@sdate, NULL) AS ScheduledDate,
        ISNULL(@stime, NULL) AS ScheduledTime,
        1 AS SmppID,
        v.CreatedBy AS U_ID,
        0 AS IsUniCode,
        0 AS IsDnd,
        0 AS IsAirtel,
        0 AS MobileSubSet,
        1 AS ValidNo,
        0 AS IsPrority,
        0 AS IsAllowDND,
        N''0'' AS DBType,
        0 AS isflash,
        N''ubc'' AS sms_source,
        v.CreatedBy AS DT_CreatedBy,
        @b AS ubc_id
    FROM mass_replaced_content m
    JOIN v_userenquiry v ON v.enquiryID = m.entityid
    WHERE m.batchid = @b AND m.type = @t AND m.sequenceactionid = @s AND m.entity = ''enquiry''';
 
    EXEC sp_executesql @sql,
        N'@b bigint,@t varchar(100),@s bigint,@snd nvarchar(50),@sdate varchar(50),@stime varchar(50)',
        @b = @batchid, @t = @type, @s = @sequenceactionid, @snd = @senderid, @sdate = @scheduleddate, @stime = @scheduledtime;
 
    -- Return created table name for caller if desired
    SELECT @tableName AS CreatedCloneTable, @batchid AS CreatedBatchId;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_CreateDefaultFollowupStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_CreateDefaultFollowupStatus
(
  @ParentId bigint = null 
)
as
begin

   If(isnull(@ParentId,0) > 0 and not exists (SELECT * FROM FollowUp_status(NOLOCK) FUM WHERE FUM.ParentId = @ParentId))    
	 Begin    
	  print 'User followup does not exist'    
	  Insert into FollowUp_status(FollowupStatus,OrderNumber,IsActive,Intent,IsCallback,IsConvert,IsDisabled,ParentId,CreatedBy,CreatedDate)    
	  SELECT FollowupStatus,OrderNumber,IsActive,Intent,IsCallback,IsConvert,0 as IsDisabled,@ParentId as ParentId,@ParentId as CreatedBy,getdate() as CreatedDate    
	  FROM FollowUp_status(NOLOCK) UTM        
	  WHERE UTM.ParentId IS NULL AND UTM.IsActive = 1        
	  ORDER BY IsDisabled desc, OrderNumber ASC     
	 End             

end


