/* ============================================================
   Procedure: [dbo].[usp_createDynamicPivotTable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_createDynamicPivotTable
  @ColumnToPivot  NVARCHAR(255),
  @ListToPivot    NVARCHAR(255),
  @parentid bigint,@fromdate date,@todate date
AS
BEGIN
 
  DECLARE @SqlStatement NVARCHAR(MAX)
  SET @SqlStatement = N'
    SELECT * FROM (
      select user_login,f.followupstatus,sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count
      from leadinteractionhistory(nolock) l 
join user_detail(nolock) ul on ul.User_ID=l.createdby
join followup_status(nolock) f on f.ID=l.FollowUpStatus
where l.parentid='+cast(@parentid as nvarchar)+' and IsReassign=0 and createdon between '+
cast(@fromdate as nvarchar)+' and '+cast(@todate as nvarchar)+'
group by user_login,f.followupstatus
    ) FollowupsDone
    PIVOT (
      SUM([Count])
      FOR ['+@ColumnToPivot+']
      IN (
        '+@ListToPivot+'
      )
    ) AS PivotTable
  ';
 
  EXEC(@SqlStatement)
 
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_CreateEnquiryJson]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


------------------------------------------------------------------------------
CREATE   PROCEDURE [dbo].[Usp_CreateEnquiryJson]    
(    
    @EventName NVARCHAR(100),    
    @Operation NVARCHAR(50),    
    @Points INT,    
    @tblAttr EnquiryScoreAttributes READONLY    
)    
AS    
BEGIN    
    -- Create a temporary table to store rule information
    CREATE TABLE #rules(id INT IDENTITY(1,1), EventName NVARCHAR(100), Operation NVARCHAR(50), Points INT);    
    
    -- Insert the rule data into the temporary table
    INSERT INTO #rules(EventName, Operation, Points)    
    VALUES (@EventName, @Operation, @Points);    
 
    -- Create a temporary table to store rule details
    CREATE TABLE #ruledetails(Eventid INT, EventAttribute NVARCHAR(100), Operator NVARCHAR(50), ComparisonValue NVARCHAR(MAX));    
    
    -- Insert the details of each attribute into the temporary table
    INSERT INTO #ruledetails(Eventid, EventAttribute, Operator, ComparisonValue)    
    SELECT 1, EventAttribute, Operator, ComparisonValue FROM @tblAttr;    
 
    -- Generate JSON from the temporary tables
    DECLARE @json NVARCHAR(MAX) =    
    (SELECT 
        EventName, 
        Operation, 
        Points,    
        (SELECT    
            EventAttribute AS [Attribute], 
            Operator, 
            ComparisonValue AS [Value]    
         FROM #ruledetails d 
         WHERE r.id = d.Eventid    
         FOR JSON PATH    
        ) AS Conditions    
     FROM #rules r    
     FOR JSON PATH, ROOT ('Rule'));    
 
    -- Clean up the JSON structure to remove unnecessary parts
    SELECT @json = REPLACE(REPLACE(@json,'{"Rule":',''),'}]}]}','}]}]');    
 
    -- Output the JSON result
    SELECT @json;     
        
    -- Drop the temporary tables
    DROP TABLE #rules;    
    DROP TABLE #ruledetails;    
 
END;  



GO

/* ============================================================
   Procedure: [dbo].[Usp_CreateJson]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_CreateJson  
(  
  @EventName nvarchar(100),  
  @Operation nvarchar(50),  
  @Points int,  
  @tblAttr LeadScoreAttributes readonly  
)  
as  
Begin  
    create table #rules(id int identity(1,1),EventName nvarchar(100),Operation nvarchar(50),Points int)  
insert into #rules(EventName,Operation,Points)  
  values(@EventName,@Operation,@Points)   
  
--values ('Lead Added','Add',5)  
  
create table #ruledetails(Eventid int,EventAttribute nvarchar(100),Operator nvarchar(50),ComparisonValue nvarchar(max))  
insert into #ruledetails(Eventid,EventAttribute,Operator,ComparisonValue)  
select 1, EventAttribute,Operator,ComparisonValue from @tblAttr  
  
  
--values (1,'Createdon','>=','20200101'),  
--(1,'Createdon','<=','20210101')  
  
declare @json nvarchar(max)=  
(select Eventname as EventName,Operation,Points,  
(select  
EventAttribute as [Attribute],Operator as [Operator],ComparisonValue as [Value]  
from #ruledetails d where r.id=d.Eventid  
for json path  
) as Conditions  
from #rules r  
for json path,root ('Rule'))  
  
   --json for lead scoring rules  
  
 select @json=replace(replace(@json,'{"Rule":',''),'}]}]}','}]}]')  
 --'[{"EventName":"Lead Added","Operation":"Add","Points":5,"Conditions":[{"Attribute":"Createdon","Operator":">=","Value":"20200101"},{"Attribute":"Createdon","Operator":"<=","Value":"20210101"}]}]'  
  --{"Rule":[{"EventName":"Lead Added","Operation":"Add","Points":5,"Conditions":[{"Attribute":"Createdon","Operator":">=","Value":"20200101"},{"Attribute":"Createdon","Operator":"<=","Value":"20210101"}]}]}  
  
  
   select @json   
     
   drop table #rules  
   drop table #ruledetails  
  
  
end  


