CREATE   PROCEDURE [dbo].[Usp_createProductMasterTable]  
(  
  @ParentID bigint  
)  
as  
Begin  
     if((@ParentID is not null) and (@ParentID <> 0))  
   Begin  
         Declare @Qtbl Nvarchar(max) = N' CREATE TABLE [dbo].[tbl_productmaster_'+cast(@ParentID as nvarchar(max))+'](  
 [ProductID] [bigint] IDENTITY(1,1) NOT NULL,  
 [Name] [nvarchar](500) NOT NULL,  
 [UserID] [int] NOT NULL,  
 [Image] [nvarchar](100) NULL,  
 [Description] [nvarchar](200) NULL,  
 [Price] [numeric](18, 2) NULL,  
 [IsPublished] [bit] NULL,  
 [IsActive] [bit] NULL,  
 [CreatedOn] [datetime] NULL,  
 [CreatedBy] [bigint] NULL,  
 [FullPath] [varchar](max) NULL,  
 [IsFeatured] [bit] NOT NULL,  
 [sku] [nvarchar](500) NULL,  
 [sale_priceNoUSE] [numeric](18, 2) NULL,  
 [quantity] [int] NULL,  
 [category_id] [int] NULL,  
 [HomeTaxIDs] [nvarchar](max) NULL,  
 [OtherTaxIDs] [nvarchar](max) NULL,  
 [tax_idNoUSE] [bigint] NULL,  
