 [UnitID] [int] NULL,  
 [IsSaleable] [bit] NULL,  
 [ThumbnailUrl] [Nvarchar](1000) Null,
 [VariantsJson] [nvarchar](max) NULL,   
 [VCombinationJson] [nvarchar](max) NULL,
PRIMARY KEY CLUSTERED   
(  
 [ProductID] ASC  
)WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON, ALLOW_PAGE_LOCKS = ON) ON [PRIMARY]  
) ON [PRIMARY] TEXTIMAGE_ON [PRIMARY]  
  
  
ALTER TABLE [dbo].[tbl_productmaster_'+cast(@ParentID as nvarchar(max))+'] ADD  DEFAULT ((0)) FOR [IsPublished]  
  
  
ALTER TABLE [dbo].[tbl_productmaster_'+cast(@ParentID as nvarchar(max))+'] ADD  DEFAULT ((1)) FOR [IsActive]  
  
  
