SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_CreateProductTableByParentID]   --old   
@userid bigint,      
@tableName nvarchar(max) output      
As       
BEGIN      
 declare @parentid bigint = (Select ParentID from User_Detail where user_id = @userid)          
 declare @sqls nvarchar(max) = ''       
 if Exists (Select 1 From User_Detail where User_ID=@userid)      
 BEGIN      
         
  SET @tableName = 'tbl_productmaster_'+cast(@parentid as varchar)        
      
  IF NOT EXISTS (select 1 from INFORMATION_SCHEMA.TABLES where TABLE_NAME=@tableName and TABLE_CATALOG=db_name())
   BEGIN          
   set @sqls='CREATE TABLE '+@tableName+' (          
   [ProductID] [bigint] IDENTITY(1,1) Primary Key,          
   [Name] [nvarchar](500) NOT NULL,          
   [UserID] [int] NOT NULL,          
   [Image] [nvarchar](100) NULL,          
   [Description] [nvarchar](200) NULL,          
   [Price] [numeric](18, 2) NULL,          
   [IsPublished] [bit] Default 0,          
   [IsActive] [bit] Default 1,          
   [CreatedOn] [datetime] NULL,          
   [CreatedBy] [bigint] NULL,          
   [FullPath] [varchar](max) NULL,          
   [IsFeatured] [bit] NOT NULL Default 0,          
   [sku] [nvarchar](500) NULL,          
     
   [quantity] [int] NULL,          
   [category_id] [int] NULL,          
   [HomeTaxIDs] [nvarchar](max) NULL,          
   [OtherTaxIDs] [nvarchar](max) NULL,          
            
   [UpdatedAt] [datetime] NULL,          
   [DeletedAt] [datetime] NULL,          
   [SellingAccount] [bigint] NULL,          
   [CostPrice] [numeric](18, 2) NULL,          
   [Cast_Account] [bigint] NULL,          
   [IsDigitalService] [bit] Default 0,          
   [IsGoods] [bit] Default 0,          
   [IsServices] [bit] Default 0,          
   [SACCode] [nvarchar](50) NULL,          
   [HSNCode] [nvarchar](50) NULL,          
   [IsTaxable] [bit] Default 0,          
   [DecimalRateItemQuantity] [int] Default 0,          
   [UnitID] [int] NULL,          
   [IsSaleable] [bit] Default 0,
   [ThumbnailUrl] [Nvarchar](1000),
    [VariantsJson] [nvarchar](max) NULL,   
	 [VCombinationJson] [nvarchar](max) NULL
   )'          
   execute sp_executesql @sqls         
         
   return 1      
   END        
   ELSE       
   BEGIN      
         
   return 1      
   END      
 END      
 ELSE      
 BEGIN      
  print 'UserId Not Exists'      
  return 0      
 END      
END 


