/* ============================================================
   Procedure: [dbo].[Usp_CreateTable_customfieldEnquiryvalueByParentID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_CreateTable_customfieldEnquiryvalueByParentID] --0,''      
	(
	@UserID BIGINT
	,@TableName NVARCHAR(200) OUTPUT
	)
AS
BEGIN
	DROP TABLE

	IF EXISTS #tempTBL
	BEGIN TRY
		DECLARE @ParentID BIGINT ;

		IF EXISTS (
				SELECT 1
				FROM User_Detail WITH (NOLOCK)
				WHERE User_ID = @UserID
				)
		BEGIN
			
			set @ParentID  = isnull((
					SELECT isnull(ParentID, 0)
					FROM User_Detail WITH (NOLOCK)
					WHERE User_ID = @UserID
					), 0)
			
			SET @TableName = 'customfieldEnquiryvalue_' + cast(@ParentID AS NVARCHAR(50))

			IF NOT EXISTS (
					SELECT 1
					FROM INFORMATION_SCHEMA.TABLES
					WHERE TABLE_NAME = @TableName
						AND TABLE_CATALOG = DB_NAME()
					)
			BEGIN
				IF (
						EXISTS (
							SELECT 1
							FROM customfields WITH (NOLOCK)
							WHERE ParentID = @ParentID
								AND isnull(isActive, 0) = 1
							)
						)
				BEGIN
					SELECT ROW_NUMBER() OVER (
							ORDER BY sequence ASC
							) AS RowNum
						,field_ID
						,fieldname
						,(
							CASE 
								WHEN datatype = 'v'
									THEN '[nvarchar](max)'
								WHEN datatype = 'f'
									THEN '[numeric](18,2)'
								WHEN datatype = 'm'
									THEN '[money]'
								WHEN datatype = 'd'
									THEN '[datetime]'
								WHEN datatype = 's'
									THEN '[nvarchar](max)'
								--WHEN datatype = 'r'
								--	THEN '[bit]'
								ELSE '[nvarchar](max)'
								END
							) AS datatype
						,defaultvalue
						,currentDate
						,isActive
						,[sequence]
					INTO #tempTBL
					FROM customfields WITH (NOLOCK)
					WHERE ParentID = @ParentID
						AND isnull(isActive, 0) = 1

					DECLARE @Count INT = 0
						,@RowNum INT = 1
					DECLARE @Query NVARCHAR(max) = ''
					DECLARE @QuerySingle NVARCHAR(max) = ''

					SELECT @Count = isnull((
								SELECT count(1)
								FROM #tempTBL
								), 0)

					WHILE (@Count > 0)
					BEGIN
						SELECT @QuerySingle = '[' + fieldname + ']' + ' ' + datatype + ' ' + CASE 
								WHEN defaultValue IS NOT NULL
									AND currentDate = 1
									THEN ' default getdate() '
								WHEN defaultValue IS NOT NULL
									AND isnull(currentDate, 0) = 0
									AND isnull(defaultValue, '') <> 0
									THEN ' default ' + CASE 
											WHEN isnumeric(cast(defaultValue AS NVARCHAR(max))) = 1
												THEN cast(defaultValue AS NVARCHAR(max))
											ELSE '''' + cast(defaultValue AS NVARCHAR(max)) + ''''
											END
								ELSE ' null '
								END
						FROM #tempTBL
						WHERE RowNum = @RowNum

						SET @RowNum = @RowNum + 1
						SET @Count = @Count - 1

						IF (@Count = 0)
						BEGIN
							SET @Query = CONCAT (
									@Query
									,' '
									,@QuerySingle
									,' '
									)
							SET @Query = CONCAT (
									N' CREATE TABLE ' + @tableName + ' (            
                               [ID] [bigint] IDENTITY(1,1) Primary Key,  
          [EnquiryID] [bigint] null ,  
  
           '
									,@Query
									,' , CreatedDate datetime default getdate() , CreatedBy bigint null ) '
									)
						END
						ELSE
						BEGIN
							SET @Query = CONCAT (
									@Query
									,' '
									,@QuerySingle
									,' , '
									)
						END
					END

					PRINT @Query

					IF (@Query <> '')
					BEGIN
						BEGIN TRY
							EXEC sp_executesql @Query

							EXEC Usp_TransferAndUpdateIntocustomfieldEnquiryvalueByParentID @ParentID
						END TRY

						BEGIN CATCH
							EXEC usp_InsertErrorInfo
						END CATCH

						RETURN 1
					END
					ELSE
					BEGIN
						SELECT @tableName = 'No Custom Field Exists'

						RETURN 0
					END
				
				--BEGIN TRY
				--	EXEC Usp_TransferAndUpdateIntocustomfieldEnquiryvalueByParentID @ParentID
				--END TRY

				--BEGIN CATCH
				--	EXEC usp_insertErrorInfo
				--END CATCH

				--RETURN 1
               END
			   else
			    Begin
				  SELECT @tableName = 'No Custom Field Exists'

						RETURN 0

				end
			END
			ELSE
			BEGIN
				BEGIN TRY
					EXEC Usp_TransferAndUpdateIntocustomfieldEnquiryvalueByParentID @ParentID
				END TRY

				BEGIN CATCH
					EXEC usp_InsertErrorInfo
				END CATCH

				RETURN 1
			END
		END
		ELSE
		BEGIN
			SELECT @tableName = 'UserID Does Not Exist'

			RETURN 0
		END
	END TRY

	BEGIN CATCH
		EXEC usp_InsertErrorInfo
	END CATCH

	DROP TABLE

	IF EXISTS #tempTBL END



GO

