as      
Begin      

     drop table if exists #tempTBL       

     Declare @ParentID bigint = isnull((select isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @UserID),0)         
      
     if Exists (Select 1 From User_Detail with(nolock) where User_ID=@UserID)          
      BEGIN      
      
     SET @TableName = 'CustomFieldLeadValue_'+cast(@ParentID as nvarchar(50))           
     IF NOT EXISTS (select 1 from INFORMATION_SCHEMA.TABLES where TABLE_NAME=@TableName and TABLE_CATALOG=DB_NAME())              
            BEGIN        
      if(exists (select 1 from customfields with(nolock) where ParentID = @ParentID   
                               and isnull(isActive,0) = 1   
     ))      
        Begin      
                    select ROW_NUMBER() over(order by sequence asc) as RowNum,field_ID, fieldname,  
              (case when datatype = 'v'  
               then '[nvarchar](max)'  
      when datatype = 'f'  
                        then '[numeric](18,2)'  
      when datatype = 'm'  
                        then '[money]'  
      when datatype = 'd'  
                        then '[datetime]'  
      when datatype = 's'  
                        then '[nvarchar](max)'  
      --when datatype = 'r'  
      --                  then '[bit]'    
      else '[nvarchar](max)'  
      end   
           ) as datatype,defaultvalue,currentDate,isActive,[sequence] into #tempTBL from customfields with(nolock) where ParentID = @ParentID  
        and isnull(isActive,0) = 1           
  
  
                  declare @Count int = 0, @RowNum int = 1  
      declare @Query nvarchar(max) = ''  
      declare @QuerySingle nvarchar(max) = ''  
  
      select  @Count = isnull((select count(1) from #tempTBL),0)      
  
  
        while(@Count > 0)  
       Begin  
             select @QuerySingle =  '[' + fieldname + ']' + ' '  
              + datatype + ' '   
        + case when defaultValue is not null and currentDate = 1  
             then ' default getdate() '  
          when  defaultValue is not null and isnull(currentDate,0) = 0 and  isnull(defaultValue,'') <> 0  
                                     then ' default '+  case when  isnumeric(cast(defaultValue as nvarchar(max))) = 1  
                             then cast(defaultValue as nvarchar(max))  
              else '''' + cast(defaultValue as nvarchar(max)) + ''''   
              end     
          else   
           ' null '  
          end      
             from #tempTBL where RowNum = @RowNum   
   
            set @RowNum = @RowNum + 1        
            set @Count = @Count - 1    
                       if(@Count = 0)  
          begin  
            set @Query = concat(@Query, ' ' ,@QuerySingle  ,' ')    
                  
        set @Query = Concat( N' CREATE TABLE '+@tableName+' (            
                               [ID] [bigint] IDENTITY(1,1) Primary Key,  
          [EnquiryID] [bigint] null , [LeadID] [bigint] null , 
  
           ',@Query , ' , CreatedDate datetime default getdate() , CreatedBy bigint null ) ')          
         
       end  
       else  
        begin  
            set @Query = concat(@Query, ' ' ,@QuerySingle ,' , ')    
           
         end       
       End  
  
     -- print @Query  
      if(@Query <> '')  
       begin  
	       begin try     
             exec sp_executesql @Query
		     exec [Usp_TransferAndUpdateIntoCustomFieldLeadValueByParentID] @ParentID		  
		   end try
		   begin catch
		     exec usp_InsertErrorInfo
		   end catch	
				     
       return 1   
       end    
      else  
       Begin  
          Select @tableName = 'No Custom Field Exists'          
                      return 0           
       end  
        End 
		   --begin try 
	    --    exec [Usp_TransferAndUpdateIntoCustomFieldLeadValueByParentID] @ParentID	 	       
     --      end try
		   --begin catch
		   --  exec usp_InsertErrorInfo
		   --end catch  
	 return 1           
   END      
            Else      
   Begin      
    --   begin try   
    --     exec [Usp_TransferAndUpdateIntoCustomFieldLeadValueByParentID] @ParentID	 
    --   end try
	   --begin catch
		  -- exec usp_InsertErrorInfo
	   --end catch         
	 return 1                  
   End        
      
      End      
   else      
   Begin      
      Select @tableName ='UserID Does Not Exist'          
         return 0        
   End          
      
 drop table if exists #tempTBL  
  
end


GO

