SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------

CREATE   PROCEDURE  [dbo].[USP_CreateUspSpamMessageEditor]  
@Spam_Words nvarchar(100)   
AS    
SET NOCOUNT ON
if exists(select Spam_Words from SpamKeyWords where Spam_Words=@Spam_Words)  
begin  
select '0'  
end  
else  
begin  
insert into SpamKeyWords(Spam_Words)values(@Spam_Words)  
select 'Spam Key Word Added Successfully'  
end  
 






