CREATE   PROCEDURE usp_createvariantcolumn
as
begin
drop table if exists #t
declare @c int, @name nvarchar(100) ='',@id bigint=0,@sql nvarchar(max)
select s.name,s.object_id  as oid into #t 
from sys.tables s where name like 'tbl_productmaster_%'
and not exists
(select 1 from sys.all_columns where object_id(s.name)=object_id and (name='Variantsjson' or name='vcombinationjson'))
select @c=count(1) from #t
while @c>0
begin
select @id=min(oid) from #t where oid>@id
select @name=min(name) from #t where oid=@id
print concat('tablename: ',@name, ', count left: ',@c)
select @sql='alter table '+quotename(@name)+ ' add VariantsJson nvarchar(max),VCombinationJson nvarchar(max)'
begin try
print @sql
exec sp_executesql @sql
end try
begin catch
exec usp_InsertErrorInfo
end catch

set @c=@c-1
end

end


GO

