SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Usp_Createwebform11                
                
--sp_helptext Usp_Createwebform11                  
                  
--sp_helptext Usp_Createwebform11                    
--exec dbo.Usp_Createwebform11 3, 9,335,335,'D:\\Kit19-04012018\\UserCRMCampaign\\Uploads\\WebForms\\335\\aaa.txt',                    
--'aaa','allure','335','16301',                    
--'asfd','asfd','',0,true,true,true,true,true,299,'',true,303,335,true,0                    
                    
                    
                     
CREATE   PROCEDURE dbo.Usp_Createwebform11                                                     
(                                
 @Option int,                                                      
 @FormId bigint = 0,                              
 @UserID bigint = 0,                              
 @PrentId bigint = 0,                              
 @FilaePath nvarchar (max) = '' ,                              
 @FormName nvarchar (max) = '',                              
 @SenderEmail nvarchar (max) = '',                              
 @EmailAccountName nvarchar (max) = '',                         
 @SmsAccountName nvarchar (max) = '',                              
 @ReplyEmail nvarchar (max) = '',                              
 @MailSubject nvarchar (max) = '',                              
 @MailBody nvarchar (max) = '',                              
 @FormType nvarchar (max) = '',                              
 @Issms bit  = false,                              
 @Isemail bit  = false,                              
 @Iswebhook bit  = false,                              
 @isEnquiry bit  = false ,                             
 @smstemplate bit = 0,                             
 @smstemplateid bigint = 0,                            
 @smsbody nvarchar(max) = '',                            
 @emailtemplate bit = 0,                             
 @emailtemplateid bigint = 0,                             
 @CreatedBy bigint = null ,                       
 @IsUniCode bit = false,                             
 @Status tinyint = null,              
 @recvmobile nvarchar(MAX) = '' ,               
 @recvMessage nvarchar(MAX) = '' ,               
 @isrecvunicode bit = false  ,              
 @recvemail nvarchar(MAX) = '',              
 @recvmsub nvarchar(MAX) = '',                
 @recvmbody nvarchar(MAX) = '',        
 @isticket bit  = false ,          
 @priority tinyint =0,         
 @tktType tinyint =0,         
 @Email_Ctrl nvarchar(MAX) = '',        
 @Sub_Ctrl nvarchar(MAX) = '',        
 @Desc_Ctrl nvarchar(MAX) = ''                              
                             
                            
)                                                     
                                                      
as                               
                              
Begin                          
                        
--declare @IsUniCode as bit = 0                            
if (@Option = 1)                              
begin                              
select  COUNT(*) from WebFormTbl where  ParentId = @PrentId and FormName = @FormName                                  
end                              
if (@Option = 2)                              
begin                              
 insert into WebFormTbl (UserID,ParentId ,FilePath ,FormName ,SenderEmail ,SmsAccountName ,ReplyEmail,           
  MailSubject ,MailBody ,FormType ,Issms ,Isemail ,Iswebhook ,isEnquiry ,                            
 smstemplate, smstemplateid, smsbody, emailtemplate, emailtemplateid ,                             
 CreatedBy ,EmailAccountName,IsUniCode,              
 recvmobile, recvMessage, isrecvunicode, recvemail, recvmsub, recvmbody,         
 isticket, priority, tktType, Email_Ctrl, Sub_Ctrl, Desc_Ctrl)                              
              
 values (@UserID,@PrentId ,@FilaePath ,@FormName ,@SenderEmail ,@SmsAccountName ,@ReplyEmail,                    
  @MailSubject ,@MailBody ,@FormType ,@Issms ,@Isemail ,@Iswebhook ,@isEnquiry ,                             @smstemplate, @smstemplateid, @smsbody, @emailtemplate, @emailtemplateid ,                             
 @CreatedBy ,@EmailAccountName, @IsUniCode,             
 @recvmobile, @recvMessage, @isrecvunicode, @recvemail, @recvmsub, @recvmbody,         
 @isticket, @priority, @tktType, @Email_Ctrl, @Sub_Ctrl, @Desc_Ctrl)                              
 declare @idInst as bigint                      
set @idInst = SCOPE_IDENTITY();                      
if (@isEnquiry=1)                begin                      
 exec [Usp_InsertPreDefinedUserCampaignMaster_NEW]  @PrentId,@UserID,@idInst,@FormName,@smsbody,                    
 @IsUniCode,@ReplyEmail,@MailSubject,@MailBody,@SenderEmail,@IsSms,@IsEmail,@SmsAccountName,                    
 @EmailAccountName,@SMStemplateid,@eMailtemplateid, 'Web Form'                       
 end  
 

                             
 select  @idInst                              
end                              
if (@Option = 3)                       
begin                      
  update WebFormTbl set FilePath=@FilaePath ,FormName=@FormName ,SenderEmail=@SenderEmail ,        
  SmsAccountName=@SmsAccountName, EmailAccountName = @EmailAccountName ,ReplyEmail=@ReplyEmail,        
  MailSubject=@MailSubject ,MailBody=@MailBody,UserID = @UserID , FormType=@FormType ,        
  Issms=@Issms ,Isemail=@Isemail ,Iswebhook=@Iswebhook ,isEnquiry=@isEnquiry ,        
  CreatedBy =@CreatedBy, smstemplate = @smstemplate, smstemplateid=@smstemplateid,                             
 emailtemplate=@emailtemplate, emailtemplateid=@emailtemplateid, IsUniCode = @IsUniCode,        
 smsbody = @smsbody ,recvmobile= @recvmobile, recvMessage=@recvMessage, isrecvunicode=@isrecvunicode,        
 recvemail=@recvemail, recvmsub=@recvmsub, recvmbody=@recvmbody,        
 isticket=@isticket, priority=@priority, tktType=@tktType, Email_Ctrl=@Email_Ctrl,        
 Sub_Ctrl=@Sub_Ctrl, Desc_Ctrl=@Desc_Ctrl where FormId= @FormId                              
                
set @idInst = @FormId                
                     
if (@isEnquiry=1)                      
begin                      
                     
                    
 if (@Option = 2)                      
 exec [Usp_InsertPreDefinedUserCampaignMaster_NEW]  @PrentId,@UserID,@FormId,@FormName,@smsbody,                    
 @IsUniCode,@ReplyEmail,@MailSubject,@MailBody,@SenderEmail,@IsSms,@IsEmail,@SmsAccountName,                    
 @EmailAccountName,@SMStemplateid,@eMailtemplateid, 'Web Form'                      
                  
 end                     
 else                    
begin                    
  declare @sourceId bigint=0;                    
  declare @mediumId bigint =0;                    
  declare @SmsCampaignId bigint=0;                    
  declare @emailcampaignid bigint =0;                    
  select @sourceId=sourceid, @mediumId=mediumid, @SmsCampaignId =SmsCampaignId,                    
  @emailcampaignid = EmailCampaignId from WebFormTbl where FormId= @FormId                    
                    
if @mediumId > 0                    
 update UserMediumSettings set IsActive = 0 where mediumId = @MediumID                    
if @SmsCampaignId > 0                     
 Update UserCampaignMaster set IsActive = 0 where ID = @SmsCampaignId                     
if @emailcampaignid > 0                     
 Update UserCampaignMaster set IsActive = 0 where ID = @emailcampaignid                     
--select top 3 * from UserCampaignMaster                    
 update WebFormTbl set sourceid=0,mediumid=0,SmsCampaignId=0,EmailCampaignId=0 where FormId= @FormId                    
 end                        
                      
                      
                        
select  @idInst                      
end                             
if (@Option = 4)                              
 select * from WebFormTbl where ParentId = @PrentId                              
                        
                          
                        
                           
                        
end 


GO

