CREATE   PROC [dbo].[usp_credit_user_creation]      
@M_UserID bigint,                      
@S_UserID int -- frm varchar  
as                      
declare @mid bigint               
set @mid=(select reseller_id from reseller_Detail where m_id=@M_UserID and user_id=@S_UserID)                
                  
declare @rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@msgDeduct bigint        
set @rmid=(select m_id from reseller_detail where reseller_id=@mid and user_id=@S_UserID)          
set @ruid=(select user_id from reseller_detail where reseller_id=@mid and user_id=@S_UserID)          
set @rbal=(select top 1 balance from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)          
set @rcid=(select top 1 credit_id from credit_details where m_id=@rmid and user_id=@ruid order by credit_id desc)          
set @msgDeduct=1        
update credit_details set balance=@rbal-@msgDeduct where m_id=@rmid and user_id=@ruid and credit_id=@rcid     
select Balance from credit_details where m_id=@M_UserID and user_id=@S_UserID





GO

