/* ============================================================
   Procedure: [dbo].[Usp_CreditUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC [dbo].[Usp_CreditUpdate] --335,100  -------for  sms  
@userId int, -- from bigint by Abhishek   
@credit bigint,   
@DNDAcType varchar(20)     
as    
begin    
declare @balance bigint,@default_credit bigint,@rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@MIDUser bigint    
declare @rvalidity nvarchar(300),@rdefault_credit nvarchar(300),@temp nvarchar(800),@finalbalance2 bigint,@finalbalance bigint,@creditup bigint,@rCredit bigint,@uCredits bigint          
select top(1) @MIDUser=m_id from User_Detail with(nolock) where user_id=@userId        
select top(1) @rmid=m_id, @ruid=user_id from reseller_detail with(nolock) where reseller_id=@MIDUser    
select top(1) @rbal=balance,@rvalidity=validity,@rdefault_credit=default_credit,@rCredit=credits,@rcid=credit_id   from credit_details where m_id=@rmid and user_id=@ruid  order by credit_id  desc                        
select top(1) @balance=balance,@default_credit=default_credit,@ucredits=credits from credit_details where user_id=@userId order by credit_id desc                              
update dbo.User_Detail set AcType=@DNDAcType  where user_id=@userId  
set @finalbalance=(@credit+isnull(@balance,0))    
set @finalbalance2=( isnull(@rbal,0)-@credit)    
--Debit    
insert into credit_details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit)    
values(@userId,@rmid,@ruid,@credit,0,@finalbalance2,@rvalidity,@rdefault_credit)    
--- Credit    
insert into credit_details (FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit)    
values(@ruid,@MIDUser,@userId,0,@credit,@finalbalance,99999,@default_credit)    
select 'Record update'    
end  

------------------------------------------------------------------------------------------------



GO

/* ============================================================
   Procedure: [dbo].[Usp_CreditUpdate_MailCreditDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_CreditUpdate_MailCreditDetails]
(@userId INT, @credit BIGINT, @DNDAcType VARCHAR(20))
AS
	--Usp_CreditUpdate_MailCreditDetails 335,100 
BEGIN
	DECLARE @balance BIGINT,
	        @default_credit BIGINT,
	        @rmid BIGINT,
	        @ruid BIGINT,
	        @rbal BIGINT,
	        @rcid BIGINT,
	        @MIDUser BIGINT
	
	DECLARE @rvalidity           NVARCHAR(300),
	        @rdefault_credit     NVARCHAR(300),
	        @finalbalance2       BIGINT,
	        @finalbalance        BIGINT,
	        @rCredit             BIGINT,
	        @uCredits            BIGINT 
	
	SELECT TOP(1) @MIDUser = m_id
	FROM   User_Detail
	WHERE  USER_ID = @userId
	
	SELECT TOP(1) @rmid = m_id,
	       @ruid           = USER_ID
	FROM   reseller_detail
	WHERE  reseller_id     = @MIDUser
	
	SELECT TOP(1) @rbal = balance,
	       @rvalidity           = validity,
	       @rdefault_credit     = default_credit,
	       @rCredit             = credits,
	       @rcid                = credit_id
	FROM   MailCreditDetails
	WHERE  m_id                 = @rmid
	       AND USER_ID          = @ruid
	ORDER BY
	       credit_id DESC
	
	SELECT TOP(1) @balance = balance,
	       @default_credit     = default_credit,
	       @ucredits           = credits
	FROM   MailCreditDetails
	WHERE  USER_ID             = @userId
	ORDER BY
	       credit_id DESC                              
	
	UPDATE dbo.User_Detail
	SET    AcType = @DNDAcType
	WHERE  USER_ID = @userId
	
	SET @finalbalance = (@credit + ISNULL(@balance, 0))    
	SET @finalbalance2 = (ISNULL(@rbal, 0) -@credit) 
	
	--Debit    
	INSERT INTO MailCreditDetails
	  (
	    FromUser_ID,
	    M_ID,
	    USER_ID,
	    Debits,
	    Credits,
	    Balance,
	    Validity,
	    Default_Credit
	  )
	VALUES
	  (
	    @userId,
	    @rmid,
	    @ruid,
	    @credit,
	    0,
	    @finalbalance2,
	    @rvalidity,
	    @rdefault_credit
	  ) 
	
	--- Credit    
	INSERT INTO MailCreditDetails
	  (
	    FromUser_ID,
	    M_ID,
	    USER_ID,
	    Debits,
	    Credits,
	    Balance,
	    Validity,
	    Default_Credit
	  )
	VALUES
	  (
	    @ruid,
	    @MIDUser,
	    @userId,
	    0,
	    @credit,
	    @finalbalance,
	    99999,
	    @default_credit
	  )    
	
	SELECT 'Record update'
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_CreditUpdate_new1]
   ============================================================ */

SET ANSI_NULLS ON
