CREATE   PROC [dbo].[Usp_CreditUpdate_new1] 
@P_userId BIGINT,
@userId     bigint,    
@credit bigint,   
@DNDAcType varchar(20)     
as    
begin 


--declare @P_userId bigint =335,@userId bigint =36980,@credit int =0,@DNDAcType varchar(20) =N'NR'

DECLARE @InsertedLicenseId VARCHAR(MAX) = '0';
    DECLARE @LicenseMetadata VARCHAR(MAX);
	 Declare @ParentID  bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @userId )--456        
      Declare @MID_P  bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID ) --1
	declare @balance bigint,@default_credit bigint,@rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@MIDUser bigint          
	declare @rvalidity nvarchar(300),@rdefault_credit nvarchar(300),@temp nvarchar(800),@finalbalance2 bigint,@finalbalance bigint,@creditup bigint,@rCredit bigint,@uCredits bigint                
 
    BEGIN TRY
	select top(1) @MIDUser=  m_id  from User_Detail with(nolock) where user_id=@P_userId  --null            
	--select top(1) @rmid=m_id, @ruid=user_id from reseller_detail where reseller_id=@MIDUser --null         
	select top(1) @rbal=balance,@rvalidity= validity, @rdefault_credit= default_credit from credit_details with(nolock) where USER_ID=@P_userId order by credit_id  desc -- balace of parent partner(335)                             
	select top(1) @balance=balance,@default_credit =default_credit,  @ucredits= credits  from credit_details with(nolock) where USER_ID=@userId order by credit_id desc  -- balace of chld partner(456)         
       
 UPDATE dbo.User_Detail  
 SET    AcType = @DNDAcType  
 WHERE  USER_ID = @userId 
/*--Debit    
insert into credit_details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit)    
values(@userId,@rmid,@ruid,@credit,0,@finalbalance2,@rvalidity,@rdefault_credit)    
--- Credit    
insert into credit_details (FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit)    
values(@ruid,@MIDUser,@userId,0,@credit,@finalbalance,99999,@default_credit)    
select 'Record update'    
end  */
DECLARE @NewBalance INT = ISNULL(@balance, 0) + @credit;  --balace of child partner after addition

		 DECLARE @NewBalanceFromUser INT = ISNULL(@rbal, 0) - @credit; --balace of parent partner after addition

   begin tran

 --Debit        
 INSERT INTO credit_details  
   (  
     FromUser_ID, M_ID,   USER_ID, Debits,Credits, Balance,Validity, Default_Credit  
   )  
 VALUES  
   (  
     @P_userId, @MID_P,@userId,0, @credit, @NewBalance, @rvalidity,@rdefault_credit  
   )  
   
 --- Credit        
 INSERT INTO credit_details  
   (  
     FromUser_ID,M_ID, USER_ID, Debits,Credits,Balance,Validity,Default_Credit  
   )  
 VALUES  
   (  
     @userId, @MIDUser, @P_userId, @credit, 0, @NewBalanceFromUser,99999, @default_credit  
   )
    select 1 as status, 'Sms wallet added successful!' AS Message
	   commit
	   if @@TRANCOUNT >0
	   begin
	   rollback
        select 0 as status, 'Sms wallet failed!' AS Message
		end 



		-----  Activity Start   -----

		-- Declare activity variables
		DECLARE @PartnerType INT = 0;  
		DECLARE @UserName VARCHAR(255), @PartnerUserName VARCHAR(255), @ChildPartnerName VARCHAR(255);
		DECLARE @Eventdata VARCHAR(MAX);

		-- Fetch user details
		SELECT @UserName = ISNULL(User_login, '') FROM User_Detail WHERE User_ID = @P_userId;
		SELECT @PartnerUserName = ISNULL(User_login, '') FROM User_Detail WHERE User_ID = @P_userId;
		SELECT @ChildPartnerName = ISNULL(User_login, '') FROM User_Detail WHERE User_ID =  @userId;

		-- Construct JSON-formatted event data
		SET @Eventdata = '{"#partner#":"' + @UserName 
						+ '","#smscreditsadded#":"' + CAST(@credit AS VARCHAR(20)) 
						+ '","#username#":"' + @ChildPartnerName 
						+ '"}';

		-- Execute stored procedure for partner activity
		EXEC usp_pm_PartnerActivity  
			@P_userId, 
			@P_userId, 
			@userId, 
			'Partner added SMS credits',
			@Eventdata,
			'credit_details',
			@InsertedLicenseId;

		-----  Activity End  -----



END TRY
    BEGIN CATCH
        -- Log error details
        EXEC usp_InsertErrorInfo;
    END CATCH
END; 

----------------------------------------------------------------



