/* ============================================================
   Procedure: [dbo].[Usp_CreditUpdateDeduction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_CreditUpdateDeduction] --335,100      
@userId int, -- from bigint     
@credit bigint,  
@DNDAcType varchar(20)          
as      
begin      
declare @balance bigint,@default_credit bigint,@rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@MIDUser bigint      
declare @rvalidity nvarchar(300),@rdefault_credit nvarchar(300),@temp nvarchar(800),@finalbalance2 bigint,@finalbalance bigint,@creditup bigint,@rCredit bigint,@uCredits bigint            

  Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @userId )
  Declare @MIDP bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID )

select top(1) @MIDUser=m_id from User_Detail with(nolock) where user_id=@userId          
select top(1) @rmid=m_id, @ruid=user_id from reseller_detail with(nolock) where reseller_id=@MIDUser

      
select top(1) @rbal=balance,@rvalidity=validity,@rdefault_credit=default_credit,@rCredit=credits,@rcid=credit_id   from credit_details with(nolock) where m_id=@rmid and user_id=@ruid  order by credit_id  desc                          
select top(1) @balance=balance,@default_credit=default_credit,@ucredits=credits from credit_details with(nolock) where user_id=@userId order by credit_id desc                                
update dbo.User_Detail set AcType=@DNDAcType  where user_id=@userId  
set @finalbalance=(@credit+isnull(@rbal,0))      
set @finalbalance2=( isnull(@balance,0)-@credit)      
--Debit      
insert into credit_details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,CD_CreatedBy)      
values(@ParentID,@rmid,@ruid,0,@credit,@finalbalance,@rvalidity,@rdefault_credit,@userId)      
--- Credit      
insert into credit_details (FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,CD_CreatedBy)      
values(@ruid,@MIDP,@ParentID,@credit,0,@finalbalance2,99999,@default_credit,@userId)      
select 'Record update'      
end     


GO

