/* ============================================================
   Procedure: [dbo].[Usp_CreditUpdateDeduction_MailCreditDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_CreditUpdateDeduction_MailCreditDetails]   ----mail
(   
    --@P_userId BIGINT,
    @userId        bigint, -- from bigint       
    @credit        BIGINT,  
    @DNDAcType     VARCHAR(20)  
)  
AS  
 -- [Usp_CreditUpdateDeduction_MailCreditDetails] 335,100             
BEGIN  
 DECLARE @balance BIGINT,  
         @default_credit BIGINT,  
         @rmid BIGINT,  
         @ruid BIGINT,  
         @rbal BIGINT,  
         @rcid BIGINT,  
         @MIDUser BIGINT  
   
 DECLARE @rvalidity           NVARCHAR(300),  
         @rdefault_credit     NVARCHAR(300),  
         @finalbalance2       BIGINT,  
         @finalbalance        BIGINT,  
         @creditup            BIGINT,  
         @rCredit             BIGINT,  
         @uCredits            BIGINT              
   
 SELECT TOP(1) @MIDUser = m_id  
 FROM   User_Detail with(nolock)
 WHERE  USER_ID = @userId  
   
 SELECT TOP(1) @rmid = m_id,  
        @ruid           = USER_ID  
 FROM   reseller_detail with(nolock)
 WHERE  reseller_id     = @MIDUser  
   
 SELECT TOP(1) @rbal = balance,  
        @rvalidity           = validity,  
        @rdefault_credit     = default_credit,  
        @rCredit             = credits,  
        @rcid                = credit_id  
 FROM   MailCreditDetails  
 WHERE  m_id                 = @rmid  
        AND USER_ID          = @ruid  
 ORDER BY  
        credit_id DESC  
   
 SELECT TOP(1) @balance = balance,  
        @default_credit     = default_credit,  
        @ucredits           = credits  
 FROM   MailCreditDetails  
 WHERE  USER_ID             = @userId  
 ORDER BY  
        credit_id DESC                                  
   
   
 UPDATE dbo.User_Detail  
 SET    AcType = @DNDAcType  
 WHERE  USER_ID = @userId  
   
 SET @finalbalance = (@credit + ISNULL(@rbal, 0))        
 SET @finalbalance2 = (ISNULL(@balance, 0) -@credit)   
   
 --Debit        
 INSERT INTO MailCreditDetails  
   (  
     FromUser_ID,  
     M_ID,  
     USER_ID,  
     Debits,  
     Credits,  
     Balance,  
     Validity,  
     Default_Credit  
   )  
 VALUES  
   (  
     @userId,  
     @rmid,  
     @ruid,  
     0,  
     @credit,  
     @finalbalance,  
     @rvalidity,  
     @rdefault_credit  
   )   
   
 --- Credit        
 INSERT INTO MailCreditDetails  
   (  
     FromUser_ID,  
     M_ID,  
     USER_ID,  
     Debits,  
     Credits,  
     Balance,  
     Validity,  
     Default_Credit  
   )  
 VALUES  
   (  
     @ruid,  
     @MIDUser,  
     @userId,  
     @credit,  
     0,  
     @finalbalance2,  
     99999,  
     @default_credit  
   )     
   
 SELECT 'Record update'  
END  
-----------------------------------------------------------------------



GO

/* ============================================================
   Procedure: [dbo].[Usp_CreditUpdateDeduction_MailCreditDetails_new1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_CreditUpdateDeduction_MailCreditDetails_new1]   ----mail credit new
(   
    @P_userId BIGINT,
    @userId        bigint, -- from bigint       
    @credit        BIGINT,  
    @DNDAcType     VARCHAR(20)  
)  
AS  
 
BEGIN  

--declare 
-- @P_userId bigint =335 ,@userId bigint =25018,@credit int =0,@DNDAcType  varchar(20)  =N'NR'


  DECLARE @InsertedLicenseId VARCHAR(MAX) = '0';
    DECLARE @LicenseMetadata VARCHAR(MAX);
	 Declare @ParentID  bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @userId )--456        
      Declare @MID_P  bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID ) --1
	declare @balance bigint,@default_credit bigint,@rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@MIDUser bigint          
	declare @rvalidity nvarchar(300),@rdefault_credit nvarchar(300),@temp nvarchar(800),@finalbalance2 bigint,@finalbalance bigint,@creditup bigint,@rCredit bigint,@uCredits bigint                
 
    BEGIN TRY
	select top(1) @MIDUser=  m_id  from User_Detail with(nolock) where user_id=@P_userId  --null            
	--select top(1) @rmid=m_id, @ruid=user_id from reseller_detail where reseller_id=@MIDUser --null         
	select top(1) @rbal=balance,@rvalidity= validity, @rdefault_credit= default_credit from MailCreditDetails with(nolock) where USER_ID=@P_userId order by credit_id  desc -- balace of parent partner(335)                             
	select top(1) @balance=balance,@default_credit =default_credit,  @ucredits= credits  from MailCreditDetails where USER_ID=@userId order by credit_id desc  -- balace of chld partner(456)         
       
 UPDATE dbo.User_Detail  
 SET    AcType = @DNDAcType  
 WHERE  USER_ID = @userId  
   
 --SET @finalbalance = (@credit + ISNULL(@rbal, 0))        
 --SET @finalbalance2 = (ISNULL(@balance, 0) -@credit)   
   DECLARE @NewBalance INT = ISNULL(@balance, 0) + @credit;  --balace of child partner after addition

		 DECLARE @NewBalanceFromUser INT = ISNULL(@rbal, 0) - @credit; --balace of parent partner after addition

   begin tran

 --Debit        
 INSERT INTO MailCreditDetails  
   (  
     FromUser_ID, M_ID,   USER_ID, Debits,Credits, Balance,Validity, Default_Credit  
   )  
 VALUES  
   (  
     @P_userId, @MID_P,@userId,0, @credit, @NewBalance, @rvalidity,@rdefault_credit  
   )  
   
 --- Credit        
 INSERT INTO MailCreditDetails  
   (  
     FromUser_ID,M_ID, USER_ID, Debits,Credits,Balance,Validity,Default_Credit  
   )  
 VALUES  
   (  
     @userId, @MIDUser, @P_userId, @credit, 0, @NewBalanceFromUser,99999, @default_credit  
   )
    select 1 as status, 'Mail credited successful!' AS Message
	   commit
	   if @@TRANCOUNT >0
	   begin
	   rollback
        select 0 as status, 'Mail credit failed!' AS Message
		end 

	SET @InsertedLicenseId = SCOPE_IDENTITY();


		----- activity start -----
	-- Declare variables for storing necessary data
	DECLARE @PartnerType INT = 0;
	DECLARE @UserName VARCHAR(255), @PartnerUserName VARCHAR(255), @ChildPartnerName VARCHAR(255);
	DECLARE @Eventdata VARCHAR(MAX);
	
 
		-- Fetch user details
		SELECT @UserName = ISNULL(User_login, '') FROM User_Detail WHERE User_ID = @P_userId;
		SELECT @PartnerUserName = ISNULL(User_login, '') FROM User_Detail WHERE User_ID = @P_userId;
		SELECT @ChildPartnerName = ISNULL(User_login, '') FROM User_Detail WHERE User_ID =  @userId;

		 print concat(  @userId,@ChildPartnerName )
	-- Build the event data JSON string
	SET @Eventdata = '{"#partnername#": ' + QUOTENAME(@UserName, '"') + ', "#mailcreditsadded#": "' + CONVERT(VARCHAR, coalesce( @credit,0)) + '", "#username#": ' 
	+ QUOTENAME(@ChildPartnerName, '"') + '}';

	print @Eventdata;

	-- Execute the stored procedure to log the activity
	EXEC usp_pm_PartnerActivity  
		@P_userid, 
		@P_userId, 
		@userId, 
		'Partner added mail credits', 
		@Eventdata, 
		'MailCreditDetails', 
		@InsertedLicenseId;

----- activity end -----


END TRY
    BEGIN CATCH
        -- Log error details
        EXEC usp_InsertErrorInfo;
    END CATCH
END; 
 -------------------------------------------------------------------------------- 




GO

/* ============================================================
   Procedure: [dbo].[usp_custom_callreports]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
select  user_login,m.batchid,senderid,message,d.DLT_TemplateID,MessageStatus from messagedeliverystatus(nolock) m
join DLT_Template_MSG d (nolock) on d.BatchID=m.BatchID
join User_Detail(nolock) u on u.user_id=u_id
 where 
isnull(MessageStatus,'') not in ('6','','DELIVRD')
order by MessageStatus


select statuswitherr,count(1) from mysmstrans.dbo.ReceiveDeliveryData(nolock)
group by StatusWithErr
 
 select m.batchid,r.* from mysmstrans.dbo.ReceiveDeliveryData(nolock) r
 join mysmstrans.dbo.messagesent(nolock) m on r.SubmitRefID in (select [value] from dbo.fn_split(m.Msgref,','))
where  StatusWithErr ='DLT Template Filter'
and createddate>'20220101'

*/
CREATE   PROCEDURE usp_custom_callreports --39020,'20220501','20220515'
@user_id bigint,
@fromdate nvarchar(50)=null,
@todate nvarchar(50)=null
as
begin
declare @parentid bigint=(select parentid from user_detail(nolock) where user_id=@user_id)
select @fromdate=coalesce(@fromdate,(select replace(first_day_of_month,'-','') from calendar(nolock) where date_id=cast(getdate() as date)))
select @todate=coalesce(@todate,dateadd(dd,1,cast(getdate() as date)))

select user_login,FName,lname,count(1) as TotalDialled,
isnull(sum(cast(duration as int)),0) as Talktime from
(
select u.user_login,u.FName,u.lname,t.callcreatedon,
u.parentid,
t.customercalldisposition as status,
datediff(ss,t.callcreatedon,t.Callendtime) as duration
from calllog(nolock) t
join user_detail(nolock) u on t.agentuserid=cast(u.User_ID as nvarchar)
where cast(t.callcreatedon as date) between @fromdate AND @todate
and u.parentid=@parentid
) a
group by user_login,FName,lname

--select * from calllog(nolock) where Parentid=39020 order by id--40032,2022-04-09 10:01:03.030
--delete from calllog where refid<40032 and 



--and srv_pro_id=t.voip_ep_id
--order by 1 desc

--select * from tbl_voip_Webhook(nolock) order by 1 desc

select s.name Source,isnull(c.name,'') Campaign,u.Leadno,personName as Name,MobileNo+isnull(', '+nullif(MobileNo1,''),'')+isnull(', '+nullif(MobileNo2,''),'') Mobile,
isnull(EmailID,'')+isnull(', '+nullif(emailid1,''),'')+isnull(', '+nullif(emailid1,''),'') Email, 
f.FollowupStatus,l.CreatedOn LastFollowedOn,isnull(l.Remarks,'') Remarks,(select user_login +'( '+isnull(fname,'')+' '+ isnull(lname,'')+' )' from user_detail(nolock) where user_id=l.CreatedBy) user_login,l.AmountPaid
--FollowupStatus,FollowupBy,FollowupDate,Remarks,AmountPaid
--	Phone number	email id	status	followup done by	Remarks
--from v_userleads(nolock) u
from userleads(nolock) u
left join LeadInteractionHistory(nolock) l on l.LeadNo=u.LeadNo and l.ParentID=u.ParentID
left join UserSourceSettings(nolock) s on s.SourceID=u.SourceName
left join UsercampaignSettings(nolock) c on c.CampaignID=u.CampaignName
join FollowUp_Status(nolock) f on f.ID=l.FollowUpStatus
where u.parentid=@parentid --and s.SourceID is null 
and l.CreatedOn between @fromdate AND @todate
--and FollowupDate between '20220101' AND '20220201'
and l.id=(select max(id) from LeadInteractionHistory(nolock) where leadno=l.leadno and parentid=l.parentid 
and CreatedBy<>parentid and FollowupStatus<>6)
order by user_login,l.CreatedOn

end




GO

/* ============================================================
   Procedure: [dbo].[usp_custom_callreports_agents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*  
select  user_login,m.batchid,senderid,message,d.DLT_TemplateID,MessageStatus from messagedeliverystatus(nolock) m  
join DLT_Template_MSG d (nolock) on d.BatchID=m.BatchID  
join User_Detail(nolock) u on u.user_id=u_id  
 where   
isnull(MessageStatus,'') not in ('6','','DELIVRD')  
order by MessageStatus  
  
  
select statuswitherr,count(1) from mysmstrans.dbo.ReceiveDeliveryData(nolock)  
group by StatusWithErr  
   
 select m.batchid,r.* from mysmstrans.dbo.ReceiveDeliveryData(nolock) r  
 join mysmstrans.dbo.messagesent(nolock) m on r.SubmitRefID in (select [value] from dbo.fn_split(m.Msgref,','))  
where  StatusWithErr ='DLT Template Filter'  
and createddate>'20220101'  
  
*/  
CREATE   PROCEDURE usp_custom_callreports_agents --39020,'20220501','20220515'  
@agentid bigint,  
@fromdate nvarchar(50)=null,  
@todate nvarchar(50)=null  
as  
begin  
declare @parentid bigint=(select parentid from calling_agents(nolock) where id=@agentid)  
select @fromdate=coalesce(@fromdate,(select replace(first_day_of_month,'-','') from calendar(nolock) where date_id=cast(getdate() as date)))  
select @todate=coalesce(@todate,dateadd(dd,1,cast(getdate() as date)))  
  
select Agentname,count(1) as TotalCalls,  
isnull(sum(cast(duration as int)),0) as Talktime from  
(  
select u.agentname,t.callcreatedon,  
u.parentid,  
t.customercalldisposition as status,  
datediff(ss,t.callcreatedon,t.Callendtime) as duration  
from calllog(nolock) t  
join calling_agents(nolock) u on t.calling_agentid=cast(u.id as nvarchar)  
where cast(t.callcreatedon as date) between @fromdate AND @todate  
and u.parentid=@parentid  
) a  
group by Agentname  
  
--select * from calllog(nolock) where Parentid=39020 order by id--40032,2022-04-09 10:01:03.030  
--delete from calllog where refid<40032 and   
  
  
  
--and srv_pro_id=t.voip_ep_id  
--order by 1 desc  
  
--select * from tbl_voip_Webhook(nolock) order by 1 desc  
  
select s.name Source,isnull(c.name,'') Campaign,u.Leadno,personName as Name,
MobileNo+isnull(', '+nullif(MobileNo1,''),'')+isnull(', '+nullif(MobileNo2,''),'') Mobile,  
isnull(EmailID,'')+isnull(', '+nullif(emailid1,''),'')+isnull(', '+nullif(emailid1,''),'') Email,   
f.FollowupStatus,l.CreatedOn LastFollowedOn,isnull(l.Remarks,'') Remarks,
(select user_login +'( '+isnull(fname,'')+' '+ isnull(lname,'')+' )' from user_detail(nolock) where user_id=l.CreatedBy) user_login,
l.AmountPaid  
--FollowupStatus,FollowupBy,FollowupDate,Remarks,AmountPaid  
-- Phone number email id status followup done by Remarks  
--from v_userleads(nolock) u  
from userleads(nolock) u  
left join LeadInteractionHistory(nolock) l on l.LeadNo=u.LeadNo and l.ParentID=u.ParentID  
left join UserSourceSettings(nolock) s on s.SourceID=u.SourceName  
left join UsercampaignSettings(nolock) c on c.CampaignID=u.CampaignName  
join FollowUp_Status(nolock) f on f.ID=l.FollowUpStatus  
where u.parentid=@parentid --and s.SourceID is null   
and l.CreatedOn between @fromdate AND @todate  
--and FollowupDate between '20220101' AND '20220201'  
and l.id=(select max(id) from LeadInteractionHistory(nolock) where leadno=l.leadno and parentid=l.parentid   
and CreatedBy<>parentid and FollowupStatus<>6)  
order by user_login,l.CreatedOn  
  
end  
  


GO

