   Procedure: [dbo].[usp_custom_enquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 --exec usp_custom_enquiry 987365  
CREATE   PROCEDURE [dbo].[usp_custom_enquiry]  
    @enqid bigint                              
as                              
begin                              
    
    set nocount on      
     --declare @enqid bigint =369824875  

    declare @ParentId bigint = ( select ParentID from UserEnquiry(nolock) where EnquiryID = @enqid )  
  
    select A.field_ID, isnull(B.fieldvalue, '') as [fieldvalue], a.fieldname,a.datatype from  
    (  
        SELECT field_ID,ParentID,fieldname,datatype,sequence,minvalue,maxvalue,addedon,  
        isActive,isMandatory,defaultValue,quickAdd,currentDate,tooltip,choices,formulaId  
            FROM  customfields(nolock)  
        Where parentid=@ParentId  and isActive = 1
    ) A left join  
    (   
        SELECT * FROM  customfieldEnquiryvalue(nolock)   WHERE EnquiryID=@enqid   
    ) B  
    ON A.field_ID=B.fieldID  
    ORDER BY A.[sequence] ASC;  
      
end  



