/* ============================================================
   Procedure: [dbo].[usp_custom_leads]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_custom_leads] --2018643   
(
    @leadid BIGINT
)
AS 
BEGIN 
    SET NOCOUNT ON;
    --declare @leadid bigint =1059685      
    declare @ParentId bigint = (
      select ParentID  from  UserLeads(nolock) where ID = @leadid
    ) 
    select 
      distinct A.field_ID, B.fieldvalue, a.fieldname, a.datatype, A.[sequence] 
    from 
      (
        SELECT field_ID, ParentID, fieldname, datatype, sequence, minvalue, maxvalue, 
            addedon, isActive, isMandatory, defaultValue, quickAdd, currentDate, tooltip, choices, formulaId 
        FROM customfields(NOLOCK) WHERE 
          parentid = @ParentId  AND isnull(isActive, 0) = 1
      ) A left join (
        SELECT * FROM customfieldLeadvalue(nolock) WHERE LeadID = @leadid
      ) B ON A.field_ID = B.fieldID 
    ORDER BY A.[sequence] ASC;
END;



