/* ============================================================
   Procedure: [dbo].[usp_CustomButtonCreation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-----------------------------------

CREATE   PROCEDURE usp_CustomButtonCreation    
    @UserId BIGINT,    
   @UserType NVARCHAR(MAX),    
    @ButtonName VARCHAR(100),    
    @ButtonDescription VARCHAR(MAX) = NULL,    
    @PlaceOnPage VARCHAR(50),    
    @ModuleCode VARCHAR(50),    
    @ActionBePerform VARCHAR(200),    
    @ActionDetails NVARCHAR(MAX),    
    @ButtonDisposition VARCHAR(100)= NULL,    
    @GroupId BIGINT,  -- Added GroupId parameter   
 @WebhookId BIGINT = NULL   
AS    
BEGIN    
    SET NOCOUNT ON;    
    
    BEGIN TRY    
        DECLARE @ParentId BIGINT = 0;    
        DECLARE @IsAdmin BIT = 0;    
        DECLARE @RoleType VARCHAR(10);    
    
        -- Fetch user details    
        SELECT @ParentId = ParentID, @IsAdmin = IsAdmin    
        FROM User_Detail (NOLOCK)    
        WHERE User_ID = @UserId;    
    
        -- Create temporary table to hold user IDs    
        IF OBJECT_ID('tempdb..#tblUserIds') IS NOT NULL    
        BEGIN    
            DROP TABLE #tblUserIds;    
        END    
    
        CREATE TABLE #tblUserIds (    
            UserId BIGINT NOT NULL    
        );    
    
        -- Determine which user IDs to insert into the temp table based on role    
        IF(@ParentId = @UserId OR @IsAdmin = 1)    
        BEGIN    
            INSERT INTO #tblUserIds (UserId)    
            SELECT User_Id    
            FROM User_Detail (NOLOCK)    
            WHERE ParentId = @ParentId;    
        END    
        ELSE    
        BEGIN    
            INSERT INTO #tblUserIds (UserId)    
            SELECT @UserId;    
        END    
      
        -- Insert the new button details into the target table    
        --INSERT INTO tbl_CB_CustomButtons (    
        --    ParentId, UserId, ButtonName, ButtonDescription, PlaceOnPage,     
        --    ModuleCode, ActionBePerform, ActionDetails,     
        --    ButtonDisposition, IsActive, CreatedBy, CreatedDate, GroupId, UserType    
        --)    
        --VALUES (    
        --    @ParentId, @UserId, @ButtonName, @ButtonDescription, @PlaceOnPage,     
        --    @ModuleCode, @ActionBePerform, @ActionDetails, @ButtonDisposition,     
        --    1, @UserId, GETDATE(), @GroupId,@UserType    
        --);    
   -- Insert the new button details into the target table    
        INSERT INTO tbl_CB_CustomButtons (    
            ParentId, UserId, ButtonName, ButtonDescription, PlaceOnPage,     
            ModuleCode, ActionBePerform, ActionDetails,     
            ButtonDisposition, IsActive, CreatedBy, CreatedDate, GroupId, UserType, WebhookID    
        )    
        VALUES (    
            @ParentId, @UserId, @ButtonName, @ButtonDescription, @PlaceOnPage,     
            @ModuleCode, @ActionBePerform, @ActionDetails, @ButtonDisposition,     
            1, @UserId, GETDATE(), @GroupId, @UserType, @WebhookId    
        );    
    
        -- Clean up temporary table    
        DROP TABLE #tblUserIds;    
    
        -- Return success message    
        SELECT 'Success' AS Message;    
    END TRY    
    BEGIN CATCH    
        -- Handle the error    
        DECLARE @ErrorMessage NVARCHAR(4000);    
        DECLARE @ErrorSeverity INT;    
        DECLARE @ErrorState INT;    
    
        SELECT     
            @ErrorMessage = ERROR_MESSAGE(),    
            @ErrorSeverity = ERROR_SEVERITY(),    
            @ErrorState = ERROR_STATE();    
    
        -- Return error message    
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState);    
    END CATCH    
END; 





GO

