CREATE   PROCEDURE usp_cw_GetWebConversationHistory    
    @visitor_id BIGINT,    
    @session_id NVARCHAR(255)=null, -- Added session_id parameter    
    @top_n INT = 20 -- Number of latest messages to retrieve    
AS    
BEGIN    
    SET NOCOUNT ON;    
    select top 1  @session_id=isnull(@session_id,current_session_id) from cw_visitor_details(nolock) where id=@visitor_id order by id desc
    SELECT TOP (@top_n)    
        message_text,    
        message_direction,    
        message_timestamp,    
        message_sent_by    
    FROM cw_web_conversations (NOLOCK)    
    WHERE visitor_id = @visitor_id    
      AND session_id = @session_id -- Filter by current session_id    
      --AND is_hidden = 0 -- Only retrieve active conversations    
    ORDER BY message_timestamp ASC;    
END;    
  
  
