/* ============================================================
   Procedure: [dbo].[usp_cw_HideOldConversations]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE usp_cw_HideOldConversations
    @visitor_id BIGINT,
    @old_session_id NVARCHAR(255)
AS
BEGIN
    SET NOCOUNT ON;

    UPDATE cw_web_conversations
    SET is_hidden = 1
    WHERE visitor_id = @visitor_id
      AND session_id = @old_session_id
      AND is_hidden = 0; -- Only hide if not already hidden

    PRINT N'Marked ' + CAST(@@ROWCOUNT AS NVARCHAR(MAX)) + N' conversations as hidden for Visitor ID: ' + CAST(@visitor_id AS NVARCHAR(MAX)) + N', Old Session ID: ' + @old_session_id;
END;



