/* ============================================================
   Procedure: [dbo].[usp_cw_InsertOrUpdateVisitorDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_cw_InsertOrUpdateVisitorDetails      
    @visitor_id BIGINT, -- Input: 0 for new visitor, existing ID for existing visitor      
    @new_session_id NVARCHAR(255), -- The session ID to associate/update      
    @ip_address NVARCHAR(45) = NULL,      
    @name NVARCHAR(255) = NULL,      
    @company_name  NVARCHAR(255) = NULL,      
    @phone NVARCHAR(20) = NULL,      
    @email NVARCHAR(255) = NULL,     
 @industry nvarchar(100)= null,    
 @demo_date varchar(50) =null,    
 @demo_time varchar(50) = null,    
    @additional_details NVARCHAR(MAX) = NULL, -- JSON string      
    @ai_status NVARCHAR(50) = NULL,      
    @is_qualified BIT = NULL,     
 @alert_human_agent bit=NULL,    
    @do_not_contact BIT = NULL ,@other_relevant_info nvarchar(max)=null ,@thread_id varchar(255)=null    
AS      
BEGIN      
    SET NOCOUNT ON;      
      
    DECLARE @ActualVisitorId BIGINT;      
    DECLARE @ExistingCurrentSessionId NVARCHAR(255);      
      
    IF @visitor_id IS NULL OR @visitor_id = 0      
    BEGIN      
        -- Case 1: New Visitor - Create a new record      
        INSERT INTO cw_visitor_details (      
            initial_session_id, current_session_id, time_of_visit, ip_address, name, company_name,      
            phone, email, industry,demo_date,demo_time, additional_details, ai_status, is_qualified, do_not_contact, last_interaction_time ,other_relevant_info     
        )      
        VALUES (      
            @new_session_id, @new_session_id, GETDATE(), @ip_address, @name, @company_name,      
            @phone, @email,@industry,@demo_date,@demo_time, @additional_details, ISNULL(@ai_status, 'new_visitor'), ISNULL(@is_qualified, 0), ISNULL(@do_not_contact, 0), GETDATE(),@other_relevant_info      
        );      
        SET @ActualVisitorId = SCOPE_IDENTITY(); -- Get the newly generated ID      
    END      
    ELSE      
    BEGIN    
 --declare @oldinfo nvarchar(max)  
        -- Case 2: Existing Visitor - Update their record      
        -- Get the existing current_session_id before updating      
        SELECT @ExistingCurrentSessionId = current_session_id      
        FROM cw_visitor_details      
        WHERE id = @visitor_id;      
      
    if isjson(@other_relevant_info)=1  
    begin  
    begin try  
    exec usp_Update_additional_details @visitor_id,@other_relevant_info,''  
    end try  
    begin catch  
    exec usp_inserterrorinfo  
    end catch  
    end  
  
        -- Update the visitor details      
        UPDATE cw_visitor_details      
        SET      
            -- Only update current_session_id if it's different from the new one      
            current_session_id = CASE WHEN @new_session_id <> current_session_id THEN @new_session_id ELSE current_session_id END,      
            ip_address = ISNULL(@ip_address, ip_address), -- Only update if provided, otherwise keep existing      
            name = ISNULL(nullif(@name,''), name),      
            company_name = ISNULL(nullif(@company_name,''), company_name),      
            phone = ISNULL(nullif(@phone,''), phone),      
            email = ISNULL(nullif(@email,''), email),      
   industry=isnull(nullif(@industry,''),industry),    
   demo_date=isnull(nullif(@demo_date,''),demo_date),    
   demo_time=isnull(nullif(@demo_time,''),demo_time),    
            additional_details =       
    CASE       
        WHEN @additional_details IS NOT NULL AND ISJSON(@additional_details) = 1      
        THEN @additional_details      
        ELSE additional_details      
    END,    
            ai_status = ISNULL(@ai_status, ai_status),      
            is_qualified = ISNULL(@is_qualified, is_qualified),    
   alert_human_agent =isnull(@alert_human_agent,alert_human_agent),    
            do_not_contact = ISNULL(@do_not_contact, do_not_contact),      
            last_interaction_time = GETDATE() ,thread_id =isnull(  @thread_id,thread_id)   
        WHERE id = @visitor_id;      
      
        SET @ActualVisitorId = @visitor_id; -- Use the provided visitor_id      
      
        -- If the session ID has changed for an existing visitor,      
        -- we need to mark old conversations for the PREVIOUS session as hidden.      
        IF @ExistingCurrentSessionId IS NOT NULL AND @ExistingCurrentSessionId <> @new_session_id      
        BEGIN      
            EXEC usp_cw_HideOldConversations @visitor_id = @ActualVisitorId, @old_session_id = @ExistingCurrentSessionId;      
        END;      
    END;      
      
    -- Return the actual visitor ID      
    SELECT @ActualVisitorId AS VisitorId;      
END;   
  
  


GO

