CREATE   PROCEDURE [dbo].[usp_cw_SendSMSAlert] --172,null,1466  
    @visitor_id BIGINT, -- Use visitor_id to fetch phone    
    @alert_reason NVARCHAR(255) = NULL, -- Reason for the alert, nullable    
    @convo_id BIGINT = NULL -- Optional conversation ID that triggered the alert    
AS    
BEGIN    
    SET NOCOUNT ON;    
  declare @msg nvarchar(2000),@demofixed nvarchar(100),@lastdemofixed nvarchar(100),@is_qualified bit=0,@demo_date varchar(50),@demo_time varchar(50),@visitor_name nvarchar(100),@visitor_company nvarchar(100),@mobile varchar(20),@batchid bigint=null,@alert_human bit=0     
if not exists (select 1 from cw_visitor_details (nolock) where id=@visitor_id and isnull(last_sms_alert_sent,dateadd(d,-2,getdate()))>dateadd(d,-1,getdate()))  
begin 
select @is_qualified=is_qualified,@demo_date=nullif(demo_date,'not provided'),@demo_time=nullif(demo_time,'not provided'), @visitor_company=nullif(company_name,'not provided'),@visitor_name=nullif(name,'not provided'),@mobile=nullif(phone,'not provided'),
@alert_human=alert_human_agent
from cw_visitor_details (nolock) where id=@visitor_id  
if @is_qualified=1  --or @alert_human=1
begin  
print 'Preparing and sending message'

if isnull(@demo_date,'')=''  
begin  
select @msg=concat('A user with no ref ',@visitor_id,' ',isnull(' with mobile:'+@mobile,' for KIT19'),' not in CRM just performed following event in Kit19 at ',getdate(),' ',isnull(@visitor_name,@visitor_company), 
' : User showed interest in demo. Please appropriate action.')  
end  
else  
begin  
select @msg=concat('A user with no ref ',@visitor_id,' ',isnull(' with mobile:'+@mobile,' for KIT19'),' for Kit19 not in CRM just performed following event in Kit19 at ',getdate(),' ', 
isnull(@visitor_name,@visitor_company),' : User fixed demo at ',left(@demo_date+ ' '+@demo_time,30),'. Please appropriate action.')  
end 
print concat('Calling send sms with details: ',335,@msg,'7840002738,9910025912','KitApp',0,2,'1707162003339091803','API' , @batchid)
exec [dbo].[usp_sendmessage_WithDLTTemplateID_withoutput] 335,@msg,'7840002738,9910025912','KitApp',0,2,'1707162003339091803','API' , @batchid  output
select @batchid=@batchid
print concat('Batchid: ',@batchid)
if isnull(@batchid,0)>0
update cw_visitor_details set last_sms_alert_sent=getdate() where id=@visitor_id  

end  
else
begin
print 'Not sending message,condition not satisfied'
end
end  
END; 




