/* ============================================================
   Procedure: [dbo].[usp_dailer_GetUserDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_dailer_GetUserDetails
(
  @UserId     BIGINT, 
  @FilterText NVARCHAR(255))
AS
BEGIN
	DECLARE 
	  @ParentId BIGINT=
	(
	  SELECT ParentID
	  FROM User_Detail( NOLOCK )
	  WHERE User_ID=@UserId
	);
	SELECT CONCAT( FName, ' ', LName )
	AS FullName, 
		   User_Login, 
		   Mobile, 
		   Image, 
		   ParentID, 
		   User_ID
	FROM User_Detail( NOLOCK )
	WHERE ParentID=@ParentId
		  AND (User_Login LIKE '%'+@FilterText+'%'
			   OR FName LIKE '%'+@FilterText+'%'
			   OR Mobile LIKE '%'+@FilterText+'%'
			   OR LName LIKE '%'+@FilterText+'%')
		  AND User_ID<>@UserId;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_dailerGetLeadEnquiryContact]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_dailerGetLeadEnquiryContact] ( 
                 @FilterText NVARCHAR(250) = '' , 
                 @EntityName NVARCHAR(250) = '' , 
                 @UserId     BIGINT
                                                 ) 
AS
    BEGIN
        DECLARE @ParentId BIGINT= ( SELECT ParentID
                                    FROM mysms.dbo.User_Detail(NOLOCK)
                                    WHERE User_ID = @UserId
                                  );
        SELECT TOP 10 *
        FROM ( 
			SELECT Id AS EntityId , PersonName , CountryCode, MobileNo, CountryCode1, MobileNo1, CountryCode2, MobileNo2, EmailID , CompanyName , ProfileImgFileName , ParentId , 'lead' AS 'EntityName'
               FROM mysms.dbo.UserLeads(NOLOCK)
               WHERE ParentID = @ParentId
               UNION
               SELECT EnquiryID AS EntityId , PersonName , CountryCode,  MobileNo, CountryCode1, MobileNo1, CountryCode2, MobileNo2, EmailID , CompanyName , ProfileImgFileName , ParentId , 'enquiry' AS 'EntityName'
               FROM mysms.dbo.UserEnquiry(NOLOCK)
               WHERE ParentID = @ParentId
        ) AS p
        WHERE p.EntityName = @EntityName
              AND 
              ( PersonName LIKE '%' + @FilterText + '%'
                OR ISNULL(MobileNo , '') LIKE '%' + @FilterText + '%'
                OR ISNULL(EmailID , '') LIKE '%' + @FilterText + '%'
                OR ISNULL(CompanyName , '') LIKE '%' + @FilterText + '%' )  --and PersonName is not null   
        ORDER BY EntityId DESC;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_dailyagentreport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Agent Name Total incoming attended (inbound and outbound) Total outbound (sim and clicktocall) Talk time     
--Total Leads  Follow up overdue Follow up done this month Closures this month Amount closed This month    
--Total tasks overdue Tasks Completed this month    
CREATE   PROCEDURE usp_dailyagentreport --335,'11-11-2020'
(@parentid bigint,@fromdate nvarchar(20))    
as    
--declare @parentid bigint=33819,@fromdate nvarchar(20)=convert(nvarchar,getdate(),104)    
begin    
select @fromdate,u.parentid,u.user_login,u.user_id,    
isnull(TotalSIMCallsToday,0)+isnull(TotalDialerCallsToday,0) as TotalOutBoundCallsToday,    
isnull(TotalSIMCallsThisMonth,0)+isnull(TotalDialerCallsThisMonth,0) as TotalOutBoundCallsThisMonth,    
isnull(TotalInboundToday,0) TotalInboundToday,    
isnull(TotalInboundThisMonth,0) TotalInboundThisMonth,    
isnull(TotalSIMCallPeriodToday,0)+    
isnull(TotalDialerCallPeriodToday,0)+    
isnull(TotalInboundCallPeriodToday,0) as [CallPeriodToday(InMins)],    
isnull(TotalSIMCallPeriodThisMonth,0)+    
isnull(TotalDialerCallPeriodThisMonth,0)+    
isnull(TotalInboundCallPeriodThisMonth,0) as [CallPeriodThisMonth(InMins)],    
isnull(TotalLeads,0)TotalLeads,isnull(FollowUpsOverDue,0) FollowUpsOverDue,isnull(FollowupsDoneToday,0) FollowupsDoneToday,isnull(ClosuresToday,0) ClosuresToday,isnull(AmountClosedToday,0)AmountClosedToday,    
isnull(FollowupsDoneThisMonth,0) FollowupsDoneThisMonth,isnull(ClosuresThisMonth,0) ClosuresThisMonth,isnull(AmountClosedThisMonth,0)AmountClosedThisMonth,    
isnull(TaskOverDue,0) TaskOverDue,isnull(TasksCompletedToday,0) TasksCompletedToday,isnull(TasksCompletedThisMonth,0) TasksCompletedthismonth    
from    
user_detail(nolock) u left join    
(    
select u.user_login,    
sum(case when cast(CallStartDateTime as date)=convert(date,@fromdate,104) then 1 else 0 end ) as TotalSIMCallsToday,    
sum(case when month(CallStartDateTime)=month(convert(date,@fromdate,104)) and year(CallStartDateTime)=year(convert(date,@fromdate,104)) then 1 else 0 end ) as TotalSIMCallsThisMonth,    
sum(case when CallStartDateTime is not null and cast(CallStartDateTime as date)=convert(date,@fromdate,104) then datediff(ss,CallStartDateTime,CallEndDateTime)/60 else 0 end) as TotalSIMCallPeriodToday,    
sum(case when CallStartDateTime is not null and month(CallStartDateTime)=month(convert(date,@fromdate,104)) and year(CallStartDateTime)=year(convert(date,@fromdate,104)) then datediff(ss,CallStartDateTime,CallEndDateTime)/60 else 0 end) as   
TotalSIMCallPeriodThisMonth     
from user_detail u(nolock)     
 join     
tbl_DailPaidCallDetails d(nolock) on u.user_id=d.userid    
where u.parentid=@parentid --and d.callstartdatetime between cast(getdate() as date) and dateadd(dd,1,cast(getdate() as date))    
group by user_login    
) A on A.user_login=u.User_Login    
left join    
(    
select u.user_login,sum(case when cast(call_start_time as date)=cast(convert(date,@fromdate,104) as date) then 1 else 0 end) as TotalDialerCallsToday,    
sum(case when month(call_start_time)=month(cast(convert(date,@fromdate,104) as date)) and year(call_start_time)=year(cast(convert(date,@fromdate,104) as date)) then 1 else 0 end) as TotalDialerCallsThisMonth,    
sum(case when cast(call_start_time as date)=cast(convert(date,@fromdate,104) as date) then billedtime else 0 end) as TotalDialerCallPeriodToday,    
sum(case when month(call_start_time)=month(cast(convert(date,@fromdate,104) as date)) and year(call_start_time)=year(cast(convert(date,@fromdate,104) as date))  then billedtime else 0 end)     
as TotalDialerCallPeriodThisMonth    
 from user_detail u(nolock)     
 join DiallerCalls d(nolock) on u.user_id=d.user_id    
 where u.parentid=@parentid --and d.call_start_time between cast(getdate() as date) and dateadd(dd,1,cast(getdate() as date))    
group by user_login    
) B on u.user_login=B.user_login    
left join    
(    
select u.user_login,    
sum(case when d.dialstatus='answer' and cast(d.call_start_time as date)=convert(date,@fromdate,104) then 1 else 0 end) TotalInboundToday,    
sum(case when d.dialstatus='answer' and month(d.call_start_time)=month(cast(convert(date,@fromdate,104) as date)) and year(d.call_start_time)=year(cast(convert(date,@fromdate,104) as date)) then 1 else 0 end)     
TotalInboundThisMonth,    
sum(case when d.dialstatus='answer' and cast(d.call_start_time as date)=convert(date,@fromdate,104) then datediff(ss,d.call_answer_time,d.call_end_time)/60 else 0 end) TotalInboundCallPeriodToday,    
sum(case when d.dialstatus='answer' and month(d.call_start_time)=month(convert(date,@fromdate,104)) and year(d.call_start_time)=year(convert(date,@fromdate,104)) then datediff(ss,d.call_answer_time,d.call_end_time)/60 else 0 end)     
TotalInboundCallPeriodThisMonth    
from     
user_detail(nolock) u join kit19calls(nolock) k on k.clientid=u.ParentID    
join Kit19CallsDialled(nolock) d on d.puniqueid=k.uniqueid and     
agentnumber=case when d.callerid like '%@setcalleridpstn/n%' or d.callerid like '%@p%' then str(u.mobile) when d.callerid like '%@setcallerid/n%' or d.callerid like '%@s%'     
then cast(u.user_id as nvarchar) else str(u.mobile) end    
where u.parentid=@parentid --and d.call_start_time between cast(getdate() as date) and dateadd(dd,1,cast(getdate() as date))    
group by user_login)    
C on C.user_login=u.user_login    
left join    
(    
select assignedto,    
count(1) TotalLeads,    
sum(case when followupdate<getdate() then 1 else 0 end) as FollowUpsOverDue,    
FollowupsDoneToday,    
ClosuresToday,    
AmountClosedToday,    
FollowupsDoneThisMonth,    
ClosuresThisMonth,    
AmountClosedThisMonth    
    
from userleads(nolock) u join    
(     
select CreatedBy,    
sum(case when cast(createdon as date)=convert(date,@fromdate,104) then 1 else 0 end) FollowupsDoneToday,    
sum(case when month(createdon)=month(convert(date,@fromdate,104)) and year(createdon)=year(convert(date,@fromdate,104)) then 1 else 0 end) FollowupsDoneThisMonth,    
sum(case when FollowUpStatus=7 and cast(createdon as date)=convert(date,@fromdate,104) then 1 else 0 end) ClosuresToday,    
sum(case when FollowUpStatus=7 and month(createdon)=month(convert(date,@fromdate,104)) and year(createdon)=year(convert(date,@fromdate,104)) then 1 else 0 end) ClosuresThisMonth,    
sum(case when FollowUpStatus=7 and cast(createdon as date)=convert(date,@fromdate,104) then AmountPaid else 0 end) AmountClosedToday,    
sum(case when FollowUpStatus=7 and month(createdon)=month(convert(date,@fromdate,104)) and year(createdon)=year(convert(date,@fromdate,104)) then AmountPaid else 0 end) AmountClosedThisMonth,    
parentid from LeadInteractionHistory(nolock) where parentid=@parentid group by CreatedBy,ParentID    
) l on l.CreatedBy=u.assignedto and l.parentid=u.parentid    
where u.parentid=@parentid    
group by assignedto,FollowupsDoneToday,ClosuresToday,AmountClosedToday,FollowupsDoneThisMonth,ClosuresThisMonth,AmountClosedThisMonth    
) D on D.assignedto=u.User_ID    
left join    
(select AssignedTo,    
sum(case when enddate<getdate() and CompletedOn is null and isactive=1 then 1 else 0 end) TaskOverDue,    
sum(case when cast(completedon as date)=convert(date,@fromdate,104) then 1 else 0 end) TasksCompletedToday,    
sum(case when month(completedon)=month(getdate()) and year(completedon)=year(getdate()) then 1 else 0 end) TasksCompletedThisMonth    
from tbl_tsk_TaskHistory(nolock) group by AssignedTo    
) E on E.AssignedTo=u.User_ID    
where u.parentid=@parentid    
end


GO

/* ============================================================
   Procedure: [dbo].[usp_dailyagentreportallusers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Agent Name Total incoming attended (inbound and outbound) Total outbound (sim and clicktocall) Talk time           
--Total Leads  Follow up overdue Follow up done this month Closures this month Amount closed This month          
--Total tasks overdue Tasks Completed this month          
CREATE   PROCEDURE usp_dailyagentreportallusers --'0','10-11-2020'        
(@users nvarchar(max)=null,@fromdate nvarchar(20)=null)          
as          
begin          
select @users=coalesce(@users,'0'),@fromdate=coalesce(@fromdate,convert(nvarchar,dateadd(d,-1,getdate()),104))    
create table #users(user_id bigint)        
 if @users<>'0'        
 begin        
 insert into #users(user_id)        
 select value as user_id from dbo.fn_split(@users,',')        
 end        
 else        
 begin        
 insert into #users(user_id)        
 select u.user_id from User_Detail(nolock) u --join Price_UserSubscriptionDetails p(nolock) on u.user_id=p.UserID and p.IsNewPlan=1 and p.PlanEndDate<=cast(getdate() as date)        
 where user_id=parentid       
 --and exists (select 1 from user_detail(nolock) where user_id<>u.user_id and parentid=u.parentid and status=1 and isnull(Cloudrole,0)<>0)        
 end        
      
create table #userreport(parentid bigint,user_login nvarchar(100),user_id bigint,TotalOutBoundCallsToday int,TotalOutBoundCallsThisMonth int,TotalInboundToday int,TotalInboundThisMonth int,[CallPeriodToday(InMins)] int,      
[CallPeriodThisMonth(InMins)] int,TotalLeads int,FollowUpsOverDue int,FollowupsDoneToday int,ClosuresToday int,AmountClosedToday numeric(18,2),FollowupsDoneThisMonth int,      
 ClosuresThisMonth int,AmountClosedThisMonth numeric(18,2),TaskOverDue int,TasksCompletedToday int, TasksCompletedthismonth int)      
      
insert into #userreport(parentid,user_login,user_id,TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth,TotalInboundToday,TotalInboundThisMonth,[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)],      
TotalLeads,FollowUpsOverDue,FollowupsDoneToday, ClosuresToday,AmountClosedToday,FollowupsDoneThisMonth,ClosuresThisMonth,AmountClosedThisMonth,TaskOverDue,TasksCompletedToday,TasksCompletedthismonth)      
      
select u.parentid,u.user_login,u.user_id,          
isnull(TotalSIMCallsToday,0)+isnull(TotalDialerCallsToday,0) as TotalOutBoundCallsToday,          
isnull(TotalSIMCallsThisMonth,0)+isnull(TotalDialerCallsThisMonth,0) as TotalOutBoundCallsThisMonth,          
isnull(TotalInboundToday,0) TotalInboundToday,          
isnull(TotalInboundThisMonth,0) TotalInboundThisMonth,          
isnull(TotalSIMCallPeriodToday,0)+          
isnull(TotalDialerCallPeriodToday,0)+          
isnull(TotalInboundCallPeriodToday,0) as [CallPeriodToday(InMins)],          
isnull(TotalSIMCallPeriodThisMonth,0)+          
isnull(TotalDialerCallPeriodThisMonth,0)+          
isnull(TotalInboundCallPeriodThisMonth,0) as [CallPeriodThisMonth(InMins)],          
isnull(TotalLeads,0)TotalLeads,isnull(FollowUpsOverDue,0) FollowUpsOverDue,isnull(FollowupsDoneToday,0) FollowupsDoneToday,isnull(ClosuresToday,0) ClosuresToday,isnull(AmountClosedToday,0)AmountClosedToday,          
isnull(FollowupsDoneThisMonth,0) FollowupsDoneThisMonth,isnull(ClosuresThisMonth,0) ClosuresThisMonth,isnull(AmountClosedThisMonth,0)AmountClosedThisMonth,          
isnull(TaskOverDue,0) TaskOverDue,isnull(TasksCompletedToday,0) TasksCompletedToday,isnull(TasksCompletedThisMonth,0) TasksCompletedthismonth          
from          
user_detail(nolock) u         
join           
 #users s(nolock) on u.ParentID=s.user_id        
left join          
(          
select u.user_login,          
sum(case when cast(CallStartDateTime as date)=convert(date,@fromdate,104) then 1 else 0 end ) as TotalSIMCallsToday,          
sum(case when month(CallStartDateTime)=month(convert(date,@fromdate,104)) and year(CallStartDateTime)=year(convert(date,@fromdate,104)) then 1 else 0 end ) as TotalSIMCallsThisMonth,          
sum(case when CallStartDateTime is not null and cast(CallStartDateTime as date)=convert(date,@fromdate,104) then datediff(ss,CallStartDateTime,CallEndDateTime)/60 else 0 end) as TotalSIMCallPeriodToday,          
sum(case when CallStartDateTime is not null and month(CallStartDateTime)=month(convert(date,@fromdate,104)) and year(CallStartDateTime)=year(convert(date,@fromdate,104)) then datediff(ss,CallStartDateTime,CallEndDateTime)/60 else 0 end)         
as TotalSIMCallPeriodThisMonth           
from user_detail u(nolock)           
join        
tbl_DailPaidCallDetails d(nolock) on u.user_id=d.userid          
--where u.parentid=@parentid --and d.callstartdatetime between cast(getdate() as date) and dateadd(dd,1,cast(getdate() as date))          
group by user_login          
) A         
on A.user_login=u.User_Login          
        
left join          
(          
select u.user_login,sum(case when cast(call_start_time as date)=cast(convert(date,@fromdate,104) as date) then 1 else 0 end) as TotalDialerCallsToday,          
sum(case when month(call_start_time)=month(cast(convert(date,@fromdate,104) as date)) and year(call_start_time)=year(cast(convert(date,@fromdate,104) as date)) then 1 else 0 end) as TotalDialerCallsThisMonth,          
sum(case when cast(call_start_time as date)=cast(convert(date,@fromdate,104) as date) then billedtime else 0 end) as TotalDialerCallPeriodToday,          
sum(case when month(call_start_time)=month(cast(convert(date,@fromdate,104) as date)) and year(call_start_time)=year(cast(convert(date,@fromdate,104) as date))  then billedtime else 0 end)           
as TotalDialerCallPeriodThisMonth          
 from user_detail u(nolock)           
 join DiallerCalls d(nolock) on u.user_id=d.user_id          
 --where u.parentid=@parentid --and d.call_start_time between cast(getdate() as date) and dateadd(dd,1,cast(getdate() as date))          
group by user_login          
) B         
on u.user_login=B.user_login          
        
left join          
(          
select u.user_login,          
sum(case when d.dialstatus='answer' and cast(d.call_start_time as date)=convert(date,@fromdate,104) then 1 else 0 end) TotalInboundToday,          
sum(case when d.dialstatus='answer' and month(d.call_start_time)=month(cast(convert(date,@fromdate,104) as date)) and year(d.call_start_time)=year(cast(convert(date,@fromdate,104) as date)) then 1 else 0 end)           
TotalInboundThisMonth,          
sum(case when d.dialstatus='answer' and cast(d.call_start_time as date)=convert(date,@fromdate,104) then datediff(ss,d.call_answer_time,d.call_end_time)/60 else 0 end) TotalInboundCallPeriodToday,          
sum(case when d.dialstatus='answer' and month(d.call_start_time)=month(convert(date,@fromdate,104)) and year(d.call_start_time)=year(convert(date,@fromdate,104)) then datediff(ss,d.call_answer_time,d.call_end_time)/60 else 0 end)           
TotalInboundCallPeriodThisMonth          
from           
user_detail(nolock) u         
join kit19calls(nolock) k on k.clientid=u.ParentID          
join Kit19CallsDialled(nolock) d on d.puniqueid=k.uniqueid and           
dbo.fn_trim0prefix(agentnumber)=case when d.callerid like '%@setcalleridpstn/n%' or d.callerid like '%@p%' then str(u.mobile) when d.callerid like '%@setcallerid/n%' or d.callerid like '%@s%'           
then cast(u.user_id as nvarchar) else str(u.mobile) end          
--where u.parentid=@parentid --and d.call_start_time between cast(getdate() as date) and dateadd(dd,1,cast(getdate() as date))          
group by user_login)  C         
on C.user_login=u.user_login          
        
left join          
(          
select assignedto,          
count(1) TotalLeads,          
sum(case when followupdate<getdate() then 1 else 0 end) as FollowUpsOverDue,          
FollowupsDoneToday,          
ClosuresToday,          
AmountClosedToday,          
FollowupsDoneThisMonth,          
ClosuresThisMonth,          
AmountClosedThisMonth          
from userleads(nolock) u join          
(           
select CreatedBy,          
sum(case when cast(createdon as date)=convert(date,@fromdate,104) then 1 else 0 end) FollowupsDoneToday,          
sum(case when month(createdon)=month(convert(date,@fromdate,104)) and year(createdon)=year(convert(date,@fromdate,104)) then 1 else 0 end) FollowupsDoneThisMonth,          
sum(case when FollowUpStatus=7 and cast(createdon as date)=convert(date,@fromdate,104) then 1 else 0 end) ClosuresToday,          
sum(case when FollowUpStatus=7 and month(createdon)=month(convert(date,@fromdate,104)) and year(createdon)=year(convert(date,@fromdate,104)) then 1 else 0 end) ClosuresThisMonth,          
sum(case when FollowUpStatus=7 and cast(createdon as date)=convert(date,@fromdate,104) then AmountPaid else 0 end) AmountClosedToday,          
sum(case when FollowUpStatus=7 and month(createdon)=month(convert(date,@fromdate,104)) and year(createdon)=year(convert(date,@fromdate,104)) then AmountPaid else 0 end) AmountClosedThisMonth,          
parentid from LeadInteractionHistory(nolock) group by CreatedBy,ParentID          
) l on l.CreatedBy=u.assignedto and l.parentid=u.parentid          
--where u.parentid=@parentid          
group by assignedto,FollowupsDoneToday,ClosuresToday,AmountClosedToday,FollowupsDoneThisMonth,ClosuresThisMonth,AmountClosedThisMonth          
) D         
on D.assignedto=u.User_ID          
        
left join          
(select AssignedTo,          
sum(case when enddate<getdate() and CompletedOn is null and isactive=1 then 1 else 0 end) TaskOverDue,          
sum(case when cast(completedon as date)=convert(date,@fromdate,104) then 1 else 0 end) TasksCompletedToday,          
sum(case when month(completedon)=month(getdate()) and year(completedon)=year(getdate()) then 1 else 0 end) TasksCompletedThisMonth          
from tbl_tsk_TaskHistory(nolock) group by AssignedTo          
) E on E.AssignedTo=u.User_ID          
      
update u set TotalOutBoundCallsToday=r.TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth=r.TotalOutBoundCallsThisMonth,TotalInboundToday=r.TotalInboundToday,TotalInboundThisMonth=r.TotalInboundThisMonth,      
[CallPeriodToday(InMins)]=r.[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)]=r.[CallPeriodThisMonth(InMins)],      
TotalLeads=r.TotalLeads,FollowUpsOverDue=r.FollowUpsOverDue,FollowupsDoneToday=r.FollowupsDoneToday, ClosuresToday=r.ClosuresToday,AmountClosedToday=r.AmountClosedToday,      
FollowupsDoneThisMonth=r.FollowupsDoneThisMonth,ClosuresThisMonth=r.ClosuresThisMonth,AmountClosedThisMonth=r.AmountClosedThisMonth,TaskOverDue=r.TaskOverDue,TasksCompletedToday=r.TasksCompletedToday,      
TasksCompletedthismonth=r.TasksCompletedthismonth,user_login=r.user_login      
from userreport u join #userreport r on u.parentid=r.parentid and u.user_id=r.user_id      
      
      
insert into userreport(parentid,user_login,user_id,TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth,TotalInboundToday,TotalInboundThisMonth,[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)],      
TotalLeads,FollowUpsOverDue,FollowupsDoneToday, ClosuresToday,AmountClosedToday,FollowupsDoneThisMonth,ClosuresThisMonth,AmountClosedThisMonth,TaskOverDue,TasksCompletedToday,TasksCompletedthismonth)      
select parentid,user_login,user_id,TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth,TotalInboundToday,TotalInboundThisMonth,[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)],      
TotalLeads,FollowUpsOverDue,FollowupsDoneToday, ClosuresToday,AmountClosedToday,FollowupsDoneThisMonth,ClosuresThisMonth,AmountClosedThisMonth,TaskOverDue,TasksCompletedToday,TasksCompletedthismonth      
from #userreport u      
where not exists(select 1 from userreport(nolock) where parentid=u.parentid and user_id=u.user_id)      
      
update userreport set Reportdate=convert(date,@fromdate,104)      
      
drop table #users      
drop table #userreport      
      
end


--select * from userreport where parentid= 38750


