/* ============================================================
   Procedure: [dbo].[usp_dailyagentreportallusers_revised]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Agent Name Total incoming attended (inbound and outbound) Total outbound (sim and clicktocall) Talk time                           
--Total Leads  Follow up overdue Follow up done this month Closures this month Amount closed This month                          
--Total tasks overdue Tasks Completed this month                          
CREATE  PROCEDURE [dbo].[usp_dailyagentreportallusers_revised] --'0','10-11-2020'                        
(@users nvarchar(max)=null,@fromdate nvarchar(20)=null)                          
as                          
begin                    
drop table if exists #users                      
drop table if exists #userreport              
--declare @users nvarchar(max)=null,@fromdate nvarchar(20)=null              
select @users=coalesce(@users,'0'),@fromdate=coalesce(@fromdate,convert(nvarchar,dateadd(d,-1,getdate()),104))                    
create table #users(user_id bigint)                        
 if @users<>'0'                        
 begin                        
 insert into #users(user_id)                        
 select value as user_id from dbo.fn_split(@users,',')                        
 end                        
 else                        
 begin                        
 insert into #users(user_id)                        
 select u.user_id from User_Detail(nolock) u join Price_UserSubscriptionDetails p(nolock) on u.user_id=p.UserID and p.IsNewPlan=1       
 and p.PlanEndDate>=cast(getdate() as date)  where user_id=parentid                       
 --and exists (select 1 from user_detail(nolock) where user_id<>u.user_id and parentid=u.parentid and status=1 and isnull(Cloudrole,0)<>0)                        
 end                        
                      
create table #userreport(parentid bigint,user_login nvarchar(100),user_id bigint,              
TotalOutBoundCallsToday int,TotalOutBoundCallsThisMonth int,TotalInboundToday int,TotalInboundThisMonth int,              
[CallPeriodToday(InMins)] int,[CallPeriodThisMonth(InMins)] int,              
TotalLeads int,FollowUpsOverDue int,FollowupsDoneToday int,ClosuresToday int,AmountClosedToday numeric(18,2),FollowupsDoneThisMonth int,                      
 ClosuresThisMonth int,AmountClosedThisMonth numeric(18,2),TaskOverDue int,TasksCompletedToday int, TasksCompletedthismonth int,              
 TotalEnquiriesAddedToday int,TotalEnquiriesAddedThismonth int,              
 TotalLeadsAddedToday int,TotalLeadsAddedThisMonth int,              
 TasksCreatedToday int,TasksCreatedThisMonth int,               
 AppointmentsCreatedToday int,AppointmentsCreatedThisMonth int, AppointmentsOverDue int,AppointmentsCompletedToday int,               
 AppointmentsCompletedthismonth int,              
 NewPipelineCasesAddedToday int,NewPipelineCasesAddedThisMonth int,PipelineMovedToday int,PipelineMovedThisMonth int,              
 PipelineCasesWonToday int,PipelineCasesWonThisMonth int,PipelineCasesExpiredToday int,PipelineCasesExpiringThisMonth int,              
 PipelineCasesLostToday int,PipelineCasesLostThisMonth int,              
 TotalCallsMissedToday int,TotalCallsMissedThisMonth int              
 )                      
                      
insert into #userreport(parentid,user_login,user_id,TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth,TotalInboundToday,TotalInboundThisMonth,[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)],                      
TotalLeads,FollowUpsOverDue,FollowupsDoneToday, ClosuresToday,AmountClosedToday,FollowupsDoneThisMonth,ClosuresThisMonth,AmountClosedThisMonth,TaskOverDue,TasksCompletedToday,TasksCompletedthismonth,              
TotalLeadsAddedToday,TotalLeadsAddedThisMonth,TasksCreatedToday,TasksCreatedThisMonth,AppointmentsCreatedToday,AppointmentsCreatedThisMonth,              
AppointmentsCompletedToday,AppointmentsCompletedthismonth,AppointmentsOverDue,TotalCallsMissedToday,TotalCallsMissedThisMonth,              
NewPipelineCasesAddedToday,NewPipelineCasesAddedThisMonth,PipelineMovedToday,PipelineMovedThisMonth,PipelineCasesWonToday,PipelineCasesWonThisMonth,              
PipelineCasesLostToday,PipelineCasesLostThisMonth,PipelineCasesExpiredToday,PipelineCasesExpiringThisMonth,              
TotalEnquiriesAddedToday,TotalEnquiriesAddedThismonth              
)                      
                      
select u.parentid,u.user_login,u.user_id,                          
isnull(TotalOutBoundCallsToday,0) as TotalOutBoundCallsToday,                          
isnull(TotalOutBoundCallsThisMonth,0) as TotalOutBoundCallsThisMonth,                          
isnull(TotalInboundCallsToday,0) TotalInboundToday,                          
isnull(TotalInboundCallsThisMonth,0) TotalInboundThisMonth,                          
isnull(TotalCallPeriodToday,0) as [CallPeriodToday(InMins)],                          
isnull(TotalCallPeriodThisMonth,0) as [CallPeriodThisMonth(InMins)],                          
isnull(TotalLeads,0)TotalLeads,isnull(FollowUpsOverDue,0) FollowUpsOverDue,isnull(FollowupsDoneToday,0) FollowupsDoneToday,isnull(ClosuresToday,0) ClosuresToday,isnull(AmountClosedToday,0)AmountClosedToday,                          
isnull(FollowupsDoneThisMonth,0) FollowupsDoneThisMonth,isnull(ClosuresThisMonth,0) ClosuresThisMonth,isnull(AmountClosedThisMonth,0)AmountClosedThisMonth,                          
isnull(TaskOverDue,0) TaskOverDue,isnull(TasksCompletedToday,0) TasksCompletedToday,isnull(TasksCompletedThisMonth,0) TasksCompletedthismonth,              
isnull(TotalLeadsAddedToday,0) TotalLeadsAddedToday,              
isnull(TotalLeadsAddedThisMonth,0) TotalLeadsAddedThisMonth,              
isnull(TasksCreatedToday,0) TasksCreatedToday,isnull(TasksCreatedThisMonth,0) TasksCreatedThisMonth,              
isnull(AppointmentsCreatedToday,0) AppointmentsCreatedToday,isnull(AppointmentsCreatedThisMonth,0) AppointmentsCreatedThisMonth,              
isnull(AppointmentsCompletedToday,0) AppointmentsCompletedToday,isnull(AppointmentsCompletedThisMonth,0) AppointmentsCompletedThisMonth,              
isnull(AppointmentsOverdue,0) AppointmentsOverdue,isnull(TotalCallsMissedToday,0) TotalCallsMissedToday,              
isnull(TotalCallsMissedThisMonth,0)TotalCallsMissedThisMonth,              
isnull(NewPipelineCasesAddedToday,0) NewPipelineCasesAddedToday,isnull(NewPipelineCasesAddedThisMonth,0) NewPipelineCasesAddedThisMonth,              
isnull(PipelineMovedToday,0) PipelineMovedToday,isnull(PipelineMovedThisMonth,0) PipelineMovedThisMonth,              
isnull(PipelineCasesWonToday,0) PipelineCasesWonToday,isnull(PipelineCasesWonThisMonth,0) PipelineCasesWonThisMonth,              
isnull(PipelineCasesLostToday,0) PipelineCasesLostToday,isnull(PipelineCasesLostThisMonth,0) PipelineCasesLostThisMonth,              
isnull(PipelineCasesExpiredToday,0) PipelineCasesExpiredToday,isnull(PipelineCasesExpiringThisMonth,0) PipelineCasesExpiringThisMonth,              
isnull(TotalEnquiriesAddedToday,0) TotalEnquiriesAddedToday,isnull(TotalEnquiriesAddedThisMonth,0) TotalEnquiriesAddedThisMonth              
from                          
user_detail(nolock) u                         
join                           
 #users s(nolock) on u.ParentID=s.user_id                        
left join                          
(                          
select u.user_login,                          
sum(case when cast(Callstarttime as date)=convert(date,@fromdate,104) and direction in ('out','outgoing') then 1 else 0 end ) as TotalOutBoundCallsToday,                          
sum(case when month(Callstarttime)=month(convert(date,@fromdate,104)) and year(Callstarttime)=year(convert(date,@fromdate,104))              
 and direction in ('out','outgoing') then 1 else 0 end ) as TotalOutBoundCallsThisMonth,                     
 sum(case when cast(Callstarttime as date)=convert(date,@fromdate,104) and direction='incoming' then 1 else 0 end ) as TotalInBoundCallsToday,                          
sum(case when month(Callstarttime)=month(convert(date,@fromdate,104)) and year(Callstarttime)=year(convert(date,@fromdate,104))              
 and direction='incoming' then 1 else 0 end ) as TotalInBoundCallsThisMonth,                     
              
sum(case when cast(Callstarttime as date)=convert(date,@fromdate,104)               
and agentcalldisposition in ('Answer','Answered')              
then datediff(ss,Agentpickuptime,CallEndTime)/60  else 0 end) as TotalCallPeriodToday,              
sum(case when Callstarttime is not null and month(Callstarttime)=month(convert(date,@fromdate,104))              
and year(Callstarttime)=year(convert(date,@fromdate,104)) and agentcalldisposition in ('Answer','Answered')              
then datediff(ss,Agentpickuptime,CallEndTime)/60  else 0 end)                         
as TotalCallPeriodThisMonth,              
sum(case when cast(Callstarttime as date)=convert(date,@fromdate,104)               
and agentcalldisposition in ('CANCEL','NOANSWER','BUSY') then 1 else 0 end) TotalCallsMissedToday,              
sum(case when Callstarttime is not null and month(Callstarttime)=month(convert(date,@fromdate,104))              
and year(Callstarttime)=year(convert(date,@fromdate,104))               
and agentcalldisposition in ('CANCEL','NOANSWER','BUSY') then 1 else 0 end) TotalCallsMissedThisMonth              
from user_detail u(nolock)                           
join                        
CallLog d(nolock) on u.user_id=d.agentuserid                          
group by user_login                          
) A                         
on A.user_login=u.User_Login                          
left join              
(              
select createdby,sum(case when cast(createddate as date)=convert(date,@fromdate,104) then 1 else 0 end) TotalEnquiriesAddedToday,              
sum(case when month(createddate)=month(convert(date,@fromdate,104)) and year(createddate)=year(convert(date,@fromdate,104)) then 1 else 0 end)              
TotalEnquiriesAddedThisMonth              
from userenquiry(nolock)               
group by createdby              
) ue on ue.CreatedBy=u.user_id              
              
              
left join                          
              
(                          
select assignedto,                          
count(1) TotalLeads,                          
sum(case when followupdate<getdate() then 1 else 0 end) as FollowUpsOverDue,                          
FollowupsDoneToday,                          
ClosuresToday,                          
AmountClosedToday,                          
FollowupsDoneThisMonth,                          
ClosuresThisMonth,                          
AmountClosedThisMonth                          
from userleads(nolock) u join                          
(                           
select l.CreatedBy,                          
sum(case when cast(createdon as date)=convert(date,@fromdate,104) and IsReassign=0 and s.IsCallback=1 then 1 else 0 end) FollowupsDoneToday,                          
sum(case when month(createdon)=month(convert(date,@fromdate,104)) and year(createdon)=year(convert(date,@fromdate,104))              
and IsReassign=0 and s.IsCallback=1               
then 1 else 0 end) FollowupsDoneThisMonth,                          
sum(case when s.IsConvert=1 and cast(FollowupDate as date)=convert(date,@fromdate,104) then 1 else 0 end) ClosuresToday,                          
sum(case when s.IsConvert=1 and month(FollowupDate)=month(convert(date,@fromdate,104)) and year(FollowupDate)=year(convert(date,@fromdate,104)) then 1 else 0 end) ClosuresThisMonth,                          
sum(case when s.IsConvert=1 and cast(FollowupDate as date)=convert(date,@fromdate,104) then AmountPaid else 0 end) AmountClosedToday,                          
sum(case when s.IsConvert=1 and month(FollowupDate)=month(convert(date,@fromdate,104)) and year(FollowupDate)=year(convert(date,@fromdate,104)) then AmountPaid else 0 end) AmountClosedThisMonth,                          
l.parentid from LeadInteractionHistory(nolock) l join FollowUp_Status s(nolock) on l.FollowUpStatus=s.id              
group by l.CreatedBy,l.ParentID                          
) l on l.CreatedBy=u.assignedto and l.parentid=u.parentid                          
 group by assignedto,FollowupsDoneToday,ClosuresToday,AmountClosedToday,FollowupsDoneThisMonth,ClosuresThisMonth,AmountClosedThisMonth                          
) D                         
on D.assignedto=u.User_ID                          
left join              
(select createdby,sum(case when cast(createdon as date)=convert(date,@fromdate,104) then 1 else 0 end) TotalLeadsAddedToday              
,sum(case when month(FollowupDate)=month(convert(date,@fromdate,104)) and year(FollowupDate)=year(convert(date,@fromdate,104)) then 1 else 0 end) TotalLeadsAddedThisMonth              
from userleads(nolock) group by createdby) ul on ul.CreatedBy=u.user_id              
left join                          
(select AssignedTo,                          
sum(case when istask=1 and enddate<getdate() and CompletedOn is null and isactive=1 then 1 else 0 end) TaskOverDue,                          
sum(case when istask=1 and cast(completedon as date)=convert(date,@fromdate,104) then 1 else 0 end) TasksCompletedToday,                          
sum(case when istask=1 and month(completedon)=month(convert(date,@fromdate,104)) and year(completedon)=year(convert(date,@fromdate,104)) then 1 else 0 end) TasksCompletedThisMonth,              
sum(case when IsAppointment=1 and enddate<getdate() and CompletedOn is null and isactive=1 then 1 else 0 end) AppointmentsOverDue,                          
sum(case when IsAppointment=1 and cast(completedon as date)=convert(date,@fromdate,104) then 1 else 0 end) AppointmentsCompletedToday,                          
sum(case when IsAppointment=1 and month(completedon)=month(convert(date,@fromdate,104)) and year(completedon)=year(convert(date,@fromdate,104)) then 1 else 0 end) AppointmentsCompletedThisMonth                          
from tbl_tsk_TaskHistory(nolock) group by AssignedTo                          
) E on E.AssignedTo=u.User_ID                          
left join                          
(select createdby,                          
sum(case when istask=1 and cast(createdon as date)=convert(date,@fromdate,104) then 1 else 0 end) TasksCreatedToday,                          
sum(case when istask=1 and month(createdon)=month(convert(date,@fromdate,104)) and year(createdon)=year(convert(date,@fromdate,104)) then 1 else 0 end) TasksCreatedThisMonth,              
sum(case when IsAppointment=1 and cast(createdon as date)=convert(date,@fromdate,104) then 1 else 0 end) AppointmentsCreatedToday,                          
sum(case when IsAppointment=1 and month(createdon)=month(convert(date,@fromdate,104)) and year(createdon)=year(convert(date,@fromdate,104)) then 1 else 0 end) AppointmentsCreatedThisMonth              
from tbl_tsk_TaskHistory(nolock) group by createdby                          
) TA on TA.createdby=u.User_ID                          
left join              
(              
select dealowner,count(distinct leadid) as NewPipelineCasesAddedToday from leadpipelinemapping (nolock) l join              
pipeline_master p (nolock) on p.id=l.pipelineid              
where               
cast(l.CreatedDate as date)=convert(date,@fromdate,104) and not exists              
(select 1 from leadpipelinemapping (nolock) where leadid=l.leadid and createddate<l.createddate and pipelineid=l.pipelineid )              
group by dealowner              
) np on np.DealOwner=u.User_ID              
left join              
(              
select dealowner,count(distinct leadid) as NewPipelineCasesAddedThisMonth from leadpipelinemapping (nolock) l join              
pipeline_master p (nolock) on p.id=l.pipelineid              
where               
month(l.CreatedDate)=month(convert(date,@fromdate,104)) and year(l.CreatedDate)=year(convert(date,@fromdate,104)) and not exists              
(select 1 from leadpipelinemapping (nolock) where leadid=l.leadid and createddate<l.createddate and pipelineid=l.pipelineid )              
group by dealowner        
) npt on np.DealOwner=u.User_ID              
left join              
(              
select dealowner,count(distinct leadid) as PipelineMovedToday from leadpipelinemapping (nolock) l join              
pipeline_master p (nolock) on p.id=l.pipelineid              
where                
cast(l.CreatedDate as date)=convert(date,@fromdate,104) and exists              
(select 1 from leadpipelinemapping (nolock) where leadid=l.leadid and createddate<l.createddate and pipelineid=l.pipelineid )              
group by dealowner              
)               
npmt on npmt.DealOwner=u.User_ID              
left join              
(              
select dealowner,count(distinct leadid) as PipelineMovedThisMonth from leadpipelinemapping (nolock) l join              
pipeline_master p (nolock) on p.id=l.pipelineid              
where                
month(l.CreatedDate)=month(convert(date,@fromdate,104)) and year(l.CreatedDate)=year(convert(date,@fromdate,104)) and exists              
(select 1 from leadpipelinemapping (nolock) where leadid=l.leadid and createddate<l.createddate and pipelineid=l.pipelineid )              
group by dealowner              
              
) npmth on npmth.DealOwner=u.User_ID              
--PipelineCasesWonToday,PipelineCasesWonThisMonth,              
--PipelineCasesLostToday,PipelineCasesLostThisMonth,PipelineCasesExpiredToday,PipelineCasesExpiredThisMonth              
left join              
(              
select dealowner,sum(case when cast(l.CreatedDate as date)=convert(date,@fromdate,104) and s.name='Won' then 1 else 0 end )              
PipelineCasesWonToday              
,sum(case when month(l.CreatedDate)=month(convert(date,@fromdate,104)) and year(l.CreatedDate)=year(convert(date,@fromdate,104)) and s.name='Won' then 1 else 0 end )              
PipelineCasesWonThisMonth              
,sum(case when cast(l.CreatedDate as date)=convert(date,@fromdate,104) and s.name='Lost' then 1 else 0 end )              
PipelineCasesLostToday              
,sum(case when month(l.CreatedDate)=month(convert(date,@fromdate,104)) and year(l.CreatedDate)=year(convert(date,@fromdate,104)) and s.name='Won' then 1 else 0 end )              
PipelineCasesLostThisMonth              
,sum( case when cast(dbo.fn_getleadexpiry(l.leadid,p.id) as date) =convert(date,@fromdate,104) then 1 else 0 end)              
PipelineCasesExpiredToday              
,sum( case when month(dbo.fn_getleadexpiry(l.leadid,p.id)) =month(convert(date,@fromdate,104)) and               
year(dbo.fn_getleadexpiry(l.leadid,p.id)) =year(convert(date,@fromdate,104))              
then 1 else 0 end)              
PipelineCasesExpiringThisMonth              
from leadpipelinemapping (nolock) l join Pipeline_Master p(nolock) on p.id=l.pipelineid              
join pipelinestages s (nolock) on s.id=l.PipeLineStage              
group by dealowner              
) p on p.dealowner=u.user_id              
              
              
--select * from #userreport              
              
              
              
              
                      
update u set TotalOutBoundCallsToday=r.TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth=r.TotalOutBoundCallsThisMonth,TotalInboundToday=r.TotalInboundToday,TotalInboundThisMonth=r.TotalInboundThisMonth,                      
[CallPeriodToday(InMins)]=r.[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)]=r.[CallPeriodThisMonth(InMins)],                      
TotalLeads=r.TotalLeads,FollowUpsOverDue=r.FollowUpsOverDue,FollowupsDoneToday=r.FollowupsDoneToday, ClosuresToday=r.ClosuresToday,AmountClosedToday=r.AmountClosedToday,                      
FollowupsDoneThisMonth=r.FollowupsDoneThisMonth,ClosuresThisMonth=r.ClosuresThisMonth,AmountClosedThisMonth=r.AmountClosedThisMonth,TaskOverDue=r.TaskOverDue,TasksCompletedToday=r.TasksCompletedToday,                      
TasksCompletedthismonth=r.TasksCompletedthismonth,user_login=r.user_login,              
TotalEnquiriesAddedToday=r.TotalEnquiriesAddedToday,TotalEnquiriesAddedThismonth=r.TotalEnquiriesAddedThismonth,              
 TotalLeadsAddedToday =r.TotalLeadsAddedToday,TotalLeadsAddedThisMonth=r.TotalLeadsAddedThisMonth,              
 TasksCreatedToday=r.TasksCreatedToday,TasksCreatedThisMonth =r.TasksCreatedThisMonth,               
 AppointmentsCreatedToday=r.AppointmentsCreatedToday,AppointmentsCreatedThisMonth=r.AppointmentsCreatedThisMonth,               
 AppointmentsOverDue=r.AppointmentsOverDue,AppointmentsCompletedToday=r.AppointmentsCompletedToday,               
 AppointmentsCompletedthismonth =r.AppointmentsCompletedthismonth,              
 NewPipelineCasesAddedToday=r.NewPipelineCasesAddedToday,NewPipelineCasesAddedThisMonth=r.NewPipelineCasesAddedThisMonth,              
 PipelineMovedToday=r.PipelineMovedToday,PipelineMovedThisMonth=r.PipelineMovedThisMonth,              
 PipelineCasesWonToday=r.PipelineCasesWonToday,PipelineCasesWonThisMonth=r.PipelineCasesWonThisMonth,              
 PipelineCasesExpiredToday=r.PipelineCasesExpiredToday,PipelineCasesExpiringThisMonth=r.PipelineCasesExpiringThisMonth,              
 PipelineCasesLostToday=r.PipelineCasesLostToday,PipelineCasesLostThisMonth=r.PipelineCasesLostThisMonth,              
 TotalCallsMissedToday=r.TotalCallsMissedToday,TotalCallsMissedThisMonth=r.TotalCallsMissedThisMonth              
from userreport u join #userreport r on u.parentid=r.parentid and u.user_id=r.user_id                      
             
   /*          
          
 update u set TotalOutBoundCallsToday=r.TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth=r.TotalOutBoundCallsThisMonth,TotalInboundToday=r.TotalInboundToday,TotalInboundThisMonth=r.TotalInboundThisMonth,                      
[CallPeriodToday(InMins)]=r.[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)]=r.[CallPeriodThisMonth(InMins)],                      
TotalLeads=r.TotalLeads,FollowUpsOverDue=r.FollowUpsOverDue,FollowupsDoneToday=r.FollowupsDoneToday, ClosuresToday=r.ClosuresToday,AmountClosedToday=r.AmountClosedToday,                      
FollowupsDoneThisMonth=r.FollowupsDoneThisMonth,ClosuresThisMonth=r.ClosuresThisMonth,AmountClosedThisMonth=r.AmountClosedThisMonth,TaskOverDue=r.TaskOverDue,TasksCompletedToday=r.TasksCompletedToday,                      
TasksCompletedthismonth=r.TasksCompletedthismonth,user_login=r.user_login,              
TotalEnquiriesAddedToday=r.TotalEnquiriesAddedToday,TotalEnquiriesAddedThismonth=r.TotalEnquiriesAddedThismonth,              
 TotalLeadsAddedToday =r.TotalLeadsAddedToday,TotalLeadsAddedThisMonth=r.TotalLeadsAddedThisMonth,              
 TasksCreatedToday=r.TasksCreatedToday,TasksCreatedThisMonth =r.TasksCreatedThisMonth,               
 AppointmentsCreatedToday=r.AppointmentsCreatedToday,AppointmentsCreatedThisMonth=r.AppointmentsCreatedThisMonth,               
 AppointmentsOverDue=r.AppointmentsOverDue,AppointmentsCompletedToday=r.AppointmentsCompletedToday,               
 AppointmentsCompletedthismonth =r.AppointmentsCompletedthismonth,              
 NewPipelineCasesAddedToday=r.NewPipelineCasesAddedToday,NewPipelineCasesAddedThisMonth=r.NewPipelineCasesAddedThisMonth,              
 PipelineMovedToday=r.PipelineMovedToday,PipelineMovedThisMonth=r.PipelineMovedThisMonth,              
 PipelineCasesWonToday=r.PipelineCasesWonToday,PipelineCasesWonThisMonth=r.PipelineCasesWonThisMonth,              
 PipelineCasesExpiredToday=r.PipelineCasesExpiredToday,PipelineCasesExpiringThisMonth=r.PipelineCasesExpiringThisMonth,              
 PipelineCasesLostToday=r.PipelineCasesLostToday,PipelineCasesLostThisMonth=r.PipelineCasesLostThisMonth,              
 TotalCallsMissedToday=r.TotalCallsMissedToday,TotalCallsMissedThisMonth=r.TotalCallsMissedThisMonth              
from userreport_Archived u join #userreport r on u.parentid=r.parentid and u.user_id=r.user_id                      
            
  */          
            
            
            
            
                      
insert into userreport(parentid,user_login,user_id,TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth,TotalInboundToday,TotalInboundThisMonth,[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)],                      
TotalLeads,FollowUpsOverDue,FollowupsDoneToday, ClosuresToday,AmountClosedToday,FollowupsDoneThisMonth,ClosuresThisMonth,AmountClosedThisMonth,TaskOverDue,TasksCompletedToday,TasksCompletedthismonth,              
TotalLeadsAddedToday,TotalLeadsAddedThisMonth,TasksCreatedToday,TasksCreatedThisMonth,AppointmentsCreatedToday,AppointmentsCreatedThisMonth,              
AppointmentsCompletedToday,AppointmentsCompletedthismonth,AppointmentsOverDue,TotalCallsMissedToday,TotalCallsMissedThisMonth,              
