 update u set TotalOutBoundCallsToday=r.TotalOutBoundCallsToday,TotalOutBoundCallsThisMonth=r.TotalOutBoundCallsThisMonth,TotalInboundToday=r.TotalInboundToday,TotalInboundThisMonth=r.TotalInboundThisMonth,                    
[CallPeriodToday(InMins)]=r.[CallPeriodToday(InMins)],[CallPeriodThisMonth(InMins)]=r.[CallPeriodThisMonth(InMins)],                    
