TasksCompletedthismonth=r.TasksCompletedthismonth,user_login=r.user_login,            
TotalEnquiriesAddedToday=r.TotalEnquiriesAddedToday,TotalEnquiriesAddedThismonth=r.TotalEnquiriesAddedThismonth,            
 TotalLeadsAddedToday =r.TotalLeadsAddedToday,TotalLeadsAddedThisMonth=r.TotalLeadsAddedThisMonth,            
 TasksCreatedToday=r.TasksCreatedToday,TasksCreatedThisMonth =r.TasksCreatedThisMonth,             
 AppointmentsCreatedToday=r.AppointmentsCreatedToday,AppointmentsCreatedThisMonth=r.AppointmentsCreatedThisMonth,             
 AppointmentsOverDue=r.AppointmentsOverDue,AppointmentsCompletedToday=r.AppointmentsCompletedToday,             
 AppointmentsCompletedthismonth =r.AppointmentsCompletedthismonth,            
 NewPipelineCasesAddedToday=r.NewPipelineCasesAddedToday,NewPipelineCasesAddedThisMonth=r.NewPipelineCasesAddedThisMonth,            
 PipelineMovedToday=r.PipelineMovedToday,PipelineMovedThisMonth=r.PipelineMovedThisMonth,            
 PipelineCasesWonToday=r.PipelineCasesWonToday,PipelineCasesWonThisMonth=r.PipelineCasesWonThisMonth,            
 PipelineCasesExpiredToday=r.PipelineCasesExpiredToday,PipelineCasesExpiringThisMonth=r.PipelineCasesExpiringThisMonth,            
 PipelineCasesLostToday=r.PipelineCasesLostToday,PipelineCasesLostThisMonth=r.PipelineCasesLostThisMonth,            
 TotalCallsMissedToday=r.TotalCallsMissedToday,TotalCallsMissedThisMonth=r.TotalCallsMissedThisMonth            
from userreport_Archived u join #userreport r on u.parentid=r.parentid and u.user_id=r.user_id      
     and Reportdate = convert(date,@fromdate,104)     
        
    
  delete from userreport_Archived        
      where cast(Reportdate as date) < cast((GETDATE() - 30)  as date)        
          
