/* ============================================================
   Procedure: [dbo].[usp_DailyEnquiryReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_DailyEnquiryReport]  
@Userid bigint,  
@fromdate date,  
@strCriteriaName nvarchar(max)  
as 
begin  
--declare @fromdate DATE   
if(@fromdate =cast(GETDATE() as date ))  
begin  
set @fromdate= CAST(DATEADD(DAY, 1, EOMONTH(GETDATE(), -1)) as date)   
end  
  
  
  
select distinct SourceID,isnull(Name,'') as Source,isnull(Name,'') as UserByName, isnull(dbo.fn_getDailyenquirysourcecount(a.CreatedBy, getdate(), getdate(), b.Name),0) as Today   
, isnull(dbo.fn_getDailyenquirysourcecount(a.CreatedBy, @fromdate, getdate(), b.Name),0) as MTD   
into #temp 
from UserEnquiry(nolock) a  
left join usersourcesettings(nolock) b on a.SourceName=b.SourceID  
where CreatedBy in (cast(@strCriteriaName as bigint)) and IsActive=1 and ParentID=@Userid-- or 0=@strCriteriaName --and SourceID<>0   
and SourceID is not null  
select ROW_NUMBER() OVER(ORDER BY (SELECT 1)) SrNo,* from #temp where Today<>0 or MTD<>0  
select 'Today,MTD' SourceNameCollections     
drop table #temp  
end  



