/* ============================================================
   Procedure: [dbo].[usp_DailyLowBalanceAlert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     --170,335,'PANDIT','This is Test',0,1,0,0        
CREATE   PROCEDURE [dbo].[usp_DailyLowBalanceAlert]       
AS        
BEGIN        
DECLARE @BatchID BIGINT      
begin tran      
 INSERT INTO GetBatchRecord        
   (        
     [User_id],        
     RandNum        
   )        
 VALUES        
   (        
     335,        
     335        
   )        
  select @BatchID=SCOPE_IDENTITY()        
 DELETE         
 FROM   GetBatchRecord        
 WHERE  BatchID=@BatchID      
 commit      

 --insert into DLT_Template_MSG(batchid,DLT_TemplateID)
 --select @BatchID,
       
declare @smppid int=(select smppid from user_detail(nolock) where USER_ID=335)      
       
select a.totalconsumption totalsmsconsumption,a.user_id,c.balance smsbalance      
into #LowSMSBalance      
from credit_details(nolock) c       
join (select user_id,sum(totalconsumption) totalconsumption from dailyconsumption d where       
datediff(dd,d.Date,cast(getdate() as DATE))<=7       
group by d.user_id) a      
on a.User_id=c.User_ID      
where c.Credit_ID =(select MAX(credit_id) from credit_details(nolock) where user_id=c.User_ID)      
and (c.Balance<a.totalconsumption or       
c.user_id=17626)      
order by totalconsumption desc      
      
select a.totalconsumption totalmailconsumption,a.user_id,c.balance mailbalance      
into #LowMailBalance      
from mailcreditdetails(nolock) c       
join (select user_id,sum(totalmailconsumption) totalconsumption from dailymailconsumption d where       
datediff(dd,d.Date,cast(getdate() as DATE))<=7      
group by d.user_id) a      
on a.User_id=c.User_ID      
where c.Credit_ID =(select MAX(credit_id) from mailcreditdetails(nolock) where user_id=c.User_ID)      
and (c.Balance<a.totalconsumption  or       
c.user_id=17626)      
order by totalconsumption desc      
      
      
select ls.totalsmsconsumption,lm.totalmailconsumption,smsbalance,mailbalance,mobile,user_login       
into #LowBalance      
from       
#LowSMSBalance ls full outer join #LowMailBalance lm      
on ls.User_id=lm.user_id      
join user_detail(nolock) u      
on ls.User_id=u.user_id or lm.User_id=u.user_id      
where u.M_ID=10043      
      
        
 INSERT INTO CloneMessageDeliveryStatus        
   (        
     -- MessageID -- this column value is auto-generated        
     BatchID,        
     Mobile,        
     [Message],        
     MessageStatus,        
     SenderID,        
     MessageInsertDate,        
     ScheduledDate,        
     ScheduledTime,        
     SmppID,        
     U_ID,        
     IsUniCode,        
     IsDnd,        
     IsAirtel,        
     MobileSubSet,        
     ValidNo,        
     IsPrority,        
     IsAllowDND,        
     DBType        
   )        
 SELECT A.BatchID,        
        A.Mobile,        
        A.Messagetext,        
        A.MessageStatus,        
        A.SenderID,        
        A.MessageInsertDate,        
        isnull(A.ScheduledDate,''),        
        isnull(A.ScheduledTime,''),        
        A.SmppID,        
        A.U_ID,        
        A.IsUnicode,        
        A.IsDnd,        
        A.IsAirtel,        
        A.MobileSubSet,        
        A.ValidNo,        
        A.IsPrority,        
        A.IsAllowDND,        
        A.DBType        
 FROM   ( SELECT @BatchID     AS BatchID,        
 str(Mobile) Mobile,  
 'Dear '+cast(a.user_login as nvarchar) + ',Some of the balances in your account are low. Current balances are '
 +      
case when smsbalance is not null then  'SMS: ' +cast(smsbalance as nvarchar)  + ' ' else '' end +
case when mailbalance is not null then  'Mail: ' +cast(smsbalance as nvarchar)  + ' ' else '' end +
 'which is lower than your last 7 days consumption of these services - Team Kit19. Need help? Reach us at +917840049991'      
--'Dear '+cast(a.user_login as nvarchar) + ' ,'+      
--case when smsbalance is not null then  'Your SMS Balance is Low. Current SMS Balance is ' +cast(smsbalance as nvarchar)  +' which is lower than your last 7 days SMS consumption of '+cast(totalsmsconsumption as nvarchar) else '' end +      
--case when mailbalance is not null then  ' Your Mail Balance is Low. Current Mail Balance is ' +cast(mailbalance as nvarchar)  +' which is lower than your last 7 days Mail consumption of '+cast(totalmailconsumption as nvarchar) else '' end +      
      
--+' - Team Kit19. Need help? Reach us at +917840049991'      
 AS Messagetext,        
NULL         AS MessageStatus,        
'KITAPP'    AS SenderID,        
GETDATE()    AS MessageInsertDate,        
 NULL         AS ScheduledDate,        
NULL AS ScheduledTime,        
@smppid smppid,        
335     AS U_ID,        
0   AS IsUnicode,        
0            AS IsDnd,        
0            AS IsAirtel,        
0            AS MobileSubSet,        
1            AS ValidNo,        
1       AS IsPrority,        
0            AS IsAllowDND,        
0            AS DBType        
FROM #lowbalance a      
  ) A        
 WHERE  A.Mobile <> ''  and A.messagetext is not null      
 drop table #lowsmsbalance      
 drop table #LowMailBalance      
 drop table #lowbalance      
       
         
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_DailyLowBalanceAlert1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     --170,335,'PANDIT','This is Test',0,1,0,0                  
CREATE   PROCEDURE [dbo].[usp_DailyLowBalanceAlert1]                 
AS                  
BEGIN                  
DECLARE @BatchID BIGINT                
begin tran                
 INSERT INTO GetBatchRecord                  
   (                  
     [User_id],                  
     RandNum                  
   )                  
 VALUES                  
   (                  
     335,                  
     335                  
   )                  
  select @BatchID=SCOPE_IDENTITY()                  
 DELETE                   
 FROM   GetBatchRecord                  
 WHERE  BatchID=@BatchID                
 commit                
       
insert into dlt_template_msg(batchid,dlt_templateid,batchtime)      
select @batchid,(select DLTTemplateID from [DLTMappedEvent] where event='low balance all') ,getdate()      
              
declare @smppid int=(select smppid from user_detail(nolock) where USER_ID=335)                
                 
select a.totalconsumption totalsmsconsumption,a.user_id,c.balance smsbalance                
into #LowSMSBalance                
from credit_details(nolock) c                 
join (select user_id,sum(totalconsumption) totalconsumption from dailyconsumption d where                 
datediff(dd,d.Date,cast(getdate() as DATE))<=7                 
group by d.user_id) a                
on a.User_id=c.User_ID                
where c.Credit_ID =(select MAX(credit_id) from credit_details(nolock) where user_id=c.User_ID)                
and (c.Balance<a.totalconsumption or                 
c.user_id=17626)        
order by totalconsumption desc                
                
select a.totalconsumption totalmailconsumption,a.user_id,c.balance mailbalance                
into #LowMailBalance                
from mailcreditdetails(nolock) c                 
join (select user_id,sum(totalmailconsumption) totalconsumption from dailymailconsumption d where                 
datediff(dd,d.Date,cast(getdate() as DATE))<=7                
group by d.user_id) a                
on a.User_id=c.User_ID                
where c.Credit_ID =(select MAX(credit_id) from mailcreditdetails(nolock) where user_id=c.User_ID)                
and (c.Balance<a.totalconsumption  or                 
c.user_id=17626)                
order by totalconsumption desc                
          
select isnull(a.totalmoneyconsumption,0) totalmoneyconsumption,a.user_id,isnull(c.balance,0) moneybalance                
into #LowMoneyBalance                
from intcredit_details(nolock) c                 
join (select user_id,sum(totalmoneyconsumption) totalmoneyconsumption from dailymoneyconsumption d where                 
datediff(dd,d.Date,cast(getdate() as DATE))<=7                 
group by d.user_id) a                
on a.User_id=c.User_ID                
where c.Credit_ID =(select MAX(credit_id) from intcredit_details(nolock) where user_id=c.User_ID)                
and (c.Balance<a.totalmoneyconsumption or                 
c.user_id=17626)                
order by totalmoneyconsumption desc                
          
                
                
select ls.totalsmsconsumption,lm.totalmailconsumption,lb.totalmoneyconsumption,smsbalance,mailbalance,moneybalance,mobile,user_login                 
into #LowBalance                
from                 
#LowSMSBalance ls full outer join #LowMailBalance lm                
on ls.User_id=lm.user_id            
full outer join #LowMoneyBalance lb          
on ls.user_id=lb.User_id              
join user_detail(nolock) u                
on ls.User_id=u.user_id or lm.User_id=u.user_id  or lb.User_id=u.User_ID              
where u.M_ID=10043  
and u.User_id=u.parentid
                
                  
 INSERT INTO CloneMessageDeliveryStatus                  
   (                  
     -- MessageID -- this column value is auto-generated                  
     BatchID,                  
     Mobile,                  
     [Message],                  
     MessageStatus,                  
     SenderID,                  
     MessageInsertDate,                  
     ScheduledDate,                  
     ScheduledTime,                  
     SmppID,                  
     U_ID,                  
 IsUniCode,                  
     IsDnd,                  
     IsAirtel,                  
     MobileSubSet,                  
     ValidNo,                  
     IsPrority,                  
     IsAllowDND,                  
     DBType                  
   )                 
 SELECT A.BatchID,                  
        A.Mobile,                  
        A.Messagetext,                  
        A.MessageStatus,                  
        A.SenderID,                  
        A.MessageInsertDate,                  
        isnull(A.ScheduledDate,''),                  
        isnull(A.ScheduledTime,''),                  
        A.SmppID,                  
        A.U_ID,                  
        A.IsUnicode,                  
        A.IsDnd,                  
        A.IsAirtel,                  
        A.MobileSubSet,                  
        A.ValidNo,            
        A.IsPrority,                  
        A.IsAllowDND,                  
        A.DBType                  
 FROM   ( SELECT @BatchID     AS BatchID,                  
 str(Mobile) Mobile,       
 'Dear '+cast(a.user_login as nvarchar) + ',Some of the balances in your account are low. Current balances are '+    
 case when smsbalance is not null then  +'SMS: '+cast(smsbalance as nvarchar) else '' end  +    
 case when mailbalance is not null then  +'Mail: '+cast(isnull(mailbalance,0) as nvarchar) else '' end +    
 case when moneybalance is not null then  'Money: '+cast(moneybalance as nvarchar) else '' end+    
 ' which is lower than your last 7 days consumption of these services - Team Kit19. Need help? Reach us at +917840049991'               
--'Dear '+cast(a.user_login as nvarchar) + ' ,'+                
--case when smsbalance is not null then  'Your SMS Balance is Low. Current SMS Balance is ' +cast(smsbalance as nvarchar)  +' which is lower than your last 7 days SMS consumption of '+cast(totalsmsconsumption as nvarchar) +'.'else '' end +                
--case when mailbalance is not null then  ' Your Mail Balance is Low. Current Mail Balance is ' +cast(isnull(mailbalance,0) as nvarchar)  +' which is lower than your last 7 days Mail consumption of '+cast(isnull(totalmailconsumption,0) as nvarchar)+'.'   
  
      
--else '' end +          
--case when moneybalance is not null then  ' Your Money Balance (used for voice calls) is Low. Current Money Balance is ' +cast(moneybalance as nvarchar)+ ' which is lower than your last 7 days Money consumption of '+cast(totalmoneyconsumption as nvarchar
--)+    
      
        
--'.' else '' end +                      
--+' - Team Kit19. Need help? Reach us at +917840049991'                
 AS Messagetext,                  
NULL         AS MessageStatus,                  
'KITAPP'    AS SenderID,                  
GETDATE()    AS MessageInsertDate,                  
 NULL         AS ScheduledDate,                  
NULL AS ScheduledTime,                  
@smppid smppid,                  
335     AS U_ID,                  
0   AS IsUnicode,                  
0            AS IsDnd,                  
0            AS IsAirtel,                  
0            AS MobileSubSet,                  
1            AS ValidNo,                  
1       AS IsPrority,                  
0            AS IsAllowDND,                  
0            AS DBType                  
FROM #lowbalance a                
  ) A                  
 WHERE  A.Mobile <> ''  and str(A.mobile) not in ('8368509853') and A.messagetext is not null                
 drop table #lowsmsbalance                
 drop table #LowMailBalance                
 drop table #lowbalance                
  drop table #LowMoneyBalance                      
                   
END 


