/* ============================================================
   Procedure: [dbo].[usp_DailySMSAlert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     --170,335,'PANDIT','This is Test',0,1,0,0            
CREATE   PROCEDURE [dbo].[usp_DailySMSAlert]           
AS            
BEGIN            
DECLARE @BatchID BIGINT          
begin tran          
 INSERT INTO GetBatchRecord            
   (            
     [User_id],            
     RandNum            
   )            
 VALUES            
   (            
     335,            
     335            
   )            
  select @BatchID=SCOPE_IDENTITY()            
 DELETE             
 FROM   GetBatchRecord            
 WHERE  BatchID=@BatchID          
 commit          
           
select clientID Parentid,count(clientID) IncomingCalls          
into #incomingCalls           
from Kit19calls k           
where k.context <>'outbound'           
and cast(dbo.[fn_getusertimefromindiantime](k.clientid,k.call_start_time) as date) =cast(dateadd(dd,-1,cast(getdate() as date)) as date)          
group by clientID          
          
select f.clientid,count(puniqueid) CallsReceived,SUM(case when dialstatus in ('NOANSWER','Busy') then 1 else 0 end)          
CallsMissed          
into #CallsMissed          
from Kit19CallsDialled k           
join Kit19Calls f on f.uniqueid=k.puniqueid           
where cast(dbo.[fn_getusertimefromindiantime](f.clientid,f.call_start_time)as date) =cast(dateadd(dd,-1,cast(getdate() as date)) as date)          
group by f.clientid          
            
select u.parentid--,sum(case when cast(dbo.[fn_getusertimefromindiantime](l.parentid,l.CreatedOn) as date) =cast(dateadd(dd,-1,cast(getdate() as date)) as date) then 1 else 0 end) TotalFollowupsDone,          
,SUM(case when u.FollowUpDate is not null and u.FollowUpDate<>'' and cast(dbo.[fn_getusertimefromindiantime](u.parentid,u.followupdate) as date) =cast(dateadd(dd,-1,cast(getdate() as date)) as date) then 1 else 0 end ) as FollowUpsPending          
into #FollowUpsOverDue           
from  userleads u (nolock)           
--join LeadInteractionHistory l (nolock) on u.parentid=l.ParentID           
group by u.parentid         
    
select c.PageName,v.ParentID,COUNT(c.pagename) as TotalVisits,SUM(case when cast(v.visitdate as date)=cast(dateadd(dd,-1,getdate()) as date) then 1 else 0 end) VisitsYesterday     
into #profilepagevisits    
from VisitPageDetails v     
join ClientPageDetail c on right(c.pagename,len(c.pagename)-charindex('/',c.pagename,1))=substring(v.pagename,charindex('?cname',v.pagename,1)+7,case when v.pagename like '%&%' then charindex('&',v.pagename,1)    
else  (LEN(v.pagename)+1) end -(charindex('?cname',v.pagename,1)+7))    
and c.User_ID=v.Parentid    
where type='LandingPage' and c.IsProfile=1    
group by c.PageName,v.ParentID    
order by SUM(case when cast(v.visitdate as date)=cast(dateadd(dd,-1,getdate()) as date) then 1 else 0 end) desc    
    
        
declare @count int= (select count(1) from [MySMS].[dbo].[Alertsdata1] a          
  join user_detail u on a.user_id=u.user_id          
  left join #incomingCalls ic on ic.Parentid=u.ParentID          
  left join #CallsMissed c on c.clientid=u.ParentID          
  left join #FollowUpsOverDue f on f.ParentID=u.ParentID     
  left join #profilepagevisits p on p.ParentID=u.ParentID         
  where u.M_ID=10043 and          
--   [DaySMSConsumption]>0          
--or [DayMailConsumption]>0           
--or           
([NewEnquiries]>0          
or [NewLeads]>0          
or [NewConversions]>0          
or [LandingPageDayLeads]> 0          
or [WebformDayLeads]>0          
or [DayEshopOrders]>0          
or [LandingPageDayLeads] >0          
or [ticketsreceivedyesterday]>0          
or [Ticketsresolvedyesterday]>0          
or [TicketsExceedingSLA] >0          
or [TicketsUnresolvedtilldate]>0          
or IncomingCalls>0          
or CallsReceived>0          
or FollowUpsPending>0     
or TotalVisits>0         
or u.user_id=17626          
  )  )         
--select @count        
 INSERT INTO CloneMessageDeliveryStatus            
   (            
     -- MessageID -- this column value is auto-generated            
     BatchID,            
     Mobile,    
     [Message],            
     MessageStatus,            
     SenderID,            
     MessageInsertDate,            
     ScheduledDate,            
     ScheduledTime,            
 SmppID,            
     U_ID,            
     IsUniCode,            
     IsDnd,            
     IsAirtel,            
     MobileSubSet,            
     ValidNo,            
     IsPrority,            
     IsAllowDND,            
     DBType            
   )            
 SELECT A.BatchID,            
        A.Mobile,            
        A.Messagetext,            
        A.MessageStatus,            
        A.SenderID,            
        A.MessageInsertDate,            
        isnull(A.ScheduledDate,''),            
        isnull(A.ScheduledTime,''),            
        A.SmppID,            
        A.U_ID,            
        A.IsUnicode,            
        A.IsDnd,            
        A.IsAirtel,            
        A.MobileSubSet,            
        A.ValidNo,            
        A.IsPrority,            
        A.IsAllowDND,            
        A.DBType            
 FROM   ( SELECT @batchid AS BatchID,            
 str(Mobile) Mobile,            
'Dear '+cast(a.user_login as nvarchar) +          
case when u.user_id=17626 then ' Total :'+cast(@count as nvarchar) else  '' end +        
' , Your '+ +' activity yesterday at '+cast(replace(resellerdomain,'www.','') as nvarchar) +' is: '+     
case when p.ParentID is not null then     
'Profile Page stats : Total Visits : '+ CAST(TotalVisits AS nvarchar) +    
', Visits Yesterday : '+ CAST(VisitsYesterday AS nvarchar) + ', ' else '' end +       
'SMS Used : '+ cast(DaySMSConsumption as nvarchar) +          
', Mail Used : '+cast(DayMailConsumption as nvarchar)+            
', Calls Received : '+CAST(isnull(IncomingCalls,0) AS nvarchar) +          
', New Inquiries : '+cast(NewEnquiries as nvarchar)+           
', New Leads : '+ cast(NewLeads as nvarchar) +          
', New Conversions :'+ cast(NewConversions as nvarchar) +           
' Amounting : '+cast(Dayorderamount as nvarchar) +            
'. You have '+CAST(isnull(FollowUpsPending,0) AS nvarchar)+ ' Follow ups overdue from yesterday and '+          
CAST(isnull(CallsMissed,0) AS nvarchar) + ' Calls were not answered yesterday'+          
'. You got ' + cast([DayEshopOrders] as nvarchar) +           
' orders amounting to ' +  cast([DayEshopOrderAmount] as nvarchar) + ' from your E-shop.'+           
' You have got '+  cast([ticketsreceivedyesterday] as nvarchar) + ' new support tickets.'+           
' Your team resolved '+ cast([Ticketsresolvedyesterday] as nvarchar) +' tickets. '+          
' Your current Balance is: '+          
'SMS : '+cast(CurrentSMSBalance AS nvarchar) +          
', Mail : '+ cast(CurrentMailBalance AS nvarchar) +          
+' - Team ' + cast(replace(resellerdomain,'www.','') as nvarchar) +          
'. Need help? Reach us at +917840049991'          
 AS Messagetext,            
NULL         AS MessageStatus,            
'KITAPP'    AS SenderID,            
GETDATE()    AS MessageInsertDate,            
 NULL         AS ScheduledDate,            
NULL         AS ScheduledTime,            
u.SmppID ,            
335     AS U_ID,            
0   AS IsUnicode,            
0            AS IsDnd,            
0            AS IsAirtel,            
0            AS MobileSubSet,            
1            AS ValidNo,            
1            AS IsPrority,            
0            AS IsAllowDND,            
0            AS DBType            
FROM [MySMS].[dbo].[Alertsdata1] a          
  join user_detail u on a.user_id=u.user_id          
  left join #incomingCalls ic on ic.Parentid=u.ParentID          
  left join #CallsMissed c on c.clientid=u.ParentID          
  left join #FollowUpsOverDue f on f.ParentID=u.ParentID      
  left join #profilepagevisits p on p.ParentID=u.ParentID         
  where u.M_ID=10043 and          
--   [DaySMSConsumption]>0          
--or [DayMailConsumption]>0           
--or           
([NewEnquiries]>0          
or [NewLeads]>0          
or [NewConversions]>0    
or [LandingPageDayLeads]> 0          
or [WebformDayLeads]>0          
or [DayEshopOrders]>0          
or [LandingPageDayLeads] >0          
or [ticketsreceivedyesterday]>0          
or [Ticketsresolvedyesterday]>0          
or [TicketsExceedingSLA] >0          
or [TicketsUnresolvedtilldate]>0          
or IncomingCalls>0          
or CallsReceived>0          
or FollowUpsPending>0     
or TotalVisits>0         
or u.user_id=17626          
  )     -- and u.user_id=17626    
        ) A            
 WHERE cast(A.Mobile as nvarchar) <> '' and cast(A.Mobile as nvarchar) not in ('8368509853')  
 and A.messagetext is not null         
     
 drop table #CallsMissed    
 drop table #FollowUpsOverDue    
 drop table #incomingCalls    
 drop table #profilepagevisits    
             
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_dashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--exec MySMS.dbo.usp_dashboard @userid=32222,@section=N'Tasks'      
--exec MySMS.dbo.usp_dashboard @userid=34594,@section=N'followups'      

CREATE   PROCEDURE [dbo].[usp_dashboard] --34594,'followups'  --43361,'leads'     
(     
 @userid bigint,     
 @section nvarchar(50)=null     
)     
as
begin     
--  declare @userid bigint= 34594 --43361;
  --declare  @section nvarchar(50)= 'followups'


  --select FORMAT(getdate(), 'dd-MMM-yyyy HH:mm:ss.fff')
  
  --declare @userid bigint = 32222, @section nvarchar(50)='enquiries'
 
 declare @isadmin int,@parentid bigint,@userlogin nvarchar(100),@ettrole nvarchar(50),@UserLoginWithName nvarchar(200)     
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))     
 Declare @UserIdTeamLst varchar(Max) = ''     
  
 select @isadmin=isnull(isadmin,0),@parentid=parentid,@userlogin=user_login, @UserLoginWithName = isnull(user_login+' ( '+isnull(fname,'')+' '+ISNULL(lname,'')+' )' ,'') from user_detail(nolock) where user_id=@userid     
     
	   if(@Isadmin = 1)
	     begin
		      insert into @tbluser     
            exec Use_GetUserDetails @parentid 
		 end
		 else
		  begin
		     insert into @tbluser     
             exec Use_GetUserDetails @userid   
		  end

	--DECLARE @UserIdTeamLst VARCHAR(4000) = ''
	--DECLARE @HierarchyJSON VARCHAR(Max) = ''

	SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	--SELECT @UserIdTeamLst = isnull(STRING_AGG( + '''' + User_ID + '''' , ','), '0')
	FROM @tbluser

	PRINT '@UserIdTeamLst: ' + @UserIdTeamLst


	 /*
     DECLARE @ScopeCode VARCHAR(10) = ''
      select @ScopeCode = ScopeCode    
       from ufn_GetUserRoleScope(@UserId) 

	 if(@ScopeCode = 'GLOBAL')
	   begin
	       set @IsAdmin = 1 
	   end
	   */

select @ettrole= t.userrole from MysmsTimeTrack.dbo.timetracking_settings t with (nolock) where user_id=@userid    
     
declare @rsection nvarchar(50)     
     
if isnull(@section,'leads')='leads'     
begin     
set @rsection='leads'     
     
 SELECT @rsection Section, *     
 FROM     
 (     
 SELECT u.ParentID,     
 SUM(CASE WHEN CAST(createdon AS DATE)=CAST(GETDATE() AS DATE) THEN 1 ELSE 0 END) LeadsToday,     
 SUM(CASE WHEN MONTH(createdon)=MONTH(GETDATE()) AND YEAR(createdon)=YEAR(GETDATE()) THEN 1     
 ELSE 0 END) LeadsThisMonth,     
 ISNULL(LeadsNotFollowedUpYet, 0) LeadsNotFollowedUpYet,     
 
 SUM(
       case 
	   when 
	   --@isadmin=1 and 
	   CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE)
	   then 1 
	   --WHEN @isadmin=0 and AssignedTo=@userid and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) THEN 1 
	    ELSE 0 
		END
	) AssignedToday,     
 
 SUM(case when @isadmin=1 and CAST(createdon AS DATE)=CAST(GETDATE() AS DATE) and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) then 1 WHEN @isadmin=0 and AssignedTo=@userid and CAST(CreatedOn AS DATE)=CAST(GETDATE() AS DATE) and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) THEN 1 ELSE 0 END) CreatedAndAssignedToday,     
 
 SUM( 
       1
        /*  
         case when @isadmin=1 then 1 
         else
	       ( 
		    CASE WHEN 
			      --AssignedTo=@userid
			  	 -- AssignedTo in (@UserIdTeamLst)
				  AssignedTo in (select User_ID from @tbluser)
			  THEN 1 ELSE 0 END
	        ) 
	       end
		 */
	  )
		AssignedTillToday     
 FROM userleads(NOLOCK) u     
 LEFT JOIN     
 (     
 SELECT parentid, COUNT(1) LeadsNotFollowedUpYet     
 FROM userleads(NOLOCK) u     
 WHERE parentid=@parentid --AND enquirysource NOT BETWEEN 12 AND 15 AND enquirysource<>22     
 
 --AND CreatedBy=CASE WHEN @isadmin=1 THEN createdby ELSE @userid END     
 and CreatedBy in (select User_ID from @tbluser)
 
 and u.ModifiedOn is null     
 AND ABS(DATEDIFF(mi, u.createdon, u.followupdate))<=2     
 /*AND NOT EXISTS     
 (     
 SELECT LeadNo     
 FROM LeadInteractionHistory(NOLOCK)     
 WHERE leadno=u.leadno AND parentid=u.ParentID     
 AND CreatedBy=CASE WHEN @isadmin=1 THEN createdby ELSE @userid END     
 GROUP BY leadno     
 HAVING COUNT(1)>1     
 )     
 AND NOT EXISTS     
 (     
 SELECT LeadNo     
 FROM LeadInteractionHistory(NOLOCK)     
 WHERE leadno=u.leadno AND parentid=u.ParentID --AND ABS(DATEDIFF(mi, createdon, u.createdon))>=5     
 AND ABS(DATEDIFF(mi, createdon, u.followupdate))<=2     
 GROUP BY leadno     
 HAVING COUNT(1)=1     
 )*/     
 GROUP BY parentid     
 ) k     
 ON u.parentid=k.ParentID     
 WHERE u.ParentID=@parentid AND     
 --CreatedBy=CASE WHEN @isadmin=1 THEN createdby ELSE @userid END     
 --AssignedTo=CASE WHEN @isadmin=1 THEN AssignedTo ELSE @userid END     
  1 = case when @isadmin=1 then 1 when assignedTo in (select User_ID from @tbluser) then 1 else 0 end
 
 GROUP BY u.ParentID, LeadsNotFollowedUpYet     
 ) a;     
     
     
 select @rsection Section,* from     
(select top 10 round((currentscore/cast((select (max(currentscore)*100)/99 from lead_score_history_latest(nolock) e where parentid=@parentid) as float)*99),2)     
CurrentScore,u.leadno,u.id as LeadID, u.personname, u.companyname, u.ProfileImgFileName     
from userleads(nolock) u left join [dbo].[lead_score_history_latest] l on u.id=l.leadid     
 where u.ParentID=@parentid     
 and 
 --CreatedBy=case when @isadmin=1 then createdby else @userid end     
  createdby  in (select User_ID from @tbluser)

 order by l.CurrentScore desc,u.createdon desc     
 ) a     
     
 select @rsection Section,* from     
(select isnull(s.name,'Unknown') Source,count(1) LeadCount from userleads (nolock) u     
left join UserSourceSettings(nolock) s on s.SourceID=u.SourceName     
