if isnull(@section,'conversions')='conversions'     
begin     
set @rsection='conversions'     
select @rsection Section,* from     
(select l.parentid,sum(case when cast(l.CreatedOn as date)=cast(getdate() as date) then 1 else 0 end) ConvertedToday     
,sum(case when month(l.CreatedOn)=month(getdate()) and year(l.CreatedOn)=year(getdate()) then 1 else 0 end) ConvertedThisMonth     
,sum(case when cast(l.CreatedOn as date)=cast(getdate() as date) then l.AmountPaid else 0 end) AmountToday     
,sum(case when month(l.CreatedOn)=month(getdate()) and year(l.CreatedOn)=year(getdate()) then l.AmountPaid else 0 end) AmountThisMonth     
from LeadInteractionHistory(nolock) l     
inner join UserLeads ul with(nolock)     
on l.LeadNo = ul.LeadNo and l.ParentID = @parentid and ul.ParentID = @parentid     
where     
--followupstatus=5     
 l.followupstatus in (select distinct Id from FollowUp_Status fup where fup.IsConvert = 1 and (fup.ParentID = @ParentID or fup.ParentID is Null))     
and l.parentid=@parentid     
 and 
 -- l.CreatedBy in ( case when @isadmin=1 then l.CreatedBy else @userid end )     
 l.createdby in (select User_ID from @tbluser)
 
 --and l.AmountPaid is not null     
     
group by l.parentid     
) a     
     
select @rsection Section,* from     
(select user_login as Executive, (isnull(FName, '') + ' ' + isnull(LName, '')) as ExecutiveName, sum(l.amountpaid) as Amount,     
isnull([Image],'') as Image     
from LeadInteractionHistory(nolock) l join User_Detail (nolock) u on l.AssignedTo=u.User_ID     
inner join UserLeads ul with(nolock)     
on l.LeadNo = ul.LeadNo and l.ParentID = @parentid and ul.ParentID = @parentid     
where     
 --followupstatus=5     
 l.followupstatus in (select Id from FollowUp_Status fup where fup.IsConvert = 1 and (fup.ParentID = @ParentID or fup.ParentID is Null))     
 and l.parentid=@parentid     
 and month(l.CreatedOn)=month(getdate()) and year(l.CreatedOn)=year(getdate())     
 and 
  --l.CreatedBy=case when @isadmin=1 then l.createdby else @userid end     
  l.createdBy in (select User_ID from @tbluser)
  and l.AmountPaid is not null      
group by user_login, FName, LName, [Image]     
) a     
end     
     
if isnull(@section,'followups')='followups'     
begin     
     
    set @rsection='followups'     
     
    -- ✅ SUMMARY (NO ORDER BY NEEDED HERE)
    select @rsection Section,* from     
    (    
        select 
            sum(case when cast(lih.FollowupDate as date)< cast(getdate() as date) then 1 else 0 end) Overdue,     
            sum(case when cast(lih.FollowupDate as date)=cast(getdate() as date) then 1 else 0 end) DueToday,     
            sum(case when datediff(dd,cast(getdate() as date),cast(lih.FollowupDate as date)) between 0 and 7 then 1 else 0 end) DueIn7Days,     
            sum(case when month(lih.FollowupDate)=month(getdate()) and year(lih.FollowupDate)=year(getdate()) then 1 else 0 end) DueThisMonth     
        
        from userleads(nolock) as ul     

        inner join leadinteractionhistory (nolock) as lih  
            on ul.LeadNo = lih.LeadNo and ul.ParentID = lih.ParentID  

        inner join (
            select leadno, parentid, max(id) as maxid
            from leadinteractionhistory (nolock)
            group by leadno, parentid
        ) latest 
            on latest.leadno = lih.leadno 
            and latest.parentid = lih.parentid 
            and latest.maxid = lih.id

        inner join FollowUp_Status(nolock) as fs     
            on lih.FollowUpStatus = fs.ID     

        where ul.ParentID=@parentid     
        and isnull(fs.IsCallBack,0) = 1     
        and isnull(fs.IsConvert,0) <> 1     
        and lih.FollowupDate is not null     
        and ul.assignedto = (case when @isadmin=1 then ul.assignedto else @userid end)     

    ) a     
     
    -- ✅ EXECUTIVE LIST (ORDER BY REQUIRED)
    select @rsection Section,* from     
    (     
        select 
            d.user_login Executive, 
            (isnull(d.FName, '') + ' ' + isnull(d.LName, '')) as ExecutiveName, 
            count(1) as FollowupsDue,
            isnull(d.[Image],'') as Image     

        from userleads(nolock) u 

        inner join leadinteractionhistory (nolock) as lih  
            on u.LeadNo = lih.LeadNo and u.ParentID = lih.ParentID  

        inner join (
            select leadno, parentid, max(id) as maxid
            from leadinteractionhistory (nolock)
            group by leadno, parentid
        ) latest 
            on latest.leadno = lih.leadno 
            and latest.parentid = lih.parentid 
            and latest.maxid = lih.id

        join user_detail (nolock) d 
            on d.user_id = u.assignedto     

        inner join FollowUp_Status(nolock) as fs     
            on lih.FollowUpStatus = fs.ID     

        where u.parentid=@parentid     
        and fs.IsCallBack = 1     
        and cast(lih.FollowupDate as date)< cast(getdate() as date)     
        and lih.FollowupDate is not null     
        and u.assignedto in (select User_ID from @tbluser)     

        group by d.user_login, d.FName, d.LName, d.[Image]     
    ) a     
    order by FollowupsDue desc     
     
end
     
if isnull(@section,'Tasks')='Tasks'     
