(select user_login Executive, (isnull(FName, '') + ' ' + isnull(LName, '')) as ExecutiveName, count(1) as TasksDue , isnull([Image],'') as Image, u.assignedto as UserID     
 from [dbo].[tbl_tsk_TaskHistory] u right join user_detail (nolock) d     
 on d.user_id=u.assignedto     
 where parentid=@parentid and u.IsActive = 1 and isnull(IsTask,0)=1 and isnull(outcomesid,0)=0     
 and taskid<>4     
 --and u.AssignedTo=case when @isadmin=1 then u.AssignedTo else @userid end     
 --and u.AssignedTo in (select User_ID from @tbluser)     
 and isnull(u.AssignedTo,u.CreatedBy) in (select User_ID from @tbluser)     
 and isnull(u.Status,'') <> 'completed'     
