if isnull(@section,'Engagement')='Engagement'     
begin     
set @rsection='Engagement'     
     
select @rsection Section,* from     
(     
select t.parentid     
,ActiveCampaigns     
,SUM(case when cast(ExecutionTime as date)=cast(getdate() as date) then NoOfRecipients else 0 end)     
+ sum(case when cast(batchinserttime as date)=cast(getdate() as date) then TotalRecords else 0 end) ReachToday     
,SUM(case when datediff(dd,cast(ExecutionTime as date),cast(getdate() as date)) between 0 and 7 then NoOfRecipients else 0 end)     
+ sum(case when datediff(dd,cast(batchinserttime as date),cast(getdate() as date)) between 0 and 7 then TotalRecords else 0 end) ReachLast7Days     
,SUM(case when month(ExecutionTime)=month(getdate()) and year(executiontime)=year(getdate()) then NoOfRecipients else 0 end)     
+ sum(case when month(BatchInsertTime)=month(getdate()) and year(BatchInsertTime)=year(getdate()) then TotalRecords else 0 end) ReachThisMonth     
 from triggeredcampaigns(nolock) t     
 join (
	select parentid, sum(isactive) as activecampaigns 
	from triggeredcampaigns(nolock) 
	where parentid = @parentid 
	group by parentid
) tr on tr.parentid = t.parentid
left join (
	select campaignid, executiontime, NoOfRecipients 
	from UserCampaignExecutionHistory(nolock) 
	where parentID = @parentid and month(executiontime) = month(getdate()) and year(executiontime) = year(getdate())
) u on u.CampaignID in (t.smscampaignid, t.mailcampaignid, t.voicecampaignid)
left join (
	select campaignid, batchinserttime, totalrecords 
	from WBatchInfo(nolock) 
	where parentID = @parentid and month(batchinserttime) = month(getdate()) and year(batchinserttime) = year(getdate())
) b on b.campaignid = t.whatsappcampaignid
where t.parentid = @parentid and @isadmin = 1
 group by t.parentid ,ActiveCampaigns     
     
) a     
end     
     
