if isnull(@section,'EmployeeTimeTracking')='EmployeeTimeTracking'     
begin     
set @rsection='EmployeeTimeTracking'     
declare @datetoday nvarchar(100)=convert(date,getdate()),@exceedingbreak int,@lowworkhours Int     
     
drop table if exists #temp     
create table #temp(userrole nvarchar(100),Total int,Available int,Late int,[Absent] int,Productive int,Slacking int)     
insert into #temp     
exec mysmstimetrack.dbo.[Usp_GetUserMatrices] @datetoday ,@userid     
     
select user_id,allowedbreakinminutes,0 as breakexceeded, 0 as workhours     
into #break from mysmstimetrack.dbo.timetracking_settings with (nolock)     
where parentid=@parentid     
     
update b set breakexceeded=1 from #break b left join mysmstimetrack.dbo.timetrackingbreakhours t     
on b.user_id=t.user_id and t.breakdate=cast(getdate() as date)     
where breaktimeinseconds*60>allowedbreakinminutes     
     
update b set workhours=isnull(t.workingtimeinseconds,0) from #break b left join     
mysmstimetrack.dbo.timetrackingworkinghours t     
on b.user_id=t.user_id and t.workingdate=cast(getdate() as date)     
     
select @exceedingbreak=count(1) from #break where breakexceeded=1     
select @lowworkhours=count(1) from #break where workhours<dbo.[fn_requiredworkingtime](user_id,cast(getdate() as date))     
select @rsection Section,@parentid Parentid,* from     
(     
select Total,Absent as AbsentToday,Late as LateToday,Available as PresentToday,@exceedingbreak ExceedingBreak,@lowworkhours LessWorkHours from #temp     
) a     
drop table if exists #break     
drop table if exists #temp     
     
end     
     
if isnull(@section,'Campaigns')='Campaigns'     
begin     
set @rsection='Campaigns'     
     
select @rsection Section,* from     
(     
select parentid,medium,count(1) CampaignEventCount from UserCampaignMaster(nolock) u where IsEventBased=1 and IsActive=1     
and eventid is null and parentid=@parentid     
and 1=@isadmin     
group by parentid,Medium     
) a     
     
select @rsection Section,* from     
(     
select parentid,medium,count(1) CampaignScheduledCount from UserCampaignMaster(nolock) u where IsEventBased=0 and IsActive=1     
and isnull(ExpiryDate,dateadd(dd,1,getdate()))>getdate() and (StartDate>getdate() or IsSchedule=1)     
and eventid is null and parentid=@parentid     
and 1=@isadmin     
group by parentid,Medium     
) a     
end     
     
if isnull(@section,'Pipeline')='Pipeline'     
begin     
set @rsection='Pipeline'     
select @rsection Section,* from     
(     
select p.parentid,p.Name Pipeline,s.Name Stage,count(1) as TotalLeads,s.Sequence     
from     
LeadPipelineMapping l right join Pipeline_Master p on l.PipelineID=p.ID     
right join PipelineStages s on l.PipeLineStage=s.ID     
where (l.id is null or (l.id=(select max(id) from LeadPipelineMapping where leadid=l.leadid and l.IsDeleted=0)     
and l.IsDeleted=0))     
and p.ParentID=@parentid     
and l.DealOwner=case when @isadmin=1 then dealowner else @userid end     
and s.name not in ('won','lost')     
group by p.parentid,p.Name,s.Name,s.Sequence     
) a order by Pipeline,Sequence     
     
select @rsection Section,* from     
(     
select p.parentid,p.Name Pipeline,user_login Executive, (isnull(FName, '') + ' ' + isnull(LName, '')) as ExecutiveName, count(1) as TotalLeads     
from     
LeadPipelineMapping l(nolock) right join Pipeline_Master p(nolock) on l.PipelineID=p.ID     
join PipelineStages s (nolock) on s.id=l.PipeLineStage     
join user_detail (nolock) u on u.user_id=l.DealOwner     
where (l.id is null or (l.id=(select max(id) from LeadPipelineMapping where leadid=l.leadid and l.IsDeleted=0)     
and l.IsDeleted=0))     
and p.ParentID=@parentid     
and l.DealOwner=case when @isadmin=1 then dealowner else @userid end     
and s.name not in ('won','lost')     
group by p.parentid,p.Name,User_Login, FName, LName     
) a order by Executive, ExecutiveName     
     
select @rsection Section,* from     
(     
select p.parentid,p.Name Pipeline,count(1) as ExpiredLeads     
from     
LeadPipelineMapping l(nolock) right join Pipeline_Master p(nolock) on l.PipelineID=p.ID     
join PipelineStages s (nolock) on s.id=l.PipeLineStage     
join user_detail (nolock) u on u.user_id=l.DealOwner     
where     
l.id=(select min(id) from LeadPipelineMapping where leadid=l.leadid and l.IsDeleted=0)     
and l.IsDeleted=0     
and dateadd(dd,p.dealexpiry,l.CreatedDate)<getdate()     
and p.ParentID=@parentid     
and l.DealOwner=case when @isadmin=1 then dealowner else @userid end     
and not exists (select 1 from LeadPipelineMapping where PipelineID=l.PipelineID     
and s.name in ('won','lost') and CreatedDate>l.CreatedDate)     
group by p.parentid,p.Name     
) a order by ExpiredLeads desc     
     
select @rsection Section,* from     
(     
select p.Name as Pipeline,p.parentid,isnull(estimatedclosure,0) EstimatedClosure     
from Pipeline_Master p join     
(     
select parentid,pipeline,cast(sum(EstimatedClosure) as money) EstimatedClosure     
from     
(     
select p.parentid,p.Name Pipeline,l.Amount*l.Probability/100 EstimatedClosure     
 --,l.Probability     
from     
LeadPipelineMapping l(nolock) right join Pipeline_Master p(nolock) on l.PipelineID=p.ID     
join PipelineStages s (nolock) on s.id=l.PipeLineStage     
where     
(l.id is null or (l.id=(select max(id) from LeadPipelineMapping where leadid=l.leadid and l.IsDeleted=0)     
and l.IsDeleted=0     
and month(l.estimatedclosuredate)=month(getdate())     
and year(l.estimatedclosuredate)=year(getdate())     
and not exists (select 1 from LeadPipelineMapping(nolock) where PipelineID=l.PipelineID     
and s.name in ('won','lost'))     
and l.DealOwner=case when @isadmin=1 then dealowner else @userid end     
))     
and p.ParentID=@parentid     
) a     
group by parentid,pipeline     
) a on a.ParentID=p.ParentID and a.Pipeline=p.Name     
 and a.ParentID = @parentid     
     
) a     
     
     
end     
     
end     



GO

/* ============================================================
   Procedure: [dbo].[usp_dashboard_correctedassignedtoday]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_dashboard_correctedassignedtoday @userid=34594,@section='leads'
CREATE   PROCEDURE [dbo].[usp_dashboard_correctedassignedtoday]       
(       
@userid bigint,       
@section nvarchar(50)=null       
)       
as       
begin       
 --declare @userid bigint=47736,@section nvarchar(50)='leads'       
 declare @isadmin int,@parentid bigint,@userlogin nvarchar(100),@ettrole nvarchar(50),@UserLoginWithName nvarchar(200)       
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))       
 Declare @UserIdTeamLst varchar(Max) = ''       
 insert into @tbluser       
 exec Use_GetUserDetails @UserId       
 select @isadmin=isnull(isadmin,0),@parentid=parentid,@userlogin=user_login, @UserLoginWithName = isnull(user_login+' ( '+isnull(fname,'')+' '+ISNULL(lname,'')+' )' ,'') from user_detail(nolock) where user_id=@userid       
       
select @ettrole= t.userrole from MysmsTimeTrack.dbo.timetracking_settings t with (nolock) where user_id=@userid      
       
declare @rsection nvarchar(50)       
       
if isnull(@section,'leads')='leads'       
begin       
set @rsection='leads'       

Exec usp_dashboard_correctedassignedtoday_v2 @userid=@userid,@section='leads'
return;
       
 SELECT @rsection Section, *       
 FROM       
 (       
 SELECT u.ParentID,       
 SUM(CASE WHEN CAST(createdon AS DATE)=CAST(GETDATE() AS DATE) THEN 1 ELSE 0 END) LeadsToday,       
 SUM(CASE WHEN MONTH(createdon)=MONTH(GETDATE()) AND YEAR(createdon)=YEAR(GETDATE()) THEN 1       
 ELSE 0 END) LeadsThisMonth,       
 ISNULL(LeadsNotFollowedUpYet, 0) LeadsNotFollowedUpYet,       
 --SUM(case when @isadmin=1 and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) then 1 WHEN @isadmin=0 and AssignedTo=@userid and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) THEN 1 ELSE 0 END) AssignedToday,       
 SUM(
       case 
	   when 
	   --@isadmin=1 and 
	   CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE)
	   then 1 
	   --WHEN @isadmin=0 and AssignedTo=@userid and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) THEN 1 
	    ELSE 0 
		END
	) AssignedToday,  
 --SUM(case when @isadmin=1 and CAST(createdon AS DATE)=CAST(GETDATE() AS DATE) and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) then 1 WHEN @isadmin=0 and AssignedTo=@userid and CAST(CreatedOn AS DATE)=CAST(GETDATE() AS DATE) and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) THEN 1 ELSE 0 END) CreatedAndAssignedToday,       
  SUM(case when @isadmin=1 and CAST(createdon AS DATE)=CAST(GETDATE() AS DATE) and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) then 1 WHEN @isadmin=0 and AssignedTo=@userid and CAST(CreatedOn AS DATE)=CAST(GETDATE() AS DATE) and CAST(LastFollowupCreatedOn AS DATE)=CAST(GETDATE() AS DATE) THEN 1 ELSE 0 END) CreatedAndAssignedToday,     
 --SUM(case when @isadmin=1 then 1 else (CASE WHEN AssignedTo=@userid THEN 1 ELSE 0 END) end) AssignedTillToday   
 SUM( 
       1
       
	  )
		AssignedTillToday  
 FROM userleads(NOLOCK) u       
 LEFT JOIN       
 (       
 SELECT parentid, COUNT(1) LeadsNotFollowedUpYet       
 FROM userleads(NOLOCK) u       
 WHERE parentid=@parentid AND enquirysource NOT in (12,13,14,15,28,29) AND enquirysource<>22       
 AND CreatedBy=CASE WHEN @isadmin=1 THEN createdby ELSE @userid END       
 and u.ModifiedOn is null       
 AND ABS(DATEDIFF(mi, u.createdon, u.followupdate))<=2       
 /*AND NOT EXISTS       
 (       
 SELECT LeadNo       
 FROM LeadInteractionHistory(NOLOCK)       
 WHERE leadno=u.leadno AND parentid=u.ParentID       
 AND CreatedBy=CASE WHEN @isadmin=1 THEN createdby ELSE @userid END       
 GROUP BY leadno       
 HAVING COUNT(1)>1       
 )       
 AND NOT EXISTS       
 (       
 SELECT LeadNo       
 FROM LeadInteractionHistory(NOLOCK)       
 WHERE leadno=u.leadno AND parentid=u.ParentID --AND ABS(DATEDIFF(mi, createdon, u.createdon))>=5       
 AND ABS(DATEDIFF(mi, createdon, u.followupdate))<=2       
 GROUP BY leadno       
 HAVING COUNT(1)=1       
 )*/       
 GROUP BY parentid       
 ) k       
 ON u.parentid=k.ParentID       
 WHERE u.ParentID=@parentid AND       
 --CreatedBy=CASE WHEN @isadmin=1 THEN createdby ELSE @userid END     
 1 = case when @isadmin=1 then 1 when assignedTo in (select User_ID from @tbluser) then 1 else 0 end
 --AssignedTo=CASE WHEN @isadmin=1 THEN AssignedTo ELSE @userid END       
 GROUP BY u.ParentID, LeadsNotFollowedUpYet       
 ) a;       
       
       
 select @rsection Section,* from       
(select top 10 round((currentscore/cast((select (max(currentscore)*100)/99 from lead_score_history_latest(nolock) e where parentid=@parentid) as float)*99),2)       
CurrentScore,u.leadno,u.id as LeadID, u.personname, u.companyname, u.ProfileImgFileName       
from userleads(nolock) u left join [dbo].[lead_score_history_latest] l on u.id=l.leadid       
 where u.ParentID=@parentid       
 and createdby  in (select User_ID from @tbluser)
 --CreatedBy=case when @isadmin=1 then createdby else @userid end and isnull(currentscore,0) != 0      
 order by l.CurrentScore desc,u.createdon desc       
 ) a       
       
 select @rsection Section,* from       
(select isnull(s.name,'Unknown') Source,count(1) LeadCount from userleads (nolock) u       
left join UserSourceSettings(nolock) s on s.SourceID=u.SourceName       
 where u.ParentID=@parentid and u.CreatedBy in (select User_ID from @tbluser) --=case when @isadmin=1 then u.createdby else @userid end       
 group by isnull(s.name,'Unknown')       
 ) a       
       
 select @rsection Section,* from       
(select isnull(s.name,'Unknown') Medium,count(1) LeadCount from userleads (nolock) u       
left join UserMediumSettings(nolock) s on s.MediumID=u.MediumName          
 where u.ParentID=@parentid and-- u.CreatedBy=case when @isadmin=1 then u.createdby else @userid end       
  u.CreatedBy in (select User_ID from @tbluser)  
 group by isnull(s.name,'Unknown')       
 ) a   
 select @rsection Section,* from       
(select isnull(s.name,'Unknown') Campaign,count(1) LeadCount from userleads (nolock) u       
left join UserCampaignSettings(nolock) s on s.CampaignID=u.CampaignName      
 where u.ParentID=@parentid and-- u.CreatedBy=case when @isadmin=1 then u.createdby else @userid end       
  u.CreatedBy in (select User_ID from @tbluser)  
 group by isnull(s.name,'Unknown')       
 ) a   
  select @rsection Section,* from       
(select  isnull(UD.User_Login,'Unknown') createdby,count(1) LeadCount from userleads (nolock) u       
left join  User_Detail (nolock) UD on UD.User_ID=u.CreatedBy      
 where u.ParentID=@parentid and-- u.CreatedBy=case when @isadmin=1 then u.createdby else @userid end       
  u.CreatedBy in (select User_ID from @tbluser)  
 group by isnull(UD.User_Login,'Unknown')      
 ) a  
 select @rsection Section,* from  
 (select  isnull(U.assignedto,'Unknown') Assignedto,count(1) LeadCount from userleads (nolock) u       
left join  User_Detail (nolock) UD on UD.User_ID=u.CreatedBy      
 where u.ParentID=@parentid and-- u.CreatedBy=case when @isadmin=1 then u.createdby else @userid end       
  u.CreatedBy in (select User_ID from @tbluser)  
 group by isnull(u.assignedto,'Unknown')      
 ) a  
  
  
  
   
 end       
       
if isnull(@section,'enquiries')='enquiries'       
begin       
set @rsection='enquiries'       
select @rsection Section,* from       
(select u.ParentID,sum(case when cast(CreatedDate as date)=cast(getdate() as date) then 1 else 0 end) EnquiriesToday,       
sum(case when month(CreatedDate)=month(getdate()) and year(CreatedDate)=year(getdate()) then 1 else 0 end) EnquiriesThisMonth,       
sum(case when isopen=1 then 1 else 0 end) StillOpen       
 from userenquiry(nolock) u       
 where parentid=@parentid       
 and u.CreatedBy=case when @isadmin=1 then u.createdby else @userid end       
 group by u.ParentID       
 ) a       
 select @rsection Section,* from       
(select top 10 isnull(s.name,'Unknown') Source,count(1) EnquiryCount from userenquiry (nolock) u left join UserSourceSettings(nolock) s on s.SourceID=u.SourceName       
 where u.ParentID=@parentid       
 and u.CreatedBy=case when @isadmin=1 then u.createdby else @userid end       
 group by isnull(s.name,'Unknown') order by count(1) desc       
 ) a       
end       
       
if isnull(@section,'conversions')='conversions'       
begin       
set @rsection='conversions'       
select @rsection Section,* from       
(select l.parentid,sum(case when cast(l.CreatedOn as date)=cast(getdate() as date) then 1 else 0 end) ConvertedToday       
,sum(case when month(l.CreatedOn)=month(getdate()) and year(l.CreatedOn)=year(getdate()) then 1 else 0 end) ConvertedThisMonth       
,sum(case when cast(l.CreatedOn as date)=cast(getdate() as date) then l.AmountPaid else 0 end) AmountToday       
,sum(case when month(l.CreatedOn)=month(getdate()) and year(l.CreatedOn)=year(getdate()) then l.AmountPaid else 0 end) AmountThisMonth       
from LeadInteractionHistory(nolock) l       
inner join UserLeads ul with(nolock)       
on l.LeadNo = ul.LeadNo and l.ParentID = @parentid and ul.ParentID = @parentid       
where       
--followupstatus=5       
 l.followupstatus in (select distinct Id from FollowUp_Status fup where fup.IsConvert = 1 and (fup.ParentID = @ParentID or fup.ParentID is Null))       
and l.parentid=@parentid       
 and l.CreatedBy in ( case when @isadmin=1 then l.CreatedBy else @userid end )       
 and l.AmountPaid is not null       
       
group by l.parentid       
) a       
       
select @rsection Section,* from       
(select user_login as Executive, (isnull(FName, '') + ' ' + isnull(LName, '')) as ExecutiveName, sum(l.amountpaid) as Amount,       
isnull([Image],'') as Image       
from LeadInteractionHistory(nolock) l join User_Detail (nolock) u on l.AssignedTo=u.User_ID       
inner join UserLeads ul with(nolock)       
on l.LeadNo = ul.LeadNo and l.ParentID = @parentid and ul.ParentID = @parentid       
where       
 --followupstatus=5       
 l.followupstatus in (select Id from FollowUp_Status fup where fup.IsConvert = 1 and (fup.ParentID = @ParentID or fup.ParentID is Null))       
 and l.parentid=@parentid       
 and month(l.CreatedOn)=month(getdate()) and year(l.CreatedOn)=year(getdate())       
 and l.CreatedBy=case when @isadmin=1 then l.createdby else @userid end       
  and l.AmountPaid is not null        
group by user_login, FName, LName, [Image]       
) a       
end       
       
if isnull(@section,'followups')='followups'       
begin       
set @rsection='followups'       
       
select @rsection Section,* from       
(select sum(case when cast(lih.FollowupDate as date)< cast(getdate() as date) then 1 else 0 end) Overdue       
,sum(case when cast(lih.followupdate as date)=cast(getdate() as date) then 1 else 0 end) DueToday       
,sum(case when datediff(dd,cast(getdate() as date),cast(lih.followupdate as date)) between 0 and 7 then 1 else 0 end) DueIn7Days       
,sum(case when month(lih.followupdate)=month(getdate()) and year(lih.followupdate)=year(getdate()) then 1 else 0 end) DueThisMonth       
from userleads(nolock) as ul inner join LeadInteractionHistory(nolock) as lih       
on ul.LeadNo = lih.LeadNo and ul.ParentID = lih.ParentID inner join FollowUp_Status(nolock) as fs       
on lih.FollowUpStatus = fs.ID       
where lih.ParentID=@parentid and fs.IsCallBack = 1 /*lih.FollowUpStatus=1*/ and lih.FollowupDate is not null       
--and lih.assignedto = (case when @isadmin=1 then lih.assignedto else @userid end)       
and lih.assignedto in (select User_ID from @tbluser)       
and lih.ID in       
(select max(id) from leadinteractionhistory(nolock) where parentid=lih.parentid and leadno=lih.leadno)       
) a       
       
select @rsection Section,* from       
(       
select user_login Executive, (isnull(FName, '') + ' ' + isnull(LName, '')) as ExecutiveName, count(1) as FollowupsDue ,isnull([Image],'') as Image       
from leadinteractionhistory(nolock) u join user_detail (nolock) d       
on d.user_id=u.assignedto inner join FollowUp_Status(nolock) as fs       
on u.FollowUpStatus = fs.ID       
where u.parentid=@parentid and fs.IsCallBack = 1/*followupstatus=1*/       
and cast(FollowupDate as date)< cast(getdate() as date)       
and FollowupDate is not null       
--and u.CreatedBy=case when @isadmin=1 then u.createdby else @userid end       
and u.assignedto in (select User_ID from @tbluser)       
and u.ID in (select max(id) from leadinteractionhistory(nolock) where parentid=u.parentid and leadno=u.leadno)       
group by user_login, FName, LName, [Image]       
) a       
order by FollowupsDue desc       
       
end       
       
if isnull(@section,'Tasks')='Tasks'       
begin       
set @rsection='Tasks'       
       
select @rsection Section,* from       
(select sum(case when cast(EndDate as date)<cast(getdate() as date) then 1 else 0 end) Overdue       
,sum(case when cast(EndDate as date)=cast(getdate() as date) then 1 else 0 end) DueToday       
,sum(case when datediff(dd,cast(getdate() as date),cast(EndDate as date)) between 0 and 7 then 1 else 0 end) DueIn7Days       
,sum(case when month(EndDate)=month(getdate()) and year(EndDate)=year(getdate()) then 1 else 0 end) DueThisMonth       
 from [dbo].[tbl_tsk_TaskHistory] u right join user_detail (nolock) d       
 on d.user_id=u.AssignedTo       
 where parentid=@parentid and isnull(IsAppointment,0)=0 and isnull(outcomesid,0)=0 and taskid<>4       
 and u.IsActive = 1 and isnull(u.Status,'') <> 'completed'       
 --and u.AssignedTo=case when @isadmin=1 then u.AssignedTo else @userid end       
 and isnull(u.AssignedTo,u.CreatedBy) in (select User_ID from @tbluser)       
 group by parentid       
 ) a       
       
 select @rsection Section,* from       
(select user_login Executive, (isnull(FName, '') + ' ' + isnull(LName, '')) as ExecutiveName, count(1) as TasksDue , isnull([Image],'') as Image, u.assignedto as UserID       
 from [dbo].[tbl_tsk_TaskHistory] u right join user_detail (nolock) d       
 on d.user_id=u.assignedto       
 where parentid=@parentid and u.IsActive = 1 and isnull(IsAppointment,0)=0 and isnull(outcomesid,0)=0       
 and taskid<>4       
 --and u.AssignedTo=case when @isadmin=1 then u.AssignedTo else @userid end       
 --and u.AssignedTo in (select User_ID from @tbluser)       
 and isnull(u.AssignedTo,u.CreatedBy) in (select User_ID from @tbluser)       
 and isnull(u.Status,'') <> 'completed'       
 group by user_login, FName, LName, [Image],u.assignedto       
 ) a order by TasksDue desc       
       
end       
       
if isnull(@section,'Appointments')='Appointments'       
begin       
set @rsection='Appointments'       
       
select @rsection Section,* from       
(select sum(case when cast(EndDate as date)<cast(getdate() as date) then 1 else 0 end) Overdue       
,sum(case when cast(EndDate as date)=cast(getdate() as date) then 1 else 0 end) DueToday       
,sum(case when datediff(dd,cast(getdate() as date),cast(EndDate as date)) between 0 and 7 then 1 else 0 end) DueIn7Days       
,sum(case when month(EndDate)=month(getdate()) and year(EndDate)=year(getdate()) then 1 else 0 end) DueThisMonth       
 from [dbo].[tbl_tsk_TaskHistory] u right join user_detail (nolock) d on d.user_id=u.AssignedTo       
 where parentid=@parentid and u.IsActive = 1 and isnull(IsAppointment,0)=1 and isnull(outcomesid,0)=0       
 and taskid<>4 and isnull(u.Status,'') <> 'completed'       
 --and u.AssignedTo=case when @isadmin=1 then u.AssignedTo else @userid end       
 and isnull(u.AssignedTo,u.CreatedBy) in (select User_ID from @tbluser)       
 group by parentid       
 ) a       
       
 select @rsection Section,isnull(Executive,null) Executive, ExecutiveName, isnull(AppointmentsDue,null) AppointmentsDue, isnull([Image],'') as Image, UserID       
 from       
(select user_login Executive, (isnull(FName, '') + ' ' + isnull(LName, '')) as ExecutiveName, count(1) as AppointmentsDue , isnull([Image],'') as Image, u.assignedto as UserID       
 from [dbo].[tbl_tsk_TaskHistory] u right join user_detail (nolock) d on d.user_id=u.assignedto       
 where parentid=@parentid and u.IsActive = 1 and       
 isnull(IsAppointment,0)=1 and isnull(outcomesid,0)=0 and taskid<>4 and isnull(u.Status,'') <> 'completed'       
 --and u.AssignedTo=case when @isadmin=1 then u.AssignedTo else @userid end       
 and isnull(u.AssignedTo,u.CreatedBy) in (select User_ID from @tbluser) group by user_login,FName, LName,[Image],u.assignedto       
 ) a order by AppointmentsDue desc       
       
end       
       
if isnull(@section,'Calls')='Calls'       
begin       
set @rsection='Calls'       
 Exec usp_getCallLogSummary @userid, @rsection    
     
 /*    
select @rsection Section,* from       
(       
select clientid Parentid       
,sum(case when context like 'in%' and cast(call_start_time as date)=cast(getdate() as date) then 1 else 0 end) IncomingCallsToday       
,sum(case when context like 'out%' and cast(call_start_time as date)=cast(getdate() as date) then 1 else 0 end) AutomatedOutgoingCallsToday       
,sum(case when context ='DialerCalls' and cast(call_start_time as date)=cast(getdate() as date) then 1 else 0 end) ClickCallsToday       
,sum(case when context like 'in%' and datediff(dd,cast(call_start_time as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) IncomingCallsLast7days       
,sum(case when context like 'out%' and datediff(dd,cast(call_start_time as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) AutomatedOutgoingCallsLast7days       
,sum(case when context like 'DialerCalls' and datediff(dd,cast(call_start_time as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) ClickCallsLast7days       
,sum(case when context like 'in%' and month(call_start_time)=month(getdate()) and year(call_start_time)=year(getdate()) then 1 else 0 end) IncomingCallsThisMonth       
,sum(case when context like 'out%' and month(call_start_time)=month(getdate()) and year(call_start_time)=year(getdate()) then 1 else 0 end) AutomatedOutgoingCallsThisMonth       
,sum(case when context like 'DialerCalls' and month(call_start_time)=month(getdate()) and year(call_start_time)=year(getdate()) then 1 else 0 end) ClickCallsThisMonth       
from Kit19Calls(nolock) k       
where clientid=@parentid and call_start_time>dateadd(dd,-30,getdate())       
and dbo.lastagentattended(k.uniqueid)= case when @isadmin=1 then dbo.lastagentattended(k.uniqueid) else @UserLoginWithName end       
group by clientid       
) a       
       
select @rsection Section,* from       
(       
select parentid       
,sum(case when cast(createon as date)=cast(getdate() as date) then 1 else 0 end) SIMCallsToday       
,sum(case when datediff(dd,cast(createon as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) SIMCallsLast7Days       
,sum(case when month(CreateOn)=month(getdate()) and year(createon)=year(getdate()) then 1 else 0 end) SIMCallsThisMonth       
from       
[dbo].[tbl_DailPaidCallDetails] t join user_detail(nolock) u on u.user_id=t.UserId       
where parentid=@parentid and createon>dateadd(dd,-30,getdate())       
and t.UserId=case when @isadmin=1 then t.UserId else @userid end       
group by parentid       
) a       
       
select @rsection Section,* from       
(       
select clientid Parentid       
--sum(case when cast(k.call_start_time as date)=cast(getdate() as date) then 1 else 0 end)       
,count(distinct (case when cast(k.call_start_time as date)=cast(getdate() as date) then puniqueid end)) as CallsMissedToday       
,count(distinct (case when datediff(dd,cast(k.call_start_time as date),cast(getdate() as date)) between 0 and 7 then puniqueid end)) as CallsMissedLast7Days       
,count(distinct (case when month(k.call_start_time)=month(getdate()) and year(k.call_start_time)=year(getdate()) then puniqueid end)) as CallsMissedThisMonth       
from Kit19CallsDialled(nolock) k join kit19calls(nolock) c on k.puniqueid=c.uniqueid       
where clientid=@parentid and k.call_start_time>dateadd(dd,-30,getdate())       
 --and c.accountcode=case when @isadmin=1 then c.accountcode else @userid end       
and not exists       
(select 1 from Kit19CallsDialled(nolock) where puniqueid=k.puniqueid and dialstatus='answer')       
group by clientid       
) a       
       
select @rsection Section,isnull(a.Executive,b.Executive) Executive,sum(isnull(IncomingCalls,0)) IncomingCalls,       
sum(isnull(missedcalls,0)) Missed,       
sum(isnull(OutgoingCalls,0)) OutgoingCalls,Image from       
(       
select clientid Parentid,[dbo].[lastagentattended](c.uniqueid) Executive,sum(case when d.uniqueid is not null then 1 else 0 end) as IncomingCalls       
,sum(case when d.uniqueid is not null then 0 else 1 end) as MissedCalls       
from kit19calls(nolock) c       
left join Kit19CallsDialled(nolock) d on puniqueid=c.uniqueid and d.uniqueid is not null       
where clientid=@parentid and context <>'DialerCalls'       
and cast(c.call_start_time as date)=cast(getdate() as date)       
and [dbo].[lastagentattended](c.uniqueid)<>''       
 --and c.accountcode=case when @isadmin=1 then c.accountcode else @userid end       
group by clientid,c.uniqueid       
       
--select clientid Parentid,[dbo].[lastagentattended](c.uniqueid) Executive,count(1) as IncomingCalls       
--from kit19calls(nolock) c       
--where clientid=@parentid and context <>'DialerCalls'       
--and cast(c.call_start_time as date)=cast(getdate() as date)       
--and exists(select 1 from Kit19CallsDialled(nolock) where puniqueid=c.uniqueid and uniqueid is not null)       
--group by clientid,c.uniqueid       
) a       
full outer join       
(select @rsection Section,parentid,Executive,sum(outgoing) as OutgoingCalls ,isnull([Image],'') as Image from       
(       
select 'clickcalls' as Mode,clientid Parentid,user_login Executive,count(1) as outgoing ,isnull([Image],'') as Image       
from kit19calls(nolock) c join user_detail(nolock) u on u.user_id=c.accountcode       
where clientid=@parentid and context ='DialerCalls'       
and cast(c.call_start_time as date)=cast(getdate() as date)       
and exists(select 1 from Kit19CallsDialled(nolock) where puniqueid=c.uniqueid and uniqueid is not null)       
and c.accountcode=case when @isadmin=1 then c.accountcode else @userid end       
group by clientid,User_Login,[Image]       
union       
select 'simcalls' as Mode,Parentid,user_login Executive,count(1) as outgoing ,isnull([Image],'') as Image       
from [tbl_DailPaidCallDetails](nolock) t join user_detail(nolock) u on u.user_id=t.UserId       
where parentid=@parentid and cast(createon as date)=cast(getdate() as date)       
 and t.userid=case when @isadmin=1 then t.UserId else @userid end       
group by parentid,User_Login,[Image]       
) a       
group by parentid,Executive ,a.Image       
) b on a.Executive=b.Executive       
group by isnull(a.Executive,b.Executive) ,b.Image       
   */    
end       
       
if isnull(@section,'Support')='Support'       
begin       
set @rsection='Support'       
       
select @rsection Section,* from       
(select parentid       
,sum(case when cast(date_created as date)=cast(getdate() as date) then 1 else 0 end) TicketsToday       
,sum(case when datediff(d,cast(date_created as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) TicketsLast7Days       
,sum(case when month(date_created)=month(getdate()) and year(date_created)=year(getdate()) then 1 else 0 end) TicketsThisMonth       
,sum(case when status =0 then 1 else 0 end) as UnattendedTillNow       
from serv_ticketmaster(nolock)       
where parentid=@parentid and deleted=0       
group by ParentID       
       
) a       
end       
       
if isnull(@section,'Mails')='Mails'       
begin       
set @rsection='Mails'       
      
select @rsection Section,* from       
(select parentid--,user_login executive       
,sum(case when cast(e.createdtime as date)=cast(getdate() as date) then 1 else 0 end) MailsToday       
,sum(case when datediff(dd,cast(e.createdtime as date),cast(getdate() as date)) between 0 and 7 then 1 else 0 end) MailsLast7days       
,sum(case when month(e.createdtime)=month(getdate()) and year(e.createdTime)=year(getdate()) then 1 else 0 end) MailsThisMonth       
from       
 mysmst.dbo.tbl_email e join mysmst.dbo.Tbl_EmailConnectionSettings c on c.Id=e.EmailConnectionId       
 join user_detail(nolock) u on u.user_id=c.UserId       
 where parentid=@parentid       
and c.UserId=case when @isadmin=1 then c.UserId else @userid end       
 group by ParentID       
) a       
end       
       
if isnull(@section,'Engagement')='Engagement'       
begin       
set @rsection='Engagement'       
       
select @rsection Section,* from       
(       
select t.parentid       
,ActiveCampaigns       
,SUM(case when cast(ExecutionTime as date)=cast(getdate() as date) then NoOfRecipients else 0 end)       
+ sum(case when cast(batchinserttime as date)=cast(getdate() as date) then TotalRecords else 0 end) ReachToday       
,SUM(case when datediff(dd,cast(ExecutionTime as date),cast(getdate() as date)) between 0 and 7 then NoOfRecipients else 0 end)       
+ sum(case when datediff(dd,cast(batchinserttime as date),cast(getdate() as date)) between 0 and 7 then TotalRecords else 0 end) ReachLast7Days       
,SUM(case when month(ExecutionTime)=month(getdate()) and year(executiontime)=year(getdate()) then NoOfRecipients else 0 end)       
+ sum(case when month(BatchInsertTime)=month(getdate()) and year(BatchInsertTime)=year(getdate()) then TotalRecords else 0 end) ReachThisMonth       
 from triggeredcampaigns(nolock) t       
 join       
 (select parentid,sum(isactive) activecampaigns from triggeredcampaigns(nolock) where parentid=@parentid group by parentid ) tr on tr.parentid=t.parentid       
 left join       
 (select campaignid,executiontime,NoOfRecipients from UserCampaignExecutionHistory(nolock)) u       
 on u.CampaignID in (t.smscampaignid,t.mailcampaignid,t.voicecampaignid)       
 left join       
 (select campaignid,batchinserttime,totalrecords from WBatchInfo (nolock)) b on b.campaignid=t.whatsappcampaignid       
 where t.parentid=@parentid       
 and 1=@isadmin       
 group by t.parentid ,ActiveCampaigns       
       
) a       
end       
       
if isnull(@section,'Webpages')='Webpages'       
begin       
set @rsection='Webpages'       
select top 3 @rsection Section,* from       
(       
select parentid,pagename,count(1) TotalVisits from       
[dbo].[VisitPageDetails] v where parentid=@parentid       
and 1=@isadmin       
and type='LandingPage' and datediff(dd,v.VisitDate,getdate()) between 0 and 30       
group by parentid,pagename       
) a       
order by TotalVisits desc       
end       
       
if isnull(@section,'Webforms')='Webforms'       
begin       
set @rsection='Webforms'       
select top 3 @rsection Section,* from       
(select f.FormName,count(1) as TotalFilled ,f.url_script from       
[dbo].[WebEntryTbl] w right join WebFormTbl f on f.FormId=w.FormId       
where f.ParentId=@parentid       
and (w.EntryDate is null or datediff(dd,cast(w.EntryDate as date),cast(getdate() as date)) between 0 and 30)       
and 1=@isadmin       
group by f.FormName ,f.url_script       
) a order by TotalFilled desc       
end       
       
if isnull(@section,'EmployeeTimeTracking')='EmployeeTimeTracking'       
begin       
set @rsection='EmployeeTimeTracking'       
declare @datetoday nvarchar(100)=convert(date,getdate()),@exceedingbreak int,@lowworkhours Int       
       
drop table if exists #temp       
create table #temp(userrole nvarchar(100),Total int,Available int,Late int,[Absent] int,Productive int,Slacking int)       
insert into #temp       
exec mysmstimetrack.dbo.[Usp_GetUserMatrices] @datetoday ,@userid       
       
select user_id,allowedbreakinminutes,0 as breakexceeded, 0 as workhours       
into #break from MysmsTimeTrack.dbo.timetracking_settings with (nolock)       
where parentid=@parentid       
       
update b set breakexceeded=1 from #break b left join MysmsTimeTrack.dbo.timetrackingbreakhours t       
on b.user_id=t.user_id and t.breakdate=cast(getdate() as date)       
where breaktimeinseconds*60>allowedbreakinminutes       
       
update b set workhours=isnull(t.workingtimeinseconds,0) from #break b left join       
MysmsTimeTrack.dbo.timetrackingworkinghours t       
on b.user_id=t.user_id and t.workingdate=cast(getdate() as date)       
       
select @exceedingbreak=count(1) from #break where breakexceeded=1       
select @lowworkhours=count(1) from #break where workhours<dbo.[fn_requiredworkingtime](user_id,cast(getdate() as date))       
select @rsection Section,@parentid Parentid,* from       
(       
select Total,Absent as AbsentToday,Late as LateToday,Available as PresentToday,@exceedingbreak ExceedingBreak,@lowworkhours LessWorkHours from #temp       
) a       
drop table if exists #break       
drop table if exists #temp       
       
end       
       
if isnull(@section,'Campaigns')='Campaigns'       
begin       
set @rsection='Campaigns'       
       
select @rsection Section,* from       
(       
select parentid,medium,count(1) CampaignEventCount from UserCampaignMaster(nolock) u where IsEventBased=1 and IsActive=1       
and eventid is null and parentid=@parentid       
and 1=@isadmin       
group by parentid,Medium       
) a       
       
select @rsection Section,* from       
(       
select parentid,medium,count(1) CampaignScheduledCount from UserCampaignMaster(nolock) u where IsEventBased=0 and IsActive=1       
and isnull(ExpiryDate,dateadd(dd,1,getdate()))>getdate() and (StartDate>getdate() or IsSchedule=1)       
and eventid is null and parentid=@parentid       
and 1=@isadmin       
group by parentid,Medium       
) a       
end       
       
if isnull(@section,'Pipeline')='Pipeline'       
begin       
set @rsection='Pipeline'       
select @rsection Section,* from       
(       
select p.parentid,p.Name Pipeline,s.Name Stage,count(1) as TotalLeads,s.Sequence       
from       
LeadPipelineMapping l right join Pipeline_Master p on l.PipelineID=p.ID       
right join PipelineStages s on l.PipeLineStage=s.ID       
where (l.id is null or (l.id=(select max(id) from LeadPipelineMapping where leadid=l.leadid and l.IsDeleted=0)       
and l.IsDeleted=0))       
and p.ParentID=@parentid       
and l.DealOwner=case when @isadmin=1 then dealowner else @userid end       
and s.name not in ('won','lost')       
group by p.parentid,p.Name,s.Name,s.Sequence       
) a order by Pipeline,Sequence       
       
select @rsection Section,* from       
(       
select p.parentid,p.Name Pipeline,user_login Executive, (isnull(FName, '') + ' ' + isnull(LName, '')) as ExecutiveName, count(1) as TotalLeads       
from       
LeadPipelineMapping l(nolock) right join Pipeline_Master p(nolock) on l.PipelineID=p.ID       
join PipelineStages s (nolock) on s.id=l.PipeLineStage       
join user_detail (nolock) u on u.user_id=l.DealOwner       
where (l.id is null or (l.id=(select max(id) from LeadPipelineMapping where leadid=l.leadid and l.IsDeleted=0)       
and l.IsDeleted=0))       
and p.ParentID=@parentid       
and l.DealOwner=case when @isadmin=1 then dealowner else @userid end       
and s.name not in ('won','lost')       
group by p.parentid,p.Name,User_Login, FName, LName       
) a order by Executive, ExecutiveName       
       
select @rsection Section,* from       
(       
select p.parentid,p.Name Pipeline,count(1) as ExpiredLeads       
from       
LeadPipelineMapping l(nolock) right join Pipeline_Master p(nolock) on l.PipelineID=p.ID       
join PipelineStages s (nolock) on s.id=l.PipeLineStage       
join user_detail (nolock) u on u.user_id=l.DealOwner       
where       
l.id=(select min(id) from LeadPipelineMapping where leadid=l.leadid and l.IsDeleted=0)       
and l.IsDeleted=0       
and dateadd(dd,p.dealexpiry,l.CreatedDate)<getdate()       
and p.ParentID=@parentid       
and l.DealOwner=case when @isadmin=1 then dealowner else @userid end       
and not exists (select 1 from LeadPipelineMapping where PipelineID=l.PipelineID       
and s.name in ('won','lost') and CreatedDate>l.CreatedDate)       
group by p.parentid,p.Name       
) a order by ExpiredLeads desc       
       
select @rsection Section,* from       
(       
select p.Name as Pipeline,p.parentid,isnull(estimatedclosure,0) EstimatedClosure       
from Pipeline_Master p join       
(       
select parentid,pipeline,cast(sum(EstimatedClosure) as money) EstimatedClosure       
from       
(       
select p.parentid,p.Name Pipeline,l.Amount*l.Probability/100 EstimatedClosure       
 --,l.Probability       
from       
LeadPipelineMapping l(nolock) right join Pipeline_Master p(nolock) on l.PipelineID=p.ID       
join PipelineStages s (nolock) on s.id=l.PipeLineStage       
where       
(l.id is null or (l.id=(select max(id) from LeadPipelineMapping where leadid=l.leadid and l.IsDeleted=0)       
and l.IsDeleted=0       
and month(l.estimatedclosuredate)=month(getdate())       
and year(l.estimatedclosuredate)=year(getdate())       
and not exists (select 1 from LeadPipelineMapping(nolock) where PipelineID=l.PipelineID       
and s.name in ('won','lost'))       
and l.DealOwner=case when @isadmin=1 then dealowner else @userid end       
))       
and p.ParentID=@parentid       
) a       
group by parentid,pipeline       
) a on a.ParentID=p.ParentID and a.Pipeline=p.Name       
 and a.ParentID = @parentid     
       
) a       
       
       
end       
       
end       



GO

/* ============================================================
   Procedure: [dbo].[usp_dashboard_correctedassignedtoday_v2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE dbo.usp_dashboard_correctedassignedtoday_v2
(
    @userid  bigint,
    @section nvarchar(50) = NULL
)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @isadmin int, @parentid bigint, @userlogin nvarchar(100),
            @ettrole nvarchar(50), @UserLoginWithName nvarchar(200);
    DECLARE @tbluser TABLE (User_ID bigint, Name varchar(100), Image varchar(100));

    INSERT INTO @tbluser
        EXEC Use_GetUserDetails @userid;

    SELECT  @isadmin           = ISNULL(isadmin, 0),
            @parentid          = parentid,
            @userlogin         = user_login,
            @UserLoginWithName = ISNULL(user_login + ' ( ' + ISNULL(fname,'') + ' ' + ISNULL(lname,'') + ' )', '')
    FROM    user_detail (NOLOCK)
    WHERE   user_id = @userid;

    SELECT  @ettrole = t.userrole
    FROM    MysmsTimeTrack.dbo.timetracking_settings t WITH (NOLOCK)
    WHERE   user_id = @userid;

    DECLARE @rsection nvarchar(50);

    IF ISNULL(@section,'leads') = 'leads'
    BEGIN
        SET @rsection = 'leads';

        /* ------ ONE scan of userleads for this tenant ------ */
        IF OBJECT_ID('tempdb..#lead') IS NOT NULL DROP TABLE #lead;
        SELECT  u.ID, u.ParentID, u.LeadNo,
                u.CreatedOn, u.ModifiedOn, u.FollowupDate, u.LastFollowupCreatedOn,
                u.CreatedBy, u.AssignedTo,
                u.SourceName, u.MediumName, u.CampaignName,
                u.enquirysource,
                u.personname, u.companyname, u.ProfileImgFileName
        INTO    #lead
        FROM    dbo.userleads (NOLOCK) u
        WHERE   u.ParentID = @parentid;

        CREATE CLUSTERED INDEX cx_lead_id ON #lead(ID);

        /* ------ Result-set 1: counter tile ------ */
        SELECT @rsection AS Section, *
        FROM
        (
            SELECT  u.ParentID,
                    SUM(CASE WHEN CAST(CreatedOn AS DATE) = CAST(GETDATE() AS DATE) THEN 1 ELSE 0 END)              AS LeadsToday,
                    SUM(CASE WHEN MONTH(CreatedOn) = MONTH(GETDATE()) AND YEAR(CreatedOn) = YEAR(GETDATE()) THEN 1
                             ELSE 0 END)                                                                            AS LeadsThisMonth,
                    ISNULL(LeadsNotFollowedUpYet, 0)                                                                AS LeadsNotFollowedUpYet,
                    SUM(CASE WHEN CAST(LastFollowupCreatedOn AS DATE) = CAST(GETDATE() AS DATE) THEN 1 ELSE 0 END)  AS AssignedToday,
                    SUM(CASE WHEN @isadmin = 1 AND CAST(CreatedOn AS DATE) = CAST(GETDATE() AS DATE)
                                                 AND CAST(LastFollowupCreatedOn AS DATE) = CAST(GETDATE() AS DATE) THEN 1
                             WHEN @isadmin = 0 AND AssignedTo = @userid
                                                 AND CAST(CreatedOn AS DATE) = CAST(GETDATE() AS DATE)
                                                 AND CAST(LastFollowupCreatedOn AS DATE) = CAST(GETDATE() AS DATE) THEN 1
                             ELSE 0 END)                                                                            AS CreatedAndAssignedToday,
                    SUM(1)                                                                                          AS AssignedTillToday
            FROM    #lead u
            LEFT JOIN
            (
                SELECT  ParentID, COUNT(1) AS LeadsNotFollowedUpYet
                FROM    #lead u
                WHERE   enquirysource NOT IN (12,13,14,15,28,29)
                  AND   enquirysource <> 22
                  AND   CreatedBy = CASE WHEN @isadmin = 1 THEN CreatedBy ELSE @userid END
                  AND   u.ModifiedOn IS NULL
                  AND   ABS(DATEDIFF(MINUTE, u.CreatedOn, u.FollowupDate)) <= 2
                GROUP BY ParentID
            ) k
                ON  u.ParentID = k.ParentID
            WHERE   1 = CASE WHEN @isadmin = 1 THEN 1
                             WHEN u.AssignedTo IN (SELECT User_ID FROM @tbluser) THEN 1
                             ELSE 0 END
            GROUP BY u.ParentID, LeadsNotFollowedUpYet
        ) a;

        /* ------ Result-set 2: top 10 by score ------ */
        SELECT @rsection AS Section, *
        FROM
        (
            SELECT TOP 10
                   ROUND((l.currentscore / CAST((SELECT (MAX(currentscore) * 100) / 99
                                                 FROM lead_score_history_latest (NOLOCK) e
                                                 WHERE parentid = @parentid) AS float)) * 99, 2) AS CurrentScore,
                   u.LeadNo, u.ID AS LeadID, u.personname, u.companyname, u.ProfileImgFileName
            FROM    #lead u
            LEFT JOIN dbo.lead_score_history_latest l (NOLOCK)
                ON  u.ID = l.leadid
            WHERE   u.CreatedBy IN (SELECT User_ID FROM @tbluser)
            ORDER BY l.currentscore DESC, u.CreatedOn DESC
        ) a;

        /* ------ Result-set 3: by Source ------ */
        SELECT @rsection AS Section, *
        FROM
        (
            SELECT  ISNULL(s.name, 'Unknown') AS Source, COUNT(1) AS LeadCount
            FROM    #lead u
            LEFT JOIN dbo.UserSourceSettings s (NOLOCK)
                ON  s.SourceID = u.SourceName
            WHERE   u.CreatedBy IN (SELECT User_ID FROM @tbluser)
            GROUP BY ISNULL(s.name, 'Unknown')
        ) a;

        /* ------ Result-set 4: by Medium ------ */
        SELECT @rsection AS Section, *
        FROM
        (
            SELECT  ISNULL(s.name, 'Unknown') AS Medium, COUNT(1) AS LeadCount
            FROM    #lead u
            LEFT JOIN dbo.UserMediumSettings s (NOLOCK)
                ON  s.MediumID = u.MediumName
            WHERE   u.CreatedBy IN (SELECT User_ID FROM @tbluser)
            GROUP BY ISNULL(s.name, 'Unknown')
        ) a;

        /* ------ Result-set 5: by Campaign ------ */
        SELECT @rsection AS Section, *
        FROM
        (
            SELECT  ISNULL(s.name, 'Unknown') AS Campaign, COUNT(1) AS LeadCount
            FROM    #lead u
            LEFT JOIN dbo.UserCampaignSettings s (NOLOCK)
                ON  s.CampaignID = u.CampaignName
            WHERE   u.CreatedBy IN (SELECT User_ID FROM @tbluser)
            GROUP BY ISNULL(s.name, 'Unknown')
        ) a;

        /* ------ Result-set 6: by CreatedBy ------ */
        SELECT @rsection AS Section, *
        FROM
        (
            SELECT  ISNULL(UD.User_Login, 'Unknown') AS createdby, COUNT(1) AS LeadCount
            FROM    #lead u
            LEFT JOIN dbo.User_Detail UD (NOLOCK)
                ON  UD.User_ID = u.CreatedBy
            WHERE   u.CreatedBy IN (SELECT User_ID FROM @tbluser)
            GROUP BY ISNULL(UD.User_Login, 'Unknown')
        ) a;

        /* ------ Result-set 7: by AssignedTo ------ */
        SELECT @rsection AS Section, *
        FROM
        (
            SELECT  ISNULL(u.AssignedTo, 'Unknown') AS Assignedto, COUNT(1) AS LeadCount
            FROM    #lead u
            LEFT JOIN dbo.User_Detail UD (NOLOCK)
                ON  UD.User_ID = u.CreatedBy
            WHERE   u.CreatedBy IN (SELECT User_ID FROM @tbluser)
            GROUP BY ISNULL(u.AssignedTo, 'Unknown')
        ) a;

        DROP TABLE #lead;
        RETURN;
    END

END



GO

/* ============================================================
   Procedure: [dbo].[usp_databaseHit]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE dbo.usp_databaseHit 
  @UserId BIGINT  
 ,@spid INT  
 ,@token VARCHAR(MAX)  
AS  
BEGIN  
 IF EXISTS (  
   SELECT 1  
   FROM tbl_loginlookup(nolock)
   WHERE user_id = @UserId  
    AND token = @token  
   )  
 BEGIN  
  IF @spid <> @@spid  
  BEGIN  
   UPDATE tbl_loginlookup  
   SET sp_id = @@spid  
    ,Modified_Date = GETDATE()  
   WHERE User_id = @UserId AND sp_id = @spid AND token = @token  
  
   SELECT @@spid  
  END  
 END  
 ELSE  
 BEGIN  
  SELECT 0  
 END  
END  
  


GO

/* ============================================================
   Procedure: [dbo].[usp_dc_DialerScheduleCallData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_dc_DialerScheduleCallData](
	@dailerId bigint,
	@Offset int  = 0,
	@PageSize int = 20
)
as
begin
	--declare 
	--	@dailerId bigint = 11,
	--	@Offset int  = 0,
	--	@PageSize int = 20

	declare @ParentId bigint = 0, @StartPoint int = 0, @EndPoint int = 0;

	set @StartPoint = @Offset + 1
	set @EndPoint = @Offset + @PageSize

	select * from (select 
		row_number() over (partition by sc.DailerId order by sc.Id) as [SNo],
		count(1) over() as [TotalRows],
		sc.Id,
		dbo.RemoveExtraSpaces(sc.MobileNo) as [MobileNo],
		sc.EntityName,
		sc.EntityId,
		(case when sc.EntityName = 'eqnuiry' then en.PersonName else ul.PersonName end) as [PersonName],
		(case when sc.EntityName = 'eqnuiry' then en.EntityId else ul.LeadNo end) as [EntityNo],
		format(c.callcreatedon, 'dd-MMM-yyyy HH:mm:ss') as [callcreatedon],
		datediff(second, c.Callstarttime, c.Callendtime) as CallDurations,
		sc.[status] as [Status]
	from tbl_dc_ScheduleCall(nolock) sc
	left join Calllog(nolock) c on c.reftable = 'tbl_voip_endpointInteraction' and  sc.UniqueId = c.refid 
	left join v_dc_UserEnquiry en on sc.EntityName = 'enquriy' and en.EntityId  = sc.EntityId 
	left join v_dc_UserLead ul on sc.EntityName = 'lead' and ul.EntityId  = sc.EntityId
		where sc.DailerId = @dailerId) t where t.SNo between @StartPoint and @EndPoint

end



