/* ============================================================
   Procedure: [dbo].[usp_dc_GetDialerLiveReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_dc_GetDialerLiveReport](
	@UserId bigint,
	@SearchText nvarchar(255) = null,
	@UserIds nvarchar(max) = '',
	@Status nvarchar(255)=null,
	@FromDate datetime,
	@ToDate datetime,
	@Offset int = 0,
	@PageSize int = 20
)
as
begin

	--declare 
	--	@UserId bigint = 34594,
	--	@UserIds nvarchar(max) = N'',
	--	@FromDate datetime = getdate(),
	--	@ToDate datetime =getdate(),
	--	@Status nvarchar(255) = '',
	--	@Offset int = 0,
	--	@PageSize int = 20

	declare @ParentId bigint = 0, @StartPoint int = 0, @EndPoint int = 0;

	set @StartPoint = @Offset + 1
	set @EndPoint = @Offset + @PageSize
	DECLARE  @isadmin INT;

	SELECT @parentid = ParentID
		,@isadmin = IsAdmin
	FROM Mysms.dbo.User_Detail(NOLOCK)
	WHERE User_ID = @UserId;

		select * from ( select top 1 
				ROW_NUMBER() over (partition by d.ParentId order by d.CreatedOn desc) as [SNo],
				Count(1) over() as [TotalRows],
				d.Id, d.UserId, d.ParentId, format(d.CreatedOn, 'dd-MMM-yyyy hh:MM:ss tt') as [CreatedOn], 
				d.DailerTimeSec, d.TalkTimeSec, d.IdleTimeSec, d.AcwTimeSec, d.BreakTimeSec,
				a.Image as [AgentImage], concat(a.User_Login, '(', a.FName, ' ', a.LName, ')') as [AgentName],
				(select top 1 status from tbl_dc_ScheduleCall cs where cs.ParentId=@ParentId order by cs.id desc) as Status,
			(SELECT Count(*)
	FROM calendar(NOLOCK) ca
	LEFT JOIN CallLog(NOLOCK) c ON cast(c.callcreatedon AS DATE) = cast(ca.start_dts AS DATE)
	--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
	WHERE cast(start_dts as date) between cast(@fromdate as date) AND cast(@todate as date)
		AND c.parentid = @ParentId
		AND c.Direction = 'Incoming'
		AND isnull(c.agentcalldisposition, '') IN ( 'ANSWERED', 'ANSWER')
		AND 1 = (
			CASE 
				WHEN @isadmin = 1
					THEN 1
				WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from User_Detail)
					THEN 1
				WHEN isnull(c.agentuserid, 0) = @UserId
					THEN 1
				ELSE 0
				END
			)) As IncomingAnsweredCall,
			(SELECT Count(*)
	FROM calendar(NOLOCK) ca
	LEFT JOIN CallLog(NOLOCK) c ON cast(c.callcreatedon AS DATE) = cast(ca.start_dts AS DATE)
	--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
	WHERE cast(start_dts as date) between cast(@fromdate as date) AND cast(@todate as date)
		AND c.parentid = @ParentId
		AND c.Direction IN ('outgoing', 'out')
		AND isnull(c.agentcalldisposition, '') IN ( 'ANSWERED', 'ANSWER')
		AND isnull(c.customercalldisposition, '') NOT IN ( 'ANSWERED', 'ANSWER')
		AND 1 = (
			CASE 
				WHEN @isadmin = 1
					THEN 1
				WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from User_Detail)
					THEN 1
				WHEN isnull(c.agentuserid, 0) = @UserId
					THEN 1
				ELSE 0
				END
			)
) As MissedCall
			from tbl_dc_DailyDialerData(nolock) d
			inner join User_Detail(nolock) a on d.UserId = a.User_ID
	      -- LEFT JOIN tbl_dc_ScheduleCall(NOLOCK) cs ON d.ParentId=cs.ParentId
	where d.ParentId = @ParentId 
				and cast(d.CreatedOn as date) between cast(@FromDate as date) and cast(@ToDate as date)
				and 1 = (case 
						when isnull(@UserIds, '') = '' then 1 
						when d.UserId in (select [value] from string_split(@UserIds, ',')) then 1 
					else 0 end)
				and 1 = (case 
						when isnull(@Status, '') = '' then 1 
						when a.User_Login like '%'+@Status+'%' then 1 
					else 0 end)
					
					
					
		) t where t.SNo between @StartPoint and @EndPoint

end




