/* ============================================================
   Procedure: [dbo].[usp_dc_GetDialserSettingList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_dc_GetDialserSettingList](
	@UserId bigint = 34594,
	@SearchText nvarchar(255) = '',
	@Offset int  = 0,
	@PageSize int = 20
)
as
begin

	--declare 
	--	@UserId bigint = 34594,
	--	@SearchText nvarchar(255) = 'New',
	--	@Offset int  = 0,
	--	@PageSize int = 20

	declare @ParentId bigint = 0;
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	declare @StartPoint int = ( @Offset + 1) 
	declare	@EndPoint int = @StartPoint + @PageSize


	select * from (
		select ROW_NUMBER() over(partition by s.ParentId order by s.ModifiedOn desc) as [SNo],
			count(1) over(partition by s.ParentId) as [TotalRow], 	
			s.Id, s.RoleId, s.RoleName, s.ParentId, s.CreatedOn, s.IsActive, ModifiedOn, 	
			concat(cr.User_Login, ' (', cr.FName, ' ', cr.LName , ')') as [CreatedBy],
			concat(cr.User_Login, ' (', cr.FName, ' ', cr.LName , ')') as [ModifiedBy]
		from tbl_dc_RolenCallSetting(nolock) s
			inner join User_Detail(nolock) cr on s.CreatedBy = cr.User_ID
			inner join User_Detail(nolock) mr on s.CreatedBy = mr.User_ID
			where s.ParentId = @ParentId
				and isnull(s.IsDeleted, 0) = 0
				and 1 = (case 
						when isnull(@SearchText, '') = '' then 1
						when s.RoleName like '%'+@SearchText+'%' then 1
					else 0 end)

	)t where t.SNo between @StartPoint and @EndPoint

end



