/* ============================================================
   Procedure: [dbo].[usp_dc_GetEntityMobileNosForSchedule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_dc_GetEntityMobileNosForSchedule](
	@EntityName nvarchar(255) = '',
	@EntityId bigint = 0,
	@UserId bigint = 0
)
as
begin
	--declare 
	--	@EntityName nvarchar(255) = 'lead',
	--	@EntityId bigint = 10716320,
	--	@UserId bigint = 32222

	declare @mobileNoJSON nvarchar(max) = '[]'

	if(@EntityName = 'lead')
	begin
		set @mobileNoJSON = (select concat(trim(CountryCode), ' ', trim(Mobile)) as [MobileNo]
			from Userleads_Mobile_Email(nolock) where ulme_id = @EntityId and Mobile not in ('', '0') for json path)
	end

	if(@EntityName = 'enquiry')
	begin
		set @mobileNoJSON = (select concat(trim(CountryCode), ' ', trim(Mobile)) as [MobileNo] 
			from Userenquiry_Mobile_Email(nolock) where enquiryid = @EntityId and Mobile not in ('', '0') for json path) 
	end

	declare @widgetSetup nvarchar(255) = '{"AfterFollowUp":false,"AfterTask":false,"AfterAppointment":false}';
	select @widgetSetup = isnull(json_query(SettingJSON, '$.ShowWidget'), 
									'{"AfterFollowUp":false,"AfterTask":false,"AfterAppointment":false}')
		from tbl_ScheduleCallPageSetting where UserId = @UserId


	declare @payloadJson nvarchar(max) = '{}'
	set @payloadJson = JSON_MODIFY(JSON_MODIFY(@payloadJson, '$.MobileNos', JSON_QUERY(@mobileNoJSON)),
							'$.ShowWidget', JSON_QUERY(@widgetSetup))

	print @payloadJson

	select @payloadJson as WidgetSettingJSON

end



