/* ============================================================
   Procedure: [dbo].[usp_dc_GetRoleMasterListByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_dc_GetRoleMasterListByUserId(
	@UserId bigint
)
AS
BEGIN
	DECLARE @ParentId BIGINT  = 0;

	SELECT @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	select id as [RoleId], rolename as [RoleName], SysRoleCode as [RoleCode]  from  systemRoles tm WITH (NOLOCK)        
	   where isnull(tm.isactive,0) = 1 and  Id IN ( 4, 9 ,10 )    
	union
	select RoleId, RoleName, RoleCode  FROM TBL_UA_RoleMaster tm WITH (NOLOCK)        
	INNER JOIN User_detail ud ON ud.User_Id = tm.CreatedBy        
	 where isnull(tm.Active,0) = 1 and ( tm.RoleId IN ( 4 ,9 ) AND tm.IsInternal = 1 )        
    OR (  tm.IsInternal = 0 AND tm.ParentId = @ParentId and isnull(tm.Active,0) = 1)  
END



