/* ============================================================
   Procedure: [dbo].[usp_dc_GetScheduleCallAction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_dc_GetScheduleCallAction(
	@Id bigint = 0,
	@SettingJSON nvarchar(max) = null,
	@UserId bigint = 0,
	@Mode nvarchar(255) = null
)
as
begin

	--declare 
	--	@Id bigint = 0,
	--	@SettingJSON nvarchar(max) = N'{"Id":2,"leftTabs":[{"name":"followUps","text":"Follow Ups","description":"Follow Ups","filterOptions":{"filterMode":"followUps","filterConditions":[]},"class":"active"},{"name":"allContacts","text":"All Contacts","description":"All Contacts","filterOptions":{"filterMode":"allContacts","filterConditions":[]},"class":""},{"name":"taskDue","text":"Task Due","description":"Task Due","filterOptions":{"filterMode":"taskDue","filterConditions":[]},"class":""},{"name":"newContacts","text":"New Contacts","description":"New Contact","filterOptions":{"filterMode":"newContacts","filterConditions":[]},"class":""},{"name":"appointmentDue","text":"Appointment Due","description":"Appointment Due","filterOptions":{"filterMode":"appointmentDue","filterConditions":[]},"class":""}],"tableConfig":{"Columns":[{"ColumnName":"PersonName","DisplayName":"Person Name","css":"customClass","width":"170"},{"ColumnName":"PinCode","DisplayName":"Pin Code","css":"customClass","width":"100"},{"ColumnName":"ResidentialAddress","DisplayName":"Residential Address","css":"customClass","width":"220"},{"ColumnName":"SourceName","DisplayName":"Source Name","css":"customClass","width":"200"},{"ColumnName":"MobileNo","DisplayName":"MobileNo","css":"customClass","width":"170"},{"ColumnName":"MediumName","DisplayName":"Medium Name","css":"customClass","width":"220"},{"ColumnName":"LeadNo","DisplayName":"Lead No","css":"customClass","width":"170"},{"ColumnName":"FollowupDate","DisplayName":"Followup Date","css":"customClass","width":"220"},{"ColumnName":"InitialRemarks","DisplayName":"Initial Remarks","css":"customClass","width":"250"},{"ColumnName":"FollowUpStatus","DisplayName":"Follow Up Status","css":"customClass","width":"150"}]}}',
	--	@UserId bigint = 32222,
	--	@Mode nvarchar(255) = N'GET_SET'
	
	
	declare @ParentId bigint, @settingId bigint, @IsAdmin bit = 0, @RoleId bigint = 0
	select @ParentId = ParentID, @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @UserId

	DECLARE @Status int = 0, @Message nvarchar(255)  = 'Invalid Opeations', @Detail nvarchar(max)

	if(@Mode = 'INSERT')
	begin
		INSERT INTO tbl_ScheduleCallPageSetting(UserId, ParentId, CreatedOn, CreatedBy, ModifiedOn, ModifiedBy, SettingJSON)
			values ( @UserId, @ParentId, GETDATE(), @UserId, GETDATE(), @UserId, @SettingJSON )
		set @settingId = SCOPE_IDENTITY()
		select @SettingJSON = JSON_MODIFY(@SettingJSON, '$.Id', @settingId);
		update tbl_ScheduleCallPageSetting set SettingJSON = @SettingJSON where Id = @settingId
		select @Status = 1, @Message = 'Data saved successfully', @Detail = @SettingJSON;
	end

	if(@Mode = 'UPDATE')
	begin
		UPDATE tbl_ScheduleCallPageSetting SET
			ModifiedOn = GETDATE(),
			ModifiedBy = @UserId,
			SettingJSON = @SettingJSON
				where Id = @Id

		select @Status = 1, @Message = 'Data saved successfully', @Detail = @SettingJSON;
	end

	if(@Mode = 'SELECT')
	begin
		SELECT @Detail = SettingJSON FROM tbl_ScheduleCallPageSetting where UserId = @UserId
		select @Status = 1, @Message = 'Success';
	end

	if(@Mode = 'GET_SET')
	begin
		if(@Id > 0)
		begin
			update tbl_ScheduleCallPageSetting set SettingJSON = @SettingJSON where Id = @Id
			set @Detail = @SettingJSON
			select @Status = 1, @Message = 'Success';
		end
		else
		begin
			if(not exists(select 1 from tbl_ScheduleCallPageSetting(nolock) where UserId = @UserId))
			begin
				insert into tbl_ScheduleCallPageSetting(UserId, ParentId, CreatedOn, CreatedBy, ModifiedOn, ModifiedBy, SettingJSON)
					values(@UserId, @ParentId, getdate(), @UserId, getdate(), @UserId, @SettingJSON)
				set @settingId = scope_identity()

				select @SettingJSON = JSON_MODIFY(@SettingJSON, '$.Id', @settingId);
				update tbl_ScheduleCallPageSetting set SettingJSON = @SettingJSON where Id = @settingId
				set @Detail = @SettingJSON
				select @Status = 1, @Message = 'Success';
			end
			else 
			begin
				select @Status = 1, @Message = 'Success', @Detail = SettingJSON
					from tbl_ScheduleCallPageSetting(nolock) where UserId = @UserId
			end
		end

		select @RoleId = tuRolem.RoleId FROM TBL_UA_UserRoleMappingMaster(NOLOCK) tuUserrm 
			LEFT JOIN VW_SystemRole_RoleMaster(NOLOCK) tuRolem 
				ON tuUserrm.RoleCode = tuRolem.RoleCode and tuUserrm.Active=1  and tuRolem.isActive=1
			WHERE [tuUserrm].[UserId] = @UserId

		If((@ParentId = @UserId or @IsAdmin = 1))
		begin
			select @RoleId=4 -- SYS_ADMIN
		end

		print @RoleId

		declare @allowedColumns nvarchar(max) = N'', @entityActionPermission nvarchar(max) = N''

		select 
			@allowedColumns = JSON_VALUE(SettingJSON, '$.AllowedColumns'),
			@entityActionPermission = JSON_VALUE(SettingJSON, '$.EntityActionPermission')
		from tbl_dc_RolenCallSetting(nolock) where IsActive = 1 and  ParentId = @ParentId and RoleId = @RoleId
		

		SET @Detail = JSON_MODIFY(JSON_MODIFY(isnull(@Detail, '{}'), '$.allowedColumns', @allowedColumns), '$.entityActionPermission', @entityActionPermission)

	end

	select @Status as [Status], @Message as [Message], @Detail as [Detail];

end



