/* ============================================================
   Procedure: [dbo].[usp_dc_GetScheduleCallDataForGrid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_dc_GetScheduleCallDataForGrid](
	@UserId bigint = 34594,
	@PageNo int = 1,
	@PageSize int = 20,
	@FromDate date = null,
	@ToDate date = null,
	@FilterText nvarchar(255) = null,
	@FilterOptions nvarchar(max) = N''
)
as
begin

	--declare
	--	@UserId bigint = 32222,
	--	@PageNo int = 1,
	--	@PageSize int = 20,
	--	@FromDate date = N'29-Oct-2024',
	--	@ToDate date = N'04-Nov-2024',
	--	@FilterText nvarchar(255) = '',
	--	@FilterOptions nvarchar(max) = N'{"filterMode":"followUps","filterConditions":[]}'

	declare @ParentId bigint = 0, @StartPoint int = 0, @EndPoint int = 20;

	set @StartPoint = ((@PageNo - 1) * @PageSize + 1)
	set @EndPoint = ( @StartPoint + @PageSize ) - 1

	print concat('@StartPoint => ',  @StartPoint,  ' :: @EndPoint => ', @EndPoint) 

	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	declare @SettingJSON nvarchar(max) = '{}', @configColumns nvarchar(max) = '[]'


	select @SettingJSON = SettingJSON,
		@configColumns = json_query(SettingJSON, '$.tableConfig.Columns' )
	from tbl_ScheduleCallPageSetting(nolock) where UserId = @UserId

	--set @configColumns = N'[{"ColumnName":"AmountPaid","DisplayName":"Amount Paid","css":"customClass","width":"200"},{"ColumnName":"AssignedTo","DisplayName":"Assigned To"},{"ColumnName":"CampaignName","DisplayName":"Campaign Name"},{"ColumnName":"City","DisplayName":"City"},{"ColumnName":"CompanyName","DisplayName":"Company Name","css":"rakesh78","width":"123"},{"ColumnName":"Country","DisplayName":"Country"},{"ColumnName":"CountryCode","DisplayName":"CountryCode"},{"ColumnName":"CountryCode1","DisplayName":"CountryCode1"},{"ColumnName":"CountryCode2","DisplayName":"CountryCode2"},{"ColumnName":"CreatedBy","DisplayName":"Created By"},{"ColumnName":"CreatedDate","DisplayName":"Created Date"},{"ColumnName":"Purnea","DisplayName":"Purnea"},{"ColumnName":"Purnea2","DisplayName":"Purnea2"},{"ColumnName":"Purnea3","DisplayName":"Purnea3"}]'

	drop table if exists #setupedColumns
	select * into #setupedColumns  from openjson(@configColumns) with (ColumnName nvarchar(255) '$.ColumnName', DisplayName nvarchar(255) '$.DisplayName')

	declare @setupedColumns nvarchar(max) = ''

	select @setupedColumns  = concat(
			iif(len(@setupedColumns) > 0, concat(@setupedColumns, ','), concat(@setupedColumns, '') ),
			concat('(case when sc.EntityName = ''enquiry'' then en.', ColumnName, ' else ul.', ColumnName, ' end) as [', ColumnName, ']')
	) from #setupedColumns 
	
	-- print @setupedColumns

	declare @filterMode nvarchar(255) = '', @filterConditionsJSON nvarchar(max) = ''
	if(len(@FilterOptions) > 0)
	begin
		select @filterMode = filterMode, @filterConditionsJSON = filterConditions from openjson(@FilterOptions) with (
			filterMode nvarchar(255) '$.filterMode',
			filterConditions nvarchar(max) '$.filterConditions'
		)
	end

	print concat('@filterMode => ', @filterMode)

	drop table if exists #scheduleCalls

	select * into #scheduleCalls from ( 
		select  
			ROW_NUMBER() over (partition by s.ParentId order by s.Id desc) as [SNo],
			COUNT(1) over(partition by s.Parentid) as [TotalRows], s.MobileNo, s.EntityName, 
			s.Id,
			s.EntityId, s.RefTable, s.RefId, s.ScheduleTime, s.ParentId, s.CreatedBy,
			s.MobileNo as [ScheduleMobileNo],
			s.CreatedOn, s.DailerId, s.IsActive, s.IsDeleted, s.DeletedBy
		from tbl_dc_ScheduleCall(nolock) s
		left join v_dc_UserEnquiry en on s.EntityName = 'enquiry' and en.EntityId  = s.EntityId
		left join v_dc_UserLead ul on s.EntityName = 'lead' and ul.EntityId  = s.EntityId
		where s.ParentId = @ParentId 
			and s.CreatedBy = @UserId
			and 1 = ( case
					when ISNULL(s.ScheduleTime,'')='' then 1
					when isnull(@FromDate, '') = '' then 1 
					when isnull(@ToDate, '') = '' then 1 
					when cast(s.ScheduleTime as date) between @FromDate and @ToDate then 1 
				else 0 end )
			and 1 = ( case 
					when ISNULL(@FilterText, '')  = '' then 1
					when ( s.MobileNo like '%'+@FilterText+'%' or  ul.PersonName like '%'+@FilterText+'%'  or  en.PersonName like '%'+@FilterText+'%') then 1 
				else 0 end)
			and isnull(s.IsActive, 0) = 1
			and 1 = (case 
				when @filterMode = 'allContacts' then 1
				when @filterMode = 'newContacts' and datediff(day, s.createdon, getdate()) <= 1 then 1
				when @filterMode = 'followUps' and 'followUps' in (select [value] from string_split(s.labels, ','))  then 1
				when @filterMode = 'taskDue' and 'taskDue' in (select [value] from string_split(s.labels, ',')) then 1
				when @filterMode = 'appointmentDue' and 'appointmentDue' in (select [value] from string_split(s.labels, ',')) then 1
				when @filterMode in (select [value] from string_split(s.labels, ','))  then 1		
				else 0 end
			)
		) t where t.SNo between @StartPoint and @EndPoint

	/*
	drop table if exists #tmpEnquiryIds 
	drop table if exists #tmpLeadIds
	create table #tmpEnquiryIds (enquiryId bigint)
	create table #tmpLeadIds (leadId bigint)

	insert into #tmpEnquiryIds(enquiryId)
	select EntityId from #scheduleCalls where EntityName = 'enquiry'

	insert into #tmpLeadIds(leadId)
	select EntityId from #scheduleCalls where EntityName = 'lead'

	declare @customNames nvarchar(max) = ''

	select @customNames = concat(
			iif(len(@customNames) > 0, concat(@customNames, ','), ''), 
			quotename(fieldname)
		) from customfields(nolock) where ParentID = @ParentId

	drop table if exists #dcUserEnquiry
	select * into #dcUserEnquiry 
		from v_dc_UserEnquiry v inner join #tmpEnquiryIds e on v.EntityId = e.enquiryId

	*/
		
		


	--declare @sqlEnquiryPvt nvarchar(max) = concat(N'select EnquiryID, ', @customNames, ' from ( ',
	--		N'select EnquiryID, fieldname, fieldvalue from ( select c.EnquiryID, f.fieldname, c.fieldvalue from #tmpEnquiryIds t ',
	--		N'inner join customfieldLeadvalue(nolock) c on t.enquiryId = c.EnquiryID ',
	--		N'inner join customfields(nolock) f on c.fieldID = f.field_ID ',	
	--	N') i ) a PIVOT ( max(a.fieldvalue) for a.fieldname in (', @customNames, ')) t ')

	--print  @sqlEnquiryPvt

	--select LeadID, [Whatsapp],[Father_Name],[Website],[DOB] from (
	--	select LeadID, fieldname, fieldvalue from ( select c.LeadID, f.fieldname, c.fieldvalue from #tmpLeadIds t
	--	inner join customfieldLeadvalue(nolock) c on t.leadId = c.LeadID
	--	inner join customfields(nolock) f on c.fieldID = f.field_ID
	--) i ) a PIVOT (
	--	max(a.fieldvalue)
	--	for a.fieldname in ([Whatsapp],[Father_Name],[Website],[DOB])
	--) t


	declare @dataQuery nvarchar(max) = concat(N'select sc.SNo, sc.TotalRows, sc.Id, format(sc.ScheduleTime, ''dd-MMM-yyyy HH:mm'') as [ScheduleTime] , sc.EntityName, sc.EntityId, sc.ScheduleMobileNo, ',
		N'(case when sc.EntityName = ''enquiry'' then en.PersonName else ul.PersonName end) as [PersonName]',
		iif(len(@setupedColumns) > 0, concat(', ', @setupedColumns, ' ') , ' '),
		N'from #scheduleCalls sc ',
			N'left join v_dc_UserEnquiry en on sc.EntityName = ''enquiry'' and en.EntityId  = sc.EntityId ',
			N'left join v_dc_UserLead ul on sc.EntityName = ''lead'' and ul.EntityId  = sc.EntityId ',
			N'order by sc.SNo asc ')

	print @dataQuery
	
	execute sp_executesql @dataQuery

end



