/* ============================================================
   Procedure: [dbo].[usp_dc_GetScheduleCallDataList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
exec usp_dc_GetScheduleCallDataList @UserId=32222,@PageNo=0,@PageSize=20,@FromDate=N'04-Nov-2024',@ToDate=N'04-Nov-2024',@FilterText=default,@UserIds=N'32222'
go
*/


CREATE   PROCEDURE [dbo].[usp_dc_GetScheduleCallDataList]
(
    @UserId BIGINT,
    @PageNo INT,
    @PageSize INT,
    @FromDate DATE = '',
    @ToDate DATE = '',
    @FilterText NVARCHAR(255) = '',
    @UserIds NVARCHAR(MAX) = N''
)
AS
BEGIN

	--declare
	--	@UserId bigint = 32222,
	--	@PageNo int = 1,
	--	@PageSize int = 20,
	--	@FromDate date = '04-Nov-2024',
	--	@ToDate date = '04-Nov-2024',
	--	@FilterText nvarchar(255) = '',
	--	@UserIds nvarchar(max) =  N''

    DECLARE @ParentId BIGINT = 0,
            @StartPoint INT = 0,
            @EndPoint INT = 20;
	set @StartPoint = @PageNo + 1
	set @EndPoint = @PageNo + @PageSize
	--SET @StartPoint = (@PageNo - 1) * @PageSize + 1;
	--SET @EndPoint = @PageNo * @PageSize;
	
    PRINT CONCAT('@StartPoint => ', @StartPoint, ' :: @EndPoint => ', @EndPoint);

    SELECT @ParentId = ParentID FROM User_Detail(NOLOCK) WHERE User_ID = @UserId AND [Status] = 1 ;
	 
	drop table if exists #tempUsers    
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))    
	insert into #tempUsers(User_ID, Name, Image)    
	exec Use_GetUserDetails @UserID = @UserId    

	DECLARE @UserIdTable TABLE (UserId BIGINT);
	if(len(@UserIds) > 0)
	begin
		INSERT INTO @UserIdTable (UserId)
		SELECT CAST(value AS BIGINT) FROM STRING_SPLIT(@UserIds, ',');
	end
	
    select t.labels, t.User_ID, t.User_Login, t.ContactCount,
        ROW_NUMBER() OVER (partition by (select null) order by (select null)) AS RowNumber,
        count(1) OVER () as TotalRows
     from (
        SELECT 
            sc.labels, ud.User_ID, ud.User_Login, count(1) as ContactCount
        FROM tbl_dc_ScheduleCall(nolock) sc
            inner join User_Detail(NOLOCK) ud on sc.CreatedBy = ud.User_ID
			inner join #tempUsers(nolock) tu on tu.User_ID=ud.User_ID
            WHERE sc.ParentID = @ParentId and IsActive = 1 
				and 1 = ( case 
					when not exists(select 1 from @UserIdTable) then 1 
					when sc.CreatedBy in (select UserId from @UserIdTable ) then 1
					else 0 end )
				and 1 = (case
						when isnull(@FromDate, '') = '' then 1
						when isnull(@ToDate, '') = '' then 1
						when isnull(sc.ScheduleTime, '')  = '' then 1
						when  cast(sc.ScheduleTime as date) between cast(@FromDate as date) and cast(@ToDate as date) then 1
						else 0
					end)
				and 1 = ( case 
					when ISNULL(@FilterText, '')  = '' then 1
					when ( sc.labels like '%'+@FilterText+'%' or  ud.User_Login like '%'+@FilterText+'%')
					then 1 
				else 0 end)
		GROUP BY sc.labels, ud.User_ID, ud.User_Login
	) t 

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
		,@Activity_type = 'View_CallDialTrans_rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_dc_ScheduleCall'
END




