/* ============================================================
   Procedure: [dbo].[usp_dc_GetScheduleCallDataListForContact]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_dc_GetScheduleCallDataListForContact]
(
    @UserId BIGINT,
    @PageNo INT,
    @PageSize INT,
    @FromDate DATE = '',
    @ToDate DATE = '',
    @FilterText NVARCHAR(255)='',
    @UserIds NVARCHAR(MAX)= '',
    @ListName NVARCHAR(MAX) = ''
)
AS
BEGIN
	--DECLARE
	--	@UserId BIGINT = 32222,
	--	@PageNo INT = 0,
	--	@PageSize INT = 20,
	--	@FromDate date = '02-Nov-2024',
	--	@ToDate date = '02-Nov-2024',
	--	@FilterText NVARCHAR(255) = null,
	--	@UserIds NVARCHAR(MAX) = N'',
	--	@ListName NVARCHAR(MAX) = 'appointmentDue'

	DECLARE
	@ParentId BIGINT = 0, @StartPoint INT = 0, @EndPoint INT = 20, @TotalUsers INT = 0;
	set @StartPoint = @PageNo + 1
	set @EndPoint = @PageNo + @PageSize
	--SET @StartPoint = (@PageNo - 1) * @PageSize + 1;
	--SET @EndPoint = @PageNo * @PageSize;
	SELECT @ParentId = ParentID FROM User_Detail(NOLOCK) WHERE User_ID = @UserId AND [Status] = 1 ;

	PRINT CONCAT('@StartPoint => ', @StartPoint, ' :: @EndPoint => ', @EndPoint,':: @ParentId=>',@ParentId);
	drop table if exists #tempUsers    
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))    
	insert into #tempUsers(User_ID, Name, Image)    
	exec Use_GetUserDetails @UserID = @UserId    
	
	DECLARE @UserIdTable TABLE (UserId BIGINT);
	if(len(@UserIds) > 0)
	begin
		INSERT INTO @UserIdTable (UserId)
		SELECT CAST(value AS BIGINT) FROM STRING_SPLIT(@UserIds, ',');
	end
	
	 select * from (
        SELECT ROW_NUMBER() OVER (partition by (select null) order by (select null)) AS RowNumber,
        count(1) OVER () as TotalRows, ud.User_Login,ud.User_ID,
            sc.Id,
            sc.labels,
            sc.EntityId,
            FORMAT(sc.ScheduleTime, 'dd-MMM-yyyy HH:mm') AS [ScheduleTime],
            CASE 
                WHEN sc.EntityName = 'enquiry' THEN isnull(en.PersonName,'')
                WHEN sc.EntityName = 'lead' THEN isnull(ul.PersonName,'')
                ELSE isnull(en.PersonName,'') 
            END AS [PersonName],
			 CASE 
                WHEN sc.EntityName = 'enquiry' THEN  isnull(en.LeadNo,'')
                WHEN sc.EntityName = 'lead' THEN isnull( ul.LeadNo,'')
                ELSE  isnull( ul.LeadNo,'')
            END AS [LeadNo],
            sc.EntityName, 
            sc.IsActive
        FROM tbl_dc_ScheduleCall(nolock) sc
            inner join User_Detail(NOLOCK) ud on sc.CreatedBy = ud.User_ID
			inner join #tempUsers(nolock) tu on tu.User_ID=ud.User_ID
			left join v_dc_UserEnquiry(NOLOCK) en ON en.EntityId = sc.EntityId and sc.EntityName = 'enquiry'
            left join v_dc_UserLead(NOLOCK) ul ON ul.EntityId = sc.EntityId and sc.EntityName = 'lead'
            WHERE sc.ParentID = @ParentId and IsActive = 1 and 
				1  = (case 
						when isnull(@ListName, '') = '' then 1
						when @ListName = 'allcontacts' then 1
						when sc.labels = @ListName then 1
						else 0 end
					)
				and 1 = ( case 
					when not exists(select 1 from @UserIdTable) then 1 
					when ud.User_ID in (select UserId from @UserIdTable ) then 1
					else 0 end )
			    and 1 = ( case
				when isnull(@FromDate, '') = '' then 1 
				when isnull(@ToDate, '') = '' then 1 
				when isnull(sc.ScheduleTime, '') = '' then 1
				when cast(sc.ScheduleTime as date) between @FromDate and @ToDate then 1
				else 0 end )
				and 1 = ( case 
					when ISNULL(@FilterText, '')  = '' then 1
					when ( ul.PersonName like '%'+@FilterText+'%'  or  en.PersonName like '%'+@FilterText+'%'  or  ud.User_Login like '%'+@FilterText+'%') then 1 
				else 0 end)
		) t where t.RowNumber between @StartPoint and @EndPoint

   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
		,@Activity_type = 'View_CallDialCont_rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_dc_ScheduleCall' 
END;



