/* ============================================================
   Procedure: [dbo].[usp_dc_GetScheduleCallForDailer]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_dc_GetScheduleCallForDailer](
	@UserId bigint,
	@RecordCount int = 10,
	@ScheduleTime int=0
)
as
begin
	--declare 
	--	@UserId bigint = 32397,
	--	@RecordCount int = 10,
	--	@ScheduleTime int=1

	declare @ParentId bigint = 0
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId and Status = 1

	drop table if exists #tblScheduleContact
	select top (@RecordCount) * into #tblScheduleContact from tbl_dc_ScheduleCall(nolock) sc
		where sc.ParentId =  @ParentId and sc.CreatedBy = @UserId and sc.IsActive =1 
		 and isnull([status], '') in ('', 'in-queue') 
		 and 1 = (case 
			when isnull(ScheduleTime, '')  = '' then 1
			when isnull(ScheduleTime, '') <> '' and 
			sc.ScheduleTime between  dateadd(HOUR, (-1*@ScheduleTime), getdate()) and dateadd(HOUR, (1*@ScheduleTime), getdate())
				then 1
			else 0 end
			)	
			order by sc.ScheduleTime asc
	
	drop table if exists #tempDialer
	create table #tempDialer(
		Id bigint,
		MobileNo nvarchar(25),
		EntityName nvarchar(25),
		EntityId bigint,
		ScheduleTime datetime,
		PersonName nvarchar(255)
	)

	declare @sqlQuery nvarchar(max) = concat(N'insert into #tempDialer(Id, MobileNo, EntityName, EntityId, ScheduleTime, PersonName ) ',
		N'select top ',@RecordCount, N' sc.Id, dbo.RemoveExtraSpaces(sc.MobileNo), sc.EntityName, sc.EntityId, sc.ScheduleTime, ',
		N'(case when sc.EntityName = ''eqnuiry'' then en.PersonName else ul.PersonName end) as [PersonName] ',
	N'from #tblScheduleContact sc ',
		N'left join v_dc_UserEnquiry en on sc.EntityName = ''enquriy'' and en.EntityId  = sc.EntityId ',
		N'left join v_dc_UserLead ul on sc.EntityName = ''lead'' and ul.EntityId  = sc.EntityId ')

	print @sqlQuery
	execute sp_executesql @sqlQuery

	update sc set sc.status = 'in-queue', sc.is_process = 2, sc.ProcessAt = getdate() 
		from #tempDialer t inner join tbl_dc_ScheduleCall(nolock) sc on t.Id = sc.Id

	select * from #tempDialer
	
end




