/* ============================================================
   Procedure: [dbo].[usp_dc_MassAddCallList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE [dbo].[usp_dc_MassAddCallList](
     @BatchID BIGINT = 0,
     @IDS NVARCHAR(MAX) = '',
     --@label NVARCHAR(255) = '',
     --@ScheduleTime datetime ,
     @EntityType NVARCHAR(10),
     @UserId BIGINT = 0,
     @MetaData NVARCHAR(MAX)
 )
 AS
BEGIN

	--DECLARE 
	--	@BatchID BIGINT = 3852,
	--	@IDS NVARCHAR(MAX) = '',
	--	@EntityType NVARCHAR(10) = 'enquiry',
	--	@UserId BIGINT = 34594,
	--	@MetaData nvarchar(max) = N''

	--SELECT @IDS =  STUFF((
	--	SELECT ',' + CAST(t.EntityId AS NVARCHAR(MAX))
	--	FROM Tbl_MassOperationDetails(NOLOCK) t WHERE t.SummaryId = @BatchID
	--	FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, '');

	--SELECT @EntityType = EntityType, @MetaData = metadata FROM Tbl_MassOperationSummary(NOLOCK) t WHERE t.BatchId = @BatchID

    DECLARE
        @lableName NVARCHAR(255) = '',
        @scheduleDate DATETIME = NULL,
        @dateType NVARCHAR(25) = '',
        @ParentId BIGINT;



    IF(ISNULL(@BatchID, 0) > 0)
    BEGIN
        --UPDATE Tbl_MassOperationSummary SET BatchStartTime = GETDATE() WHERE BatchID = @BatchID;

        SELECT @ParentId = ParentID FROM User_Detail (NOLOCK) WHERE User_ID = @UserId;

        SELECT @lableName=ListName,@scheduleDate=ScheduleDates,@dateType=DateType
        FROM OPENJSON(@MetaData) WITH (
                ListName NVARCHAR(255) '$.ListName',
                ScheduleDates NVARCHAR(255) '$.ScheduleDates',
                DateType NVARCHAR(25) '$.DateType'
            );

        DROP TABLE IF EXISTS #scContact;

        CREATE TABLE #scContact(
            Id BIGINT PRIMARY KEY IDENTITY(1,1),
            EntityName NVARCHAR(25),
            EntityId BIGINT,
            PersonName NVARCHAR(255),
            MobileNo NVARCHAR(255),
            ScheduleTime DATETIME,
            labelName NVARCHAR(255),
            ParentId BIGINT,
            UserId BIGINT
        );

        IF (@EntityType = 'enquiry')
        BEGIN
            INSERT INTO #scContact(EntityName, EntityId, PersonName, MobileNo, ScheduleTime, labelName, ParentId, UserId)
            SELECT 'enquiry', TRIM(REPLACE([s].[value], '  ', ' ')), TRIM(REPLACE(en.PersonName, '  ', ' ')),
                (CASE
                    WHEN MobileNo IS NOT NULL THEN CONCAT(CountryCode, ' ', MobileNo)
                    WHEN MobileNo1 IS NOT NULL THEN CONCAT(CountryCode1, ' ', MobileNo1)
                    WHEN MobileNo2 IS NOT NULL THEN CONCAT(CountryCode2, ' ', MobileNo2)
                END),
                (CASE
                    WHEN @dateType = 'SpecificTime' THEN @scheduleDate
                    WHEN @dateType = 'Blank' THEN NULL /* blank, any, nextFollowUp, specific */
                    WHEN @dateType = 'Any' THEN @scheduleDate
                    ELSE NULL
                END),
                @lableName, @ParentId, @UserId
            FROM STRING_SPLIT(@IDS, ',') s
            INNER JOIN UserEnquiry (NOLOCK) en ON en.EnquiryID = TRIM([s].[value])
            WHERE ISNULL(COALESCE(en.MobileNo, en.MobileNo1, en.MobileNo2), '') <> '';

        END;

        IF (@EntityType = 'lead')
        BEGIN
            INSERT INTO #scContact(EntityName, EntityId, PersonName, MobileNo, ScheduleTime, labelName, ParentId, UserId)
            SELECT 'lead', TRIM(REPLACE([s].[value], '  ', ' ')), TRIM(REPLACE(ul.PersonName, '  ', ' ')),
                (CASE
                    WHEN ul.MobileNo IS NOT NULL THEN CONCAT(ul.CountryCode, ' ', ul.MobileNo)
                    WHEN ul.MobileNo1 IS NOT NULL THEN CONCAT(ul.CountryCode1, ' ', ul.MobileNo1)
                    WHEN ul.MobileNo2 IS NOT NULL THEN CONCAT(ul.CountryCode2, ' ', ul.MobileNo2)
                END),
                (CASE
                    WHEN @dateType = 'SpecificTime' THEN @scheduleDate
                    WHEN @dateType = 'Blank' THEN NULL /* blank, any, nextFollowUp, specific */
                    WHEN @dateType = 'Any' THEN @scheduleDate
                    WHEN @dateType = 'NextFollowUp' THEN ul.NextStatusDate
                    ELSE NULL
                END), @lableName, @ParentId, @UserId
            FROM STRING_SPLIT(@IDS, ',') s
            INNER JOIN UserLeads (NOLOCK) ul ON ul.ID = TRIM([s].[value]);

        END;

        IF (EXISTS (SELECT TOP 1 1 FROM #scContact))
        BEGIN

			--  Deactivate active lead and update as per new filter

			UPDATE tbl_dc_ScheduleCall SET IsActive = 0 FROM tbl_dc_ScheduleCall sc
			INNER JOIN #scContact scContact ON sc.EntityId = scContact.EntityId AND sc.EntityName = scContact.EntityName
            WHERE sc.IsActive = 1

            DECLARE @batchSize INT = 100;
            DECLARE @offset INT = 0;
            WHILE (SELECT COUNT(*) FROM #scContact) > @offset
            BEGIN
                DECLARE @InsertedRecords TABLE (EntityName NVARCHAR(25), EntityId BIGINT, SchdeudleId BIGINT);
                
                INSERT INTO tbl_dc_ScheduleCall(MobileNo, EntityName, EntityId, RefTable, RefId, ScheduleTime, ParentId, CreatedBy, CreatedOn, DailerId, IsActive, labels)
                OUTPUT inserted.EntityName, inserted.EntityId, inserted.Id INTO @InsertedRecords
                SELECT MobileNo, EntityName, EntityId, '', 0, ScheduleTime, ParentId, UserId, GETDATE(), 0, 1, labelName 
                FROM #scContact ORDER BY EntityId OFFSET @offset ROWS FETCH NEXT @batchSize ROWS ONLY;

				DECLARE @tbl LeadActivitywithid_Tbltype 

				INSERT INTO @tbl ( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )
				SELECT c.EntityId, u.User_ID, u.ParentID,
					( CASE WHEN c.EntityName = 'enquiry' then 
							CONCAT('Enquiry with name ', e.PersonName, ' with No. ', e.EnquiryID,' was added in call listName: ', labelName, ' by ', u.User_Login)
						WHEN c.EntityName = 'enquiry' then 
							CONCAT('Lead with name ', l.PersonName, ' with No. ', l.LeadNo, ' was added in call listName: ', labelName, ' by ', u.User_Login)
					end ),
					( CASE WHEN c.EntityName = 'enquiry' then  'Enquiry added to Call List'
						WHEN c.EntityName = 'enquiry' then 'Lead added to Call List' end ),
					'tbl_dc_ScheduleCall', i.SchdeudleId						
				FROM #scContact c 
					INNER JOIN @InsertedRecords  i ON i.EntityName = c.EntityName and i.EntityId = c.EntityId
					INNER JOIN User_Detail(NOLOCK) u ON c.UserId = u.User_ID 
					LEFT JOIN UserLeads(NOLOCK) l ON c.EntityId = l.ID AND c.EntityName = 'lead'
					LEFT JOIN UserEnquiry(NOLOCK) e ON c.EntityId = e.EnquiryID AND c.EntityName = 'lead'


				exec UspSaveentityActivity_withMultipleValue_withid @tbl
                
                SET @offset += @batchSize;

            END;
        END;

        SELECT 'Success' AS StatusMessage, COUNT(*) AS TotalRecords FROM #scContact;

        IF(ISNULL(@BatchID, 0) > 0)
        BEGIN
            UPDATE Tbl_MassOperationSummary SET BatchStartTime = GETDATE(), BatchEndTime = GETDATE(), 
				Remarks = 'Record Saved', IsProcessed = 1 WHERE BatchID = @BatchID;
        END;

        EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId
            @User_id = @UserId,
            @Activity_type = 'Insert',
            @ActionType = 'I',
            @RowJson = @MetaData,
            @Table_name = 'tbl_dc_ScheduleCall';

    END;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_dc_RolenCallSettingAction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_dc_RolenCallSettingAction]  
    @Mode NVARCHAR(10),  
    @Id BIGINT = NULL,  
    @RoleId BIGINT = NULL,  
    @RoleName NVARCHAR(255) = NULL,  
    @IsActive BIT = 1,  
    @SettingJSON NVARCHAR(MAX) = NULL,  
	@UserId  BIGINT = NULL  
AS  
BEGIN  


--declare
--    @Mode NVARCHAR(10) = N'CREATE',  
--    @Id BIGINT = 0,  
--    @RoleId BIGINT = 0,  
--    @RoleName NVARCHAR(255) = N'',  
--    @IsActive BIT = 1,  
--    @SettingJSON NVARCHAR(MAX) = N'{"Id":0,"Name":"DailerSetting_1720765362282","Role":{"Id":0,"Code":"","Name":""},"Roles":[{"Id":4,"Name":"Admin"},{"Id":9,"Name":"User"}],"EntityActionPermission":"call,sms,email","MassActionPermission":[],"AllowedColumns":"AmountPaid,AssignedTo,CampaignName"}',  
--	@UserId  BIGINT = 32222  

 DECLARE @Status int = 0, @Message nvarchar(255)  = 'Invalid Opeations', @Detail nvarchar(max)  
 BEGIN TRY  
  DECLARE @ParentId BIGINT = 0;  
  SELECT @ParentId = ParentID   
   FROM User_Detail(nolock) where User_ID = @UserId  

	IF(@Mode = 'CREATE')
	begin
		drop table if exists #tblJsonData
		create table #tblJsonData ( 
			Id INT,
			RoleId bigint,
			RoleName NVARCHAR(255),
			SettingJSON nvarchar(max)
		)

		declare @RolesJSON nvarchar(max) = json_query(@SettingJSON, '$.Roles')

		print @RolesJSON

		insert into #tblJsonData(Id, RoleId, RoleName, SettingJSON)
		select s.SNo, s.RoleId, s.RoleName,
			json_modify(json_modify(json_modify(json_modify(
				s.SettingJSON, '$.Name', CONCAT(JSON_VALUE(s.SettingJSON, '$.Name'), '_', s.RoleName)),
				'$.Role.Id', s.RoleId ), '$.Role.Name', s.RoleName),
				'$.Roles', '[]' )
			from (
				select Id, r.RoleId, r.RoleName, 
				@SettingJSON as [SettingJSON],
				ROW_NUMBER() over (partition by (select null) order by Id) as [SNo]
				from openjson(@SettingJSON) with (Id bigint '$.Id') 
				CROSS APPLY OPENJSON(@RolesJSON) with ( RoleId bigint '$.Id', RoleName nvarchar(255) '$.Name' ) AS r
			) s

		if(exists( select 1 from #tblJsonData j 
			inner join tbl_dc_RolenCallSetting(nolock) r on j.RoleId = r.RoleId and j.RoleName = j.RoleName
				where r.ParentId = @ParentId and r.IsActive = 1))
		begin
			declare @roleString nvarchar(255) = ''
			 select @roleString = STRING_AGG(r.RoleName, ',') from #tblJsonData j  inner join tbl_dc_RolenCallSetting(nolock) r
				on j.RoleId = r.RoleId and j.RoleName = j.RoleName where r.ParentId = @ParentId and r.IsActive = 1
			select @Message = 'Already Configured', @Detail = concat('(', @roleString, ') role settings are already configured')
		end
		else
		begin
			declare @insertedRole as table (
				id bigint
			)
			
			INSERT INTO tbl_dc_RolenCallSetting (
					RoleId, RoleName, ParentId, CreatedBy, CreatedOn, ModifiedBy, ModifiedOn, IsActive, SettingJSON)
				output inserted.id as sno into @insertedRole
			select  j.RoleId, j.RoleName, @ParentId, @UserId, GETDATE(), @UserId, GETDATE(), 1, j.SettingJSON
				from #tblJsonData as j 

			update r set r.SettingJSON = JSON_MODIFY(r.SettingJSON, '$.Id', i.id)
				from tbl_dc_RolenCallSetting(nolock) r inner join @insertedRole i on r.Id = i.id

			select @Status = 1, @Message = 'Data saved successfully'
		end
  end
  
  IF @Mode = 'UPDATE'  
  BEGIN  
   UPDATE tbl_dc_RolenCallSetting  
   SET RoleId = @RoleId,  
    RoleName = @RoleName,  
    ParentId = @ParentId,  
    ModifiedBy = @UserId,  
    ModifiedOn = GETDATE(),  
    SettingJSON = @SettingJSON  
   WHERE Id = @Id;  
   select @Status = 1, @Message = 'Data saved successfully';  
  END   
  IF @Mode = 'DELETE'  
  BEGIN  
   UPDATE tbl_dc_RolenCallSetting set IsActive = 0, IsDeleted = 1,   
     DeletedBy = @UserId, DeletedOn = GETDATE()   
    WHERE Id = @Id;  
   select @Status = 1, @Message = 'Data saved successfully';  
  END  
  
  IF @Mode = 'ACTIVE'  
  BEGIN  
   UPDATE tbl_dc_RolenCallSetting set IsActive = @IsActive,  
     ModifiedBy = @UserId, ModifiedOn = GETDATE()  
    WHERE Id = @Id;  
   select @Status = 1, @Message = 'Data saved successfully';  
  END  
  
  IF @Mode = 'SETTING'  
  BEGIN  
   select @Detail = SettingJSON from tbl_dc_RolenCallSetting (nolock) WHERE Id = @Id;  
   select @Status = 1, @Message = 'Data saved successfully';  
  END  
  
  
 END TRY  
	BEGIN CATCH  
		select @Status = 0, @Message = ERROR_MESSAGE();  
	END CATCH  
  
 select @Status as [Status], @Message as [Message], @Detail as [Detail];  
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_dc_SaveChangeScheduleCall]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_dc_SaveChangeScheduleCall]
    @Ids NVARCHAR(MAX),       
    @UserIds NVARCHAR(MAX)     
AS
BEGIN
    --DECLARE 
    --    @Ids NVARCHAR(MAX) = '[72463,72524,72541,72585,72728,72879,72997,73054,73138,73151,73336,73528,72116,72732,73132,73353,73404,72554,72586,72633]', 
    --    @UserIds NVARCHAR(MAX) = '[34594,36931]';

    DROP TABLE IF EXISTS #TempScheduleCall;

    CREATE TABLE #TempScheduleCall (
        Id BIGINT IDENTITY(1,1),
        EntityId INT,
        RefTable NVARCHAR(255),
        RefId INT,
        ScheduleTime DATETIME,
        ParentId INT,
        CreatedBy INT,
        MobileNo NVARCHAR(50), 
        EntityName NVARCHAR(255),
        ScheduleMobileNo NVARCHAR(50), 
        CreatedOn DATETIME,
        DailerId INT,
        labels NVARCHAR(500),  
        status NVARCHAR(500),  
        IsActive BIT
    );

    DECLARE @SIds TABLE (Id INT);
    INSERT INTO @SIds (Id)
    SELECT value
    FROM OPENJSON(@Ids);

    DECLARE @UIds TABLE (Id BIGINT, SNO INT);
    INSERT INTO @UIds (Id, SNO)
    SELECT value, ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS SNO
    FROM OPENJSON(@UserIds);

    DECLARE @noff INT = 0;
    SELECT @noff = COUNT(*) FROM @UIds; 

       DECLARE @EntityIds TABLE (EntityId INT);

    INSERT INTO @EntityIds (EntityId)
    SELECT EntityId
    FROM tbl_dc_ScheduleCall
    WHERE Id IN (SELECT Id FROM @SIds);
    UPDATE s
    SET s.IsActive = 0 
    FROM tbl_dc_ScheduleCall s
    WHERE s.EntityId IN (SELECT EntityId FROM @EntityIds);

    INSERT INTO #TempScheduleCall (EntityId, RefTable, RefId, ScheduleTime, ParentId, CreatedBy, MobileNo, EntityName, ScheduleMobileNo, CreatedOn, DailerId, labels, status, IsActive)
    SELECT r.EntityId, r.RefTable, r.RefId, r.ScheduleTime, r.ParentId, ui.Id, r.MobileNo, r.EntityName, 
           r.MobileNo, GETDATE(), NULL, r.labels, null, 1
    FROM (
        SELECT 
            s.EntityId, s.RefTable, s.RefId, s.ScheduleTime, s.ParentId, 0 AS CreatedBy, s.EntityName, 
            s.MobileNo, s.CreatedOn, s.DailerId, s.labels, s.status, 1 AS IsActive, 
            NTILE(@noff) OVER (ORDER BY s.Id) AS NTILE_GROUPID
        FROM tbl_dc_ScheduleCall(NOLOCK) s  
        INNER JOIN @SIds si ON s.Id = si.Id 
    ) r 
    INNER JOIN @UIds ui ON ui.SNO = r.NTILE_GROUPID;

    INSERT INTO tbl_dc_ScheduleCall(EntityId, RefTable, RefId, ScheduleTime, ParentId, CreatedBy, MobileNo, EntityName, CreatedOn, DailerId, labels, status, IsActive)
    SELECT 
        EntityId, RefTable, RefId, MAX(ScheduleTime), ParentId, MAX(CreatedBy), MobileNo, EntityName, MAX(CreatedOn), DailerId, labels, status, IsActive
    FROM 
        #TempScheduleCall
    GROUP BY EntityId, RefTable, RefId, ParentId, MobileNo, EntityName, DailerId, labels, status, IsActive;

END;



GO

/* ============================================================
   Procedure: [dbo].[usp_dc_SaveChangeScheduleCallList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_dc_SaveChangeScheduleCallList]
    @SelectedList NVARCHAR(MAX),       
    @UserIds NVARCHAR(MAX)     
AS
BEGIN
    --DECLARE  
    --    @SelectedList NVARCHAR(MAX) = '[{"UIds":"34594","LableList":"appointmentDue"}]', 
    --    @UserIds NVARCHAR(MAX) = '[36931]';

    DROP TABLE IF EXISTS #TempScheduleCall;
    CREATE TABLE #TempScheduleCall (
        Id BIGINT IDENTITY(1,1),
        EntityId INT,
        RefTable NVARCHAR(255),
        RefId INT,
        ScheduleTime DATETIME,
        ParentId INT,
        CreatedBy INT,
        MobileNo NVARCHAR(50), 
        EntityName NVARCHAR(255),
        ScheduleMobileNo NVARCHAR(50), 
        CreatedOn DATETIME,
        DailerId INT,
        IsActive BIT,
        labels NVARCHAR(50)  
    );

    DECLARE @ListTable TABLE (Listname NVARCHAR(255), UId BIGINT);
    INSERT INTO @ListTable (Listname, UId)
    SELECT LableList, UIds
    FROM OPENJSON(@SelectedList)
    WITH (
        LableList NVARCHAR(255),
        UIds BIGINT
    );

    DECLARE @UIds TABLE (Id BIGINT, SNO INT);
    INSERT INTO @UIds (Id, SNO)
    SELECT value, ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS SNO
    FROM OPENJSON(@UserIds);

    UPDATE s 
    SET s.IsActive = 0 
    FROM tbl_dc_ScheduleCall s
    INNER JOIN @ListTable lt ON s.labels = lt.Listname AND s.CreatedBy = lt.UId
    WHERE s.IsActive = 1;  
    INSERT INTO #TempScheduleCall (EntityId, RefTable, RefId, ScheduleTime, ParentId, CreatedBy, MobileNo, EntityName,
        ScheduleMobileNo, CreatedOn, DailerId, IsActive, labels) 
    SELECT r.EntityId, r.RefTable, r.RefId, r.ScheduleTime, r.ParentId, ui.Id AS CreatedBy, r.MobileNo, r.EntityName, 
        r.MobileNo, GETDATE(), r.DailerId, 1, r.labels  -- Ensure that 1 is a BIT value
    FROM (
        SELECT 
            s.EntityId, s.RefTable, s.RefId, s.ScheduleTime, s.ParentId, s.MobileNo, s.EntityName, 
            s.CreatedOn, s.DailerId, 
            s.labels, 
            NTILE((SELECT COUNT(*) FROM @UIds)) OVER (ORDER BY s.id) AS NTILE_GROUPID
        FROM tbl_dc_ScheduleCall s
        INNER JOIN @ListTable lt ON s.labels = lt.Listname AND s.CreatedBy = lt.UId
    ) r 
    INNER JOIN @UIds ui ON ui.SNO = r.NTILE_GROUPID;

    INSERT INTO tbl_dc_ScheduleCall (EntityId, RefTable, RefId, ScheduleTime, ParentId, CreatedBy, MobileNo, EntityName, CreatedOn, DailerId, IsActive, labels)
    SELECT 
        EntityId, RefTable, RefId, MAX(ScheduleTime), ParentId, MAX(CreatedBy), MobileNo, EntityName, MAX(CreatedOn), DailerId, 1, labels  
    FROM 
        #TempScheduleCall
    GROUP BY EntityId, RefTable, RefId, ParentId, MobileNo, EntityName, DailerId, labels;  
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_dc_UpdateDialerData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_dc_UpdateDialerData](
	@UserId bigint,
	@Mode nvarchar(255) = null,
	@OperationJSON nvarchar(max) = '{}'
)
as
begin
	
	--declare
	--	@UserId bigint = 34594,
	--	@Mode nvarchar(255) = N'NEW_RECORD',
	--	@OperationJSON nvarchar(max) = N'{"LabelName":"TestNewTab","ScheduleTime":"05-Jul-2024 10:39","EntityName":"lead","EntityId":"1691853","SuccessMessage":"Data saved successfully"}'

	declare @ParentId bigint = 0;
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId and [Status] = 1

	DECLARE @Status int = 0, @Message nvarchar(255)  = 'Invalid Opeations', @Detail nvarchar(max)

	if(len(@OperationJSON) > 2)
	begin
		declare @scheduleCallId bigint = 0, @uniqueId bigint = 0, @outcomeId bigint = 0, @remarks nvarchar(max) = '',
			@status_msg nvarchar(255) = '', @dialerTimeSec int = 0, @talkTimeSec int = 0, @idleTimeSec int = 0,
			@acwTimeSec int  = 0, @breakTimeSec int  = 0, @dialerId bigint = 0, @scheduleDateTime datetime = getdate(),
			@LabelName nvarchar(25) = null, @EntityName nvarchar(25) = '', @EntityId bigint = 0, @MobileNo nvarchar(25) = ''


		select top 1 @dialerId = Id from tbl_dc_DailyDialerData(nolock) 
				where UserId = @UserId and cast(CreatedOn as date) = cast(getdate() as date) order by id desc

		if(@Mode = 'ACW')
		begin
			
			select @scheduleCallId = scheduleCallId, @uniqueId = uniqueId, 
				@outcomeId = outcomeId, @remarks = remarks 
			from openjson(@OperationJSON) with (
				scheduleCallId bigint '$.scheduleCallId',
				uniqueId bigint '$.uniqueId',
				outcomeId bigint '$.outcomeId',
				remarks nvarchar(max) '$.remarks'
			)
			
			declare @callLogId bigint = 0;

			select @callLogId = id from CallLog(nolock) where reftable = 'tbl_voip_endpointInteraction' and refcolumn = 'id' and refid = 88
				order by id desc
			
			if(@callLogId > 0)
			begin
				exec usp_mob_MarkCalllogAsCompleted 
					@RecordingUrl = '', @CallLogId = @callLogId, @OutcomeId = @outcomeId, @Remarks = @remarks, @UserID = @UserId
			end
	
			update tbl_dc_ScheduleCall set UniqueId = @uniqueId, ProcessAt = GETDATE(), [status] = 'completed', DailerId = @dialerId 
				where id = @scheduleCallId select @Status = 1, @Message = 'Data saved successfully';
		end
	
		if(@Mode = 'CallStatus')
		begin
			select @scheduleCallId = scheduleCallId, @uniqueId = uniqueId, @status_msg = status
			from openjson(@OperationJSON) with (
				scheduleCallId bigint '$.scheduleCallId',
				uniqueId bigint '$.uniqueId',
				status nvarchar(max) '$.remarks'
			)
			
			update tbl_dc_ScheduleCall set UniqueId = @uniqueId, ProcessAt = GETDATE(), [status] = @status_msg where id = @scheduleCallId
			select @Status = 1, @Message = 'Data saved successfully';
		end

		if(@Mode = 'DialerTimeUpdate')
		begin
			
			select @dialerTimeSec = DialerTimeSec, @talkTimeSec = TalkTimeSec, @idleTimeSec = IdleTimeSec, 
				@acwTimeSec = AcwTimeSec, @breakTimeSec = breakTimeSec
			from openjson(@OperationJSON) with (
				DialerTimeSec bigint '$.DialerTimeSec',
				TalkTimeSec bigint '$.TalkTimeSec',
				IdleTimeSec bigint '$.IdleTimeSec',
				AcwTimeSec bigint '$.AcwTimeSec',
				breakTimeSec bigint '$.BreakTimeSec'
			)

			if(exists(select 1 from tbl_dc_DailyDialerData(nolock) where UserId = @UserId and cast(CreatedOn as date) = cast(getdate() as date)))
			begin
				update tbl_dc_DailyDialerData set 
					DailerTimeSec = case when @dialerTimeSec > 0 then @dialerTimeSec else DailerTimeSec end,
					TalkTimeSec = case when @talkTimeSec > 0 then @talkTimeSec else TalkTimeSec end, 
					IdleTimeSec = case when @idleTimeSec > 0 then @idleTimeSec else IdleTimeSec end,
					AcwTimeSec = case when @acwTimeSec > 0 then @acwTimeSec else AcwTimeSec end,
					BreakTimeSec = case when @breakTimeSec > 0 then @breakTimeSec else BreakTimeSec end
				where UserId = @UserId and cast(CreatedOn as date) = cast(getdate() as date)

				 set @Detail = (select Id, DailerTimeSec as [DialerTimeSec], TalkTimeSec, IdleTimeSec, AcwTimeSec, BreakTimeSec from tbl_dc_DailyDialerData(nolock)
					where UserId = @UserId and cast(CreatedOn as date) = cast(getdate() as date) for json path, without_array_wrapper)
			end
			else
			begin
				insert into tbl_dc_DailyDialerData(UserId, ParentId, DailerTimeSec, TalkTimeSec, IdleTimeSec, AcwTimeSec, BreakTimeSec)
					values(@UserId, @ParentId, @dialerTimeSec, @talkTimeSec, @idleTimeSec, @acwTimeSec, @breakTimeSec)
				
				declare @dialerDataId bigint = 0;

				set @Detail = (select Id, DailerTimeSec as [DialerTimeSec], TalkTimeSec, IdleTimeSec, AcwTimeSec, BreakTimeSec from tbl_dc_DailyDialerData(nolock)
					where id = @dialerDataId for json path, without_array_wrapper)
				
			end
			select @Status = 1, @Message = 'Data saved successfully';
		end
		
		if(@Mode = 'UPDATE_SCHEDULE')
		begin
			select @scheduleCallId = scheduleCallId, @scheduleDateTime = ScheduleTime
			from openjson(@OperationJSON) with (
				scheduleCallId bigint '$.ScheduleId',
				ScheduleTime datetime '$.ScheduleTime'
			)

			update tbl_dc_ScheduleCall set ScheduleTime = @scheduleDateTime where id = @scheduleCallId
			select @Status = 1, @Message = 'Data saved successfully';
		end

		if(@Mode = 'REMOVE_RECORD')
		begin
			select @scheduleCallId = scheduleCallId 
			from openjson(@OperationJSON) with (
				scheduleCallId bigint '$.ScheduleId'
			)
				
			update tbl_dc_ScheduleCall set IsActive = 0 where id = @scheduleCallId
			select @Status = 1, @Message = 'Data saved successfully';
		end


		if(@Mode = 'MOVE_TO_OTHER_LIST')
		begin
			select @scheduleCallId = scheduleCallId, @LabelName = LabelName
			from openjson(@OperationJSON) with (
				scheduleCallId bigint '$.ScheduleId',
				LabelName nvarchar(25) '$.LabelName'
			)
				
			update tbl_dc_ScheduleCall set labels = @LabelName where id = @scheduleCallId
			select @Status = 1, @Message = 'Data saved successfully';
		end

		if(@Mode = 'NEW_RECORD')
		begin
			select @LabelName = LabelName, @scheduleDateTime = ScheduleTime, @EntityName = EntityName, @EntityId = EntityId, @MobileNo = MobileNo
			from openjson(@OperationJSON) with (
					LabelName nvarchar(25) '$.LabelName',
					ScheduleTime datetime '$.ScheduleTime',
					MobileNo nvarchar(25) '$.MobileNo',
					EntityName nvarchar(25) '$.EntityName',
					EntityId bigint '$.EntityId'
				)

			if(exists(select 1 from tbl_dc_ScheduleCall(nolock) 
				where EntityName = @EntityName and EntityId = @EntityId and is_process = 0))
			begin
				update tbl_dc_ScheduleCall set IsActive = 0
					where EntityName = @EntityName and EntityId = @EntityId and is_process = 0
			end
			
			insert into tbl_dc_ScheduleCall(MobileNo, EntityName, EntityId, ScheduleTime, ParentId, CreatedBy, IsActive, labels)
					select @MobileNo, @EntityName, @EntityId, @scheduleDateTime, @ParentId, @UserId, 1, @LabelName

			select @Status = 1, @Message = 'Data saved successfully';
		end
	end
	else
	begin
		select @Status = 0, @Message = 'OperationJSON blank or not valid';
	end


	select @Status as [Status], @Message as [Message], @Detail as [Detail];
end



GO

