(      
      
  @PipelineID bigint,      
  @DealID bigint  ,    
  @CreatedBy bigint    
    
)      
as      
Begin      
           
  declare @StageID bigint = 0;      
        
  select top 1  @StageID = isnull(ID,0) from PipelineStages where PipelineID = @PipelineID and Name = 'Lost'      
      
  -- update LeadPipelineMapping set PipeLineStage = @StageID where ID = @DealID                       
  declare @lpmid bigint      
  insert into LeadPipelineMapping      
    (      
       [LeadID]      
      ,[PipelineID]      
      ,[PipeLineStage]      
      ,[Probability]      
      ,[Amount]      
      ,[Remarks]      
      ,[CreatedDate]      
      ,[CreatedBy]      
      ,[EstimatedClosureDate]      
      ,[DealOwner]      
      ,[IsDeleted]      
   )      
   Select       
       [LeadID]      
      ,[PipelineID]      
      ,@StageID      
      ,[Probability]      
      ,[Amount]      
      ,[Remarks]      
      ,getdate()      
      ,@CreatedBy      
      ,[EstimatedClosureDate]      
      ,[DealOwner]      
      ,0      
      from   LeadPipelineMapping where ID = @DealID      
      select @lpmid=SCOPE_IDENTITY()    
      update LeadPipelineMapping set IsDeleted = 1 ,deletedon = getdate() where ID = @DealID    
     
        
   begin try  
  
      Declare @LeadIDTemp bigint = 0  
   Declare @ParentID bigint = 0  
     
   select @ParentID = isnull(ParentID,0) from User_Detail where User_ID = @CreatedBy  
   select @LeadIDTemp=isnull(LeadID,0) from LeadPipelineMapping where ID = @DealID  
  
   declare @eventDesc nvarchar(500) =  'Deal moved for pipelinestage id:' + cast(@StageID as nvarchar)  
   exec UspSaveLeadActivity_withid @LeadIDTemp,@Createdby,@ParentID,@eventDesc,'Deal Updated','LeadPipelineMapping',@lpmid   
  
   end try  
   begin catch  
       exec usp_InsertErrorInfo  
   end catch  
  
           
  select 'Stage Updated'         
      
      
       
End 


