/* ============================================================
   Procedure: [dbo].[usp_deductmailcredits_aspermailsize]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_deductmailcredits_aspermailsize
@batchid bigint
as
begin
declare @ispersonalized int=(select ispersonalized from BatchEmail_Infos(nolock) where batchid=@batchid)
declare @credit int--100KB=1 credit
if @ispersonalized=0 and exists(select 1 from campaignmessages where batchid=@batchid)
begin
select @credit=(select ceiling(round(isnull(datalength(messages),(select datalength(mailcontent)  from UserMailTemplate where id=templateid))/cast(100 as float),0)) 
from campaignmessages where batchid=@batchid)
end
else
begin
select @credit=(select top 1 ceiling(round(case when nullif(c.templateid,0) is not null then 
			 (select datalength(mailcontent) from UserMailTemplate where id=c.TemplateID) 
			 else datalength(coalesce(c.Messages,c.Mail_TempleteBody)) end/cast(100 as float),0)) from CloneEmailsFilter (nolock) c 
			 where Mail_BatchID=@batchid)
end
INSERT INTO Mailcreditdetails                                      
                  (ID,                                      
                   -- Credit_ID -- this column value is auto-generated                                      
                   M_ID,                                      
                   FromUser_ID,                                      
                   [User_ID],                                      
                   Debits,                                      
                 Credits,                                      
                 Balance,                                      
                   Validity,                                      
                   Default_Credit,                                      
                   FromDate,                                      
                   ToDate,                                      
                   DateCreated,                                      
                   DateUpdated,                                      
               EmpUpdated,                                      
                   MachineName,                                      
                   LastModified,                          
                   typecredit,    
                   campaignid)                                      
      SELECT top 1 Newid(),                                      
             Ud.M_ID,                                      
             Mail_UserID,                                      
             Mail_UserID,                                      
             count*@credit,                                      
             0,                                      
             (SELECT TOP 1 Mcd.Balance                                      
              FROM   Mailcreditdetails AS Mcd                                      
              WHERE  Mcd.[User_ID] = Mail_UserID                                      
              ORDER  BY Mcd.Credit_ID DESC) - (count*@credit),                                      
             99999,                                      
       '',                                      
             Getdate(),                                      
             Getdate(),                                      
             Getdate(),                                      
             Getdate(),                                      
             '',                                      
             '',                                      
             Getdate(),                             
             '',    
             0                                      
      FROM   cloneemailsfilter c (nolock) join user_detail ud (nolock) on ud.User_ID=c.mail_userid where c.Mail_BatchID=@batchid
	  end


GO

/* ============================================================
   Procedure: [dbo].[usp_DeductRefundBalanceWithOutput]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_DeductRefundBalanceWithOutput]
(
    @parentid           BIGINT,
    @batchId            BIGINT,
    @m_id               BIGINT,
    @cost_in_inr_credit NUMERIC(18,4),
    @cost_in_inr_debit  NUMERIC(18,4),
    @credit_type        INT,
    @remarks            NVARCHAR(1000),
    @intCredId          BIGINT OUTPUT
)
AS
BEGIN
    
    SET NOCOUNT ON;

    DECLARE @intid BIGINT;

    -- Default M_ID if not provided
    SELECT @m_id = COALESCE(@m_id, 10043);

    -- Insert transaction into IntCredit_Details
    INSERT INTO IntCredit_Details
    (
        FromUser_ID,
        M_ID,
        User_ID,
        Debits,
        Credits,
        Balance,
        Validity,
        typecredit,
        Remarks,
        Batchid
    )
    VALUES
    (
        @parentid,
        @m_id,
        @parentid,
        @cost_in_inr_debit,
        @cost_in_inr_credit,
        (dbo.fn_GetMoneyBalance(@parentid) + @cost_in_inr_credit - @cost_in_inr_debit),
        99999,
        @credit_type,
        @remarks,
        @batchId
    );

    -- Capture identity of inserted record
    SELECT @intid = SCOPE_IDENTITY();

    -- Update reserve fund transaction
    EXEC usp_rf_UpdateReserveFundTransaction @CreditId = @intid;

    -- Set output parameter
    SET @intCredId = @intid;
