/* ============================================================
   Procedure: [dbo].[usp_DeductTransformCharges]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_DeductTransformCharges] --32222      
    @UserID BIGINT ,    
 @Previewtext nvarchar(max)=''    
AS      
BEGIN      
    SET NOCOUNT ON;      
      
    BEGIN TRY      
        DECLARE @ROW_COUNT BIGINT,      
                @TotalCostForCreditDetails DECIMAL(18, 4),      
                @ParentID BIGINT,      
                @creditid BIGINT,      
                @M_ID BIGINT,      
                @default_credit DECIMAL(18, 4),      
                @balancecredits DECIMAL(18, 4), @userlogin nvarchar(200) ,  @availbal numeric(18,4),  
                @insertedCreditID INT;      
      
        -- Calculate total cost for credit details      
        SELECT @TotalCostForCreditDetails = ISNULL(BR.Price, 0.00)      
        FROM tbl_AI_PriceMaster BR (NOLOCK)       
        WHERE BR.FeatureTypeId = 1;   
		
		SELECT TOP 1 @M_ID = M_ID ,@ParentID = ParentID,@userlogin=user_login       
        FROM User_Detail WITH (NOLOCK)        
        WHERE User_ID = @UserID;      

      
        SET @balancecredits = dbo.fn_GetMoneyBalance(@ParentID)-- dbo.GetAvailableBalanceForService(@UserID, 12);      
        DECLARE @FinalBalance DECIMAL(18,4) = (@balancecredits - @TotalCostForCreditDetails);      
      
    
      
        SET @creditid = (      
            SELECT MAX(Credit_ID)       
            FROM IntCredit_Details WITH (NOLOCK)       
            WHERE User_ID = @ParentID     
        );      
      
        SELECT @default_credit = MAX(default_credit)       
        FROM IntCredit_Details WITH (NOLOCK)       
        WHERE User_ID = @ParentID       
        AND Credit_ID = @creditid;      
      
        PRINT '@@TotalCostForCreditDetails: ' + CAST(@TotalCostForCreditDetails AS VARCHAR);      
      
        -- Insert into IntCredit_Details table      
        INSERT INTO IntCredit_Details      
        (      
            FromUser_ID, M_ID, User_ID, Debits, Credits, Balance, Validity, Default_Credit, BatchID, ICD_CreatedBy, typecredit, Remarks      
        )      
        VALUES      
        (      
            @ParentID, @M_ID, @ParentID, @TotalCostForCreditDetails, 0, @FinalBalance, 99999, @default_credit, NULL, @UserID, 12,CONCAT(    
        'Amount deducted for using AI rewrite tool by ',     
        @userlogin  
  --,     
        --' for text starting with "',     
        --@Previewtext,     
        --'"'    
    )      
        );      
      
        -- Get the inserted credit ID      
        SET @insertedCreditID = SCOPE_IDENTITY();      
      
        -- Check if the insertion was successful and return the deducted amount      
        IF @insertedCreditID IS NOT NULL      
        BEGIN      
            PRINT 'Deducted Amount: ' + CAST(@TotalCostForCreditDetails AS VARCHAR);      
            SELECT @TotalCostForCreditDetails AS DeductedAmount;      
        END      
        ELSE      
        BEGIN      
            PRINT 'No deduction occurred.';      
            SELECT 0.00 AS DeductedAmount;      
        END      
      
        -- Execute the reserve fund transaction      
         EXEC usp_rf_UpdateReserveFundTransaction @insertedCreditID      
      
    END TRY      
      
    BEGIN CATCH      
        PRINT ERROR_MESSAGE();      
        EXEC Usp_inserterrorinfo;      
    END CATCH          
END 


GO

