as    
declare @r bigint=(select count(1) from [MySMS].[dbo].[ThirtyDaysHistory] where DATEDIFF(d,MessageInsertDate,getdate())>30)
while @r>0
begin
Delete top (1000) c from  [MySMS].[dbo].[ThirtyDaysHistory] c where DATEDIFF(d,MessageInsertDate,getdate())>30
set @r=@r-1000
end


