CREATE   PROCEDURE usp_DeleteChecklistItems  
    @ParentId BIGINT,  
    @StageId BIGINT,  
    @UserId BIGINT  
AS  
BEGIN  
    SET NOCOUNT ON;  
    BEGIN TRY  
        -- Delete Checklist Items based on ParentId, StageId, and UserId  
        DELETE FROM tbl_ChecklistItms  
        WHERE ParentId = @ParentId  
          AND StageId = @StageId  
          AND UserId = @UserId;  
  
        -- Return the number of rows affected  
        SELECT @@ROWCOUNT AS RowsDeleted;  
    END TRY  
    BEGIN CATCH  
       EXEC usp_InsertErrorInfo;  
    END CATCH  
END;


