CREATE   PROCEDURE usp_deleteclientmessages
@batchid bigint,
@processtable int
as
begin
IF (@PROCESSTABLE = 1)   
 BEGIN   
delete p From PROCESSTABLEFIRST p join ClientMobile c on c.mobile=p.mobile WHERE BATCHID = @BATCHID
end
else IF (@PROCESSTABLE = 2)   
 BEGIN   
delete p From PROCESSTABLEtwo p join ClientMobile c on c.mobile=p.mobile WHERE BATCHID = @BATCHID
end
else IF (@PROCESSTABLE = 3)   
 BEGIN   
delete p From ProcessTableThree p join ClientMobile c on c.mobile=p.mobile WHERE BATCHID = @BATCHID
end
else IF (@PROCESSTABLE = 4)   
 BEGIN   
delete p From PROCESSTABLEFour p join ClientMobile c on c.mobile=p.mobile WHERE BATCHID = @BATCHID
end

end


GO

