SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_DeleteContactForApp]                  
@User_ID int,                
@Contact_Mobile varchar(20),                
@Action varchar(20),  
@CountryCode varchar(10)                      
 as                   
 begin                 
 if (@Action='delete')                
  begin      
  if EXISTS (select 'x' from Contact_Detail where User_ID=@User_ID and Contact_Mobile=@Contact_Mobile and CountryCode=@CountryCode)        
  begin             
  DELETE FROM Contact_Detail where User_ID=@User_ID and Contact_Mobile=@Contact_Mobile    
  declare @groupid bigint     
  select @groupid=group_id from Contact_Detail where User_ID=@User_ID and Contact_Mobile=@Contact_Mobile and CountryCode=@CountryCode and group_id !=null       
  if(@groupid!=null)    
       begin    
        DELETE FROM Contact_Detail where User_ID=@User_ID and Contact_Mobile=@Contact_Mobile and CountryCode=@CountryCode and group_id=@groupid    
       end    
        
select 'Record  Deleted Successfully' as Msg       
  end      
  else      
  begin      
  select 'Your Mobile Are Not Exists' as Msg       
  end               
  end         
  end      
      
       
      
      
      
      
      


GO

