/* ============================================================
   Procedure: [dbo].[usp_DeleteDashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_DeleteDashboard (@DashboardId BIGINT)
AS
BEGIN
	IF (@DashboardId > 0)
	BEGIN
		DECLARE @rowJson NVARCHAR(MAX) = (
				SELECT *
				FROM tbl_Dashboard WITH(NOLOCK)
				WHERE DashboardId = @DashboardId
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)
		DECLARE @parentId BIGINT = (
				SELECT ParentId
				FROM tbl_Dashboard
				WHERE DashboardId = @DashboardId
				)

		DELETE
		FROM tbl_DashboardUserMapping
		WHERE DashboardId = @DashboardId

		DELETE
		FROM tbl_DashboardReportMapping
		WHERE DashboardId = @DashboardId

		DELETE
		FROM tbl_Dashboard
		WHERE DashboardId = @DashboardId

		SELECT Msg = 'Dashboard deleted successfully'
			,MsgId = 1
	END
	ELSE
	BEGIN
		SELECT Msg = 'Dashboard deletion unsuccessfull'
			,MsgId = - 1
	END

	IF @RowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @parentId
			,@Activity_type = 'Delt_dsbrd'
			,@ActionType = 'D'
			,@RowJson = @rowJson
			,@Table_name = 'tbl_Dashboard'
	END
END



GO

