/* ============================================================
   Procedure: [dbo].[Usp_DeleteDLTTemplate_ParentIDCheck]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_DeleteDLTTemplate_ParentIDCheck (
	@DLT_TemplateID NVARCHAR(200)
	,@UserID BIGINT
	)
AS
BEGIN
	--delete from DLT_Template where DLT_TemplateID = @DLT_TemplateID    
	--delete from DLT_TemplateSenderMapping where DLT_TemplateID = @DLT_TemplateID    
	DECLARE @ParentID BIGINT = 0

	SELECT @ParentID = Isnull(ParentID, user_id)
	FROM user_detail(NOLOCK)
	WHERE User_ID = @UserID

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserMailTemplate
			WHERE DLT_TemplateID = @DLT_TemplateID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	DELETE
	FROM UserMailTemplate
	WHERE DLT_TemplateID = @DLT_TemplateID
		AND ParentID = @ParentID

	DELETE
	FROM DLT_TemplateSenderMapping
	WHERE DLT_TemplateID = @DLT_TemplateID
		AND CreatedBy = @UserID

	SELECT 'Template Deleted'

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'Delt_dlttmpt'
		,@ActionType = 'D'
		,@RowJson = @rowJson
		,@Table_name = 'UserMailTemplate'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_deleteDuplicateContact]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC [dbo].[usp_deleteDuplicateContact] 
(
    @user_id INT,
    @group_id BIGINT-- frm int 17-08-2010
)          
AS          
BEGIN
	WITH CTE(USER_ID, Contact_Mobile, DuplicateCount) 
	     AS 
	     (
	         SELECT USER_ID,
	                Contact_Mobile,
	                ROW_NUMBER() OVER(PARTITION BY Contact_Mobile ORDER BY Contact_id) AS 
	                DuplicateCount
	         FROM   contact_detail
	         WHERE  USER_ID = @user_id
	     )
	
	DELETE 
	FROM   CTE
	WHERE  DuplicateCount > 1
END  
  
  


GO

