/* ============================================================
   Procedure: [dbo].[Usp_DeleteEnquiryAttribures]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-----------------

CREATE   PROCEDURE [dbo].[Usp_DeleteEnquiryAttribures]  
    @EnquiryID BIGINT  
AS  
BEGIN  
    -- Error handling and transaction management  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Begin transaction  
        BEGIN TRANSACTION;  
  
        -- Delete records from tbl_EnquiryAttribute where ID matches the provided EnquiryID  
        DELETE FROM tbl_EnquiryAttribute  
        WHERE ID = @EnquiryID;  
  
        -- Return a message indicating success  
        SELECT 'Record Deleted' AS ResultMessage;  
  
        -- Commit the transaction  
        COMMIT TRANSACTION;  
    END TRY  
    BEGIN CATCH  
        -- If an error occurs, rollback the transaction  
        ROLLBACK TRANSACTION;  
  
        -- Log the error using the error logging procedure  
        EXEC usp_InsertErrorInfo;  
  
        -- Return the error message  
        SELECT ERROR_MESSAGE() AS ResultMessage;  
  
        -- Throw the error to be caught by the calling method  
        THROW;  
    END CATCH;  
  
    SET NOCOUNT OFF;  
END;  




GO

/* ============================================================
   Procedure: [dbo].[usp_DeleteEnquiryAttributes]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_DeleteEnquiryAttributes  
    @ParentId BIGINT,  
    @StageId BIGINT,  
    @UserId BIGINT  
AS  
BEGIN  
    SET NOCOUNT ON;  
    BEGIN TRY  
        -- Delete Enquiry Attributes based on ParentId, StageId, and UserId  
        DELETE FROM tbl_EnquiryAttribute  
        WHERE ParentId = @ParentId  
          AND StageId = @StageId  
          AND UserId = @UserId;  
  
        -- Return the number of rows affected  
        SELECT @@ROWCOUNT AS RowsDeleted;  
    END TRY  
    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;  
    END CATCH  
END;


GO

