   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_DeleteEnquiryDetails](@EnquiryID BIGINT)  
AS  
BEGIN 
DECLARE @sqlquery NVARCHAR(MAX);
declare @userid bigint =(select CreatedBy from UserEnquiry(nolock) where EnquiryID = @EnquiryID )
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM UserEnquiry WITH(NOLOCK)      
   WHERE EnquiryID = @EnquiryID      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )   
    DELETE FROM UserEnquiry  
    WHERE EnquiryID = @EnquiryID;  
    DELETE FROM customfieldenquiryvalue  
    WHERE EnquiryId = @EnquiryID;  
    SELECT 'Record Deleted';  
	
    DECLARE @exists bigint;
    
    SET @sqlquery = '
        SELECT cast(1 as bigint)
        FROM convusers (NOLOCK) 
WHERE Entity = ''enquiry'' 
    AND Entityid = ' + CAST(@EnquiryID AS NVARCHAR);

EXEC usp_clr_GetRemoteLongValue @sqlquery, @retval = @exists OUT;

    /*IF(EXISTS  
    (  
        SELECT 1  
        FROM MySMSConversations.dbo.convusers(NOLOCK)  
        WHERE Entity = 'enquiry'  
                AND Entityid = @EnquiryID  
    ))  */
	IF (@exists > 0)
        BEGIN  
           /* UPDATE MySMSConversations.dbo.convusers  
                SET   
                    isactive = 0  
            WHERE trim(lower(Entity)) = 'enquiry'  
                    AND Entityid = @EnquiryID;  */
					SET @sqlquery = '
        UPDATE convusers
        SET isactive = 0
        WHERE LTRIM(RTRIM(LOWER(Entity))) = N''enquiry''
          AND Entityid = ' + CAST(@EnquiryID AS NVARCHAR) + '
        ';
        
        EXEC usp_clr_ExecuteRemoteQuery @sqlquery;
    END  
	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @user_id = @userid      
  ,@Activity_type = 'Delt_Enquiry_Details'      
  ,@ActionType = 'D'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'UserEnquiry'  
END  



