/* ============================================================
   Procedure: [dbo].[Usp_DeleteLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_DeleteLeadDetails] --367963  
(
	@ID BIGINT
)
AS
    BEGIN
        DECLARE @LeadNo BIGINT= 0;
        DECLARE @ParentID BIGINT= 0;
		DECLARE @sqlquery NVARCHAR(MAX), @exists bigint;
        SELECT @LeadNo = LeadNo, 
               @ParentID = ParentID
        FROM UserLeads
        WHERE ID = @ID;
        UPDATE UserEnquiry
          SET 
              IsOpen = 1, 
              LeadNo = NULL
        WHERE LeadNo = @LeadNo
              AND ParentID = @ParentID;
        BEGIN TRY
            DECLARE @UserID_LDACTV BIGINT= @ParentID;
            DECLARE @evntMessage NVARCHAR(MAX)= '';
            DECLARE @ParentID_LDACTV BIGINT= @ParentID;
            DECLARE @LeadID_LDACTV BIGINT= @ID;
            CREATE TABLE #tblEventDescrb(EVNT_Description NVARCHAR(MAX));
            IF(ISNULL(@LeadID_LDACTV, 0) > 0)
                BEGIN
                    INSERT INTO #tblEventDescrb
                    EXEC Usp_EventTemplate_DynamicVarReplacement 
                         'Lead Deleted', 
                         @UserID_LDACTV, 
                         '', 
                         '', 
                         @LeadID_LDACTV, 
                         '', 
                         NULL, 
                         0, 
                         0, 
                         '', 
                         '', 
                         0, 
                         '', 
                         0, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         NULL, 
                         0, 
                         0, 
                         0, 
                         NULL, 
                         NULL, 
                         NULL, 
                         0, 
                         NULL, 
                         NULL, 
                         NULL, 
                         0, 
                         NULL, 
                         NULL;
                    SELECT @evntMessage = ISNULL(EVNT_Description, '')
                    FROM #tblEventDescrb;

                    --select @evntMessage  

                    IF(@evntMessage <> '')
                        BEGIN
                            EXEC UspSaveLeadActivity_withid 
                                 @LeadID_LDACTV, 
                                 @UserID_LDACTV, 
                                 @ParentID_LDACTV, 
                                 @evntMessage, 
                                 'Lead Deleted', 
                                 'Userleads', 
                                 @id;
                    END;
            END;
        END TRY
        BEGIN CATCH
            EXEC usp_InsertErrorInfo;
        END CATCH;
        IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence    
            BEGIN
                DROP TABLE #tblEventDescrb;
        END;
        DELETE FROM UserLeads
        WHERE ID = @ID;
        DELETE FROM customfieldLeadvalue
        WHERE LeadId = @ID;
        IF(@LeadNo <> 0
           AND @ParentID <> 0)
            BEGIN
                DELETE FROM LeadInteractionHistory
                WHERE LeadNo = @LeadNo
                      AND ParentID = @ParentID;
        END;
       /* IF(EXISTS
        (
            SELECT 1
            FROM MySMSConversations.dbo.convusers(NOLOCK)
            WHERE trim(lower(Entity)) = 'lead'
                  AND Entityid = @ID
        ))*/
		SET @sqlquery = '
            
                SELECT cast(1 as bigint)
               FROM convusers (NOLOCK) 
WHERE TRIM(LOWER(Entity)) = ''lead'' 
AND EntityId = ' + CAST(@ID AS NVARCHAR);
            
            EXEC usp_clr_GetRemoteLongValue @sqlquery, @retval = @exists OUT;
			IF (@exists >0)
            BEGIN
               /* UPDATE MySMSConversations.dbo.convusers
                  SET 
                      isactive = 0
                WHERE trim(lower(Entity)) = 'lead'
                      AND Entityid = @ID;*/
					  SET @sqlquery = '
              UPDATE convusers
              SET isactive = 0
              WHERE LTRIM(RTRIM(LOWER(Entity))) = N''lead''
                AND Entityid = ' + CAST(@ID AS NVARCHAR) + '
          ';
          
          EXEC usp_clr_ExecuteRemoteQuery @sqlquery;
        END;
        SELECT 'Record Deleted';
    END; 


GO

