/* ============================================================
   Procedure: [dbo].[usp_DeletePaymentGateway]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




CREATE   PROCEDURE [dbo].[usp_DeletePaymentGateway]  
 @ID BIGINT  
AS  
BEGIN  
 DECLARE @IdNew BIGINT = (  
             SELECT TOP 1 upg.ID  
             FROM   UserPaymentGateway AS upg  
             WHERE  upg.ParentID IN (SELECT upg2.ParentID  
                                     FROM   UserPaymentGateway AS upg2  
                                     WHERE  upg2.ID = @ID)  
                    AND upg.ID <> @ID  
             ORDER BY  
                    upg.CreatedOn DESC  
         )  
   
 IF EXISTS (  
        SELECT upg2.ParentID  
        FROM   UserPaymentGateway AS upg2  
        WHERE  upg2.ID = @ID  
               AND upg2.IsDefault = 1  
    )  
 BEGIN  
     UPDATE UserPaymentGateway  
     SET    IsDefault     = 1  
     WHERE  ID            = @IdNew  
 END  
   
 IF NOT EXISTS (  
        SELECT 1  
        FROM   UserPaymentGateway AS upg  
        WHERE  upg.ParentID IN (SELECT upg2.ParentID  
                                FROM   UserPaymentGateway AS upg2  
                                WHERE  upg2.ID = @ID)  
        HAVING COUNT(*) = 1  
    )  
 BEGIN  
     DELETE   
     FROM   UserPaymentGateway  
     WHERE  ID = @ID  
       
     SELECT 'Success'  
 END  
 ELSE  
 BEGIN  
     SELECT 'Cannot Delete Last Entry'  
 END  
END  



GO

/* ============================================================
   Procedure: [dbo].[Usp_DeleteProduct]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_DeleteProduct (
	@ProductID BIGINT
	,@UserID BIGINT
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0;
	DECLARE @sqls NVARCHAR(max) = ''
		,@status INT
		,@tableName NVARCHAR(max) = ''

	EXEC @status = Usp_CreateProductTableByParentID @UserID
		,@tableName OUTPUT

	DECLARE @rowJson NVARCHAR(MAX) = 'Select @rowJson =(SELECT * FROM ' + @tableName + ' WHERE ProductId=' + cast(@ProductID AS VARCHAR) + '
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)'

	EXECUTE sp_executesql @rowJson
		,N'@rowJson Varchar(max) OUTPUT'
		,@rowJson OUTPUT

	DELETE
	FROM EntityTagMapping
	WHERE EntityID = @ProductID
		AND Entity = 'Product'

	DELETE
	FROM ProductImageMapping
	WHERE ProductID = @ProductID

	SET @sqls = 'delete from ' + @tableName + ' where ProductID = ' + cast(@ProductID AS VARCHAR)

	EXECUTE sp_executesql @sqls

	SELECT 'Data Deleted' AS msg

	--PRINT @rowJson
	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
			,@Activity_type = 'Delt_Prdct'
			,@ActionType = 'D'
			,@RowJson = @rowJson
			,@Table_name = @tableName
	END
END



