/* ============================================================
   Procedure: [dbo].[usp_DeleteScheduleById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_DeleteScheduleById]    
    @UserId BIGINT = NULL,    
    @ScheduleId BIGINT = NULL    
AS    
BEGIN    
    DECLARE @ResultMessage NVARCHAR(100);  -- Declare a variable for the result message  
  
    BEGIN TRY    
        -- Begin transaction if required for data consistency    
        BEGIN TRANSACTION;    
  
        -- Update statement to deactivate the schedule  
        UPDATE [schedules]   
        SET is_active = 0    
        WHERE     
            (TRY_CAST(parentid AS BIGINT) = @UserId)    
            AND (id = @ScheduleId OR @ScheduleId IS NULL OR @ScheduleId = '');  
  
        -- Check if any rows were affected  
        IF @@ROWCOUNT > 0  
        BEGIN  
            SET @ResultMessage = 'Record Deleted';  
        END  
        ELSE  
        BEGIN  
            SET @ResultMessage = 'No schedule found or already inactive.';  
        END  
  
        COMMIT TRANSACTION;     
  
        -- Return the success message  
        SELECT @ResultMessage AS Message;    
    END TRY    
    BEGIN CATCH    
        -- Rollback the transaction in case of an error    
        IF @@TRANCOUNT > 0    
        BEGIN    
            ROLLBACK TRANSACTION;    
        END    
  
        -- Handle the error and return error information  
        SELECT   
            ERROR_MESSAGE() AS ErrorMessage,  
            ERROR_LINE() AS ErrorLine,  
            ERROR_PROCEDURE() AS ErrorProcedure;  
          
        -- Optionally log the error  
        EXEC usp_InsertErrorInfo;    
    END CATCH    
END  

----------------------------------


GO

/* ============================================================
   Procedure: [dbo].[usp_deletescheduledmails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_deletescheduledmails --81418844
	@batchid BIGINT
AS
BEGIN
	BEGIN TRY
		DECLARE @count INT = (
				SELECT CASE 
						WHEN isnull(creditsused, 0) = 0
							THEN isnull(totalrecords, 0)
						ELSE creditsused
						END
				FROM BatchEmail_Infos(NOLOCK)
				WHERE isbatchdeleted = 0
					AND batchid = @batchid
				)
			,@parentsuperresellerid BIGINT
			,@USERID BIGINT

		IF @count IS NOT NULL
		BEGIN
			DECLARE @tablename NVARCHAR(50) = (
					SELECT tablename
					FROM BatchEmail_Infos(NOLOCK)
					WHERE batchid = @batchid
					)

			SET @USERID = (
					SELECT userid
					FROM BatchEmail_Infos(NOLOCK)
					WHERE batchid = @batchid
					)

			IF OBJECT_ID('' + @tablename + '') IS NOT NULL
			BEGIN
				DECLARE @dropquery NVARCHAR(max) = 'drop table ' + @tablename + ''

				EXEC (@dropquery)

				INSERT INTO Mailcreditdetails (
					ID
					,
					-- Credit_ID -- this column value is auto-generated                                        
					M_ID
					,FromUser_ID
					,[User_ID]
					,Debits
					,Credits
					,Balance
					,Validity
					,Default_Credit
					,FromDate
					,ToDate
					,DateCreated
					,DateUpdated
					,EmpUpdated
					,MachineName
					,LastModified
					,typecredit
					,campaignid
					)
				SELECT Newid()
					,Ud.M_ID
					,UserID
					,UserID
					,0
					,@count
					,(
						SELECT TOP 1 Mcd.Balance
						FROM Mailcreditdetails AS Mcd
						WHERE Mcd.[User_ID] = UserID
						ORDER BY Mcd.Credit_ID DESC
						) + @count
					,99999
					,''
					,Getdate()
					,Getdate()
					,Getdate()
					,Getdate()
					,''
					,''
					,Getdate()
					,''
					,0
				FROM BatchEmail_Infos c(NOLOCK)
				JOIN user_detail ud(NOLOCK) ON ud.User_ID = c.userid
				WHERE BatchID = @batchid

				SELECT @parentsuperresellerid = parentsuperresellerid
				FROM user_detail(NOLOCK)
				WHERE USER_ID = @USERID
					AND HasVirtualCredits = 1

				IF @parentsuperresellerid IS NOT NULL
					AND @parentsuperresellerid <> 335
				BEGIN
					INSERT INTO SuperresellerMailcreditdetails (
						ID
						,
						-- Credit_ID -- this column value is auto-generated                                        
						M_ID
						,FromUser_ID
						,[User_ID]
						,Debits
						,Credits
						,Balance
						,Validity
						,Default_Credit
						,FromDate
						,ToDate
						,DateCreated
						,DateUpdated
						,EmpUpdated
						,MachineName
						,LastModified
						,typecredit
						,campaignid
						)
					SELECT Newid()
						,Ud.M_ID
						,@ParentSuperResellerId
						,@ParentSuperResellerId
						,0
						,@count
						,(
							SELECT TOP 1 Mcd.Balance
							FROM SuperResellerMailCreditDetails AS Mcd(NOLOCK)
							WHERE Mcd.[User_ID] = @ParentSuperResellerId
							ORDER BY Mcd.Credit_ID DESC
							) + @count
						,99999
						,''
						,Getdate()
						,Getdate()
						,Getdate()
						,Getdate()
						,''
						,''
						,Getdate()
						,''
						,0
					FROM BatchEmail_Infos c(NOLOCK)
					JOIN user_detail ud(NOLOCK) ON ud.User_ID = @parentsuperresellerid
				END
			END
		END

		UPDATE BatchEmail_Infos
		SET isbatchdeleted = 1
		WHERE BatchID = @batchid

		SELECT 'Record Deleted'

		DECLARE @rowJson NVARCHAR(MAX) = (
				SELECT *
				FROM BatchEmail_Infos
				WHERE BatchID = @BatchID
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		IF @rowJson IS NOT NULL
		BEGIN
			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @USERID
				,@Activity_type = 'Delt_SchMail_rpt'
				,@ActionType = 'U'
				,@RowJson = @rowJson
				,@Table_name = 'BatchEmail_Infos'
		END
	END TRY

	BEGIN CATCH
		EXEC usp_InsertErrorInfo
	END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_DeleteScheduledMessages]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROC [dbo].[usp_DeleteScheduledMessages]              
(              
@batchid bigint          
)            
as          
begin    
Declare @totalCredit int,@user_id bigint                  
select @user_id=(select userid from batchinfo(nolock) where batchid=@batchid)    
Declare @ParentID bigint = (select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @user_id )

if exists(select debits from Credit_Details(nolock) where batchid=@batchid)    
begin    
select @totalCredit= debits from Credit_Details(nolock) where batchid=@batchid                
end    
else    
begin     
select *,len(message) as Length,case when (isunicode=0 and len(message)<=160) or (isunicode=1 and len(message)<=70) then 1 when isunicode=0 and len(message)>160    
then ceiling(len(message)/cast(153 as float)) else ceiling(len(message)/cast(67 as float)) end as CreditsUsed into #temp from CloneMessageDeliveryStatus(nolock)    
set @totalCredit= isnull((select sum(creditsused) from #temp),0)    
end    
    
declare @BalanceMsg bigint,@creditid bigint,@FinalBalance bigint,@UsageMessage int,@debit bigint ,@finaldebit bigint                                               
set @creditid=(select max(Credit_ID) from Credit_Details with(nolock) where User_ID=@ParentID)                                                
set @BalanceMsg=(select max(Balance) from Credit_Details with(nolock) where User_ID=@ParentID and Credit_ID=@creditid)                  
set @debit=(select max(Debits) from Credit_Details with(nolock)  where  User_ID=@ParentID and Credit_ID=@creditid)                                                                              
--set @UsageMessage=(@MsgCount*@NoOfPeople)                                      
--set @FinalBalance=(@BalanceMsg-@MsgCount)                                                
set @FinalBalance=(@BalanceMsg+@totalCredit)                
set @finaldebit=(@debit-@totalCredit)                                      
  
  
--insert into Credit_Details(ID,Credit_ID,M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,MachineName,LastModified,    
--typecredit,batchid,CreatedBy)    
--select ID,Credit_ID,M_ID,User_ID,User_ID,0,@totalCredit,@FinalBalance,Validity,Default_Credit,FromDate,ToDate,getdate(),getdate(),EmpUpdated,MachineName,getdate(),    
--typecredit,@batchid,@User_ID from Credit_Details(nolock) where credit_id=@creditid    
    
  
  insert into Credit_Details(M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,MachineName,LastModified,    
typecredit,batchid,CreatedBy,CD_CreatedBy)    
select M_ID,User_ID,User_ID,0,@totalCredit,@FinalBalance,Validity,Default_Credit,FromDate,ToDate,getdate(),getdate(),EmpUpdated,MachineName,getdate(),    
typecredit,@batchid,@User_ID,@user_id from Credit_Details(nolock) where credit_id=@creditid    
  
  
  
--delete from batchinfo where userid=@User_ID and batchid=@batchid    
delete from CloneMessageDeliveryStatus where BATCHID=@batchid     
end    
    
    


GO

