/* ============================================================
   Procedure: [dbo].[USP_DeleteTop_ButtomFiveInQue_Cond3]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
/****************************************************************************        
SP_Name        : USP_DeleteTop_ButtomFiveInQue_Cond3                           
Author         : Pawan        
Created ON     : 14/01/2010 04:30 PM              
Version        : 1        
Alter BY       :                
Alter Date    :         
Location       :          
SP Description : This SP is Used to Delete Top AND Buttom Five FROM QUEUE         
     Table                
****************************************************************************/          
CREATE   PROC [dbo].[USP_DeleteTop_ButtomFiveInQue_Cond3]          
@BatchID BIGINT,  -- frm int to big int 19-08-2010  
@ProcessTable TINYINT          
AS          
BEGIN          
   IF (@ProcessTable = 1)          
   BEGIN          
     WITH CTETemp          
     AS          
     (          
          
    SELECT ProcessID ,ROW_NUMBER() OVER (ORDER BY ProcessID) AS TopFive,ROW_NUMBER() OVER (ORDER BY ProcessID Desc) AS BottomFive          
    FROM   ProcessTableFirst          
    WHERE BatchID = @BatchID AND  Operator <> 'AD'       
   )          
            
   DELETE FROM ProcessTableFirst          
   WHERE ProcessID IN ( SELECT ProcessID FROM CTETemp WHERE TopFive <= 3 or BottomFive <= 2)            
   END          
   ELSE IF (@ProcessTable = 2)          
   BEGIN          
     WITH CTETemp          
     AS          
     (          
  SELECT ProcessID ,ROW_NUMBER() OVER (ORDER BY ProcessID) AS TopFive,ROW_NUMBER() OVER (ORDER BY ProcessID Desc) AS BottomFive          
  FROM   ProcessTableTwo          
  WHERE BatchID = @BatchID AND  Operator <> 'AD'      
     )          
            
     DELETE FROM ProcessTableTwo          
     WHERE ProcessID IN ( SELECT ProcessID FROM CTETemp WHERE TopFive <= 3 or BottomFive <= 2)            
     END          
  ELSE IF (@ProcessTable = 3)          
  BEGIN          
   WITH CTETemp          
  AS          
  (          
   SELECT ProcessID ,ROW_NUMBER() OVER (ORDER BY ProcessID) AS TopFive,ROW_NUMBER() OVER (ORDER BY ProcessID Desc) AS BottomFive          
   FROM   ProcessTableThree          
   WHERE BatchID = @BatchID AND Operator <> 'AD'        
        )          
            
   DELETE FROM ProcessTableThree          
      WHERE ProcessID IN ( SELECT ProcessID FROM CTETemp WHERE TopFive <= 3 or BottomFive <= 2)            
      END          
      ELSE IF (@ProcessTable = 4)          
      BEGIN          
      WITH CTETemp          
      AS          
      (          
         SELECT ProcessID ,ROW_NUMBER() OVER (ORDER BY ProcessID) AS TopFive,ROW_NUMBER() OVER (ORDER BY ProcessID Desc) AS BottomFive          
         FROM   ProcessTableFour          
         WHERE BatchID = @BatchID AND Operator <> 'AD'        
      )          
            
      DELETE FROM ProcessTableFour          
      WHERE ProcessID IN ( SELECT ProcessID FROM CTETemp WHERE TopFive <= 3 or BottomFive <= 2)            
      END            
END   
  


GO

