/* ============================================================
   Procedure: [dbo].[usp_DeleteUserMailTemplate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_DeleteUserMailTemplate]  
 @ID BIGINT  
AS  
BEGIN  

   DECLARE @TemplateID BIGINT = @ID
 
SELECT DISTINCT ugtm.GroupID INTO     #TempGroup
FROM   UserGroupTemplateMix        AS ugtm
WHERE  ugtm.TemplateID = @TemplateID
 
 
SELECT ugtm.ID,
       ugtm.ParentID,
       ugtm.GroupID,
       ugtm.TemplateID,
       ugtm.IsActivated,
       ugtm.OrderNo INTO        #tempInsertGroup
FROM   UserGroupTemplateMix  AS ugtm
WHERE  ugtm.GroupID IN (SELECT GroupID
                        FROM   #TempGroup)
       AND ugtm.TemplateID <> @TemplateID
ORDER BY
       ugtm.GroupID,
       ugtm.OrderNo
 
DELETE 
FROM   UserGroupTemplateMix
WHERE  GroupID IN (SELECT tt.GroupID
                   FROM   #tempInsertGroup tt)
 
INSERT INTO UserGroupTemplateMix
  (
    -- ID -- this column value is auto-generated
    ParentID,
    GroupID,
    TemplateID,
    OrderNo,
    CreatedOn,
    IsActivated
  )
SELECT tt.ParentID,
       tt.GroupID,
       tt.TemplateID,
       ROW_NUMBER() OVER(
           PARTITION BY groupid ORDER BY groupid,
           TEMPLATEID,
           orderno ASC
       ),
       GETDATE(),
       tt.IsActivated
FROM   #tempInsertGroup tt
        
 
 DROP TABLE #TempGroup
 
 DROP TABLE #tempInsertGroup


 DELETE   
 FROM   UserMailTemplate  
 WHERE  ID = @ID  
 
 update UserCampaignMaster set IsActive = 0 where TemplateID=@ID
 
 SELECT 'Success'  


END



GO

