/* ============================================================
   Procedure: [dbo].[Usp_DiscountCalculation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[Usp_DiscountCalculation]  --24795,'Promotional',10,'asa'
@userID nvarchar(50),
@PlanName nvarchar(50),
@Quantity nvarchar(50),
@CouponCode nvarchar(100)
as
begin

 IF NOT EXISTS(SELECT * FROM CustomerCouponDetails WHERE UserId=@userID AND status = 1 and CouponCode=@CouponCode)
    BEGIN
select discount from M_Coupon m left join CustomerCouponDetails c on m.CouponCode=c.CouponCode where c.CouponCode=@CouponCode and m.Route=@PlanName and m.status=1 and (@Quantity BETWEEN m.MinVolume AND m.MaxVolume) and UserId=@userID
end

else
begin
select 'Used'
end

End



GO

