/* ============================================================
   Procedure: [dbo].[USP_DISPLAYDELIVERYREPORT1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
--        
-- select * from  dbo.TBL_VoiceSmsDetails        
CREATE   PROC [dbo].[USP_DISPLAYDELIVERYREPORT1] -- '316','','','','9/08/2009','09/08/2009'           
(            
@UID int,    -- frm varchr 19-08-2010  
@Number varchar(10),        
@FileName varchar(50),        
@Status varchar(20),        
@FromDate varchar(20),        
@ToDate varchar(20)        
)           
as         
        
if @Status='PENDING'        
   begin        
   set @Status='0'        
   end        
else if @Status='APPROVEd'        
   begin        
   set @Status='1'        
   end        
else if @Status='QUEUE'        
   begin        
   set @Status='2'        
   end        
else if @Status='BROADCAST'        
   begin        
   set @Status='3'        
   end        
   else        
   begin        
     set @Status=''        
   end        
Declare @Sql varchar(MAX)                                                                          
Declare @whereClause varchar(max)                           
set @whereClause=''          
--added by vinay to search                
     If @Number=''                                                                            
    Begin                            
    Set @whereClause =@Number +  '1=1 and '                                                                            
    End                                                                            
    Else                                                                            
    Begin                        
    Set @whereClause = @whereClause+ ' MobilesNumber like ''%'+@Number+'%''  and '                                                                            
    End                  
                                          
    If @FileName=''                                                                            
    Begin                            
    Set @whereClause =@whereClause+'1=1 and '                                                                            
    End                                                                            
    Else                                                                            
    Begin                              
    Set @whereClause = @whereClause+ ' FileName like ''%'+@FileName+'%''  and '                                                                            
    End                                       
                       
    If @Status = ''                                                                           
    Begin                            
    Set @whereClause =@whereClause+'1=1 and '                                                                            
    End                                                                            
    Else                                                                            
    Begin            
    Set @whereClause = @whereClause+ ' Status = '''+@Status+''' and '          
    End        
    If (@FromDate !='' and @ToDate !='')                                              
    Begin                                               
    Set @whereClause = @whereClause+ '(convert(nvarchar,convert(datetime,UploadedAt,104),112) between convert(nvarchar,convert(datetime,'''+@FromDate+''',104),112) and convert(nvarchar,convert(datetime ,'''+@ToDate +''',104),112)) '                       
  
  
    
   End                                              
     Else                                              
     Begin                                              
       Set @whereClause =@whereClause +  ' 1=1 '                                              
     End                                   
SET NOCOUNT ON            
set @Sql= 'SELECT MobilesNumber,FileName,UploadedAt,CASE Status WHEN 0 THEN ''PENDING''            
WHEN 1 THEN ''APPROVED'' WHEN 2 THEN ''QUEUE'' WHEN 3 THEN ''BROADCAST'' END AS STATUS            
FROM TBL_VoiceSmsDetails WHERE   U_ID='+CONVERT(VARCHAR,@UID,20)+' and '+@whereClause+''          
exec(@Sql)        
        
        
--sp_helptext USP_DISPLAYDELIVERYREPORT1   
  


GO

/* ============================================================
   Procedure: [dbo].[Usp_DisplayNotificationSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_DisplayNotificationSettings --335    
(    
  @UserID bigint      
)    
as    
Begin    
      Declare @ParentID bigint = 0    
   Select top 1  @ParentID = ISNULL(Parentid,User_ID) from User_Detail(nolock) where User_ID = @UserID      
       
   select ID as EventID,isnull(EventName,'') as EventName, '' as Mode , '0' as Status, '' as Recipient from ActivityMaster(nolock) as AM  where (context = 'Lead' or context = 'Enquiry')          
     and Am.ID not in (  select NM.activityid from adminnotificationsettings(nolock) as ADM    
                         join notificationsmaster(nolock) as NM on ADM.notificationid = NM.id    
           where parentid = @ParentID    
              )    
        
     
   --declare @jsnData nvarchar(max) = ''   
  
   --set @jsnData =   
   --(  
  
   select NM.activityid as EventID, ISNULL(am.EventName,'') as EventName,   
 STUFF((  
  
SELECT ',' + CAST(innerTable.mode AS nvarchar(100))  
  
FROM notificationmodes(nolock) AS innerTable  
  
WHERE innerTable.id = nm.modeid  
  
FOR XML PATH('')  
  
),1,1,'') AS Mode, isnull(ADN.isactive,0) as Status,  
    
   STUFF((  
  
  SELECT ',' + CAST(SRole.rolename AS nvarchar(100))  
  
  FROM systemroles(nolock) AS SRole  
  
  WHERE SRole.id = NM.roleid  
  
  FOR XML PATH('')  
  
  ),1,1,'') AS Recipient  
    
    
  from ActivityMaster(nolock) as AM   
  join  adminnotificationsettings(nolock) as ADN  
  on  AM.ID = adn.ans_eventid  
     join notificationsmaster(nolock) as NM  on adn.notificationid = nm.id    
  --join ActivityMaster(nolock) as AM on Nm.activityid = AM.ID  
  
    
  where ADN.parentid = 33819 --and Am.ID = 3  
  --FOR JSON PATH  
    
  --group by NM.activityid,am.EventName,Nm.modeid,adn.isactive--,nm.roleid  
  --)  
   
