 SELECT TOP 1 @ParentID = ISNULL(Parentid, User_ID)      
 FROM User_Detail(NOLOCK)      
 WHERE User_ID = @UserID      
      

 ;WITH Notification_data AS 
 (      
  SELECT  am.ID AS EventID      
   ,isnull(EventName, '') AS EventName  
   ,am.context AS RelatedTo
   ,'' AS Mode      
   ,'' AS Recipient      
   ,'0' AS STATUS      
   ,'0' AS EntryStatus      
   ,'second' AS TimeUnit      
   ,'0' AS TimeBeforeEvent      
  FROM ActivityMaster(NOLOCK) AS AM      
  WHERE (      
    context = 'Lead'      
    OR context = 'Enquiry'      
    or context='user'      
    )      
   --AND Am.ID NOT IN (      
   -- SELECT NM.activityid      
