   -- WHERE parentid = @ParentID      
   -- )      
   AND AM.ID NOT IN (      
    SELECT NM.activityid      
    FROM adminnotificationsettings(NOLOCK) AS ADM      
    JOIN notificationsmaster(NOLOCK) AS NM ON ADM.notificationid = NM.id      
    WHERE parentid = @ParentID and adm.isactive = 1     
    )  
  UNION 
  SELECT DISTINCT  am.ID AS EventID      
   ,EventName  
   ,am.context AS RelatedTo
   ,dbo.fn_getroles(ans_eventid, a.parentid, 'mode') AS Mode      
   ,dbo.fn_getroles(ans_eventid, a.parentid, 'role') AS Recipient      
   ,a.isactive AS STATUS      
   ,'1' AS EntryStatus      
   ,a.TimeUnit      
   ,abs(isnull(a.TimeBeforeEvent,0)) as TimeBeforeEvent    
  FROM adminnotificationsettings(NOLOCK) a      
  JOIN notificationsmaster n ON a.notificationid = n.id      
  JOIN systemroles m ON m.id = n.roleid      
  JOIN activitymaster(NOLOCK) am ON am.id = a.ans_eventid      
  WHERE a.parentid = @ParentID  
  )

