 where   (CASE WHEN  @P_ACTIVE < 2 THEN  STATUS ELSE 1 END) = ( CASE WHEN   @P_ACTIVE < 2 THEN @P_ACTIVE ELSE 1 END)	
    AND 
( (CASE WHEN COALESCE(@P_SEARCH_VAL,'') != '' THEN COALESCE(EVENTNAME,'')  ELSE '1'  END) LIKE (CASE WHEN COALESCE(@P_SEARCH_VAL,'') != '' THEN '%'+ COALESCE(@P_SEARCH_VAL,'')+'%' ELSE '1'  END)
  OR   (CASE WHEN COALESCE(@P_SEARCH_VAL,'') != '' THEN COALESCE(RelatedTo,'')  ELSE '1'  END) LIKE (CASE WHEN COALESCE(@P_SEARCH_VAL,'') != '' THEN '%'+ COALESCE(@P_SEARCH_VAL,'')+'%' ELSE '1'  END))


 SELECT @TOT_COUNT = COUNT(EVENTID) FROM #TMP_NOTIFICATION

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY EVENTID)[ROW_NUM] ,@TOT_COUNT [TOT_COUNT],@W_PAGE_SIZE as PAGE_SIZE, EVENTID,  EVENTNAME,RELATEDTO,MODE,RECIPIENT,[STATUS], ENTRYSTATUS, TIMEUNIT,TIMEBEFOREEVENT
 FROM  #TMP_NOTIFICATION 
 GROUP BY  EVENTID,  EVENTNAME,RELATEDTO,MODE,RECIPIENT,[STATUS], ENTRYSTATUS, TIMEUNIT,TIMEBEFOREEVENT
