CREATE   PROCEDURE [dbo].[Usp_DisplayTimeTriggeredCampaigns] --42185--34594--39680                  
(
	@UserID BIGINT,
	@CampName VARCHAR(max) = NULL,	
	@status CHAR(1) = NULL,
	@FromDate NVARCHAR(max) = NULL,
	@ToDate NVARCHAR(max) = NULL,
	@CampaignStatus VARCHAR(max) = NULL
)
AS
BEGIN
	--DECLARE	
	--	@UserID BIGINT = 34594,
	--	@CampName VARCHAR(max) = NULL,
	--	@status CHAR(1) = NULL


	DECLARE @ParentID BIGINT = 0

	SELECT TOP 1 @ParentID = isnull(ParentID, User_ID)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID

	 DROP TABLE IF EXISTS #temp;
    CREATE TABLE #temp (Reached BIGINT, ruleid BIGINT, LastRun  datetime,isprocessed int );

DECLARE @query NVARCHAR(MAX);
SET @query = '
    SELECT 
        ruleid,
        COUNT(DISTINCT activityid) AS Reached,
        MAX(processedat) AS LastRun
    FROM tbl_wa_automationtasks (NOLOCK)
    WHERE activityid IS NOT NULL AND ISNULL(isprocessed, 0) <> 0
    GROUP BY ruleid;';

    -- Execute the query using your CLR procedure
    INSERT INTO #temp(ruleid, Reached, LastRun)
    EXEC usp_clr_FillRemoteData @query;

	/*SELECT *
	FROM (
		SELECT TGC.id
			,cname
			--,eventid
			--,AM.EventName
			,TGC.parentid
			,TGC.isactive
			,cast(TGC.createdon AS NVARCHAR(100)) AS createdon
			,TGC.createdby
			,isnull(smscampaignid, 0) AS smscampaignid
			,isnull(mailcampaignid, 0) AS mailcampaignid
			,isnull(voicecampaignid, 0) AS voicecampaignid
			,isnull(whatsappcampaignid, 0) AS whatsappcampaignid
			,Audience
			,TGC.ExcludeAudience
			,TGC.Schedule
			,CASE 
				WHEN cast(tgc.Audience AS NVARCHAR) <> '0'
					THEN STUFF((
								SELECT ', ' + t2.CriteriaName
								FROM tbl_SearchCriteria(NOLOCK) t2
								WHERE t2.ID IN (
										SELECT value
										FROM fn_Split(TGC.Audience, '#')
										)
								FOR XML PATH('')
								), 1, 2, '')
				--ELSE CASE 
				--		--WHEN Am.context = 'Lead'
				--		--	THEN 'All Leads'
				--		--ELSE 'All Enquiries'
				--		END
				END AS AudienceCollection
			,0 AS AudienceDefaultID
			--,dbo.func_ToGetTotalReached(isnull(smscampaignid, 0), isnull(mailcampaignid, 0), isnull(voicecampaignid, 0), isnull(whatsappcampaignid, 0))  
			--,dbo.func_ToGetTotalReached_includingsequence(tgc.id) AS TotalReached
			,isnull(t.reached,0)+isnull(wat.reached,0) as TotalReached
			--  ,cast(isnull(dbo.funcToGetLastRun_New(Cast(isnull(smscampaignid, 0) AS NVARCHAR) + '#' + CAST(isnull(mailcampaignid, 0) AS NVARCHAR) + '#' + CAST(isnull(voicecampaignid, 0) AS NVARCHAR) + '#' + cast(isnull(whatsappcampaignid, 0) AS NVARCHAR)), 'Never')  
			--AS NVARCHAR(200)) AS LastRun   
			--,cast(isnull(dbo.funcToGetLastRun_New_includingsequence(tgc.id), 'Never') AS NVARCHAR(200)) AS LastRun
			--,dbo.fn_max_date(t.reached,wat.reached) as LastRun
			,isnull(cast(case when t.LastRun is not null and wat.LastRun is not null and t.LastRun>wat.LastRun then t.LastRun
			when t.LastRun is not null and wat.LastRun is not null and t.LastRun<=wat.LastRun then wat.LastRun
			when t.LastRun is not null and wat.LastRun is null then t.LastRun
			when t.LastRun is null and wat.LastRun is not null then wat.LastRun
			else null end as nvarchar(50)),'Never') as LastRun
			--,Am.context
			,CASE 
				WHEN tgc.sequenceid != ''
					THEN 'sequenceDark-icon.png'
				ELSE 'sequenceLight-icon.png'
				END sequenceidicon
			,isnull(tgc.sequenceid, 0) sequenceid
			,isnull(tgc.issequenceactive, 0) issequenceactive
			,(
				SELECT COunt(cond.id)
				FROM triggeredcampaignrules rules
				JOIN [triggeredcampaignruleconditions] cond ON rules.id = cond.ruleid
				WHERE rules.triggeredcampaignid = TGC.id
				) RuleCount,
				dbo.GetCountBasedOnCondition(TGC.id) as [ExecutionCount]   
			,isnull(Trule.id, 0) ruleid
		FROM triggeredcampaigns(NOLOCK) AS TGC
		--JOIN activityMaster(NOLOCK) AS AM ON TGC.eventid = AM.ID
		LEFT JOIN triggeredcampaignrules AS Trule ON Trule.triggeredcampaignid = TGC.id
		left join

		(select t.id,sum(t.Reached) Reached,max(t.LastRun) as LastRun from
		
		( select tgc.id,c.campaignid,count(1) Reached,max(c.ExecutionTime) LastRun  from UserCampaignExecutionHistory(nolock) 
		as c join triggeredcampaigns tgc (nolock) on c.campaignid in (tgc.smscampaignid,tgc.mailcampaignid,tgc.voicecampaignid,tgc.whatsappcampaignid)
		group by campaignid,tgc.id) t group by t.id ) as t on t.id=tgc.id
        left join
		(select ruleid,count(distinct activityid) Reached,max(processedat) LastRun from MySMSConversations.dbo.tbl_wa_automationtasks(nolock) where activityid  
         is not null and isnull(isprocessed,0) <>0 group by ruleid) as WAT on WAT.ruleid=tgc.id
		WHERE TGC.parentid = @ParentID
			
		) AS tbl
	WHERE (
			@CampName IS NULL
			OR tbl.cname LIKE '%' + @CampName + '%'
			)
		AND (
			@status IS NULL
			OR tbl.isactive = @status
			)
			AND (
    tbl.Schedule IS NOT NULL AND tbl.Schedule <> ''
)
--			AND (
--    (
--        (@FromDate IS NULL OR @ToDate IS NULL)
--        OR TRY_CAST(tbl.Schedule AS DATETIME) BETWEEN TRY_CAST(@FromDate AS DATETIME) AND TRY_CAST(@ToDate AS DATETIME)
--    )
--)
	ORDER BY tbl.id DESC*/
	SELECT *
	FROM (
		SELECT TGC.id
			,cname
			--,eventid
			--,AM.EventName
			,TGC.parentid
			,TGC.isactive
			,cast(TGC.createdon AS NVARCHAR(100)) AS createdon
			,TGC.createdby
			,isnull(smscampaignid, 0) AS smscampaignid
			,isnull(mailcampaignid, 0) AS mailcampaignid
			,isnull(voicecampaignid, 0) AS voicecampaignid
			,isnull(whatsappcampaignid, 0) AS whatsappcampaignid
			,Audience
			,TGC.ExcludeAudience
			,TGC.Schedule
			,CASE 
				WHEN cast(tgc.Audience AS NVARCHAR) <> '0'
					THEN STUFF((
								SELECT ', ' + t2.CriteriaName
								FROM tbl_SearchCriteria(NOLOCK) t2
								WHERE t2.ID IN (
										SELECT value
										FROM fn_Split(TGC.Audience, '#')
										)
								FOR XML PATH('')
								), 1, 2, '')
				--ELSE CASE 
				--		--WHEN Am.context = 'Lead'
				--		--	THEN 'All Leads'
				--		--ELSE 'All Enquiries'
				--		END
				END AS AudienceCollection
			,0 AS AudienceDefaultID
			--,dbo.func_ToGetTotalReached(isnull(smscampaignid, 0), isnull(mailcampaignid, 0), isnull(voicecampaignid, 0), isnull(whatsappcampaignid, 0))  
			--,dbo.func_ToGetTotalReached_includingsequence(tgc.id) AS TotalReached
			,isnull(t.reached,0)+isnull(wat.reached,0) as TotalReached
			--  ,cast(isnull(dbo.funcToGetLastRun_New(Cast(isnull(smscampaignid, 0) AS NVARCHAR) + '#' + CAST(isnull(mailcampaignid, 0) AS NVARCHAR) + '#' + CAST(isnull(voicecampaignid, 0) AS NVARCHAR) + '#' + cast(isnull(whatsappcampaignid, 0) AS NVARCHAR)), 'Never')  
			--AS NVARCHAR(200)) AS LastRun   
			--,cast(isnull(dbo.funcToGetLastRun_New_includingsequence(tgc.id), 'Never') AS NVARCHAR(200)) AS LastRun
			--,dbo.fn_max_date(t.reached,wat.reached) as LastRun
			,isnull(cast(case when t.LastRun is not null and wat.LastRun is not null and t.LastRun>wat.LastRun then t.LastRun
			when t.LastRun is not null and wat.LastRun is not null and t.LastRun<=wat.LastRun then wat.LastRun
			when t.LastRun is not null and wat.LastRun is null then t.LastRun
			when t.LastRun is null and wat.LastRun is not null then wat.LastRun
			else null end as nvarchar(50)),'Never') as LastRun
			--,Am.context
			,CASE 
				WHEN tgc.sequenceid != ''
					THEN 'sequenceDark-icon.png'
				ELSE 'sequenceLight-icon.png'
				END sequenceidicon
			,isnull(tgc.sequenceid, 0) sequenceid
			,isnull(tgc.issequenceactive, 0) issequenceactive
			,(
				SELECT COunt(cond.id)
				FROM triggeredcampaignrules rules
				JOIN [triggeredcampaignruleconditions] cond ON rules.id = cond.ruleid
				WHERE rules.triggeredcampaignid = TGC.id
				) RuleCount,
				dbo.GetCountBasedOnCondition(TGC.id) as [ExecutionCount]   
			,isnull(Trule.id, 0) ruleid
		FROM triggeredcampaigns(NOLOCK) AS TGC
		--JOIN activityMaster(NOLOCK) AS AM ON TGC.eventid = AM.ID
		LEFT JOIN triggeredcampaignrules AS Trule ON Trule.triggeredcampaignid = TGC.id
		left join

		(select t.id,sum(t.Reached) Reached,max(t.LastRun) as LastRun from
		
		( select tgc.id,c.campaignid,count(1) Reached,max(c.ExecutionTime) LastRun  from UserCampaignExecutionHistory(nolock) 
		as c join triggeredcampaigns tgc (nolock) on c.campaignid in (tgc.smscampaignid,tgc.mailcampaignid,tgc.voicecampaignid,tgc.whatsappcampaignid)
		group by campaignid,tgc.id) t group by t.id ) as t on t.id=tgc.id
        left join
		#temp as WAT on WAT.ruleid=tgc.id
		WHERE TGC.parentid = @ParentID
			
		) AS tbl
	WHERE (
			@CampName IS NULL
			OR tbl.cname LIKE '%' + @CampName + '%'
			)
		AND (
			@status IS NULL
			OR tbl.isactive = @status
			)
			AND (
    tbl.Schedule IS NOT NULL AND tbl.Schedule <> ''
)
--			AND (
--    (
--        (@FromDate IS NULL OR @ToDate IS NULL)
--        OR TRY_CAST(tbl.Schedule AS DATETIME) BETWEEN TRY_CAST(@FromDate AS DATETIME) AND TRY_CAST(@ToDate AS DATETIME)
--    )
--)
	ORDER BY tbl.id DESC


	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'View_TriggrComp'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'triggeredcampaigns'
END



