    @status CHAR(1) = NULL,
    @FromDate NVARCHAR(max) = NULL,
    @ToDate NVARCHAR(max) = NULL,
    @CampaignStatus VARCHAR(max) = NULL,
    @OffsetValue INT,
    @PagingSize INT
)
AS
BEGIN
   
   /*declare
   @UserID BIGINT=32222,
    @CampName VARCHAR(max) = '',    
    @status CHAR(1) = 1,
    @FromDate NVARCHAR(max) = '2025-02-01',
    @ToDate NVARCHAR(max) = '2025-03-07',
    @CampaignStatus VARCHAR(max) = NULL,
    @OffsetValue INT=0,
    @PagingSize INT=20*/

	begin try

    DECLARE @ParentID BIGINT = 0
    DECLARE @StartPoint INT = @OffsetValue + 1
    DECLARE @EndPoint INT = @PagingSize + @OffsetValue

    SELECT TOP 1 @ParentID = ISNULL(ParentID, User_ID)
    FROM User_Detail (NOLOCK)
    WHERE User_ID = @UserID

    ;WITH CTE_Campaigns AS (
        SELECT 
		ROW_NUMBER() OVER (ORDER BY TGC.id DESC) AS RowNumber,
            TGC.id,
            cname,
            TGC.parentid,
            TGC.isactive,
            --CAST(TGC.createdon AS NVARCHAR(100)) AS createdon,
			TGC.createdon AS createdon,
            TGC.createdby,
            ISNULL(smscampaignid, 0) AS smscampaignid,
            ISNULL(mailcampaignid, 0) AS mailcampaignid,
            ISNULL(voicecampaignid, 0) AS voicecampaignid,
            ISNULL(whatsappcampaignid, 0) AS whatsappcampaignid,
            Audience,
            TGC.ExcludeAudience,
            --TGC.Schedule,
			s.schedule_name as Schedule,
            S.expiry,
            dbo.usp_GetNextRunTime_schedule(TGC.Schedule, S.expiry) AS NextExecution, 
            CASE 
                WHEN CAST(tgc.Audience AS NVARCHAR) <> '0'
                    THEN STUFF((
                        SELECT ', ' + t2.CriteriaName
                        FROM tbl_SearchCriteria (NOLOCK) t2
                        WHERE t2.ID IN (
                            SELECT value
                            FROM fn_Split(TGC.Audience, '#')
                        )
                        FOR XML PATH('')
                    ), 1, 2, '')
            END AS AudienceCollection,
            0 AS AudienceDefaultID,
            ISNULL(t.reached, 0) + ISNULL(wat.reached, 0) AS TotalReached,
            ISNULL(CAST(CASE 
                WHEN t.LastRun IS NOT NULL AND wat.LastRun IS NOT NULL AND t.LastRun > wat.LastRun THEN t.LastRun
                WHEN t.LastRun IS NOT NULL AND wat.LastRun IS NOT NULL AND t.LastRun <= wat.LastRun THEN wat.LastRun
                WHEN t.LastRun IS NOT NULL AND wat.LastRun IS NULL THEN t.LastRun
                WHEN t.LastRun IS NULL AND wat.LastRun IS NOT NULL THEN wat.LastRun
                ELSE NULL 
            END AS NVARCHAR(50)), 'Never') AS LastRun,
            CASE 
                WHEN tgc.sequenceid != '' THEN 'sequenceDark-icon.png'
                ELSE 'sequenceLight-icon.png'
            END AS sequenceidicon,
            ISNULL(tgc.sequenceid, 0) AS sequenceid,
            ISNULL(tgc.issequenceactive, 0) AS issequenceactive,
            (
                SELECT COUNT(cond.id)
                FROM triggeredcampaignrules rules
                JOIN triggeredcampaignruleconditions cond ON rules.id = cond.ruleid
                WHERE rules.triggeredcampaignid = TGC.id
            ) AS RuleCount,
            dbo.GetCountBasedOnCondition(TGC.id) AS ExecutionCount,
            ISNULL(Trule.id, 0) AS ruleid,
            count(1) OVER (PARTITION BY tgc.parentid) AS TotalRows
			 --AM.context
        FROM triggeredcampaigns (NOLOCK) AS TGC
		 LEFT JOIN schedules (NOLOCK) AS S ON S.id = TGC.Schedule 
        LEFT JOIN triggeredcampaignrules AS Trule ON Trule.triggeredcampaignid = TGC.id
        LEFT JOIN (
            SELECT t.id, SUM(t.Reached) AS Reached, MAX(t.LastRun) AS LastRun 
            FROM (
                SELECT tgc.id, c.campaignid, COUNT(1) AS Reached, MAX(c.ExecutionTime) AS LastRun  
                FROM UserCampaignExecutionHistory (NOLOCK) AS c 
                JOIN triggeredcampaigns tgc (NOLOCK) ON c.campaignid IN (tgc.smscampaignid, tgc.mailcampaignid, tgc.voicecampaignid, tgc.whatsappcampaignid)
                GROUP BY campaignid, tgc.id
            ) t 
            GROUP BY t.id
        ) AS t ON t.id = tgc.id
        LEFT JOIN (
            SELECT ruleid, COUNT(DISTINCT activityid) AS Reached, MAX(processedat) AS LastRun 
            FROM [10.0.0.135].mysmsConversations.dbo.tbl_wa_automationtasks as u  with(NOLOCK) 
            WHERE activityid IS NOT NULL AND ISNULL(isprocessed, 0) <> 0 
            GROUP BY ruleid
        ) AS WAT ON WAT.ruleid = tgc.id
        WHERE TGC.parentid = @ParentID
    AND (@CampName IS NULL OR TGC.cname LIKE '%' + @CampName + '%')
    AND (
    @status IS NULL 
    OR (@status = 0 AND TGC.isactive IN (0, 1)) 
    OR (@status = 1 AND TGC.isactive = 1)
    OR (@status = 2 AND TGC.isactive = 0)
)
    AND (TGC.Schedule IS NOT NULL AND TGC.Schedule <> '')
  AND (
    @FromDate IS NULL OR LTRIM(RTRIM(@FromDate)) = '' 
    OR @ToDate IS NULL OR LTRIM(RTRIM(@ToDate)) = ''
    OR (
        TGC.createdon BETWEEN TRY_CAST(@FromDate AS DATETIME) AND DATEADD(DAY, 1, TRY_CAST(@ToDate AS DATETIME)) -- Include the full day for ToDate
    )
)


)
    SELECT *
    FROM CTE_Campaigns
    WHERE RowNumber BETWEEN @StartPoint AND @EndPoint

    EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId 
        @User_id = @UserID,
        @Activity_type = 'View_TriggrComp',
        @ActionType = 'S',
        @RowJson = '',
        @Table_name = 'triggeredcampaigns'
		END TRY

    -- Catch block to handle errors
    BEGIN CATCH
        -- Log error information
        EXEC usp_InsertErrorInfo;
    END CATCH
END




GO

