			when t.reached is not null and wat.reached is null then t.reached
			when t.reached is null and wat.reached is not null then wat.reached
			else null end as nvarchar(50)),'Never') as LastRun
			,Am.context
			,CASE 
				WHEN tgc.sequenceid != ''
					THEN 'sequenceDark-icon.png'
				ELSE 'sequenceLight-icon.png'
				END sequenceidicon
			,isnull(tgc.sequenceid, 0) sequenceid
			,isnull(tgc.issequenceactive, 0) issequenceactive
			,(
				SELECT COunt(cond.id)
				FROM triggeredcampaignrules rules
				JOIN [triggeredcampaignruleconditions] cond ON rules.id = cond.ruleid
				WHERE rules.triggeredcampaignid = TGC.id
				) RuleCount
			,isnull(Trule.id, 0) ruleid
		FROM triggeredcampaigns(NOLOCK) AS TGC
		JOIN activityMaster(NOLOCK) AS AM ON TGC.eventid = AM.ID
		LEFT JOIN triggeredcampaignrules AS Trule ON Trule.triggeredcampaignid = TGC.id
		left join
		(select t.id,sum(t.Reached) Reached,max(t.LastRun) as LastRun from
		(select tgc.id,c.campaignid,count(1) Reached,max(c.ExecutionTime) LastRun  from UserCampaignExecutionHistory(nolock) 
		as c join triggeredcampaigns tgc (nolock) on c.campaignid in (tgc.smscampaignid,tgc.mailcampaignid,tgc.voicecampaignid,tgc.whatsappcampaignid)
		group by campaignid,tgc.id) t group by t.id) as t on t.id=tgc.id
        left join
		(select ruleid,count(distinct activityid) Reached,max(scheduledfor) LastRun from MySMSConversations.dbo.tbl_wa_automationtasks(nolock) where activityid  
         is not null and isprocessed is not null group by ruleid) as WAT on WAT.ruleid=tgc.id
		WHERE TGC.parentid = @ParentID
			AND AM.ID NOT IN (
				108
				,109
				,110
				,111
				,112
				,113
				,114
				,115
				--,116    
				,117
				)
		
		UNION
		
		SELECT 0 AS id
			,SUBSTRING(EventName, 1, 10) + '_' + CAST(ROW_NUMBER() OVER (
					ORDER BY AM.id ASC
					) AS NVARCHAR) AS cname
			,id AS eventid
			,EventName
			,@ParentID AS parentid
			,0 AS isactive
			,'Never' AS createdon
			,@UserID AS createdby
			,0 AS smscampaignid
			,0 AS mailcampaignid
			,0 AS voicecampaignid
			,0 AS whatsappcampaignid
			,'' AS Audience
			,CASE 
				WHEN Am.context = 'Lead'
					THEN 'All Leads'
				ELSE 'All Enquiries'
				END AS AudienceCollection
			,isnull((
					SELECT isnull(id, 0)
					FROM tbl_SearchCriteria(NOLOCK) AS USL
					WHERE USL.CriteriaName = CASE 
							WHEN AM.context = 'Lead'
								THEN 'All Leads'
							WHEN Am.context = 'Enquiry'
								THEN 'All Enquiries'
							END
						AND ParentID = @ParentID
					), 0) AS AudienceDefaultID
			,'0' AS TotalReached
			,'Never' AS LastRun
			,Am.context
			,'sequenceLight-icon.png' sequenceidicon
			,0 sequenceid
			,0 issequenceactive
			,0 RuleCount
			,0 ruleid
		FROM ActivityMaster(NOLOCK) AS AM
		WHERE (
				(ParentId = @ParentID)
				OR (ParentId IS NULL)
				)
			AND (
				context = 'Lead'
				OR context = 'Enquiry'
				)
			AND ID NOT IN (
				SELECT eventid
				FROM triggeredcampaigns(NOLOCK)
				WHERE parentid = @ParentID
				)
			AND AM.ID NOT IN (
				108
				,109
				,110
				,111
				,112
				,113
				,114
				,115
				--,116    
				,117
				)
		) AS tbl
	WHERE (
			@CampName IS NULL
			OR tbl.cname LIKE '%' + @CampName + '%'
			)
		AND (
			@status IS NULL
			OR tbl.isactive = @status
			)
	ORDER BY tbl.id DESC*/

	SELECT *
	FROM (
		SELECT TGC.id
			,cname
			,eventid
			,AM.EventName
			,TGC.parentid
			,TGC.isactive
			,cast(TGC.createdon AS NVARCHAR(100)) AS createdon
			,TGC.createdby
			,isnull(smscampaignid, 0) AS smscampaignid
			,isnull(mailcampaignid, 0) AS mailcampaignid
			,isnull(voicecampaignid, 0) AS voicecampaignid
			,isnull(whatsappcampaignid, 0) AS whatsappcampaignid
			,Audience
			,CASE 
				WHEN cast(tgc.Audience AS NVARCHAR) <> '0'
					THEN STUFF((
								SELECT ', ' + t2.CriteriaName
								FROM tbl_SearchCriteria(NOLOCK) t2
								WHERE t2.ID IN (
										SELECT value
										FROM fn_Split(TGC.Audience, '#')
										)
								FOR XML PATH('')
								), 1, 2, '')
				ELSE CASE 
						WHEN Am.context = 'Lead'
							THEN 'All Leads'
						ELSE 'All Enquiries'
						END
				END AS AudienceCollection
			,0 AS AudienceDefaultID
			--,dbo.func_ToGetTotalReached(isnull(smscampaignid, 0), isnull(mailcampaignid, 0), isnull(voicecampaignid, 0), isnull(whatsappcampaignid, 0))  
			--,dbo.func_ToGetTotalReached_includingsequence(tgc.id) AS TotalReached
			,isnull(t.reached,0)+isnull(wat.reached,0) as TotalReached
			--  ,cast(isnull(dbo.funcToGetLastRun_New(Cast(isnull(smscampaignid, 0) AS NVARCHAR) + '#' + CAST(isnull(mailcampaignid, 0) AS NVARCHAR) + '#' + CAST(isnull(voicecampaignid, 0) AS NVARCHAR) + '#' + cast(isnull(whatsappcampaignid, 0) AS NVARCHAR)), 'Never')  
			--AS NVARCHAR(200)) AS LastRun   
			--,cast(isnull(dbo.funcToGetLastRun_New_includingsequence(tgc.id), 'Never') AS NVARCHAR(200)) AS LastRun
			--,dbo.fn_max_date(t.reached,wat.reached) as LastRun
			,isnull(cast(case when t.reached is not null and wat.reached is not null and t.reached>wat.reached then t.reached
			when t.reached is not null and wat.reached is not null and t.reached<=wat.reached then wat.reached
			when t.reached is not null and wat.reached is null then t.reached
			when t.reached is null and wat.reached is not null then wat.reached
			else null end as nvarchar(50)),'Never') as LastRun
			,Am.context
			,CASE 
				WHEN tgc.sequenceid != ''
					THEN 'sequenceDark-icon.png'
				ELSE 'sequenceLight-icon.png'
				END sequenceidicon
			,isnull(tgc.sequenceid, 0) sequenceid
			,isnull(tgc.issequenceactive, 0) issequenceactive
			,(
				SELECT COunt(cond.id)
				FROM triggeredcampaignrules rules
				JOIN [triggeredcampaignruleconditions] cond ON rules.id = cond.ruleid
				WHERE rules.triggeredcampaignid = TGC.id
				) RuleCount
			,isnull(Trule.id, 0) ruleid
		FROM triggeredcampaigns(NOLOCK) AS TGC
		JOIN activityMaster(NOLOCK) AS AM ON TGC.eventid = AM.ID
		LEFT JOIN triggeredcampaignrules AS Trule ON Trule.triggeredcampaignid = TGC.id
		left join
		(select t.id,sum(t.Reached) Reached,max(t.LastRun) as LastRun from
		(select tgc.id,c.campaignid,count(1) Reached,max(c.ExecutionTime) LastRun  from UserCampaignExecutionHistory(nolock) 
		as c join triggeredcampaigns tgc (nolock) on c.campaignid in (tgc.smscampaignid,tgc.mailcampaignid,tgc.voicecampaignid,tgc.whatsappcampaignid)
		group by campaignid,tgc.id) t group by t.id) as t on t.id=tgc.id
        left join
		#temp as WAT on WAT.ruleid=tgc.id
		WHERE TGC.parentid = @ParentID
			AND AM.ID NOT IN (
				108
				,109
				,110
				,111
				,112
				,113
				,114
				,115
				--,116    
				,117
				)
		
		UNION
		
		SELECT 0 AS id
			,SUBSTRING(EventName, 1, 10) + '_' + CAST(ROW_NUMBER() OVER (
					ORDER BY AM.id ASC
					) AS NVARCHAR) AS cname
			,id AS eventid
			,EventName
			,@ParentID AS parentid
			,0 AS isactive
			,'Never' AS createdon
			,@UserID AS createdby
			,0 AS smscampaignid
			,0 AS mailcampaignid
			,0 AS voicecampaignid
			,0 AS whatsappcampaignid
			,'' AS Audience
			,CASE 
				WHEN Am.context = 'Lead'
					THEN 'All Leads'
				ELSE 'All Enquiries'
				END AS AudienceCollection
			,isnull((
					SELECT isnull(id, 0)
					FROM tbl_SearchCriteria(NOLOCK) AS USL
					WHERE USL.CriteriaName = CASE 
							WHEN AM.context = 'Lead'
								THEN 'All Leads'
							WHEN Am.context = 'Enquiry'
								THEN 'All Enquiries'
							END
						AND ParentID = @ParentID
					), 0) AS AudienceDefaultID
			,'0' AS TotalReached
			,'Never' AS LastRun
			,Am.context
			,'sequenceLight-icon.png' sequenceidicon
			,0 sequenceid
			,0 issequenceactive
			,0 RuleCount
			,0 ruleid
		FROM ActivityMaster(NOLOCK) AS AM
		WHERE (
				(ParentId = @ParentID)
				OR (ParentId IS NULL)
				)
			AND (
				context = 'Lead'
				OR context = 'Enquiry'
				)
			AND ID NOT IN (
				SELECT eventid
				FROM triggeredcampaigns(NOLOCK)
				WHERE parentid = @ParentID
				)
			AND AM.ID NOT IN (
				108
				,109
				,110
				,111
				,112
				,113
				,114
				,115
				--,116    
				,117
				)
		) AS tbl
	WHERE (
			@CampName IS NULL
			OR tbl.cname LIKE '%' + @CampName + '%'
			)
		AND (
			@status IS NULL
			OR tbl.isactive = @status
			)
	ORDER BY tbl.id DESC


	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'View_TriggrComp'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'triggeredcampaigns'
END



