/* ============================================================
   Procedure: [dbo].[Usp_DisplayTriggeredCampaignsPagging]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_DisplayTriggeredCampaignsPagging] --42185--34594--39680
(
	@UserID BIGINT = 34594,
    @CampName VARCHAR(max) = NULL,
    @status CHAR(1) = 1,
    @OffsetValue int  = 0,
    @PagingSize int  = 20
)
AS
BEGIN
     --DECLARE	
     --   @UserID BIGINT = 32222,
     --   @CampName VARCHAR(max) = NULL,
     --   @status CHAR(1) = N'0',
     --   @OffsetValue int  = 0,
     --   @PagingSize int  = 20

    

	DECLARE
		@ParentID BIGINT = 0

		DROP TABLE IF EXISTS #temp;
    CREATE TABLE #temp (Reached BIGINT, ruleid BIGINT, LastRun  datetime,isprocessed int );

DECLARE @query NVARCHAR(MAX);
SET @query = '
    SELECT 
        ruleid,
        COUNT(DISTINCT activityid) AS Reached,
        MAX(processedat) AS LastRun
    FROM tbl_wa_automationtasks (NOLOCK)
    WHERE activityid IS NOT NULL AND ISNULL(isprocessed, 0) <> 0
    GROUP BY ruleid;';

    -- Execute the query using your CLR procedure
    INSERT INTO #temp(ruleid, Reached, LastRun)
    EXEC usp_clr_FillRemoteData @query;

	DECLARE @StartPoint int = @OffsetValue + 1, @EndPoint int = @PagingSize + @OffsetValue

    SELECT TOP 1 @ParentID = ISNULL(ParentID, User_ID) FROM User_Detail (NOLOCK) WHERE User_ID = @UserID

	/*select RowNumber, id, cname, eventid, EventName, parentid, isactive, createdon, createdby, smscampaignid, mailcampaignid, voicecampaignid, whatsappcampaignid,
			 Audience, AudienceCollection, AudienceDefaultID, TotalReached, LastRun, context, sequenceidicon, sequenceid, issequenceactive, RuleCount, ExecutionCount, ruleid, TotalRows
	from ( SELECT 
	 	row_number() OVER (ORDER BY t.id) AS RowNumber,
		t.id, t.cname, t.eventid, t.EventName, t.parentid, t.isactive, t.createdon, t.createdby, t.smscampaignid, t.mailcampaignid, 
	 	t.voicecampaignid, t.whatsappcampaignid, t.Audience, t.AudienceCollection, t.AudienceDefaultID, t.TotalReached, t.LastRun, t.context, t.sequenceidicon,
	 	t.sequenceid, t.issequenceactive, t.RuleCount, t.ExecutionCount, t.ruleid, 
		count(1) OVER (PARTITION BY t.parentid) AS TotalRows
     FROM (
        SELECT TGC.id, cname, eventid, AM.EventName, TGC.parentid, TGC.isactive, CAST(TGC.createdon AS NVARCHAR(100)) createdon, TGC.createdby,
			ISNULL(smscampaignid,0) smscampaignid,ISNULL(mailcampaignid,0) mailcampaignid, ISNULL(voicecampaignid,0) voicecampaignid,
			ISNULL(whatsappcampaignid,0) whatsappcampaignid, Audience,
            CASE 
                WHEN CAST(TGC.Audience AS NVARCHAR) <> '0'
                    THEN STUFF((SELECT ', ' + t2.CriteriaName
                                FROM tbl_SearchCriteria (NOLOCK) t2
                                WHERE t2.ID IN (SELECT value FROM fn_Split(TGC.Audience, '#'))
                                FOR XML PATH('')), 1, 2, '')
                ELSE 
                    CASE 
                        WHEN AM.context = 'Lead' THEN 'All Leads'
                        ELSE 'All Enquiries'
                    END
            END AS AudienceCollection,
            0 AS AudienceDefaultID,
            ISNULL(t.reached, 0) + ISNULL(wat.reached, 0) AS TotalReached,
            ISNULL(CAST(CASE 
                            WHEN t.LastRun IS NOT NULL AND wat.LastRun IS NOT NULL AND t.LastRun > wat.LastRun THEN t.LastRun
                            WHEN t.LastRun IS NOT NULL AND wat.LastRun IS NOT NULL AND t.LastRun <= wat.LastRun THEN wat.LastRun
                            WHEN t.LastRun IS NOT NULL AND wat.LastRun IS NULL THEN t.LastRun
                            WHEN t.LastRun IS NULL AND wat.LastRun IS NOT NULL THEN wat.LastRun
                            ELSE NULL 
                        END AS NVARCHAR(50)), 'Never') AS LastRun,
            AM.context,
            CASE 
                WHEN TGC.sequenceid != '' THEN 'sequenceDark-icon.png'
                ELSE 'sequenceLight-icon.png'
            END sequenceidicon,
            ISNULL(TGC.sequenceid, 0) sequenceid,
            ISNULL(TGC.issequenceactive, 0) issequenceactive,
            (SELECT COUNT(cond.id)
             FROM triggeredcampaignrules rules
             JOIN triggeredcampaignruleconditions cond ON rules.id = cond.ruleid
             WHERE rules.triggeredcampaignid = TGC.id) RuleCount,
            dbo.GetCountBasedOnCondition(TGC.id) AS [ExecutionCount],
            ISNULL(Trule.id, 0) ruleid
        FROM 
            triggeredcampaigns (NOLOCK) AS TGC
        JOIN 
            activityMaster (NOLOCK) AS AM ON TGC.eventid = AM.ID
        LEFT JOIN 
            triggeredcampaignrules AS Trule ON Trule.triggeredcampaignid = TGC.id
        LEFT JOIN 
            (SELECT t.id, SUM(t.Reached) Reached, MAX(t.LastRun) AS LastRun
             FROM 
                (SELECT tgc.id, c.campaignid, COUNT(1) Reached, MAX(c.ExecutionTime) LastRun
                 FROM UserCampaignExecutionHistory (NOLOCK) AS c
                 JOIN triggeredcampaigns tgc (NOLOCK) ON c.campaignid IN (tgc.smscampaignid, tgc.mailcampaignid, tgc.voicecampaignid, tgc.whatsappcampaignid)
                 GROUP BY campaignid, tgc.id) t
             GROUP BY t.id) AS t ON t.id = TGC.id
        LEFT JOIN 
            (SELECT ruleid, COUNT(DISTINCT activityid) Reached, MAX(processedat) LastRun
             FROM MySMSConversations.dbo.tbl_wa_automationtasks (NOLOCK)
             WHERE activityid IS NOT NULL AND ISNULL(isprocessed, 0) <> 0
             GROUP BY ruleid) AS WAT ON WAT.ruleid = TGC.id
        WHERE 
             TGC.parentid = @ParentID
    ) AS t  	
	WHERE (@CampName IS NULL OR t.cname LIKE '%' + @CampName + '%')  
		AND
		1 = ( CASE 
				WHEN ISNULL(@status, 0) = '0' THEN 1
				WHEN ISNULL(@status, 0) = '1' AND t.isactive = 1 THEN 1
				WHEN ISNULL(@status, 0) = '2' AND t.isactive = 0 THEN 1
			ELSE 0 END
		)  
	) p where RowNumber between @StartPoint and @EndPoint*/
	
	
	SELECT RowNumber, id, cname, eventid, EventName, parentid, isactive, createdon, createdby, smscampaignid, mailcampaignid, voicecampaignid, whatsappcampaignid,
       Audience, AudienceCollection, AudienceDefaultID, TotalReached, LastRun, context, sequenceidicon, sequenceid, issequenceactive, RuleCount, ExecutionCount, ruleid, TotalRows
FROM (
    SELECT 
        ROW_NUMBER() OVER (ORDER BY t.id DESC) AS RowNumber,
        t.id, t.cname, t.eventid, t.EventName, t.parentid, t.isactive, t.createdon, t.createdby, t.smscampaignid, t.mailcampaignid, 
        t.voicecampaignid, t.whatsappcampaignid, t.Audience, t.AudienceCollection, t.AudienceDefaultID, t.TotalReached, t.LastRun, t.context, t.sequenceidicon,
        t.sequenceid, t.issequenceactive, t.RuleCount, t.ExecutionCount, t.ruleid, 
        COUNT(1) OVER (PARTITION BY t.parentid) AS TotalRows
    FROM (
        SELECT TGC.id, cname, eventid, AM.EventName, TGC.parentid, TGC.isactive, CAST(TGC.createdon AS NVARCHAR(100)) createdon, TGC.createdby,
            ISNULL(smscampaignid,0) smscampaignid, ISNULL(mailcampaignid,0) mailcampaignid, ISNULL(voicecampaignid,0) voicecampaignid,
            ISNULL(whatsappcampaignid,0) whatsappcampaignid, Audience,
            --CASE 
            --    WHEN CAST(TGC.Audience AS NVARCHAR) <> '0'
            --        THEN STUFF((SELECT ', ' + t2.CriteriaName
            --                    FROM tbl_SearchCriteria (NOLOCK) t2
            --                    WHERE t2.ID IN (SELECT value FROM fn_Split(TGC.Audience, '#'))
            --                    FOR XML PATH('')), 1, 2, '')
            --    ELSE 
            --        CASE 
            --            WHEN AM.context = 'Lead' THEN 'All Leads'
            --            ELSE 'All Enquiries'
            --        END
            --END AS AudienceCollection,
			CASE 
    WHEN CAST(TGC.Audience AS NVARCHAR) <> '0'
        THEN STUFF((SELECT ', ' + t2.CriteriaName
                    FROM tbl_SearchCriteria (NOLOCK) t2
                    WHERE t2.ID IN (SELECT CAST(value AS BIGINT) FROM fn_Split(TGC.Audience, '#') WHERE ISNUMERIC(value) = 1)
                    FOR XML PATH('')), 1, 2, '')
    ELSE 
        CASE 
            WHEN AM.context = 'Lead' THEN 'All Leads'
            ELSE 'All Enquiries'
        END
END AS AudienceCollection,

            0 AS AudienceDefaultID,
            ISNULL(t.reached, 0) + ISNULL(wat.reached, 0) AS TotalReached,
            ISNULL(CAST(CASE 
                            WHEN t.LastRun IS NOT NULL AND wat.LastRun IS NOT NULL AND t.LastRun > wat.LastRun THEN t.LastRun
                            WHEN t.LastRun IS NOT NULL AND wat.LastRun IS NOT NULL AND t.LastRun <= wat.LastRun THEN wat.LastRun
                            WHEN t.LastRun IS NOT NULL AND wat.LastRun IS NULL THEN t.LastRun
                            WHEN t.LastRun IS NULL AND wat.LastRun IS NOT NULL THEN wat.LastRun
                            ELSE NULL 
                        END AS NVARCHAR(50)), 'Never') AS LastRun,
            AM.context,
            CASE 
                WHEN TGC.sequenceid != '' THEN 'sequenceDark-icon.png'
                ELSE 'sequenceLight-icon.png'
            END sequenceidicon,
            ISNULL(TGC.sequenceid, 0) sequenceid,
            ISNULL(TGC.issequenceactive, 0) issequenceactive,
            (SELECT COUNT(cond.id)
             FROM triggeredcampaignrules rules
             JOIN triggeredcampaignruleconditions cond ON rules.id = cond.ruleid
             WHERE rules.triggeredcampaignid = TGC.id) RuleCount,
            dbo.GetCountBasedOnCondition(TGC.id) AS [ExecutionCount],
            ISNULL(Trule.id, 0) ruleid
        FROM 
            triggeredcampaigns (NOLOCK) AS TGC
        JOIN 
            activityMaster (NOLOCK) AS AM ON TGC.eventid = AM.ID
        LEFT JOIN 
            triggeredcampaignrules AS Trule ON Trule.triggeredcampaignid = TGC.id
        LEFT JOIN 
            (SELECT t.id, SUM(t.Reached) Reached, MAX(t.LastRun) AS LastRun
             FROM 
                (SELECT tgc.id, c.campaignid, COUNT(1) Reached, MAX(c.ExecutionTime) LastRun
                 FROM UserCampaignExecutionHistory (NOLOCK) AS c
                 JOIN triggeredcampaigns tgc (NOLOCK) ON c.campaignid IN (tgc.smscampaignid, tgc.mailcampaignid, tgc.voicecampaignid, tgc.whatsappcampaignid)
                 GROUP BY campaignid, tgc.id) t
             GROUP BY t.id) AS t ON t.id = TGC.id
        LEFT JOIN 
            #temp AS WAT ON WAT.ruleid = TGC.id
        WHERE 
            TGC.parentid = @ParentID
    ) AS t  	
    WHERE (@CampName IS NULL OR t.cname LIKE '%' + @CampName + '%')  
        AND
        1 = ( CASE 
                WHEN ISNULL(@status, 0) = '0' THEN 1
                WHEN ISNULL(@status, 0) = '1' AND t.isactive = 1 THEN 1
                WHEN ISNULL(@status, 0) = '2' AND t.isactive = 0 THEN 1
            ELSE 0 END
        )  
) p 
WHERE RowNumber BETWEEN @StartPoint AND @EndPoint

    EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId 
        @User_id = @UserID,
        @Activity_type = 'View_TriggrComp',
        @ActionType = 'S',
        @RowJson = '',
        @Table_name = 'triggeredcampaigns'

END



