	/*select RowNumber, id, cname, eventid, EventName, parentid, isactive, createdon, createdby, smscampaignid, mailcampaignid, voicecampaignid, whatsappcampaignid,
			 Audience, AudienceCollection, AudienceDefaultID, TotalReached, LastRun, context, sequenceidicon, sequenceid, issequenceactive, RuleCount, ExecutionCount, ruleid, TotalRows
	from ( SELECT 
