/* ============================================================
   Procedure: [dbo].[Usp_DleteDocument]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_DleteDocument]     
(    
  
@docupid int  
)         
AS          
BEGIN       
    
    Update tbl_LeadDocumentUpload set ISDeleted=1,DeletedDate=GETDATE() where DocUpID=@docupid  

	  DECLARE @UserID_LDACTV BIGINT = 0 --@UserID      
	  DECLARE @DocName_LDACTV NVARCHAR(500) = '' --@DocumentName      
	  DECLARE @evntMessage NVARCHAR(max) = ''      
	  DECLARE @ParentID_LDACTV BIGINT = 0--@ParentID      
	  DECLARE @LeadID_LDACTV BIGINT = 0 --@LeadID      
       
	    /*
	    DocUpID
		UserID
		LeadID
		ParentID
		DocumentName
	   */
   BEGIN TRY      
     select top 1  @UserID_LDACTV = UserID, @DocName_LDACTV = DocumentName , @ParentID_LDACTV = ParentID
	             , @LeadID_LDACTV = LeadID   
	           from tbl_LeadDocumentUpload with(nolock) where DocUpID = @docupid 

   CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(max))      
      
  IF (isnull(@LeadID_LDACTV, 0) > 0)      
   BEGIN      
     INSERT INTO #tblEventDescrb      
	  EXEC Usp_EventTemplate_DynamicVarReplacement 'Doc deleted'      
	  ,@UserID_LDACTV      
     ,''      
	 ,''      
    ,0      
    ,''      
    ,NULL      
    ,0      
    ,0      
    ,''      
    ,''      
    ,0      
    ,''      
    ,0      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,NULL      
    ,0      
    ,0      
    ,0      
    ,NULL      
    ,NULL      
    ,NULL      
    ,0      
    ,NULL      
    ,NULL      
    ,NULL      
    ,0      
    ,@DocName_LDACTV      
    ,NULL      
      
   SELECT @evntMessage = isnull(EVNT_Description, '')      
   FROM #tblEventDescrb      
      
   SELECT @evntMessage      
      
   IF(@evntMessage <> '')      
   BEGIN      
    EXEC UspSaveLeadActivity_withid @LeadID_LDACTV      
     ,@UserID_LDACTV      
     ,@ParentID_LDACTV      
     ,@evntMessage      
     ,'Doc deleted'      
     ,'tbl_LeadDocumentUpload'      
     ,@docupid      
   END 
   END      
 END TRY      
      
 BEGIN CATCH      
  EXEC usp_insertErrorInfo      
 END CATCH      
      
 IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence          
 BEGIN      
  DROP TABLE #tblEventDescrb      
 END      

     
END   


GO

