/* ============================================================
   Procedure: [dbo].[Usp_DLTApprovedDefaultSenderID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_DLTApprovedDefaultSenderID
(
 @UserID bigint 
)
as
Begin

  select top 1 Sender_ID,Sender_Name  from SenderID_Detail(nolock)  
  where isnull(User_ID,0) = @UserID and isnull(Status,0) = 1
     and isnull(Sender_Name,'') in
	  (
	   select Sender_Name from Default_SenderID(nolock) where User_ID = @UserID and ISNULL(Sender_Name ,'') <> ''
	  ) 
	  order by Sender_ID desc
End


GO

