/* ============================================================
   Procedure: [dbo].[usp_dnd]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_dnd]   --     '254416','','01/08/2015','23/09/2015'               
            
              
@U_ID INT,                 
@SENDER_ID NVARCHAR(100),                 
@FDATE NVARCHAR(20),                  
@TDATE NVARCHAR(20)                  
AS                  
--DECLARE @U_ID NVARCHAR(200)                  
IF(@U_ID!='')                
BEGIN                
--SELECT @U_ID=USER_ID FROM USER_DETAIL(NOLOCK) WHERE USER_LOGIN=@USER_LOGIN              
;WITH CTE AS(          
SELECT DU.MESSAGEINSERTDATE,DU.MOBILE,ISNULL((CASE DU.MESSAGESTATUS WHEN '' THEN 'DND' WHEN '6'THEN                 
'INVALID' WHEN 'NULL' THEN 'DND'  WHEN '5' THEN 'BLACKLISTED' WHEN '9' THEN  'INVALID' ELSE MESSAGESTATUS END),                
'DND')AS MESSAGESTATUS,DU.SENDERID,DU.MESSAGE FROM [MYSMSREPORT].[DBO].[SixDaysHistory] DU (NOLOCK) JOIN                 
[MYGROUPAPPCOMB].[DBO].[DNDDIRECTORY] DD ON DU.MOBILE=DD.[DNDMOBILENO] WHERE DU.U_ID=@U_ID AND (CONVERT(NVARCHAR,CONVERT(DATETIME,MESSAGEINSERTDATE,104),112) BETWEEN               
CONVERT(NVARCHAR,CONVERT(DATETIME,@FDATE,104),112) AND CONVERT(NVARCHAR,CONVERT(DATETIME,@TDATE,104),112)))            
SELECT MESSAGEINSERTDATE,MOBILE,MESSAGESTATUS,SENDERID,MESSAGE FROM CTE                
END                
ELSE IF(@SENDER_ID!='')                
BEGIN               
;WITH CTE AS(             

SELECT DU.MESSAGEINSERTDATE,DU.MOBILE,ISNULL((CASE DU.MESSAGESTATUS WHEN '' THEN 'DND' WHEN '6'THEN                 
'INVALID' WHEN 'NULL' THEN 'DND'  WHEN '5' THEN 'BLACKLISTED' WHEN '9' THEN  'INVALID' ELSE MESSAGESTATUS END),                
'DND')AS MESSAGESTATUS,DU.SENDERID,DU.MESSAGE FROM [MYSMSREPORT].[DBO].[SixDaysHistory] DU (NOLOCK) JOIN                 
[MYGROUPAPPCOMB].[DBO].[DNDDIRECTORY] DD ON DU.MOBILE=DD.[DNDMOBILENO] WHERE DU.SENDERID=@SENDER_ID AND (CONVERT(NVARCHAR,CONVERT(DATETIME,MESSAGEINSERTDATE,104),112) BETWEEN               
CONVERT(NVARCHAR,CONVERT(DATETIME,@FDATE,104),112) AND CONVERT(NVARCHAR,CONVERT(DATETIME,@TDATE,104),112)))                
SELECT MESSAGEINSERTDATE,MOBILE,MESSAGESTATUS,SENDERID,MESSAGE FROM CTE            
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_DndRefundUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****************************              
This SP se for Refund Dnd Messages that was NotAllow.            
Created By : Abhishek            
****************************/              
CREATE   PROC Usp_DndRefundUser              
( @UserId int,              
@Id int,              
@Dnd int,              
@Priority int,              
@messageLength int,            
@RefundBy varchar(20),        
@IsUnicode int,      
@batchid bigint              
)              
AS              
Begin              
Declare @creditid bigint              
Declare @balance bigint,@FinalBalance bigint              
   
     Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @UserId ) 
     Declare @MIDP bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID ) 
              
set @creditid=(select max(Credit_ID) from Credit_Details with(nolock) where User_ID=@ParentID)              
                
select top 1 @balance=max(Balance) from Credit_Details with(nolock) where User_ID=@ParentID and Credit_ID=@creditid         
if @IsUnicode=0        
Begin          
set @Dnd= (((@messageLength-1)/160)+1)* @Dnd         
End        
Else        
Begin        
set @Dnd= (((@messageLength-1)/70)+1)* @Dnd         
End               
 if(@Priority = 1)          
Begin          
set @Dnd=2*@Dnd          
end                       
set @FinalBalance=(@balance+@Dnd)               
              
update Credit_Details set Balance=(@FinalBalance) where User_ID=@ParentID and Credit_ID=@creditid               
              
Update dndRefund set IsRefund=1,RefundBy=@RefundBy,RefundDate=getdate() where batchid=@batchid and USERID=@UserId              
End 


GO

