--Usp_DuplicateEnquiryMerge @userid=34594,  @mode ='enq', @orderby='MobileNo',@ordertype = '1' @filtertext='test'           
CREATE   PROCEDURE [dbo].[Usp_DuplicateEnquiryMerge] @userid BIGINT          
 ,@enquiryid BIGINT = NULL          
 ,@personname NVARCHAR(max) = NULL          
 ,@companyname NVARCHAR(max) = NULL          
 ,@mobileno NVARCHAR(max) = NULL          
 ,@mobileno1 NVARCHAR(max) = NULL          
 ,@mobileno2 NVARCHAR(max) = NULL          
 ,@emailid NVARCHAR(max) = NULL          
 ,@emailid1 NVARCHAR(max) = NULL          
 ,@emailid2 NVARCHAR(max) = NULL          
 ,@city NVARCHAR(max) = NULL          
 ,@state NVARCHAR(max) = NULL          
 ,@country NVARCHAR(max) = NULL          
 ,@countrycode NVARCHAR(max) = NULL          
 ,@pincode NVARCHAR(max) = NULL          
 ,@residentialaddress NVARCHAR(max) = NULL          
 ,@officeaddress NVARCHAR(max) = NULL          
 ,@Initialremarks NVARCHAR(max) = NULL          
 ,@delby NVARCHAR(10) = NULL          
 ,@deleteall CHAR(1) = NULL          
 ,@filtertext NVARCHAR(MAX) = NULL          
 ,@orderby nvarchar(max) =NULL        
 ,@ordertype nvarchar(5)=NULL   
 ,@duplicatetype nvarchar(6)= null  
 ,@mode VARCHAR(10)          
AS          
BEGIN          
 DECLARE @mobile NVARCHAR(max)          
  ,@email NVARCHAR(max)          
  ,@mobile1 NVARCHAR(max)          
  ,@email1 NVARCHAR(max)          
  ,@mobile2 NVARCHAR(max)          
  ,@email2 NVARCHAR(max)          
  ,@hashedEnquiryids NVARCHAR(max)          
 DECLARE @parentid BIGINT = (          
   SELECT ParentID          
   FROM User_detail(NOLOCK)          
   WHERE User_ID = @userid          
   )          
    drop table if exists #tempEnquiryID
    create table #tempEnquiryID( ROWNO int , enquiryid bigint)
	Declare @min int = 0 , @max int =500 , @count int, @len int = 500
	
 IF @mode = 'enq'          
 BEGIN          
 IF @duplicatetype ='mobile'   
 BEGIN  
   SELECT Mobile.*          
    ,Ue.Enquiryid          
    ,Ue.Personname          
    ,ltrim(trim(isnull(UE.Countrycode, '')) + ' ' + trim(isnull(UE.MobileNO, '')))          
    --+ CASE           
    -- WHEN trim(isnull(UE.MobileNO, '')) <> ''          
    --  THEN ', ...'          
    -- ELSE ''          
    -- END           
    AS MobileNO          
    ,UE.EmailID          
    ,CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15), 7, 7, ' ') AS CreatedDate          
    ,UD.User_Login        
   FROM (          
    SELECT row_number() OVER (          
   PARTITION BY mobile ORDER BY enquiryid ASC          
   ) row          
  ,count(*) OVER (PARTITION BY mobile)-1 cnt          
  ,*          
    FROM userenquiry_mobile_email   (NOLOCK)         
    WHERE Parentid = @parentid          
  AND mobile <> '0'          
         ) Mobile          
  JOIN userenquiry (NOLOCK) UE ON UE.EnquiryID = Mobile.enquiryid          
  LEFT JOIN Usersourcesettings(NOLOCK) Uss ON Ue.Sourcename = Uss.Sourceid          
  LEFT JOIN Usermediumsettings(NOLOCK) Ums ON Ue.Mediumname = Ums.Mediumid          
  LEFT JOIN Usercampaignsettings(NOLOCK) Ucs ON Ue.Campaignname = Ucs.Campaignid          
  LEFT JOIN User_detail(NOLOCK) Ud ON Ue.Createdby = Ud.User_id          
   AND Ue.Parentid = Ud.ParentID          
  LEFT JOIN (          
   SELECT STRING_AGG( cast(Tag as Nvarchar(max)), ',') AS Tags          
    ,etm.EntityID          
   FROM TagMaster(NOLOCK) tm          
   INNER JOIN EntityTagMapping(NOLOCK) etm ON tm.id = etm.TagID          
    AND etm.entity = 'enquiry'          
    AND tm.ParentID = @parentid          
   WHERE ISNULL(etm.EntityID, 0) > 0          
   GROUP BY etm.EntityID          
   ) tg ON tg.EntityID = Ue.EnquiryId          
  WHERE Mobile.row = 1          
   AND MObile.cnt > 0          
   AND (          
    @filtertext IS NULL          
    OR UE.PersonName LIKE '%' + @filtertext + '%'          
    OR Mobile.Mobile LIKE '%' + @filtertext + '%'          
    OR Mobile.email LIKE '%' + @filtertext + '%'          
    )          
 ORDER BY          
   Case          
    WHEN @orderby = 'PersonName' and @ordertype = '2'        
    THEN   Ue.PersonName        
    WHEN @orderby = 'MobileNo' and @ordertype ='2'        
    THEN   UE.MobileNo          
    WHEN @orderby ='EmailID' and @ordertype ='2'        
    THEN   UE.EmailID        
    WHEN @orderby ='City' and @ordertype ='2'        
    THEN   UE.City        
    WHEN @orderby ='State' and @ordertype ='2'        
    THEN  cast( UE.State as nvarchar)        
    WHEN @orderby ='Country' and @ordertype ='2'        
    THEN  cast( UE.Country as nvarchar)        
    WHEN @orderby ='Pincode' and @ordertype ='2'        
    THEN  cast( UE.Pincode as nvarchar)        
    WHEN @orderby ='CreatedBy' and @ordertype ='2'        
    THEN  Ud.User_Login         
    WHEN @orderby ='CreatedDate' and @ordertype ='2'        
    THEN cast( ue.CreatedDate as nvarchar)        
    WHEN @orderby ='enquiryid' and @ordertype ='2'        
    THEN Cast( UE.enquiryid as nvarchar)        
    --else Cast (UE.enquiryid  as nvarchar)        
    end ASC,        
    Case          
    WHEN @orderby = 'PersonName' and @ordertype ='1'        
    THEN   Ue.PersonName        
    WHEN @orderby = 'MobileNo'  and @ordertype ='1'        
    THEN   UE.MobileNo          
    WHEN @orderby ='EmailID' and @ordertype ='1'        
    THEN   UE.EmailID        
    WHEN @orderby ='City' and @ordertype ='1'        
    THEN   UE.City        
    WHEN @orderby ='State' and @ordertype ='1'        
    THEN   UE.[State]        
    WHEN @orderby ='Country' and @ordertype ='1'        
    THEN   UE.Country        
    WHEN @orderby ='Pincode' and @ordertype ='1'        
    THEN cast(  UE.Pincode as nvarchar)        
    WHEN @orderby ='CreatedBy' and @ordertype ='1'        
    THEN Ud.User_Login         
    WHEN @orderby ='CreatedDate' and @ordertype ='1'        
    THEN cast( ue.CreatedDate as nvarchar)        
    WHEN @orderby ='enquiryid' and @ordertype ='1'        
    THEN Cast( UE.enquiryid as nvarchar)        
    --else Cast (UE.enquiryid  as nvarchar)        
    end  desc      
 END  
 IF @duplicatetype='email'  
 BEGIN  
 SELECT Mobile.*          
    ,Ue.Enquiryid          
    ,Ue.Personname          
    ,ltrim(trim(isnull(UE.Countrycode, '')) + ' ' + trim(isnull(UE.MobileNO, '')))          
    --+ CASE           
    -- WHEN trim(isnull(UE.MobileNO, '')) <> ''          
    --  THEN ', ...'          
    -- ELSE ''          
    -- END           
    AS MobileNO          
    ,UE.EmailID          
    ,CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15), 7, 7, ' ') AS CreatedDate          
    ,UD.User_Login        
   FROM(  
  SELECT row_number() OVER (          
     PARTITION BY email ORDER BY enquiryid ASC          
     ) row          
    ,count(*) OVER (PARTITION BY email)-1 cnt          
    ,*          
   FROM userenquiry_mobile_email   (NOLOCK)        
   WHERE Parentid = @parentid          
    AND email <> '1'          
   ) Mobile          
  JOIN userenquiry (NOLOCK) UE ON UE.EnquiryID = Mobile.enquiryid          
  LEFT JOIN Usersourcesettings(NOLOCK) Uss ON Ue.Sourcename = Uss.Sourceid          
  LEFT JOIN Usermediumsettings(NOLOCK) Ums ON Ue.Mediumname = Ums.Mediumid          
  LEFT JOIN Usercampaignsettings(NOLOCK) Ucs ON Ue.Campaignname = Ucs.Campaignid          
  LEFT JOIN User_detail(NOLOCK) Ud ON Ue.Createdby = Ud.User_id          
   AND Ue.Parentid = Ud.ParentID          
  LEFT JOIN (          
   SELECT STRING_AGG(CAst(Tag as NVARCHAR(max)), ',') AS Tags          
    ,etm.EntityID          
   FROM TagMaster(NOLOCK) tm          
   INNER JOIN EntityTagMapping(NOLOCK) etm ON tm.id = etm.TagID          
    AND etm.entity = 'enquiry'          
    AND tm.ParentID = @parentid          
   WHERE ISNULL(etm.EntityID, 0) > 0          
   GROUP BY etm.EntityID          
   ) tg ON tg.EntityID = Ue.EnquiryId          
  WHERE Mobile.row = 1          
   AND MObile.cnt >0  
   AND (          
    @filtertext IS NULL          
    OR UE.PersonName LIKE '%' + @filtertext + '%'          
    OR Mobile.Mobile LIKE '%' + @filtertext + '%'          
    OR Mobile.email LIKE '%' + @filtertext + '%'          
    )          
 ORDER BY          
   Case          
    WHEN @orderby = 'PersonName' and @ordertype = '2'        
    THEN   Ue.PersonName        
    WHEN @orderby = 'MobileNo' and @ordertype ='2'        
    THEN   UE.MobileNo          
    WHEN @orderby ='EmailID' and @ordertype ='2'        
    THEN   UE.EmailID        
    WHEN @orderby ='City' and @ordertype ='2'        
    THEN   UE.City        
    WHEN @orderby ='State' and @ordertype ='2'        
    THEN  cast( UE.State as nvarchar)        
    WHEN @orderby ='Country' and @ordertype ='2'        
    THEN  cast( UE.Country as nvarchar)        
    WHEN @orderby ='Pincode' and @ordertype ='2'        
    THEN  cast( UE.Pincode as nvarchar)        
    WHEN @orderby ='CreatedBy' and @ordertype ='2'        
    THEN  Ud.User_Login         
    WHEN @orderby ='CreatedDate' and @ordertype ='2'        
    THEN cast( ue.CreatedDate as nvarchar)        
    WHEN @orderby ='enquiryid' and @ordertype ='2'        
    THEN Cast( UE.enquiryid as nvarchar)        
    --else Cast (UE.enquiryid  as nvarchar)        
    end ASC,        
    Case          
    WHEN @orderby = 'PersonName' and @ordertype ='1'        
    THEN   Ue.PersonName        
    WHEN @orderby = 'MobileNo'  and @ordertype ='1'        
    THEN   UE.MobileNo          
    WHEN @orderby ='EmailID' and @ordertype ='1'        
    THEN   UE.EmailID        
    WHEN @orderby ='City' and @ordertype ='1'        
    THEN   UE.City        
    WHEN @orderby ='State' and @ordertype ='1'        
    THEN   UE.[State]        
    WHEN @orderby ='Country' and @ordertype ='1'        
    THEN   UE.Country        
    WHEN @orderby ='Pincode' and @ordertype ='1'        
    THEN cast(  UE.Pincode as nvarchar)        
    WHEN @orderby ='CreatedBy' and @ordertype ='1'        
    THEN Ud.User_Login         
    WHEN @orderby ='CreatedDate' and @ordertype ='1'        
    THEN cast( ue.CreatedDate as nvarchar)        
    WHEN @orderby ='enquiryid' and @ordertype ='1'        
    THEN Cast( UE.enquiryid as nvarchar)        
    --else Cast (UE.enquiryid  as nvarchar)        
    end  desc      
 END  
  
