--    THEN Cast( UE.enquiryid as nvarchar)        
--    --else Cast (UE.enquiryid  as nvarchar)        
--    end  desc        
 END          
 ELSE IF @mode = 'dupli'          
 BEGIN          
  SELECT @mobile = mobileno          
   ,@email = emailid          
   ,@mobile1 = MobileNo1          
   ,@email1 = emailid1          
   ,@mobile2 = MobileNo2          
   ,@email2 = EmailID2          
   ,@parentid = parentid          
  FROM UserEnquiry    (NOLOCK)       
  WHERE EnquiryID = @enquiryid          
    
  IF @duplicatetype ='mobile'   
 BEGIN  
  SELECT DISTINCT          
   --Mobile.*,          
   Ue.Enquiryid          
   ,Ue.Personname          
   ,ltrim(trim(isnull(Ue.Countrycode, '')) + ' ' + trim(isnull(Ue.MobileNo, ''))) + CASE           
    WHEN trim(isnull(Ue.MobileNo1, '')) <> ''          
     THEN ', '  +  trim(isnull(Ue.MobileNo1, ''))        
  WHEN trim(isnull(Ue.MobileNo2, '')) <> ''          
     THEN ', '  +  trim(isnull(Ue.MobileNo2, ''))        
    ELSE ''          
    END AS MobileNO          
   ,UE.EmailID + case when TRIM(isnull(UE.EmailID1,''))<>''      
    then ', '+UE.EmailID1       
    when TRIM(isnull(UE.EmailID2,''))<>''      
    then ', '+UE.EmailID2      
    Else '' END As EmailID      
   ,CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15), 7, 7, ' ') AS CreatedDate          
  FROM (          
   SELECT row_number() OVER (          
     PARTITION BY mobile ORDER BY enquiryid ASC          
     ) row          
    ,count(*) OVER (PARTITION BY mobile) cnt          
    ,*          
   FROM userenquiry_mobile_email (NOLOCK)          
   WHERE Parentid = @parentid          
    AND mobile IN (          
     @mobile          
     ,@mobile1          
     ,@mobile2          
     )          
    AND enquiryid <> @enquiryid          
         ) Mobile          
  JOIN userenquiry (NOLOCK) UE ON UE.EnquiryID = Mobile.enquiryid          
  LEFT JOIN Usersourcesettings(NOLOCK) Uss ON Ue.Sourcename = Uss.Sourceid          
  LEFT JOIN Usermediumsettings(NOLOCK) Ums ON Ue.Mediumname = Ums.Mediumid          
  LEFT JOIN Usercampaignsettings(NOLOCK) Ucs ON Ue.Campaignname = Ucs.Campaignid          
  LEFT JOIN User_detail(NOLOCK) Ud ON Ue.Createdby = Ud.User_id          
   AND Ue.Parentid = Ud.ParentID          
  LEFT JOIN (          
   SELECT STRING_AGG(CAST(Tag as nvarchar(max)), ',') AS Tags          
    ,etm.EntityID          
   FROM TagMaster(NOLOCK) tm          
   INNER JOIN EntityTagMapping(NOLOCK) etm ON tm.id = etm.TagID          AND etm.entity = 'enquiry'          
    AND tm.ParentID = @parentid          
   WHERE ISNULL(etm.EntityID, 0) > 0          
   GROUP BY etm.EntityID          
   ) tg ON tg.EntityID = Ue.EnquiryId      
  
 END    
 IF @duplicatetype='email'  
 BEGIN  
  
  
  SELECT DISTINCT          
   --Mobile.*,          
   Ue.Enquiryid          
   ,Ue.Personname          
   ,ltrim(trim(isnull(Ue.Countrycode, '')) + ' ' + trim(isnull(Ue.MobileNo, ''))) + CASE           
    WHEN trim(isnull(Ue.MobileNo1, '')) <> ''          
     THEN ', '  +  trim(isnull(Ue.MobileNo1, ''))        
  WHEN trim(isnull(Ue.MobileNo2, '')) <> ''          
     THEN ', '  +  trim(isnull(Ue.MobileNo2, ''))        
    ELSE ''          
    END AS MobileNO          
   ,UE.EmailID + case when TRIM(isnull(UE.EmailID1,''))<>''      
    then ', '+UE.EmailID1       
    when TRIM(isnull(UE.EmailID2,''))<>''      
    then ', '+UE.EmailID2      
    Else '' END As EmailID      
   ,CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15), 7, 7, ' ') AS CreatedDate          
  FROM (   
   SELECT row_number() OVER (          
     PARTITION BY email ORDER BY enquiryid ASC          
     ) row          
    ,count(*) OVER (PARTITION BY email) cnt          
    ,*          
   FROM userenquiry_mobile_email   (NOLOCK)        
   WHERE Parentid = @parentid          
    AND email IN (          
     @email          
     ,@email1          
     ,@email2          
     )          
    AND enquiryid <> @enquiryid          
   ) Mobile          
  JOIN userenquiry (NOLOCK) UE ON UE.EnquiryID = Mobile.enquiryid          
  LEFT JOIN Usersourcesettings(NOLOCK) Uss ON Ue.Sourcename = Uss.Sourceid          
  LEFT JOIN Usermediumsettings(NOLOCK) Ums ON Ue.Mediumname = Ums.Mediumid          
  LEFT JOIN Usercampaignsettings(NOLOCK) Ucs ON Ue.Campaignname = Ucs.Campaignid          
  LEFT JOIN User_detail(NOLOCK) Ud ON Ue.Createdby = Ud.User_id          
   AND Ue.Parentid = Ud.ParentID          
  LEFT JOIN (          
   SELECT STRING_AGG(CAST(Tag as nvarchar(max)), ',') AS Tags          
    ,etm.EntityID          
   FROM TagMaster(NOLOCK) tm          
   INNER JOIN EntityTagMapping(NOLOCK) etm ON tm.id = etm.TagID          AND etm.entity = 'enquiry'          
    AND tm.ParentID = @parentid          
   WHERE ISNULL(etm.EntityID, 0) > 0          
   GROUP BY etm.EntityID          
   ) tg ON tg.EntityID = Ue.EnquiryId          
   --order by Mobile.enquiryid desc          
 END  
 END          
 ELSE IF @mode = 'duplimerge'          
 BEGIN          
  SELECT @mobile = mobileno          
   ,@email = emailid          
   ,@mobile1 = MobileNo1          
   ,@email1 = emailid1          
   ,@mobile2 = MobileNo2          
   ,@email2 = EmailID2          
   ,@parentid = parentid          
  FROM UserEnquiry  (NOLOCK)         
  WHERE EnquiryID = @enquiryid          
    
  SELECT enquiryid          
   ,personname          
   ,companyname          
   ,mobileno          
   ,mobileno1          
   ,mobileno2          
   ,emailid          
   ,emailid1          
   ,emailid2          
   ,city          
   ,STATE          
   ,country          
   ,countrycode          
   ,countrycode1          
   ,countrycode2          
   ,pincode          
   ,residentialaddress          
   ,officeaddress          
   ,Initialremarks          
  FROM UserEnquiry   (NOLOCK)        
  WHERE EnquiryID = @enquiryid          
          
 IF @duplicatetype ='mobile'   
 BEGIN  
  SELECT DISTINCT Ue.EnquiryID          
   ,Ue.Personname          
   ,Ue.Companyname          
   ,Ue.Mobileno          
   ,ltrim(trim(isnull(Ue.Countrycode, '')) + ' ' + trim(isnull(Ue.Mobileno, ''))) + CASE           
    WHEN trim(isnull(Ue.Mobileno1, '')) <> ''          
     THEN ', ...'          
    ELSE ''          
    END AS MobileNo3          
   ,trim(Ue.Mobileno1) AS Mobileno1          
   ,trim(Ue.Mobileno2) AS Mobileno2          
   ,Ue.Emailid          
   ,Ue.Emailid AS EmailID3          
   ,Ue.Emailid1          
   ,Ue.Emailid2          
   ,Ue.Residentialaddress          
   ,Ue.Officeaddress          
   ,Ue.City          
   ,Ue.[State]          
   ,Ue.Country          
   ,Ue.Countrycode          
   ,Ue.Pincode          
   ,Ue.Initialremarks          
  FROM (          
   SELECT row_number() OVER (          
     PARTITION BY mobile ORDER BY enquiryid ASC          
     ) row          
    ,count(*) OVER (PARTITION BY mobile) cnt          
    ,*          
   FROM userenquiry_mobile_email   (NOLOCK)        
   WHERE Parentid = @parentid          
    AND mobile IN (          
     @mobile          
     ,@mobile1          
     ,@mobile2          
     )          
    AND enquiryid <> @enquiryid          
      ) Mobile          
  JOIN userenquiry (NOLOCK) UE ON UE.EnquiryID = Mobile.enquiryid          
  LEFT JOIN Usersourcesettings(NOLOCK) Uss ON Ue.Sourcename = Uss.Sourceid          
  LEFT JOIN Usermediumsettings(NOLOCK) Ums ON Ue.Mediumname = Ums.Mediumid          
  LEFT JOIN Usercampaignsettings(NOLOCK) Ucs ON Ue.Campaignname = Ucs.Campaignid          
  LEFT JOIN User_detail(NOLOCK) Ud ON Ue.Createdby = Ud.User_id          
   AND Ue.Parentid = Ud.ParentID          
  LEFT JOIN (          
   SELECT STRING_AGG(CAST(Tag AS nvarchar(max)), ',') AS Tags          
    ,etm.EntityID          
   FROM TagMaster(NOLOCK) tm          
   INNER JOIN EntityTagMapping(NOLOCK) etm ON tm.id = etm.TagID          
    AND etm.entity = 'enquiry'          
    AND tm.ParentID = @parentid          
   WHERE ISNULL(etm.EntityID, 0) > 0          
   GROUP BY etm.EntityID          
   ) tg ON tg.EntityID = Ue.EnquiryId     
  END  
      
 IF @duplicatetype='email'  
 BEGIN  
      SELECT DISTINCT Ue.EnquiryID          
   ,Ue.Personname          
   ,Ue.Companyname          
   ,Ue.Mobileno          
   ,ltrim(trim(isnull(Ue.Countrycode, '')) + ' ' + trim(isnull(Ue.Mobileno, ''))) + CASE           
    WHEN trim(isnull(Ue.Mobileno1, '')) <> ''          
     THEN ', ...'          
    ELSE ''          
    END AS MobileNo3          
   ,trim(Ue.Mobileno1) AS Mobileno1          
   ,trim(Ue.Mobileno2) AS Mobileno2          
   ,Ue.Emailid          
   ,Ue.Emailid AS EmailID3          
   ,Ue.Emailid1          
   ,Ue.Emailid2          
   ,Ue.Residentialaddress          
   ,Ue.Officeaddress          
   ,Ue.City          
   ,Ue.[State]          
   ,Ue.Country          
   ,Ue.Countrycode          
   ,Ue.Pincode          
   ,Ue.Initialremarks          
  FROM (         
   SELECT row_number() OVER (          
     PARTITION BY email ORDER BY enquiryid ASC          
    ) row          
    ,count(*) OVER (PARTITION BY email) cnt          
    ,*          
   FROM userenquiry_mobile_email  (NOLOCK)         
   WHERE Parentid = @parentid          
    AND email IN (          
     @email          
     ,@email1          
     ,@email2          
     )          
    AND enquiryid <> @enquiryid          
   ) Mobile          
  JOIN userenquiry (NOLOCK) UE ON UE.EnquiryID = Mobile.enquiryid          
  LEFT JOIN Usersourcesettings(NOLOCK) Uss ON Ue.Sourcename = Uss.Sourceid          
  LEFT JOIN Usermediumsettings(NOLOCK) Ums ON Ue.Mediumname = Ums.Mediumid          
  LEFT JOIN Usercampaignsettings(NOLOCK) Ucs ON Ue.Campaignname = Ucs.Campaignid          
  LEFT JOIN User_detail(NOLOCK) Ud ON Ue.Createdby = Ud.User_id          
   AND Ue.Parentid = Ud.ParentID          
  LEFT JOIN (          
   SELECT STRING_AGG(CAST(Tag as NVARCHAR(max)), ',') AS Tags          
    ,etm.EntityID          
   FROM TagMaster(NOLOCK) tm          
   INNER JOIN EntityTagMapping(NOLOCK) etm ON tm.id = etm.TagID          
    AND etm.entity = 'enquiry'          
    AND tm.ParentID = @parentid          
   WHERE ISNULL(etm.EntityID, 0) > 0          
   GROUP BY etm.EntityID          
   ) tg ON tg.EntityID = Ue.EnquiryId          
   --where Mobile.row > 1           
   --order by Mobile.enquiryid desc       
   END  
 END          
 ELSE IF @mode = 'mergedata'          
 BEGIN          
  UPDATE UserEnquiry          
  SET personname = @personname          
   ,companyname = @companyname          
   ,mobileno = @mobileno          
   ,mobileno1 = @mobileno1          
   ,mobileno2 = @mobileno2          
   ,emailid = @emailid          
   ,emailid1 = @emailid1          
   ,emailid2 = emailid2          
   ,city = city          
   ,STATE = @state          
   ,country = @country          
   ,countrycode = @countrycode          
   ,pincode = @pincode          
   ,residentialaddress = @residentialaddress          
   ,officeaddress = @officeaddress          
   ,Initialremarks = @Initialremarks          
  WHERE EnquiryID = @enquiryid          
          
  SELECT 'Enquiry Merged'          
 END          
 ELSE IF @mode = 'deleteall'          
 BEGIN          
  IF @delby = 'earliest'          
  BEGIN          
   IF @deleteall = '0'          
   BEGIN          
    SELECT count(DISTINCT enquiryid)          
    FROM (          
     SELECT enquiryid          
     FROM (          
      SELECT row_number() OVER (          
        PARTITION BY mobile ORDER BY enquiryid          
        ) row          
       ,count(*) OVER (PARTITION BY mobile) cnt          
       ,*          
      FROM userenquiry_mobile_email  (NOLOCK)         
      WHERE userenquiry_mobile_email.Parentid = @parentid          
       AND userenquiry_mobile_email.mobile <> '0'          
      ) tt          
     WHERE row > 1          
               
     UNION ALL          
               
     SELECT enquiryid          
     FROM (          
      SELECT row_number() OVER (          
        PARTITION BY email ORDER BY enquiryid          
        ) row          
       ,count(*) OVER (PARTITION BY email) cnt          
       ,*          
      FROM userenquiry_mobile_email   (NOLOCK)        
      WHERE userenquiry_mobile_email.Parentid = @parentid          
       AND userenquiry_mobile_email.email <> '1'          
      ) tt          
     WHERE row > 1          
     ) test          
   END          
          
   IF @deleteall = '1'          
   BEGIN          
    Insert into #tempEnquiryID (ROWNO , enquiryid)
    SELECT ROW_NUMBER () OVER (Order by enquiryid desc  ) ROWNO , enquiryid 
    FROM  (          
     SELECT DISTINCT enquiryid          
     FROM (          
      SELECT enquiryid          
      FROM (          
       SELECT row_number() OVER (          
         PARTITION BY mobile ORDER BY enquiryid          
         ) row          
        ,count(*) OVER (PARTITION BY mobile) cnt          
        ,*          
       FROM userenquiry_mobile_email (NOLOCK)          
       WHERE userenquiry_mobile_email.Parentid = @parentid          
        AND userenquiry_mobile_email.mobile <> '0'          
       ) tt          
      WHERE row > 1          
                
      UNION ALL          
                
      SELECT enquiryid          
      FROM (          
       SELECT row_number() OVER (          
         PARTITION BY email ORDER BY enquiryid          
         ) row          
        ,count(*) OVER (PARTITION BY email) cnt          
        ,*          
       FROM userenquiry_mobile_email (NOLOCK)          
       WHERE userenquiry_mobile_email.Parentid = @parentid          
        AND userenquiry_mobile_email.email <> '1'          
       ) tt          
      WHERE row > 1          
      ) Enquryid          
     ) hashedenquiryid          
          
	

	select   @count= Count(rowNo) from #tempEnquiryID 
	CHeckLen:
	if len((Select CONCAT (@parentid ,'$',@userid ,'$', STRING_AGG(cast(enquiryid as nvarchar(max)),'#'))  from #tempEnquiryID where ROWNO between @min and @max)) > 4000
	BEGIN
		set @len=@len/2
		set @max=@len
		--Select 'len', @min ,@max,@len
		Goto CHeckLen
	END
		--Select 'len', @min ,@max,@len,@count
	while @count>0
	BEGIN
		--Select 'value', @min ,@max,@len
		Select @hashedEnquiryids= STRING_AGG(cast(enquiryid as nvarchar(max)),'#') from #tempEnquiryID where ROWNO between @min and @max
		SELECT @hashedEnquiryids = CONCAT (          
      @parentid          
      ,'$'          
      ,@userid          
      ,'$'          
      ,@hashedEnquiryids          
      )          
		 --SELECT len(@hashedEnquiryids)    
		 EXEC Usp_EnquiryDeleteById @CSVID = @hashedEnquiryids          
     ,@Mode = 'criteria'          
		Set @min=@min+@len
		Set @max=@max+@len
		set @count=@count-@len 
	END
   END          
  END          
          
 IF @delby = 'latest'          
 BEGIN          
  IF @deleteall = '0'          
  BEGIN          
   SELECT count(DISTINCT enquiryid)          
   FROM (          
    SELECT enquiryid          
    FROM (          
     SELECT row_number() OVER (          
       PARTITION BY mobile ORDER BY enquiryid DESC          
       ) row          
      ,count(*) OVER (PARTITION BY mobile) cnt          
      ,*          
     FROM userenquiry_mobile_email (NOLOCK)          
     WHERE userenquiry_mobile_email.Parentid = @parentid          
      AND userenquiry_mobile_email.mobile <> '0'          
     ) tt          
    WHERE row > 1          
              
    UNION ALL          
              
    SELECT enquiryid          
    FROM (          
     SELECT row_number() OVER (          
       PARTITION BY email ORDER BY enquiryid DESC          
       ) row          
      ,count(*) OVER (PARTITION BY email) cnt          
      ,*          
     FROM userenquiry_mobile_email (NOLOCK)          
     WHERE userenquiry_mobile_email.Parentid = @parentid          
      AND userenquiry_mobile_email.email <> '1'          
     ) tt          
    WHERE row > 1          
    ) test          
  END          
          
  IF @deleteall = '1'          
  BEGIN          
    Insert into #tempEnquiryID (ROWNO , enquiryid)
  SELECT ROW_NUMBER () OVER (Order by enquiryid desc  ) ROWNO , enquiryid 
   FROM (          
    SELECT DISTINCT enquiryid          
    FROM (          
     SELECT enquiryid          
     FROM (          
      SELECT row_number() OVER (          
        PARTITION BY mobile ORDER BY enquiryid DESC          
        ) row          
       ,count(*) OVER (PARTITION BY mobile) cnt          
       ,*          
      FROM userenquiry_mobile_email  (NOLOCK)         
      WHERE userenquiry_mobile_email.Parentid = @parentid          
       AND userenquiry_mobile_email.mobile <> '0'          
      ) tt          
     WHERE row > 1          
               
     UNION ALL          
               
     SELECT enquiryid          
     FROM (          
      SELECT row_number() OVER (          
        PARTITION BY email ORDER BY enquiryid DESC          
        ) row          
       ,count(*) OVER (PARTITION BY email) cnt          
       ,*          
      FROM userenquiry_mobile_email  (NOLOCK)         
      WHERE userenquiry_mobile_email.Parentid = @parentid          
       AND userenquiry_mobile_email.email <> '1'          
      ) tt          
     WHERE row > 1          
     ) Enquryid          
    ) hashedenquiryid          
         
		 select   @count= Count(rowNo) from #tempEnquiryID 
	CHeckLen2:
	if len((Select  CONCAT (@parentid ,'$',@userid ,'$', STRING_AGG(cast(enquiryid as nvarchar(max)),'#')) from #tempEnquiryID where ROWNO between @min and @max)) > 4000
	BEGIN
		set @len=@len/2
		set @max=@len
		--Select 'len', @min ,@max,@len
		Goto CHeckLen2
	END
		--Select 'len', @min ,@max,@len,@count
	while @count>0
	BEGIN
		--Select 'value', @min ,@max,@len
		Select @hashedEnquiryids= STRING_AGG(cast(enquiryid as nvarchar(max)),'#') from #tempEnquiryID where ROWNO between @min and @max
		SELECT @hashedEnquiryids = CONCAT (          
      @parentid          
      ,'$'          
      ,@userid          
      ,'$'          
      ,@hashedEnquiryids          
      )          
		 --SELECT @hashedEnquiryids    
		EXEC Usp_EnquiryDeleteById @CSVID = @hashedEnquiryids          
			,@Mode = 'criteria'          
		Set @min=@min+@len
		Set @max=@max+@len
		set @count=@count-@len 
	END      
  END          
 END          
          
           
END          
ELSE IF @mode='checkdupli'          
 BEGIN          
          
  SELECT count(DISTINCT enquiryid)          
    FROM (          
     SELECT *          
     FROM (          
      SELECT row_number() OVER (          
        PARTITION BY mobile ORDER BY enquiryid          
        ) row          
       ,count(*) OVER (PARTITION BY mobile) cnt          
   ,*          
      FROM userenquiry_mobile_email  (NOLOCK)         
      WHERE userenquiry_mobile_email.Parentid = @parentid          
       AND userenquiry_mobile_email.mobile <> '0'          
      ) tt          
     WHERE cnt>1          
               
     UNION ALL          
               
     SELECT *          
     FROM (          
      SELECT row_number() OVER (          
        PARTITION BY email ORDER BY enquiryid          
        ) row          
       ,count(*) OVER (PARTITION BY email) cnt          
       ,*          
      FROM userenquiry_mobile_email  (NOLOCK)         
      WHERE userenquiry_mobile_email.Parentid = @parentid          
       AND userenquiry_mobile_email.email <> '1'          
      ) tt          
     WHERE cnt > 1          
     ) test          
 END          
END


