/* ============================================================
   Procedure: [dbo].[usp_ed_GetSetExportDataSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ed_GetSetExportDataSetting](
	@Id bigint = 0,
	@SettingName nvarchar(255) = '',
	@PageUrl nvarchar(255) = '',
	@CsvColumns nvarchar(max) = '',
	@Section nvarchar(255) = '',
	@EntityName nvarchar(255) = '',
	@UserId bigint,
	@Mode nvarchar(25) = 'get'
)
as
begin
	declare @ParentId bigint = 0
		
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId
	if(@Mode = 'set')
	begin
		if(@Id > 0)
		begin
			update tbl_ed_ExportDataSettings set
				SettingName = iif(isnull(@SettingName, '') = '', SettingName, @SettingName),
				PageUrl = iif(isnull(@PageUrl, '') = '', PageUrl, @PageUrl),
				CsvColumns = iif(isnull(@CsvColumns, '') = '', CsvColumns, @CsvColumns),
				Section = iif(isnull(@Section, '') = '', Section, @Section)
			where Id = @Id
		end

		if(isnull(@Id, 0) = 0)
		begin
			insert into tbl_ed_ExportDataSettings( SettingName, PageUrl, CsvColumns, UserId, ParentId, IsDefault)
			select @SettingName, @PageUrl, @CsvColumns, @UserId, @ParentId,
				iif((select count(1) from tbl_ed_ExportDataSettings(nolock) where ParentId = @ParentId
					and UserId = @UserId and PageUrl = @PageUrl and Section = @Section and EntityName = @EntityName ) > 0, 0, 2 )
		end
	end

	if(@Mode = 'get')
	begin
		select * from tbl_ed_ExportDataSettings(nolock)
			where ParentId = @ParentId and UserId = @UserId and PageUrl = @PageUrl 
				--and Section = @Section and EntityName = @EntityName
	end
end




