/* ============================================================
   Procedure: [dbo].[usp_EditLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_EditLeadDetails] (        
 @LeadNo BIGINT        
 ,@ParentID BIGINT        
 ,@PersonName NVARCHAR(200)        
 ,@CompanyName NVARCHAR(500)        
 ,@MobileNo VARCHAR(100)        
 ,@MobileNo1 VARCHAR(100)        
 ,@MobileNo2 VARCHAR(100)        
 ,@EmailID VARCHAR(100)        
 ,@EmailID1 VARCHAR(100)        
 ,@EmailID2 VARCHAR(100)        
 ,@City VARCHAR(100)        
 ,@State VARCHAR(100)        
 ,@Country VARCHAR(100)        
 ,@CountryCode VARCHAR(50)        
 ,@CountryCode1 VARCHAR(50)        
 ,@CountryCode2 VARCHAR(50)        
 ,@PinCode BIGINT        
 ,@ResidentialAddress NVARCHAR(500) = ''        
 ,@OfficialAddress NVARCHAR(500) = ''        
 ,@SourceName BIGINT        
 ,@MediumName BIGINT        
 ,@CampaignName BIGINT        
 ,@ModifiedBy BIGINT        
 ,@custom customleads3 readonly        
 ,@InitialRemarks NVARCHAR(1000) = NULL        
 ,@WhereAddress NVARCHAR(255) = ''        
 ,@WhereLatitude NVARCHAR(255) = ''        
 ,@WhereLongitude NVARCHAR(255) = ''        
 ,@LeadTags NVARCHAR(max) = NULL        
 )        
AS        
BEGIN        
 SET @MobileNo = rtrim(ltrim(@MobileNo))        
 SET @MobileNo1 = rtrim(ltrim(@MobileNo1))        
 SET @MobileNo2 = rtrim(ltrim(@MobileNo2))        
        
 CREATE TABLE #temp (        
  [mobile] VARCHAR(100)        
  ,[email] VARCHAR(100)        
  );        
        
 DECLARE @latitude FLOAT = NULL;        
        
 IF (ISNULL(@WhereLatitude, '') <> '')        
 BEGIN        
  SET @latitude = cast(@WhereLatitude AS FLOAT)        
 END        
        
 DECLARE @longitude FLOAT = NULL;        
        
 IF (ISNULL(@WhereLatitude, '') <> '')        
 BEGIN        
  SET @longitude = cast(@WhereLongitude AS FLOAT)        
 END        
        
 INSERT INTO #temp (        
  [mobile]        
  ,[email]        
  )        
 SELECT CAST(ISNULL([CountryCode], 0) AS NVARCHAR) + CAST(ISNULL(NULLIF([MobileNo], ''), 0) AS NVARCHAR)        
  ,ISNULL(NULLIF([EmailID], ''), 0)        
 FROM UserLeads        
 WHERE [ParentID] = @PARENTID        
  AND [LeadNo] <> @LEADNO        
         
 UNION        
         
 SELECT CAST(ISNULL([CountryCode1], 0) AS NVARCHAR) + CAST(ISNULL(NULLIF([MobileNo1], ''), 0) AS NVARCHAR)        
  ,ISNULL(NULLIF([EmailID1], ''), 0)        
 FROM UserLeads        
 WHERE [ParentID] = @PARENTID        
  AND [LeadNo] <> @LEADNO        
         
 UNION        
         
 SELECT CAST(ISNULL([CountryCode2], 0) AS NVARCHAR) + CAST(ISNULL(NULLIF([MobileNo2], ''), 0) AS NVARCHAR)        
  ,ISNULL(NULLIF([EmailID2], ''), 0)        
 FROM UserLeads        
 WHERE [ParentID] = @PARENTID        
  AND [LeadNo] <> @LEADNO;        
        
 IF EXISTS (        
   SELECT 1        
   FROM UserLeads        
   WHERE [ParentID] = @ParentID        
    AND CAST(ISNULL(@CountryCode, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN (        
     SELECT [Mobile]        
     FROM [#temp]        
     )        
   )        
 BEGIN        
  SELECT 'Lead with Mobile ' + @mobileno + ' already exists';        
        
  GOTO LeadNotInserted;        
 END;        
        
 IF EXISTS (        
   SELECT 1        
   FROM UserLeads        
   WHERE [ParentID] = @ParentID        
    AND CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN (        
     SELECT [Mobile]        
     FROM [#temp]        
     )        
   )        
 BEGIN        
  SELECT 'Lead with Mobile ' + @mobileno1 + ' already exists';        
        
  GOTO LeadNotInserted;        
 END;        
        
 IF EXISTS (        
   SELECT 1        
   FROM UserLeads        
   WHERE [ParentID] = @ParentID        
    AND CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN (        
     SELECT [Mobile]        
     FROM [#temp]        
     )        
   )        
 BEGIN        
  SELECT 'Lead with Mobile ' + @mobileno2 + ' already exists';        
        
  GOTO LeadNotInserted;        
 END;        
        
 IF EXISTS (        
   SELECT 1        
   FROM UserLeads        
   WHERE [ParentID] = @ParentID        
    AND CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN (        
     SELECT [email]        
     FROM [#temp]        
     )        
   )        
 BEGIN        
  SELECT 'Lead with Email ' + @EmailID + ' already exists';        
        
  GOTO LeadNotInserted;        
 END;        
       
 IF EXISTS (        
   SELECT 1        
   FROM UserLeads        
   WHERE [ParentID] = @ParentID        
    AND CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN (        
     SELECT [email]        
     FROM [#temp]        
     )        
   )        
 BEGIN        
  SELECT 'Lead with Email ' + @EmailID1 + ' already exists';        
        
  GOTO LeadNotInserted;        
 END;        
        
 IF EXISTS (        
   SELECT 1        
   FROM UserLeads        
   WHERE [ParentID] = @ParentID        
    AND CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN (        
     SELECT [email]        
     FROM [#temp]        
     )        
   )        
 BEGIN        
  SELECT 'Lead with Email ' + @EmailID2 + ' already exists';        
        
  GOTO LeadNotInserted;        
 END;        
        
 UPDATE UserLeads        
 SET [PersonName] = @PersonName        
  ,[CompanyName] = @CompanyName        
  ,[MobileNo] = @MobileNo        
  ,[MobileNo1] = @MobileNo1        
  ,[MobileNo2] = @MobileNo2        
  ,[CampaignNAME] = @CampaignName        
  ,[EmailID] = @EmailID        
  ,[EmailID1] = @EmailID1        
  ,[EmailID2] = @EmailID2        
  ,[City] = @City        
  ,STATE = @State        
  ,[Country] = @Country        
  ,[SourceName] = @SourceName        
  ,[CountryCode] = @CountryCode        
  ,[CountryCode1] = @CountryCode1        
  ,[CountryCode2] = @CountryCode2        
  ,[PinCode] = @PinCode        
  ,[MediumName] = @MediumName        
  ,InitialRemarks = CASE         
   WHEN @InitialRemarks IS NULL        
    THEN InitialRemarks        
   ELSE @InitialRemarks        
   END        
  ,[ResidentialAddress] = CASE         
   WHEN @ResidentialAddress != ''        
    THEN @ResidentialAddress        
   ELSE [ResidentialAddress]        
   END        
  ,[OfficeAddress] = CASE         
   WHEN @OfficialAddress != ''        
    THEN @OfficialAddress        
   ELSE [OfficeAddress]        
   END        
  ,[ModifiedOn] = GETDATE()        
  ,[ModifiedBy] = @ModifiedBy        
  ,whereAddress = @WhereAddress        
  ,latitude = @latitude        
  ,longitude = @longitude        
 WHERE [LeadNo] = @LeadNo        
  AND [ParentID] = @ParentID;        
        
 DECLARE @LeadId BIGINT = (        
   SELECT TOP 1 ID        
   FROM UserLeads(NOLOCK)        
   WHERE [LeadNo] = @LeadNo        
    AND [ParentID] = @ParentID        
   )        
        
 PRINT '@@ROWCOUNT - UserLeads:- ' + cast(@@ROWCOUNT AS VARCHAR)        
        
    DROP TABLE IF EXISTS #update;
    DROP TABLE IF EXISTS #insert;

    -- Rows where LeadID+fieldID already exist → UPDATE
    SELECT * INTO #update
    FROM @custom c
    WHERE EXISTS (
        SELECT 1 
        FROM customfieldLeadvalue cf
        WHERE cf.LeadID = c.LeadID
          AND cf.fieldID = c.fieldID
    );

    -- Rows where LeadID+fieldID don't exist → INSERT
    SELECT * INTO #insert
    FROM @custom c
    WHERE NOT EXISTS (
        SELECT 1 
        FROM customfieldLeadvalue cf
        WHERE cf.LeadID = c.LeadID
          AND cf.fieldID = c.fieldID
    );     
        
 /* Start Lead activity Lead added  */        
 IF (ISNULL(@LeadTags, '') <> '')        
 BEGIN        
  DROP TABLE        
        
  IF EXISTS #tempTagName        
   SELECT tn.*        
    ,tm.ID AS tagId        
    ,0 AS isProcess        
   INTO #tempTagName        
   FROM (        
    SELECT [position] AS [id]        
     ,LTRIM(RTRIM(iif(CHARINDEX(':', [value], 1) = 0, [value], SUBSTRING([value], 1, CHARINDEX(':', [value], 1) - 1)))) AS [tagName]        
    FROM fn_Split(@LeadTags, ',')        
    ) AS tn        
   LEFT JOIN TagMaster(NOLOCK) tm ON tm.ParentID = @ParentID        
    AND lower(tm.Tag) = lower(tagName)        
        
  WHILE (        
    EXISTS (        
     SELECT *        
     FROM #tempTagName        
     WHERE isProcess = 0        
     )        
    )   
  BEGIN        
   DECLARE @tId INT        
    ,@tTagName NVARCHAR(255)        
    ,@tagId BIGINT        
        
   SELECT TOP 1 @tId = id        
    ,@tTagName = tagName        
    ,@tagId = tagId        
   FROM #tempTagName        
   WHERE isProcess = 0        
        
   PRINT @tTagName        
        
   IF (@tagId IS NULL)        
   BEGIN        
    INSERT INTO TagMaster (        
     Tag        
     ,ParentID        
     ,CreatedDate        
     ,CreatedBy        
     )        
    VALUES (        
     @tTagName        
     ,@ParentID        
     ,getdate()        
     ,@ParentID        
     )        
        
    DECLARE @sId BIGINT = scope_identity()        
        
    UPDATE #tempTagName        
    SET tagId = @sId        
    WHERE id = @tId        
   END        
        
   UPDATE #tempTagName        
   SET isProcess = 1        
   WHERE id = @tId        
  END        
        
  DELETE EntityTagMapping        
  WHERE EntityID = @LeadId        
   AND lower(Entity) = 'lead'        
        
  INSERT INTO EntityTagMapping (        
   EntityID        
   ,Entity        
   ,TagID        
   ,CreatedDate        
   )        
  SELECT @LeadId        
   ,'lead'        
   ,tagId        
   ,getdate()        
  FROM #tempTagName        
 END        
        
    DECLARE @updatecount SMALLINT;        
    DECLARE @insertcount SMALLINT;        

    SELECT @updatecount = ISNULL(COUNT([fieldID]), 0) FROM #update;        
    SELECT @insertcount = ISNULL(COUNT([fieldID]), 0) FROM #insert;        

    IF @updatecount > 0        
    BEGIN        
        UPDATE customfieldLeadvalue        
        SET [fieldvalue] = [r].[fieldvalue]        
        FROM [#update] [r]        
        WHERE customfieldLeadvalue.LeadID = r.LeadID        
          AND customfieldLeadvalue.fieldID = r.fieldID;        
    END;        

    IF @insertcount > 0        
    BEGIN        
        INSERT INTO customfieldLeadvalue (LeadID, EnquiryID, fieldID, fieldvalue)        
        SELECT LeadID, EnquiryID, fieldID, fieldvalue 
        FROM #insert;        
    END;       
       
        
 SELECT 'Record Updated';        
        
 DECLARE @rowJson NVARCHAR(MAX) = (        
   select *    
   FROM UserLeads        
   WHERE LeadNo = @LeadNo        
    AND ParentID = @ParentID        
   FOR JSON AUTO        
    ,INCLUDE_NULL_VALUES        
   )        
 DECLARE @userId NVARCHAR(MAX) = (        
   SELECT Createdby        
   FROM UserLeads        
   WHERE LeadNo = @LeadNo        
    AND ParentID = @ParentID        
   )        
        
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @user_id = @userId        
  ,@Activity_type = 'Updt_Lead'        
  ,@ActionType = 'U'        
  ,@RowJson = @rowJson        
  ,@Table_name = 'UserLeads'        
        
 LeadNotInserted:        
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_EditLeadDetails_MOB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_EditLeadDetails_MOB]              
(                      
 @LeadNo BIGINT,          
 @ParentID BIGINT,          
 @PersonName VARCHAR(100),  
 @PersonImage VARCHAR(100)= '',  
 @CompanyName VARCHAR(100),          
 @MobileNo VARCHAR(100),          
 @MobileNo1 VARCHAR(100),          
 @MobileNo2 VARCHAR(100),          
 @EmailID VARCHAR(100),          
 @EmailID1 VARCHAR(100),          
 @EmailID2 VARCHAR(100),          
 @City VARCHAR(100),          
 @State VARCHAR(100),          
 @Country VARCHAR(100),          
 @CountryCode VARCHAR(50),          
 @CountryCode1 VARCHAR(50),          
 @CountryCode2 VARCHAR(50),          
 @PinCode BIGINT,          
 @ResidentialAddress VARCHAR(500) = '',      
 @OfficialAddress VARCHAR(500) = '',      
 @SourceName BIGINT,          
 @MediumName BIGINT,          
 @CampaignName BIGINT,          
 @ModifiedBy BIGINT,          
 @custom customleads3 readonly,          
 @InitialRemarks varchar(1000)=null,      
 @WhereAddress       NVARCHAR(255) = '',        
 @WhereLatitude      NVARCHAR(255) = '',        
 @WhereLongitude     NVARCHAR(255) = '',        
 @LeadTags        NVARCHAR(max) = null      
)                      
AS                      
BEGIN 

	--declare 
	--@custom dbo.customleads3
	--insert into @custom values(N'10553022',NULL,N'377',N'0')
	--insert into @custom values(N'10553022',NULL,N'2009',N'Male')
	--insert into @custom values(N'10553022',NULL,N'5288',N'0')
	--insert into @custom values(N'10553022',NULL,N'2691',N'0')
	--insert into @custom values(N'10553022',NULL,N'4085',N'0')
	--insert into @custom values(N'10553022',NULL,N'4488',N'test')
	--insert into @custom values(N'10553022',NULL,N'5057',NULL)
	--insert into @custom values(N'10553022',NULL,N'5155',N'0')
	--insert into @custom values(N'10553022',NULL,N'5156',N'0')
	--insert into @custom values(N'10553022',NULL,N'5235',NULL)
	--insert into @custom values(N'10553022',NULL,N'5236',NULL)
	--insert into @custom values(N'10553022',NULL,N'5237',N'0')
	--insert into @custom values(N'10553022',NULL,N'5252',N'0')
	--insert into @custom values(N'10553022',NULL,N'5286',N'0')
	--insert into @custom values(N'10553022',NULL,N'5287',N'0')

	--declare 
	-- @LeadNo BIGINT = 109228,          
	-- @ParentID BIGINT = 32222,          
	-- @PersonName VARCHAR(100) = N'Sanjay Patel',
	-- @PersonImage VARCHAR(100) = N'person.png',
	-- @CompanyName VARCHAR(100) = N'Connecttodigital',
	-- @MobileNo VARCHAR(100) = N'9998101009',
	-- @MobileNo1 VARCHAR(100) = N'9998101010',
	-- @MobileNo2 VARCHAR(100) = N'asdfs',
	-- @EmailID VARCHAR(100) = N'sanjay@connecttodigital.in',
	-- @EmailID1 VARCHAR(100) = N'',
	-- @EmailID2 VARCHAR(100) = N'',
	-- @City VARCHAR(100) = N'',
	-- @State VARCHAR(100) = N'',
	-- @Country VARCHAR(100) = N'',
	-- @CountryCode VARCHAR(50) = N'+91',
	-- @CountryCode1 VARCHAR(50) = N'+91',
	-- @CountryCode2 VARCHAR(50) = N'',
	-- @PinCode BIGINT = N'0',
	-- @ResidentialAddress VARCHAR(500) = N'',
	-- @OfficialAddress VARCHAR(500) = N'Ankit',
	-- @SourceName BIGINT = N'595754',
	-- @MediumName BIGINT = N'',
	-- @CampaignName BIGINT = N'',
	-- @ModifiedBy BIGINT = 32222,
	-- @InitialRemarks varchar(1000) = '',
	-- @WhereAddress       NVARCHAR(255) = '',
	-- @WhereLatitude      NVARCHAR(255) = '',
	-- @WhereLongitude     NVARCHAR(255) = '',
	-- @LeadTags        NVARCHAR(max) = 0



              
  set @MobileNo = dbo.fnGetNumericValue(@MobileNo)               
  set @MobileNo1 = dbo.fnGetNumericValue(@MobileNo1)      
  set @MobileNo2 = dbo.fnGetNumericValue(@MobileNo2)   
  
  if(cast(@MobileNo as bigint) = 0)
  begin
	set @MobileNo = ''
  end

  if(cast(@MobileNo1 as bigint) = 0)
  begin
	set @MobileNo1 = ''
  end

  if(cast(@MobileNo2 as bigint) = 0)
  begin
	set @MobileNo2 = ''
  end
  
  
print concat('@MobileNo => ', @MobileNo)
print concat('@MobileNo1 => ', @MobileNo1)
print concat('@MobileNo2 => ', @MobileNo2)
   
drop table if exists #temp
CREATE TABLE #temp               
(               
    [mobile] VARCHAR(100) ,               
    [email]  VARCHAR(100)              
);              
           
declare @latitude float = null;      
if(ISNULL(@WhereLatitude, '') <> '')      
begin      
 set @latitude = cast(@WhereLatitude as float)      
end      
declare @longitude float = null;      
if(ISNULL(@WhereLatitude, '') <> '')      
begin      
 set @longitude = cast(@WhereLongitude as float)       
end      
      
INSERT INTO #temp ( [mobile] , [email] )               
       SELECT CAST(ISNULL([CountryCode] , 0) AS NVARCHAR) + CAST(ISNULL(NULLIF([MobileNo] , '') , 0) AS NVARCHAR) , ISNULL(NULLIF([EmailID] , '') , 0)              
       FROM UserLeads              
       WHERE [ParentID] = @PARENTID AND  [LeadNo] <> @LEADNO              
       UNION              
       SELECT CAST(ISNULL([CountryCode1] , 0) AS NVARCHAR) + CAST(ISNULL(NULLIF([MobileNo1] , '') , 0) AS NVARCHAR) , ISNULL(NULLIF([EmailID1] , '') , 0)              
       FROM UserLeads              
       WHERE [ParentID] = @PARENTID AND  [LeadNo] <> @LEADNO              
       UNION              
       SELECT CAST(ISNULL([CountryCode2] , 0) AS NVARCHAR) + CAST(ISNULL(NULLIF([MobileNo2] , '') , 0) AS NVARCHAR) , ISNULL(NULLIF([EmailID2] , '') , 0)              
       FROM UserLeads              
       WHERE [ParentID] = @PARENTID AND [LeadNo] <> @LEADNO;  
	   
           
IF EXISTS ( SELECT 1 FROM UserLeads WHERE [ParentID] = @ParentID 
	AND CAST(ISNULL(@CountryCode , 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo , 1) AS NVARCHAR) IN ( SELECT [Mobile]FROM [#temp]) )              
BEGIN 
    SELECT 'Lead with Mobile ' + @MobileNo + ' already exists', 0 as [Status];              
    GOTO LeadNotInserted;              
END;              
              
IF EXISTS ( SELECT 1 FROM UserLeads WHERE [ParentID] = @ParentID AND  CAST(ISNULL(@CountryCode1 , 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1 , 1) AS NVARCHAR) IN ( SELECT [Mobile] FROM [#temp]) )              
BEGIN    
    SELECT 'Lead with Mobile ' + @MobileNo1 + ' already exists', 0 as [Status];
    GOTO LeadNotInserted;              
END;           
IF EXISTS ( SELECT 1 FROM UserLeads WHERE [ParentID] = @ParentID  AND CAST(ISNULL(@CountryCode2 , 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2 , 1) AS NVARCHAR) IN ( SELECT [Mobile] FROM [#temp]) )              
BEGIN   
    SELECT 'Lead with Mobile ' + @MobileNo2 + ' already exists', 0 as [Status]
    GOTO LeadNotInserted;              
END;              
              
IF EXISTS ( SELECT 1 FROM UserLeads WHERE [ParentID] = @ParentID AND CAST(ISNULL(NULLIF(@EmailID , '') , 1) AS NVARCHAR) IN ( SELECT [email] FROM [#temp]))               
BEGIN              
    SELECT 'Lead with Email ' + @EmailID + ' already exists', 0 as [Status]
GOTO LeadNotInserted;              
END;              
              
IF EXISTS ( SELECT 1 FROM UserLeads WHERE [ParentID] = @ParentID AND  CAST(ISNULL(NULLIF(@EmailID1 , '') , 1) AS NVARCHAR) IN ( SELECT [email] FROM [#temp]))               
BEGIN              
    SELECT 'Lead with Email ' + @EmailID1 + ' already exists', 0 as [Status] 
    GOTO LeadNotInserted;              
END;              
              
IF EXISTS ( SELECT 1 FROM UserLeads WHERE [ParentID] = @ParentID AND CAST(ISNULL(NULLIF(@EmailID2 , '') , 1) AS NVARCHAR) IN ( SELECT [email] FROM [#temp]))               
BEGIN              
    SELECT 'Lead with Email ' + @EmailID2 + ' already exists', 0 as [Status]
    GOTO LeadNotInserted;              
END;  


              
UPDATE UserLeads SET       
  [PersonName] = @PersonName,       
  [CompanyName] = @CompanyName,
  [ProfileImgFileName] =  (case when @PersonImage = '' then ProfileImgFileName else @PersonImage end),
  [MobileNo] = @MobileNo,       
  [MobileNo1] = @MobileNo1,      
  [MobileNo2] = @MobileNo2,      
  [CampaignNAME] = @CampaignName,      
  [EmailID] = @EmailID,      
  [EmailID1] = @EmailID1,      
  [EmailID2] = @EmailID2,      
  [City] = @City,      
  STATE = @State,      
  [Country] = @Country,      
  [SourceName] = @SourceName,      
  [CountryCode] = @CountryCode,      
  [CountryCode1] = @CountryCode1,      
  [CountryCode2] = @CountryCode2,      
  [PinCode] = @PinCode,      
  [MediumName] = @MediumName,      
  InitialRemarks= case when @InitialRemarks is null then InitialRemarks else @InitialRemarks end,      
  [ResidentialAddress] = case when @ResidentialAddress != '' then @ResidentialAddress else [ResidentialAddress] end,      
  [OfficeAddress] = case when @OfficialAddress != '' then @OfficialAddress else [OfficeAddress] end,      
  [ModifiedOn] = GETDATE(), [ModifiedBy] = @ModifiedBy,      
  whereAddress = @WhereAddress,      
  latitude = @latitude,      
  longitude = @longitude      
 WHERE [LeadNo] = @LeadNo AND [ParentID] = @ParentID;              
       
declare @LeadId bigint = (select top 1 ID from UserLeads(nolock) where [LeadNo] = @LeadNo AND [ParentID] = @ParentID)      
      
print '@@ROWCOUNT - UserLeads:- ' + cast(@@ROWCOUNT as varchar)              
              
SELECT *              
INTO [#update]              
FROM @custom;              
              
SELECT *              
INTO [#insert]              
FROM @custom              
WHERE [fieldID] NOT IN ( SELECT ISNULL([fieldID] , 0)              
                         FROM [customfieldLeadvalue]              
                         WHERE [LeadID] IN ( SELECT DISTINCT [LeadID] FROM @custom)              
                       );              
              
DELETE FROM #update WHERE [LeadID] IN ( SELECT [LeadID] FROM [#insert]);              
              
    /* Start Lead activity Lead added  */       
       
if(ISNULL(@LeadTags, '') <> '')      
begin      
 drop table if exists #tempTagName      
 select tn.*, tm.ID as tagId, 0 as isProcess  into #tempTagName from ( select [position] as [id],  LTRIM(RTRIM(      
  iif(      
   CHARINDEX(':', [value],  1 ) = 0 ,       
   [value],       
   SUBSTRING([value], 1, CHARINDEX(':', [value],  1 ) - 1)      
  ))) as [tagName]       
 from fn_Split(@LeadTags, ',') ) as tn       
 left join TagMaster(nolock) tm on tm.ParentID = @ParentID and lower(tm.Tag) = lower(tagName)      
      
 while(exists(select * from #tempTagName where isProcess = 0))      
 begin      
  declare @tId int, @tTagName nvarchar(255), @tagId bigint      
  select top 1 @tId = id, @tTagName = tagName, @tagId = tagId from #tempTagName where isProcess = 0      
      
  print @tTagName      
      
  if(@tagId is null)      
  begin      
   insert into TagMaster(Tag, ParentID, CreatedDate, CreatedBy)      
    values ( @tTagName, @ParentID, getdate(), @ParentID )      
      
   declare @sId bigint =  scope_identity()      
   update #tempTagName set tagId = @sId where id = @tId      
  end      
  update #tempTagName set isProcess = 1 where id = @tId      
 end      
      
 delete EntityTagMapping where EntityID = @LeadId and lower(Entity) = 'lead'      
      
 insert into EntityTagMapping(EntityID, Entity, TagID, CreatedDate)      
  select @LeadId, 'lead', tagId, getdate() from #tempTagName      
      
end      
      
      
DECLARE @updatecount SMALLINT;              
DECLARE @insertcount SMALLINT;              
              
SELECT @updatecount = ISNULL(COUNT([fieldID]) , 0) FROM #update;              
              
SELECT @insertcount = ISNULL(COUNT([fieldID]) , 0) FROM #insert;              
              
IF @updatecount > 0              
BEGIN              
    UPDATE customfieldLeadvalue              
            SET [fieldvalue] = [r].[fieldvalue]              
    FROM [#update] [r]              
    WHERE [customfieldLeadvalue].[LeadID] = [r].[LeadID] AND               
            [customfieldLeadvalue].[fieldID] = [r].[fieldID];              
END;              
              
IF @insertcount > 0              
BEGIN              
    INSERT INTO customfieldLeadvalue ( [LeadID] , [EnquiryID] , [fieldID] , [fieldvalue])               
    SELECT * FROM #insert;              
END;              
              
DROP TABLE #update;              
DROP TABLE #insert;              
              
--SELECT 'Lead Updated Successfully';       
    SELECT 'Record Updated', 1 as [Status];          
              
LeadNotInserted:              
              
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_em_GetEmailDetailForParsing]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_em_GetEmailDetailForParsing(
	@MessageId nvarchar(255)
)
as
begin
	select Top 1 ud.ParentID, e.ToAddr, e.FromAddr, e.CreatedTime, e.MailSubject, e.MailContentText, e.MailContentHtml, e.MessageId from MYSMST.dbo.Tbl_Email(nolock) e
		inner join MYSMST.dbo.Tbl_EmailConnectionSettings(nolock) ecs on e.EmailConnectionId = ecs.Id
		inner join MySMS.dbo.User_Detail(nolock) ud on ecs.UserId = ud.User_ID
		where e.MessageId = @MessageId Order by e.Id desc
end



GO

/* ============================================================
   Procedure: [dbo].[usp_em_SendAssignedTaskNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_em_SendAssignedTaskNotification(@TaskHistoryId BIGINT)
AS
    BEGIN
        DECLARE @TaskTitle NVARCHAR(255), @CreatedOn DATETIME, @u_id BIGINT, @message NVARCHAR(MAX)= '', @subject NVARCHAR(255), @scheduleddate DATETIME= DATEADD(minute, 2, GETDATE()), @SchTime TIME= CAST(DATEADD(minute, 2, GETDATE()) AS TIME), @IsTask bit = 0;
        SELECT @TaskTitle = Title, 
               @CreatedOn = CreatedOn, 
               @u_id = AssignedTo,
			   @IsTask = IsTask
        FROM tbl_tsk_TaskHistory
        WHERE AssignedTo = @TaskHistoryId;

		declare @FirstName nvarchar(255)
			SELECT @FirstName = FName FROM User_Detail(nolock) where User_ID = @u_id

		set @subject = 'Task Notification {'+ @TaskTitle +'}';
		set @message =  'Dear '+ @FirstName ;
		set	@message += 'A '+ IIF(@IsTask = 1, 'Task', 'Appointment' ) + ' is assigned to you with title of ' +@TaskTitle;




        DECLARE @ToEmailID VARCHAR(MAX), @type VARCHAR(100)= '1';
        DECLARE @mailbal BIGINT, @TotalEmailIds BIGINT= 1;
        SELECT @mailbal = dbo.fn_GetMailBalance(@u_id);
        IF(@mailbal >= @TotalEmailIds)
            BEGIN
                IF EXISTS
                (
                    SELECT *
                    FROM MySMST.dbo.Tbl_EmailConnectionSettings
                    WHERE UserId = @u_id
                )
                    BEGIN
                        DECLARE @EmailId VARCHAR(MAX);
                        SELECT @EmailId = Email
                        FROM MySMST.dbo.Tbl_EmailConnectionSettings
                        WHERE UserId = @u_id
                              AND IsDefault = 1;
                        EXEC [usp_SendScheduledEmailNotification] 
                             @u_id, 
                             @message, 
                             @subject, 
                             @EmailId, 
                             @scheduleddate, 
                             @SchTime, 
                             @type;
                END;
                DROP TABLE #tempMobileIds;
        END;
            ELSE
            BEGIN
                PRINT @mailbal;
        END;
    END;


GO

/* ============================================================
   Procedure: [dbo].[usp_em_SendEmailForParsing]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_em_SendEmailForParsing(
	@ParentId bigint,
	@FromMail nvarchar(255),
	@ToEmail nvarchar(255),
	@MailDate nvarchar(50),
	@MailSubject nvarchar(max),
	@MailContent nvarchar(max),
	@HtmlBody nvarchar(max),
	@MessageId nvarchar(255)
)
as
begin
	if(not exists(select * from MySMS.dbo.UserMails(nolock) where MessageID = @MessageId))
	begin
		insert into MySMS.dbo.UserMails(UserID, FromMail, ToEmail, MailDate, MailSubject, MailContent, HTMLBody, MessageID, IsFiltered, IsSample, EmailCount)
			values(@ParentId, @FromMail, @ToEmail, @MailDate, @MailSubject, @MailContent, @HtmlBody, @MessageId, 0, 0, 0)

		select SCOPE_IDENTITY() as [UserMailId]
	end
end



