/* ============================================================
   Procedure: [dbo].[usp_email_InQueueCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_email_InQueueCount ( 
 @emBatchIds nvarchar(max) 
) 
as 
begin 
select * from ( 
 SELECT b.[value] as BatchID, COUNT( 1 ) AS inqueue 
 FROM mysms.dbo.emailsfilter AS e with (nolock) JOIN ( select [value] from fn_Split(@emBatchIds, ',')) AS b ON b.[value]=e.Mail_BatchID 
 GROUP BY b.[value] 
 UNION 
 SELECT b.[value], COUNT( 1 ) AS inqueue 
 FROM mysmstrans.dbo.Mail_EmailsReport00 AS e with (nolock) JOIN ( select [value] from fn_Split(@emBatchIds, ',')) AS b 
 ON b.[value]=e.Mail_BatchID 
 GROUP BY b.[value] 
 UNION 
 SELECT b.[value], COUNT( 1 ) AS inqueue 
 FROM mysmstrans.dbo.Mail_EmailsReport01 AS e with (nolock) 
 JOIN ( select [value] from fn_Split(@emBatchIds, ',')) AS b 
 ON b.[value] = e.Mail_BatchID 
 GROUP BY b.[value] 
 UNION 
 SELECT b.[value], COUNT( 1 ) AS inqueue 
 FROM mysmstrans.dbo.Mail_EmailsReport02 AS e with (nolock) JOIN ( select [value] from fn_Split(@emBatchIds, ',')) AS b 
 ON b.[value]=e.Mail_BatchID 
 GROUP BY b.[value] 
 UNION 
 SELECT b.[value], COUNT( 1 ) AS inqueue 
 FROM mysmstrans.dbo.Mail_EmailsReport03 AS e with (nolock) JOIN ( select [value] from fn_Split(@emBatchIds, ',')) AS b 
 ON b.[value]=e.Mail_BatchID 
 GROUP BY b.[value] 
 UNION 
 SELECT b.[value], COUNT( 1 ) AS inqueue 
 FROM mysmstrans.dbo.Mail_EmailsReport04 AS e with (nolock) JOIN ( select [value] from fn_Split(@emBatchIds, ',')) AS b 
 ON b.[value] = e.Mail_BatchID 
 GROUP BY b.[value] 
 UNION 
 SELECT b.[value], COUNT( 1 ) AS inqueue 
 FROM mysmstrans.dbo.Mail_EmailsReport05 AS e with (nolock) JOIN ( select [value] from fn_Split(@emBatchIds, ',')) AS b 
 ON b.[value] = e.Mail_BatchID 
 GROUP BY b.[value] 
 UNION 
 SELECT b.[value] , COUNT( 1 ) AS inqueue 
 FROM mysmstrans.dbo.Mail_EmailsReport2 AS e with (nolock) 
 JOIN ( select [value] from fn_Split(@emBatchIds, ',')) AS b 
 ON b.[value]=e.Mail_BatchID 
 GROUP BY b.[value] 
 UNION 
 SELECT b.[value], COUNT( 1 ) AS inqueue 
 FROM mysmstrans.dbo.Mail_EmailsReport1 AS e with (nolock) JOIN ( select [value] from fn_Split(@emBatchIds, ',')) AS b 
 ON b.[value]=e.Mail_BatchID 
 GROUP BY b.[value] ) as iq 
end 



