/* ============================================================
   Procedure: [dbo].[Usp_EmailDeliveryStatusToBeSaved]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_EmailDeliveryStatusToBeSaved] 
( 
 @API_Header nvarchar(500), 
 @BatchID nvarchar(100), 
 @message_id nvarchar(200), 
 @cust_ref_id nvarchar(200), 
 @event_status nvarchar(500), 
 @event_code nvarchar(200), 
 @event_desc nvarchar(1000), 
 @accept_time nvarchar(100), 
 @event_time nvarchar(100), 
 @Reason nvarchar(500) 
) 
as 
Begin 
set @event_time=nullif(@event_time,'null') 
RETRY: 
BEGIN TRY 
BEGIN TRAN 
 
 -- select top 1 @BatchID=mail_batchid from mysmstrans.dbo.EmailsReportSent with (nolock) 
  -- where Mail_GUID=@cust_ref_id order by SentMail_ID desc 

     	  select top 1 @BatchID=BatchID from 
	   (
	     select BatchID, Email_Id, UserId from ClientEmails with (nolock) where GUID=@cust_ref_id 
	        union   
          select BatchID, Email_Id, UserId from ThirtyDaysClientEmails with (nolock) where GUID=@cust_ref_id    
	   ) as tbl  
	   
	     if(isnull(@batchid,'')='' or @batchid='null')
	      begin
		       select  @batchid = case when charindex('~',@cust_ref_id) <> 0
	                  then (select  value from fn_split(@cust_ref_id,'~') where Position = 2)
					  else
					     @cust_ref_id 
					  end 
           end


COMMIT 
END TRY 
BEGIN CATCH 
IF @@TRANCOUNT>0 
ROLLBACK 
EXECUTE USP_INSERTERRORINFO; 
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number 
BEGIN 
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms 
GOTO RETRY -- Go to Label RETRY 
END 
END CATCH 
 
 
 
 insert into EmailDeliveryStatus 
 ( 
 API_Header , 
 BatchID , 
 message_id , 
 cust_ref_id , 
 event_status , 
 event_code , 
 event_desc , 
 accept_time , 
 event_time , 
 Reason 
 ) 
 values 
 ( 
 
 @API_Header , 
 @BatchID , 
 @message_id , 
 @cust_ref_id , 
 @event_status , 
 @event_code , 
 @event_desc , 
 @accept_time , 
 @event_time , 
 @Reason 
 
 ) 
 
 select 'Data Saved' 
 
End 




GO

/* ============================================================
   Procedure: [dbo].[Usp_EmailDeliveryStatusToBeSaved_KarixAPI]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*
Procedure Name		: Usp_EmailDeliveryStatusToBeSaved_KarixAPI
Parameter(s)		: NIL

Initial Version		:

Revision Date		: 2025-01-14
Revision Remarks	: 1. Data type for the parameter BatchID in ClientEmails table update modified to NVARCHAR(40) 
						for better plan to minimize blocking
*/
CREATE   PROCEDURE [dbo].[Usp_EmailDeliveryStatusToBeSaved_KarixAPI]                    
(                    
   @to_email nvarchar(max),                
   --@API_Header nvarchar(500),                     
   --@BatchID nvarchar(100),                    
   @message_id nvarchar(200),                    
   @cust_ref_id nvarchar(200),                    
   @event_status nvarchar(500),                    
   @event_code nvarchar(200),                    
   @event_desc nvarchar(1000),                    
   @accept_time nvarchar(100),                    
   @event_time nvarchar(100)                    
   --@Reason nvarchar(500),                  
   --@message_tag1 nvarchar(500),                  
   --@message_tag2 nvarchar(500),                  
   --@message_tag3 nvarchar(500),                  
   --@message_tag4 nvarchar(500),                  
   --@message_tag5 nvarchar(500),                   
   --@message_tag6 nvarchar(500)                  
)                    
                  
as                    
Begin                    
                    
  begin try            
            
   declare @EventDscSql nvarchar(1000) = 'Delivered'          
   select top 1  @EventDscSql = Event_Desc from MailStatusCodes with(nolock) where Event_Status =  @event_status          
          
  declare @rowsaffected  int,@batch_id bigint =0 ,@eid bigint ,@mailsource nvarchar(20)                     
  set @event_time=nullif(@event_time,'null')                       
  --if isnull(@BatchID,'')<>''                      
  --begin                        
  --if isnumeric(@batchid)=1                      
  --set @batch_id=cast(@batchid as bigint)                      
  --end                      
         
  --set @batch_id =cast(isnull(nullif(@cust_ref_id,''),0) as bigint)            
          
   select @batch_id =  case when charindex('~',@cust_ref_id) <> 0        
                   then (select  value from fn_split(@cust_ref_id,'~') where Position = 2)        
       else        
          @cust_ref_id         
       end         
                
  insert into EmailDeliveryStatus                    
   (                    
   --API_Header ,                     
                       
   message_id ,                    
   cust_ref_id ,                    
   event_status ,                    
   event_code ,                    
   event_desc ,                    
   accept_time ,                    
   event_time,                     
  -- Reason,                  
  -- message_tag1 ,                  
  -- message_tag2 ,                  
     message_tag3 ,                  
  -- message_tag4 ,                  
  -- message_tag5 ,                   
  -- message_tag6                     
                  
    BatchID                
  )                    
   values                    
   (                    
                       
  -- @API_Header ,                     
    @message_id ,                    
    @cust_ref_id,        
  -- @cust_ref_id ,                    
   @event_status ,                    
   @event_code ,                    
   @EventDscSql ,                    
   @accept_time ,                    
   @event_time ,                     
  -- @Reason ,                   
  -- @message_tag1 ,                  
  -- @message_tag2 ,                  
     @to_email,                   
  -- @message_tag4 ,                  
  -- @message_tag5 ,                   
  -- @message_tag6                     
    @batch_id                
   )                    
                       
     select @eid=SCOPE_IDENTITY()                                   
          
         
   if(@EventDscSql = 'Delivered')      
        begin    

		/*
		Added: DBA
		Date: 2025-01-14
		*/
		DECLARE @b_ID AS NVARCHAR(40);
		SET @b_ID = CAST(@batch_id AS NVARCHAR(40));
    
		update ClientEmails set Status = 'Delivered' , SentFinalDatetime = getdate()  where BatchID = @b_ID and Email_Id = @to_email  
  
         update  t set t.mailcount = isnull(t.mailcount,0) -1 from EmailCounTracking as t with(nolock)                
            where batchID = @batch_id and tablename = 'tbl_MailResponse' and isnull(t.mailcount,0) > 0       
   
        if( not exists (select 1 from EmailCounTracking with(nolock) where batchID = @batch_id and tablename = 'EmailDeliveryStatus' ))        
       begin            
         insert into EmailCounTracking                
                (batchid, tablename, mailcount, createdon)                
                select @batch_id as batchid , 'EmailDeliveryStatus', 1, GETDATE()                
           end      
     else      
     begin      
       update t set t.mailcount = isnull(t.mailcount,0) + 1      
        from EmailCounTracking as t with(nolock) where batchID = @batch_id and tablename = 'EmailDeliveryStatus'      
    end      
     end      
         
         
      
      
      
 select @mailsource=mail_source from BatchEmail_Infos(nolock) where batchid=@batch_id                  
                  
 if @mailsource='InternalCRM'                  
 begin                  
 --exec usp_insertcrmenagagementactivity @batchid,@message_tag3,'Mail',@event_desc,'EmailDeliveryStatus',@eid,@event_time                  
  exec usp_insertcrmenagagementactivity @batch_id, @to_email,'Mail',@EventDscSql,'EmailDeliveryStatus',@eid,@event_time                  
 end                  
   select 'Data Saved'                          
end try                      
begin catch                      
exec usp_InsertErrorInfo                      
end catch                      
                       
End 



GO

