(                
   @API_Header nvarchar(500),                 
   @BatchID nvarchar(100),                
   @message_id nvarchar(200),                
   @cust_ref_id nvarchar(200),                
   @event_status nvarchar(500),                
   @event_code nvarchar(200),                
   @event_desc nvarchar(1000),                
   @accept_time nvarchar(100),                
   @event_time nvarchar(100),                
   @Reason nvarchar(500),              
   @message_tag1 nvarchar(500),              
   @message_tag2 nvarchar(500),              
   @message_tag3 nvarchar(500),              
   @message_tag4 nvarchar(500),              
   @message_tag5 nvarchar(500),               
   @message_tag6 nvarchar(500)              
)                
              
as                
Begin                
 begin try               
  declare @rowsaffected  int,@batch_id bigint =0 ,@eid bigint ,@mailsource nvarchar(20)   
  set @event_time=nullif(@event_time,'null')     
  --if isnull(@BatchID,'')<>''    
  --begin      
  --if isnumeric(@batchid)=1    
  --set @batch_id=cast(@batchid as bigint)    
  --end    
  set @batch_id=cast(@message_tag2 as bigint)  
          
          
  insert into EmailDeliveryStatus                
   (                
   API_Header ,                 
   BatchID ,                
   message_id ,                
   cust_ref_id ,                
   event_status ,                
   event_code ,                
   event_desc ,                
   accept_time ,                
   event_time ,                
   Reason,              
   message_tag1 ,              
   message_tag2 ,              
   message_tag3 ,              
   message_tag4 ,              
   message_tag5 ,               
   message_tag6                 
    )                
   values                
   (                
                   
   @API_Header ,                 
   @Batch_ID ,                
   @message_id ,                
   @cust_ref_id ,                
   @event_status ,                
   @event_code ,                
   @event_desc ,                
   @accept_time ,                
   @event_time ,                
   @Reason ,               
   @message_tag1 ,              
   @message_tag2 ,              
   @message_tag3 ,              
   @message_tag4 ,              
   @message_tag5 ,               
   @message_tag6                 
   )                
  select @eid=SCOPE_IDENTITY()                 
   
 select @mailsource=mail_source from BatchEmail_Infos(nolock) where batchid=@batch_id

 if @mailsource='InternalCRM'
 begin
 exec usp_insertcrmenagagementactivity @batchid,@message_tag3,'Mail',@event_desc,'EmailDeliveryStatus',@eid,@event_time
 end
 
   
   select 'Data Saved'        
   
   
   
           
end try    
begin catch    
exec usp_InsertErrorInfo    
end catch                   
End     
    
--select top 100 * from emaildeliverystatus(nolock) where event_desc<>'Delivered' order by id desc    
    
    
    




GO

/* ============================================================
   Procedure: [dbo].[usp_emailreportsdetailed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
 
 --[usp_emailreportssummary] 335,null,null,'2021-07-01','2021-07-11' 
CREATE   PROCEDURE [dbo].[usp_emailreportsdetailed]-- 33819,null,null,'2021-05-01','2021-07-11',null,null,'clicked' 
( 
@parentid bigint, 
@campaigntype nvarchar(20)=null, 
@campaignname nvarchar(100)=null, 
@fromdate date=null, 
@todate date=null, 
@mail_source nvarchar(200)=null, 
@batchid bigint=null, 
@reporttype nvarchar(50)=null 
) 
as 
begin 
--declare @parentid bigint=335, 
--@campaigntype nvarchar(20)=null, 
--@campaignname nvarchar(100)=null, 
--@fromdate date='2021-07-01', 
--@todate date='2021-07-10' 
 
 if(@campaigntype = '') 
 Begin 
 set @campaigntype = null 
 End 
 
 if(@campaignname = '') 
 Begin 
 set @campaignname = null 
 End 
 
 if(@fromdate = '') 
 Begin 
 set @fromdate = null 
 End 
 
 if(@todate = '') 
 Begin 
 set @todate = null 
 End 
 
 if(@mail_source = '') 
 Begin 
 set @mail_source = null 
 End 
 
 
 
if @fromdate=null 
begin 
set @fromdate=cast(DATEADD(m, DATEDIFF(m, 0, GETDATE()), 0) as date) 
set @todate=cast(getdate() as date) 
end 
 
create table #batchids(batchid bigint) 
if @mail_source is not null 
begin 
insert into #batchids (batchid) 
select batchid from mysms.dbo.BatchEmail_Infos with (nolock) where 
userid=@parentid and 
mail_source=@mail_source and isnull(scheduleddate,batchinserttime) between @fromdate and @todate 
end 
if @batchid is not null 
begin 
insert into #batchids (batchid) 
select @batchid 
end 
 
 
 
drop table if exists #batch 
drop table if exists #invalidmails 
drop table if exists #sent 
drop table if exists #karixreport 
drop table if exists #kopened 
drop table if exists #kclicked 
drop table if exists #awsreport 
drop table if exists #unsubscribed 
 
select b.batchid,mail_source , 
coalesce(t.cname,c.campaignname,case when mail_source in ('emails','csv') then 
cast(isnull(scheduleddate,batchinserttime) as nvarchar(50))+'_'+cast(b.batchid as nvarchar) 
else 'CRM_'+mail_source end) 
 as campaignname, 
 case when t.id is not null then 'Triggered Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=1 then 'Scheduled Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=0 then 'Event Based Campaign' 
 when mail_source in ('emails','csv') then 'Bulk Mail Campaign' 
 else 'CRM Mails' end 
 as campaigntype,cast(isnull(scheduleddate,batchinserttime) as date) CampaignDate,TotalRecords,scheduleddate,batchinserttime 
 
into #batch 
from 
mysms.dbo.BatchEmail_Infos b with (nolock) 
join mysms.dbo.user_detail u with (nolock) on u.User_ID=b.UserID 
left join mysms.dbo.usercampaignmaster c with (nolock) on c.ParentID=u.parentid and b.mail_source like 'campaign%' 
and cast(c.ID as nvarchar)=replace(b.mail_source, 
'Campaign :','') 
left join mysms.dbo.triggeredcampaigns t with (nolock) on c.eventid=t.eventid and t.mailcampaignid=c.id 
left join #batchids bd on b.batchid=bd.BatchID 
where u.ParentID=@parentid 
and isnull(bd.batchid,0)=case when @mail_source is not null or @batchid is not null then bd.batchid else 0 end 
and cast(isnull(scheduleddate,batchinserttime) as date) between @fromdate and @todate 
 
select emails,isnull(t.batchid,0) Batchid,userid,min(CreatedOn) as Unsubscribeddate 
into #unsubscribed 
from mysms.dbo.tbl_subscription t with (nolock) 
left join #batch b 
on t.batchid=b.BatchID 
where t.UserID=@parentid and Status='Unsubscribed' 
group by emails,isnull(t.batchid,0),userid 
 
 
 
 
if @reporttype='unsubscribe' 
begin 
select emails,u.Batchid,userid,Unsubscribeddate,isnull(campaignname,'Unknown') campaignname,CampaignDate 
,isnull(campaigntype,'Unknown') campaigntype 
from #unsubscribed u 
left join #batch b on u.batchid=b.BatchID 
where (campaigntype is null or (campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end )) 
order by Unsubscribeddate desc 
end 
else if @reporttype='clicked' 
begin 
select e.batchid,e.customer_reference_id,e.destination_url, 
cast((event_date + ' '+event_time) as datetime) ClickedTime,campaignname ,BatchInsertTime 
into #kclicked_link 
from 
mysms.dbo.[EngagementEventOpenClick] e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
where isnull(e.destination_url,'')<>'' 
and (campaigntype is null or (campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end )) 
 
 
select k.batchid,destination_url Link,Mail_ToEmail Email,k.campaignname,k.BatchInsertTime as Senttime,ClickedTime 
from #kclicked_link k join 
mysmstrans.dbo.emailsreportsent e with (nolock) 
on e.Mail_BatchID=k.BatchID and k.customer_reference_id=e.Mail_GUID 
order by ClickedTime desc 
end 
else 
begin 
select e.BatchID,e.cust_ref_id,event_status,event_desc,Reason as Description,cast(event_time as datetime) as Delivereddate 
into #karixreport 
from mysms.dbo.EmailDeliveryStatus e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
 
create table #awsreport(batchid bigint,apiheader nvarchar(100),mailstatus nvarchar(50),description nvarchar(200), eventdate datetime) 
 
insert into #awsreport(batchid,apiheader,mailstatus,description,eventdate) 
select e.batchid,APIHeader,'Delivered' as mailstatus,'' as description,Delivereddate 
from mysms.dbo.Maildeliveries e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
union 
select e.batchid,apiheader,'Bounced' as mailstatus,cast(bouncetype as nvarchar(20))+'- '+BounceSubType as Description,createdon 
from mysms.dbo.Mailbounces e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
 
select e.mail_batchid batchid,e.Mail_ToEmail, 
case when smtpserver='aws' then a.mailstatus 
when smtpserver='karix' then k.event_desc 
else 'Sent' end as MailStatus, 
case when smtpserver='aws' then a.description 
when smtpserver='karix' then k.description 
 end as Description, 
case when smtpserver='aws' then a.eventdate 
when smtpserver='karix' then k.Delivereddate 
 end as delivereddate, 
 smtpserver 
into #sent 
from mysmstrans.dbo.emailsreportsent e with (nolock) 
join #batch b on e.Mail_BatchID=b.BatchID 
left join #karixreport k on k.BatchID=e.Mail_BatchID and k.cust_ref_id=e.Mail_GUID 
left join #awsreport a on a.BatchID=e.Mail_BatchID and a.apiheader=e.Mail_GUID 
 
 
select e.mail_batchid batchid,e.Mail_ToEmail,'Not Sent' as mailstatus 
into #invalidmails 
from mysmstrans.dbo.invalid_mail_emailsreport e with (nolock) 
join #batch b on e.Mail_BatchID=b.BatchID 
 
select e.batchid,customer_reference_id,count(1) as OpenedTimes,max(cast((event_date + ' '+event_time) as datetime)) LastOpened 
into #kopened 
from 
mysms.dbo.[EngagementEventOpenClick] e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
where isnull(e.destination_url,'')='' 
group by e.batchid,customer_reference_id 
--order by cast((event_date + ' '+event_time) as datetime) 
 
 
select e.batchid,e.customer_reference_id , 
max(cast((event_date + ' '+event_time) as datetime)) LastClickedTime 
into #kclicked 
from 
mysms.dbo.[EngagementEventOpenClick] e with (nolock) 
join #batch b on e.BatchID=b.BatchID 
where isnull(e.destination_url,'')<>'' 
group by e.batchid,e.customer_reference_id 
--order by cast((event_date + ' '+event_time) as datetime) desc 
 
 
 
 
 
 
 
select CampaignDate,mail_source ,campaigntype,campaignname,batchid,SentTime,Mail_ToEmail,mailstatus,delivereddate,Description,OpenedTimes,LastOpened,LastClickedTime,smtpserver as mailRoute,Unsubscribeddate 
from 
( 
select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime, 
isnull(s.Mail_ToEmail,i.Mail_ToEmail) Mail_ToEmail,isnull(s.MailStatus,i.mailstatus) Mailstatus,delivereddate,ko.OpenedTimes,ko.LastOpened,isnull(s.Description,'') Description, 
kc.LastClickedTime,smtpserver,Unsubscribeddate 
from 
#batch b 
left join #sent s on b.BatchID=s.batchid 
left join #kopened ko on ko.BatchID=b.BatchID 
left join #kclicked kc on kc.BatchID=b.BatchID 
left join #invalidmails i on i.batchid=b.BatchID 
left join #unsubscribed u on u.Batchid=b.BatchID 
--union 
--select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime, 
--s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened 
--from 
--#batch b 
--left join #invalidmails s on s.batchid=b.BatchID 
) a 
where campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end 
--group by CampaignDate,campaigntype,campaignname,mail_source 
order by CampaignDate desc 
 
 
end 
 
drop table if exists #batch 
drop table if exists #invalidmails 
drop table if exists #sent 
drop table if exists #karixreport 
drop table if exists #kopened 
drop table if exists #kclicked 
drop table if exists #awsreport 
drop table if exists #unsubscribed 
 
 
 
 
 
 
 
/* 
if @fromdate=null 
begin 
set @fromdate=cast(DATEADD(m, DATEDIFF(m, 0, GETDATE()), 0) as date) 
set @todate=cast(getdate() as date) 
end 
select CampaignDate,campaigntype,campaignname,sum(TotalRecords) as Recipients 
from 
( 
select 
coalesce(t.cname,c.campaignname,case when mail_source in ('emails','csv') then 
cast(isnull(scheduleddate,batchinserttime) as nvarchar(50))+'_'+cast(b.batchid as nvarchar) 
else 'CRM' end) 
 as campaignname, 
 case when t.id is not null then 'Triggered Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=1 then 'Scheduled Campaign' 
 when c.id is not null and isnull(c.IsScheduled,0)=0 then 'Event Based Campaign' 
 when mail_source in ('emails','csv') then 'Bulk Mail Campaign' 
 else 'CRM Mails' end 
 as campaigntype,cast(isnull(scheduleddate,batchinserttime) as date) CampaignDate,TotalRecords 
from 
BatchEmail_Infos b with (nolock) 
join user_detail u with (nolock) on u.User_ID=b.UserID 
left join usercampaignmaster c with (nolock) on c.ParentID=u.parentid and b.mail_source like 'campaign%' 
and cast(c.ID as nvarchar)=replace(b.mail_source, 
'Campaign :','') 
left join triggeredcampaigns t with (nolock) on c.eventid=t.eventid and t.mailcampaignid=c.id 
where u.ParentID=@parentid 
and cast(isnull(scheduleddate,batchinserttime) as date) between @fromdate and @todate 
) a 
where campaigntype=case when @campaigntype is null then campaigntype 
else @campaigntype end 
and campaignname=case when @campaignname is null then campaignname 
else @campaignname end 
group by CampaignDate,campaigntype,campaignname 
order by CampaignDate desc 
*/ 
