CREATE   PROCEDURE [dbo].[usp_emailreportsdetailed_Bounced] --0,20,33819,null,null,'2021-06-30','2021-07-29',null,null,'unsubscribe','','',''                         
(
  @OffsetValue     INT          =0, 
  @PagingSize      INT          =20, 
  @parentid        BIGINT, 
  @campaigntype    NVARCHAR(20) =NULL, 
  @campaignname    NVARCHAR(100)=NULL, 
  @fromdate        DATE         =NULL, 
  @todate          DATE         =NULL, 
  @mail_source     NVARCHAR(200)=NULL, 
  @batchid         BIGINT       =NULL, 
  @reporttype      NVARCHAR(50) =NULL, 
  @Recipient       NVARCHAR(500), 
  @BouncedFromDate NVARCHAR(100), 
  @BouncedToDate   NVARCHAR(100))
AS
BEGIN
--declare @parentid bigint=335,                            
--@campaigntype nvarchar(20)=null,                            
--@campaignname nvarchar(100)=null,                            
--@fromdate date='2021-07-01',                            
--@todate date='2021-07-10'     ,  
--@OffsetValue int = 0,                                              
--@PagingSize int  = 20,                  
--@mail_source nvarchar(200)=null,                      
--@batchid bigint=null,                          
--@reporttype nvarchar(50)=null,                      
--@Recipient nvarchar(500),                
--@BouncedFromDate nvarchar(100),              
--@BouncedToDate nvarchar(100)        
DROP TABLE IF EXISTS #batch;
DROP TABLE IF EXISTS #batchids;
DROP TABLE IF EXISTS #tblbounced;
DROP TABLE IF EXISTS #tbllead;
DROP TABLE IF EXISTS #tblEnquiry;  
--drop table if exists #invalidmails                      
--drop table if exists #sent                      
--drop table if exists #karixreport                      
--drop table if exists #kopened                      
--drop table if exists #kclicked                      
--drop table if exists #awsreport                      
DROP TABLE IF EXISTS #unsubscribed;
IF @batchid=0
BEGIN
SET @batchid=NULL;
END;
IF @campaigntype=''
BEGIN
SET @campaigntype=NULL;
END;
IF @campaignname=''
BEGIN
SET @campaignname=NULL;
END;
IF @fromdate=''
BEGIN
SET @fromdate=NULL;
END;
IF @todate=''
BEGIN
SET @todate=NULL;
END;
IF @mail_source=''
BEGIN
SET @mail_source=NULL;
END;
IF @reporttype=''
BEGIN
SET @reporttype=NULL;
END;
IF @fromdate=NULL
BEGIN
SET @fromdate=CAST( DATEADD( m, DATEDIFF( m, 0, GETDATE( ) ), 0 ) AS DATE );
SET @todate=CAST( GETDATE( ) AS DATE );
END;
CREATE TABLE #batchids
(
  batchid BIGINT);
IF @mail_source IS NOT NULL
BEGIN
INSERT INTO #batchids
(batchid)
       SELECT batchid
       FROM mysms.dbo.BatchEmail_Infos with (nolock)
       WHERE userid=@parentid
             AND mail_source=@mail_source
             AND ISNULL( scheduleddate, batchinserttime ) BETWEEN @fromdate AND @todate;
END;
IF @batchid IS NOT NULL
BEGIN
INSERT INTO #batchids
(batchid)
       SELECT @batchid;
END;
SELECT u.parentid, 
       b.batchid, 
       mail_source, 
       COALESCE( t.cname, c.campaignname,
                            CASE
                              WHEN mail_source IN( 'emails', 'csv' )
                              THEN CAST( ISNULL( scheduleddate, batchinserttime ) AS NVARCHAR(50) )+'_'+CAST( b.batchid AS NVARCHAR )
                              ELSE 'CRM_'+mail_source
                            END )
AS                                                              campaignname,
       CASE
         WHEN t.id IS NOT NULL
         THEN 'Triggered Campaign'
         WHEN c.id IS NOT NULL
              AND ISNULL( c.IsScheduled, 0 )=1
         THEN 'Scheduled Campaign'
         WHEN c.id IS NOT NULL
              AND ISNULL( c.IsScheduled, 0 )=0
         THEN 'Event Based Campaign'
         WHEN mail_source IN( 'emails', 'csv' )
         THEN 'Bulk Mail Campaign'
         ELSE 'CRM Mails'
       END
AS                                                              campaigntype, 
       CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE ) CampaignDate, 
       TotalRecords, 
       scheduleddate, 
       batchinserttime
INTO #batch
FROM mysms.dbo.BatchEmail_Infos  b with (nolock) 
JOIN
mysms.dbo.user_detail  u with (nolock) 
ON u.User_ID=b.UserID
    LEFT JOIN
    mysms.dbo.usercampaignmaster  c with (nolock) 
    ON c.ParentID=u.parentid
       AND b.mail_source LIKE 'campaign%'
       AND CAST( c.ID AS NVARCHAR )=replace( b.mail_source, 'Campaign :', '' )
        LEFT JOIN
        mysms.dbo.triggeredcampaigns  t with (nolock) 
        ON c.eventid=t.eventid
           AND t.mailcampaignid=c.id
            LEFT JOIN
            #batchids bd
            ON b.batchid=bd.BatchID
WHERE u.ParentID=@parentid
      AND ISNULL( bd.batchid, 0 )=CASE
                                    WHEN @mail_source IS NOT NULL
                                         OR @batchid IS NOT NULL
                                    THEN bd.batchid
                                    ELSE 0
                                  END
      AND CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE ) BETWEEN @fromdate AND @todate;
SELECT emails, 
       batchid, 
       userid, 
       unsubscribeddate, 
       Description
INTO #tblbounced
FROM
(
  SELECT t.message_tag3
  AS emails, 
         ISNULL( t.message_tag2, 0 )
  AS Batchid, 
         b.parentid
  AS userid,  
         --min(t.event_time) as Unsubscribeddate,
         t.event_time
  AS Unsubscribeddate, 
         ISNULL( event_desc, 'bounce' )+ISNULL( ' : '+reason, '' )
  AS description
  FROM MySMS.dbo.EmailDeliveryStatus  t with (nolock) 
  JOIN
  #batch b
  ON t.batchid=b.BatchID
  WHERE parentid=@parentid
        AND t.event_status<>'001'
        AND CONVERT( DATE, t.CreatedOn ) BETWEEN @fromdate AND @todate
  UNION
  SELECT ToMail
  AS emails, 
         ISNULL( t.BatchID, 0 )
  AS Batchid, 
         parentid
  AS userid,  
         --min(t.createdon) as Unsubscribeddate ,
         t.createdon
  AS Unsubscribeddate, 
         ISNULL( BounceType, 'Bounce' )+ISNULL( ' : '+bouncesubtype, '' )
  AS description
  FROM MySMS.dbo.mailBounces  t with (nolock) 
  JOIN
  #batch b
  ON t.batchid=b.BatchID
  WHERE parentid=@parentid
        AND CONVERT( DATE, t.CreatedOn ) BETWEEN @fromdate AND @todate
) a;
/* start  leadid and img handling */
SELECT v.leadno, 
       ISNULL( personname, '' )         personname, 
       ISNULL( ProfileImgFileName, '' ) ProfileImgFileName, 
       email, 
       u.ID
AS                                      LeadID
INTO #tbllead
FROM mysms.dbo.Userleads_Mobile_Email v with (nolock)
JOIN
mysms.dbo.userleads  u with (nolock) 
ON u.parentid=v.parentid
   AND v.leadno=u.LeadNo
WHERE v.parentid=@parentid
      AND email<>'1'
 and v.ulme_id=(select max(ulme_id) from mysms.dbo.Userleads_Mobile_Email with (nolock) where email=v.email )	  
	  ;
SELECT v.enquiryid, 
       ISNULL( personname, '' )         personname, 
       ISNULL( ProfileImgFileName, '' ) ProfileImgFileName, 
       email
INTO #tblEnquiry
FROM mysms.dbo.Userenquiry_Mobile_Email v with (nolock)
JOIN
mysms.dbo.userenquiry  u with (nolock) 
ON u.parentid=v.parentid
   AND v.enquiryid=u.enquiryid
WHERE v.parentid=@parentid
      AND email<>'1'
  and v.enquiryid=(select max(enquiryid) from mysms.dbo.Userenquiry_Mobile_Email with (nolock) where email=v.email )
	  
	  ;
-- select * from #tblbounced            
/* end  leadid and img handling */
--if @reporttype='unsubscribe'                    
--begin            
IF @BouncedFromDate<>''
   AND @BouncedToDate<>''
BEGIN
SELECT COUNT( u.BatchID ) OVER( )
AS                                                                           TotalRow, 
       emails, 
       u.Batchid, 
       userid, 
       Unsubscribeddate, 
       ISNULL( campaignname, 'Unknown' )                                     campaignname, 
       CampaignDate, 
       ISNULL( campaigntype, 'Unknown' )                                     campaigntype,
       CASE
         WHEN leadno IS NOT NULL
         THEN 'lead'
         WHEN enquiryid IS NOT NULL
         THEN 'enquiry'
         ELSE ''
       END
AS                                                                           entity, 
       COALESCE( leadno, enquiryid, 0 )                                      entityid, 
       COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image, 
       COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname, 
       tblLead.LeadID, 
       u.description
FROM #tblbounced u
LEFT JOIN
#batch b
ON u.batchid=b.BatchID
    LEFT JOIN
    #tblEnquiry tblEnq
    ON u.Emails=tblEnq.Email
        LEFT JOIN
        #tblLead tblLead
        ON u.Emails=tblLead.Email
WHERE Emails LIKE '%'+@Recipient+'%'
      AND (campaigntype IS NULL
           OR campaigntype=CASE
                             WHEN @campaigntype IS NULL
                             THEN campaigntype
                             ELSE @campaigntype
                           END
           AND campaignname=CASE
                              WHEN @campaignname IS NULL
                              THEN campaignname
                              ELSE @campaignname
                            END)
      AND CONVERT( DATE, Unsubscribeddate ) BETWEEN CONVERT( DATE, @BouncedFromDate ) AND CONVERT( DATE, @BouncedToDate )
ORDER BY Unsubscribeddate DESC
OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;
END;
  ELSE
BEGIN
SELECT COUNT( u.BatchID ) OVER( )
AS                                                                           TotalRow, 
       emails, 
       u.Batchid, 
       userid, 
       Unsubscribeddate, 
       ISNULL( campaignname, 'Unknown' )                                     campaignname, 
       CampaignDate, 
       ISNULL( campaigntype, 'Unknown' )                                     campaigntype,
       CASE
         WHEN leadno IS NOT NULL
         THEN 'lead'
         WHEN enquiryid IS NOT NULL
         THEN 'enquiry'
         ELSE ''
       END
AS                                                                           entity, 
       COALESCE( leadno, enquiryid, 0 )                                      entityid, 
       COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image, 
       COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname, 
       tblLead.LeadID, 
       u.description
FROM #tblbounced u
LEFT JOIN
#batch b
ON u.batchid=b.BatchID
    LEFT JOIN
    #tblEnquiry tblEnq
    ON u.Emails=tblEnq.Email
        LEFT JOIN
        #tblLead tblLead
        ON u.Emails=tblLead.Email
WHERE Emails LIKE '%'+@Recipient+'%'
      AND (campaigntype IS NULL
           OR campaigntype=CASE
                             WHEN @campaigntype IS NULL
                             THEN campaigntype
                             ELSE @campaigntype
                           END
           AND campaignname=CASE
                              WHEN @campaignname IS NULL
                              THEN campaignname
                              ELSE @campaignname
                            END)
ORDER BY Unsubscribeddate DESC
OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;
END;
--end                    
DROP TABLE IF EXISTS #batch;
DROP TABLE IF EXISTS #batchids;                     
--drop table if exists #invalidmails                      
--drop table if exists #sent                      
--drop table if exists #karixreport                     
--drop table if exists #kopened                      
--drop table if exists #kclicked                      
--drop table if exists #awsreport                      
DROP TABLE IF EXISTS #unsubscribed;
DROP TABLE IF EXISTS #batchids;
DROP TABLE IF EXISTS #kclicked_link;
DROP TABLE IF EXISTS #kclicked_link1;
DROP TABLE IF EXISTS #tblEnquiry;
DROP TABLE IF EXISTS #tbllead;
END;



