									  ELSE @campaignname  
									END)  
			  AND CONVERT( DATE, Unsubscribeddate ) BETWEEN CONVERT( DATE, @BouncedFromDate ) AND CONVERT( DATE, @BouncedToDate )  
		ORDER BY Unsubscribeddate DESC  
		OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
		END;  
		  ELSE  
		BEGIN  
		SELECT COUNT( u.BatchID ) OVER( )  
		AS                                                                           TotalRow,   
			   emails,   
			   u.Batchid,   
			   userid,   
			   Unsubscribeddate,   
			   ISNULL( campaignname, 'Unknown' )                                     campaignname,   
			   CampaignDate,   
			   ISNULL( campaigntype, 'Unknown' )                                     campaigntype,  
			   CASE  
				 WHEN leadno IS NOT NULL  
				 THEN 'lead'  
				 WHEN enquiryid IS NOT NULL  
				 THEN 'enquiry'  
				 ELSE ''  
			   END  
		AS                                                                           entity,   
			   COALESCE( leadno, enquiryid, 0 )                                      entityid,   
			   COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
			   COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname,   
			   tblLead.LeadID,   
			   u.description  
		FROM #tblbounced u  
		LEFT JOIN  
		#batch b  
		ON u.batchid=b.BatchID  
			LEFT JOIN  
			#tblEnquiry tblEnq  
			ON u.Emails=tblEnq.Email  
				LEFT JOIN  
				#tblLead tblLead  
