  if(@Mode = 'bademails' ) 
     begin
	    SELECT emails,   
       batchid,   
       userid,   
       unsubscribeddate,   
       Description  
INTO #tblBadEmails  
FROM  
(  
  SELECT t.MAIL_TOEMAIL  
  AS emails,   
         ISNULL( t.Mail_BatchID, 0 )  
  AS Batchid,   
         b.parentid  
  AS userid,    
         --min(t.event_time) as Unsubscribeddate,  
         CAST( t.MAIL_INSERTEDDATE AS DATETIME )  
