                                 THEN campaignname  
                                 ELSE @campaignname  
                               END)  
      AND CONVERT( DATE, Unsubscribeddate ) BETWEEN CONVERT( DATE, @BouncedFromDate ) AND CONVERT( DATE, @BouncedToDate )  
ORDER BY Unsubscribeddate DESC  
OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
END;  
  ELSE  
BEGIN  
SELECT COUNT( u.BatchID ) OVER( )  
AS                                                                           TotalRow,   
       emails,   
       u.Batchid,   
       userid,   
       Unsubscribeddate,   
       ISNULL( campaignname, 'Unknown' )                                     campaignname,   
       CampaignDate,   
       ISNULL( campaigntype, 'Unknown' )                                     campaigntype,  
       CASE  
         WHEN leadno IS NOT NULL  
         THEN 'lead'  
         WHEN enquiryid IS NOT NULL  
         THEN 'enquiry'  
         ELSE ''  
       END  
AS                                                                           entity,   
       COALESCE( leadno, enquiryid, 0 )                                      entityid,   
       COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
       COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname,   
       tblLead.LeadID,   
       u.description  
FROM #tblBadEmails u  
LEFT JOIN  
#batch b  
ON u.batchid=b.BatchID  
    LEFT JOIN  
    #tblEnquiry tblEnq  
    ON u.Emails=tblEnq.Email  
        LEFT JOIN  
        #tblLead tblLead  
        ON u.Emails=tblLead.Email  
WHERE Emails LIKE '%'+@Recipient+'%'  
      AND (campaigntype IS NULL  
           OR campaigntype=CASE  
                             WHEN @campaigntype IS NULL  
                             THEN campaigntype  
                             ELSE @campaigntype  
                           END  
              AND campaignname=CASE  
                                 WHEN @campaignname IS NULL  
                                 THEN campaignname  
                                 ELSE @campaignname  
                               END)  
ORDER BY Unsubscribeddate DESC  
OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
END; 



	 end
  if(@Mode = 'queuedmails' )
   begin
	 
	 SELECT emails,   
	 batchid,   
	 userid,   
	 unsubscribeddate,   
	 Description   
	INTO #tblqueue   
	FROM   
	(   
	 SELECT t.Mail_ToEmail   
	 AS emails,   
	 b.batchid   
	 AS Batchid,   
	 b.parentid   
	 AS userid,   
	 CAST( t.Mail_InsertedDate AS DATETIME )   
	 AS unsubscribeddate,   
	 ''   
	 AS Description   
	 FROM mysms.dbo.emailsfilter t with (nolock)   
	 JOIN   
	 #batch b   
	 ON b.batchid=t.Mail_BatchID   
	 WHERE b.ParentID=@parentid   
	 AND CONVERT( DATE, t.Mail_InsertedDate ) BETWEEN @fromdate AND @todate   
	 UNION   
	 SELECT t.Mail_ToEmail   
	 AS emails,   
	 b.batchid   
	 AS Batchid,   
	 b.parentid   
	 AS userid,   
	 CAST( t.Mail_InsertedDate AS DATETIME )   
	 AS unsubscribeddate,   
	 ''   
	 AS Description   
	 FROM mysmstrans.[dbo].[allmailqueues] t with (nolock)   
	 JOIN   
	 #batch b   
	 ON b.batchid=t.Mail_BatchID   
	 WHERE b.ParentID=@parentid   
		AND CONVERT( DATE, t.Mail_InsertedDate ) BETWEEN @fromdate AND @todate   
	 ) a

  IF @BouncedFromDate<>''   
   AND @BouncedToDate<>''   
		BEGIN   
		SELECT COUNT( u.BatchID ) OVER( )   
		AS TotalRow,   
		 emails,   
		 u.Batchid,   
		 userid,   
		 Unsubscribeddate,   
		 ISNULL( campaignname, 'Unknown' ) campaignname,   
		 CampaignDate,   
		 ISNULL( campaigntype, 'Unknown' ) campaigntype,   
		 CASE   
		 WHEN leadno IS NOT NULL   
		 THEN 'lead'   
		 WHEN enquiryid IS NOT NULL   
		 THEN 'enquiry'   
		 ELSE ''   
		 END   
		AS entity,   
		 COALESCE( leadno, enquiryid, 0 ) entityid,   
		 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
		 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,   
		 tblLead.LeadID,   
		 u.description   
		FROM #tblqueue u   
		LEFT JOIN   
		#batch b   
		ON u.batchid=b.BatchID   
		 LEFT JOIN   
		 #tblEnquiry tblEnq   
		 ON u.Emails=tblEnq.Email   
		 LEFT JOIN   
		 #tblLead tblLead   
		 ON u.Emails=tblLead.Email   
		WHERE Emails LIKE '%'+@Recipient+'%'   
		 AND (campaigntype IS NULL   
		 OR campaigntype=CASE   
		 WHEN @campaigntype IS NULL   
		 THEN campaigntype   
		 ELSE @campaigntype   
		 END   
		 AND campaignname=CASE   
		 WHEN @campaignname IS NULL   
		 THEN campaignname   
		 ELSE @campaignname   
		 END)   
		 AND CONVERT( DATE, Unsubscribeddate ) BETWEEN CONVERT( DATE, @BouncedFromDate ) AND CONVERT( DATE, @BouncedToDate )   
		ORDER BY Unsubscribeddate DESC   
		OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;   
		END;   
		 ELSE   
		BEGIN   
		SELECT COUNT( u.BatchID ) OVER( )   
		AS TotalRow,   
		 emails,   
		 u.Batchid,   
		 userid,   
		 Unsubscribeddate,   
		 ISNULL( campaignname, 'Unknown' ) campaignname,   
		 CampaignDate,   
		 ISNULL( campaigntype, 'Unknown' ) campaigntype,   
		 CASE   
		 WHEN leadno IS NOT NULL   
		 THEN 'lead'   
		 WHEN enquiryid IS NOT NULL   
		 THEN 'enquiry'   
		 ELSE ''   
		 END   
		AS entity,   
		 COALESCE( leadno, enquiryid, 0 ) entityid,   
		 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
		 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,   
		 tblLead.LeadID,   
		 u.description   
		FROM #tblqueue u   
		LEFT JOIN   
		#batch b   
		ON u.batchid=b.BatchID   
		 LEFT JOIN   
		 #tblEnquiry tblEnq   
		 ON u.Emails=tblEnq.Email   
		 LEFT JOIN   
		 #tblLead tblLead   
		 ON u.Emails=tblLead.Email   
		WHERE Emails LIKE '%'+@Recipient+'%'   
		 AND (campaigntype IS NULL   
		 OR campaigntype=CASE   
		 WHEN @campaigntype IS NULL   
		 THEN campaigntype   
		 ELSE @campaigntype   
		 END   
		 AND campaignname=CASE   
		 WHEN @campaignname IS NULL   
		 THEN campaignname   
		 ELSE @campaignname   
		 END)   
		ORDER BY Unsubscribeddate DESC   
		OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;   
    END;

      
 end


