CREATE   PROCEDURE [dbo].[usp_emailreportsdetailed_ByMode_New] --0,200000,18907,null,null,'2022-02-21','2022-02-28',null,79994093,null,'','''Delivered'       
(       
 --declare 
 @OffsetValue INT =0,       
 @PagingSize INT =20,       
 @parentid BIGINT,       
 @campaigntype NVARCHAR(20) =NULL,       
 @campaignname NVARCHAR(100)=NULL,       
 @fromdate DATE =NULL,       
 @todate DATE =NULL,       
 @mail_source NVARCHAR(200)=NULL,       
 @batchid BIGINT =NULL,       
 @reporttype NVARCHAR(50) =NULL,       
 @Recipient NVARCHAR(500),       
 @MailStatus NVARCHAR(100),-- for recipient   
 --@DeliveredFrom NVARCHAR(100) = '', -- for delivered         
 --@DeliveredTo NVARCHAR(100) = '' , -- for delivered   
 @LastOpenedDate NVARCHAR(100),-- for opned    
 --@ClickedFromDate NVARCHAR(100), -- for clicked       
 --@ClickedToDate NVARCHAR(100), -- for clicked      
 @Link NVARCHAR(MAX),     -- for clicked  
