CREATE TABLE #batchids       
(       
 batchid BIGINT);       
IF @mail_source IS NOT NULL       
BEGIN       
INSERT INTO #batchids       
(batchid)       
 SELECT batchid       
 FROM mysms.dbo.BatchEmail_Infos with (nolock)       
 WHERE userid=@parentid       
 AND mail_source=@mail_source       
 AND ISNULL( scheduleddate, batchinserttime ) BETWEEN @fromdate AND @todate;       
END;       
IF @batchid IS NOT NULL       
BEGIN       
INSERT INTO #batchids       
(batchid)       
 SELECT @batchid;       
END;       


print concat(format(getdate(),'dd-MMM-yyyy HH:mm.sss'),' : ','#batchids created')    
    
    
SELECT  u.ParentID, b.batchid,       
 mail_source,       
 COALESCE( t.cname, c.campaignname,       
 CASE       
 WHEN mail_source IN( 'emails', 'csv' )       
 THEN CAST( ISNULL( scheduleddate, batchinserttime ) AS NVARCHAR(50) )+'_'+CAST( b.batchid AS NVARCHAR )       
 ELSE 'CRM_'+mail_source       
 END )       
AS campaignname,       
 CASE       
 WHEN t.id IS NOT NULL       
 THEN 'Triggered Campaign'       
 WHEN c.id IS NOT NULL       
 AND ISNULL( c.IsScheduled, 0 )=1       
 THEN 'Scheduled Campaign'       
 WHEN c.id IS NOT NULL       
 AND ISNULL( c.IsScheduled, 0 )=0       
 THEN 'Event Based Campaign'       
 WHEN mail_source IN( 'emails', 'csv' )       
 THEN 'Bulk Mail Campaign'       
 ELSE 'CRM Mails'       
 END       
AS campaigntype,       
 CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE ) CampaignDate,       
 TotalRecords,       
 scheduleddate,       
 batchinserttime --,       
 --case when isnull(b.finalmailroute,b.mailroute)='T'   
 --and a.id is not null and a.isactive=1 then 'aws'       
 --when k.id is not null then 'karix'       
 --else '' end as smtpserver       
INTO #batch       
FROM mysms.dbo.BatchEmail_Infos b with (nolock)       
JOIN mysms.dbo.user_detail u with (nolock) ON u.User_ID=b.UserID       
LEFT JOIN mysms.dbo.usercampaignmaster c with (nolock) ON c.ParentID=u.parentid       
AND b.mail_source LIKE 'campaign%'       
AND CAST( c.ID AS NVARCHAR )=replace( b.mail_source, 'Campaign :', '' )       
LEFT JOIN mysms.dbo.triggeredcampaigns t with (nolock) ON c.eventid=t.eventid AND t.mailcampaignid=c.id       
LEFT JOIN #batchids bd ON b.batchid=bd.BatchID       
--left join Mysms.dbo.awsmailroute a on a.mailuser= b.UserID and SenderName=a.frommailid       
--left join Mysms.dbo.karixmailroute k on k.mailuser= b.UserID and SenderName=k.frommailid       
WHERE u.ParentID=@parentid       
AND ISNULL( bd.batchid, 0 )=CASE WHEN @mail_source IS NOT NULL OR @batchid IS NOT NULL THEN bd.batchid ELSE 0 END       
AND CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE ) BETWEEN @fromdate AND @todate;       
--select emails,isnull(t.batchid,0) Batchid,userid,min(CreatedOn) as Unsubscribeddate       
--into #unsubscribed       
--from mysms.dbo.tbl_subscription t with (nolock)       
--left join #batch b       
--on t.batchid=b.BatchID       
--where t.UserID=@parentid and Status='Unsubscribed'       
--group by emails,isnull(t.batchid,0),userid   


print concat(format(getdate(),'dd-MMM-yyyy HH:mm.sss'),' : ','#batch created')    

  
