IF @MailStatus='Delivered'       
BEGIN  
print concat(format(getdate(),'dd-MMM-yyyy HH:mm.sss'),' : ','entered @MailStatus Delivered')    

SELECT COUNT( batchid ) OVER( )       
AS TotalRow,       
 CampaignDate,       
 campaigntype,       
 campaignname,       
 batchid,       
 SentTime,       
 Mail_ToEmail,       
 delivereddate,       
 LastOpened,       
 entity,       
 entityid,       
 image,       
 Personname,       
 LeadID       
FROM       
(       
 SELECT CampaignDate,       
 campaigntype,       
 campaignname,       
 b.batchid,       
 ISNULL( scheduleddate, batchinserttime )       
 AS SentTime,       
 s.Mail_ToEmail Mail_ToEmail,       
 delivereddate,       
 ko.LastOpened,       
 CASE       
 WHEN leadno IS NOT NULL       
 THEN 'lead'       
 WHEN enquiryid IS NOT NULL       
 THEN 'enquiry'       
 ELSE ''       
 END       
 AS entity,       
 COALESCE( leadno, enquiryid, 0 ) entityid,       
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,       
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,       
 tblLead.LeadID       
 FROM #batch b       
 LEFT JOIN       
 --#sent s   
  #karixreport s  
 ON b.BatchID=s.batchid       
 LEFT JOIN     
 



 #kopened ko       
 ON ko.BatchID=b.BatchID and ko.customer_reference_id=s.cust_ref_id
 --left join #kclicked kc on kc.BatchID=b.BatchID       
 --LEFT JOIN       
 --#invalidmails i       
 --ON i.batchid=b.BatchID       
 --left join #unsubscribed u on u.Batchid=b.BatchID       
 LEFT JOIN       
 #tblEnquiry tblEnq       
 ON s.Mail_ToEmail=tblEnq.Email       
 LEFT JOIN       
 #tblLead tblLead       
 ON s.Mail_ToEmail=tblLead.Email       
 --union       
 --select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime,       
 --s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened       
 --from       
 --#batch b       
 --left join #invalidmails s on s.batchid=b.BatchID       
) a       
WHERE Mail_ToEmail LIKE '%'+@Recipient+'%'       
 AND campaigntype=CASE       
 WHEN @campaigntype IS NULL       
 THEN campaigntype       
 ELSE @campaigntype       
 END       
 AND campaignname=CASE       
 WHEN @campaignname IS NULL       
 THEN campaignname       
 ELSE @campaignname       
 END       
 AND delivereddate IS NOT NULL       
--group by CampaignDate,campaigntype,campaignname,mail_source       
ORDER BY CampaignDate DESC       
OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  

 print concat(format(getdate(),'dd-MMM-yyyy HH:mm.sss'),' : ','completed @MailStatus delivered')    

END;       
 ELSE       
 IF @MailStatus='Opened'       
