 LastOpened,       
 entity,       
 entityid,       
 image,       
 Personname,       
 LeadID       
FROM       
(       
 SELECT CampaignDate,       
 campaigntype,       
 campaignname,       
 b.batchid,       
 ISNULL( scheduleddate, batchinserttime )       
 AS SentTime,       
 --ISNULL( s.Mail_ToEmail, i.Mail_ToEmail ) Mail_ToEmail,     
