	  mailstatus,       
	  description,       
	  eventdate
	 )
	 
	 SELECT e.batchid,       
	 APIHeader,       
	 'Delivered'       
	 AS mailstatus,       
	 ''       
	 AS description,       
	 Delivereddate       
	 FROM mysms.dbo.Maildeliveries e with (nolock)       
	 JOIN       
	 #batch b       
	 ON e.BatchID=b.BatchID       
	 UNION       
	 SELECT e.batchid,       
	 apiheader,       
	 'Bounced'       
	 AS mailstatus,       
	 CAST( bouncetype AS NVARCHAR(20) )+'- '+BounceSubType       
	 AS Description,       
	 createdon       
	 FROM mysms.dbo.Mailbounces e with (nolock)       
	 JOIN       
	 #batch b       
	 ON e.BatchID=b.BatchID;       
	  */

	  IF @ModeTypeFromDate<>''       
           AND @ModeTypeToDate<>''       
       BEGIN       
					SELECT COUNT( batchid ) OVER( )       
					AS TotalRow,       
					 CampaignDate,       
					 campaigntype,       
					 campaignname,       
					 batchid,       
					 SentTime,       
					 Mail_ToEmail,       
					 delivereddate,       
					 entity,       
					 entityid,       
					 image,       
					 Personname,       
					 LeadID       
					FROM       
					(       
					 SELECT CampaignDate,       
					 campaigntype,       
					 campaignname,       
					 b.batchid,       
					 ISNULL( scheduleddate, batchinserttime )       
					 AS SentTime,       
					 s.Mail_ToEmail Mail_ToEmail,       
					 delivereddate,       
					 CASE       
					 WHEN leadno IS NOT NULL       
					 THEN 'lead'       
					 WHEN enquiryid IS NOT NULL       
					 THEN 'enquiry'       
					 ELSE ''       
					 END       
					 AS entity,       
					 COALESCE( leadno, enquiryid, 0 ) entityid,       
					 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,       
					 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,       
					 isnull(tblLead.LeadID       ,'') LeadID
					 FROM #batch b       
					 LEFT JOIN       
					 --#sent s 
					 #karixreport_Delivered s
					 ON b.BatchID=s.batchid       
					 --left join #kopened ko on ko.BatchID=b.BatchID       
					 --left join #kclicked kc on kc.BatchID=b.BatchID       
					 --LEFT JOIN       
					 --#invalidmails i       
					 --ON i.batchid=b.BatchID       
					 --left join #unsubscribed u on u.Batchid=b.BatchID       
					 LEFT JOIN       
					 #tblEnquiry tblEnq       
					 ON s.Mail_ToEmail=tblEnq.Email       
					 LEFT JOIN       
					 #tblLead tblLead       
					 ON s.Mail_ToEmail=tblLead.Email       
					 --union       
					 --select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime,       
					 --s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened       
					 --from       
					 --#batch b       
					 --left join #invalidmails s on s.batchid=b.BatchID       
					) a       
					WHERE Mail_ToEmail LIKE '%'+@Recipient+'%'       
					 AND campaigntype=CASE       
					 WHEN @campaigntype IS NULL       
					 THEN campaigntype       
					 ELSE @campaigntype       
					 END       
					 AND campaignname=CASE       
					 WHEN @campaignname IS NULL       
					 THEN campaignname       
					 ELSE @campaignname       
					 END       
					 AND delivereddate IS NOT NULL       
					 AND CONVERT( DATE, delivereddate ) BETWEEN CONVERT( DATE, @ModeTypeFromDate ) AND CONVERT( DATE, @ModeTypeToDate )       
					--group by CampaignDate,campaigntype,campaignname,mail_source       
					ORDER BY CampaignDate DESC       
				---	OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;       
              END;
		 else
		  BEGIN       
SELECT COUNT( batchid ) OVER( )       
AS TotalRow,       
 CampaignDate,       
 campaigntype,       
 campaignname,       
 batchid,       
 SentTime,       
 Mail_ToEmail,       
 delivereddate,       
 entity,       
 entityid,       
 image,       
 Personname,       
 LeadID       
FROM       
(      
 SELECT CampaignDate,       
 campaigntype,       
 campaignname,       
 b.batchid,       
 ISNULL( scheduleddate, batchinserttime )       
 AS SentTime,       
 s.Mail_ToEmail Mail_ToEmail,       
 delivereddate,       
 CASE       
 WHEN leadno IS NOT NULL       
 THEN 'lead'       
 WHEN enquiryid IS NOT NULL       
 THEN 'enquiry'       
 ELSE ''       
 END       
 AS entity,       
 COALESCE( leadno, enquiryid, 0 ) entityid,       
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,       
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,       
 isnull(tblLead.LeadID       ,'') LeadID
 FROM #batch b       
 LEFT JOIN       
 --#sent s 
  #karixreport_Delivered s
 ON b.BatchID=s.batchid       
 --left join #kopened ko on ko.BatchID=b.BatchID       
 --left join #kclicked kc on kc.BatchID=b.BatchID       
 --LEFT JOIN       
 --#invalidmails i       
 --ON i.batchid=b.BatchID       
 --left join #unsubscribed u on u.Batchid=b.BatchID       
 LEFT JOIN       
 #tblEnquiry tblEnq       
 ON s.Mail_ToEmail=tblEnq.Email       
 LEFT JOIN       
 #tblLead tblLead       
 ON s.Mail_ToEmail =tblLead.Email       
 --union       
 --select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime,       
 --s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened       
 --from       
 --#batch b       
 --left join #invalidmails s on s.batchid=b.BatchID       
) a       
WHERE Mail_ToEmail LIKE '%'+@Recipient+'%'       
 AND campaigntype=CASE       
 WHEN @campaigntype IS NULL       
 THEN campaigntype       
 ELSE @campaigntype       
 END       
 AND campaignname=CASE       
 WHEN @campaignname IS NULL       
 THEN campaignname       
 ELSE @campaignname       
 END       
 AND delivereddate IS NOT NULL       
--group by CampaignDate,campaigntype,campaignname,mail_source       
ORDER BY CampaignDate DESC       
--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;       
END; 



end  
if(@Mode = 'Opened' )
 begin
 
    SELECT e.BatchID,       
	 e.cust_ref_id,       
	 event_status,       
	 event_desc,       
	 Reason       
	AS Description,       
	 CAST( event_time AS DATETIME )       
	AS Delivereddate,       
	e.message_tag3 as Mail_ToEmail
	INTO #karixreport_Opened       
	FROM mysms.dbo.EmailDeliveryStatus e with (nolock)       
	JOIN       
	#batch b       
	ON e.BatchID=b.BatchID    
	where event_status = '001'    



 SELECT  e.batchid,     
	 to_email,     
	 COUNT(distinct to_email )     
	AS OpenedTimes,     
	 MAX( CAST( event_date+' '+event_time AS DATETIME ) ) LastOpened     
	INTO #kopened_Opened     
	FROM mysms.dbo.EngagementEventOpenClick e with (nolock)     
	JOIN     
	#batch b     
	ON e.BatchID=b.BatchID     
	 AND ISNUMERIC( e.BatchID )=1     
	 AND ISNUMERIC( b.BatchID )=1     
	WHERE ISNULL( e.destination_url, '' )=''   
	and cast(e.CreatedOn as date)  between @fromdate and @todate   
	GROUP BY e.batchid,     
	 to_email;  
	 
	 SELECT COUNT( batchid ) OVER( )     
AS TotalRow,     
 CampaignDate,     
 campaigntype,     
 campaignname,     
 batchid,     
 SentTime,     
 Mail_ToEmail,     
 OpenedTimes,     
 LastOpened,     
 entity,     
 entityid,     
 image,     
 Personname,     
 LeadID     
FROM     
(     
 SELECT CampaignDate,     
 campaigntype,     
 campaignname,     
 b.batchid,     
 ISNULL( scheduleddate, batchinserttime )     
 AS SentTime,     
 --ISNULL( s.Mail_ToEmail, i.Mail_ToEmail ) Mail_ToEmail,   
 ISNULL( s.Mail_ToEmail,'') Mail_ToEmail,     
 ko.OpenedTimes,     
 ko.LastOpened,     
 CASE     
 WHEN leadno IS NOT NULL     
 THEN 'lead'     
 WHEN enquiryid IS NOT NULL     
 THEN 'enquiry'     
 ELSE ''     
 END     
 AS entity,     
 COALESCE( leadno, enquiryid, 0 ) entityid,     
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,     
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,     
 isnull(tblLead.LeadID     ,'') LeadID
 FROM #batch b     
 LEFT JOIN     
 --#sent s
 #karixreport_Opened s
 ON b.BatchID=s.batchid     
 LEFT JOIN     
 #kopened_Opened ko     
 ON ko.BatchID=b.BatchID and ko.batchid=s.batchid and ko.to_email=s.Mail_ToEmail     
 --left join #kclicked kc on kc.BatchID=b.BatchID     
 -- LEFT JOIN     
   -- #invalidmails i     
    --ON i.batchid=b.BatchID and ko.batchid=s.batchid     
 --left join #unsubscribed u on u.Batchid=b.BatchID     
 LEFT JOIN     
 #tblEnquiry tblEnq     
 --ON ISNULL( s.Mail_ToEmail, i.Mail_ToEmail )=tblEnq.Email     
 ON s.Mail_ToEmail=tblEnq.Email     
 LEFT JOIN     
 #tblLead tblLead     
 --ON ISNULL( s.Mail_ToEmail, i.Mail_ToEmail )=tblLead.Email     
 ON s.Mail_ToEmail = tblLead.Email     
 
 --union     
 --select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime,     
 --s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened     
 --from     
 --#batch b     
 --left join #invalidmails s on s.batchid=b.BatchID     
) a     
WHERE     
 Mail_ToEmail LIKE '%'+@Recipient+'%'     
 AND campaigntype=CASE     
 WHEN @campaigntype IS NULL     
 THEN campaigntype     
 ELSE @campaigntype     
 END     
 AND campaignname=CASE     
 WHEN @campaignname IS NULL     
 THEN campaignname     
 ELSE @campaignname     
 END     
 AND LastOpened IS NOT NULL     
 AND CONVERT( DATE, LastOpened )
     =
     case when @LastOpenedDate <> ''
         then CONVERT( DATE, @LastOpenedDate)
		 else CONVERT( DATE, LastOpened )
     end


--group by a.BatchID,CampaignDate,campaigntype,campaignname--,mail_source     
     
--group by CampaignDate,     
-- campaigntype,     
-- campaignname,     
-- batchid,     
-- SentTime,     
-- Mail_ToEmail,     
-- OpenedTimes,     
-- LastOpened,     
-- entity,     
-- entityid,     
-- image,     
-- Personname,     
-- LeadID     
ORDER BY CampaignDate DESC     
--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
	 

 end
 if(@Mode = 'Clicked' )  
    begin
	 SELECT e.batchid,     
	    e.to_email,     
		MAX( CAST( event_date+' '+event_time AS DATETIME ) ) LastClickedTime     
		INTO #kclicked     
		FROM mysms.dbo.EngagementEventOpenClick e with (nolock)     
		JOIN     
		#batch b     
		ON e.BatchID=b.BatchID     
		 AND ISNUMERIC( e.BatchID )=1     
		 AND ISNUMERIC( b.BatchID )=1     
		WHERE ISNULL( e.destination_url, '' )<>''     
		GROUP BY e.batchid,     
		 e.to_email;     
       
	      IF @ModeTypeFromDate<>''     
 AND @ModeTypeToDate<>''     
BEGIN     
SELECT e.batchid,     
 e.to_email,     
 e.destination_url,     
 CAST( event_date+' '+event_time AS DATETIME ) ClickedTime,     
 campaignname,     
 BatchInsertTime     
INTO #kclicked_link     
FROM mysms.dbo.EngagementEventOpenClick e with (nolock)     
JOIN     
#batch b     
ON CAST( ISNULL( NULLIF( e.BatchID, 'null' ), 0 ) AS BIGINT )=b.BatchID     
WHERE ISNULL( e.destination_url, '' )<>''     
 AND (campaigntype IS NULL     
 OR campaigntype=CASE     
 WHEN @campaigntype IS NULL     
 THEN campaigntype     
 ELSE @campaigntype     
 END     
 AND campaignname=CASE     
 WHEN @campaignname IS NULL     
 THEN campaignname     
 ELSE @campaignname     
 END);     
SELECT COUNT( k.BatchID ) OVER( )     
AS TotalRow,     
 k.batchid,     
 destination_url Link,     
 Mail_ToEmail Email,     
 k.campaignname,     
 k.BatchInsertTime     
AS Senttime,     
 ClickedTime,     
 CASE     
 WHEN leadno IS NOT NULL     
 THEN 'lead'     
 WHEN enquiryid IS NOT NULL     
 THEN 'enquiry'     
 ELSE ''     
 END     
AS entity,     
 COALESCE( leadno, enquiryid, 0 ) entityid,     
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,     
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,     
 isnull(tblLead.LeadID     ,'') LeadID
FROM #kclicked_link k     
JOIN     
--mysmstrans.dbo.emailsreportsent e with (nolock) 

 (select cast(guid as nvarchar(100)) as mail_guid,email_id as mail_toemail,e.batchid as mail_batchid from     
ClientEmails e with (nolock)     
union all     
select cast(guid as nvarchar(100)),email_id,e.batchid from     
ThirtyDaysClientEmails e with (nolock)     
) as e 

ON e.Mail_BatchID=k.BatchID     
 AND k.to_email=e.Mail_ToEmail     
 LEFT JOIN     
 #tblEnquiry tblEnq     
 ON e.Mail_ToEmail=tblEnq.Email     
 LEFT JOIN     
 #tblLead tblLead     
 ON e.Mail_ToEmail=tblLead.Email     
WHERE destination_url LIKE '%'+@Link+'%'     
 AND Mail_ToEmail LIKE '%'+@Recipient+'%'     
 AND ClickedTime IS NOT NULL     
 AND CONVERT( DATE, ClickedTime ) BETWEEN CONVERT( DATE, @ModeTypeFromDate ) AND CONVERT( DATE, @ModeTypeToDate )     
ORDER BY ClickedTime DESC     
--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;     
END;     
 ELSE     
BEGIN     
SELECT e.batchid,     
 e.to_email,     
 e.destination_url,     
 CAST( event_date+' '+event_time AS DATETIME ) ClickedTime,     
 campaignname,     
 BatchInsertTime     
INTO #kclicked_link1     
FROM mysms.dbo.EngagementEventOpenClick e with (nolock)     
JOIN     
#batch b     
ON CAST( ISNULL( NULLIF( nullif(e.BatchID,''), 'null' ), 0 ) AS BIGINT )=b.BatchID     
WHERE ISNULL( e.destination_url, '' )<>''  
  and  ISNUMERIC(ISNULL( NULLIF( nullif(e.BatchID,''), 'null' ), 0 )) = 1
 --and cast(e.CreatedOn as date) between @fromdate and @todate     
 AND (campaigntype IS NULL     
 OR campaigntype=CASE     
 WHEN @campaigntype IS NULL     
 THEN campaigntype     
 ELSE @campaigntype     
 END     
 AND campaignname=CASE     
 WHEN @campaignname IS NULL     
 THEN campaignname     
 ELSE @campaignname     
 END);     
SELECT COUNT( k.BatchID ) OVER( )     
AS TotalRow,     
 k.batchid,     
 destination_url Link,     
 Mail_ToEmail Email,     
 k.campaignname,     
 k.BatchInsertTime     
AS Senttime,     
 ClickedTime,     
 CASE     
 WHEN leadno IS NOT NULL     
 THEN 'lead'     
 WHEN enquiryid IS NOT NULL     
 THEN 'enquiry'     
 ELSE ''     
 END     
AS entity,     
 COALESCE( leadno, enquiryid, 0 ) entityid,     
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,     
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,     
 isnull(tblLead.LeadID     ,'') LeadID
FROM #kclicked_link1 k     
JOIN     
--mysmstrans.dbo.emailsreportsent e with (nolock)     
(select cast(guid as nvarchar(100)) as mail_guid,email_id as mail_toemail,e.batchid as mail_batchid from     
ClientEmails e with (nolock)     
union all     
select cast(guid as nvarchar(100)),email_id,e.batchid from     
ThirtyDaysClientEmails e with (nolock)     
)     
e     
ON e.Mail_BatchID=k.BatchID     
 AND k.to_email=e.mail_toemail     
 LEFT JOIN     
 #tblEnquiry tblEnq     
 ON e.Mail_ToEmail=tblEnq.Email     
 LEFT JOIN     
 #tblLead tblLead     
 ON e.Mail_ToEmail=tblLead.Email     
WHERE destination_url LIKE '%'+@Link+'%'     
 AND Mail_ToEmail LIKE '%'+@Recipient+'%'     
 AND ClickedTime IS NOT NULL     
ORDER BY ClickedTime DESC     
--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;     

   end     


	end
 if(@Mode = 'unsubscribed')
    begin
	   SELECT distinct email_id emails,   
       ISNULL( c.batchid, 0 ) Batchid,   
       userid,   
          MIN( CreatedOn )  
		AS  Unsubscribeddate  
		INTO #unsubscribed  
		FROM   
		(select email_id,c.batchid from mysms.dbo.clientemails c with (nolock) JOIN    
		#batch b  ON b.BatchID=c.batchid where   
		cast(c.SentDateTime as date) between @fromdate and @todate and  
		dbo.fn_isemailunsubscribed(@parentid,c.Email_Id)=1     
		union  
		select email_id,c.batchid from mysms.dbo.ThirtyDaysClientEmails c with (nolock) JOIN    
		#batch b  ON b.BatchID=c.batchid where   
		cast(c.SentDateTime as date) between @fromdate and @todate and  
		dbo.fn_isemailunsubscribed(@parentid,c.Email_Id)=1     
		) c  
		left join  
		mysms.dbo.tbl_subscription( NOLOCK ) t  
		ON t.emails=c.email_ID  
		WHERE t.UserID=@parentid  
			  AND dbo.fn_isemailunsubscribed(@parentid,email_id)=1  
		GROUP BY email_id,   
				c.batchid,   
				 userid;  

        IF @ModeTypeFromDate<>''  
   AND @ModeTypeToDate<>''  
BEGIN  
SELECT COUNT( u.BatchID ) OVER( )  
AS                                                                           TotalRow,   
       emails,   
       u.Batchid,   
       userid,   
       Unsubscribeddate,   
       ISNULL( campaignname, 'Unknown' )                                     campaignname,   
       CampaignDate,   
       ISNULL( campaigntype, 'Unknown' )                                     campaigntype,  
       CASE  
         WHEN leadno IS NOT NULL  
         THEN 'lead'  
         WHEN enquiryid IS NOT NULL  
         THEN 'enquiry'  
         ELSE ''  
       END  
AS                                                                           entity,   
       COALESCE( leadno, enquiryid, 0 )                                      entityid,   
       COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
       COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname,   
      isnull( tblLead.LeadID  ,'') LeadID
FROM #unsubscribed u  
LEFT JOIN  
#batch b  
ON u.batchid=b.BatchID  
    LEFT JOIN  
    #tblEnquiry tblEnq  
    ON u.Emails=tblEnq.Email  
        LEFT JOIN  
        #tblLead tblLead  
        ON u.Emails=tblLead.Email  
WHERE Emails LIKE '%'+@Recipient+'%'  
      AND (campaigntype IS NULL  
           OR campaigntype=CASE  
                             WHEN @campaigntype IS NULL  
                             THEN campaigntype  
                             ELSE @campaigntype  
                           END  
           AND campaignname=CASE  
                              WHEN @campaignname IS NULL  
                              THEN campaignname  
                              ELSE @campaignname  
                            END)  
      AND CONVERT( DATE, Unsubscribeddate ) BETWEEN CONVERT( DATE, @ModeTypeFromDate ) AND CONVERT( DATE, @ModeTypeToDate )  
ORDER BY Unsubscribeddate DESC  
--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
END;  
  ELSE  
BEGIN  
SELECT COUNT( u.BatchID ) OVER( )  
AS                                                                           TotalRow,   
       emails,   
       u.Batchid,   
       userid,   
       Unsubscribeddate,   
       ISNULL( campaignname, 'Unknown' )                                     campaignname,   
       CampaignDate,   
       ISNULL( campaigntype, 'Unknown' )                                     campaigntype,  
       CASE  
         WHEN leadno IS NOT NULL  
         THEN 'lead'  
         WHEN enquiryid IS NOT NULL  
         THEN 'enquiry'  
         ELSE ''  
       END  
    AS                                                                           entity,   
       COALESCE( leadno, enquiryid, 0 )                                      entityid,   
       COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
       COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname,   
       isnull(tblLead.LeadID  ,'') LeadID
		FROM #unsubscribed u  
		LEFT JOIN  
		#batch b  
		ON u.batchid=b.BatchID  
			LEFT JOIN  
			#tblEnquiry tblEnq  
			ON u.Emails=tblEnq.Email  
				LEFT JOIN  
				#tblLead tblLead  
				ON u.Emails=tblLead.Email  
		WHERE Emails LIKE '%'+@Recipient+'%'  
			  AND (campaigntype IS NULL  
				   OR campaigntype=CASE  
									 WHEN @campaigntype IS NULL  
									 THEN campaigntype  
									 ELSE @campaigntype  
								   END  
				   AND campaignname=CASE  
									  WHEN @campaignname IS NULL  
									  THEN campaignname  
									  ELSE @campaignname  
									END)  
		ORDER BY Unsubscribeddate DESC  
		--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
	 END;     
	end
  if(@Mode = 'bounced' )  
    begin
	    SELECT emails,   
		       batchid,   
			   userid,   
			   unsubscribeddate,   
			   Description  
			INTO #tblbounced  
			FROM  
			(  
			  SELECT t.message_tag3  
			  AS emails,   
					 ISNULL( t.message_tag2, 0 )  
			  AS Batchid,   
					 b.parentid  
			  AS userid,    
					 --min(t.event_time) as Unsubscribeddate,  
					 t.event_time  
			  AS Unsubscribeddate,   
					 ISNULL( event_desc, 'bounce' )+ISNULL( ' : '+reason, '' )  
			  AS description  
			  FROM MySMS.dbo.EmailDeliveryStatus  t with (nolock)   
			  JOIN  
			  #batch b  
			  ON t.batchid=b.BatchID  
			  WHERE parentid=@parentid  
					AND t.event_status<>'001'  
					AND CONVERT( DATE, t.CreatedOn ) BETWEEN @fromdate AND @todate
					
			       and  
					 t.id in (  select ID from  
						(  
					  SELECT max(id) as ID , Message_tag3  
						FROM MySMS.dbo.EmailDeliveryStatus  p with (nolock)  
					  where p.batchid = t.BatchID     
					   group by p.message_tag3  
						) as tbl   
					)       

			  UNION  
			  SELECT ToMail  
			  AS emails,   
					 ISNULL( t.BatchID, 0 )  
			  AS Batchid,   
					 parentid  
			  AS userid,    
					 --min(t.createdon) as Unsubscribeddate ,  
					 t.createdon  
			  AS Unsubscribeddate,   
					 ISNULL( BounceType, 'Bounce' )+ISNULL( ' : '+bouncesubtype, '' )  
			  AS description  
			  FROM MySMS.dbo.mailBounces  t with (nolock)   
			  JOIN  
			  #batch b  
			  ON t.batchid=b.BatchID  
			  WHERE parentid=@parentid  
					AND CONVERT( DATE, t.CreatedOn ) BETWEEN @fromdate AND @todate  
			) a;

	IF @ModeTypeFromDate<>''  
       AND @ModeTypeToDate<>''  
		BEGIN  
		SELECT COUNT( u.BatchID ) OVER( )  
		AS                                                                           TotalRow,   
			   emails,   
			   u.Batchid,   
			   userid,   
			   Unsubscribeddate,   
			   ISNULL( campaignname, 'Unknown' )                                     campaignname,   
			   CampaignDate,   
			   ISNULL( campaigntype, 'Unknown' )                         campaigntype,  
			   CASE  
				 WHEN leadno IS NOT NULL  
				 THEN 'lead'  
				 WHEN enquiryid IS NOT NULL  
				 THEN 'enquiry'  
				 ELSE ''  
			   END  
		AS                                                                           entity,   
			   COALESCE( leadno, enquiryid, 0 )                                      entityid,   
			   COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
			   COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname,   
			   isnull(tblLead.LeadID,'') LeadID,   
			   u.description  
		FROM #tblbounced u  
		LEFT JOIN  
		#batch b  
		ON u.batchid=b.BatchID  
			LEFT JOIN  
			#tblEnquiry tblEnq  
			ON u.Emails=tblEnq.Email  
				LEFT JOIN  
				#tblLead tblLead  
				ON u.Emails=tblLead.Email  
		WHERE Emails LIKE '%'+@Recipient+'%'  
			  AND (campaigntype IS NULL  
				   OR campaigntype=CASE  
									 WHEN @campaigntype IS NULL  
									 THEN campaigntype  
									 ELSE @campaigntype  
								   END  
				   AND campaignname=CASE  
									  WHEN @campaignname IS NULL  
									  THEN campaignname  
									  ELSE @campaignname  
									END)  
			  AND CONVERT( DATE, Unsubscribeddate ) BETWEEN CONVERT( DATE, @ModeTypeFromDate ) AND CONVERT( DATE, @ModeTypeToDate )  
		ORDER BY Unsubscribeddate DESC  
		--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
		END;  
		  ELSE  
		BEGIN  
		SELECT COUNT( u.BatchID ) OVER( )  
		AS                                                                           TotalRow,   
			   emails,   
			   u.Batchid,   
			   userid,   
			   Unsubscribeddate,   
			   ISNULL( campaignname, 'Unknown' )                                     campaignname,   
			   CampaignDate,   
			   ISNULL( campaigntype, 'Unknown' )                                     campaigntype,  
			   CASE  
				 WHEN leadno IS NOT NULL  
				 THEN 'lead'  
				 WHEN enquiryid IS NOT NULL  
				 THEN 'enquiry'  
				 ELSE ''  
			   END  
		AS                                                                           entity,   
			   COALESCE( leadno, enquiryid, 0 )                                      entityid,   
			   COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
			   COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname,   
			   isnull(tblLead.LeadID,   '') LeadID,
			   u.description  
		FROM #tblbounced u  
		LEFT JOIN  
		#batch b  
		ON u.batchid=b.BatchID  
			LEFT JOIN  
			#tblEnquiry tblEnq  
			ON u.Emails=tblEnq.Email  
				LEFT JOIN  
				#tblLead tblLead  
				ON u.Emails=tblLead.Email  
		WHERE Emails LIKE '%'+@Recipient+'%'  
			  AND (campaigntype IS NULL  
				   OR campaigntype=CASE  
									 WHEN @campaigntype IS NULL  
									 THEN campaigntype  
									 ELSE @campaigntype  
								   END  
				   AND campaignname=CASE  
									  WHEN @campaignname IS NULL  
									  THEN campaignname  
									  ELSE @campaignname  
									END)  
		ORDER BY Unsubscribeddate DESC  
		--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
		END;
			   

	end
  if(@Mode = 'bademails' ) 
     begin
	    SELECT emails,   
       batchid,   
       userid,   
       unsubscribeddate,   
       Description  
INTO #tblBadEmails  
FROM  
(  
 SELECT  t.MAIL_TOEMAIL  
  AS emails,   
        -- ISNULL( t.Mail_BatchID, 0 )  
		 case when charindex('~',t.[Mail_BatchID]) <> 0        
                   then (select  value from fn_split(t.[Mail_BatchID],'~') where Position = 2)        
       else        
          t.[Mail_BatchID]         
       end   
  AS Batchid,   
         t.[MAIL_USERID]   
  AS userid,    
         --min(t.event_time) as Unsubscribeddate,  
         CAST( t.CreatedOn AS DATETIME )  
  AS Unsubscribeddate,  
         --isnull(event_desc, 'bounce') + isnull(' : ' +reason,'') as description     
         ''  
  AS description  
  FROM [tbl_InvalidEmailID_KarixAPI]  t with (nolock)   
  JOIN  
  #batch b  
  ON   case when charindex('~',t.[Mail_BatchID]) <> 0        
                   then (select  value from fn_split(t.[Mail_BatchID],'~') where Position = 2)        
       else        
          t.[Mail_BatchID]         
       end   =   b.BatchID  
  WHERE parentid=@parentid  
        AND --t.event_status<>'001' and  
        CONVERT( DATE, CAST( t.CreatedOn AS DATETIME ) ) BETWEEN @fromdate AND @todate                 
  --union  
  --select     
  -- ToMail as emails,    
  -- isnull(t.BatchID,0) as [Batchid],    
  -- parentid as [userid],    
  -- --min(t.createdon) as Unsubscribeddate ,  
  -- t.createdon as Unsubscribeddate ,  
  -- isnull(BounceType,'Bounce')+isnull(' : '+bouncesubtype,'') as description                     
  -- from MySMS.dbo.mailBounces with (nolock)   
  -- t                  
  --join #batch b  on t.batchid=b.BatchID   
  --where parentid = @parentid and convert(date,t.CreatedOn) between @fromdate   and @todate                  
   ) a;

    IF @ModeTypeFromDate<>''  
   AND @ModeTypeToDate<>''  
BEGIN  
SELECT COUNT( u.BatchID ) OVER( )  
AS                                                                           TotalRow,   
       emails,   
       u.Batchid,   
       userid,   
       Unsubscribeddate,   
       ISNULL( campaignname, 'Unknown' )                         campaignname,   
       CampaignDate,   
       ISNULL( campaigntype, 'Unknown' )                                     campaigntype,  
       CASE  
         WHEN leadno IS NOT NULL  
         THEN 'lead'  
         WHEN enquiryid IS NOT NULL  
         THEN 'enquiry'  
         ELSE ''  
       END  
AS                                                                           entity,   
       COALESCE( leadno, enquiryid, 0 )                                      entityid,   
       COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
       COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname,   
       isnull(tblLead.LeadID,'') LeadID,
	   
       u.description  
FROM #tblBadEmails u  
LEFT JOIN  
#batch b  
ON u.batchid=b.BatchID  
    LEFT JOIN  
    #tblEnquiry tblEnq  
    ON u.Emails=tblEnq.Email  
        LEFT JOIN  
        #tblLead tblLead  
        ON u.Emails=tblLead.Email  
WHERE Emails LIKE '%'+@Recipient+'%'  
      AND (campaigntype IS NULL  
           OR campaigntype=CASE  
                             WHEN @campaigntype IS NULL  
                             THEN campaigntype  
                             ELSE @campaigntype  
                           END  
              AND campaignname=CASE  
                                 WHEN @campaignname IS NULL  
                                 THEN campaignname  
                                 ELSE @campaignname  
                               END)  
      AND CONVERT( DATE, Unsubscribeddate ) BETWEEN CONVERT( DATE, @ModeTypeFromDate ) AND CONVERT( DATE, @ModeTypeToDate )  
ORDER BY Unsubscribeddate DESC  
--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
END;  
  ELSE  
BEGIN  
SELECT COUNT( u.BatchID ) OVER( )  
AS                                                                           TotalRow,   
       emails,   
       u.Batchid,   
       userid,   
       Unsubscribeddate,   
       ISNULL( campaignname, 'Unknown' )                                     campaignname,   
       CampaignDate,   
       ISNULL( campaigntype, 'Unknown' )                                     campaigntype,  
       CASE  
         WHEN leadno IS NOT NULL  
         THEN 'lead'  
         WHEN enquiryid IS NOT NULL  
         THEN 'enquiry'  
         ELSE ''  
       END  
AS                                                                           entity,   
       COALESCE( leadno, enquiryid, 0 )                                      entityid,   
       COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
       COALESCE( tbllead.personname, tblenq.personname, '' )                 Personname,   
       isnull(tblLead.LeadID,   '') LeadID,
       u.description  
FROM #tblBadEmails u  
LEFT JOIN  
#batch b  
ON u.batchid=b.BatchID  
    LEFT JOIN  
    #tblEnquiry tblEnq  
    ON u.Emails=tblEnq.Email  
        LEFT JOIN  
        #tblLead tblLead  
        ON u.Emails=tblLead.Email  
WHERE Emails LIKE '%'+@Recipient+'%'  
      AND (campaigntype IS NULL  
           OR campaigntype=CASE  
                             WHEN @campaigntype IS NULL  
                             THEN campaigntype  
                             ELSE @campaigntype  
                           END  
              AND campaignname=CASE  
                                 WHEN @campaignname IS NULL  
                                 THEN campaignname  
                                 ELSE @campaignname  
                               END)  
ORDER BY Unsubscribeddate DESC  
--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;  
END; 



	 end
  if(@Mode = 'queuedmails' )
   begin
	 
	 SELECT emails,   
	 batchid,   
	 userid,   
	 unsubscribeddate,   
	 Description   
	INTO #tblqueue   
	FROM   
	(   
	 SELECT t.Mail_ToEmail   
	 AS emails,   
	 b.batchid   
	 AS Batchid,   
	 b.parentid   
	 AS userid,   
	 CAST( t.Mail_InsertedDate AS DATETIME )   
