	 JOIN   
	 #batch b   
	 ON b.batchid=t.Mail_BatchID   
	 WHERE b.ParentID=@parentid   
		AND CONVERT( DATE, t.Mail_InsertedDate ) BETWEEN @fromdate AND @todate   
	 */
	 
	 ) a

  IF @ModeTypeFromDate<>''   
   AND @ModeTypeToDate<>''   
		BEGIN   
		SELECT COUNT( u.BatchID ) OVER( )   
		AS TotalRow,   
		 emails,   
		 u.Batchid,   
		 userid,   
		 Unsubscribeddate,   
		 ISNULL( campaignname, 'Unknown' ) campaignname,   
		 CampaignDate,   
		 ISNULL( campaigntype, 'Unknown' ) campaigntype,   
		 CASE   
		 WHEN leadno IS NOT NULL   
		 THEN 'lead'   
		 WHEN enquiryid IS NOT NULL   
		 THEN 'enquiry'   
		 ELSE ''   
		 END   
		AS entity,   
		 COALESCE( leadno, enquiryid, 0 ) entityid,   
		 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
		 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,   
		isnull( tblLead.LeadID,   '') LeadID,
		 u.description   
		FROM #tblqueue u   
		LEFT JOIN   
		#batch b   
		ON u.batchid=b.BatchID   
		 LEFT JOIN   
		 #tblEnquiry tblEnq   
		 ON u.Emails=tblEnq.Email   
		 LEFT JOIN   
		 #tblLead tblLead   
		 ON u.Emails=tblLead.Email   
		WHERE Emails LIKE '%'+@Recipient+'%'   
		 AND (campaigntype IS NULL   
		 OR campaigntype=CASE   
		 WHEN @campaigntype IS NULL   
		 THEN campaigntype   
		 ELSE @campaigntype   
		 END   
		 AND campaignname=CASE   
		 WHEN @campaignname IS NULL   
		 THEN campaignname   
		 ELSE @campaignname   
		 END)   
		 AND CONVERT( DATE, Unsubscribeddate ) BETWEEN CONVERT( DATE, @ModeTypeFromDate ) AND CONVERT( DATE, @ModeTypeToDate )   
		ORDER BY Unsubscribeddate DESC   
	--	OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;   
		END;   
		 ELSE   
		BEGIN   
		SELECT COUNT( u.BatchID ) OVER( )   
		AS TotalRow,   
		 emails,   
		 u.Batchid,   
		 userid,   
		 Unsubscribeddate,   
		 ISNULL( campaignname, 'Unknown' ) campaignname,   
		 CampaignDate,   
		 ISNULL( campaigntype, 'Unknown' ) campaigntype,   
		 CASE   
		 WHEN leadno IS NOT NULL   
		 THEN 'lead'   
		 WHEN enquiryid IS NOT NULL   
		 THEN 'enquiry'   
		 ELSE ''   
		 END   
		AS entity,   
		 COALESCE( leadno, enquiryid, 0 ) entityid,   
		 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
		 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,   
		 isnull(tblLead.LeadID,   '') LeadID,
		 u.description   
		FROM #tblqueue u   
		LEFT JOIN   
		#batch b   
		ON u.batchid=b.BatchID   
		 LEFT JOIN   
		 #tblEnquiry tblEnq   
		 ON u.Emails=tblEnq.Email   
		 LEFT JOIN   
		 #tblLead tblLead   
		 ON u.Emails=tblLead.Email   
		WHERE Emails LIKE '%'+@Recipient+'%'   
		 AND (campaigntype IS NULL   
		 OR campaigntype=CASE   
		 WHEN @campaigntype IS NULL   
		 THEN campaigntype   
		 ELSE @campaigntype   
		 END   
		 AND campaignname=CASE   
		 WHEN @campaignname IS NULL   
		 THEN campaignname   
		 ELSE @campaignname   
		 END)   
		ORDER BY Unsubscribeddate DESC   
		--OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;   
    END;

      
 end


