 @parentid BIGINT,     
 @campaigntype NVARCHAR(20) =NULL,     
 @campaignname NVARCHAR(100)=NULL,     
 @fromdate DATE =NULL,     
 @todate DATE =NULL,     
 @mail_source NVARCHAR(200)=NULL,     
 @batchid BIGINT =NULL,     
 @reporttype NVARCHAR(50) =NULL,     
 @Recipient NVARCHAR(500),     
 @MailStatus NVARCHAR(100),-- for recipient 
