 --@ClickedToDate NVARCHAR(100), -- for clicked    
 @Link NVARCHAR(MAX),     -- for clicked
 --@UnsubscribedFromDate NVARCHAR(100), -- for unsubscribed   
 --@UnsubscribedToDate   NVARCHAR(100), -- for unsubscribed
 --@BouncedFromDate NVARCHAR(100), -- bounced, bad emails, queued    
 --@BouncedToDate  NVARCHAR(100), -- bounced, bad emails, queued
 
 @ModeTypeFromDate NVARCHAR(100), -- for delivered, clicked, unsubscribed, bounced, bad emails, queued
 @ModeTypeToDate NVARCHAR(100),  -- for delivered, clicked, unsubscribed, bounced, bad emails, queued 
 @Mode nvarchar(200)  
 )  
AS     
BEGIN     
--declare @parentid bigint=335,     
--@campaigntype nvarchar(20)=null,     
--@campaignname nvarchar(100)=null,     
--@fromdate date='2021-07-01',     
--@todate date='2021-07-10'     
IF @batchid=0     
BEGIN     
SET @batchid=NULL;     
END;     
IF @campaigntype=''     
BEGIN     
SET @campaigntype=NULL;     
END;     
IF @campaignname=''     
BEGIN     
SET @campaignname=NULL;     
END;     
IF @fromdate=''     
BEGIN     
SET @fromdate=NULL;     
END;     
IF @todate=''     
BEGIN     
SET @todate=NULL;     
END;     
IF @mail_source=''     
BEGIN     
SET @mail_source=NULL;     
END;     
IF @reporttype=''     
BEGIN     
SET @reporttype=NULL;     
END;     
IF @fromdate=NULL     
BEGIN     
SET @fromdate=CAST( DATEADD( m, DATEDIFF( m, 0, GETDATE( ) ), 0 ) AS DATE );     
SET @todate=CAST( GETDATE( ) AS DATE );     
END;     
  
