SELECT e.mail_guid,e.mail_batchid batchid,     
 e.Mail_ToEmail,     
 CASE     
 WHEN e.smtpserver='aws'     
 THEN a.mailstatus     
 WHEN e.smtpserver='karix'     
 THEN k.event_desc     
 ELSE 'Sent'     
