/*     
SELECT e.mail_guid,e.mail_batchid batchid,     
 e.Mail_ToEmail,     
 CASE     
 WHEN smtpserver='aws'     
 THEN a.mailstatus     
 WHEN smtpserver='karix'     
 THEN k.event_desc     
 ELSE 'Sent'     
 END     
AS MailStatus,     
 CASE     
 WHEN smtpserver='aws'     
 THEN a.description     
 WHEN smtpserver='karix'     
 THEN k.description     
 END     
AS Description,     
 CASE     
 WHEN smtpserver='aws'     
 THEN a.eventdate     
 WHEN smtpserver='karix'     
 THEN k.Delivereddate     
 END     
AS delivereddate,     
 smtpserver     
INTO #sent     
FROM     
(select cast(guid as nvarchar(100)) as mail_guid,email_id as mail_toemail,e.batchid as mail_batchid from     
ClientEmails e with (nolock)     
union all     
select cast(guid as nvarchar(100)),email_id,e.batchid from     
ThirtyDaysClientEmails e with (nolock)     
) e     
JOIN     
#batch b     
ON e.mail_batchid=b.BatchID     
LEFT JOIN     
#karixreport k     
ON k.BatchID=e.mail_batchid     
AND k.cust_ref_id=e.mail_guid     
LEFT JOIN     
#awsreport a     
ON a.BatchID=e.mail_BatchID     
AND a.apiheader=e.mail_GUID;     

*/
     
SELECT e.batchid,     
 customer_reference_id,     
 COUNT( 1 )     
AS OpenedTimes,     
 MAX( CAST( event_date+' '+event_time AS DATETIME ) ) LastOpened     
INTO #kopened     
FROM mysms.dbo.EngagementEventOpenClick e with (nolock)     
JOIN     #batch b     
ON e.BatchID=b.BatchID     
 AND ISNUMERIC( e.BatchID )=1     
 AND ISNUMERIC( b.BatchID )=1     
WHERE ISNULL( e.destination_url, '' )=''     
GROUP BY e.batchid,     
 customer_reference_id;     
