		select email_id,c.batchid from mysms.dbo.ThirtyDaysClientEmails c with (nolock) JOIN    
		#batch b  ON b.BatchID=c.batchid where   
		cast(c.SentDateTime as date) between @fromdate and @todate and  
		dbo.fn_isemailunsubscribed(@parentid,c.Email_Id)=1     
		) c  
		left join  
		mysms.dbo.tbl_subscription( NOLOCK ) t  
		ON t.emails=c.email_ID  
		WHERE t.UserID=@parentid  
			  AND dbo.fn_isemailunsubscribed(@parentid,email_id)=1  
		GROUP BY email_id,   
				c.batchid,   
