DROP TABLE IF EXISTS #kopened_Opened
drop table if exists #karixreport_Opened 
drop table if exists #kclicked_link
drop table if exists #kclicked_link1
DROP TABLE IF EXISTS #tblbounced;
DROP TABLE IF EXISTS #tblBadEmails
DROP TABLE IF EXISTS #tblqueue

END;     
     
     
     
