CREATE   PROCEDURE [dbo].[usp_emailreportsdetailed_Clicked] --0,20,33819,null,null,'2021-06-30','2021-07-29',null,null,null,'','','',''   
(   
 @OffsetValue INT =0,   
 @PagingSize INT =20,   
 @parentid BIGINT,   
 @campaigntype NVARCHAR(20) =NULL,   
 @campaignname NVARCHAR(100)=NULL,   
 @fromdate DATE =NULL,   
 @todate DATE =NULL,   
 @mail_source NVARCHAR(200)=NULL,   
 @batchid BIGINT =NULL,   
 @reporttype NVARCHAR(50) =NULL,   
 @Recipient NVARCHAR(500),   
 @ClickedFromDate NVARCHAR(100),   
 @ClickedToDate NVARCHAR(100),   
 @Link NVARCHAR(MAX))   
AS   
BEGIN   
--declare @parentid bigint=335,   
--@campaigntype nvarchar(20)=null,   
--@campaignname nvarchar(100)=null,   
--@fromdate date='2021-07-01',   
--@todate date='2021-07-10'   
IF @batchid=0   
BEGIN   
SET @batchid=NULL;   
END;   
IF @campaigntype=''   
BEGIN   
SET @campaigntype=NULL;   
END;   
IF @campaignname=''   
BEGIN   
SET @campaignname=NULL;   
END;   
IF @fromdate=''   
BEGIN   
SET @fromdate=NULL;   
END;   
IF @todate=''   
BEGIN   
SET @todate=NULL;   
END;   
IF @mail_source=''   
BEGIN   
SET @mail_source=NULL;   
END;   
IF @reporttype=''   
BEGIN   
SET @reporttype=NULL;   
END;   
IF @fromdate=NULL   
BEGIN   
SET @fromdate=CAST( DATEADD( m, DATEDIFF( m, 0, GETDATE( ) ), 0 ) AS DATE );   
SET @todate=CAST( GETDATE( ) AS DATE );   
END;   
CREATE TABLE #batchids   
(   
 batchid BIGINT);   
IF @mail_source IS NOT NULL   
BEGIN   
INSERT INTO #batchids   
(batchid)   
 SELECT batchid   
 FROM mysms.dbo.BatchEmail_Infos with (nolock)   
 WHERE userid=@parentid   
 AND mail_source=@mail_source   
 AND ISNULL( scheduleddate, batchinserttime ) BETWEEN @fromdate AND @todate;   
END;   
IF @batchid IS NOT NULL   
BEGIN   
INSERT INTO #batchids   
(batchid)   
 SELECT @batchid;   
END;   
DROP TABLE IF EXISTS #batch;   
--drop table if exists #invalidmails   
--drop table if exists #sent   
--drop table if exists #karixreport   
--drop table if exists #kopened   
--drop table if exists #kclicked   
--drop table if exists #awsreport   
--drop table if exists #unsubscribed   
DROP TABLE IF EXISTS #kclicked_link;   
DROP TABLE IF EXISTS #kclicked_link1;   
DROP TABLE IF EXISTS #tblEnquiry;   
DROP TABLE IF EXISTS #tblLead;   
SELECT b.batchid,   
 mail_source,   
 COALESCE( t.cname, c.campaignname,   
 CASE   
 WHEN mail_source IN( 'emails', 'csv' )   
 THEN CAST( ISNULL( scheduleddate, batchinserttime ) AS NVARCHAR(50) )+'_'+CAST( b.batchid AS NVARCHAR )   
 ELSE 'CRM_'+mail_source   
 END )   
AS campaignname,   
 CASE   
 WHEN t.id IS NOT NULL   
 THEN 'Triggered Campaign'   
 WHEN c.id IS NOT NULL   
 AND ISNULL( c.IsScheduled, 0 )=1   
 THEN 'Scheduled Campaign'   
 WHEN c.id IS NOT NULL   
 AND ISNULL( c.IsScheduled, 0 )=0   
 THEN 'Event Based Campaign'   
 WHEN mail_source IN( 'emails', 'csv' )   
 THEN 'Bulk Mail Campaign'   
 ELSE 'CRM Mails'   
 END   
AS campaigntype,   
 CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE ) CampaignDate,   
 TotalRecords,   
 scheduleddate,   
 batchinserttime   
INTO #batch   
FROM mysms.dbo.BatchEmail_Infos b with (nolock)   
JOIN   
mysms.dbo.user_detail u with (nolock)   
ON u.User_ID=b.UserID   
 LEFT JOIN   
 mysms.dbo.usercampaignmaster c with (nolock)   
 ON c.ParentID=u.parentid   
 AND b.mail_source LIKE 'campaign%'   
 AND CAST( c.ID AS NVARCHAR )=replace( b.mail_source, 'Campaign :', '' )   
 LEFT JOIN   
 mysms.dbo.triggeredcampaigns t with (nolock)   
 ON c.eventid=t.eventid   
 AND t.mailcampaignid=c.id   
 LEFT JOIN   
 #batchids bd   
 ON b.batchid=bd.BatchID   
WHERE u.ParentID=@parentid   
 AND ISNULL( bd.batchid, 0 )=CASE   
 WHEN @mail_source IS NOT NULL   
 OR @batchid IS NOT NULL   
 THEN bd.batchid   
 ELSE 0   
 END   
 AND CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE ) BETWEEN @fromdate AND @todate;   
--select emails,isnull(t.batchid,0) Batchid,userid,min(CreatedOn) as Unsubscribeddate   
--into #unsubscribed   
--from mysms.dbo.tbl_subscription t with (nolock)   
--left join #batch b   
--on t.batchid=b.BatchID   
--where t.UserID=@parentid and Status='Unsubscribed'   
--group by emails,isnull(t.batchid,0),userid   
--select e.BatchID,e.cust_ref_id,event_status,event_desc,Reason as Description,cast(event_time as datetime) as Delivereddate   
--into #karixreport   
--from mysms.dbo.EmailDeliveryStatus e with (nolock)   
--join #batch b on e.BatchID=b.BatchID   
--create table #awsreport(batchid bigint,apiheader nvarchar(100),mailstatus nvarchar(50),description nvarchar(200), eventdate datetime)   
--insert into #awsreport(batchid,apiheader,mailstatus,description,eventdate)   
--select e.batchid,APIHeader,'Delivered' as mailstatus,'' as description,Delivereddate   
--from mysms.dbo.Maildeliveries e with (nolock)   
--join #batch b on e.BatchID=b.BatchID   
--union   
--select e.batchid,apiheader,'Bounced' as mailstatus,cast(bouncetype as nvarchar(20))+'- '+BounceSubType as Description,createdon   
--from mysms.dbo.Mailbounces e with (nolock)   
--join #batch b on e.BatchID=b.BatchID   
--select e.mail_batchid batchid,e.Mail_ToEmail,   
--case when smtpserver='aws' then a.mailstatus   
--when smtpserver='karix' then k.event_desc   
--else 'Sent' end as MailStatus,   
--case when smtpserver='aws' then a.description   
--when smtpserver='karix' then k.description   
-- end as Description,   
--case when smtpserver='aws' then a.eventdate   
--when smtpserver='karix' then k.Delivereddate   
-- end as delivereddate,   
-- smtpserver   
--into #sent   
--from mysmstrans.dbo.emailsreportsent e with (nolock)   
--join #batch b on e.Mail_BatchID=b.BatchID   
--left join #karixreport k on k.BatchID=e.Mail_BatchID and k.cust_ref_id=e.Mail_GUID   
--left join #awsreport a on a.BatchID=e.Mail_BatchID and a.apiheader=e.Mail_GUID   
--select e.mail_batchid batchid,e.Mail_ToEmail,'Not Sent' as mailstatus   
--into #invalidmails   
--from mysmstrans.dbo.invalid_mail_emailsreport e with (nolock)   
--join #batch b on e.Mail_BatchID=b.BatchID   
--select e.batchid,customer_reference_id,count(1) as OpenedTimes,max(cast((event_date + ' '+event_time) as datetime)) LastOpened   
--into #kopened   
--from   
--mysms.dbo.[EngagementEventOpenClick] e with (nolock)   
--join #batch b on e.BatchID=b.BatchID   
--where isnull(e.destination_url,'')=''   
--group by e.batchid,customer_reference_id   
----order by cast((event_date + ' '+event_time) as datetime)   
SELECT e.batchid,   
 e.to_email,   
 MAX( CAST( event_date+' '+event_time AS DATETIME ) ) LastClickedTime   
INTO #kclicked   
FROM mysms.dbo.EngagementEventOpenClick e with (nolock)   
JOIN   
#batch b   
ON e.BatchID=b.BatchID   
 AND ISNUMERIC( e.BatchID )=1   
 AND ISNUMERIC( b.BatchID )=1   
WHERE ISNULL( e.destination_url, '' )<>''   
GROUP BY e.batchid,   
 e.to_email;   
--order by cast((event_date + ' '+event_time) as datetime) desc   
/* start leadid and img handling */   
SELECT v.leadno,   
 ISNULL( personname, '' ) personname,   
 ISNULL( ProfileImgFileName, '' ) ProfileImgFileName,   
 email,   
 u.ID   
AS LeadID   
INTO #tbllead   
FROM mysms.dbo.Userleads_Mobile_Email v with (nolock)   
JOIN   
mysms.dbo.userleads u with (nolock)   
ON u.parentid=v.parentid   
 AND v.leadno=u.LeadNo   
WHERE v.parentid=@parentid   
 AND email<>'1'
  and v.ulme_id=(select max(ulme_id) from mysms.dbo.Userleads_Mobile_Email with (nolock) where email=v.email )
 ;   
SELECT v.enquiryid,   
 ISNULL( personname, '' ) personname,   
 ISNULL( ProfileImgFileName, '' ) ProfileImgFileName,   
 email   
INTO #tblEnquiry   
FROM mysms.dbo.Userenquiry_Mobile_Email v with (nolock)   
JOIN   
mysms.dbo.userenquiry u with (nolock)   
ON u.parentid=v.parentid   
 AND v.enquiryid=u.enquiryid   
WHERE v.parentid=@parentid   
 AND email<>'1'
   and v.enquiryid=(select max(enquiryid) from mysms.dbo.Userenquiry_Mobile_Email with (nolock) where email=v.email )

 ;   
/* end leadid and img handling */   
IF @ClickedFromDate<>''   
 AND @ClickedToDate<>''   
BEGIN   
SELECT e.batchid,   
 e.to_email,   
 e.destination_url,   
 CAST( event_date+' '+event_time AS DATETIME ) ClickedTime,   
 campaignname,   
 BatchInsertTime   
INTO #kclicked_link   
FROM mysms.dbo.EngagementEventOpenClick e with (nolock)   
JOIN   
#batch b   
ON CAST( ISNULL( NULLIF( e.BatchID, 'null' ), 0 ) AS BIGINT )=b.BatchID   
WHERE ISNULL( e.destination_url, '' )<>''   
 AND (campaigntype IS NULL   
 OR campaigntype=CASE   
 WHEN @campaigntype IS NULL   
 THEN campaigntype   
 ELSE @campaigntype   
 END   
 AND campaignname=CASE   
 WHEN @campaignname IS NULL   
 THEN campaignname   
 ELSE @campaignname   
 END);   
SELECT COUNT( k.BatchID ) OVER( )   
AS TotalRow,   
 k.batchid,   
 destination_url Link,   
 Mail_ToEmail Email,   
 k.campaignname,   
 k.BatchInsertTime   
AS Senttime,   
 ClickedTime,   
 CASE   
 WHEN leadno IS NOT NULL   
 THEN 'lead'   
 WHEN enquiryid IS NOT NULL   
 THEN 'enquiry'   
 ELSE ''   
 END   
AS entity,   
 COALESCE( leadno, enquiryid, 0 ) entityid,   
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,   
 tblLead.LeadID   
FROM #kclicked_link k   
JOIN   
    --mysmstrans.dbo.emailsreportsent e with (nolock) 
	   (
		  select cast(guid as nvarchar(100)) as mail_guid,email_id as mail_toemail,e.batchid as mail_batchid from     
		    ClientEmails e with (nolock)     
			union all     
			select cast(guid as nvarchar(100)),email_id,e.batchid from     
			ThirtyDaysClientEmails e with (nolock)     
	  ) e

ON e.Mail_BatchID=k.BatchID   
 AND k.to_email=e.Mail_ToEmail   
 LEFT JOIN   
 #tblEnquiry tblEnq   
 ON e.Mail_ToEmail=tblEnq.Email   
 LEFT JOIN   
 #tblLead tblLead   
 ON e.Mail_ToEmail=tblLead.Email   
WHERE destination_url LIKE '%'+@Link+'%'   
 AND Mail_ToEmail LIKE '%'+@Recipient+'%'   
 AND ClickedTime IS NOT NULL   
 AND CONVERT( DATE, ClickedTime ) BETWEEN CONVERT( DATE, @ClickedFromDate ) AND CONVERT( DATE, @ClickedToDate )   
ORDER BY ClickedTime DESC   
OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;   
END;   
 ELSE   
BEGIN   
SELECT e.batchid,   
 e.to_email,   
 e.destination_url,   
 CAST( event_date+' '+event_time AS DATETIME ) ClickedTime,   
 campaignname,   
 BatchInsertTime   
INTO #kclicked_link1   
FROM mysms.dbo.EngagementEventOpenClick e with (nolock)   
JOIN   
#batch b   
ON CAST( ISNULL( NULLIF( e.BatchID, 'null' ), 0 ) AS BIGINT )=b.BatchID   
WHERE ISNULL( e.destination_url, '' )<>''
 --and cast(e.CreatedOn as date) between @fromdate and @todate   
 AND (campaigntype IS NULL   
 OR campaigntype=CASE   
 WHEN @campaigntype IS NULL   
 THEN campaigntype   
 ELSE @campaigntype   
 END   
 AND campaignname=CASE   
 WHEN @campaignname IS NULL   
 THEN campaignname   
 ELSE @campaignname   
 END);   
SELECT COUNT( k.BatchID ) OVER( )   
AS TotalRow,   
 k.batchid,   
 destination_url Link,   
 Mail_ToEmail Email,   
 k.campaignname,   
 k.BatchInsertTime   
AS Senttime,   
 ClickedTime,   
 CASE   
 WHEN leadno IS NOT NULL   
 THEN 'lead'   
 WHEN enquiryid IS NOT NULL   
 THEN 'enquiry'   
 ELSE ''   
 END   
AS entity,   
 COALESCE( leadno, enquiryid, 0 ) entityid,   
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,   
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,   
 tblLead.LeadID   
FROM #kclicked_link1 k   
JOIN   
--mysmstrans.dbo.emailsreportsent e with (nolock)   
(select cast(guid as nvarchar(100)) as mail_guid,email_id as mail_toemail,e.batchid as mail_batchid from   
ClientEmails e with (nolock)   
union all   
select cast(guid as nvarchar(100)),email_id,e.batchid from   
ThirtyDaysClientEmails e with (nolock)   
)   
e   
ON e.Mail_BatchID=k.BatchID   
 AND k.to_email=e.mail_toemail   
 LEFT JOIN   
 #tblEnquiry tblEnq   
 ON e.Mail_ToEmail=tblEnq.Email   
 LEFT JOIN   
 #tblLead tblLead   
 ON e.Mail_ToEmail=tblLead.Email   
WHERE destination_url LIKE '%'+@Link+'%'   
 AND Mail_ToEmail LIKE '%'+@Recipient+'%'   
 AND ClickedTime IS NOT NULL   
ORDER BY ClickedTime DESC   
OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;   
END;   
DROP TABLE IF EXISTS #batch;   
--drop table if exists #invalidmails   
--drop table if exists #sent   
--drop table if exists #karixreport   
--drop table if exists #kopened   
--drop table if exists #kclicked   
--drop table if exists #awsreport   
--drop table if exists #unsubscribed   
--drop table if exists #batchids   
DROP TABLE IF EXISTS #kclicked_link;   
DROP TABLE IF EXISTS #kclicked_link1;   
DROP TABLE IF EXISTS #tblEnquiry;   
DROP TABLE IF EXISTS #tblLead;   
END;   




