/* ============================================================
   Procedure: [dbo].[usp_emailreportsdetailed_Delivered]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     
CREATE   PROCEDURE [dbo].[usp_emailreportsdetailed_Delivered] --0,2000,39008,null,null,'2022-06-24','2022-06-25',null,89907301,null,'','',''     
(     
 @OffsetValue INT =0,     
 @PagingSize INT =20,     
 @parentid BIGINT,     
 @campaigntype NVARCHAR(20) =NULL,     
 @campaignname NVARCHAR(100)=NULL,     
 @fromdate DATE =NULL,     
 @todate DATE =NULL,     
 @mail_source NVARCHAR(200)=NULL,     
 @batchid BIGINT =NULL,     
 @reporttype NVARCHAR(50) =NULL,     
 @Recipient NVARCHAR(500),     
 @DeliveredFrom NVARCHAR(100),     
 @DeliveredTo NVARCHAR(100))     
AS     
BEGIN     
--declare @parentid bigint=335,     
--@campaigntype nvarchar(20)=null,     
--@campaignname nvarchar(100)=null,     
--@fromdate date='2021-07-01',     
--@todate date='2021-07-10'     
IF @batchid=0     
BEGIN     
SET @batchid=NULL;     
END;     
IF @campaigntype=''     
BEGIN     
SET @campaigntype=NULL;     
END;     
IF @campaignname=''     
BEGIN     
SET @campaignname=NULL;     
END;     
IF @fromdate=''     
BEGIN     
SET @fromdate=NULL;     
END;     
IF @todate=''     
BEGIN     
SET @todate=NULL;     
END;     
IF @mail_source=''     
BEGIN     
SET @mail_source=NULL;     
END;     
IF @reporttype=''     
BEGIN     
SET @reporttype=NULL;     
END;     
IF @fromdate=NULL     
BEGIN     
SET @fromdate=CAST( DATEADD( m, DATEDIFF( m, 0, GETDATE( ) ), 0 ) AS DATE );     
SET @todate=CAST( GETDATE( ) AS DATE );     
END;     
CREATE TABLE #batchids     
(     
 batchid BIGINT);     
IF @mail_source IS NOT NULL     
BEGIN     
INSERT INTO #batchids     
(batchid)     
 SELECT batchid     
 FROM mysms.dbo.BatchEmail_Infos with (nolock)     
 WHERE userid=@parentid     
 AND mail_source=@mail_source     
 AND ISNULL( scheduleddate, batchinserttime ) BETWEEN @fromdate AND @todate;     
END;     
IF @batchid IS NOT NULL     
BEGIN     
INSERT INTO #batchids     
(batchid)     
 SELECT @batchid;     
END;     
DROP TABLE IF EXISTS #batch;     
DROP TABLE IF EXISTS #invalidmails;     
DROP TABLE IF EXISTS #sent;     
DROP TABLE IF EXISTS #karixreport;     
--drop table if exists #kopened     
--drop table if exists #kclicked     
DROP TABLE IF EXISTS #awsreport;     
--drop table if exists #unsubscribed     
SELECT b.batchid,     
 mail_source,     
 COALESCE( t.cname, c.campaignname,     
 CASE     
 WHEN mail_source IN( 'emails', 'csv' )     
 THEN CAST( ISNULL( scheduleddate, batchinserttime ) AS NVARCHAR(50) )+'_'+CAST( b.batchid AS NVARCHAR )     
 ELSE 'CRM_'+mail_source     
 END )     
AS campaignname,     
 CASE     
 WHEN t.id IS NOT NULL     
 THEN 'Triggered Campaign'     
 WHEN c.id IS NOT NULL     
 AND ISNULL( c.IsScheduled, 0 )=1     
 THEN 'Scheduled Campaign'     
 WHEN c.id IS NOT NULL     
 AND ISNULL( c.IsScheduled, 0 )=0     
 THEN 'Event Based Campaign'     
 WHEN mail_source IN( 'emails', 'csv' )     
 THEN 'Bulk Mail Campaign'     
 ELSE 'CRM Mails'     
 END     
AS campaigntype,     
 CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE ) CampaignDate,     
 TotalRecords,     
 scheduleddate,     
 batchinserttime,     
 case when isnull(b.finalmailroute,b.mailroute)='T' and a.id is not null and a.isactive=1 then 'aws'     
 when k.id is not null then 'karix'     
 else '' end as smtpserver     
INTO #batch     
FROM mysms.dbo.BatchEmail_Infos b with (nolock)     
JOIN     
mysms.dbo.user_detail u with (nolock)     
ON u.User_ID=b.UserID     
 LEFT JOIN     
 mysms.dbo.usercampaignmaster c with (nolock)     
 ON c.ParentID=u.parentid     
 AND b.mail_source LIKE 'campaign%'     
 AND CAST( c.ID AS NVARCHAR )=replace( b.mail_source, 'Campaign :', '' )     
 LEFT JOIN     
 mysms.dbo.triggeredcampaigns t with (nolock)     
 ON c.eventid=t.eventid     
 AND t.mailcampaignid=c.id     
 LEFT JOIN     
 #batchids bd     
 ON b.batchid=bd.BatchID     
left join Mysms.dbo.awsmailroute a on a.mailuser= b.UserID and SenderName=a.frommailid     
left join Mysms.dbo.karixmailroute k on k.mailuser= b.UserID and SenderName=k.frommailid     
WHERE u.ParentID=@parentid     
 AND ISNULL( bd.batchid, 0 )=CASE     
 WHEN @mail_source IS NOT NULL     
 OR @batchid IS NOT NULL     
 THEN bd.batchid     
 ELSE 0     
 END     
 AND CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE ) BETWEEN @fromdate AND @todate;     
--select emails,isnull(t.batchid,0) Batchid,userid,min(CreatedOn) as Unsubscribeddate     
--into #unsubscribed     
--from mysms.dbo.tbl_subscription t with (nolock)     
--left join #batch b     
--on t.batchid=b.BatchID     
--where t.UserID=@parentid and Status='Unsubscribed'     
--group by emails,isnull(t.batchid,0),userid     
SELECT e.BatchID,     
 e.cust_ref_id,     
 event_status,     
 event_desc,     
 Reason     
AS Description,     
 CAST( event_time AS DATETIME )     
AS Delivereddate     
INTO #karixreport     
FROM mysms.dbo.EmailDeliveryStatus e with (nolock)     
JOIN     
#batch b     
ON e.BatchID=b.BatchID  
where event_status = '001'  
;     
CREATE TABLE #awsreport     
(     
 batchid BIGINT,     
 apiheader NVARCHAR(100),     
 mailstatus NVARCHAR(50),     
 description NVARCHAR(200),     
 eventdate DATETIME);     
INSERT INTO #awsreport     
(batchid,     
 apiheader,     
 mailstatus,     
 description,     
 eventdate)     
 SELECT e.batchid,     
 APIHeader,     
 'Delivered'     
 AS mailstatus,     
 ''     
 AS description,     
 Delivereddate     
 FROM mysms.dbo.Maildeliveries e with (nolock)     
 JOIN     
 #batch b     
 ON e.BatchID=b.BatchID     
 UNION     
 SELECT e.batchid,     
 apiheader,     
 'Bounced'     
 AS mailstatus,     
 CAST( bouncetype AS NVARCHAR(20) )+'- '+BounceSubType     
 AS Description,     
 createdon     
 FROM mysms.dbo.Mailbounces e with (nolock)     
 JOIN     
 #batch b     
 ON e.BatchID=b.BatchID;     
     
/*     
SELECT e.mail_batchid batchid,     
 e.Mail_ToEmail,     
 CASE     
 WHEN smtpserver='aws'     
 THEN a.mailstatus     
 WHEN smtpserver='karix'     
 THEN k.event_desc     
 ELSE 'Sent'     
 END     
AS MailStatus,     
 CASE     
 WHEN smtpserver='aws'     
 THEN a.description     
 WHEN smtpserver='karix'     
 THEN k.description     
 END     
AS Description,     
 CASE     
 WHEN smtpserver='aws'     
 THEN a.eventdate     
 WHEN smtpserver='karix'     
 THEN k.Delivereddate     
 END     
AS delivereddate,     
 smtpserver     
INTO #sent     
FROM mysmstrans.dbo.emailsreportsent e with (nolock)     
JOIN     
#batch b     
ON e.Mail_BatchID=b.BatchID     
 LEFT JOIN     
 #karixreport k     
 ON k.BatchID=e.Mail_BatchID     
 AND k.cust_ref_id=e.Mail_GUID     
 LEFT JOIN     
 #awsreport a     
 ON a.BatchID=e.Mail_BatchID     
 AND a.apiheader=e.Mail_GUID;     
SELECT e.mail_batchid batchid,     
 e.Mail_ToEmail,     
 'Not Sent'     
AS mailstatus     
INTO #invalidmails     
FROM mysmstrans.dbo.invalid_mail_emailsreport e with (nolock)     
JOIN     
#batch b     
ON e.Mail_BatchID=b.BatchID;     
*/     
     
SELECT e.mail_guid,e.mail_batchid batchid,     
 e.Mail_ToEmail,     
 CASE     
 WHEN smtpserver='aws'     
 THEN a.mailstatus     
 WHEN smtpserver='karix'     
 THEN k.event_desc     
 ELSE 'Sent'     
 END     
AS MailStatus,     
 CASE     
 WHEN smtpserver='aws'     
 THEN a.description     
 WHEN smtpserver='karix'     
 THEN k.description     
 END     
AS Description,     
 CASE     
 WHEN smtpserver='aws'     
 THEN a.eventdate     
 WHEN smtpserver='karix'     
 THEN k.Delivereddate     
 END     
AS delivereddate,     
 smtpserver     
INTO #sent     
FROM     
(select cast(guid as nvarchar(100)) as mail_guid,email_id as mail_toemail,e.batchid as mail_batchid from     
ClientEmails e with (nolock)     
union all     
select cast(guid as nvarchar(100)),email_id,e.batchid from     
ThirtyDaysClientEmails e with (nolock)     
) e     
JOIN     
#batch b     
ON e.mail_batchid=b.BatchID     
LEFT JOIN     
#karixreport k     
ON k.BatchID=e.mail_batchid     
AND k.cust_ref_id=e.mail_guid     
LEFT JOIN     
#awsreport a     
ON a.BatchID=e.mail_BatchID     
AND a.apiheader=e.mail_GUID;     
     
--select e.batchid,customer_reference_id,count(1) as OpenedTimes,max(cast((event_date + ' '+event_time) as datetime)) LastOpened     
--into #kopened     
--from     
--mysms.dbo.[EngagementEventOpenClick] e with (nolock)     
--join #batch b on e.BatchID=b.BatchID     
--where isnull(e.destination_url,'')=''     
--group by e.batchid,customer_reference_id     
----order by cast((event_date + ' '+event_time) as datetime)     
--select e.batchid,e.customer_reference_id ,     
--max(cast((event_date + ' '+event_time) as datetime)) LastClickedTime     
--into #kclicked     
--from     
--mysms.dbo.[EngagementEventOpenClick] e with (nolock)     
--join #batch b on e.BatchID=b.BatchID     
--where isnull(e.destination_url,'')<>''     
--group by e.batchid,e.customer_reference_id     
----order by cast((event_date + ' '+event_time) as datetime) desc     
/* start leadid and img handling */     
SELECT v.leadno,     
 ISNULL( personname, '' ) personname,     
 ISNULL( ProfileImgFileName, '' ) ProfileImgFileName,     
 email,     
 u.ID     
AS LeadID     
INTO #tbllead     
FROM mysms.dbo.Userleads_Mobile_Email v with (nolock)     
JOIN     
mysms.dbo.userleads u with (nolock)     
ON u.parentid=v.parentid     
 AND v.leadno=u.LeadNo     
WHERE v.parentid=@parentid     
 AND email<>'1'
 and ulme_id=(select max(ulme_id) from mysms.dbo.Userleads_Mobile_Email  with (nolock) where email=v.email)
 ;     
SELECT v.enquiryid,     
 ISNULL( personname, '' ) personname,     
 ISNULL( ProfileImgFileName, '' ) ProfileImgFileName,     
 email     
INTO #tblEnquiry     
FROM mysms.dbo.Userenquiry_Mobile_Email v with (nolock)     
JOIN     
mysms.dbo.userenquiry u with (nolock)     
ON u.parentid=v.parentid     
 AND v.enquiryid=u.enquiryid     
WHERE v.parentid=@parentid     
 AND email<>'1'
 and v.enquiryid=(select max(enquiryid) from mysms.dbo.Userenquiry_Mobile_Email with (nolock) where email=v.email)
 ;     
/* end leadid and img handling */     
IF @DeliveredFrom<>''     
 AND @DeliveredTo<>''     
BEGIN     
SELECT COUNT( batchid ) OVER( )     
AS TotalRow,     
 CampaignDate,     
 campaigntype,     
 campaignname,     
 batchid,     
 SentTime,     
 Mail_ToEmail,     
 delivereddate,     
 entity,     
 entityid,     
 image,     
 Personname,     
 LeadID     
FROM     
(     
 SELECT CampaignDate,     
 campaigntype,     
 campaignname,     
 b.batchid,     
 ISNULL( scheduleddate, batchinserttime )     
 AS SentTime,     
 s.Mail_ToEmail Mail_ToEmail,     
 delivereddate,     
 CASE     
 WHEN leadno IS NOT NULL     
 THEN 'lead'     
 WHEN enquiryid IS NOT NULL     
 THEN 'enquiry'     
 ELSE ''     
 END     
 AS entity,     
 COALESCE( leadno, enquiryid, 0 ) entityid,     
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,     
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,     
 tblLead.LeadID     
 FROM #batch b     
 LEFT JOIN     
 #sent s     
 ON b.BatchID=s.batchid     
 --left join #kopened ko on ko.BatchID=b.BatchID     
 --left join #kclicked kc on kc.BatchID=b.BatchID     
 --LEFT JOIN     
 --#invalidmails i     
 --ON i.batchid=b.BatchID     
 --left join #unsubscribed u on u.Batchid=b.BatchID     
 LEFT JOIN     
 #tblEnquiry tblEnq     
 ON s.Mail_ToEmail=tblEnq.Email     
 LEFT JOIN     
 #tblLead tblLead     
 ON s.Mail_ToEmail=tblLead.Email     
 --union     
 --select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime,     
 --s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened     
 --from     
 --#batch b     
 --left join #invalidmails s on s.batchid=b.BatchID     
) a     
WHERE Mail_ToEmail LIKE '%'+@Recipient+'%'     
 AND campaigntype=CASE     
 WHEN @campaigntype IS NULL     
 THEN campaigntype     
 ELSE @campaigntype     
 END     
 AND campaignname=CASE     
 WHEN @campaignname IS NULL     
 THEN campaignname     
 ELSE @campaignname     
 END     
 AND delivereddate IS NOT NULL     
 AND CONVERT( DATE, delivereddate ) BETWEEN CONVERT( DATE, @DeliveredFrom ) AND CONVERT( DATE, @DeliveredTo )     
--group by CampaignDate,campaigntype,campaignname,mail_source     
ORDER BY CampaignDate DESC     
OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;     
END;     
 ELSE     
BEGIN     
SELECT COUNT( batchid ) OVER( )     
AS TotalRow,     
 CampaignDate,     
 campaigntype,     
 campaignname,     
 batchid,     
 SentTime,     
 Mail_ToEmail,     
 delivereddate,     
 entity,     
 entityid,     
 image,     
 Personname,     
 LeadID     
FROM     
(    
 SELECT CampaignDate,     
 campaigntype,     
 campaignname,     
 b.batchid,     
 ISNULL( scheduleddate, batchinserttime )     
 AS SentTime,     
 s.Mail_ToEmail Mail_ToEmail,     
 delivereddate,     
 CASE     
 WHEN leadno IS NOT NULL     
 THEN 'lead'     
 WHEN enquiryid IS NOT NULL     
 THEN 'enquiry'     
 ELSE ''     
 END     
 AS entity,     
 COALESCE( leadno, enquiryid, 0 ) entityid,     
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image,     
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname,     
 tblLead.LeadID     
 FROM #batch b     
 LEFT JOIN     
 #sent s     
 ON b.BatchID=s.batchid     
 --left join #kopened ko on ko.BatchID=b.BatchID     
 --left join #kclicked kc on kc.BatchID=b.BatchID     
 --LEFT JOIN     
 --#invalidmails i     
 --ON i.batchid=b.BatchID     
 --left join #unsubscribed u on u.Batchid=b.BatchID     
 LEFT JOIN     
 #tblEnquiry tblEnq     
 ON s.Mail_ToEmail=tblEnq.Email     
 LEFT JOIN     
 #tblLead tblLead     
 ON s.Mail_ToEmail =tblLead.Email     
 --union     
 --select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime,     
 --s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened     
 --from     
 --#batch b     
 --left join #invalidmails s on s.batchid=b.BatchID     
) a     
WHERE Mail_ToEmail LIKE '%'+@Recipient+'%'     
 AND campaigntype=CASE     
 WHEN @campaigntype IS NULL     
 THEN campaigntype     
 ELSE @campaigntype     
 END     
 AND campaignname=CASE     
 WHEN @campaignname IS NULL     
 THEN campaignname     
 ELSE @campaignname     
 END     
 AND delivereddate IS NOT NULL     
--group by CampaignDate,campaigntype,campaignname,mail_source     
ORDER BY CampaignDate DESC     
OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY;     
END;     
DROP TABLE IF EXISTS #batch;     
DROP TABLE IF EXISTS #invalidmails;     
DROP TABLE IF EXISTS #sent;     
DROP TABLE IF EXISTS #karixreport;     
--drop table if exists #kopened     
--drop table if exists #kclicked     
DROP TABLE IF EXISTS #awsreport;     
--drop table if exists #unsubscribed     
DROP TABLE IF EXISTS #tblEnquiry;     
DROP TABLE IF EXISTS #tblLead;     
END; 


