/* start leadid and img handling */ 
SELECT v.leadno, 
 ISNULL( personname, '' ) personname, 
 ISNULL( ProfileImgFileName, '' ) ProfileImgFileName, 
 email, 
 u.ID 
AS LeadID 
INTO #tbllead 
FROM mysms.dbo.Userleads_Mobile_Email v with (nolock) 
JOIN 
mysms.dbo.userleads u with (nolock) 
ON u.parentid=v.parentid 
 AND v.leadno=u.LeadNo 
WHERE v.parentid=@parentid 
 AND email<>'1'; 
SELECT v.enquiryid, 
 ISNULL( personname, '' ) personname, 
 ISNULL( ProfileImgFileName, '' ) ProfileImgFileName, 
 email 
INTO #tblEnquiry 
FROM mysms.dbo.Userenquiry_Mobile_Email v with (nolock) 
JOIN 
mysms.dbo.userenquiry u with (nolock) 
ON u.parentid=v.parentid 
 AND v.enquiryid=u.enquiryid 
WHERE v.parentid=@parentid 
 AND email<>'1'; 
/* end leadid and img handling */ 
IF @DeliveredFrom<>'' 
 AND @DeliveredTo<>'' 
BEGIN 
SELECT COUNT( batchid ) OVER( ) 
AS TotalRow, 
 CampaignDate, 
 campaigntype, 
 campaignname, 
 batchid, 
 SentTime, 
 Mail_ToEmail, 
 delivereddate, 
 entity, 
 entityid, 
 image, 
 Personname, 
 LeadID 
FROM 
( 
 SELECT CampaignDate, 
 campaigntype, 
 campaignname, 
 b.batchid, 
 ISNULL( scheduleddate, batchinserttime ) 
 AS SentTime, 
 ISNULL( s.Mail_ToEmail, i.Mail_ToEmail ) Mail_ToEmail, 
 delivereddate, 
 CASE 
 WHEN leadno IS NOT NULL 
 THEN 'lead' 
 WHEN enquiryid IS NOT NULL 
 THEN 'enquiry' 
 ELSE '' 
 END 
 AS entity, 
 COALESCE( leadno, enquiryid, 0 ) entityid, 
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image, 
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname, 
 tblLead.LeadID 
 FROM #batch b 
 LEFT JOIN 
 #sent s 
 ON b.BatchID=s.batchid 
 --left join #kopened ko on ko.BatchID=b.BatchID 
 --left join #kclicked kc on kc.BatchID=b.BatchID 
 LEFT JOIN 
 #invalidmails i 
 ON i.batchid=b.BatchID 
 --left join #unsubscribed u on u.Batchid=b.BatchID 
 LEFT JOIN 
 #tblEnquiry tblEnq 
 ON ISNULL( s.Mail_ToEmail, i.Mail_ToEmail )=tblEnq.Email 
 LEFT JOIN 
 #tblLead tblLead 
 ON ISNULL( s.Mail_ToEmail, i.Mail_ToEmail )=tblLead.Email 
 --union 
 --select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime, 
 --s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened 
 --from 
 --#batch b 
 --left join #invalidmails s on s.batchid=b.BatchID 
) a 
WHERE Mail_ToEmail LIKE '%'+@Recipient+'%' 
 AND campaigntype=CASE 
 WHEN @campaigntype IS NULL 
 THEN campaigntype 
 ELSE @campaigntype 
 END 
 AND campaignname=CASE 
 WHEN @campaignname IS NULL 
 THEN campaignname 
 ELSE @campaignname 
 END 
 AND delivereddate IS NOT NULL 
 AND CONVERT( DATE, delivereddate ) BETWEEN CONVERT( DATE, @DeliveredFrom ) AND CONVERT( DATE, @DeliveredTo ) 
--group by CampaignDate,campaigntype,campaignname,mail_source 
ORDER BY CampaignDate DESC; 
--OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY 
END; 
 ELSE 
BEGIN 
SELECT COUNT( batchid ) OVER( ) 
AS TotalRow, 
 CampaignDate, 
 campaigntype, 
 campaignname, 
 batchid, 
 SentTime, 
 Mail_ToEmail, 
 delivereddate, 
 entity, 
 entityid, 
 image, 
 Personname, 
 LeadID 
FROM 
( 
 SELECT CampaignDate, 
 campaigntype, 
 campaignname, 
 b.batchid, 
 ISNULL( scheduleddate, batchinserttime ) 
 AS SentTime, 
 ISNULL( s.Mail_ToEmail, i.Mail_ToEmail ) Mail_ToEmail, 
 delivereddate, 
 CASE 
 WHEN leadno IS NOT NULL 
 THEN 'lead' 
 WHEN enquiryid IS NOT NULL 
 THEN 'enquiry' 
 ELSE '' 
 END 
 AS entity, 
 COALESCE( leadno, enquiryid, 0 ) entityid, 
 COALESCE( tbllead.ProfileImgFileName, tblenq.ProfileImgFileName, '' ) image, 
 COALESCE( tbllead.personname, tblenq.personname, '' ) Personname, 
 tblLead.LeadID 
 FROM #batch b 
 LEFT JOIN 
 #sent s 
 ON b.BatchID=s.batchid 
 --left join #kopened ko on ko.BatchID=b.BatchID 
 --left join #kclicked kc on kc.BatchID=b.BatchID 
 LEFT JOIN 
 #invalidmails i 
 ON i.batchid=b.BatchID 
 --left join #unsubscribed u on u.Batchid=b.BatchID 
 LEFT JOIN 
 #tblEnquiry tblEnq 
 ON ISNULL( s.Mail_ToEmail, i.Mail_ToEmail )=tblEnq.Email 
 LEFT JOIN 
 #tblLead tblLead 
 ON ISNULL( s.Mail_ToEmail, i.Mail_ToEmail )=tblLead.Email 
 --union 
 --select CampaignDate,mail_source ,campaigntype,campaignname,b.batchid,isnull(scheduleddate,batchinserttime) as SentTime, 
 --s.Mail_ToEmail,s.MailStatus,null as OpenedTimes,null as LastOpened 
 --from 
 --#batch b 
 --left join #invalidmails s on s.batchid=b.BatchID 
) a 
WHERE Mail_ToEmail LIKE '%'+@Recipient+'%' 
 AND campaigntype=CASE 
 WHEN @campaigntype IS NULL 
 THEN campaigntype 
 ELSE @campaigntype 
 END 
 AND campaignname=CASE 
 WHEN @campaignname IS NULL 
 THEN campaignname 
 ELSE @campaignname 
 END 
 AND delivereddate IS NOT NULL 
--group by CampaignDate,campaigntype,campaignname,mail_source 
ORDER BY CampaignDate DESC; 
--OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY 
END; 
DROP TABLE IF EXISTS #batch; 
DROP TABLE IF EXISTS #invalidmails; 
DROP TABLE IF EXISTS #sent; 
DROP TABLE IF EXISTS #karixreport; 
--drop table if exists #kopened 
--drop table if exists #kclicked 
DROP TABLE IF EXISTS #awsreport; 
--drop table if exists #unsubscribed 
DROP TABLE IF EXISTS #tblEnquiry; 
DROP TABLE IF EXISTS #tblLead; 
END; 




